INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0401334F$$, $$Large Aircraft Survivability Systems (LASS)$$, $$rdte_af_ba7$$, $$aflcmc$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 70096000, 49785000, 27856000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 50111000, 50111000, 0, 50111000, 28420000, $$Large Aircraft Survivability Systems (LASS) expands the protection of large aircraft beyond surface-to-air infrared (IR) missile threats to ensure the survivability of the High Value Airborne Assets (HVAA), air-refueling aircraft, and tactical/strategic airlifters against the increasing lethality of long-range enemy threats. LASS will develop and integrate a set of modular, platform-agnostic, scalable, on-board systems of sensors, processors, and effectors to support both on-board and off-board engagement systems. These sensors will look downward and upward to identify threats and provide aircrews a common operating picture and provide non-kinetic and kinetic engagement solutions to defeat threats to US and allied aircraft. Funding will support development and prototyping within a modular, scalable architecture, ensuring the capability can be rapidly upgraded to detect new and emerging threats. Large aircraft must have the ability to detect, decide, and defeat the enemy threats organically from onboard the aircraft. Multiple sensors will detect threats, processors will decide what threat is inbound and which aircraft is being targeted, and determine which effector is the best option to defeat the threat and provide continuous targeting data to the effector, if necessary. Effector systems may use kinetic and non-kinetic means to defeat the threat. LASS efforts include, but are not limited to, developing operational hardware and software to improve detection field of view, processing, algorithms, and dynamic tracking to ensure common interfaces for components and early countermeasure engagement. Project 67A038, Active Defense Sensor continues development on the Long-Range Detect Sensor (LRDS) and Active Defense Sensor (ADS) efforts that began in FY 2026 under PE 0401134F, LAIRCM transferred to the LASS PE 0401334F in FY 2027. These upward looking sensors operate separately from the downward looking LAIRCM sensors to detect different threats. They work together to provide the processor with the detection and ranging data needed for the effector to defeat long-range threats. LRDS is the passive sensor that detects long range threats at significant distances, enhances aircrew situational awareness, and provides early warning of incoming threats. Upon receiving a cue from LRDS, the ADS takes over. ADS locates the target, gathers range information to form a cue-quality track, and maintains custody of the target until the processor determines its validity. If confirmed as a real threat, the processor calculates the You Are The One/You Are Not The One Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                             Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                 PE 0401334F / Large Aircraft Survivability Systems (LASS) Operational Systems Development (YATO/YANTO) by fusing the aircraft's own position in time and space with sensor data. The processor then uses the range information from the ADS to determine the optimal moment to launch an effector. Following launch, the ADS will likely need to transmit coordinates and range information to the effector, requiring it to continuously transmit and receive signals from both the target and the effector to ensure a successful engagement. Project 67A038, Active Defense Sensor funding provides for Advanced Capability Development to include Latent Capability Development (LCD), software development that integrates the GLTA-101, an advanced upgrade laser turret and Guardian Laser Turret Assembly-101 (GLTA-101) software development. These efforts transferred from PE 0401134F, LAIRCM, Project 674942, LAIRCM. LCD develops the ability for downward looking sensors to detect and defeat a distinct new category of lethal threats and includes updates to the latest modeling and simulation threat models. It provides all support required to update the downward looking system's hardware, firmware, and software. The GLTA-101s are being procured in FY 2027 and being installed on C-17s in FY 2029. The requirements for the LRDS, ADS, Processor, and Effector are documented in the validated Platform Agnostic Kinetic Self-Defense (PAKS-D) System Attributes Requirements Document (SARD). Program support cost efforts consist of, but are not limited to, contract services and government costs. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0401334F_ba5$$, $$Large Aircraft Survivability Systems (LASS)$$, $$rdte_af_ba5$$, $$aflcmc$$, 2026, 0, 0, 0, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy27", "original_pe": "0401334F", "fy27_base_v158_t7": "hygiene: base=request for disc-only RDT&E rows post v7 I-23/I-24 + v9 I-2 INSERTs"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, 17996000, 17996000, NULL, 17996000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0408011F$$, $$Special Tactics / Combat Control$$, $$rdte_af_ba7$$, $$afsoc$$, 2026, 0, 7711000, 9421000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0408011F"}$$::jsonb, $$Mission Description and Budget Item Justification Special Tactics (ST) is a human-based weapon system, comprised of both human and equipment capabilities formulated to provide the Air Force and Joint Force with support across the following missions: Global Access, Precision Strike, and Personnel Recovery (PR); with additional focus on Electromagnetic Spectrum Operations (EMSO), Counter-Unmanned Aircraft Systems (UAS), and Ground-based Suppression of Enemy Air Defenses (SEAD). ST is employed by Air Force Special Operations Command (AFSOC) across three distinct operator specialties: Combat Control, Pararescue, and Special Reconnaissance. ST, along with the Guardian Angel and Tactical Air Control Party (TACP) weapon systems, collectively make up Air Force Special Warfare (AFSPECWAR), formerly known as Battlefield Airmen. Special Warfare Acquisition, Growth and Refresh (SWAGR) is the program of record to develop, integrate, test, procure and field the latest technology and equipment across a wide range of capabilities to ensure AFSPECWAR ST operators can achieve the mission sets outlined above. Specifically, SWAGR delivers modernized capability in the areas of body-worn hardware/software, tactical communications, ground mobility, small UAS, visual augmentation, maritime, special reconnaissance, technical recovery, and assault zones. Funding will provide for continued software development and modernization of the body-worn kit to enhance situational awareness, communication, information management, and airpower integration for ST operators in the battlespace. These enhancements will improve the ability recognize, identify, range, nominate, and designate targets during both day and night operations. Improvements will also significantly reduce the time required to find, track, fix targets, and engage the enemy by attacking adversary signals of interest, providing highly accurate target grid coordinates in three dimensions, generating target imagery both pre- and post-strike, and transmitting target data to Command and Control centers. Funding will also provide for the development and test of emerging technology, and the integration of the latest mature technology into the ST weapon system to conduct mission essential tasks such as improving support to Global Access (through Assault Zone operations and surveys), Precision Strike, PR, Counter-Space, Counter-UAS Operations, Ground-based SEAD, EMSO (to include awareness/defensive/offensive capabilities), and any other ST capability needs. Funding will also support innovation activities to include industry technology demonstrations, prototypes, studies, analyses, engineering support, and requirements definition to accelerate technology transition into future acquisition programs. Due to the rapidly changing threat environment, the acquisition program manager has the authority to redirect funding as necessary to meet current slated and emerging requirements. FY26 funding ($9.622M) for BA 07 0408011F was transferred to BA 07 Project 0207457F. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0408011F / Special Tactics / Combat Control Operational Systems Development This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 1.320M was expended for civilian pay expenses in this program element, and in FY 2025 1.488M is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 0, 0, 0, NULL, NULL, 282, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 9146000, 28200000, 0, 0, 0, 0, 0, $$Mission Description and Budget Item Justification Special Tactics (ST) is a human-based weapon system, comprised of both human and equipment capabilities formulated to provide the Air Force and Joint Force with support across the following missions: Global Access, Precision Strike, and Personnel Recovery (PR); with additional focus on Electromagnetic Spectrum Operations (EMSO), Counter-Unmanned Aircraft Systems (UAS), and Ground-based Suppression of Enemy Air Defenses (SEAD). ST is employed by Air Force Special Operations Command (AFSOC) across three distinct operator specialties: Combat Control, Pararescue, and Special Reconnaissance. ST, along with the Guardian Angel and Tactical Air Control Party (TACP) weapon systems, collectively make up Air Force Special Warfare (AFSPECWAR), formerly known as Battlefield Airmen. Special Warfare Acquisition, Growth and Refresh (SWAGR) is the program of record to develop, integrate, test, procure and field the latest technology and equipment across a wide range of capabilities to ensure AFSPECWAR ST operators can achieve the mission sets outlined above. Specifically, SWAGR delivers modernized capability in the areas of body-worn hardware/software, tactical communications, ground mobility, small UAS, visual augmentation, maritime, special reconnaissance, technical recovery, and assault zones. Funding will provide for continued software development and modernization of the body-worn kit to enhance situational awareness, communication, information management, and airpower integration for ST operators in the battlespace. These enhancements will improve the ability recognize, identify, range, nominate, and designate targets during both day and night operations. Improvements will also significantly reduce the time required to find, track, fix targets, and engage the enemy by attacking adversary signals of interest, providing highly accurate target grid coordinates in three dimensions, generating target imagery both pre- and post-strike, and transmitting target data to Command and Control centers. Funding will also provide for the development and test of emerging technology, and the integration of the latest mature technology into the ST weapon system to conduct mission essential tasks such as improving support to Global Access (through Assault Zone operations and surveys), Precision Strike, PR, Counter-Space, Counter-UAS Operations, Ground-based SEAD, EMSO (to include awareness/defensive/offensive capabilities), and any other ST capability needs. Funding will also support innovation activities to include industry technology demonstrations, prototypes, studies, analyses, engineering support, and requirements definition to accelerate technology transition into future acquisition programs. Due to the rapidly changing threat environment, the acquisition program manager has the authority to redirect funding as necessary to meet current slated and emerging requirements. The FY 2026 spend plan amount for 0408011F includes $28,200 thousand of discretionary and $10,000 thousand of mandatory (reconciliation) for a total of $38,200. The FY 2026 funding ($9.622 Million) and FY2027 funding ($9.893 Million) for BA 07 Project 0408011F was transferred to BA 07 Project 0207457F. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0408011F / Special Tactics / Combat Control Operational Systems Development 0408011F (Special Tactics/Combat Control), received a Congressional add for FY2026 $28.2 million for Hurricane sUAS ($25.0 million) and a Rapidly Deployable Surveillance and Precision Landing System (PLS) ($3.2 Million). Upon Congressional spend plan approval, an Internal Reprogramming (IR) will be processed aligning Hurricane UAS funding to PE 0208201F, BPAC 660192 and PLS funding to PE 0207457F, BPAC 675138 for proper execution. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2035_L198$$, $$BUILDING, PRE-FAB, RELOCATABLE$$, $$proc_army_2035_ba3$$, $$peo_c3t$$, 2026, 10490000, 12500000, 14622000, NULL, $${"page": 50, "ba_num": "03", "source": "p1_fy26", "ba_name": "Other support equipment", "line_no": "198", "service": "army", "fy24_qty": null, "fy25_qty": null, "appr_code": "2035", "appr_name": "Other Procurement, Army", "fy26_v178": {"note": "no_parser_pair", "source": "p40_fy26_v178"}, "fy26t_qty": null, "fy26d_cost": 10490000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, 1227991000, NULL, NULL, NULL, FALSE, 14622000, 10490000, 0, 0, 0, 0, NULL, NULL, $$Budget J-Books/FY27/Army/Other Procurement - BA3 & 4 - Other Support Equipment & Initial Spares.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604642A$$, $$Light Tactical Wheeled Vehicles$$, $$rdte_army_ba5$$, $$peo_cscss$$, 2026, 0, 3394000, 3000000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 16, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0604642A", "page_header": "Department of the Army"}$$::jsonb, $$The Army's High Mobility Multipurpose Vehicle (HMMWV) is a lightweight, high performance four-wheel drive, air transportable and air droppable family of tactical vehicles. The vehicle comes armored and unarmored with several different configurations: Command and Control; Cargo/Shelter Carrier; Weapons Carrier and Ambulance and is capable of performing multiple mission roles for personnel and payloads across the full spectrum of military operations. HMMWV Occupancy Protection supports an All Belts to Seats (ABTS) effort which would mitigate occupant injuries during rollover events, integrate air bags/air belts, and significantly minimize head contact with the roof and doors. Efforts within the Program Element includes Infantry Squad Vehicle (ISV), and HMMWV Occupancy Protection. The Army Infantry Squad Vehicle (ISV), through enhanced tactical mobility, will motorize the Brigade Combat Teams (BCT's) and the 75th Ranger Regiment with their associated equipment to move quickly around the battlefield. This capability is required across the range of military operations conducting crisis response, initial entry, and selected decisive action missions. ISV deploys worldwide by sea, air, and land modes to support strategic deployment and operational maneuver in accordance with Army and Joint doctrine. This capability provides flexibility for entry operations (permissive and non-permissive) to counter threat anti-access strategies by using multiple austere entry points to bring in combined arms configured units. ISV enables infantry squad to operate dispersed and cover greater distances that will achieve positions of advantage and enables platoons and companies to transport and power enabling capabilities at the speeds, distances, and survivability required to support ISV enabled infantry squads and other supporting mission payloads. The ISV enables charging of critical capabilities through increased export power, pushing forward of Class I&V resupply, and enabling CASEVAC. Supports modernization of the current Wheeled Vehicle fleets by investigating technology insertions including, but not limited to: predictive logistics, vetronics, Victory Architecture, autonomous operations and other emerging technologies and variants. Funding also supports developing initial prototypes to enable refinement of Operational Requirements and early user feedback to support future sustainment and operational movement operating concepts. PE 06044642A has no FY26 funding request. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                              Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0604642A / Light Tactical Wheeled Vehicles Development & Demonstration (SDD)$$, NULL, NULL, NULL, NULL, NULL, NULL, 109, $$RDTE - Vol 3 - Budget Activity 5A.pdf$$, NULL, FALSE, 5058000, 0, 6142000, 6142000, NULL, 6142000, NULL, $$The Army's High Mobility Multipurpose Vehicle (HMMWV) is a lightweight, high performance four-wheel drive, air transportable and air droppable family of tactical vehicles. The vehicle comes armored and unarmored with several different configurations: Command and Control; Cargo/Shelter Carrier; Weapons Carrier and Ambulance and is capable of performing multiple mission roles for personnel and payloads across the full spectrum of military operations. HMMWV Occupancy Protection supports an All Belts to Seats (ABTS) effort which would mitigate occupant injuries during rollover events, integrate air bags/air belts, and significantly minimize head contact with the roof and doors. Efforts within the Program Element includes Infantry Squad Vehicle (ISV), and HMMWV Occupancy Protection. The Infantry Squad Vehicle (ISV) composed of the ISV and ISV-Utility (ISV-U) is a modified commercial off the shelf (M-COTS) program which incorporates greater affordability goals, as well as requirements for reduced weight, and increased vehicle transportability. The ISV provides enhanced tactical mobility for an Brigade Combat Team (BCT), a nine-Soldier infantry squad, with their associated equipment to move quickly around the battlefield. This includes the ability to execute medium distance insertion operations which provides commanders greater freedom of movement and freedom of action. The ISV-U is a five-seat ground vehicle platform that leverages the base ISV configuration. This provides the US Army with a highly mobile and transportable platform that provides Rapid Mission Payload capability on the proven ISV platform. The ISV-H is a six-seat ground vehicle platform that supports the BCT with enhanced operational flexibility by enabling air assault missions, mission command on the move and Tactical Operations Center (TOC) operations while providing increased payload capacity and power management capabilities to adapt to dynamic battle conditions. ISV deploys worldwide by sea, air, and land modes to support strategic deployment and operational maneuver in accordance with Army and Joint doctrine. This capability provides flexibility for entry operations (permissive and non-permissive) to counter threat anti-access strategies by using multiple austere entry points to bring in combined arms configured units. ISV, transportable by CH-47/UH-60, air drop capable, payload of nine Soldiers with equipment/supplies for three days of operations. The purpose of the ISV-U is to serve as cargo variant of the ISV passenger for BCTs and other end Users with larger payload. The intended function is to provide larger payload capacity and payload area for unique mission packages in the cargo bed across a battlefield for the User to achieve their objective. The Infantry Squad Vehicle - Heavy (ISV-H) is designed to fulfill critical operational roles such as export power for TOC operations and onboard power for Mission Command on the Move. These roles emphasize versatility, mobility, and support for tactical operations across diverse environments. Primary intended usage for the ISV-H is at Division and Brigade. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                  Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System               PE 0604642A / Light Tactical Wheeled Vehicles Development & Demonstration (SDD) Supports modernization of the current Wheeled Vehicle fleets by investigating technology insertions including, but not limited to: predictive logistics, platform safety enhancements including operations in extreme environments, vetronics, Victory Architecture, autonomous operations and other emerging technologies and variants. Funding also supports developing initial prototypes to enable refinement of Operational Requirements and early user feedback to support future sustainment and operational movement operating concepts.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0601000BR$$, $$DTRA BASIC RESEARCH$$, $$rdte_dw_ba1$$, $$dw_dtra$$, 2026, 15643000, 21387000, 15311000, NULL, $${"act": "01", "ba_raw": "6.1", "source": "r1_fy26", "service": "dw", "page_num": 66, "original_pe": "0601000BR", "page_header": "Defense-Wide"}$$::jsonb, $$The Basic Research for Countering Weapons of Mass Destruction (CWMD) project, as the nation’s primary basic research portfolio dedicated to CWMD, is a core strategic investor in future scientific and technological progress across the Defense Threat Reduction Agency's (DTRA) mission areas. This project concentrates on high-risk, high-payoff basic research, leveraging world-class expertise in academia, government, and industry, to increase the foundational body of scientific knowledge supporting DTRA’s Applied Research and Advanced Technology Development projects. This project aligns with DTRA’s strategic objectives that support policy and planning guidance from the Executive Office of the President, the Department of Defense (DoD), and the broader Weapons of Mass Destruction (WMD) threat reduction community. The portfolio addresses this guidance through capability enhancements, projects, and Science and Technology (S&T) investments that support CWMD. Specifically, they include: accelerating the development of standoff radiological/nuclear detection capabilities; securing vulnerable materials; defeating WMD agents; strategic radiation hardened microelectronics; and leveraging science, technology, and innovation through domestic partnerships and agreements. This project solicits, coordinates, and conducts research to build a robust, forward-looking fundamental research portfolio targeting strategic, mission-focused, basic research with high potential impact for CWMD. The research projects are selected for scientific merit, technical quality, and the potential for innovation. Each research project offers opportunities to expand the knowledge base to help the warfighter, to bring to bear new science solutions with a fresh approach, or to leverage revolutionary approaches to technical surprise, building a foundation for future CWMD solutions. This research will enable new capabilities to control, defeat, disable, and/or dispose of WMD threats.$$, NULL, 15385000, 15722000, 16004000, NULL, NULL, 1, $$RDTE_DTRA_PB_2026.pdf$$, $$DTRA$$, FALSE, 14933000, 15481000, 15070000, 15070000, 0, 15070000, 16325000, $$The Basic Research for Countering Weapons of Mass Destruction (CWMD) project, as the nation’s primary basic research portfolio dedicated to CWMD, is a core strategic investor in future scientific and technological progress across the Defense Threat Reduction Agency's (DTRA) mission areas. This project concentrates on high-risk, high-payoff basic research, leveraging world-class expertise in academia, government, and industry, to increase the foundational body of scientific knowledge supporting DTRA’s Applied Research and Advanced Technology Development projects. Specifically, research projects support CWMD and include: accelerating the development of standoff radiological/nuclear detection capabilities; securing vulnerable materials; defeating WMD agents; strategic radiation hardened microelectronics; and leveraging science, technology, and innovation through domestic partnerships and agreements. This project solicits, coordinates, and conducts research to build a robust, forward-looking fundamental research portfolio targeting strategic, mission-focused, basic research with high potential impact for CWMD. Research projects are selected for scientific merit, technical quality, and the potential for innovation. Each research project offers opportunities to expand the knowledge base to help the warfighter, to bring to bear new science solutions with a fresh approach, or to leverage revolutionary approaches to technical surprise, building a foundation for future CWMD solutions. This research will enable new capabilities to control, defeat, disable, and/or dispose of WMD threats.$$, $$Budget J-Books/FY27/Remaining/RDTE_DTRA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0601102A$$, $$Defense Research Sciences$$, $$rdte_army_ba1$$, $$devcom_arl$$, 2026, 237678000, 322341000, 297680000, NULL, $${"act": "01", "ba_raw": "6.1", "source": "r1_fy26", "service": "army", "page_num": 10, "original_pe": "0601102A", "page_header": "Department of the Army", "fy26_v182_disc_K": 258178, "fy26_v182_supp_K": 1000, "fy26_v182_total_K": 259178, "fy26_v182_note_name": "Defense Research Sciences", "fy26_v182_source_file": "RDTE - Vol 1 - Budget Activity 1.txt", "fy26_v182_source_line": 708}$$::jsonb, $$This Program Element (PE) builds fundamental scientific knowledge contributing to the sustainment of United States (US) Army scientific and technological superiority in land warfighting capability and to solving military problems related to long-term national security needs, investigates new concepts and technologies for the Army's future force, and provides the means to exploit scientific breakthroughs and avoid technological surprises. This PE fosters innovation in Army niche areas (e.g., lightweight armor, energetic materials, and night vision capability) and areas where there are no commercial investments due to limited markets (e.g., vaccines for Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                   Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 1: Basic                 PE 0601102A / Defense Research Sciences Research tropical diseases). It also focuses university single investigator research on areas of high interest to the Army (e.g., high-density compact power and novel sensor phenomenology). The in-house portion of the program capitalizes on the Army's scientific talent and specialized facilities to transition knowledge and technology into appropriate developmental activities. The extramural program leverages the research efforts of other government agencies, academia, and industry. This PE also supports basic research at the Army laboratories through the In-House Laboratory Independent Research (ILIR) program. The ILIR program serves as a catalyst for major technology breakthroughs by providing laboratory directors flexibility in implementing novel research ideas and by nurturing promising young scientists and engineers and is used to attract and retain top doctoral degreed scientists and engineers. The ILIR program also provides a source of competitive funds for peer reviewed efforts at Army laboratories to stimulate high quality, innovative research with significant opportunity for payoff to Army warfighting capability. This PE also identifies emerging and disruptive basic scientific research outcomes in order to translate, integrate, and ingrain research outcomes with Army Warfighting Concepts which describe how the Army will fight in the far-term future. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. The FY 2026 request was reduced by $7.871 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $1.412 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 215376000, 226586000, 229467000, NULL, NULL, 1, $$RDTE - Vol 1 - Budget Activity 1.pdf$$, NULL, FALSE, 290464000, 259178000, 215322000, 215322000, NULL, 215322000, 227880000, $$This Program Element (PE) builds fundamental scientific knowledge contributing to the sustainment of United States (US) Army scientific and technological superiority in land warfighting capability and to solving military problems related to long-term national security needs, investigates new concepts and technologies for the Army's future force, and provides the means to exploit scientific breakthroughs and avoid technological surprises. This PE fosters innovation in Army niche areas (e.g., lightweight armor, energetic materials, and night vision capability) and areas where there are no commercial investments due to limited markets (e.g., vaccines for tropical diseases). It also focuses university single investigator research on areas of high interest to the Army (e.g., high-density compact power and novel sensor phenomenology). The in-house portion of the program capitalizes on the Army's scientific talent and specialized facilities to transition knowledge and technology into appropriate developmental activities. The extramural program leverages the research efforts of other government agencies, academia, and industry. This PE also supports basic research at the Army laboratories through the In-House Laboratory Independent Research (ILIR) program. The ILIR program serves as a catalyst for major technology breakthroughs by providing laboratory directors flexibility in implementing novel research ideas and by nurturing promising young scientists and engineers and is used to attract and retain top doctoral degreed scientists and engineers. The ILIR program also provides a source of competitive funds for peer reviewed efforts at Army laboratories to stimulate high quality, innovative research with significant opportunity for payoff to Army warfighting capability. This PE also identifies emerging and disruptive basic scientific research outcomes in order to translate, integrate, and ingrain research outcomes with Army Warfighting Concepts which describe how the Army will fight in the far-term future.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 1.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0601102SF$$, $$Defense Research Sciences$$, $$rdte_sf_ba1$$, $$afrl_afosr$$, 2026, 22270000, 0, 21349000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$Defense Research Sciences consists of research activities in academia and industry along with research performed in the Department of the Air Force (DAF), including the Air Force Research Laboratory, Air Force Institute of Technology, and the United States Air Force Academy. This program supports basic broad-based scientific and engineering research in areas critical to the five core technical competencies of the United States Space Force: Space Security; Combat Power Projection; Space Mobility and Logistics; Information Mobility; and Space Domain Awareness, while simultaneously building capacity in academia and cultivating the Science, Technology, Engineering, and Mathematics (STEM) pipeline. All research areas are subject to long-range planning and technical review by both DAF and tri-Service scientific planning groups. Efforts in this program have been coordinated through the Department of Defense (DoD) Science and Technology (S&T) Executive Committee process to harmonize efforts and eliminate duplication. This program is executed by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain science and technology (S&T) solutions that propel innovation today and support the Air and Space Force in securing dominance in future operational environments. AFRL effectively aligns the Department of the Air Force (DAF) S&T enterprise and workforce towards the most consequential DAF priorities to accelerate the delivery of game-changing S&T. In order to manage, execute, and deliver science and technology capabilities, this program element may include necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. Funds in this program element may be used to investigate specified science advancements primarily targeted to challenges in the space domain and multi-domain research with space-domain application. The FY 2026 request was increased by 0.921 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, Implementing the President's Department of Government Efficiency Cost Efficiency Initiative. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation without regard to any limitation on appointments, positions, or funding in a manner consistent with the budget. This program is in Budget Activity 1, Basic Research because this budget activity includes scientific study and experimentation directed toward increasing fundamental knowledge and understanding in those fields of the physical, engineering, environmental, and life sciences related to long-term national security needs. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 1: Basic PE 0601102SF / Defense Research Sciences Research$$, NULL, 23218000, 23528000, 24229000, NULL, NULL, 1, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 19949000, 21999000, 20833000, 20833000, 0, 20833000, 24721000, $$The Air Force Office of Scientific Research (AFOSR) is researching, analyzing and developing technology through the Defense Research Sciences Project 0601102SF (Project 610001) to support Guardians across Science & Technology and Test & Evaluation. The effects of our efforts will ensure that future Science & Technology and Test & Evaluation have the necessary experimentation and analytic results for future USSF R&D activities. Defense Research Sciences consists of research activities in academia and industry along with research performed in the Department of the Air Force (DAF), including the Air Force Research Laboratory (AFRL), Air Force Institute of Technology, and the United States Air Force Academy. This program supports basic broad-based scientific and engineering research in areas critical to the five core technical competencies of the United States Space Force: Space Security; Combat Power Projection; Space Mobility and Logistics; Information Mobility; and Space Domain Awareness, while simultaneously building capacity in academia and cultivating the Science, Technology, Engineering, and Mathematics (STEM) pipeline. All research areas are subject to long-range planning and technical review by both DAF and tri-service scientific planning groups. In order to manage, execute, and deliver Science and Technology (S&T) capabilities, this program element may include necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. Funds in this program element may be used to investigate specified science advancements primarily targeted to challenges in the space domain and multi-domain research with space-domain application. This program falls within the S&T and Test & Evaluation (T&E) mission area which provides the S&T initiatives, demonstrations, experiments, and studies towards developing next-generation space capabilities. The T&E mission area provides all efforts required to establish and operate the test infrastructure for USSF capabilities. Space Force investment program interdependencies include: RDT&E Budget Line Items: Defense Research Sciences (0601102SF); Major T&E Investments - Space (1206759SF); Small Business Innovation Research (1205502SF); Space Advanced Tech Dev / Demo (1206616SF); Space Innov Intg & Rapid Tech Dev (1203174SF); Space Rapid Capabilities Office (1206857SF); Space Science and Technology (1206310SF); Space Systems Prototype Transition (1206427SF); Space Technology (1206601SF); Space Test and Evaluation (1202051SF); Space Test Program (1206864SF); University Research Initiatives (0601103SF); Operational Test & Training Infrastructure (1206617SF) and elements of Procurement Budget Line Item: General Information Tech - Space (GNRLIT) Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 1: Basic PE 0601102SF / Defense Research Sciences Research The FY 2027 request was reduced by $0.020 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency” Cost Efficiency Initiative. This program is in Budget Activity 1, Basic Research because this budget activity includes scientific study and experimentation directed toward increasing fundamental knowledge and understanding in those fields of the physical, engineering, environmental, and life sciences related to long-term national security needs.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303767A$$, $$AMBIT - Pre-Auctioned SRF$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 0, 20791000, 0, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 20, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0303767A", "page_header": "Department of the Army"}$$::jsonb, $$In accordance with 47 USC 928 and the Commercial Spectrum Enhancement Act (CSEA) Title, P.L. 108-494, dated December 23, 2004, established the Spectrum Relocation Fund (SRF) to provide Federal agencies a mechanism to recover the cost associated with relocating spectrum dependent systems from spectrum bands which were auctioned for commercial purposes. The activities described meet the CSEA and SRF requirements for funding to support spectrum relocation and the Americas Mid-band Initiative Team (AMBIT). The Department of Defense (DoD) PRE-AUCTION AMBIT Transition Plan supports the relocation and sharing costs associated with the reallocation of an electromagnetic spectrum (EMS) band (in this case, 3450-3550 MHz), as required by the Enhanced 911 Services Act, 2004 (PL 108-494) and as amended by the Middle-Class Tax Relief Act, 2012 (PL 112-96), and defines the necessary RDT&E efforts to share EMS access for governmental and commercial use of the AMBIT band. When the Federal Communications Commission (FCC) auctions EMS bands to the commercial sector, previously reserved for governmental or military use, the DoD incurs costs as it must relocate to a new EMS band or share the auctioned band with commercial entities. Funds from the SRF are made available for DoD to pay relocation or sharing costs related to auctioned EMS bands, such as the costs of any modification or replacement of equipment, spares, associated ancillary equipment, software, facilities, operating manuals, training, or compliance with regulations that are attributable to relocation or sharing; the costs of all engineering, equipment, software, site acquisition, and construction, as well as any legitimate and prudent transaction expenses, including term-limited Federal civil servant and contractor staff necessary to carry out the relocation or sharing activities of a Federal entity, and reasonable additional costs incurred by the Federal entity that are attributable to relocation or sharing, including increased recurring costs. The SRF is funded with proceeds from FCC conducted auctions of spectrum licenses. SRF funds have an indefinite obligation period and remain available until expended (X Year). The DoD Chief Information Officer (CIO) executes oversight of DoD spectrum relocation and sharing efforts.$$, NULL, NULL, NULL, NULL, NULL, NULL, 171, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 2502000, 0, NULL, NULL, NULL, NULL, NULL, $$In accordance with 47 USC 928 and the Commercial Spectrum Enhancement Act (CSEA) Title, P.L. 108-494, dated December 23, 2004, established the Spectrum Relocation Fund (SRF) to provide Federal agencies a mechanism to recover the cost associated with relocating spectrum dependent systems from spectrum bands which were auctioned for commercial purposes. The activities described meet the CSEA and SRF requirements for funding to support spectrum relocation and the Americas Mid-band Initiative Team (AMBIT). The Department of War (DoW) PRE-AUCTION AMBIT Transition Plan supports the relocation and sharing costs associated with the reallocation of an electromagnetic spectrum (EMS) band (in this case, 3450-3550 MHz), as required by the Enhanced 911 Services Act, 2004 (PL 108-494) and as amended by the Middle-Class Tax Relief Act, 2012 (PL 112-96), and defines the necessary RDT&E efforts to share EMS access for governmental and commercial use of the AMBIT band. When the Federal Communications Commission (FCC) auctions EMS bands to the commercial sector, previously reserved for governmental or military use, the DoW incurs costs as it must relocate to a new EMS band or share the auctioned band with commercial entities. Funds from the SRF are made available for DoW to pay relocation or sharing costs related to auctioned EMS bands, such as the costs of any modification or replacement of equipment, spares, associated ancillary equipment, software, facilities, operating manuals, training, or compliance with regulations that are attributable to relocation or sharing; the costs of all engineering, equipment, software, site acquisition, and construction, as well as any legitimate and prudent transaction expenses, including term-limited Federal civil servant and contractor staff necessary to carry out the relocation or sharing activities of a Federal entity, and reasonable additional costs incurred by the Federal entity that are attributable to relocation or sharing, including increased recurring costs. The SRF is funded with proceeds from FCC conducted auctions of spectrum licenses. SRF funds have an indefinite obligation period and remain available until expended (X Year). The DoW Chief Information Officer (CIO) executes oversight of DoW spectrum relocation and sharing efforts. PE 0303767A / AMBIT - Pre-Auctioned SRF has no funding request in FY 2027. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                    Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System        PE 0303767A / AMBIT - Pre-Auctioned SRF Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0601103A$$, $$University Research Initiatives$$, $$rdte_army_ba1$$, $$dw_osd$$, 2026, 78947000, 72781000, 78166000, NULL, $${"act": "01", "ba_raw": "6.1", "source": "r1_fy26", "service": "army", "page_num": 10, "original_pe": "0601103A", "page_header": "Department of the Army", "fy26_v182_disc_K": 77178, "fy26_v182_supp_K": 28000, "fy26_v182_total_K": 105178, "fy26_v182_note_name": "University Research Initiatives", "fy26_v182_source_file": "RDTE - Vol 1 - Budget Activity 1.txt", "fy26_v182_source_line": 3557}$$::jsonb, $$This Program Element (PE) supports the Multidisciplinary University Research Initiative (MURI), the Defense University Research Instrumentation Program (DURIP), and the Presidential Early Career Awards for Scientists and Engineers (PECASE) program. The MURI program funds university based basic research in a wide range of scientific and engineering disciplines pertinent to maintaining land combat technology superiority. Army MURI efforts involve teams of researchers investigating high-priority, transformational topics that intersect more than one traditional technical discipline (e.g., Intelligent Luminescence for Communication, Display, and Identification). For many complex problems, this multidisciplinary approach serves to accelerate research progress and expedite transition of results to application. The DURIP provides funds to acquire major research equipment to augment current, or devise new, research capabilities in support of Army transformational research. The PECASE program funds single-investigator research efforts performed by outstanding academic scientists and engineers early in their independent research careers. Work in this PE provides a foundation for applied research initiatives at the Army laboratories and research, development and engineering centers. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. The FY 2026 request was reduced by $0.307 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.411 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                              Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 1: Basic             PE 0601103A / University Research Initiatives Research$$, NULL, 72279000, 75856000, 76668000, NULL, NULL, 2, $$RDTE - Vol 1 - Budget Activity 1.pdf$$, NULL, FALSE, 75313000, 105178000, 63102000, 63102000, NULL, 63102000, 77433000, $$This Program Element (PE) supports the Multidisciplinary University Research Initiative (MURI), the Defense University Research Instrumentation Program (DURIP), and the Presidential Early Career Awards for Scientists and Engineers (PECASE) program. The MURI program funds university based basic research in a wide range of scientific and engineering disciplines pertinent to maintaining land combat technology superiority. Army MURI efforts involve teams of researchers investigating high-priority, transformational topics that intersect more than one traditional technical discipline (e.g., Intelligent Luminescence for Communication, Display, and Identification). For many complex problems, this multidisciplinary approach serves to accelerate research progress and expedite transition of results to application. The DURIP provides funds to acquire major research equipment to augment current, or devise new, research capabilities in support of Army transformational research. The PECASE program funds single-investigator research efforts performed by outstanding academic scientists and engineers early in their independent research careers. Work in this PE provides a foundation for applied research initiatives at the Army laboratories and research, development and engineering centers.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 1.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0601103SF$$, $$University Research Initiatives$$, $$rdte_sf_ba1$$, $$afrl_afosr$$, 2026, 14569000, 0, 14731000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$This program supports defense-related basic research in a wide range of scientific and engineering disciplines relevant to maintaining U.S. military technology superiority. Research topics include, but are not limited to, revolutionary and high priority technologies critical to the five core technical competencies of the United States Space Force: Space Security; Combat Power Projection; Space Mobility and Logistics; Information Mobility; and Space Domain Awareness. The program also enhances and promotes the education of U.S. scientists and engineers in disciplines critical to maintaining, advancing, and enabling future U.S. defense technologies. This program assists universities in establishing superior instrumentation capabilities needed to improve the quality of defense-related research and education. A fundamental component of this program is the recognition that future technologies and technology exploitations require highly coordinated and concerted multi- and interdisciplinary efforts. Efforts in this program have been coordinated through the Department of Defense Science and Technology Executive Committee process to harmonize efforts and eliminate duplication. This program is executed by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi domain science and technology (S&T) solutions that propel innovation today and support the Air and Space Force in securing dominance in future operational environments. AFRL effectively aligns the Department of the Air Force (DAF) S&T enterprise and workforce towards the most consequential DAF priorities to accelerate the delivery of game-changing S&T. In order to manage, execute, and deliver science and technology capabilities, this program element may include: necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. Funds in this program element may be used to investigate specified science advancements primarily targeted to challenges in the space domain and multi-domain research with space-domain application. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation without regard to any limitation on appointments, positions, or funding in a manner consistent with the budget. This program is in Budget Activity 1, Basic Research because this budget activity includes scientific study and experimentation directed toward increasing fundamental knowledge and understanding in those fields of the physical, engineering, environmental, and life sciences related to long-term national security needs. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 1: Basic PE 0601103SF / University Research Initiatives Research$$, NULL, 15368000, 15364000, 15790000, NULL, NULL, 2, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 13604000, 14330000, 14426000, 14426000, 0, 14426000, 16028000, $$The Air Force Office of Scientific Research (AFOSR) is researching, analyzing, and developing technology through the University Research Initiatives PE 0601103SF (Project 610002) to support Guardians across Science & Technology and Test & Evaluation. The effects of our efforts will ensure that future Science & Technology and Test & Evaluation have the necessary experimentation and analytic results for future USSF R&D activities. This program supports defense-related basic research in a wide range of scientific and engineering disciplines relevant to maintaining U.S. military technology superiority. Research topics include, but are not limited to, revolutionary and high priority technologies critical to the five core technical competencies of the United States Space Force: Space Security; Combat Power Projection; Space Mobility and Logistics; Information Mobility; and Space Domain Awareness. The program also enhances and promotes the education of U.S. scientists and engineers in disciplines critical to maintaining, advancing, and enabling future U.S. defense technologies. This program assists universities in establishing superior instrumentation capabilities needed to improve the quality of defense-related research and education. A fundamental component of this program is the recognition that future technologies and technology exploitations require highly coordinated and concerted multi- and interdisciplinary efforts. In order to manage, execute, and deliver Science and Technology (S&T) capabilities, this program element may include: necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. Funds in this program element may be used to investigate specified science advancements primarily targeted to challenges in the space domain and multi-domain research with space-domain application. This program falls within the S&T and Test & Evaluation (T&E) mission area which provides the S&T initiatives, demonstrations, experiments, and studies towards developing next-generation space capabilities. The T&E mission area provides all efforts required to establish and operate the test infrastructure for USSF capabilities. Space Force investment program interdependencies include: RDT&E Budget Line Items: Defense Research Sciences (0601102SF); Major T&E Investments - Space (1206759SF); Small Business Innovation Research (1205502SF); Space Advanced Tech Dev / Demo (1206616SF); Space Innov Intg & Rapid Tech Dev (1203174SF); Space Rapid Capabilities Office (1206857SF); Space Science and Technology (1206310SF); Space Systems Prototype Transition (1206427SF); Space Technology (1206601SF); Space Test and Evaluation (1202051SF); Space Test Program (1206864SF); University Research Initiatives (0601103SF); Operational Test & Training Infrastructure (1206617SF) and elements of Procurement Budget Line Item: General Information Tech - Space (GNRLIT). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 1: Basic PE 0601103SF / University Research Initiatives Research This program is in Budget Activity 1, Basic Research because this budget activity includes scientific study and experimentation directed toward increasing fundamental knowledge and understanding in those fields of the physical, engineering, environmental, and life sciences related to long-term national security needs.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0601108D8Z$$, $$High Energy Laser Research Initiatives$$, $$rdte_dw_ba1$$, $$dw$$, 2026, 16817000, 15848000, 16518000, NULL, $${"act": "01", "ba_raw": "6.1", "source": "r1_fy26", "service": "dw", "page_num": 66, "original_pe": "0601108D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program is executed via the Joint Directed Energy Transition Office (JDETO) in alignment with the Department of Defense Directed Energy Roadmap, as well as other strategic guidance. Section 219 of the 2017 National Defense Authorization Act designated a senior official for directed energy and redesignated a legacy office as the JDETO with reporting to the senior official. Currently, the Principal Director for Directed Energy serves as this senior official and updates the Department of Defense Directed Energy Roadmap on an annual basis. The goal of this program, in turn, is to support the Department’s initiatives in directed energy to build a sustainable and long-term advantage, in addition to a resilient Joint force and defense ecosystem. This program funds basic research in directed energy to enable game-changing high energy laser and high power microwave technologies. These efforts provide fundamental scientific knowledge to support future Department of Defense directed energy weapon systems. In practice, directed energy weapon systems have many potential advantages, including speed-of-light time-to-target, high precision, low incremental cost per kill, and a magazine that is recharged through on-board, fuel-based power and thermal management systems that reduce logistics requirements in contrast to stocks of munitions or warheads. As a result, directed energy weapon systems have the potential to perform a wide variety of military missions. Activities conducted under this program are generally chosen for their potential to grow the directed energy workforce with next-generation scientists and engineers. This program is part of an overall Department of Defense strategy in Joint directed energy basic research. Efforts within this program will leverage multi-disciplinary university research institutes (both domestic and international) to stimulate student interest in directed energy and encourage research in topics related to high energy laser and high power microwave technologies. This program builds upon other investments in directed energy basic research by the Services and Agencies to harmonize Department efforts and eliminate duplication. In support, efforts in this program have been coordinated with the Department of Defense Directed Energy and Non-Lethal Weapons Science and Technology Community of Interest. This program is executed via a technical program within the JDETO referred to as the Directed Energy Center of Excellence Program, which enables (1) basic research in directed energy technology that supports workforce development with university partners and (2) international collaboration between universities in the United States and partner countries. Note that (1) and (2) are in alignment with the near-, mid-, and long-term goals of Department of Defense Directed Energy Roadmap and encourage transition. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                              Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 1: Basic PE 0601108D8Z / High Energy Laser Research Initiatives Research$$, NULL, 18143000, 18485000, 18880000, NULL, NULL, 3, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 16046000, 16720000, 17667000, 17667000, NULL, 17667000, 18879000, $$This program is executed via Scaled Directed Energy (SCADE) Science and Technology and in alignment with the Department of War Directed Energy Roadmap, as well as other strategic guidance. The goal of this program is to support the Department’s initiatives in directed energy to build a sustainable and long-term advantage. This program funds research in directed energy to enable game-changing high energy laser and high power microwave technologies. These efforts provide fundamental scientific knowledge to support future Department of War directed energy weapon systems. In practice, directed energy weapon systems have many potential advantages, including speed-of-light time-to-target, high precision, low incremental cost per kill, and a rechargeable magazine through on-board power and thermal management systems improving logistics requirements over stocks of munitions or warheads. As a result, directed energy weapon systems have the potential to perform a wide variety of military missions. This program is executed via a technical program within the JDETO referred to as the Directed Energy Foundational Research Program which enables research in directed energy technology by (1) university partners and (2) international collaboration between universities in the United States and partner countries.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0601110D8Z$$, $$Basic Research Initiatives$$, $$rdte_dw_ba1$$, $$dw$$, 2026, 82264000, 108132000, 87132000, NULL, $${"act": "01", "ba_raw": "6.1", "source": "r1_fy26", "service": "dw", "page_num": 66, "original_pe": "0601110D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$Basic research is a process of exploration and discovery, yielding disruptive, non-incremental advances that can improve or radically change military capabilities, strategy, and operations, towards realizing overwhelming technology advantage against competitors. It is a mission-oriented activity that provides the Department of Defense (DoD) with a deep and broad awareness of research areas to explore and invest in. These areas span a wide range of fundamental physical sciences (e.g., chemistry, biology, materials, mathematics, computer science, etc.) as well as fundamental research in engineering sciences that can catalyze the emergence of new technologies at scale (e.g., new materials or information systems). Basic research generates the critical technical knowledge that enables the ideation, design and realization of future DoD capabilities, including the exploration of new concepts of warfare. Basic research also sustains the scientific and engineering communities and creates new generations of a talented workforce that can support the DoD for the next decades. The Basic Research Initiatives Program includes programs and pilots designed to accomplish these objectives.$$, NULL, 76501000, 68552000, 62727000, NULL, NULL, 4, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 84289000, 108879000, 87091000, 87091000, NULL, 87091000, 57800000, $$Basic research is a process of exploration and discovery, yielding disruptive, non-incremental advances that can improve or radically change military capabilities, strategy, and operations, towards realizing overwhelming technology advantage against competitors. It is a mission-oriented activity that provides the Department of War (DoW) with a deep and broad awareness of research areas to explore and invest in. These areas span a wide range of fundamental physical sciences (e.g., chemistry, biology, materials, mathematics, computer science, etc.) as well as fundamental research in engineering sciences that can catalyze the emergence of new technologies at scale (e.g., new materials or information systems). Basic research generates the critical technical knowledge that enables the ideation, design and realization of future DoW capabilities, including the exploration of new concepts of warfare. Basic research also sustains the scientific and engineering communities and creates new generations of a talented workforce that can support the DoW for the next decades. The Basic Research Initiatives Program includes programs and pilots designed to accomplish these objectives.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0601120D8Z$$, $$National Defense Education Program (NDEP)$$, $$rdte_dw_ba1$$, $$dw$$, 2026, 156010000, 157139000, 169986000, NULL, $${"act": "01", "ba_raw": "6.1", "source": "r1_fy26", "service": "dw", "page_num": 66, "original_pe": "0601120D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Department's strategy to Build Sustainable and Long-Term Advantage and Cultivate the Workforce that the DoD needs. The National Defense Education Program (NDEP) supports the National Defense Science & Technology Strategy in ensuring the foundations for research and development have the workforce it needs now and into the future, through investments at every level of education. NDEP: (1) Fosters and enhances the Department of Defense’s (DoD) ability to develop and access high-quality science, technology, engineering, and mathematics (STEM) talent vital to national defense; (2) Is executed by the Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)); (3) Aligns to the Federal STEM Strategy, and addresses critical STEM education and talent development challenges across the PreK-20 education continuum through evidence-based approaches; (4) Activities align with the Department’s vision of a diverse STEM talent pool readily accessible to serve our Nation and evolve the Department’s competitive edge; (5) Activities engage in assessment and evaluation practices as outlined by the Office of Management and Budget and the Government Accountability Office; and (6) Aligns to the DoD STEM Strategic Plan in support of the National Defense Strategy and the DoD science and technology (S&T) critical technology areas. NDEP is part of the broader Department-wide effort under DoD STEM, which works collectively with partners from academia, industry non-profit organizations, defense research laboratories and engineering centers, and other government entities to: (1) build strong foundations for STEM literacy; (2) increase inclusion, diversity, and equity in STEM; and (3) prepare the STEM workforce of the future. NDEP activities provide authentic learning experiences through a variety of education and outreach initiatives in the form of scholarships, internships, enrichment activities, project/research-based competitions, and mentorships through strategic partnerships. The NDEP programs span across all age groups, including Pre- kindergarten through twelfth grade (PreK-12) students and teachers, and postsecondary, undergraduate, and graduate students. The NDEP’s portfolio includes: the Science, Mathematics, and Research for Transformation (SMART) scholarship-for-service program; STEM Education and Outreach (E&O) efforts including the Defense STEM Education Consortium (DSEC); and specific Congressionally directed programs, to include the Manufacturing Engineering Education Program (MEEP) per 10 U.S. Code 4843 and broader NDEP funding opportunities in STEM education and workforce development. The SMART Program enables the Department to transform its STEM workforce while addressing near-term workforce demands. Per 10 U.S. Code 4093, the SMART program awards highly competitive scholarships to undergraduate and graduate students in any of the 24 STEM academic disciplines critical to national security, and Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                  Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 1: Basic PE 0601120D8Z / National Defense Education Program (NDEP) Research hires the students, upon graduation, into DoD's civilian workforce. As part of the SMART experience, scholars engage in internships that allow for relevant hands-on research and work experiences in DoD facilities and international partner research institutions, thereby enhancing their educational experience. The SMART program ensures the Department has a steady infusion of high-quality technical talent, prepared in areas of critical importance, and ready to apply their technical knowledge, skills, and abilities to fulfill the DoD mission. Through an annual competitive SEED grant, SMART offers transitioning Ph.D. scholars an opportunity to establish a foundational research and engineering effort in their area of expertise aligned with a DoD mission or critical technology area and supporting their development into subject matter experts. Additionally, per FY 2021 NDAA Sec. 250, SMART also offers a competitive funding opportunity through the Creative Research & Engineering Advancing Technical Equity in STEM (CREATES) Grant to expand and enhance connections and opportunities between the SMART program, SMART scholars, SMART sponsoring facilities, and students and faculty at Historically Black Colleges and Universities (HBCU), Minority Institutions (MI), Minority Service Institutions (MSI), Tribal Colleges and Universities (TCU) and Women’s Colleges (WC). Since its inception in FY 2005, SMART has awarded approximately 5,200 scholarships to students pursuing undergraduate and graduate STEM degrees. To date, over 3,400 scholars have completed their academic pursuit and transitioned into DoD employment. More than 1,300 scholars are currently pursuing their SMART-funded degrees. Over 2,000 participants have successfully completed the program through their DoD Service commitment. NDEP’s STEM E&O activities will continue to engage military-connected students in collaboration with the Department of Defense Education Activity (DoDEA), external partners, and other stakeholders to support the preparation of dependents of members of the armed forces for careers in STEM as enacted under 10 U.S. Code 2192(b). Additionally, where feasible, NDEP activities will also support the Supporting Veterans in STEM Careers Act, enacted in FY 2020. Per 10 U.S. Code 2192, NDEP’s STEM E&O activities support a cohesive and coordinated approach by providing a continuum of preK to career opportunities for students, educators (formal and informal), administrators, and schools, especially for military-connected students. The primary effort under NDEP STEM E&O is the Defense STEM Education Consortium (DSEC), which is a consortium-model approach, leveraging a collaborative ecosystem of partners that aims to develop America’s STEM workforce of the future ready to support the national security mission and the Warfighter. The DSEC is a multi-year investment through a cooperative agreement award comprised of a consortium of program partners that have a national reach, as well as regionally focused activities leveraging evidence-based approaches. In FY2025, about 40% of SMART Scholarship recipients previously participated in preK-12 programs such as those funded under DSEC. DSEC is designed to evolve over time, enabling the Department and the consortium the flexibility to bring in new strategic partners to address emerging issues in STEM education and talent development, and to align to DoD’s priorities. The Biotechnology Education and Workforce Development (BIOTECH) efforts will be consolidated into the STEM E&O beginning in FY 2026 and establishes new educational programs that align with biotechnology priorities through competitive grants and internal call for proposals. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                   Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 1: Basic PE 0601120D8Z / National Defense Education Program (NDEP) Research$$, NULL, 176078000, 178078000, 183492000, NULL, NULL, 6, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 161261000, 159032000, 165488000, 165488000, NULL, 165488000, 188917000, $$This program supports the Department's priorities to improve lethality, warfighting, and readiness by developing America’s future technical workforce poised to create advanced technologies, tools, and capabilities necessary to ensure the U.S. military remains the most powerful and advanced, capable of deterring adversaries and protecting American interests at home and abroad. NDEP is executed by the Office of the Under Secretary of War for Research and Engineering (OUSW(R&E)), and specifically: (1) Ensures the Department’s ability to develop and access high-quality science, technology, engineering, and mathematics (STEM) talent vital to addressing key areas of national defense and supporting the warfighter; (2) Supports the National Defense Strategy to ensure the U.S. maintains its edge in DoW science and technology (S&T) critical technology areas, such as hypersonics, artificial intelligence, and advanced manufacturing; (3) Provides programming across the Pre-K to career education continuum to address critical STEM education and talent development challenges through evidence- based approaches; (4) Engages in assessment and evaluation practices as outlined by the Office of Management and Budget and the Government Accountability Office to ensure efficiency and meritocracy of programming; and (5) Provides open, merit-based programs available to all American learners and educators, to include military-connected students and veterans, ensuring they receive quality education and support and allowing our Nation’s armed service members to remain focused on their warfighting mission. NDEP activities provide authentic DoW-relevant learning experiences through a variety of initiatives in the form of scholarships, internships, enrichment activities, project/research-based competitions, and mentorships. NDEP programs span across all age groups, including Pre-kindergarten through twelfth grade (PreK-12), postsecondary, undergraduate, and graduate students and educators (holistically termed “Pre-K to Career”). The NDEP portfolio includes: the Science, Mathematics, and Research for Transformation (SMART) scholarship-for-service program; joint K-12 STEM education initiatives managed in conjunction with the Tri-Services (New NDEP Pcode Pending); STEM Education and Workforce Development (EWD) efforts at post-secondary levels; and specific Congressionally directed programs, to include the Manufacturing Engineering Education Program (MEEP) per 10 U.S. Code 4843 and additional NDEP funding opportunities in STEM education and workforce development. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                             Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 1: Basic PE 0601120D8Z / National Defense Education Program (NDEP) Research$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_0300_L021$$, $$Defense Information System Network$$, $$proc_dw_0300_ba1$$, $$dw_other$$, 2026, 125292000, 111123000, 100587000, NULL, $${"page": 164, "ba_num": "01", "source": "p1_fy26", "ba_name": "Major equipment", "line_no": "21", "service": "dw", "fy24_qty": null, "fy25_qty": null, "fy27_v27": {"ba": "01", "p1_li": 10}, "appr_code": "0300", "appr_name": "Procurement, Defense-Wide", "fy26_v181": {"li_num": 10, "source": "p1_master_fy26_v181", "source_pdf": "Budget J-Books/FY27/Remaining/FY2027_p1.pdf", "fy26_disc_K": 252370, "fy26_supp_K": 0, "fy26_total_K": 252370, "name_partial": "Defense Information System Network"}, "fy26t_qty": null, "fy26d_cost": 125292000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 252370000, 392650000, 392650000, 0, 392650000, NULL, NULL, $$Budget J-Books/FY27/DW_Procurement/PROC_DISA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0601121A$$, $$Cyber Collaborative Research Alliance$$, $$rdte_army_ba1$$, $$devcom_arl$$, 2026, 5463000, 5459000, 5525000, NULL, $${"act": "01", "ba_raw": "6.1", "source": "r1_fy26", "service": "army", "page_num": 10, "original_pe": "0601121A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) fosters research performed through the Cyber Security Collaborative Research Alliance (CSEC CRA), a competitively selected consortium, formed to advance the theoretical foundations of cyber science in the context of Army networks. This CRA consists of academia, industry and government researchers working jointly with the objective of developing a fundamental understanding of cyber phenomena so that fundamental laws, theories, and theoretically grounded and empirically validated models can be applied to a broad range of Army domains, applications, and environments. This research focuses on three interrelated aspects of cyber security and is conducted using a trans-disciplinary approach that takes into account the human element of the network. The three aspects of cyber that are addressed are: 1) vulnerabilities and risks of cyber networks to malicious activities, 2) anticipating, detecting, and analyzing malicious activities, and 3) agile cyber maneuver to thwart and defeat malicious activities. Overarching goals of cyber security are to significantly decrease the adversary's return on investment when considering cyber attack on Army networks, and minimizing the impact on Army network performance related to implementing cyber security. The CRA research creates a framework that effectively integrates the knowledge of cyber assets and potential adversary capabilities and approaches, and provides defense mechanisms that dynamically adjust to changes related to mission, assets, vulnerability state, and defense mechanisms. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. The FY 2026 request was reduced by $0.054 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, NULL, NULL, NULL, NULL, NULL, 4, $$RDTE - Vol 1 - Budget Activity 1.pdf$$, NULL, FALSE, 5525000, 5463000, NULL, NULL, NULL, NULL, 57000, $$This Program Element (PE) fosters research performed through the Cyber Security Collaborative Research Alliance (CSEC CRA), a competitively selected consortium, formed to advance the theoretical foundations of cyber science in the context of Army networks. This CRA consists of academia, industry and government researchers working jointly with the objective of developing a fundamental understanding of cyber phenomena so that fundamental laws, theories, and theoretically grounded and empirically validated models can be applied to a broad range of Army domains, applications, and environments. This research focuses on three interrelated aspects of cyber security and is conducted using a trans-disciplinary approach that takes into account the human element of the network. The three aspects of cyber that are addressed are: 1) vulnerabilities and risks of cyber networks to malicious activities, 2) anticipating, detecting, and analyzing malicious activities, and 3) agile cyber maneuver to thwart and defeat malicious activities. Overarching goals of cyber security are to significantly decrease the adversary's return on investment when considering cyber attack on Army networks, and minimizing the impact on Army network performance related to implementing cyber security. The CRA research creates a framework that effectively integrates the knowledge of cyber assets and potential adversary capabilities and approaches, and provides defense mechanisms that dynamically adjust to changes related to mission, assets, vulnerability state, and defense mechanisms.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 1.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0601122E$$, $$EMERGING OPPORTUNITIES$$, $$rdte_dw_ba1$$, $$dw_darpa$$, 2026, 360456000, 0, 0, NULL, $${"act": "01", "ba_raw": "6.1", "source": "r1_fy26", "service": "dw", "page_num": 66, "original_pe": "0601122E", "page_header": "Defense-Wide", "fy26_v182_disc_K": 345053, "fy26_v182_supp_K": 12500, "fy26_v182_total_K": 357553, "fy26_v182_note_name": "Research, Development, Test and Evaluation, Defense-Wide for DARPA", "fy26_v182_source_file": "RDTE_Vol1_DARPA_MasterJustificationBook_PB_2027.txt", "fy26_v182_source_line": 1179}$$::jsonb, $$The efforts described in this Program Element (PE) address the Basic Research associated with the Emerging Opportunities Program that provides the technical foundation for long-term National Security enhancement through the discovery of new phenomena and the exploration of the potential of such phenomena for Defense applications. This PE supports the scientific study and experimentation that is the basis for more advanced knowledge and understanding in quantum, electronic, mathematical, information, computer, materials, and medical sciences. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. The Math and Computer Sciences project supports scientific study and experimentation on new mathematical and computational algorithms, models, and mechanisms in support of long-term national security objectives. Modern information technologies, both classical and quantum, and analytic technologies, enable important new military capabilities and drive the productivity gains essential to U.S. economic competitiveness. Conversely, new classes of threats require the creation of fundamentally new mathematical and computational approaches to enhance the software-intensive systems upon which our society depends. The basic research conducted under the Math and Computer Sciences project will produce breakthroughs that enable new capabilities for national and homeland security. The Disruptive Microtechnologies Sciences project supports investigations into materials, devices, and architectures that will enable dramatic improvements versus the current state-of-the-art. This includes developing technology to enable fundamentally new ways of creating useful circuits to enable the next generation of microtechnologies. Areas of focus include photonic circuits that harness the power of light at the chip-scale, quantum circuits that take advantage of the unique properties that quantum offers versus classical computing and sensing, and organic circuits that integrate organic molecules into microtechnologies. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                            Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 1: Basic PE 0601122E / EMERGING OPPORTUNITIES Research The Materials Sciences project provides the fundamental research that underpins the design, development, assembly, and optimization of advanced materials, devices, and systems for DoD applications in areas such as design and simulation of novel materials and structures, energetics, complex hybrid systems, and advanced metrology. The Basic Operational Medical Science project will explore and develop basic research in medical-related information and technology leading to fundamental discoveries, tools, and applications critical to overcoming DoD challenges. This project will address the Department's identified warfighter medical care related to prevention and treatment of infectious disease, real-time healthcare interventions of acute and chronic illness and injury, and interventions for improved warfighter resilience and performance against operational stressors. The Emerging Opportunities Support project contains non-headquarters management costs in support of DARPA functions and activities across the entire Emerging Opportunities PE. These costs include: DARPA classified and unclassified network support and equipment; contractor support; classified program security; building security; commercial transition services that increase the likelihood that DARPA-funded technologies remain in the U.S. and provide new capabilities for national defense; DARPA outreach to universities and industry; external contracting, financial and support fees; Program Manager Intragovernmental Personnel Act (IPA) Funding; Program Managers from other Government Agencies; and similar operating expenses. Agency support is allocated on a pro-rata basis across the Agency's BA1, BA2 and BA3 PEs and, therefore, fluctuates per PE by fiscal year based on the total Agency budget in that fiscal year. Prior to FY 2026, efforts in this PE were funded in PE 0601101E, Defense Research Sciences, and PE 0601117E, Basic Operational Medical Science.$$, NULL, 423322000, 427802000, 436873000, NULL, NULL, 7, $$RDTE_Vol1_DARPA_MasterJustificationBook_PB_2026.pdf$$, $$DARPA$$, FALSE, 0, 357553000, 387633000, 387633000, NULL, 387633000, 445964000, $$The efforts described in this Program Element (PE) address the Basic Research associated with the Emerging Opportunities Program that provides the technical foundation for long-term National Security enhancement through the discovery of new phenomena and the exploration of the potential of such phenomena for Department of War applications. This PE supports the scientific study and experimentation that is the basis for more advanced knowledge and understanding in quantum, electronic, mathematical, information, computer, materials, and medical sciences. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. The Math and Computer Sciences project supports scientific study and experimentation on new mathematical and computational algorithms, models, and mechanisms in support of long-term national security objectives. Modern information technologies, both classical and quantum, and analytic technologies, enable important new military capabilities and drive the productivity gains essential to U.S. economic competitiveness. Conversely, new classes of threats require the creation of fundamentally new mathematical and computational approaches to enhance the software-intensive systems upon which our society depends. The basic research conducted under the Math and Computer Sciences project will produce breakthroughs that enable new capabilities for national and homeland security. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Advanced Research Projects Agency                                            Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 1: Basic PE 0601122E / EMERGING OPPORTUNITIES Research The Disruptive Microtechnologies Sciences project supports investigations into materials, devices, and architectures that will enable dramatic improvements versus the current state-of-the-art. This includes developing technology to enable fundamentally new ways of creating useful circuits to enable the next generation of microtechnologies. Areas of focus include photonic circuits that harness the power of light at the chip-scale, quantum circuits that take advantage of the unique properties that quantum offers versus classical computing and sensing, and organic circuits that integrate organic molecules into microtechnologies. The Materials Sciences project provides the fundamental research that underpins the design, development, assembly, and optimization of advanced materials, devices, and systems for DoW applications in areas such as design and simulation of novel materials and structures, energetics, complex hybrid systems, and advanced metrology. The Basic Operational Medical Science project will explore and develop basic research in medical-related information and technology leading to fundamental discoveries, tools, and applications critical to overcoming DoW challenges. This project will address the Department's identified warfighter medical care related to prevention and treatment of infectious disease, real-time healthcare interventions of acute and chronic illness and injury, and interventions for improved warfighter resilience and performance against operational stressors. The Emerging Opportunities Support project contains management costs in support of DARPA functions and activities across the entire Emerging Opportunities PE. These costs include: DARPA classified and unclassified network support and equipment; contractor support; classified program security; building security; commercial transition services that increase the likelihood that DARPA-funded technologies remain in the U.S. and provide new capabilities for national defense; DARPA outreach to universities and industry; external contracting, financial and support fees; Program Manager Intragovernmental Personnel Act (IPA) Funding; Program Managers from other Government Agencies; and similar operating expenses. Agency support is allocated on a pro-rata basis across the Agency's BA1, BA2 and BA3 PEs and, therefore, fluctuates per PE by fiscal year based on the total Agency budget in that fiscal year. Prior to FY 2026, efforts in this PE were funded in PE 0601101E, Defense Research Sciences, and PE 0601117E, Basic Operational Medical Science.$$, $$Budget J-Books/FY27/DW/RDTE_Vol1_DARPA_MasterJustificationBook_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0601153N$$, $$Defense Research Sciences$$, $$rdte_navy_ba1$$, $$onr$$, 2026, 511163000, 545432000, 496414000, NULL, $${"act": "01", "ba_raw": "6.1", "source": "r1_fy26", "service": "navy", "page_num": 26, "original_pe": "0601153N", "page_header": "Department of the Navy", "fy26_v182_disc_K": 527574, "fy26_v182_supp_K": 8000, "fy26_v182_total_K": 535574, "fy26_v182_note_name": "Research, Development, Test and Evaluation, Navy", "fy26_v182_source_file": "RDTEN_BA1-3_Book.txt", "fy26_v182_source_line": 2773}$$::jsonb, $$The Office of Naval Research (ONR) was established by Congress in 1946 to plan, foster and encourage scientific research in recognition of its paramount importance to the maintenance of American naval power and national security. ONR manages the Department of the Navy's (DON) portfolio of Basic Research (BA1), Applied Research (BA2) and Advanced Technology Development (BA3) investments to ensure naval forces can effectively deter conflict, but when called upon, are equipped and prepared to fight, win and return home safely. This Defense Research Sciences (DRS) Program Element (PE) supports the Basic Research (BA1) portion of the Department of the Navy (DON) science and technology (S&T) portfolio, laying the foundation for new innovative technologies and future capabilities for naval warfighters. Basic research conducted within this PE include theoretical and experimental investigations directed toward increasing our knowledge and understanding of the physical, chemical, engineering, environmental and life sciences. The preponderance of research conducted within this PE is performed by academia and government labs, both of which play significant roles in developing the S&T workforce of tomorrow in addition to delivery new knowledge and scientific discoveries. This PE supports higher guidance defined by the National Defense Strategy, and responds to requirements identified by the Secretary of the Navy (SECNAV) through research priorities set by the Chief of Naval Research (CNR) and coordinated across the Naval Research Enterprise (NRE). Research activities support long-term investments as outlined in an S&T Strategic Plan. The basic research conducted within this PE supports areas of traditional, unique and emerging naval need to help ensure naval operational readiness and unsurpassed warfighting capabilities in the maritime domain. Basic research conducted within this Defense Research Sciences (DRS) PE has been organized around the following research areas of priority naval interest: - Information, Cyber and Spectrum Superiority - Ocean Battlespace Sensing - Mission capable, Persistent & Survivable Naval Platforms - Warfighter Performance Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                            Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 1: Basic              PE 0601153N / Defense Research Sciences Research - Naval Air Warfare and Weapons - Naval Research Laboratory - Base - ONR Global - In-House Laboratory Independent Research Research advancements and fundamental science breakthroughs within these research areas of naval priority interest establish a foundation that provides an opportunity to mature concepts through continued exploration and more narrowly focused applied research applications. The thoughtful, systematic study of fundamental phenomena towards more naval specific environments, applications and warfighting solutions is critical to long-term naval operational and security needs. The basic research conducted within this PE is expected to be at Technology Readiness Level (TRL) 1 (basic principles observed and reported) up to TRL 2 (technology concept and/or application formulation). DRS basic research (BA1) results provide the foundation for later applied research (BA2) and advanced technology development (BA3) solution options for the Navy and Marine Corps. DRS research advancements and technology development accomplishments influence candidate solutions to the Navy and Marine Corps technical and operational challenges experienced by acquisition Programs of Record (PoR) via the Future Naval Capabilities (FNCs) portfolio. DRS research advancements are also fundamentally relevant to more general, fundamental naval warfighting concepts and approaches by opening up new potential warfighting capability options via the Innovative Naval Prototypes (INPs) portfolio. Due to the number of efforts in this PE, the projects described herein are representative of research conducted within this PE.$$, NULL, 544287000, 575770000, 569546000, NULL, NULL, 2, $$RDTEN_BA1-3_Book.pdf$$, NULL, FALSE, 487237000, 535574000, 525399000, 525399000, NULL, 525399000, 559163000, $$The Office of Naval Research (ONR) was established by Congress in 1946 to plan, foster and encourage scientific research in recognition of its paramount importance to the maintenance of American naval power and national security. ONR manages the Department of the Navy's (DON) portfolio of Basic Research (BA1), Applied Research (BA2) and Advanced Technology Development (BA3) investments to ensure naval forces can effectively deter conflict, but when called upon, are equipped and prepared to fight, win and return home safely. This Defense Research Sciences (DRS) Program Element (PE) supports the Basic Research (BA1) portion of the Department of the Navy (DON) science and technology (S&T) portfolio, laying the foundation for new innovative technologies and future capabilities for naval warfighters. Basic research conducted within this PE include theoretical and experimental investigations directed toward increasing our knowledge and understanding of the physical, chemical, engineering, environmental and life sciences. The preponderance of research conducted within this PE is performed by academia and government labs, both of which play significant roles in developing the S&T workforce of tomorrow in addition to delivery new knowledge and scientific discoveries. This PE supports higher guidance defined by the National Defense Strategy, and responds to requirements identified by the Secretary of the Navy (SECNAV) through research priorities set by the Chief of Naval Research (CNR). Research activities support long-term investments as outlined in an S&T Strategic Plan. The basic research conducted within this PE supports areas of traditional, unique and emerging naval need to help ensure naval operational readiness and unsurpassed warfighting capabilities in the maritime domain. Basic research conducted within this Defense Research Sciences (DRS) PE has been organized around the following research areas of priority naval interest: - Information, Cyber and Spectrum Superiority - Ocean Battlespace Sensing - Mission capable, Persistent & Survivable Naval Platforms - Warfighter Performance - Naval Air Warfare and Weapons Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                            Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 1: Basic              PE 0601153N / Defense Research Sciences Research - Naval Research Laboratory - Base - ONR Global - In-House Laboratory Independent Research Research advancements and fundamental science breakthroughs within these research areas of naval priority interest establish a foundation that provides an opportunity to mature concepts through continued exploration and more narrowly focused applied research applications. The thoughtful, systematic study of fundamental phenomena towards more naval specific environments, applications and warfighting solutions is critical to long-term naval operational and security needs. The basic research conducted within this PE is expected to be at Technology Readiness Level (TRL) 1 (basic principles observed and reported) up to TRL 2 (technology concept and/or application formulation). DRS basic research (BA1) results provide the foundation for later applied research (BA2) and advanced technology development (BA3) solution options for the Navy and Marine Corps. DRS research advancements and technology development accomplishments influence candidate solutions to the Navy and Marine Corps technical and operational challenges experienced by acquisition Programs of Record (PoR) via the Future Naval Capabilities (FNCs) portfolio. DRS research advancements are also fundamentally relevant to more general, fundamental naval warfighting concepts and approaches by opening up new potential warfighting capability options via the Innovative Naval Prototypes (INPs) portfolio. Due to the number of efforts in this PE, the projects described herein are representative of research conducted within this PE. The FY 2026 spend plan amount for Research, Development, Test and Evaluation, Navy includes $527,574 thousand of discretionary and $8,000 thousand of mandatory (reconciliation) for a total of $535,574.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA1-3_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_0300_L038$$, $$Fourth Estate Network Optimization (4ENO)$$, $$proc_dw_0300_ba1$$, $$dw_other$$, 2026, 2230000, 2135000, 2191000, NULL, $${"page": 165, "ba_num": "01", "source": "p1_fy26", "ba_name": "Major equipment", "line_no": "38", "service": "dw", "fy24_qty": null, "fy25_qty": null, "fy27_v27": {"ba": "01", "p1_li": 16}, "appr_code": "0300", "appr_name": "Procurement, Defense-Wide", "fy26_v181": {"li_num": 16, "source": "p1_master_fy26_v181", "source_pdf": "Budget J-Books/FY27/Remaining/FY2027_p1.pdf", "fy26_disc_K": 75386, "fy26_supp_K": 0, "fy26_total_K": 75386, "name_partial": "4ENO"}, "fy26t_qty": null, "fy26d_cost": 2230000, "fy26r_cost": 0, "ident_code": ""}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 75386000, 60808000, 60808000, 0, 60808000, NULL, NULL, $$Budget J-Books/FY27/DW_Procurement/PROC_DISA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2031_L005$$, $$SMALL UNMANNED AIRCRAFT SYSTEMS$$, $$proc_army_2031_ba1$$, $$peo_aviation$$, 2026, 0, 49969000, 43514000, NULL, $${"page": 10, "ba_num": "01", "source": "p1_fy26", "ba_name": "Aircraft", "line_no": "5", "service": "army", "fy24_qty": null, "fy25_qty": null, "appr_code": "2031", "appr_name": "Aircraft Procurement, Army", "fy26_v178": {"disc_K": 426029, "li_num": 3, "source": "p40_fy26_v178", "supp_K": 300000, "source_pdf": "uploads/Budget J-Books/FY27/Army/Aircraft_Procurement_Army.txt"}, "fy26t_qty": null, "fy26d_cost": 0, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 190914000, 426029000, 291472000, 291472000, 0, 291472000, NULL, NULL, $$Budget J-Books/FY27/Army/Aircraft_Procurement_Army.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0601228D8Z$$, $$Historically Black Colleges and Universities and Minority-Serving Instit$$, $$rdte_dw_ba1$$, $$dw$$, 2026, 99610000, 97790000, 102292000, NULL, $${"act": "01", "ba_raw": "6.1", "source": "r1_fy26", "service": "dw", "page_num": 66, "original_pe": "0601228D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$The Historically Black Colleges and Universities and Minority-Serving Institutions (HBCU/MI) program provides support in fields of science and engineering that are important to national defense. The Department of Defense (DoD) HBCU/MI Program encourages participation of eligible research institutions. The program is authorized by 10 U.S.C. § 4144. This competitive program provides support through grants, cooperative agreements, or contracts for research, education assistance, and instrumentation purchases. Work in this program provides a foundation to enhance participation of HBCUs/MIs in DoD research. Programs are structured to: build infrastructure; strengthen research and educational opportunities at HBCUs/MIs and increase the number of graduates in the science, technology, engineering, and mathematics (STEM) disciplines; and expand the pool of scientists and engineers to meet future workforce needs. The DoD HBCU/MI Program aligns with the Secretary of Defense priority to rebuild the military. The DoD HBCU/MI Program aligns with the Department’s technology vision through establishing Centers of Excellence and awarding research grants in critical technology areas. The HBCU/MI Program aligns with the Secretary of Defense “Message to the Force” memorandum through its contributions to the defense industrial base and its role in the development of emerging technologies. The DoD HBCU/ MI Program helps to increase the workforce required for DoD through providing internships and fellowships to students and faculty from HBCUs/MIs. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                   Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 1: Basic PE 0601228D8Z / Historically Black Colleges and Universities and Minority-Serving Instit Research                                                                   utions$$, NULL, 99785000, 101718000, 103752000, NULL, NULL, 8, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 98547000, 112992000, 99706000, 99706000, NULL, 99706000, 105828000, $$The Historically Black Colleges and Universities and Minority-Serving Institutions (HBCU/MI) program provides support in fields of science and engineering that are important to national defense. The Department of War (DoW) HBCU/MI Program encourages participation of eligible research institutions. The program is authorized by 10 U.S.C. § 4144. This competitive program provides support through grants, cooperative agreements, or contracts for research, education assistance, and instrumentation purchases. Work in this program provides a foundation to enhance participation of HBCUs/MIs in DoW research. Programs are structured to: build infrastructure; strengthen research and educational opportunities at HBCUs/MIs and increase the number of graduates in the science, technology, engineering, and mathematics (STEM) disciplines; and expand the pool of scientists and engineers to meet future workforce needs. The DoW HBCU/MI Program aligns investments to address the objectives and priorities of the National Security Strategy (NSS), the National Defense Strategy (NDS), and the Under Secretary of War for Research and Engineering memorandum titled “New Vision” for Critical Technology Areas, dated November 13, 2025. The NDS calls for "adopting new advances in technology, like artificial intelligence (AI)" and "reinvest[ing] in U.S. defense production." By training students in critical areas, HBCU/MI Centers of Excellence (COEs) are directly building the expert workforce required to revitalize the U.S. defense industrial base. The DoW HBCU/MI Program further helps to increase the workforce required for DoW through providing internships and fellowships to students and faculty from HBCUs/MIs. The DoW HBCU/MI Program aligns with the Secretary of War “Message to the Force” memorandum and the Under Secretary of War for Research and Engineering critical technology vision (as indicated in the November 2025 memorandum) by establishing Centers of Excellence and awarding research grants in critical technology areas. The DoW HBCU/MI Program has established COEs in biotechnology, quantum science, advanced materials, fully networked C3, aerospace education, research, and innovation, artificial intelligence and machine learning, energy resilience, advanced computing and software, integrated sensors and cyber, and future generation wireless technology. The DoW HBCU/MI Program awards research grants in critical technology areas contributing to the defense industrial base and the development of emerging technologies. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                   Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 1: Basic PE 0601228D8Z / Historically Black Colleges and Universities and Minority-Serving Instit Research                                                                   utions$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0601275A$$, $$Electronic Warfare Basic Research$$, $$rdte_army_ba1$$, $$devcom_arl$$, 2026, 88053000, 0, 0, NULL, $${"act": "01", "ba_raw": "6.1", "source": "r1_fy26", "service": "army", "page_num": 10, "original_pe": "0601275A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) builds fundamental scientific knowledge contributing to the sustainment of United States (US) Army scientific and technological superiority in electronic warfare, electromagnetic spectrum sciences, and associated enabling and supporting technologies. This PE investigates new concepts and technologies for the Army's future force and provides the means to exploit scientific breakthroughs and avoid technological surprises. The research focuses on understanding and exploiting the electromagnetic spectrum to ensure dominance in contested environments. As modern warfare increasingly relies on electronic systems for communication, navigation, and targeting, maintaining superiority in the electromagnetic domain is crucial for mission success. The in-house portion of the program capitalizes on the Army's scientific talent and specialized facilities to transition knowledge and technology into appropriate developmental activities. The extramural program leverages the research efforts of other government agencies, academia, and industry. Work in this PE fosters university and industry-based research to provide a scientific foundation for enabling technologies for future force capabilities by supporting Collaborative Technology Alliances / Collaborative Research Alliances (CTAs/ CRAs). The Army formed CTAs to leverage large investments by universities and by the commercial sector in basic research areas that are of great interest to the Army. CTAs are industry-led partnerships between industry, academia, and the Army to incorporate the practicality of industry, the expansion of the boundaries of knowledge from universities, and Army scientists to shape, mature, and transition technology relevant to the Army mission. CRAs are academia-led partnerships, which leverage the cutting-edge innovation found in the academic environment. Work in the PE complements work in PEs 0602275A (Electronic Warfare Applied Research) and 0603275A (Electronic Warfare Advanced Technology). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 1: Basic             PE 0601275A / Electronic Warfare Basic Research Research The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy.$$, NULL, 80382000, 84115000, 85880000, NULL, NULL, 5, $$RDTE - Vol 1 - Budget Activity 1.pdf$$, NULL, FALSE, NULL, 94862000, 64031000, 64031000, NULL, 64031000, 86854000, $$This Program Element (PE) builds fundamental scientific knowledge contributing to the sustainment of United States (US) Army scientific and technological superiority in electronic warfare, electromagnetic spectrum sciences, and associated enabling and supporting technologies. This PE investigates new concepts and technologies for the Army's future force and provides the means to exploit scientific breakthroughs and avoid technological surprises. The research focuses on understanding and exploiting the electromagnetic spectrum to ensure dominance in contested environments. As modern warfare increasingly relies on electronic systems for communication, navigation, and targeting, maintaining superiority in the electromagnetic domain is crucial for mission success. The in-house portion of the program capitalizes on the Army's scientific talent and specialized facilities to transition knowledge and technology into appropriate developmental activities. The extramural program leverages the research efforts of other government agencies, academia, and industry. Work in this PE fosters university and industry-based research to provide a scientific foundation for enabling technologies for future force capabilities by supporting Collaborative Technology Alliances / Collaborative Research Alliances (CTAs/ CRAs). The Army formed CTAs to leverage large investments by universities and by the commercial sector in basic research areas that are of great interest to the Army. CTAs are industry-led partnerships between industry, academia, and the Army to incorporate the practicality of industry, the expansion of the boundaries of knowledge from universities, and Army scientists to shape, mature, and transition technology relevant to the Army mission. CRAs are academia-led partnerships, which leverage the cutting-edge innovation found in the academic environment. Work in the PE complements work in PEs 0602275A (Electronic Warfare Applied Research) and 0603275A (Electronic Warfare Advanced Technology). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 1: Basic             PE 0601275A / Electronic Warfare Basic Research Research$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 1.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0601384BP$$, $$Chemical and Biological Defense Program$$, $$rdte_dw_ba1$$, $$dw_cbdp$$, 2026, 36582000, 33486000, 37812000, NULL, $${"act": "01", "ba_raw": "6.1", "source": "r1_fy26", "service": "dw", "page_num": 66, "original_pe": "0601384BP", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 24870000, 24008000, 23578000, NULL, NULL, NULL, NULL, NULL, FALSE, 36957000, 28232000, 27425000, 27425000, 0, 27425000, 23410000, $$This program element (PE) resources basic research efforts directed at promoting theoretical and experimental research in Life and Physical Sciences. These efforts are part of an integrated portfolio addressing emerging chemical and biological (CB) threats, and are a key enabler supporting the Understand, Protect, and Mitigate portfolios. Basic research focuses on pursuing fundamental science to advance a greater understanding of threats, improve situational awareness of emerging threats, and support transformative research in emerging research areas that can potentially foster paradigm shifts in the CB defense research arena to a rapid response capability. Individual projects include: - Life Sciences (LF1): Fundamental efforts to understand living systems' response to biological or chemical agents to support detection, diagnostics, protection, and medical treatment (e.g., microbiology, biochemistry, pathogenic mechanisms, cell and molecular biology, immunology, nanoscale science, and information science). - Physical Sciences (PS1): Fundamental scientific phenomena to support the investigation of physical and chemical properties and interactions for enhanced functionalities important to detection, diagnostics, protection, and decontamination (e.g., chemistry, physics, materials science, nanotechnologies, nanoscale science, and environmental science). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Chemical and Biological Defense Program                                         Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 1: Basic PE 0601384BP / Chemical and Biological Defense Program Research$$, $$Budget J-Books/FY27/DW/RDTE_CBDP_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0601601A$$, $$Artificial Intelligence and Machine Learning Basic Research$$, $$rdte_army_ba1$$, $$cft_lrpf$$, 2026, 7012000, 10206000, 10309000, NULL, $${"act": "01", "ba_raw": "6.1", "source": "r1_fy26", "service": "army", "page_num": 10, "original_pe": "0601601A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) executes intramural and extramural basic research in artificial intelligence (AI) and machine learning (ML) to support an AI-enabled Multi- Domain Operations (MDO) Force. The PE includes projects that perform basic research in AI/ML with the potential to impact areas such as: Target Detection using Multiple Cooperative Autonomous Sensors (MCAS); more effective and quicker leader decision-making through use of AI-enhanced Common Operating Procedure (COP); replication of tactical behaviors to enable autonomous capabilities for maneuver; predictive maintenance; Intel support for Operations (specifically in support of long range precision fires); AI-enabled network/cybersecurity; intelligent business and process automation; and medical support. The Army's Artificial Intelligence Integration Center (AI2C) will provide strategic guidance and coordination of these basic research efforts in AI/ML across the Army Modernization enterprise. Work in this PE contributes to the Army Science and Technology (S&T) portfolio and is fully coordinated with efforts in PE 0602180A Artificial Intelligence Technologies and PE 0603040A Artificial Intelligence Advanced Technologies. The cited work is consistent with the Under Secretary of Defense for Research and Engineering S&T focus areas, the Army Modernization Strategy and the Chief Digital and Artificial Intelligence Office.$$, NULL, NULL, NULL, NULL, NULL, NULL, 6, $$RDTE - Vol 1 - Budget Activity 1.pdf$$, NULL, FALSE, 9933000, 17012000, NULL, NULL, NULL, NULL, NULL, $$This Program Element (PE) executes intramural and extramural basic research in artificial intelligence (AI) and machine learning (ML) to support an AI-enabled Multi- Domain Operations (MDO) Force. The PE includes projects that perform basic research in AI/ML with the potential to impact areas such as: Target Detection using Multiple Cooperative Autonomous Sensors (MCAS); more effective and quicker leader decision-making through use of AI-enhanced Common Operating Procedure (COP); replication of tactical behaviors to enable autonomous capabilities for maneuver; predictive maintenance; Intel support for Operations (specifically in support of long range precision fires); AI-enabled network/cybersecurity; intelligent business and process automation; and medical support. The Army's Artificial Intelligence Integration Center (AI2C) will provide strategic guidance and coordination of these basic research efforts in AI/ML across the Army Modernization enterprise. Work in this PE contributes to the Army Science and Technology (S&T) portfolio and is fully coordinated with efforts in PE 0602180A Artificial Intelligence Technologies and PE 0603040A Artificial Intelligence Advanced Technologies.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 1.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602000D8Z$$, $$Joint Munitions Technology$$, $$rdte_dw_ba2$$, $$dw_ousd_re$$, 2026, 19734000, 17025000, 19373000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "dw", "page_num": 66, "original_pe": "0602000D8Z", "page_header": "Defense-Wide", "fy26_v182_disc_K": 18228, "fy26_v182_supp_K": 5940, "fy26_v182_total_K": 24168, "fy26_v182_note_name": "Research, Development, Test & Evaluation, Defense-Wide for Joint Munitions Technology", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 3154}$$::jsonb, $$This program supports the Department's priorities to reestablish deterrence by building munitions technology advantages that solve operational and mission-focused challenges. The Joint Enhanced Munitions Technology Program (JEMTP), within the Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)) was established to develop and demonstrate joint munitions enhancing technologies (energetics, warheads, propulsion systems, advanced lethality mechanisms, fuzes and fuze components, and target detection) to provide future kinetic fires capabilities and ensure advantage for U.S. warfighters. The program’s plans and investments are informed by threat-opportunity based analyses from Joint Force campaign scenarios. The JEMTP activities within Program Element 0602000D8Z are executed under two Project Codes: 076 - Enhanced Munitions and 355 – Energetics Technologies. These advancements through JEMTP provide foundational capabilities that impact a wide range of munitions including One-Way Attack, Counter-small UAS technologies, and munitions that may be utilized for Homeland Missile Defense. The JEMTP program also provides technologies that support munitions and energetics organic Industrial Base resiliency and increased production rates. Project Code 076 - The Enhanced Munitions Project focuses on investments of novel fuzing, power sources, target detection sensing technologies, and counter- countermeasure technologies that are enablers for enhancing future munition lethality and survivability. Alternative Positioning, Navigation, & Timing (Alt-PNT) is a new project focus starting in FY26. Alt-PNT technology investments will enable munitions to maintain effective operations in contested scenarios. Project Code 355 - This program executes the Energetics Technology project focused on investigation and research of energetic materials (ingredients and formulations) to enhance munitions capability and address supply chain resilience. The Energetics Technology Project supports and enables DoD Service strategies and roadmaps for advanced energetics material synthesis and formulation development; to accelerate the application and transition of advanced energetics materials into DoD munitions and the energetics manufacturing base; and to apply modern, agile energetics processing and manufacturing technologies. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                              Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:          PE 0602000D8Z / Joint Munitions Technology Applied Research$$, NULL, 39112000, 46630000, 49519000, NULL, NULL, 10, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 19279000, 24168000, 32145000, 32145000, NULL, 32145000, 52281000, $$This program supports the Department's priorities to reestablish deterrence by building munitions technology advantages that solve operational and mission-focused challenges. The Joint Enhanced Munitions Technology Program (JEMTP), within the Office of the Under Secretary of War for Research and Engineering (OUSW(R&E)) was established to develop and demonstrate joint munitions enhancing technologies (energetics, warheads, propulsion systems, advanced lethality mechanisms, fuzes and fuze components, and target detection) to provide future kinetic fires capabilities and ensure advantage for U.S. warfighters. The program’s plans and investments are informed by threat-opportunity based analyses from Joint Force campaign scenarios. The advancements through JEMTP provide foundational capabilities that impact a wide range of munitions including One-Way Attack, Counter-small UAS technologies, and munitions that may be utilized for Homeland Missile Defense. The JEMTP program also provides technologies that support munitions and energetics organic Industrial Base resiliency and increased production rates. The Enhanced Munitions Project focuses on investments of novel fuzing, power sources, target detection sensing technologies, and counter-countermeasure technologies that are enablers for enhancing future munition lethality and survivability. Alternative Positioning, Navigation, & Timing (Alt-PNT) is a new project starting in FY 2026, that reflects Department priority to develop technologies to address challenges to the Joint Force’s contested navigation warfare (NAVWAR) environment. Alt- PNT technology investments will enable munitions to maintain effective operations in contested scenarios. The Energetics Technologies Project focuses on investigation and research of energetic materials (ingredients and formulations) to enhance munitions capability and address supply chain resilience. The Energetics Technology Project supports and enables DoW Service strategies and roadmaps for advanced energetics material synthesis and formulation development; to accelerate the application and transition of advanced energetics materials into DoW munitions and the energetics manufacturing base; and to apply modern, agile energetics processing and manufacturing technologies. The FY 2026 spend plan amount for Research, Development, Test & Evaluation, Defense-Wide for Joint Munitions Technology includes $18,228 thousand of discretionary and $5,940 thousand of mandatory (reconciliation) for a total of $24,168 thousand. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:         PE 0602000D8Z / Joint Munitions Technology Applied Research$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_0300_L098$$, $$Unmanned ISR$$, $$proc_dw_0300_ba2$$, $$dw_socom$$, 2026, 2031000, 5915000, 5259000, NULL, $${"page": 168, "ba_num": "02", "source": "p1_fy26", "ba_name": "Special Operations Command", "line_no": "98", "service": "dw", "fy24_qty": null, "fy25_qty": null, "fy27_v27": {"ba": "02", "p1_li": 52}, "appr_code": "0300", "appr_name": "Procurement, Defense-Wide", "fy26_v181": {"li_num": 52, "source": "p1_master_fy26_v181", "source_pdf": "Budget J-Books/FY27/Remaining/FY2027_p1.pdf", "fy26_disc_K": 9358, "fy26_supp_K": 0, "fy26_total_K": 9358, "name_partial": "Unmanned ISR"}, "fy26t_qty": null, "fy26d_cost": 2031000, "fy26r_cost": 0, "ident_code": ""}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 9358000, 0, 0, 0, 0, NULL, NULL, $$Budget J-Books/FY27/DW_Procurement/PROC_SOCOM_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_0300_L108$$, $$Intelligence Systems$$, $$proc_dw_0300_ba2$$, $$dw_socom$$, 2026, 2824000, 5718000, 3918000, NULL, $${"page": 170, "ba_num": "02", "source": "p1_fy26", "ba_name": "Special Operations Command", "line_no": "108", "service": "dw", "fy24_qty": null, "fy25_qty": null, "fy27_v27": {"ba": "02", "p1_li": 62}, "appr_code": "0300", "appr_name": "Procurement, Defense-Wide", "fy26_v181": {"li_num": 62, "source": "p1_master_fy26_v181", "source_pdf": "Budget J-Books/FY27/Remaining/FY2027_p1.pdf", "fy26_disc_K": 223226, "fy26_supp_K": 0, "fy26_total_K": 223226, "name_partial": "Intelligence Systems"}, "fy26t_qty": null, "fy26d_cost": 2824000, "fy26r_cost": 0, "ident_code": ""}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 223226000, 319241000, 319241000, 0, 319241000, NULL, NULL, $$Budget J-Books/FY27/DW_Procurement/PROC_SOCOM_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_0300_L115_v27$$, $$Operational Enhancements$$, $$proc_dw_0300_ba2$$, $$dw_other$$, 2027, 0, 0, 0, NULL, $${"fy27_v27": {"ba": "02", "kind": "INSERT-new-row", "p1_li": 71}, "fy26_v181": {"li_num": 71, "source": "p1_master_fy26_v181", "source_pdf": "Budget J-Books/FY27/Remaining/FY2027_p1.pdf", "fy26_disc_K": 352100, "fy26_supp_K": 115653, "fy26_total_K": 467753, "name_partial": "Operational Enhancements"}}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 467753000, 360595000, 360595000, 0, 360595000, NULL, NULL, $$Budget J-Books/FY27/DW_Procurement/PROC_SOCOM_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602002A$$, $$Army Agile Innovation and Development-Applied Research$$, $$rdte_army_ba2$$, $$devcom$$, 2026, 9455000, 964000, 1000000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 10, "original_pe": "0602002A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) funds the Army's goal of assessing and seeding innovative research solutions to achieve future force modernization. Critical technologies that allow for technological superiority are increasingly dual-use or developed in academia-led partnerships that leverage cutting edge innovation. Cross-cutting modernization initiatives leverage strategic partnerships and foster an environment to bring knowledge and expertise to demonstrate breakthrough and innovative technologies that will benefit the warfighter. These collaborations bring new ways of doing business to assess and evaluate emerging technologies with high payoff potential to address current technology shortfalls. Leveraging other innovative mechanisms, to include accelerators, incubators, and other technology accelerants, to enhance innovation is part of the overall innovation strategy. Innovation includes not only hardware and physical products but also software, software development, artificial intelligence (AI) and machine learning; all are stand-alone initiatives that are part of broader innovation to programs and technology development. Through the Army's Innovation Oversight Board, Army senior leadership approves innovation projects in the budget year and year of execution based on priority and opportunity, ensuring that innovations have a high potential for filling capability gaps and transitioning to Army Science and Technology (S&T) projects to inform an optimal technology investment strategy and rapidly deliver capabilities to the soldier. Work is performed by the United States Army Combat Capabilities Development Command (DEVCOM), Army Artificial Intelligence Integration Center (AI2C), the Engineering Research and Development Center, Space and Missile Defense Technical Center, and the United States Army Research Institute for the Behavioral and Social Sciences. The FY 2026 request was reduced by $0.078 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.029 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                           Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied         PE 0602002A / Army Agile Innovation and Development-Applied Research Research$$, NULL, NULL, NULL, NULL, NULL, NULL, 7, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, 973000, 9455000, NULL, NULL, NULL, NULL, NULL, $$This Program Element (PE) funds the Army's goal of assessing and seeding innovative research solutions to achieve future force modernization. Critical technologies that allow for technological superiority are increasingly dual-use or developed in academia-led partnerships that leverage cutting edge innovation. Cross-cutting modernization initiatives leverage strategic partnerships and foster an environment to bring knowledge and expertise to demonstrate breakthrough and innovative technologies that will benefit the warfighter. These collaborations bring new ways of doing business to assess and evaluate emerging technologies with high payoff potential to address current technology shortfalls. Leveraging other innovative mechanisms, to include accelerators, incubators, and other technology accelerants, to enhance innovation is part of the overall innovation strategy. Innovation includes not only hardware and physical products but also software, software development, artificial intelligence (AI) and machine learning; all are stand-alone initiatives that are part of broader innovation to programs and technology development. Through the Army's Innovation Oversight Board, Army senior leadership approves innovation projects in the budget year and year of execution based on priority and opportunity, ensuring that innovations have a high potential for filling capability gaps and transitioning to Army Science and Technology (S&T) projects to inform an optimal technology investment strategy and rapidly deliver capabilities to the soldier. Work is performed by the United States Army Combat Capabilities Development Command (DEVCOM), Army Artificial Intelligence Integration Center (AI2C), the Engineering Research and Development Center, Space and Missile Defense Technical Center, and the United States Army Research Institute for the Behavioral and Social Sciences.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 2.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602022F$$, $$University Affiliated Research Center (UARC) - Tactical Autonomy$$, $$rdte_af_ba2$$, $$afrl_afosr$$, 2026, 6294000, 6180000, 8225000, NULL, $${"ba_raw": "6.2", "source": "af_r1_fy26", "original_pe": "0602022F"}$$::jsonb, $$The Tactical Autonomy University Affiliated Research Center (UARC) supports a consortium performing innovative research to advance the state of the art as well as cultivate awareness of and expertise in the field of tactical autonomy. Research topics of interest include, but are not limited to, the following: Trust in Mission Autonomy, Collaboration between Platforms, and Human Machine Teaming. Funds in this program element are planned to investigate, design, develop, digitize, and/or analyze specified technology advancements in air, space, ground, sea, and/or cyber domains. This research will address factors that have complicated the deployment and adoption of autonomous technologies such as trust in mission autonomy, collaboration between platforms, and human-machine teaming. Research will also seek to integrate autonomous technologies with advanced battle management systems. This research initiative will support the Department of Defense Science, Technology, Engineering, and Mathematics (STEM) Strategic Plan and the Air and Space STEM Outreach Strategic Plan by establishing long-term core research expertise in tactical autonomy that will leverage scientific and engineering capabilities among the consortium of contributing universities. Tactical autonomy will be a critical technology in prolonged great power conflict because the development of autonomous systems is a realistic approach to counter an adversary approaching parity in conventional strength in theatre, and tactical autonomy will enable warfighting capability in an environment where command and control may be disrupted by cyber or electronic warfare effects. Research will produce creative solutions to optimize the capabilities of reliable data-driven autonomous platforms capable of operating in environments well suited to uncrewed systems, such as persistent defensive or force protection-related missions, or in high-risk environments such as heavy anti-access or Nuclear, Chemical, Biological (NBC) affected settings. One of the foremost advantages of the United States in technological competition is its advanced university-based scientific research institutions. This research initiative will strengthen the universities' scientific and engineering capabilities, advance the early career development of STEM students, leverage the research contributions of university faculty, and expand the pipeline of STEM graduates with national security experience for the government and the private-sector defense industrial base. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied        PE 0602022F / University Affiliated Research Center (UARC) - Tactical Autonomy Research$$, NULL, 0, 0, 0, NULL, NULL, 4, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 7924000, 6208000, 0, 0, 0, 0, 0, $$The Tactical Autonomy University Affiliated Research Center (UARC) supports a consortium performing innovative research to advance the state of the art as well as cultivate awareness of and expertise in the field of tactical autonomy. Research topics of interest include, but are not limited to, the following: Trust in Mission Autonomy, Collaboration between Platforms, and Human Machine Teaming. This program is accomplished by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This research initiative supports the Department of War (DoD) and DAF Science, Technology, Engineering, and Mathematics (STEM) Strategic Plans by establishing sustained research expertise in tactical autonomy through a consortium of leading universities. It will advance autonomous systems critical for future conflicts, especially where conventional strength is contested or command and control is degraded by cyber or electronic warfare. In addition to advancing defense technology, it will strengthen university research capacity, support early-career STEM development, and grow a pipeline of graduates equipped with national security expertise to serve in both government and the defense industrial base. Funds in this program element are planned to investigate, design, develop, digitize, and/or analyze specified technology advancements in air, space, ground, sea, and/or cyber domains. In order to manage, execute, and deliver science and technology capabilities, this program element may include: necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, etc. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied      PE 0602022F / University Affiliated Research Center (UARC) - Tactical Autonomy Research$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602023E$$, $$ACCESS AND AWARENESS$$, $$rdte_dw_ba2$$, $$dw_darpa$$, 2026, 100791000, 0, 0, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "dw", "page_num": 66, "original_pe": "0602023E", "page_header": "Defense-Wide", "fy26_v182_disc_K": 98269, "fy26_v182_supp_K": 7000, "fy26_v182_total_K": 105269, "fy26_v182_note_name": "Research, Development, Test and Evaluation, Defense-Wide for DARPA", "fy26_v182_source_file": "RDTE_Vol1_DARPA_MasterJustificationBook_PB_2027.txt", "fy26_v182_source_line": 2464}$$::jsonb, $$The efforts described in this Program Element (PE) address the Applied Research associated with the Access and Awareness Program that is directed toward the development and application of technologies that ensure physical or virtual presence where and when necessary and that collect, integrate, or disseminate data and/or knowledge. There is strong interest in the development and application of advanced, innovative autonomy, computing, and communications technologies. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. The All Domain Tactical Technologies project examines and evaluates emerging technologies and system concepts for developing technologies for enhancing U.S. military effectiveness and survivability in operations across all domains. Enabling and novel technologies include concepts for expanding the envelope of operational naval capabilities to include the entire sea column such as improved situational awareness over large maritime environments, ship self-defense techniques, novel underwater propulsion modalities, high speed underwater vessels, improved techniques for underwater object detection and discrimination, long endurance unmanned surface vehicles, methods and techniques for servicing assets throughout the sea column, and high bandwidth communications. This project will also examine methods and architectures for distributing maritime operations to enable a more agile, survivable, and cost-effective fleet. Technologies will be studied for enhancing U.S. military effectiveness and survivability in ground operations ranging from traditional threats to military operations against irregular forces that can employ disruptive or catastrophic capabilities, or disrupt stabilization operations, including competing in underground spaces. Programs in this project will break the relative symmetry of land combat to give U.S. forces a decided advantage in the current and future ground battlefield. Aeronautics and space technology efforts studied will address high payoff opportunities that dramatically reduce costs associated with advanced aeronautical and space systems and/or provide revolutionary new system capabilities for satisfying current and projected military mission requirements. This includes advanced technology studies of revolutionary propulsion, vehicle, and launch concepts, sophisticated fabrication methods, and examination of novel materials and enabling technologies for aeronautics and space system applications. Studies that also fundamentally change the calculus of battle including consideration of a mix of assets, platforms that are potentially disposable or with limited lifespans, and autonomous integration of space and air platforms in the tactical battlespace are included. The Access and Awareness Support project contains non-headquarters management costs in support of DARPA functions and activities across the entire Access and Awareness PE. These costs include: DARPA classified and unclassified network support and equipment; contractor support; classified program security; building security; commercial transition services that increase the likelihood that DARPA-funded technologies remain in the U.S. and provide new capabilities for national defense; DARPA outreach to universities and industry; external contracting, financial and support fees; Program Manager Intragovernmental Personnel Act (IPA) Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                    Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:          PE 0602023E / ACCESS AND AWARENESS Applied Research Funding; Program Managers from other Government Agencies; and similar operating expenses. Agency support is allocated on a pro-rata basis across the Agency's BA1, BA2 and BA3 PEs and, therefore, fluctuates per PE by fiscal year based on the total Agency budget in that fiscal year. Prior to FY 2026, efforts in this PE were funded in PE 0602702E, Tactical Technology.$$, NULL, 192689000, 224907000, 232945000, NULL, NULL, 11, $$RDTE_Vol1_DARPA_MasterJustificationBook_PB_2026.pdf$$, $$DARPA$$, FALSE, 0, 105269000, 110096000, 110096000, NULL, 110096000, 237009000, $$The efforts described in this Program Element (PE) address the Applied Research associated with the Access and Awareness Program that is directed toward the development and application of technologies that ensure physical or virtual presence where and when necessary and that collect, integrate, or disseminate data and/or knowledge. There is strong interest in the development and application of advanced, innovative autonomy, computing, and communications technologies. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. The All Domain Tactical Technologies project examines and evaluates emerging technologies and system concepts for developing technologies for enhancing U.S. military effectiveness and survivability in operations across all domains. Enabling and novel technologies include concepts for expanding the envelope of operational naval capabilities to include the entire sea column such as improved situational awareness over large maritime environments, ship self-defense techniques, novel underwater propulsion modalities, high speed underwater vessels, improved techniques for underwater object detection and discrimination, long endurance unmanned surface vehicles, methods and techniques for servicing assets throughout the sea column, and high bandwidth communications. This project will also examine methods and architectures for distributing maritime operations to enable a more agile, survivable, and cost-effective fleet. Technologies will be studied for enhancing U.S. military effectiveness and survivability in ground operations ranging from traditional threats to military operations against irregular forces that can employ disruptive or catastrophic capabilities, or disrupt stabilization operations, including competing in underground spaces. Programs in this project will break the relative symmetry of land combat to strengthen and maintain U.S. forces' decisive advantages in the current and future ground battlefield. Aeronautics and space technology efforts studied will address high payoff opportunities that dramatically reduce costs associated with advanced aeronautical and space systems and/or provide revolutionary new system capabilities for satisfying current and projected military mission requirements. This includes advanced technology studies of revolutionary propulsion, vehicle, and launch concepts, sophisticated fabrication methods, and examination of novel materials and enabling technologies for aeronautics and space system applications. Studies that also fundamentally change the calculus of battle including consideration of a mix of assets, platforms that are potentially disposable or with limited lifespans, and autonomous integration of space and air platforms in the tactical battlespace are included. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Advanced Research Projects Agency                                        Date: April 2026 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:                PE 0602023E / ACCESS AND AWARENESS Applied Research The Access and Awareness Support project contains management costs in support of DARPA functions and activities across the entire Access and Awareness PE. These costs include: DARPA classified and unclassified network support and equipment; contractor support; classified program security; building security; commercial transition services that increase the likelihood that DARPA-funded technologies remain in the U.S. and provide new capabilities for national defense; DARPA outreach to universities and industry; external contracting, financial and support fees; Program Manager Intragovernmental Personnel Act (IPA) Funding; Program Managers from other Government Agencies; and similar operating expenses. Agency support is allocated on a pro-rata basis across the Agency's BA1, BA2 and BA3 PEs and, therefore, fluctuates per PE by fiscal year based on the total Agency budget in that fiscal year. Prior to FY 2026, efforts in this PE were funded in PE 0602702E, Tactical Technology.$$, $$Budget J-Books/FY27/DW/RDTE_Vol1_DARPA_MasterJustificationBook_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602024E$$, $$WARFIGHTING PERFORMANCE$$, $$rdte_dw_ba2$$, $$dw_darpa$$, 2026, 278121000, 0, 0, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "dw", "page_num": 66, "original_pe": "0602024E", "page_header": "Defense-Wide", "fy26_v182_disc_K": 307727, "fy26_v182_supp_K": 87500, "fy26_v182_total_K": 395227, "fy26_v182_note_name": "Research, Development, Test and Evaluation, Defense-Wide for DARPA", "fy26_v182_source_file": "RDTE_Vol1_DARPA_MasterJustificationBook_PB_2027.txt", "fy26_v182_source_line": 2921}$$::jsonb, $$The efforts described in this Program Element (PE) address the Applied Research associated with the Warfighting Performance program that is focused on developing biologically based materials and biological technologies that make possible a wide range of new military capabilities. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. The Biologically Based Materials and Devices project will leverage the growing application space of the biological sciences for the development of new DoD capabilities to improve the sustainability of warfighters and operational platforms in varied domains. This project will develop solutions for critical resource processing, materials development, threat detection and characterization, and warfighter resilience to infectious disease. The materials and technologies developed through this project will protect and sustain warfighters and operations in austere conditions, enhancing warfighter resiliency and lethality. The Biomedical Technology project focuses on applied research for medical related technologies that will maintain warfighter health and performance before, during, or after operations. Successful technologies within this project will maintain warfighter health against emerging threats through novel biothreat detection, rapid medical countermeasure identification and development, and distributed production of effective therapeutics. In-theater, warfighter health will be maintained through the development of field-relevant technologies such as reliable and accessible critical medical resources, novel detection and protection capabilities, and rapid, effective triage of battlefield injuries. Technologies are also being developed to provide new capabilities for warfighter recovery from sustained injury. Additionally, this project will improve warfighter readiness by characterizing and assaying physical and cognitive performance to drive data-driven awareness. The Warfighting Performance Support project contains non-headquarters management costs in support of DARPA functions and activities across the entire Warfighting Performance PE. These costs include: DARPA classified and unclassified network support and equipment; contractor support; classified program security; building security; commercial transition services that increase the likelihood that DARPA-funded technologies remain in the U.S. and provide new capabilities for national defense; DARPA outreach to universities and industry; external contracting, financial and support fees; Program Manager Intragovernmental Personnel Act (IPA) Funding; Program Managers from other Government Agencies; and similar operating expenses. Agency support is allocated on a pro-rata basis across the Agency's BA1, BA2 and BA3 PEs and, therefore, fluctuates per PE by fiscal year based on the total Agency budget in that fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                    Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:         PE 0602024E / WARFIGHTING PERFORMANCE Applied Research Prior to FY 2026, efforts in this PE were funded in PE 0602715E, Materials and Biological Technology, and PE 0602115E, Biomedical Technology.$$, NULL, 381379000, 407087000, 412853000, NULL, NULL, 12, $$RDTE_Vol1_DARPA_MasterJustificationBook_PB_2026.pdf$$, $$DARPA$$, FALSE, 0, 395227000, 364141000, 364141000, NULL, 364141000, 419202000, $$The efforts described in this Program Element (PE) address the Applied Research associated with the Warfighting Performance program that is focused on developing biologically based materials and biological technologies that make possible a wide range of new military capabilities. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. The Biologically Based Materials and Devices project will leverage the growing application space of the biological sciences for the development of new DoW capabilities to improve the sustainability of warfighters and operational platforms in varied domains. This project will develop solutions for critical resource processing, materials development, threat detection and characterization, and warfighter resilience to infectious disease. The materials and technologies developed through this project will protect and sustain warfighters and operations in austere conditions, enhancing warfighter resiliency and lethality. The Biomedical Technology project focuses on applied research for medical related technologies that will maintain warfighter health and performance before, during, or after operations. Successful technologies within this project will maintain warfighter health against emerging threats through novel biothreat detection, rapid medical countermeasure identification and development, and distributed production of effective therapeutics. In-theater, warfighter health will be maintained through the development of field-relevant technologies such as reliable and accessible critical medical resources, novel detection and protection capabilities for traumatic brain injury, and rapid, effective triage of battlefield injuries. Additionally, this project will improve warfighter readiness by characterizing and assaying physical and cognitive performance to drive data-driven awareness. The Warfighting Performance Support project contains management costs in support of DARPA functions and activities across the entire Warfighting Performance PE. These costs include: DARPA classified and unclassified network support and equipment; contractor support; classified program security; building security; commercial Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Advanced Research Projects Agency                                          Date: April 2026 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:                PE 0602024E / WARFIGHTING PERFORMANCE Applied Research transition services that increase the likelihood that DARPA-funded technologies remain in the U.S. and provide new capabilities for national defense; DARPA outreach to universities and industry; external contracting, financial and support fees; Program Manager Intragovernmental Personnel Act (IPA) Funding; Program Managers from other Government Agencies; and similar operating expenses. Agency support is allocated on a pro-rata basis across the Agency's BA1, BA2 and BA3 PEs and, therefore, fluctuates per PE by fiscal year based on the total Agency budget in that fiscal year. Prior to FY 2026, efforts in this PE were funded in PE 0602715E, Materials and Biological Technology, and PE 0602115E, Biomedical Technology.$$, $$Budget J-Books/FY27/DW/RDTE_Vol1_DARPA_MasterJustificationBook_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602025E$$, $$MAKING, MAINTAINING, SUPPLY CHAIN AND LOGISTICS$$, $$rdte_dw_ba2$$, $$dw_darpa$$, 2026, 1597049000, 0, 0, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "dw", "page_num": 66, "original_pe": "0602025E", "page_header": "Defense-Wide", "fy26_v182_disc_K": 1318411, "fy26_v182_supp_K": 250000, "fy26_v182_total_K": 1568411, "fy26_v182_note_name": "Research, Development, Test and Evaluation, Defense-Wide for DARPA", "fy26_v182_source_file": "RDTE_Vol1_DARPA_MasterJustificationBook_PB_2027.txt", "fy26_v182_source_line": 4013}$$::jsonb, $$The efforts described in this Program Element (PE) address the Applied Research associated with the Making, Maintaining, Supply Chain and Logistics Program that is directed toward needed technical innovations involved with preserving a healthy, responsive technology supply chain and its associated logistics. This PE also supports the applied research associated with novel techniques in materials processing to include the discovery of said materials and doing so in an environmentally stable fashion. It also includes the development of advanced electronics and disruptive microtechnologies to include advanced manufacturing and fabrication tools, built-in-test, and new circuit materials and topologies. The Quantum Technologies project addresses the Applied Research associated with the development and evaluation of emerging technologies and system concepts that exploit or employ quantum technology and phenomenon for quantum computing and networking to include hardware, software, relevant protocols, and commercialization prospects. This PE also supports innovation and incubation of advanced quantum hardware, architectures, software, and design automation for computing, networking, and sensing. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                            Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:              PE 0602025E / MAKING, MAINTAINING, SUPPLY CHAIN and LOGISTICS Applied Research The major goal of the Materials Processing Technology project is to develop novel materials, fabrication and processing techniques, models, devices and components that will increase the performance, and/or enable new missions for military platforms and systems that can be manufactured at commercial scales. Included in this project are efforts across a wide range of technology areas including manufacturing, electronics, sensors, optics, and complex and autonomous systems. The Disruptive Microtechnologies project continues advancement in microelectronics, including electronic and optoelectronic devices, semiconductor device design and fabrication, and new materials and material structures. This includes developing next generation photonics, quantum, and organic circuits; developing new additive, subtractive, and combination fabrication tools that minimize waste and optimize performance; and new concepts in design, integration, and hardware security that leverages commercial scaling while preserving the superiority of defense systems. In doing so, this area will create disruptive opportunities and prevent the surprise associated with the unintended consequences of technology development. The Electronic Technology project supports pursues materials, devices, and architectures that will enable dramatic improvements versus the current state-of-the-art. Areas of particular emphasis of this work include the development of techniques for advanced fabrication and test and the development of technologies that support electronics reuse and recycling. These technologies will reduce the barriers to designing and fabricating advanced technologies and exploit improved manufacturing techniques to provide these advanced technologies faster and cheaper to the end users. The Cyber Security project is developing the computing, networking, and cyber security technologies required to protect Department of Defense, U.S. Government, and U.S. civilian information, information infrastructure, cyber-physical and embedded systems, critical infrastructure, and other computation-intensive mission-critical systems. Information technologies enable important existing and new military capabilities and drive the productivity gains essential to U.S. industry. Meanwhile, cyber threats grow in sophistication and number, and put sensitive data, classified computer programs, mission-critical information systems, and U.S. economic competitiveness at risk. The technologies developed in this project will enhance the resilience of information systems to current and emerging cyber threats; enable broad situational awareness of the cyber domain; and provide the basis for accurate, calibrated, and safe cyber response. The Artificial Intelligence and Human-Machine Symbiosis project develops technologies to enable machines to function not only as tools that facilitate human action but also as trustworthy partners to human operators. Of particular interest are systems that can understand human language, extract information, and reliably categorize content contained in diverse media; answer questions, reach conclusions, and propose explanations; and learn, reason, and apply knowledge gained through experience to respond intelligently to new and unforeseen events. Enabling computing systems with such human-like intelligence is now of critical importance because the tempo of military operations in emerging domains exceeds that at which unaided humans can orient, understand, and act. The technologies developed in this project will enable warfighters to make better decisions in complex, time-critical, battlefield environments with greater efficiency and confidence; and autonomous systems and intelligent computational agents to perform critical missions in contested and adversarial physical and virtual environments safely and reliably. The Making, Maintaining, Supply Chain and Logistics Support project contains non-headquarters management costs in support of DARPA functions and activities across the entire Making, Maintaining, Supply Chain and Logistics PE. These costs include: DARPA classified and unclassified network support and equipment; contractor support; classified program security; building security; commercial transition services that increase the likelihood that DARPA-funded technologies remain in the U.S. and provide new capabilities for national defense; DARPA outreach to universities and industry; external contracting, financial and support fees; Program Manager Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                    Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:          PE 0602025E / MAKING, MAINTAINING, SUPPLY CHAIN and LOGISTICS Applied Research Intragovernmental Personnel Act (IPA) Funding; Program Managers from other Government Agencies; and similar operating expenses. Agency support is allocated on a pro-rata basis across the Agency's BA1, BA2 and BA3 PEs and, therefore, fluctuates per PE by fiscal year based on the total Agency budget in that fiscal year. Prior to FY 2026, efforts in this PE were funded in PE 0602715E, Materials and Biological Technology, PE 0602716E, Electronics Technology, and PE 0602303E, Information & Communications Technology.$$, NULL, 1484421000, 1121759000, 1166547000, NULL, NULL, 13, $$RDTE_Vol1_DARPA_MasterJustificationBook_PB_2026.pdf$$, $$DARPA$$, FALSE, 0, 1568411000, 1624523000, 1624523000, NULL, 1624523000, 1185521000, $$The efforts described in this Program Element (PE) address the Applied Research associated with the Making, Maintaining, Supply Chain and Logistics Program that is directed toward needed technical innovations involved with preserving a healthy, responsive technology supply chain and its associated logistics. This PE also supports the applied research associated with novel techniques in materials processing to include the discovery of said materials and doing so in an environmentally stable fashion. It also includes the development of advanced electronics and disruptive microtechnologies to include advanced manufacturing and fabrication tools, built-in-test, and new circuit materials and topologies. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Advanced Research Projects Agency                                          Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:          PE 0602025E / MAKING, MAINTAINING, SUPPLY CHAIN AND LOGISTICS Applied Research The Quantum Technologies project addresses the Applied Research associated with the development and evaluation of emerging technologies and system concepts that exploit or employ quantum technology and phenomenon for quantum computing and networking to include hardware, software, relevant protocols, and commercialization prospects. This PE also supports innovation and incubation of advanced quantum hardware, architectures, software, and design automation for computing, networking, and sensing. The major goal of the Materials Processing Technology project is to develop novel materials, fabrication and processing techniques, models, devices and components that will increase the performance, and/or enable new missions for military platforms and systems that can be manufactured at commercial scales. Included in this project are efforts across a wide range of technology areas including manufacturing, electronics, sensors, optics, and complex and autonomous systems. The Disruptive Microtechnologies project continues advancement in microelectronics, including electronic and optoelectronic devices, semiconductor device design and fabrication, and new materials and material structures. This includes developing next generation photonics, quantum, and organic circuits; developing new additive, subtractive, and combination fabrication tools that minimize waste and optimize performance; and new concepts in design, integration, and hardware security that leverages commercial scaling while preserving the superiority of defense systems. In doing so, this area will create disruptive opportunities and prevent the surprise associated with the unintended consequences of technology development. The Electronic Technology project pursues materials, devices, and architectures that will enable dramatic improvements over the current state-of-the-art. Areas of particular emphasis of this work include the development of techniques for advanced fabrication and test and the development of technologies that support electronics reuse and recycling. These technologies will reduce the barriers to designing and fabricating advanced technologies and exploit improved manufacturing techniques to provide these advanced technologies faster and cheaper to the warfighter. The Cyber Security project is developing the computing, networking, and cyber security technologies required to protect Department of War, U.S. Government, and U.S. civilian information, information infrastructure, cyber-physical and embedded systems, critical infrastructure, and other computation-intensive mission-critical systems. Information technologies enable important existing and new military capabilities and drive the productivity gains essential to U.S. industry. Meanwhile, cyber threats grow in sophistication and number, and put data, computer programs, key information systems, and U.S. economic competitiveness at risk. The technologies developed in this project will enhance the resilience of information systems to current and emerging cyber threats; enable broad situational awareness of the cyber domain; and provide the basis for accurate, calibrated, and safe cyber response. The Artificial Intelligence and Human-Machine Symbiosis project develops technologies to enable machines to function not only as tools that facilitate human action but also as trustworthy partners to human operators. Of particular interest are systems that can understand human language, extract information, and reliably categorize content contained in diverse media; answer questions, reach conclusions, and propose explanations; and learn, reason, and apply knowledge gained through experience to respond intelligently to new and unforeseen events. Enabling computing systems with such human-like intelligence matters because the tempo of military operations in emerging domains can exceed that at which unaided humans can orient, understand, and act. The technologies developed in this project will enable warfighters to make better decisions in complex, time-critical, battlefield environments with greater efficiency and confidence; and help autonomous systems and intelligent computational agents to safely and reliably perform critical missions in contested and adversarial physical and virtual environments. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Advanced Research Projects Agency                                      Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:              PE 0602025E / MAKING, MAINTAINING, SUPPLY CHAIN AND LOGISTICS Applied Research The Making, Maintaining, Supply Chain and Logistics Support project contains management costs in support of DARPA functions and activities across the entire Making, Maintaining, Supply Chain and Logistics PE. These costs include: DARPA classified and unclassified network support and equipment; contractor support; classified program security; building security; commercial transition services that increase the likelihood that DARPA-funded technologies remain in the U.S. and provide new capabilities for national defense; DARPA outreach to universities and industry; external contracting, financial and support fees; Program Manager Intragovernmental Personnel Act (IPA) Funding; Program Managers from other Government Agencies; and similar operating expenses. Agency support is allocated on a pro-rata basis across the Agency's BA1, BA2 and BA3 PEs and, therefore, fluctuates per PE by fiscal year based on the total Agency budget in that fiscal year. Prior to FY 2026, efforts in this PE were funded in PE 0602715E, Materials and Biological Technology, PE 0602716E, Electronics Technology, and PE 0602303E, Information & Communications Technology.$$, $$Budget J-Books/FY27/DW/RDTE_Vol1_DARPA_MasterJustificationBook_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602102F$$, $$Materials$$, $$rdte_af_ba2$$, $$afrl_rx$$, 2026, 147422000, 274790000, 185336000, NULL, $${"ba_raw": "6.2", "source": "af_r1_fy26", "original_pe": "0602102F"}$$::jsonb, $$The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This program develops advanced materials, processing, and inspection technologies to reduce life cycle costs and improve performance, sustainability, availability, affordability, supportability, reliability, and survivability of current and future Department of the Air Force systems and operations. The program has three projects that develop: structural, propulsion, and sub-systems materials and processes technologies; electronic, optical, and survivability materials and processes technologies; and sustainment materials, processes technologies, and advanced non-destructive inspection methodologies. Efforts in the program have been coordinated through the Department of Defense Science and Technology Executive Committee process to harmonize efforts and eliminate duplication. Funds in this PE may be used to investigate specified technology advancements in air, space and/or cyber domains. This program includes funding for the requisite DAF Science & Engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The use of program funds in this program element is in conjunction with the civilian pay expenses budgeted in the following program elements: 1206601SF, 1206616SF, 0601102F, 0602020, 0602202F, 0602203F, 0602204F, 0602298F, 0602336F, 0602602F, 0602605F, 0602788F, and 0603680F. In FY 2026, $68.328 million is budgeted in this program for 333 direct Full-Time Equivalent (FTE) civilians. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology capabilities. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied      PE 0602102F / Materials Research This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters.$$, NULL, 146937000, 155962000, 158981000, NULL, NULL, 5, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 176661000, 232193000, 139872000, 139872000, 0, 139872000, 158038000, $$This program develops advanced materials, processing, and inspection technologies to reduce life cycle costs and improve performance, sustainability, availability, affordability, supportability, reliability, and survivability of current and future Department of the Air Force systems and operations. The program has three projects that develop: structural, propulsion, and sub-systems materials and processes technologies; electronic, optical, and survivability materials and processes technologies; and sustainment materials, processes technologies, and advanced non-destructive inspection methodologies. This program is accomplished by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. Funds in this PE may be used to investigate specified technology advancements in air, space and/or cyber domains. This program includes funding for the requisite DAF Science & Engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The use of program funds in this program element is in conjunction with the civilian pay expenses budgeted in the following program elements: 1206601SF, 1206616SF, 0601102F, 0602020F, 0602202F, 0602203F, 0602204F, 0602298F, 0602336F, 0602602F, 0602605F, 0602788F, and 0603680F. In FY 2027, $63.575 million is budgeted in this program for 321 direct Full-Time Equivalent (FTE) civilians. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology capabilities. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                            Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied      PE 0602102F / Materials Research This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_0300_L117$$, $$Operational Enhancements Intelligence$$, $$proc_dw_0300_ba2$$, $$dw_other$$, 2026, 395001000, 322341000, 331592000, NULL, $${"page": 170, "ba_num": "02", "source": "p1_fy26", "ba_name": "Special Operations Command", "line_no": "117", "service": "dw", "fy24_qty": null, "fy25_qty": null, "fy27_v27": {"ba": "02", "p1_li": 70}, "appr_code": "0300", "appr_name": "Procurement, Defense-Wide", "fy26_v181": {"li_num": 70, "source": "p1_master_fy26_v181", "source_pdf": "Budget J-Books/FY27/Remaining/FY2027_p1.pdf", "fy26_disc_K": 21339, "fy26_supp_K": 0, "fy26_total_K": 21339, "name_partial": "Operational Enhancements Intelligence"}, "fy26t_qty": null, "fy26d_cost": 352100000, "fy26r_cost": 42901000, "ident_code": ""}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 21339000, 28074000, 28074000, 0, 28074000, NULL, NULL, $$Budget J-Books/FY27/DW_Procurement/PROC_SOCOM_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602115E$$, $$BIOMEDICAL TECHNOLOGY$$, $$rdte_dw_ba2$$, $$dw_darpa$$, 2026, 0, 106591000, 132601000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "dw", "page_num": 66, "original_pe": "0602115E", "page_header": "Defense-Wide"}$$::jsonb, $$The Biomedical Technology Program Element (PE) focuses on applied research for medical related technologies that will maintain warfighter health and performance before, during, or after operations. Successful technologies within this Program Element will maintain warfighter health against emerging threats through novel biothreat detection, rapid medical countermeasure identification and development, and distributed production of effective therapeutics. In-theater, warfighter health will be maintained through the development of field-relevant technologies such as reliable and accessible critical medical resources, novel detection and protection capabilities for traumatic brain injury, and rapid, effective triage of battlefield injuries. Technologies are also being developed to provide new capabilities for warfighter recovery from sustained injury including, but not limited, to spinal cord injury. Additionally, this PE will improve warfighter readiness by characterizing and assaying physical and cognitive performance to drive data-driven awareness. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA-funded technologies take root in the U.S. and provide new capabilities for national defense. Beginning in FY 2026, efforts in this PE will be funded in PE 0602024E, Warfighting Performance.$$, NULL, 0, 0, 0, NULL, NULL, 15, $$RDTE_Vol1_DARPA_MasterJustificationBook_PB_2026.pdf$$, $$DARPA$$, FALSE, 128307000, 0, 0, 0, NULL, 0, 0, $$The Biomedical Technology Program Element (PE) focuses on applied research for medical related technologies that will maintain warfighter health and performance before, during, or after operations. Successful technologies within this Program Element will maintain warfighter health against emerging threats through novel biothreat detection, rapid medical countermeasure identification and development, and distributed production of effective therapeutics. In-theater, warfighter health will be maintained through the development of field-relevant technologies such as reliable and accessible critical medical resources, novel detection and protection capabilities for traumatic brain injury, and rapid, effective triage of battlefield injuries. Technologies are also being developed to provide new capabilities for warfighter recovery from sustained injury including but not limited to spinal cord injury. Additionally, this PE will improve warfighter readiness by characterizing and assaying physical and cognitive performance to drive data-driven awareness. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA-funded technologies take root in the U.S. and provide new capabilities for national defense. Beginning in FY 2026, efforts in this PE will be funded in PE 0602024E, Warfighting Performance.$$, $$Budget J-Books/FY27/DW/RDTE_Vol1_DARPA_MasterJustificationBook_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602123N$$, $$Force Protection Applied Res$$, $$rdte_navy_ba2$$, $$onr$$, 2026, 125699000, 280078000, 191716000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "navy", "page_num": 26, "original_pe": "0602123N", "page_header": "Department of the Navy"}$$::jsonb, $$America is a maritime nation with global responsibilities that require U.S. naval forces be respected around the world and decisive when it matters. The Office of Naval Research (ONR) was established to guide ongoing research to ensure the technical superiority of the U.S. Navy and Marine Corps. This Program Element (PE) addresses applied research associated with providing the capability of Platform and Force Protection for the U.S. Navy. This program supports the development of technologies associated with all naval platforms (surface, subsurface, terrestrial, and air) and the protection of those platforms. The goal is to provide the ability to deter, or avoid engagements, and if necessary, fight and win against adversary naval platforms or weapons. In the event of conflict, naval platforms must be able to resist and control damage while preserving operational capability. Research is focused on providing technologically superior defense of naval assets and delivering warfighting capabilities at reduced total ownership costs for surface and subsurface platforms through investments in the following Focus Areas: a) Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR)/Naval Space, b) Autonomy/Artificial intelligence (AI), c) Human & Biological Systems, d) Directed Energy & Kinetic Systems, e) Materials/Electronics, f) Power and Energy (formerly Power, Energy & Propulsion) g) Naval Engineering (formerly Platform Design and Engineering), h) Naval Aerospace, i) Undersea Systems and j) Ocean, Atmosphere, & Space. These investments in applied research move innovation from new technology identification to prototype. This program identifies and develops technologies for reduced observables technology and enhanced capability of naval aviation aircraft platforms in terms of mission effectiveness, platform range, responsiveness, survivability, observability, readiness, safety and life cycle cost. It also addresses innovation in technology development to provide substantial improvements in energetic material systems and subsystems, primarily in terms of performance, but also addressing safety, reliability, and affordability concerns. The program supports mission-driven design thinking and problem solving within the Naval Research and Development Establishment (NR&DE) and academia in support of culture changes towards agile and rapid prototyping driven by effective innovation process and operations. Today's Sailors and Marines are enabled by naval Science and Technology (S&T) and the business of innovation. Since 1946, the Office of Naval Research (ONR) has fostered scientific research related to the maintenance of maritime superiority and national defense. ONR manages the Department of the Navy's (DON) portfolio of naval Basic and Applied research, and Advanced Technology Development investments, as well as the NavalX office, to ensure naval forces can effectively deter conflict, but when called upon, fight, win and come home safe. Current investments, combined with innovation operations, hedge against uncertainty, providing solutions to commanders today, and options for the future. The Naval S&T budget supports higher guidance defined by the National Defense Strategy, and responds to requirements identified by the Secretary of the Navy through research priorities set by the Chief of Naval Research, coordinated across the Naval Research Enterprise (NRE), and outlined in the Naval R&D Framework. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                               Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 2: Applied            PE 0602123N / Force Protection Applied Res Research This Program Element (PE) funds Applied Research, which is the systematic study to understand the means to meet a recognized and specific need. Most of the work in this PE can be classified between Technology Readiness Level (TRL) 2 (technology concept and/or application formulation) and TRL 4 (component and/or breadboard validation in laboratory environments). Due to the number of efforts in this PE, the programs described herein are representative and not exhaustive of the work included in this PE. Beginning in FY 2026, Research Areas have been identified for the Focus Areas within the S&T budget. These new Research Areas aim to better align the efforts in the Focus Area to allow visibility into the specific challenges and the approaches to alleviate those challenges.$$, NULL, 148166000, 154045000, 154054000, NULL, NULL, 4, $$RDTEN_BA1-3_Book.pdf$$, NULL, FALSE, 183150000, 243086000, 137779000, 137779000, NULL, 137779000, 156436000, $$America is a maritime nation with global responsibilities that require U.S. naval forces be respected around the world and decisive when it matters. The Office of Naval Research (ONR) was established to guide ongoing research to ensure the technical superiority of the U.S. Navy and Marine Corps. This Program Element (PE) addresses applied research associated with providing the capability of Platform and Force Protection for the U.S. Navy. This program supports the development of technologies associated with all naval platforms (surface, subsurface, terrestrial, and air) and the protection of those platforms. The goal is to provide the ability to deter, or avoid engagements, and if necessary, fight and win against adversary naval platforms or weapons. In the event of conflict, naval platforms must be able to resist and control damage while preserving operational capability. Research is focused on providing technologically superior defense of naval assets and delivering warfighting capabilities at reduced total ownership costs for surface and subsurface platforms through investments in the following Focus Areas: a) Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR)/Naval Space, b) Autonomy/Artificial intelligence (AI), c) Human & Biological Systems, d) Directed Energy & Kinetic Systems, e) Materials/Electronics, f) Power and Energy (formerly Power, Energy & Propulsion) g) Naval Engineering (formerly Platform Design and Engineering), h) Naval Aerospace, i) Undersea Systems and j) Ocean, Atmosphere, & Space. These investments in applied research move innovation from new technology identification to prototype. This program identifies and develops technologies for reduced observables technology and enhanced capability of naval aviation aircraft platforms in terms of mission effectiveness, platform range, responsiveness, survivability, observability, readiness, safety and life cycle cost. It also addresses innovation in technology development to provide substantial improvements in energetic material systems and subsystems, primarily in terms of performance, but also addressing safety, reliability, and affordability concerns. The program supports mission-driven design thinking and problem solving within the Naval Research and Development Establishment (NR&DE) and academia in support of culture changes towards agile and rapid prototyping driven by effective innovation process and operations. Today's Sailors and Marines are enabled by naval Science and Technology (S&T) and the business of innovation. Since 1946, the Office of Naval Research (ONR) has fostered scientific research related to the maintenance of maritime superiority and national defense. ONR manages the Department of the Navy's (DON) portfolio of naval Basic and Applied research, and Advanced Technology Development investments, as well as the NavalX office, to ensure naval forces can effectively deter conflict, but when called upon, fight, win and come home safe. Current investments, combined with innovation operations, hedge against uncertainty, providing solutions to commanders today, and options for the future. The Naval S&T budget supports higher guidance defined by the National Defense Strategy, and responds to requirements identified by the Secretary of the Navy through research priorities set by the Chief of Naval Research and outlined in the Naval R&D Framework. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                               Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 2: Applied            PE 0602123N / Force Protection Applied Res Research This Program Element (PE) funds Applied Research, which is the systematic study to understand the means to meet a recognized and specific need. Most of the work in this PE can be classified between Technology Readiness Level (TRL) 2 (technology concept and/or application formulation) and TRL 4 (component and/or breadboard validation in laboratory environments). Due to the number of efforts in this PE, the programs described herein are representative and not exhaustive of the work included in this PE.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA1-3_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602128D8Z$$, $$Promotion and Protection Strategies$$, $$rdte_dw_ba2$$, $$dw$$, 2026, 3166000, 3199000, 3191000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "dw", "page_num": 66, "original_pe": "0602128D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$The Promotion and Protection Strategies program executes activities providing visibility, fostering partnerships, incentivizing industry transition partners, and supporting a developmental network that serves as a nucleus of the defense industrial base for biotechnology. The program centralizes transition planning efforts for the Distributed Bio industrial Manufacturing Program (DBIMP) by coordinating the Acquisition (e.g., Program Executive Officers, Program Managers, technology warrant officers, etc.), Policy, and Research and Engineering communities, including the Tri-Service Biotechnology for a Resilient Supply Chain (T-BRSC) program, This efforts streamlines acquisition for transition of non-pharmaceutical biomanufactured materials and chemicals by integrating innovative biomanufactured products into DoD’s systems and platforms through holistic informed investment, research & development, and acquisition strategies. The effort represents the Department’s first coordinated effort to centralize acquisition efforts for biotechnology. By providing visibility, fostering partnerships across DoD, and incentivizing industry transition partners, this work will support a developmental network in which new technologies are not only pushed to higher budget activities from lower ones, but where personnel and industry partners at higher budget activities pull on technologies being developed at lower ones. This will serve as the nucleus of a defense industrial base for biotechnology that delivers innovative biomanufactured products into DoD’s systems and platforms. This directly supports the rebuilding of our military by providing capabilities matched with the threat, reviving our defense industrial base, and rapidly fielding emerging technologies. It also reestablishes deterrence by providing capabilities closer to the threat other logistically advantageous locations. Activities focus on efforts to supply DoD priority systems with critical chemicals and materials in support of production of materiel including munitions, hypersonics, and UASs, as well as point-on-need biomanufacturing in the INDOPACOM theater. Promotion and Protection Strategies executes landscape and subject matter assessments to facilitate transition, align acquisition, policy, and research and engineering communities, to inform DBIMP investments to ensure integration of innovative Bioindustrial manufactured products into DoD’s systems and platforms through current and holistic investment, research and development, and acquisition strategies. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                             Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:         PE 0602128D8Z / Promotion and Protection Strategies Applied Research$$, NULL, 4848000, 5412000, 6386000, NULL, NULL, 16, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 3170000, 3158000, 4260000, 4260000, NULL, 4260000, 7054000, $$The Promotion and Protection Strategies program executes activities providing visibility, fostering partnerships, incentivizing industry transition partners, and supporting a developmental network that serves as a nucleus of the defense industrial base for biomanufacturing. The program centralizes transition planning efforts for the Distributed Bioindustrial Manufacturing Program (DBIMP) by coordinating the Acquisition (e.g., Program Executive Officers, Program Managers, technology warrant officers, etc.), Policy, and Research and Engineering communities, including the Tri-Service Biotechnology for a Resilient Supply Chain (T-BRSC) program, This efforts streamlines acquisition for transition of non-pharmaceutical biomanufactured materials and chemicals by integrating innovative biomanufactured products into DoW’s systems and platforms through holistic informed investment, research & development, and acquisition strategies. The effort represents the Department’s first coordinated effort to centralize acquisition efforts for biomanufacturing. By providing visibility, fostering partnerships across the DoW, and incentivizing industry transition partners, this work supports a developmental network in which new technologies are not only pushed to higher budget activities from lower ones, but where DoW and industry partners at higher budget activities pull on technologies being developed at lower ones. This will serve as the nucleus of a defense industrial base for biomanufacturing that delivers innovative biomanufactured products into DoW’s systems and platforms. This directly supports the rebuilding of our military by providing capabilities matched with the threat, reviving our defense industrial base, and rapidly fielding emerging technologies. It also re-establishes deterrence by providing capabilities closer to the threat other logistically advantageous locations. Activities focus on efforts to supply DoW priority systems with critical chemicals and materials in support of production of materiel including munitions, hypersonics, and Unmanned Aerial Systems (UASs), as well as geographically distributed biomanufacturing capabilities, including point-of-need biomanufacturing in the United States Indo-Pacific Command (INDOPACOM) theater. Promotion and Protection Strategies executes landscape and subject matter assessments to facilitate transition, align acquisition, policy, and research and engineering communities, to inform DBIMP investments to ensure integration of innovative biomanufactured products into DoW’s systems and platforms through current and holistic informed investment, research and development, and acquisition strategies. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:         PE 0602128D8Z / Promotion and Protection Strategies Applied Research$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602131M$$, $$Marine Corps Lndg Force Tech$$, $$rdte_navy_ba2$$, $$onr$$, 2026, 45697000, 66603000, 58508000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "mc", "page_num": 26, "original_pe": "0602131M", "page_header": "Department of the Navy"}$$::jsonb, $$The U.S. Navy/Marine Corps team is the most potent naval fighting force in the world. Fundamental to their success are the technologies necessary for effective distributed maritime operations. The Office of Naval Research (ONR) combines knowledge of the naval mission with researchers to select and explore solutions critical to expeditionary warfighting needs. This Program Element (PE) addresses requirements outlined in the Expeditionary Advanced Base Operations (EABO), which is a form of expeditionary warfare that involves the employment of mobile, reduced signature, operationally relevant, and relatively easy to maintain and sustain naval expeditionary forces from a series of austere, temporary locations ashore or inshore within a contested or potentially contested maritime area in order to conduct sea denial, support sea control, or enable fleet sustainment. Additionally, USMC forces must be ready for worldwide contingency operations, which frequently includes contested urban environments with complex physical and operational challenges. This can include physical compartmentalization and canalization, additional physical dimensions (subterranean and multi-story structures), crowded conditions and associated threat obscuration, communications challenges, informational and human aspects, and proliferation of observation and fires technologies. These operating environments require capabilities addressing all the activities within this PE and while it provides many challenges, unique opportunities are also presented and can further shape technology approaches. These future challenges and portents demand robust technologies for the Marine Corps, but the technology options are constrained. They must have a lightweight deployable character, and the ability to operate in austere conditions with little fixed infrastructure or support while retaining the agility and lethality of an integrated maneuver force. Technology must provide full spectrum capability against robust and complex peer and near-peer adversaries while meeting size, weight, power, cost limitations, and command and control systems that work within degraded, disconnected, intermittent and limited environments with reduced threat detectability. The approach within this PE encompasses ideas that support both revolutionary and evolutionary capabilities, and in this way considers and balances both "push" and "pull" aspects of technology projects. This Program Element (PE) funds Applied Research, which is the systematic study to understand the means to meet a recognized and specific need. Most of the work in this PE can be classified between Technology Readiness Level (TRL) 2 (technology concept and/or application formulation) and TRL 4 (component and/or breadboard validation in laboratory environments). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                           Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 2: Applied            PE 0602131M / Marine Corps Lndg Force Tech Research Due to the number of efforts in this PE, the programs described herein are representative of the work included in this PE.$$, NULL, 54582000, 60827000, 61353000, NULL, NULL, 5, $$RDTEN_BA1-3_Book.pdf$$, NULL, FALSE, 56730000, 62108000, 57567000, 57567000, NULL, 57567000, 62762000, $$The U.S. Navy/Marine Corps team is the most potent naval fighting force in the world. Fundamental to their success are the technologies necessary for effective distributed maritime operations. The Office of Naval Research (ONR) combines knowledge of the naval mission with researchers to select and explore solutions critical to expeditionary warfighting needs. This Program Element (PE) addresses requirements outlined in the Expeditionary Advanced Base Operations (EABO), which is a form of expeditionary warfare that involves the employment of mobile, reduced signature, operationally relevant, and relatively easy to maintain and sustain naval expeditionary forces from a series of austere, temporary locations ashore or inshore within a contested or potentially contested maritime area in order to conduct sea denial, support sea control, or enable fleet sustainment. Additionally, USMC forces must be ready for worldwide contingency operations, which frequently includes contested urban environments with complex physical and operational challenges. This can include physical compartmentalization and canalization, additional physical dimensions (subterranean and multi-story structures), crowded conditions and associated threat obscuration, communications challenges, informational and human aspects, and proliferation of observation and fires technologies. These operating environments require capabilities addressing all the activities within this PE and while it provides many challenges, unique opportunities are also presented and can further shape technology approaches. These future challenges and portents demand robust technologies for the Marine Corps, but the technology options are constrained. They must have a lightweight deployable character, and the ability to operate in austere conditions with little fixed infrastructure or support while retaining the agility and lethality of an integrated maneuver force. Technology must provide full spectrum capability against robust and complex peer and near-peer adversaries while meeting size, weight, power, cost limitations, and command and control systems that work within degraded, disconnected, intermittent and limited environments with reduced threat detectability. The approach within this PE encompasses ideas that support both revolutionary and evolutionary capabilities, and in this way considers and balances both "push" and "pull" aspects of technology projects. This Program Element (PE) funds Applied Research, which is the systematic study to understand the means to meet a recognized and specific need. Most of the work in this PE can be classified between Technology Readiness Level (TRL) 2 (technology concept and/or application formulation) and TRL 4 (component and/or breadboard validation in laboratory environments). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                           Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 2: Applied            PE 0602131M / Marine Corps Lndg Force Tech Research Due to the number of efforts in this PE, the programs described herein are representative of the work included in this PE.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA1-3_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602134A$$, $$Counter Improvised-Threat Advanced Studies$$, $$rdte_army_ba2$$, $$dw_dtra$$, 2026, 6174000, 6014000, 6163000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 10, "original_pe": "0602134A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) executes applied research into novel methods for detecting and defeating Improvised Explosive Devices (IED) through the application of emerging technologies as well as research into emerging IED threats to evaluate potential methods of defeat. Efforts are selected in the budget year and current year of execution to address program requirements. This PE is executed in coordination with the Under Secretary of Defense for Research and Engineering (USD/R&E) and the Defense Threat Reduction Agency (DTRA). Work in this Project is fully coordinated with Program Element (PE) 0603134A (Counter Improvised Threat Simulation), Project CD3 (Counter Improvised Threat Simulation). The cited work is consistent with the USD/R&E priority focus areas. Work in this Project is managed by Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center. Work is performed by the United States Army Combat Capabilities Development Command (DEVCOM), Army Artificial Intelligence Integration Center (AI2C), the Engineering Research and Development Center, Space and Missile Defense Technical Center, and the United States Army Research Institute for the Behavioral and Social Sciences with oversight from Assistant Secretary of the Army for Acquisition, Logistics and Technology for Research and Technology (DASA R&T).$$, NULL, NULL, NULL, NULL, NULL, NULL, 8, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, 4098000, 6174000, NULL, NULL, NULL, NULL, NULL, $$This PE executes applied research into novel methods for the detection and classification complex obstacles, including new advanced surface-laid and buried anti- personnel mines, anti-tank mines, off-route effectors, wire, anti-vehicle obstacles, and other threat constructed obstacles under the expected environmental conditions in Large Scale Combat Operations (LSCO) to enable application to maneuver and breaching. This PE is executed in coordination with the Under Secretary of War for Research and Engineering and the Defense Threat Reduction Agency (DTRA). Work in this PE is fully coordinated with PE 0603134A (Counter Improvised Threat Simulation), Project CD3 (Counter Improvised Threat Simulation). Work in this project is managed by Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center. Work is performed by the U.S. Army Combat Capabilities Development Command (DEVCOM), Army Artificial Intelligence Integration Center (AI2C), the Engineering Research and Development Center, Space and Missile Defense Technical Center, and the U.S. Army Research Institute for the Behavioral and Social Sciences with oversight from Assistant Secretary of the Army for Acquisition, Logistics and Technology for Research and Technology (DASA R&T).$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 2.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602135A$$, $$Counter Small Unmanned Aerial Systems (C-SUAS) Applied Research$$, $$rdte_army_ba2$$, $$dw_osd$$, 2026, 12618000, 0, 0, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 10, "original_pe": "0602135A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) investigates, designs, and develops novel capabilities that aid in the detection, tracking, identification, mitigation, and/or defeat of small unmanned aerial systems (sUAS) groups 1-3. Provides counter-small UAS (C-SUAS) detection capabilities in radar, radio frequency (RF), electro-optical and infrared (EO/IR), and acoustic signature regimes. Provides capabilities to track and predict UAS flight paths, airspace situational awareness, and/or location of UAS operators to increase defeat and force protection capabilities. Develops identification methods to discern aerial systems and payloads. Develops algorithms to enable threat prioritization, airspace control, coordinated response, and resource management of C-SUAS capabilities. Designs and develops interceptor capabilities to deliver physical effects that enable faster intercept, greater standoff ranges, increased magazine depth, survivability, affordability, and/or decrease in size, weight, and/or power requirements. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy.$$, NULL, 14784000, 14469000, 14547000, NULL, NULL, 9, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, NULL, 12618000, 26523000, 26523000, NULL, 26523000, 16155000, $$This Program Element (PE) investigates, designs, and develops novel capabilities that aid in the detection, tracking, identification, mitigation, and/or defeat of small unmanned aerial systems (sUAS) groups 1-3. Provides counter-small UAS (C-SUAS) detection capabilities in radar, radio frequency (RF), electro-optical and infrared (EO/IR), and acoustic signature regimes. Provides capabilities to track and predict UAS flight paths, airspace situational awareness, and/or location of UAS operators to increase defeat and force protection capabilities. Develops identification methods to discern aerial systems and payloads. Develops algorithms to enable threat prioritization, airspace control, coordinated response, and resource management of C-SUAS capabilities. Designs and develops interceptor capabilities to deliver physical effects that enable faster intercept, greater standoff ranges, increased magazine depth, survivability, affordability, and/or decrease in size, weight, and/or power requirements.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 2.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604538D8Z$$, $$Economic Defense Unit$$, $$rdte_dw_ba7$$, $$dw$$, 2027, 0, 0, 0, NULL, $${"fy27_mand_k": 189378, "fy27_mand_v157": "2026-05-08", "fy26_v182_disc_K": 0, "fy26_v182_supp_K": 266450, "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy26_v182_total_K": 266450, "fy27_mand_section": "Defense Industrial Base", "fy26_v182_note_name": "Research, Development, Test & Evaluation, EDU,", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 46613}$$::jsonb, NULL, NULL, 620447000, 632857000, 645513000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 266450000, 403903000, 403903000, 189378000, 593281000, 658424000, $$The mission of the Economic Defense Unit (EDU) is to support some of the Department of War's (DoW) Economic Competition activities by providing analysis, recommendations, insights, and other support to ensure alignment with DoW objectives and in support of the DoW’s National Defense Strategy, National Military Strategy, and National Defense Industrial Strategy. Additionally, the office will develop requirements for Economic Competition activities that may include access, basing, and overflight; countering mobilization of adversaries; countering defense industrial base activities by adversaries; and ensuring access for the United States to critical materials and capabilities. It will also provide economic analysis and advisory input on DoW contracting and other commercial approaches meeting criteria developed by the Director of EDU, and sponsor and conduct regular tabletop exercises and activities to assess the economic impacts of DoW decisions during crisis and conflicts. The EDU's economic weapon system will integrate economic competition workflows into a single system in order to (1) Enable data-driven coordination across economic competition activities; (2) Improve collaboration via recurring system usage by EDU; (3) Establish an enduring operating model for data acquisition and integration; (4) Support planning and execution of economic competition activities at scale. The FY 2027 request for EDU includes $403,903 thousand of discretionary and $189,378 thousand of mandatory for a total of $593,281 thousand. The mandatory funds EDU's investment program which will make strategic equity and control investments in companies that align with its mission. This includes securing access to critical minerals and materials, enhancing access, basing and overflight, countering adversary mobilization and countering adversaries defense industrial base. Through these targeted investments, the EDU aims to strengthen national security, promote economic resilience, and counter the strategic influence of global competitors. The FY 2027 mandatory funds continue efforts from FY 2026 to make critical investments in the defense industrial base. The FY 2026 spend plan amount for Research, Development, Test & Evaluation, EDU, includes $0 thousand of discretionary and $266,450 thousand of mandatory for a total of $266,450 thousand. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                   Date: April 2026 Appropriation/Budget Activity                                             R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:      PE 0604538D8Z / Economic Defense Unit Operational Systems Development$$, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602141A$$, $$Lethality Technology$$, $$rdte_army_ba2$$, $$cft_lrpf$$, 2026, 97157000, 145375000, 128659000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 10, "original_pe": "0602141A", "page_header": "Department of the Army"}$$::jsonb, $$Work done in this Program Element (PE) supports research technologies, methodologies, and models required to enable next generation lethality. The effort focuses on: lethal mechanism technologies for projectiles and warheads that provide revolutionary capability to defeat Tier 1 adversary vehicle and body armors; selection of propulsion and energetic materials and technology to validate novel energetic materials concepts to exploit controllable energy release for future gun/missile systems; scalable effects for mixed target defeat while simultaneously decreasing warhead mass; development of materials solutions for improvement of weight and volume efficiency, lethal effects and sustainability for the warfighter in the Army of today and beyond; and multiple pathways to enhance lethal effects by investigating synergistic effects of novel micro warheads using advanced materials. Funding in this PE is a continuation of work done in PEs 0602105A (Materials Technology), 0602618A (Ballistics Technology), and 0602624A (Weapons and Munitions Technology). Work in this PE complements PEs 0602147A (Long Range Precision Fires Technology), 0602150A (Air and Missile Defense Technology), 0602143A (Soldier Lethality Technology), 0602144A (Ground Technology), 0602145A (Next Generation Combat Vehicle Technology), and 0603116A (Lethality Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. The FY 2026 request was reduced by $0.302 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.437 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                            Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied           PE 0602141A / Lethality Technology Research$$, NULL, 113331000, 109590000, 120328000, NULL, NULL, 10, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, 126660000, 176157000, 232046000, 232046000, NULL, 232046000, 121562000, $$Work done in this Program Element (PE) supports research technologies, methodologies, and models required to enable next generation lethality. The effort focuses on: lethal mechanism technologies for projectiles and warheads that provide revolutionary capability to defeat Tier 1 adversary vehicle and body armors; selection of propulsion and energetic materials and technology to validate novel energetic materials concepts to exploit controllable energy release for future gun/missile systems; scalable effects for mixed target defeat while simultaneously decreasing warhead mass; development of materials solutions for improvement of weight and volume efficiency, lethal effects and sustainability for the warfighter in the Army of today and beyond; and multiple pathways to enhance lethal effects by investigating synergistic effects of novel micro warheads using advanced materials. Funding in this PE is a continuation of work done in PEs 0602105A (Materials Technology), 0602618A (Ballistics Technology), and 0602624A (Weapons and Munitions Technology). Work in this PE complements PEs 0602147A (Long Range Precision Fires Technology), 0602150A (Air and Missile Defense Technology), 0602143A (Soldier Lethality Technology), 0602144A (Ground Technology), 0602145A (Next Generation Combat Vehicle Technology), and 0603116A (Lethality Advanced Technology).$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 2.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602143A$$, $$Soldier Lethality Technology$$, $$rdte_army_ba2$$, $$devcom$$, 2026, 72670000, 209084000, 137771000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 10, "original_pe": "0602143A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) conducts fundamental research on Soldier Lethality technologies to develop an integrated Soldier and Squad architecture of equipment and systems that improve Soldier and Small Combat Unit survivability, sustainability, mobility, combat effectiveness, and individual cognitive and physical readiness. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                               Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied              PE 0602143A / Soldier Lethality Technology Research To address the challenges of integrating multiple technologies and sub-systems, research conducted in this PE, significant Science and Technology applied research investments in all areas of Soldier Lethality focuses on how to improve the effectiveness of the technologies a Soldier utilizes and apply systems-level practices to mitigate constraints from size and weight of the equipment. Research areas encompass individual and crew-served weapon designs and technologies as well as applied research in lightweight and transparent armor materials to mitigate effects from blast and ballistic threats, counter explosive hazard detection, counter-sensor capabilities, and signature management of weapons, equipment, personnel and high value targets. This PE investigates, develops and designs materials, technologies, methodologies and system models required to experiment and optimize Soldier lethality and survivability through investments in mobility, human-agent teaming, and improved situational awareness interfaces and display technologies as well as to provide Soldier-borne power and energy materials and components that support multiple Soldier-borne systems. This PE also investigates Warfighter training technologies and develops the underpinning technologies to establish architecture standards and interfaces necessary for creating realistic synthetic environments to create a single, interconnected synthetic training system to enable Army units and leaders to conduct realistic multi-echelon / multi-domain combined arms maneuver and mission command training, increasing proficiency through repetition. Human Factors Engineering projects conduct applied research to design weapon systems standards, guidelines, handbooks, and Soldier training curriculum and tools. Results of these efforts are transitioned within the Army Futures Command, the Program Executive Offices, Army Training and Doctrine Command (TRADOC), Army Medical Command (MEDCOM), and the Army Test and Evaluation Command (ATEC). Work in this PE complements PE 0603118A (Soldier Lethality Advanced Technology). Portions of this funding line support the Soldier Lethality Army Modernization Priority. The FY 2026 request was reduced by $0.698 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.362 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                          Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied          PE 0602143A / Soldier Lethality Technology Research$$, NULL, 95373000, 111795000, 113358000, NULL, NULL, 12, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, 131645000, 223990000, 68018000, 68018000, NULL, 68018000, 109089000, $$This Program Element (PE) conducts fundamental research on Soldier Lethality technologies to develop an integrated Soldier and Squad architecture of equipment and systems that improve Soldier and Small Combat Unit survivability, sustainability, mobility, combat effectiveness, and individual cognitive and physical readiness. To address the challenges of integrating multiple technologies and sub-systems, research conducted in this PE, significant Science and Technology applied research investments in all areas of Soldier Lethality focuses on how to improve the effectiveness of the technologies a Soldier utilizes and apply systems-level practices to mitigate constraints from size and weight of the equipment. Research areas encompass individual and crew-served weapon designs and technologies as well as Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                               Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied             PE 0602143A / Soldier Lethality Technology Research applied research in lightweight and transparent armor materials to mitigate effects from blast and ballistic threats, counter explosive hazard detection, counter-sensor capabilities, and signature management of weapons, equipment, personnel and high value targets. This PE investigates, develops and designs materials, technologies, methodologies and system models required to experiment and optimize Soldier lethality and survivability through investments in mobility, human-agent teaming, and improved situational awareness interfaces and display technologies as well as to provide Soldier-borne power and energy materials and components that support multiple Soldier-borne systems. This PE also investigates Warfighter training technologies and develops the underpinning technologies to establish architecture standards and interfaces necessary for creating realistic synthetic environments to create a single, interconnected synthetic training system to enable Army units and leaders to conduct realistic multi-echelon / multi-domain combined arms maneuver and mission command training, increasing proficiency through repetition. Human Factors Engineering projects conduct applied research to design weapon systems standards, guidelines, handbooks, and Soldier training curriculum and tools. Results of these efforts are transitioned within the Army Futures Command, the Program Executive Offices, Army Training and Doctrine Command (TRADOC), Army Medical Command (MEDCOM), and the Army Test and Evaluation Command (ATEC). Work in this PE complements PE 0603118A (Soldier Lethality Advanced Technology). Portions of this funding line support the Soldier Lethality Army Modernization Priority.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 2.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605161D8Z$$, $$Nuclear Matters Management Support$$, $$rdte_dw_ba6$$, $$dw$$, 2026, 12549000, 14744000, 18710000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 76, "original_pe": "0605161D8Z", "page_header": "Defense-Wide", "fy26_v182_disc_K": 12384, "fy26_v182_supp_K": 15000, "fy26_v182_total_K": 27384, "fy26_v182_note_name": "Nuclear Matters Management Support", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 40214}$$::jsonb, $$The mission of Nuclear Matters is to ensure the continued credibility, safety, security, resiliency, and effectiveness of the U.S. nuclear deterrent to deter adversaries, assure allies and partners, and achieve U.S. objectives if deterrence fails—today and in the future. Nuclear Matters serves as the Department of Defense (DoD) focal point for the modernization and sustainment of the U.S. nuclear weapons stockpile, as well as for a wide range of nuclear counter-terrorism and counter-proliferation issues. The funds for this program are used to support research, development, test and evaluation efforts as well as studies and analyses for nuclear weapons modernization, sustainment, security, use control, nuclear weapons stockpile safety, and survivability requirements. Funds are also used to develop and implement plans for the future of the stockpile and broader nuclear deterrent; infrastructure analyses and assessments; DoD-National Nuclear Security Administration (NNSA) Nuclear Weapons Council (NWC) activities, as mandated by Title 10 U.S. Code, section 179; radiological and nuclear emergency response efforts; and management of international programs of nuclear cooperation, particularly with respect to enhancing international nuclear safety and security. Nuclear Matters is also responsible for policy development and implementation for personnel reliability; nuclear weapons, nuclear command and control, and special nuclear materials security; use control; nuclear weapons transportation; physical security equipment; countering nuclear threats; and nuclear and radiological incident response. Additionally, Nuclear Matters serves as a focal point for DoD activities and initiatives related to countering the threat from nuclear terrorism and nuclear proliferation. Nuclear Matters is leading a series of efforts to provide data-driven support to integrated portfolio management for 21st century nuclear deterrent sustainment and modernization. The United States is modernizing all three legs of its nuclear triad and is also reconstituting its nuclear weapons production capability at roughly the same time, while simultaneously sustaining weapons and systems that have aged well beyond their original design lives. The NWC and similar bodies seek to manage the transition from legacy Cold War delivery systems and weapons to replacement systems and warheads and make decisions that will affect U.S. national security through the end of the 21st century. To field a modern, threat-informed, nuclear deterrent that will keep pace with evolving adversary capabilities, it is necessary to conduct a variety of assessment and study efforts to enable data-driven decisions concerning the future of the U.S. nuclear deterrent. To meet the 2023 National Defense Authorization Act requirement to implement a portfolio management framework for nuclear forces, the Office of the Assistant Secretary of Defense for Nuclear, Chemical, and Biological Defense Programs will lead a nuclear integration and analysis cell to identify and analyze risks and Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                 Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:              PE 0605161D8Z / Nuclear Matters Management Support RDT&E Management Support opportunities across the nuclear enterprise. This effort will leverage advanced data analytics, enterprise risk management, and modeling and simulation tools across the nuclear deterrent portfolio to support data-driven decisions by the Nuclear Weapons Council and the newly formed Nuclear Deputy's Management Action Group which, "provide[s] senior leaders a comprehensive and strategic view of the state of the enterprise and prioritize[s] actions for executive decision.”$$, NULL, 24119000, 24664000, 23082000, NULL, NULL, 176, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 18052000, 27384000, 21862000, 21862000, NULL, 21862000, 23359000, $$The FY 2026 spend plan amount for Nuclear Matters Management Support includes $12,384 thousands of discretionary and $15,000 thousand of mandatory (reconciliation) for a total of $27,384 thousands. The mission of Nuclear Matters is to ensure the continued credibility, safety, security, resiliency, and effectiveness of the U.S. nuclear deterrent to deter adversaries, assure allies and partners, and achieve U.S. objectives if deterrence fails—today and in the future. Nuclear Matters serves as the Department of War (DoW) focal point for the modernization and sustainment of the U.S. nuclear weapons stockpile, as well as for a wide range of nuclear counter-terrorism and counter-proliferation issues. The funds for this program are used to support research, development, test and evaluation efforts as well as studies and analyses for nuclear weapons modernization, sustainment, security, use control, nuclear weapons stockpile safety, and survivability requirements. Funds are also used to develop and implement plans for the future of the stockpile and broader nuclear deterrent; infrastructure analyses and assessments; DoW-National Nuclear Security Administration (NNSA) Nuclear Weapons Council (NWC) activities, as mandated by Title 10 U.S. Code, section 179; radiological and nuclear emergency response efforts; and management of international programs of nuclear cooperation, particularly with respect to enhancing international nuclear safety and security. Nuclear Matters is also responsible for policy development and implementation for personnel reliability; nuclear weapons, nuclear command and control, and special nuclear materials security; use control; nuclear weapons transportation; physical security equipment; countering nuclear threats; and nuclear and radiological incident response. Additionally, Nuclear Matters serves as a focal point for DoW activities and initiatives related to countering the threat from nuclear terrorism and nuclear proliferation. Nuclear Matters is leading a series of efforts to provide data-driven support to integrated portfolio management for 21st century nuclear deterrent sustainment and modernization. The United States is modernizing all three legs of its nuclear triad and is also reconstituting its nuclear weapons production capability at roughly the same time, while simultaneously sustaining weapons and systems that have aged well beyond their original design lives. The NWC and similar bodies seek to manage the transition from legacy Cold War delivery systems and weapons to replacement systems and warheads and make decisions that will affect U.S. national security through the end of the 21st century. To field a modern, threat-informed, nuclear deterrent that will keep pace with evolving adversary capabilities, it is necessary to conduct a variety of assessment and study efforts to enable data-driven decisions concerning the future of the U.S. nuclear deterrent. To meet the 2023 National Defense Authorization Act requirement to implement a portfolio management framework for nuclear forces, the Office of the Assistant Secretary of War for Nuclear Deterrence, Chemical, and Biological Defense Policy and Programs will lead a nuclear integration and analysis cell to identify and analyze risks and opportunities across the nuclear enterprise. This effort will leverage advanced data analytics, enterprise risk management, and modeling and simulation tools Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                 Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:              PE 0605161D8Z / Nuclear Matters Management Support RDT&E Management Support across the nuclear deterrent portfolio to support data-driven decisions by the Nuclear Weapons Council and additional senior leader decisions forums to provide[s] senior leaders a comprehensive and strategic view of the state of the enterprise and prioritize[s] actions for executive decision.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0206624M$$, $$Marine Corps Cmbt Services Supt$$, $$rdte_navy_ba7$$, $$asn_rda$$, 2026, 20419000, 28503000, 33641000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "mc", "page_num": 38, "original_pe": "0206624M", "page_header": "Department of the Navy", "fy26_v182_deferred": true, "fy26_v182_source_file": "RDTEN_BA7-8_Book.txt", "fy26_v182_source_line": 40404, "fy26_v182_supp_K_skipped": 10531, "fy26_v182_deferred_reason": "parser_disc_does_not_match_db_disc"}$$::jsonb, NULL, NULL, 12934000, 11036000, 11223000, NULL, NULL, NULL, NULL, NULL, FALSE, 34905000, 20419000, 19915000, 19915000, NULL, 19915000, 11549000, $$This program provides funding for Marine Air-Ground Task Force requirements for Combat Service Support equipment improvement. It will enhance combat breaching capabilities of the ground combat elements, logistics, maintenance and transportation. The PE also provides improvements in all areas of Combat Service Support Equipment Vehicles by determining the replacement for the light fleet of vehicles. This includes projects such as: Alternative Power Sources for Communications Equipment which is a suite of devices that provide the commander with the capability to use existing power to operate his communication equipment, computers and peripheral equipment instead of using batteries or fossil fuel generators; the Marine Corps Family of Automatic Test Systems, formerly TETS, which provides automatic testing capability for use by technicians both in garrison and forward edge of the battlefield; improvements in all areas of the LVSR & MTVR; the High Performance Capabilities for Military Vehicles Project which is dedicated to applying the best practices of the motor sports industry to military vehicles including engineering expertise, equipment, and technology. The FY 2026 spend plan amount for Combat Service Support Engineering Equipment includes $34,905 thousands of discretionary and $10,531 thousands of mandatory (reconciliation) for a total of $45,436 thousands. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                   Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational    PE 0206624M / Marine Corps Cmbt Services Supt Systems Development$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2031_L006$$, $$UNMANNED AIRCRAFT SYSTEMS (UAS)$$, $$proc_army_2031_ba1$$, $$peo_aviation$$, 2026, 26850000, 0, 0, NULL, $${"page": 10, "ba_num": "01", "source": "p1_fy26", "ba_name": "Aircraft", "line_no": "6", "service": "army", "fy24_qty": null, "fy25_qty": null, "appr_code": "2031", "appr_name": "Aircraft Procurement, Army", "fy26_v178": {"note": "no_parser_pair", "source": "p40_fy26_v178"}, "fy26t_qty": null, "fy26d_cost": 26850000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, 1146596000, NULL, NULL, NULL, FALSE, NULL, 0, 52398000, 52398000, 0, 52398000, NULL, NULL, $$Budget J-Books/FY27/Army/Aircraft_Procurement_Army.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602144A$$, $$Ground Technology$$, $$rdte_army_ba2$$, $$devcom_arl$$, 2026, 56342000, 266663000, 155829000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 10, "original_pe": "0602144A", "page_header": "Department of the Army"}$$::jsonb, $$This Program element (PE) executes research that support and enable the Army's modernization priority for the Next Generation of Combat Vehicles including systems for the deployment and sustainment of ground movement and maneuver. This PE designs and validates technologies that are necessary and foundational for enduring and future ground movement, maneuver and protection of Soldiers and systems. Project CG6: Ground Vehicle Power and Energy Concepts and Tech in PE 0602144A was eliminated to reflect Department of Defense priorities and will cease investigating, designing, and developing electronics technologies to reduce size and weight of military vehicles. Project CI2: Ground Enabling University Applied Research in PE 0602144A was eliminated to reflect Department of Defense priorities and will cease university partnerships in the development of autonomy. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work is performed by the Army Research Laboratory (ARL); the Chemical Biological Center (CBC); the Data and Analysis Center (DAC); the University Technology Development Division; the Armaments Center (AC); the Aviation and Missile Center (AVMC); the Soldier Center (SC); the Ground Vehicle Systems Center (GVSC); the Environmental Laboratory; and the Cold Regions Research and Engineering Laboratory; the Construction Engineering Research Laboratory; the Information Technology Laboratory; the Geotechnical and Structures Laboratory. Work in this PE complements PE 0602145A (Next Generation Combat Vehicle Technology), PE 0603119A (Ground Advanced Technology), PE 0603462A (Next Generation Combat Vehicle Advanced Technology), PE 0602143A (Soldier Lethality Technology) and PE 0603118A (Soldier Lethality Advanced Technology). The FY 2026 request was reduced by $0.499 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.241 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                    Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied            PE 0602144A / Ground Technology Research$$, NULL, 54114000, 53106000, 54984000, NULL, NULL, 13, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, 148459000, 130842000, 44146000, 44146000, NULL, 44146000, 54333000, $$This PE executes research that support and enable the Army's modernization priority for the Next Generation of Combat Vehicles including systems for the deployment and sustainment of ground movement and maneuver. This PE designs and validates technologies that are necessary and foundational for enduring and future ground movement, maneuver and protection of Soldiers and systems. The cited work is consistent with the Under Secretary of War for Research and Engineering priority focus areas. Work is performed by the Army Research Laboratory (ARL); the Chemical Biological Center (CBC); the Data and Analysis Center (DAC); the University Technology Development Division; the Armaments Center (AC); the Aviation and Missile Center (AVMC); the Soldier Center (SC); the Ground Vehicle Systems Center (GVSC); the Environmental Laboratory; and the Cold Regions Research and Engineering Laboratory; the Construction Engineering Research Laboratory; the Information Technology Laboratory; the Geotechnical and Structures Laboratory. Work in this PE complements PE 0602145A (Next Generation Combat Vehicle Technology), PE 0603119A (Ground Advanced Technology), PE 0603462A (Next Generation Combat Vehicle Advanced Technology), PE 0602143A (Soldier Lethality Technology) and PE 0603118A (Soldier Lethality Advanced Technology).$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 2.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602145A$$, $$Next Generation Combat Vehicle Technology$$, $$rdte_army_ba2$$, $$cft_ngcv$$, 2026, 71547000, 248335000, 167233000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 10, "original_pe": "0602145A", "page_header": "Department of the Army"}$$::jsonb, $$This Program element (PE) line is directly aligned to the Next Generation Combat Vehicle (NGCV) Army Modernization Priority. This PE researches, designs, and evaluates combat vehicle technologies that enable the Army to have a smarter, faster, more lethal, more precise, more protected, and more adaptable force. The focus is on building upon the foundational vehicle architectures to support the Next Generation of Combat Vehicles, to include autonomy architecture, power architecture, vehicle electronic architecture, physical architecture, lethality architecture and vehicle protection architecture. The research conducted will provide technologies to enable leap ahead capabilities for manned, optionally manned and unmanned vehicles that deliver decisive lethality. Project BF3: Combat Vehicle Robotics Tech was eliminated in PE 0602145A to reflect Department of Defense priorities and will cease Governmental development of autonomy software. Project BH5: Platform Electrification and Mobility Tech was eliminated in PE 0602145A to reflect Department of Defense priorities and will cease the design and development of hybrid-drive systems for combat vehicles. Project BK2: Virtual Prototyping was eliminated in PE 0602145A to reflect Department of Defense priorities and will cease Army capabilities to digitally design and evaluate prototype combat vehicle platforms. Projects CG8: Human Autonomy Teaming and BF6: Crew Augmentation and Optimization Tech in PE 0602145A were eliminated to reflect Department of Defense priorities and will cease Governmental development of autonomy software and autonomous platform controls. Work in this PE complements PE 0602141A (Lethality Technology), PE 0602144A (Ground Technology), PE 0602146A (Network C3I Technology), PE 0603116A (Lethality Advanced Technology), PE 0603119A (Ground Advanced Technology), PE 0603462A (Next Generation Combat Vehicle Advanced Technology), and PE 0603463A (Network C3I Advanced Technology). Work in this PE will transition to PE 0603462A (Next Generation Combat Vehicle Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Priority focus areas. Work is performed by the Ground Vehicle System Center (GVSC); the Army Research Laboratory (ARL); the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center; the Geotechnical and Structures Laboratory; the Data and Analysis Center (DAC); and the Armaments Center (AC). Overseas Operations Costs (OOC) funds this requirement in the amount of $1,041 thousand for FY 2025 Budget Estimate. Overseas Operations Costs (OOC) are those financed with former Overseas Contingency Operations (OCO) funding. The FY 2026 request was reduced by $0.139 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.403 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                      Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied         PE 0602145A / Next Generation Combat Vehicle Technology Research$$, NULL, 71848000, 84192000, 89183000, NULL, NULL, 14, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, 167383000, 169297000, 70540000, 70540000, NULL, 70540000, 90632000, $$This PE is directly aligned to the Next Generation Combat Vehicle (NGCV) Army Modernization Priority. This PE researches, designs, and evaluates combat vehicle technologies that enable the Army to have a smarter, faster, more lethal, more precise, more protected, and more adaptable force. The focus is on building upon the foundational vehicle architectures to support the Next Generation of Combat Vehicles, to include autonomy architecture, power architecture, vehicle electronic architecture, physical architecture, lethality architecture and vehicle protection architecture. The research conducted will provide technologies to enable leap ahead capabilities for manned, optionally manned and unmanned vehicles that deliver decisive lethality. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                            Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied           PE 0602145A / Next Generation Combat Vehicle Technology Research Work in this PE complements PE 0602141A (Lethality Technology), PE 0602144A (Ground Technology), PE 0602146A (Network C3I Technology), PE 0603116A (Lethality Advanced Technology), PE 0603119A (Ground Advanced Technology), PE 0603462A (Next Generation Combat Vehicle Advanced Technology), and PE 0603463A (Network C3I Advanced Technology). Work in this PE will transition to PE 0603462A (Next Generation Combat Vehicle Advanced Technology). The cited work is consistent with the Under Secretary of War for Research and Engineering Priority focus areas. Work is performed by the Ground Vehicle System Center (GVSC); the Army Research Laboratory (ARL); the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center; the Geotechnical and Structures Laboratory; the Data and Analysis Center (DAC); and the Armaments Center (AC). Overseas Operations Costs (OOC) funds this requirement in the amount of $1,041 thousand for FY 2025 Budget Estimate. Overseas Operations Costs (OOC) are those financed with former Overseas Contingency Operations (OCO) funding.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 2.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602146A$$, $$Network C3I Technology$$, $$rdte_army_ba2$$, $$peo_c3t$$, 2026, 56529000, 135543000, 110417000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 10, "original_pe": "0602146A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) is aligned to the Network and Assured Positioning, Navigation, & Timing (APNT) Army Modernization Priorities. This PE investigates technologies, techniques, components and tools to provide an Army tactical network and enabling infrastructure that support Multi-Domain operations in contested, congested, degraded, and/or denied environments. This is accomplished through the design and development of technologies and components (e.g., electronic components, software and protocols) that provide unified transport and are supportable; mobile, and survivable, and robust mission command on the move; assured and secure positioning, navigation, and timing in all environments; converged and coordinated cyber and electronic warfare activities; resilient communication and intelligence, surveillance, and reconnaissance payloads for tactical space and high-altitude platforms, and the collection, processing, and dissemination of intel/ops information into a common operating environment. Commercial technologies are continuously investigated and leveraged where possible. Work in this PE complements PE 0602143A (Soldier Lethality Technology), PE 0602145A (Next Generation Combat Vehicle Technology), PE 0602147A (Long Range Precision Fires Technology), PE 0602148A (Future Vertical Lift Technology), PE 0602150A (Air and Missile Defense Technology), PE 0603118A (Soldier Lethality Advanced Technology), PE 0603462A (Next Generation Combat Vehicle Advanced Technology), PE 0603464A (Long Range Precision Fires Advanced Technology), PE 0603465A (Future Vertical Lift Advanced Technology), PE 0603466A (Air and Missile Defense Advanced Technology), PE 0603463A (Network C3I Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                            Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied        PE 0602146A / Network C3I Technology Research Work in this performed by the United States Army Futures Command, the United States Army Space and Missile Defense Command and the Army Engineer Research and Development Center. The FY 2026 request was reduced by $1.144 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.222 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 99462000, 122811000, 123897000, NULL, NULL, 15, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, 105577000, 107029000, 53373000, 53373000, NULL, 53373000, 124967000, $$This PE is aligned to the Network and Assured Positioning, Navigation, & Timing (APNT) Army Modernization Priorities. This PE investigates technologies, techniques, components and tools to provide an Army tactical network and enabling infrastructure that support Multi-Domain operations in contested, congested, degraded, and/or denied environments. This is accomplished through the design and development of technologies and components (e.g., electronic components, software and protocols) that provide unified transport and are supportable; mobile, and survivable, and robust mission command on the move; assured and secure positioning, navigation, and timing in all environments; converged and coordinated cyber and electronic warfare activities; resilient communication and intelligence, surveillance, and reconnaissance payloads for tactical space and high-altitude platforms, and the collection, processing, and dissemination of intel/ops information into a common operating environment. Commercial technologies are continuously investigated and leveraged where possible. Work in this PE complements PE 0602143A (Soldier Lethality Technology), PE 0602145A (Next Generation Combat Vehicle Technology), PE 0602147A (Long Range Precision Fires Technology), PE 0602148A (Future Vertical Lift Technology), PE 0602150A (Air and Missile Defense Technology), PE 0603118A (Soldier Lethality Advanced Technology), PE 0603462A (Next Generation Combat Vehicle Advanced Technology), PE 0603464A (Long Range Precision Fires Advanced Technology), PE 0603465A (Future Vertical Lift Advanced Technology), PE 0603466A (Air and Missile Defense Advanced Technology), PE 0603463A (Network C3I Advanced Technology). The cited work is consistent with the Under Secretary of War for Research and Engineering priority focus areas and the Army modernization strategy. Work in this performed by the U.S. Army Futures Command, the U.S. Army Space and Missile Defense Command and the Army Engineer Research and Development Center. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                         Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied          PE 0602146A / Network C3I Technology Research$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 2.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602147A$$, $$Long Range Precision Fires Technology$$, $$rdte_army_ba2$$, $$cft_lrpf$$, 2026, 25744000, 96154000, 67589000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 10, "original_pe": "0602147A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) is directly aligned to the Army Long Range Precision Fires (LRPF) Modernization Priority. Work in this PE investigates and develops LRPF technologies to destroy, neutralize, or suppress the enemy by cannon artillery and missile fire and enable integration of fire support assets into combined arms operations. Major Focus Areas for LRPF Science and Technology include: Missiles, Cannon Artillery, and Supporting LRPF Technologies covering Strategic, Operational and Tactical Fires Lines of Effort. LRPF Missiles Applied Research investigates and develops a broad range of Missile technologies to enhance Army integrated LRPF capabilities at extended range. Cannon Artillery Applied Research investigates and develops critical technologies to increase range, precision, and both point and area effects for cannon artillery. Supporting LRPF Technologies Applied Research investigates and develops a broad range of component technologies to address weapon cost drivers and enhance performance of future LRPF munitions and systems. Research in this PE complements PE 0603464A (Long Range Precision Fires Advanced Technology). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied           PE 0602147A / Long Range Precision Fires Technology Research The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. The FY 2026 request was reduced by $1.1 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.177 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 26526000, 20829000, 25746000, NULL, NULL, 16, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, 66351000, 114294000, 24086000, 24086000, NULL, 24086000, 26378000, $$This PE is directly aligned to the Army Long Range Precision Fires (LRPF) Modernization Priority. Work in this PE investigates and develops LRPF technologies to destroy, neutralize, or suppress the enemy by cannon artillery and missile fire and enable integration of fire support assets into combined arms operations. Major Focus Areas for LRPF Science and Technology include: Missiles, Cannon Artillery, and Supporting LRPF Technologies covering Strategic, Operational and Tactical Fires Lines of Effort. LRPF Missiles Applied Research investigates and develops a broad range of Missile technologies to enhance Army integrated LRPF capabilities at extended range. Cannon Artillery Applied Research investigates and develops critical technologies to increase range, precision, and both point and area effects for cannon artillery. Supporting LRPF Technologies Applied Research investigates and develops a broad range of component technologies to address weapon cost drivers and enhance performance of future LRPF munitions and systems. Research in this PE complements PE 0603464A (Long Range Precision Fires Advanced Technology). The cited research is consistent with the Under Secretary of War for Research and Engineering priority focus areas and the Army modernization strategy. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied           PE 0602147A / Long Range Precision Fires Technology Research$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 2.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602148A$$, $$Future Verticle Lift Technology$$, $$rdte_army_ba2$$, $$cft_fvl$$, 2026, 20420000, 104850000, 52350000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 10, "original_pe": "0602148A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) is directly aligned to the Future Vertical Lift (FVL) Army Modernization Priority. This PE conducts air vehicle and mission system component design, fabrication, and evaluation to enable Army Future Vertical Lift. Emphasis is on developing aviation platform and mission system technologies to enhance manned and unmanned air vehicle combat and combat support operations for attack, reconnaissance, air assault, survivability, logistics, and command and control missions. Research in this PE contributes to the Army Science and Technology (S&T) air systems portfolio and is fully coordinated with efforts in PE 0603465A (Future Vertical Lift Advanced Technology), PE 0602183A (Air Platform Applied Research) and PE 0603043A (Air Platform Advanced Technology). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied           PE 0602148A / Future Verticle Lift Technology Research The cited research is consistent with the Under Secretary of Defense for Research and Engineering S&T focus areas and the Army Modernization Strategy. The FY 2026 request was reduced by $0.228 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.094 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 19983000, 19202000, 22439000, NULL, NULL, 17, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, 52804000, 38920000, 17727000, 17727000, NULL, 17727000, 22021000, $$This PE is directly aligned to the Future Vertical Lift (FVL) Army Modernization Priority. This PE conducts air vehicle and mission system component design, fabrication, and evaluation to enable Army Future Vertical Lift. Emphasis is on developing aviation platform and mission system technologies to enhance manned and unmanned air vehicle combat and combat support operations for attack, reconnaissance, air assault, survivability, logistics, and command and control missions. Research in this PE contributes to the Army Science and Technology (S&T) air systems portfolio and is fully coordinated with efforts in PE 0603465A (Future Vertical Lift Advanced Technology), PE 0602183A (Air Platform Applied Research) and PE 0603043A (Air Platform Advanced Technology). The cited research is consistent with the Under Secretary of War for Research and Engineering S&T focus areas and the Army Modernization Strategy. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied           PE 0602148A / Future Verticle Lift Technology Research$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 2.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602150A$$, $$Air and Missile Defense Technology$$, $$rdte_army_ba2$$, $$devcom_avmc$$, 2026, 25992000, 102784000, 49188000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 10, "original_pe": "0602150A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) line is directly aligned with the Air & Missile Defense (AMD) Army Modernization Priority. Work in this PE investigates and develops AMD technologies to enable defense of ground forces and selected geopolitical assets from aerial attack, missile attack, and surveillance. Major focus areas for AMD Science and Technology include: Missiles, Directed Energy, Gun-Based Air Defense Technologies, and Battlefield Sensors and Supporting AMD Technologies. Missiles Applied Research investigates and develops a broad range of Missile technologies to enhance Army integrated AMD capabilities at extended range. Directed Energy Applied Research investigates and develops critical High Energy Laser (HEL) technologies to explore performance against Air Defense threats and for other Directed Energy applications across Army Modernization Priorities. Gun-Based Air Defense Technologies Applied Research investigates and develops Combined Arms for Air Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                              Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied              PE 0602150A / Air and Missile Defense Technology Research Defense (CAFAD) technologies and components in a laboratory environment. Sensors and Supporting AMD Technologies Applied Research investigates and develops Battlefield Sensor and radar technologies required for detection, acquisition and tracking of air defense targets as well as supporting technologies that enhance AMD. Work in this PE complements PE 0603466A (Air and Missile Defense Advanced Technology). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Research is performed by U.S. Army Aviation and Missiles Center (AvMC). The FY 2026 request was reduced by $1.463 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.078 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 37731000, 39876000, 39929000, NULL, NULL, 18, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, 47942000, 71792000, 36113000, 36113000, NULL, 36113000, 40287000, $$This PE line is directly aligned with the Air & Missile Defense (AMD) Army Modernization Priority. Work in this PE investigates and develops AMD technologies to enable defense of ground forces and selected geopolitical assets from aerial attack, missile attack, and surveillance. Major focus areas for AMD Science and Technology include: Missiles, Directed Energy, Gun-Based Air Defense Technologies, and Battlefield Sensors and Supporting AMD Technologies. Missiles Applied Research investigates and develops a broad range of Missile technologies to enhance Army integrated AMD capabilities at extended range. Directed Energy Applied Research investigates and develops critical High Energy Laser (HEL) technologies to explore performance against Air Defense threats and for other Directed Energy applications across Army Modernization Priorities. Gun-Based Air Defense Technologies Applied Research investigates and develops Combined Arms for Air Defense (CAFAD) Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                            Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied               PE 0602150A / Air and Missile Defense Technology Research technologies and components in a laboratory environment. Sensors and Supporting AMD Technologies Applied Research investigates and develops Battlefield Sensor and radar technologies required for detection, acquisition and tracking of air defense targets as well as supporting technologies that enhance AMD. Work in this PE complements PE 0603466A (Air and Missile Defense Advanced Technology). The cited research is consistent with the Under Secretary of War for Research and Engineering priority focus areas and the Army Modernization Strategy. Research is performed by U.S. Army Aviation and Missiles Center (AvMC) in coordination with Space and Missile Defense Command (SMDC).$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 2.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602180A$$, $$Artificial Intelligence and Machine Learning Technologies$$, $$rdte_army_ba2$$, $$cft_lrpf$$, 2026, 13745000, 23702000, 20319000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 11, "original_pe": "0602180A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) investigates artificial intelligence (AI) and machine learning (ML) to support an AI-enabled Multi-Domain Operations (MDO) Force to mature target recognition/detection using multiple cooperative autonomous sensors (MCAS), leader decision-making, replication of tactical behaviors to enable autonomous capabilities for maneuver, predictive maintenance, and intelligence support for operations in support of long-range precision fires. The Army's Artificial Integration Center (AI2C) will provide strategic guidance and coordination of these applied research efforts in AI/ML across the Army Modernization enterprise. Work in this PE contributes to the Army Science and Technology (S&T) portfolio and is fully coordinated with efforts in PE 0601601A (Artificial Intelligence Basic Research) and PE 0603040A (Artificial Intelligence Advanced Technologies). The cited research is consistent with the Under Secretary of Defense for Research and Engineering S&T focus areas, the Army Modernization Strategy and the Chief Digital and Artificial Intelligence Office (CDAO). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                               Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied            PE 0602180A / Artificial Intelligence and Machine Learning Technologies Research$$, NULL, NULL, NULL, NULL, NULL, NULL, 19, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, 17072000, 13745000, NULL, NULL, NULL, NULL, NULL, $$This PE investigates artificial intelligence (AI) and machine learning (ML) to support an AI-enabled Multi-Domain Operations (MDO) Force to mature target recognition/ detection using multiple cooperative autonomous sensors (MCAS), leader decision-making, replication of tactical behaviors to enable autonomous capabilities for maneuver, predictive maintenance, and intelligence support for operations in support of long-range precision fires. The Army's Artificial Integration Center (AI2C) will provide strategic guidance and coordination of these applied research efforts in AI/ML across the Army Modernization enterprise. Work in this PE contributes to the Army Science and Technology (S&T) portfolio and is fully coordinated with efforts in PE 0601601A (Artificial Intelligence Basic Research) and PE 0603040A (Artificial Intelligence Advanced Technologies). The cited research is consistent with the Under Secretary of War for Research and Engineering S&T focus areas, the Army Modernization Strategy and the Chief Digital and Artificial Intelligence Office (CDAO). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                         Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied        PE 0602180A / Artificial Intelligence and Machine Learning Technologies Research$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 2.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602181A$$, $$All Domain Convergence Applied Research$$, $$rdte_army_ba2$$, $$cft_ngcv$$, 2026, 0, 13775000, 12269000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 11, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0602181A", "page_header": "Department of the Army"}$$::jsonb, $$The Program Element (PE) executes research as part of a campaign of learning to assess feasibility of technologies in an operational environment, learning from early failure and re-scope research to improve speed of response, scalability, interoperability, and range of engagement. This PE will investigate technologies that will enable sensor to shooter applications, from tactical to strategic level, taking a system design approach in support of Army experimentation events and Department of Defense (DoD) Combined Joint All-Domain Command and Control (CJADC2). The research will enable optimal lethal and non-lethal effects across all domains using artificial intelligence and machine learning to improve how we recognize threats, augment and enhance leader decision-making, and replicate tactical behaviors to enable autonomous capabilities. Work in this PE complements PE 0602145A (Next Generation Combat Vehicle Technology), PE 0602146A (Network C3I Technology) and PE 0603463 (Network C3I Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Priority focus areas and the Army Modernization Strategy. Work in this program is performed by the Army Research Laboratory (ARL).$$, NULL, NULL, NULL, NULL, NULL, NULL, 20, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, 12088000, 0, NULL, NULL, NULL, NULL, NULL, $$The PE executes research as part of a campaign of learning to assess feasibility of technologies in an operational environment, learning from early failure and re-scope research to improve speed of response, scalability, interoperability, and range of engagement. This PE will investigate technologies that will enable sensor to shooter applications, from tactical to strategic level, taking a system design approach in support of Army experimentation events and DoW Combined Joint All-Domain Command and Control (CJADC2). The research will enable optimal lethal and non-lethal effects across all domains using artificial intelligence and machine learning to improve how we recognize threats, augment and enhance leader decision-making, and replicate tactical behaviors to enable autonomous capabilities. Work in this PE complements PE 0602145A (Next Generation Combat Vehicle Technology), PE 0602146A (Network C3I Technology) and PE 0603463A (Network C3I Advanced Technology). The cited work is consistent with the Under Secretary of War for Research and Engineering Priority focus areas and the Army Modernization Strategy. Work in this program is performed by the Army Research Laboratory (ARL).$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 2.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602183A$$, $$Air Platform Applied Research$$, $$rdte_army_ba2$$, $$cft_fvl$$, 2026, 53305000, 53611000, 48854000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 11, "original_pe": "0602183A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) undertakes applied research efforts that support and enable the overall Army Aviation portfolio in general, and the Army's modernization priority for future vertical lift (FVL). Vital and enduring applied research is conducted in the air portfolio that supports mid-to-long term requirements in contested operational environments and technologies that have broad application to FVL modernization, as well as overall Army and specific Department of Defense (DoD) aviation needs. Research in this PE contributes to the Army Science and Technology (S&T) air systems portfolio and is fully coordinated with efforts in PE 0602148A (Future Vertical Lift Technology), PE 0603465A (Future Vertical Lift Advanced Technology) and PE 0603043A (Air Platform Advanced Technology). The cited research is consistent with the Under Secretary of Defense for Research and Engineering S&T focus areas and the Army Modernization Strategy. The FY 2026 request was reduced by $0.592 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.264 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                 Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied            PE 0602183A / Air Platform Applied Research Research$$, NULL, 69846000, 75075000, 74636000, NULL, NULL, 22, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, 42356000, 63305000, 43700000, 43700000, NULL, 43700000, 74881000, $$This PE undertakes applied research efforts that support and enable the overall Army Aviation portfolio in general, and the Army's modernization priority for future vertical lift (FVL). Vital and enduring applied research is conducted in the air portfolio that supports mid-to-long term requirements in contested operational environments and technologies that have broad application to FVL modernization, as well as overall Army and specific DoW aviation needs. Research in this PE contributes to the Army Science and Technology (S&T) air systems portfolio and is fully coordinated with efforts in PE 0602148A (Future Vertical Lift Technology), PE 0603465A (Future Vertical Lift Advanced Technology) and PE 0603043A (Air Platform Advanced Technology). The cited research is consistent with the Under Secretary of War for Research and Engineering S&T focus areas and the Army Modernization Strategy.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 2.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602184A$$, $$Soldier Applied Research$$, $$rdte_army_ba2$$, $$dw_osd$$, 2026, 27597000, 17622000, 14131000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 11, "original_pe": "0602184A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) investigates, designs, and performs research focused on technologies necessary for capability enhancements for the Soldier and Squad over the long-term well beyond those technologies planned within the Soldier Lethality Cross- Functional Team. Applied research projects investigate nascent and enduring science and technology areas that are applicable to the individual Soldier and Squads of Soldiers needs with emphasis on maximizing Soldier and Squad performance, lethality, mobility and survivability. This PE also designs and validates technologies that are necessary and foundational for future capabilities with far- reaching impact on mission success. The outputs of these efforts transition to advanced research efforts that mature and demonstrate potential opportunities to realize improved Soldier performance and inform technical requirements for future Soldier systems. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                    Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied               PE 0602184A / Soldier Applied Research Research The PE will fund civilian salaries for in-house researchers/scientists and program managers collaborating with external subject matter experts in academia and industry who are leaders in these technology research areas. This PE is coordinated with PE 0602143A (Soldier Lethality Technology), 0602785A (Manpower, Personnel and Training Technology), 0603007A (Manpower, Personnel and Training Advanced Tech), 0603044A (Soldier Advanced Technology), and 0603118A (Soldier Lethality Advanced Technology). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. The FY 2026 request was reduced by $0.226 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.101 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 2499000, 2535000, 2568000, NULL, NULL, 23, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, 13873000, 27597000, 2429000, 2429000, NULL, 2429000, 2593000, $$This PE investigates, designs, and performs research focused on technologies necessary for capability enhancements for the Soldier and Squad over the long-term well beyond those technologies planned within the Soldier Lethality Cross- Functional Team. Applied research projects investigate nascent and enduring science and technology areas that are applicable to the individual Soldier and Squads of Soldiers needs with emphasis on maximizing Soldier and Squad performance, lethality, mobility and survivability. This PE also designs and validates technologies that are necessary and foundational for future capabilities with far-reaching impact on mission success. The outputs of these efforts transition to advanced research efforts that mature and demonstrate potential opportunities to realize improved Soldier performance and inform technical requirements for future Soldier systems. The PE will fund civilian salaries for in-house researchers/scientists and program managers collaborating with external subject matter experts in academia and industry who are leaders in these technology research areas. This PE is coordinated with PE 0602143A (Soldier Lethality Technology), 0602785A (Manpower, Personnel and Training Technology), 0603007A (Manpower, Personnel and Training Advanced Tech), 0603044A (Soldier Advanced Technology), and 0603118A (Soldier Lethality Advanced Technology). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                            Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied           PE 0602184A / Soldier Applied Research Research The cited research is consistent with the Under Secretary of War for Research and Engineering priority focus areas and the Army Modernization Strategy.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 2.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602201F$$, $$Aerospace Vehicle Technologies$$, $$rdte_af_ba2$$, $$afrl_rq$$, 2026, 0, 188530000, 15235000, NULL, $${"ba_raw": "6.2", "source": "af_r1_fy26", "original_pe": "0602201F"}$$::jsonb, $$This program investigates, develops, and analyzes aerospace vehicle technologies in the primary areas of high speed systems, autonomy and flight control technologies, aeromechanics, structure systems and nuclear system technology. The effort has five current projects, each focusing on a technology area critical to the Department of the Air Force. The High Speed Systems Technology project develops component level vehicle technologies for expendable and reusable high speed/ hypersonic aerospace systems. The Flight Controls and Pilot-Vehicle Interface project develops technologies that enable affordable mass and maximum capabilities for manned, remotely-piloted and autonomous aerospace vehicles. The Aeromechanics and Integration project designs advanced aerodynamic vehicle configurations that are developed and analyzed through simulations, experiments, and multi-disciplinary analyses. It also develops design techniques, incorporating vehicle, inter- vehicle, and intra-vehicle control systems. The Structures project develops and exploits new materials, and fabrication processes. The Nuclear System Technology project provides science and technology to preserve nuclear deterrence for future generations. In FY 2025, the RDT&E Budget Activity 02 (BA02) Aerospace Vehicles Technologies efforts and activities under PE 0602201F, was transferred to PE 0602203F, Aerospace Propulsion for increased integration between airframe, flight control, propulsion, electrical, power and thermal management. In FY 2025, the entirety of PE 0602201F, Aerospace Vehicle Technologies, Project 622401 Structures, was transferred to PE 0602203F, Aerospace Propulsion, Project 622401 Structures. In FY 2025, the entirety of PE 0602201F, Aerospace Vehicle Technologies, Project 622403, Flight Controls and Pilot-Vehicle Interface, was transferred to PE 0602203F, Aerospace Propulsion, Project 622403 Flight Controls and Pilot-Vehicle Interface. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied        PE 0602201F / Aerospace Vehicle Technologies Research In FY 2025, the entirety of PE 0602201F, Aerospace Vehicle Technologies, Project 622404, Aeromechanics, was transferred to PE 0602203F, Aerospace Propulsion, Project 622401 Structures. In FY 2025, the entirety of PE 0602201F, Aerospace Vehicle Technologies, Project 622405, High Speed Systems Technology, was transferred to PE 0602203F, Aerospace Propulsion, Project 622405 High Speed Systems Technology. This program element may include necessary civilian pay expenses required to manage, execute, and deliver science & technology capabilities. The use of program funds in this program element would be in addition to the civilian pay expenses budgeted in program elements 0601102F, 0602020F, 0602102F, 0602203F,0602202F, 0602204F, 0602602F, 0602605F, 0602788F, 0602298F, and 1206601SF. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology capabilities. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters.$$, NULL, 0, 0, 0, NULL, NULL, 6, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 4932000, 0, 0, 0, 0, 0, 0, $$This program provides sustaining science and technology to preserve nuclear deterrence for future generations, develops complimentary projects to inform future systems, establishing inter-agency partnerships for Modeling & Simulation and test platforms, and coordinates with existing programs for next generation strategic systems development and test platforms. This program is executed by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. Funds in this PE may be used to investigate specified technology advancements in air, space and/or cyber domains. In order to manage, execute, and deliver science and technology capabilities, this program element may include: necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                               Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied   PE 0602201F / Aerospace Vehicle Technologies Research$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602202F$$, $$Human Effectiveness Applied Research$$, $$rdte_af_ba2$$, $$afrl_rh$$, 2026, 133928000, 138098000, 137425000, NULL, $${"ba_raw": "6.2", "source": "af_r1_fy26", "original_pe": "0602202F"}$$::jsonb, $$This program conducts applied research in the area of airmen training, airmen performance sustainment, bioeffects, and understanding and shaping adversarial behavior, maturing technology and readying it for eventual integration into combat and combat support systems. The Learning and Operational Readiness project conducts research to increase the agility of training to operate aircraft, weapons, logistics, intelligence, and space systems while advancing learning and performance assessment science and practice. The Biosciences Performance project conducts research to discover, demonstrate, and transition capabilities which optimize and safe-guard Airman and Guardian physical and cognitive performance allowing for the maximum impact during combat and contingency operations. The Warfighter Interfaces and Teaming project conducts research to discover, develop, and transition advanced interface technology, decision aiding tools, and situationally-adaptive augmentation methods to seamlessly integrate Airmen and intelligent machines into maximally collaborative warfighting teams. The Bioeffects project conducts novel and operational directed energy bioeffects research, exposure effects analysis and develops national/international exposure standards for the Air Force to enable, sustain, and enhance Airman performance and protection during deployment of directed energy systems. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied        PE 0602202F / Human Effectiveness Applied Research Research The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology capabilities. This program includes funding for the requisite DAF Science & Engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The use of program funds in this program element is in conjunction with the civilian pay expenses budgeted in the following program elements: 1206601SF, 0601102F, 0602020F, 0602102F, 0602203F, 0602204F, 0602298F, 0602336F, 0602602F, 0602605F, 0602788F, and 0603680F. In FY 2026, $64.637 million is budgeted in this program for 349 direct Full-Time Equivalent (FTE) civilians. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation. The FY 2026 request was reduced by $0.427 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” The FY 2026 request was reduced by $6.733 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative.” This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied       PE 0602202F / Human Effectiveness Applied Research Research$$, NULL, 104573000, 126947000, 134070000, NULL, NULL, 7, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 130281000, 145285000, 103170000, 103170000, 0, 103170000, 136677000, $$This program focuses on enhancing DAF warfighting capability by ensuring the human weapon systems operators are at peak performance by conducting applied research focused on the areas of learning and knowledge assimilation, cognitive and physical performance sustainment, directed energy bioeffects, human-machine teaming, and understanding and shaping adversarial behavior. This program matures technology and readies it for eventual integration into combat and combat support systems. The Learning and Operational Readiness project conducts research to increase the agility of training to operate aircraft, weapons, logistics, and intelligence while advancing learning and performance assessment science and practice. The Biosciences Performance project conducts research to discover, demonstrate, and transition capabilities which optimize and safe-guard Airman physical and cognitive performance allowing for the maximum impact during combat and contingency operations. The Warfighter Interfaces and Teaming project conducts research to discover, develop, and transition advanced interface technology, decision aiding tools, and situationally-adaptive augmentation methods to seamlessly integrate Airmen and intelligent machines into maximally collaborative warfighting teams. The Bioeffects project conducts novel and operational directed energy bioeffects research, exposure effects analysis and develops national/international exposure standards for the Air Force to enable, sustain, and enhance Airman performance and protection during deployment of directed energy systems. The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology capabilities. Funds in this PE may be used to investigate specified technology advancements in air, space and/or cyber domains. This program includes funding for the requisite DAF Science & Engineering and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The use of program funds in this program element is in conjunction with the civilian pay expenses Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied         PE 0602202F / Human Effectiveness Applied Research Research budgeted in the following program elements: 1206601SF, 126616SF, 0601102F, 0602020F, 0602102F, 0602203F, 0602204F, 0602298F, 0602336F, 0602602F, 0602605F, 0602788F, and 0603680F. In FY 2027, $60.709 million is budgeted in this program for 331 direct Full-Time Equivalent civilians. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602203F$$, $$Aerospace Systems Technologies$$, $$rdte_af_ba2$$, $$afrl_rq$$, 2026, 321059000, 233413000, 333320000, NULL, $${"ba_raw": "6.2", "source": "af_r1_fy26", "original_pe": "0602203F"}$$::jsonb, $$In FY 2026, the RDT&E Budget Activity 02 (BA02) 0602203F Aerospace Propulsion program is renamed Aerospace Systems Technologies program. Aerospace Systems Technologies program includes Applied Research funds for contracts, in-house efforts, civilian pay, travel, and infrastructure support costs for the Air Force Research Laboratory (AFRL) Aerospace Systems Directorate (RQ) located at Wright-Patterson AFB, Ohio, Edwards AFB, CA, and Arnold AFB, TN. Aerospace Systems investigates, develops, and analyzes aerospace system technologies for military applications that remove operational limitations while advancing warfighter capabilities critical to the future threat. Technologies being developed include Aerodynamics and Structures Technology, Aerospace Power & Flight Control Technology, High Speed Systems, Advanced Propulsion, Turbine Engine, Aerospace Power, Rocket Propulsion, and Aerospace Fuels. These technologies enable Autonomous Collaborative Platforms, High Speed Weapons and Platforms, and Rapidly Produced and Upgraded Platforms. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                         R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied             PE 0602203F / Aerospace Systems Technologies Research This program investigates, develops, and analyzes aerospace system technologies for military applications that remove operational limitations and advance warfighter capabilities critical to the future threat. The specific areas of applied research are in: -Aerodynamics and Structures Technology: Develops and exploits advanced aerodynamic vehicle configurations, new materials, fabrication processes, design techniques, and incorporates vehicle, inter-vehicle, and intra-vehicle control systems enabling advanced capabilities for the Air Force. -Aerospace Power & Flight Control Technology: Develops technologies that enable maximum affordable capability focusing on manned and autonomous collaborative platforms for military applications that remove operational limitations and enable advanced vehicle designs and mission systems. -High-Speed Systems Technology: Design and develop cutting-edge technologies for high-speed and hypersonic aerospace systems, including advanced high- temperature structures and innovative aerodynamic vehicle designs. These advancements will enable the creation of next-generation high-speed weapons, surveillance and reconnaissance platforms, and multi-domain vehicles. Furthermore, high-speed aerospace vehicles, including hypersonic capabilities, and high-speed air-breathing propulsion systems will be developed, enabling revolutionary capabilities to counter near-peer competitors. -Advanced Propulsion Technology: Note: In FY2026 this effort is transferred to High-Speed Systems Technology. Develops high-speed (to include hypersonic) aerospace vehicles as well as high-speed air breathing propulsion enabling revolutionary capabilities for near peer-to-peer competition. -Combustion and Mechanical Systems: Evaluates lubricants, for advanced turbine engines, and combined cycle engines with emphasis on low cost and high-speed applications. -Turbine Engine Technology: Develops engine technology to address military specific needs for manned systems, autonomous collaborative platforms, and munition applications in various class sizes. -Aerospace Power Technology: Note: In FY2026 this effort is transferred to Aerospace Power & Flight Control Technology. Develops electrical and thermal control technologies for military applications that remove operational limitations enabling advanced vehicle designs and high-power mission systems. - Rocket Propulsion Technologies: Develops rocket propulsion technologies for the design, development, and fabrication of strategic systems and tactical missiles enabling timely and affordable capacity. -Aerospace Fuel Technology: Evaluates fuels and related technologies to enable increased performance and affordability of high-speed and munition capabilities. In FY 2025, the RDT&E Budget Activity 02 (BA02) Aerospace Vehicles Technologies efforts and activities under PE 0602201F, were transferred to PE 0602203F, Aerospace Propulsion for increased integration between airframe, flight control, propulsion, electrical, power and thermal management. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied    PE 0602203F / Aerospace Systems Technologies Research In FY 2025, the entirety of PE 0602201F, Aerospace Vehicle Technologies, Project 622401 Structures, was transferred to PE 0602203F, Aerospace Propulsion, Project 622401 Structures. In FY 2025, the entirety of PE 0602201F, Aerospace Vehicle Technologies, Project 622404, Aeromechanics, was transferred to PE 0602203F, Aerospace Propulsion, Project 622401 Structures. In FY 2025, the entirety of PE 0602201F, Aerospace Vehicle Technologies, Project 622403, Flight Controls and Pilot-Vehicle Interface, was transferred to PE 0602203F, Aerospace Propulsion, Project 622403 Flight Controls and Pilot-Vehicle Interface. In FY 2025, the entirety of PE 0602201F, Aerospace Vehicle Technologies, Project 622405, High Speed Systems Technology, was transferred to PE 0602203F, Aerospace Propulsion, Project 622405 High Speed Systems Technology. Efforts in this program have been coordinated through the Department of Defense (DoD) Science and Technology (S&T) Executive Committee process to harmonize efforts and eliminate duplication. This program element may include necessary civilian pay expenses required to manage, execute, and deliver science & technology capabilities. In FY 2026, $122.064 million is budgeted in this program for 616 Civilian Full- Time Equivalents (FTEs). The use of program funds in this program element would be in addition to the civilian pay expenses budgeted in program elements 0601102F, 0602020F, 0602102F, 0602202F, 0602204F, 0602336F, 0602602F, 0602605F, 0602788F, 0602298F, 0603680F, 1206601SF and 1206616SF. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver S&T capabilities. Funds in this program element may be used to investigate specified technology advancements in multiple domains. The FY 2026 request was reduced by $1.238 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $13.547 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied      PE 0602203F / Aerospace Systems Technologies Research$$, NULL, 380280000, 434277000, 437668000, NULL, NULL, 8, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 330065000, 381094000, 397809000, 397809000, 0, 397809000, 444894000, $$In FY 2026, the RDT&E Budget Activity 02 (BA02) 0602203F Aerospace Propulsion program is renamed Aerospace Systems Technologies program. Aerospace Systems Technologies program includes Applied Research funds for contracts, in-house efforts, civilian pay, travel, and infrastructure support costs for the Air Force Research Laboratory (AFRL) Aerospace Systems Directorate (RQ) located at Wright-Patterson AFB, Ohio, Edwards AFB, CA, and Arnold AFB, TN. Aerospace Systems investigates, develops, and analyzes aerospace system technologies for military applications that remove operational limitations while advancing warfighter capabilities critical to the future threat. Aerospace Systems is focused on integration by design and starting with desired mission effect to deliver war winning capabilities to defend the homeland, provide nuclear deterrence, and deliver force projection. Technologies being developed include Aerodynamics and Structures, Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                             R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied PE 0602203F / Aerospace Systems Technologies Research Aerospace Power & Flight Control, High Speed Systems, Advanced Propulsion, Turbine Engine, Aerospace Power, Rocket Propulsion, and Aerospace Fuels. These technologies enable Autonomous Collaborative Platforms, High Speed Weapons and Platforms, and Rapidly Produced and Upgraded Platforms. This program investigates, develops, and analyzes aerospace system technologies for military applications that remove operational limitations and advance warfighter capabilities critical to the future threat. The specific areas of applied research are in: -Aerodynamics and Structures Technology: Develops and exploits advanced aerodynamic vehicle configurations, new materials, fabrication processes, design techniques, and incorporates vehicle, inter-vehicle, and intra-vehicle control systems enabling advanced capabilities for the Air Force. -Aerospace Power & Flight Control Technology: Develops technologies that enable maximum affordable capability focusing on manned and autonomous collaborative platforms for military applications that remove operational limitations and enable advanced vehicle designs and mission systems. -High-Speed Systems Technology: Design and develop cutting-edge technologies for high-speed and hypersonic aerospace systems, affordable mass, including advanced high-temperature structures and innovative aerodynamic vehicle designs. These advancements will enable the creation of next-generation high-speed weapons, surveillance and reconnaissance platforms, and multi-domain vehicles. Furthermore, high-speed aerospace vehicles, including hypersonic capabilities, and high-speed air-breathing propulsion systems will be developed, enabling revolutionary capabilities to counter near-peer competitors. -Advanced Propulsion Technology: Note: In FY2026 this effort is transferred to High-Speed Systems Technology. Develops high-speed (to include hypersonic) aerospace vehicles as well as high-speed air breathing propulsion enabling revolutionary capabilities for near peer-to-peer competition. -Combustion and Mechanical Systems: For advanced turbine engines, and combined cycle engines with emphasis on low cost weapons and uncrewed platforms. -Turbine Engine Technology: Develops engine technology to address military specific needs for manned systems, autonomous collaborative platforms, and munition applications in various class sizes. -Aerospace Power Technology: Note: In FY 2026 this effort is transferred to Aerospace Power & Flight Control Technology. Develops electrical and thermal control technologies for military applications that remove operational limitations enabling advanced vehicle designs and high-power mission systems. - Rocket Propulsion Technologies: Develops rocket propulsion technologies for the design, development, and fabrication of strategic systems and tactical missiles enabling timely and affordable capacity. -Aerospace Fuel Technology: Note: In FY 2027 this effort is transferred to Turbine Engine Technology. Evaluates fuels and related technologies to enable increased performance and affordability of high-speed and munition capabilities. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied         PE 0602203F / Aerospace Systems Technologies Research This program element may include necessary civilian pay expenses required to manage, execute, and deliver science & technology capabilities. The use of program funds in this program element would be in addition to the civilian pay expenses budgeted in program elements 0601102F, 0602020F, 0602102F, 0602202F, 0602204F, 0602336F, 0602602F, 0602605F, 0602788F, 0602298F, 0603680F, 1206601SF and 1206616SF. In FY 2027, 118.635 million is budgeted in this program for 602 direct Full-Time Equivalent (FTE) civilians. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation. This program includes funding for the requisite DAF Science & Engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. Funds in this program element may be used to investigate specified technology advancements in multiple domains. Aerospace Systems Technologies, received a Congressional add for FY2026 $2.500 million for hypersonic high-speed aerodynamics research. Upon Congressional spend plan approval, an Internal Reprogramming (IR) will be processed aligning the funding to PE0602201F for proper execution. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602204F$$, $$Aerospace Sensors$$, $$rdte_af_ba2$$, $$afrl_ry$$, 2026, 199120000, 236340000, 193029000, NULL, $${"ba_raw": "6.2", "source": "af_r1_fy26", "original_pe": "0602204F"}$$::jsonb, $$The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This program develops the technology base for Air Force aerospace sensors and electromagnetic combat. Advances in aerospace sensors are required to increase combat effectiveness by providing anytime, anywhere surveillance, reconnaissance, precision targeting, and electromagnetic warfare capabilities. To achieve this progress, this program pursues simultaneous advances in: 1) generating, controlling, receiving, and processing electronic and photonic signals for radio frequency sensor aerospace applications; 2) affordable, reliable, all weather radio frequency and electro-optical/infrared countermeasure concepts; 3) positioning, navigation Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied           PE 0602204F / Aerospace Sensors Research and timing integrity, accuracy, and resiliency; 4)electro-optical and infrared aerospace sensor technologies for a variety of offensive and defensive uses; 5) radio frequency antennas and associated electronics for airborne and space surveillance, together with active and passive electro-optical/infrared sensors; 6) technologies to manage and fuse on-board sensor information for timely, comprehensive situational awareness; 7) technology for affordable, trusted, resilient, and reliable, all-weather surveillance, reconnaissance, and precision strike radio frequency sensors and electronic combat systems; and 8) technologies that aid in the development of agile and resilient mission systems. This program has been coordinated through the Department of Defense Science and Technology Executive Committee process to harmonize efforts and eliminate duplication. Funds in this program element may be used to investigate specified technology advancements in multiple domains. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology capabilities. This program includes funding for the requisite DAF Science & Engineering and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The use of program funds in this program element is in conjunction with the civilian pay expenses budgeted in the following program elements: 1206601SF, 0601102F, 0602020F, 0602102F, 0602202F, 0602203F, 0602298F, 0602336F, 0602602F, 0602605F, 0602788F, and 0603680F. In FY 2026, $106.756 million is budgeted in this program for 535 direct Full-Time Equivalent civilians. The Air Force Research Laboratory utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters.$$, NULL, 180585000, 198722000, 211647000, NULL, NULL, 9, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 183053000, 218973000, 164962000, 164962000, 0, 164962000, 215906000, $$The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This program develops the technology base for Air Force aerospace sensors and electromagnetic combat. Advances in aerospace sensors are required to increase combat effectiveness by providing anytime, anywhere surveillance, reconnaissance, precision targeting, and electromagnetic warfare capabilities. To achieve this progress, this program pursues simultaneous advances in: 1) generating, controlling, receiving, and processing electronic and photonic signals for radio frequency sensor aerospace applications; 2) affordable, reliable, all weather radio frequency and electro-optical/infrared countermeasure concepts; 3) positioning, navigation and timing integrity, accuracy, and resiliency; 4) electro-optical and infrared aerospace sensor technologies for a variety of offensive and defensive uses; 5) radio frequency antennas and associated electronics for airborne and space surveillance, together with active and passive electro-optical/infrared sensors; 6) technologies to manage and fuse on-board sensor information for timely, comprehensive situational awareness; 7) technology for affordable, trusted, resilient, and reliable, all-weather surveillance, reconnaissance, and precision strike radio frequency sensors and electronic combat systems; and 8) technologies that aid in the development of agile and Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied    PE 0602204F / Aerospace Sensors Research resilient mission systems. This program has been coordinated through the Department of War Science and Technology Executive Committee process to harmonize efforts and eliminate duplication. This program is accomplished by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. Funds in this program element may be used to investigate specified technology advancements in multiple domains. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology capabilities. This program includes funding for the requisite DAF Science & Engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The use of program funds in this program element is in conjunction with the civilian pay expenses budgeted in the following program elements: 1206601SF, 1206616SF, 0601102F, 0602020F, 0602102F, 0602202F, 0602203F, 0602298F, 0602336F, 0602602F, 0602605F, 0602788F, and 0603680F. In FY 2027, 101.785 million is budgeted in this program for 512 direct Full-Time Equivalent (FTE) civilians. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602212F$$, $$Defense Laboratories R&D Projects (10 U.S.C, Sec 2358)$$, $$rdte_af_ba2$$, $$afrl$$, 2026, 0, 111692000, 0, NULL, $${"ba_raw": "6.2", "source": "af_r1_fy26", "original_pe": "0602212F"}$$::jsonb, $$Implementation of 10 U.S.C. Section 2363, amendment to PL 110-417, 10 U.S.C. Section 2358 and 10 U.S.C. 2805(d)(1)(B), to fund: innovative basic and applied research conducted at the defense laboratory and supports military missions; development programs supporting the transition of technologies developed by the defense laboratory into operational use; workforce development activities improving the capacity of the defense laboratory to recruit and retain personnel with necessary scientific and engineering expertise that support military missions; and the repair or minor military construction of the laboratory infrastructure and equipment. The Air Force is dependent on technological advances in response to emerging threats and to maintain a competitive advantage. Air Force has a comprehensive and deliberative planning process to identify and fund research that is expected to have the greatest benefit to the Air Force and the warfighter. 10 U.S.C. Section 2363 provides the Commander of the Air Force Research Laboratory (AFRL), in consultation with the Air Force Science and Technology (S&T) Executive, a degree of flexibility to rapidly exploit scientific breakthroughs or respond to emerging threats, to include developing a skilled workforce and necessary infrastructure. This flexibility increases the rate of innovation and accelerates the development and fielding of needed military capabilities to address current and future problems. The Air Force has established PE 0602212F, where the 10 U.S.C. Section 2363 funds are internally reprogrammed to this program element in the year of execution after receipt of the appropriation. This allows increased transparency to Congress on 10 U.S.C. Section 2363 funding and additional execution flexibility for 10 U.S.C. Section 2363 activities to cross all technology areas. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied        PE 0602212F / Defense Laboratories R&D Projects (10 U.S.C, Sec 2358) Research$$, NULL, 0, 0, 0, NULL, NULL, 10, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 97809000, 0, 0, 0, 0, 0, 0, $$Implementation of 10 U.S.C. Section 2363, amendment to PL 110-417, 10 U.S.C. Section 2358 and 10 U.S.C. 2805(d)(1)(B), to fund: innovative basic and applied research conducted at the defense laboratory and supports military missions; development programs supporting the transition of technologies developed by the defense laboratory into operational use; workforce development activities improving the capacity of the defense laboratory to recruit and retain personnel with necessary scientific and engineering expertise that support military missions; and the repair or minor military construction of the laboratory infrastructure and equipment. The Air Force is dependent on technological advances in response to emerging threats and to maintain a competitive advantage. Air Force has a comprehensive and deliberative planning process to identify and fund research that is expected to have the greatest benefit to the Air Force and the warfighter. 10 U.S.C. Section 2363 provides the Commander of the Air Force Research Laboratory (AFRL), in consultation with the Air Force Science and Technology (S&T) Executive, a degree of flexibility to rapidly exploit scientific breakthroughs or respond to emerging threats, to include developing a skilled workforce and necessary infrastructure. This flexibility increases the rate of innovation and accelerates the development and fielding of needed military capabilities to address current and future problems. The Air Force has established PE 0602212F, where the 10 U.S.C. Section 2363 funds are internally reprogrammed to this program element in the year of execution after receipt of the appropriation. This allows increased transparency to Congress on 10 U.S.C. Section 2363 funding and additional execution flexibility for 10 U.S.C. Section 2363 activities to cross all technology areas. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied        PE 0602212F / Defense Laboratories R&D Projects (10 U.S.C, Sec 2358) Research$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602213A$$, $$C3I Applied Cyber$$, $$rdte_army_ba2$$, $$peo_c3t$$, 2026, 4716000, 20664000, 28656000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 11, "original_pe": "0602213A", "page_header": "Department of the Army"}$$::jsonb, $$This Program element (PE) investigates, designs, and develops cyber architectures, software, tools, and techniques to enable Cyber Electromagnetic Activities (CEMA) to counter adversary communications and harden the Army's tactical communications networks against cyber attacks. For offensive cyber effort against adversary communications, efforts investigate capabilities to identify and capture data traversing targeted networks for detection, identification, exploitation, direction finding, geolocation, and denial of service. Defensive cyber efforts in this PE focus on hardening the Army's tactical network by investigating and applying robust cyber security technologies and techniques to advance software, algorithms and protocols utilized within tactical networks, to protect against nation state level cyber-attacks and maintain Warfighter confidence in network information by hardening the blue force attack surface. The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization priorities. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                        Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied        PE 0602213A / C3I Applied Cyber Research$$, NULL, 5493000, 16966000, 15634000, NULL, NULL, 24, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, 28656000, 4716000, 63000, 63000, NULL, 63000, 15789000, $$This PE investigates, designs, and develops cyber architectures, software, tools, and techniques to enable Cyber Electromagnetic Activities (CEMA) to counter adversary communications and harden the Army's tactical communications networks against cyber attacks. For offensive cyber effort against adversary communications, efforts investigate capabilities to identify and capture data traversing targeted networks for detection, identification, exploitation, direction finding, geolocation, and denial of service. Defensive cyber efforts in this PE focus on hardening the Army's tactical network by investigating and applying robust cyber security technologies and techniques to advance software, algorithms and protocols utilized within tactical networks, to protect against nation state level cyber-attacks and maintain Warfighter confidence in network information by hardening the blue force attack surface. The cited research is consistent with the Under Secretary of War for Research and Engineering priority focus areas and the Army modernization priorities. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied           PE 0602213A / C3I Applied Cyber Research$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 2.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602230D8Z$$, $$Defense Technology Innovation (Beyond 5G)$$, $$rdte_dw_ba2$$, $$dw$$, 2026, 46261000, 19379000, 28515000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "dw", "page_num": 66, "original_pe": "0602230D8Z", "page_header": "Defense-Wide", "fy26_v182_disc_K": 40051, "fy26_v182_supp_K": 351380, "fy26_v182_total_K": 391431, "fy26_v182_note_name": "Research, Development, Test & Evaluation, Defense-Wide for Defense Technology Innovation (Beyond 5G)", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 3655}$$::jsonb, $$This program supports the Department's priorities to rebuild our military by matching capabilities to threats, and to reestablish deterrence by defending the Homeland. Today’s mobile and tactical communications are stove-piped and limit the force from fully executing Combined Joint All-Domain Command and Control (CJADC2) concepts of tomorrow. Warfighters require integrated network mission solutions utilizing 5G/FutureG technologies to support the future battle. Beyond 5G delivers unified solutions in mobile and tactical networks to give U.S. DoD an asymmetric advantage. Through strategically architected lines of effort in Resilient and Open Commercial Solutions (ROCS), Integrated Sensing and Communications (ISAC), Expeditionary and Tactical Use (ETU), and Ubiquitous, Secure and Instant Access (USIA), this PE enables DoD to keep pace with warfighter capability requirements. The net benefit will be a reduction in the technical and tactical burden on DoD network operators via implementations of high performing mission solutions which are situationally aware and can rapidly and autonomously adapt to changing battlefield conditions. By maximizing the use of dual-use technologies as the foundation of more capable military solutions, this research and development enables a force to fight and win with agile spectrum operations where novel and asymmetric capabilities are matched to threats. To protect the Homeland, this PE continues critical research activities which enable the utilization of existing wireless infrastructure as a sensor for low flying threats to the Homeland. When integrated, this detection network becomes a key component of the Golden Dome for America initiative.$$, NULL, 43425000, 46403000, 46642000, NULL, NULL, 17, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 27554000, 391431000, 43405000, 43405000, NULL, 43405000, 48178000, $$This program supports the Department's priorities to rebuild our military by matching capabilities to threats, and to reestablish deterrence by defending the Homeland. Today’s mobile and tactical communications are stove-piped and limit the force from fully executing Combined Joint All-Domain Command and Control (CJADC2) concepts of tomorrow. Warfighters require integrated network mission solutions utilizing 6G wireless technologies to support the future battle. Beyond 5G delivers unified solutions in mobile and tactical networks to give U.S. Department of War (DoW) an asymmetric advantage. Through strategically architected lines of effort in Resilient and Open Commercial Solutions (ROCS), Integrated Sensing and Communications (ISAC), Expeditionary and Tactical Use (ETU), Agile Spectrum Operations (ASO), and Ubiquitous, Secure and Instant Access (USIA), this program enables DoW to keep pace with warfighter capability requirements and remain agile on a rapidly changing battlefield. The net benefit is a reduction in the technical and tactical burden on DoW network operators via implementations of high performing mission solutions which are situationally aware and can rapidly and autonomously adapt to changing battlefield conditions. By maximizing the use of dual-use technologies as the foundation of more capable military solutions. This research and development enables a force to fight and win with agile spectrum operations where novel and asymmetric capabilities are matched to threats. Integrated Sensing and Communications research and engineering in this program continues critical research activities which enable the utilization of existing wireless infrastructure as a sensor for object and environmental detection. When integrated, this sensor network becomes a key component of the Golden Dome for America initiative and other military C2 and intelligence systems. The FY 2026 spend plan amount for Research, Development, Test & Evaluation, Defense-Wide for Defense Technology Innovation (Beyond 5G) includes $40,051 thousand of discretionary and $351,380 thousand of mandatory (reconciliation) for a total of $391,431 thousand. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:         PE 0602230D8Z / Defense Technology Innovation (Beyond 5G) Applied Research$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L048$$, $$Maritime Battlespace Awareness$$, $$proc_navy_1810_ba2$$, $$navsea$$, 2026, 363312000, 536796000, 405854000, NULL, $${"page": 97, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "48", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 44", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 490548, "p1_line_num": 44, "fy27_total_K": 490548}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 352312, "li_num": 44, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA2_Book.txt"}, "fy26_v197": {"method": "title_fuzzy_partial", "delta_K": 143000, "src_pdf": "Budget J-Books/FY27/Navy/OPN_BA1_Book.pdf", "mapped_K": 5108087, "applied_at": "2026-05-09T_v197d", "table2_total_K": 5802107, "supersedes_partial": "fy26_v179_concentrated", "unmapped_residual_K": 694020}, "fy26t_qty": null, "fy26d_cost": 352312000, "fy26r_cost": 11000000, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 4680000, 13008000, 490548000, 490548000, 0, 490548000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602235N$$, $$Common Picture Applied Research$$, $$rdte_navy_ba2$$, $$onr$$, 2026, 55246000, 50947000, 51202000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "navy", "page_num": 26, "original_pe": "0602235N", "page_header": "Department of the Navy"}$$::jsonb, $$Activities and efforts in this program examine concepts and technologies that enable the transformation to Distributed Maritime Operations (DMO). Network centric capabilities rely on information to connect assets and provide timely and accurate understanding of the environment. The mission area requirements for rapid, accurate decision-making; dynamic, efficient, mission- focused communications and networks; and pervasive and persistent sensing drive network centric Science and Technology (S&T) investments. Today's Sailors and Marines are enabled by Naval S&T. Since 1946, the Office of Naval Research (ONR) has fostered scientific research related to the maintenance of maritime superiority and national defense. ONR manages the Department of the Navy's (DON) portfolio of naval Basic and Applied research, and Advanced Technology Development investments to ensure naval forces can effectively deter conflict, but when called upon, fight, win and come home safe. Current investments hedge against uncertainty, providing solutions to commanders today, and options for the future. The Naval S&T budget supports higher guidance defined by the National Defense Strategy, and responds to requirements identified by the Secretary of the Navy through research priorities set by the Chief of Naval Research, coordinated across the Naval Research Enterprise (NRE), and outlined in the Naval R&D Framework. This Program Element (PE) funds Applied Research, which is the systematic study to understand the means to meet a recognized and specific need. Most of the work in this PE can be classified between Technology Readiness Level (TRL) 2 (technology concept and/or application formulation) and TRL 4 (component and/or breadboard validation in laboratory environments). Due to the number of efforts in this Program Element (PE), the programs described herein are representative of the work included in this PE. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                            Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 2: Applied          PE 0602235N / Common Picture Applied Research Research$$, NULL, 45598000, 48751000, 47570000, NULL, NULL, 6, $$RDTEN_BA1-3_Book.pdf$$, NULL, FALSE, 50260000, 70209000, 40433000, 40433000, NULL, 40433000, 48087000, $$Activities and efforts in this program examine concepts and technologies that enable the transformation to Distributed Maritime Operations (DMO). Network centric capabilities rely on information to connect assets and provide timely and accurate understanding of the environment. The mission area requirements for rapid, accurate decision-making; dynamic, efficient, mission- focused communications and networks; and pervasive and persistent sensing drive network centric Science and Technology (S&T) investments. Today's Sailors and Marines are enabled by Naval S&T. Since 1946, the Office of Naval Research (ONR) has fostered scientific research related to the maintenance of maritime superiority and national defense. ONR manages the Department of the Navy's (DON) portfolio of naval Basic and Applied research, and Advanced Technology Development investments to ensure naval forces can effectively deter conflict, but when called upon, fight, win and come home safe. Current investments hedge against uncertainty, providing solutions to commanders today, and options for the future. The Naval S&T budget supports higher guidance defined by the National Defense Strategy, and responds to requirements identified by the Secretary of the Navy through research priorities set by the Chief of Naval Research and outlined in the Naval R&D Framework. This Program Element (PE) funds Applied Research, which is the systematic study to understand the means to meet a recognized and specific need. Most of the work in this PE can be classified between Technology Readiness Level (TRL) 2 (technology concept and/or application formulation) and TRL 4 (component and/or breadboard validation in laboratory environments). Due to the number of efforts in this Program Element (PE), the programs described herein are representative of the work included in this PE. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                          Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 2: Applied        PE 0602235N / Common Picture Applied Research Research$$, $$Budget J-Books/FY27/Navy/RDTEN_BA1-3_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602251D8Z$$, $$Applied Research for the Advancement of S&T Priorities$$, $$rdte_dw_ba2$$, $$dw$$, 2026, 53983000, 59676000, 51555000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "dw", "page_num": 67, "original_pe": "0602251D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$The Applied Research for the Advancement of Science and Technology (S&T) Priorities (ARAP) Program directly supports the Interim National Defense Strategy and aligns with DoD critical science and technology priorities, strengthening broadly applicable technical capabilities and fostering emerging technologies within the Department of Defense laboratories to enhance warfighter advantages. By funding foundational enabling technologies, the ARAP Program facilitates the design, development, advancement and transition of early-stage technologies and novel ideas, translating promising research into solutions for critical military needs that directly improve situational awareness through advanced sensors, enhanced lethality with precision weaponry, and more effective communication and coordination. Continuous infusion of new technology ensures our forces maintain a decisive edge and have the flexibility needed to adapt to diverse and rapidly changing operational environments. Furthermore, the ARAP Program fosters increased collaboration and partnership among science and engineering teams of subject matter experts across the DoD enterprise, providing funding to recruit top national talent from universities, and bolsters the in-house scientific and technical research capabilities of DoD laboratories, ultimately accelerating the delivery of advanced capabilities to our warfighters. The ARAP Program funds the activities of the DoD Reliance 21 collaborative framework. This framework’s core strength lies in its strategic planning and the DoD Science & Technology (S&T) Executive Committee’s (EXCOM) robust leadership, comprised of senior-level executives from across the Department. The S&T EXCOM ensures coordinated resource allocation by convening regularly to align resources and proactively address emerging challenges. For example, the S&T EXCOM recently awarded funding to accelerate the development of long-range strike capabilities that pushes the boundaries of several technological domains in response to evolving battlefield threats, and strategically prioritized investments in Quantum technology to enhance decision-making speed. This leadership is powered by a robust ecosystem of 16 S&T Communities of Interest (COIs). These COIs, spanning cross-cutting topics like advanced materials, cyber warfare, biomedical and biotech, energy and power, warfighter and space platforms, and other critical technology areas, maintain a global perspective on technological advancements. They strategically guide investment through detailed technology roadmaps that inform and identify candidate ARAP projects, ensuring resources are directed towards the most promising and impactful areas. The Applied Research for the Advancement of Science and Technology (S&T) Priorities program strategically implements and executes Department-wide technology development portfolios, ensuring the timely availability of emerging capabilities that will transition and enhance the effectiveness of both near- and far-term weapon systems. Collaboration across multiple technical and technology areas is essential for increasingly complex modern weapons systems development. For example, a next-generation fighter jet might require advancements in materials science, artificial intelligence, sensor technology, propulsion, and cyber security. Progress in one area can be heavily dependent on breakthroughs in others. Collaboration across the DoD scientific and engineering communities allows subject matter experts from Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                               Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:              PE 0602251D8Z / Applied Research for the Advancement of S&T Priorities Applied Research these fields to share knowledge, identify synergies, and overcome integration issues. The ARAP Program provides the platform to facilitate this collaboration through three investment areas:(1) three-year, multi-Service, applied research projects selected by the S&T Executive Committee (EXCOM); (2) two-year, multi-discipline, technology projects nominated by the S&T Communities of Interest (COI) Leaders to address technology gaps or opportunities; and (3) technology assessment and study support to the COIs. The execution of the ARAP Program by the Office of the Undersecretary of Defense and the support it provides to the S&T COIs inspire and ensure joint strategic S&T oversight and multi-Service, multi-agency, collaboration and coordination.$$, NULL, 61218000, 63562000, 66753000, NULL, NULL, 19, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 52044000, 48845000, 59560000, 59560000, NULL, 59560000, 69968000, $$The Applied Research for the Advancement of Science and Technology (S&T) Priorities (ARAP) Program directly supports the Interim National Defense Strategy and aligns with DoW critical science and technology priorities, strengthening broadly applicable technical capabilities and fostering emerging technologies within the Department of War laboratories to enhance warfighter advantages. By funding foundational enabling technologies, the ARAP Program facilitates the design, development, advancement and transition of early-stage technologies and novel ideas, translating promising research into solutions for critical military needs that directly improve situational awareness through advanced sensors, enhanced lethality with precision weaponry, and more effective communication and coordination. Continuous infusion of new technology ensures our forces maintain a decisive edge and have the flexibility needed to adapt to diverse and rapidly changing operational environments. Furthermore, the ARAP Program fosters increased collaboration and partnership among science and engineering teams of subject matter experts across the DoW enterprise, providing funding to recruit top national talent from universities, and bolsters the in-house scientific and technical research capabilities of DoW laboratories, ultimately accelerating the delivery of advanced capabilities to our warfighters. The ARAP Program funds the activities of the DoW Reliance 21 collaborative framework. This framework’s core strength lies in its strategic planning and the DoW Science & Technology (S&T) Executive Committee’s (EXCOM) robust leadership, comprised of senior-level executives from across the Department. The S&T EXCOM ensures coordinated resource allocation by convening regularly to align resources and proactively address emerging challenges. For example, the S&T EXCOM recently awarded funding to accelerate the development of long-range strike capabilities that pushes the boundaries of several technological domains in response to evolving battlefield threats, and strategically prioritized investments in Quantum technology to enhance decision-making speed. This leadership is powered by a robust ecosystem of 16 S&T Communities of Interest (COIs). These COIs, spanning cross-cutting topics like advanced materials, cyber warfare, biomedical and biotech, energy and power, warfighter and space platforms, and other critical technology areas, maintain a global perspective on technological advancements. They strategically guide investment through detailed technology roadmaps that inform and identify candidate ARAP projects, ensuring resources are directed towards the most promising and impactful areas. The Applied Research for the Advancement of Science and Technology (S&T) Priorities program strategically implements and executes Department-wide technology development portfolios, ensuring the timely availability of emerging capabilities that will transition and enhance the effectiveness of both near- and far-term weapon systems. Collaboration across multiple technical and technology areas is essential for increasingly complex modern weapons systems development. For example, a next-generation fighter jet might require advancements in materials science, artificial intelligence, sensor technology, propulsion, and cyber security. Progress in one area can be heavily dependent on breakthroughs in others. Collaboration across the DoW scientific and engineering communities allows subject matter experts from Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                 Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:              PE 0602251D8Z / Applied Research for the Advancement of S&T Priorities Applied Research these fields to share knowledge, identify synergies, and overcome integration issues. The ARAP Program provides the platform to facilitate this collaboration through three investment areas:(1) three-year, multi-Service, applied research projects selected by the S&T Executive Committee (EXCOM); (2) two-year, multi-discipline, technology projects nominated by the S&T Communities of Interest (COI) Leaders to address technology gaps or opportunities; and (3) technology assessment and study support to the COIs. The execution of the ARAP Program by the Office of the Undersecretary of War and the support it provides to the S&T COIs inspire and ensure joint strategic S&T oversight and multi-Service, multi-agency, collaboration and coordination.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602275A$$, $$Electronic Warfare Applied Research$$, $$rdte_army_ba2$$, $$devcom$$, 2026, 45415000, 0, 0, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 11, "original_pe": "0602275A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) focuses on investigating and developing advanced Electromagnetic Warfare (EW) capabilities for modern, multi-domain military operations. It researches and develops cutting-edge technologies - including architectures, infrastructure, tools, and techniques - across the spectrum of EW activities: Electronic Attack (EA) to disrupt enemy Command, Control, Computing, Communications, Cyber, Intelligence, Surveillance, and Targeting (C-C5ISR&T) systems and ensure non-kinetic survivability; Electronic Support (ES) for precise detection, identification, and geolocation of enemy RF emissions to enable effective fires; network and RADAR Electronic Protection (EP) with intelligent resource orchestration to bolster resilience and robustness against increasingly sophisticated electronic attacks; battle management tools for intelligent planning, targeting, and execution of effects across the entire electromagnetic spectrum; and position, navigation, and timing techniques to enable coordination of electronic attacks. This PE aims to provide a comprehensive and integrated EW suite that not only ensures our forces maintain a decisive advantage in the contested electromagnetic environment, but also creates novel opportunities for operational advantage, increasing unit survivability, maneuverability, and the effective employment of non-kinetic effects in highly contested and congested spaces. Work in this PE complements PE 0603275A (Electronic Warfare Advanced Technology). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy.$$, NULL, 36461000, 41034000, 42052000, NULL, NULL, 25, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, NULL, 45415000, 51184000, 51184000, NULL, 51184000, 42883000, $$This PE focuses on investigating and developing advanced Electromagnetic Warfare (EW) capabilities for modern, multi-domain military operations. It researches and develops cutting-edge technologies - including architectures, infrastructure, tools, and techniques - across the spectrum of EW activities: Electronic Attack (EA) to disrupt enemy Command, Control, Computing, Communications, Cyber, Intelligence, Surveillance, and Targeting (C-C5ISR&T) systems and ensure non-kinetic survivability; Electronic Support (ES) for precise detection, identification, and geolocation of enemy RF emissions to enable effective fires; network and RADAR Electronic Protection (EP) with intelligent resource orchestration to bolster resilience and robustness against increasingly sophisticated electronic attacks; battle management tools for intelligent planning, targeting, and execution of effects across the entire electromagnetic spectrum; and position, navigation, and timing techniques to enable coordination of electronic attacks. This PE aims to provide a comprehensive and integrated EW suite that not only ensures our forces maintain a decisive advantage in the contested electromagnetic environment, but also creates novel opportunities for operational advantage, increasing unit survivability, maneuverability, and the effective employment of non-kinetic effects in highly contested and congested spaces. Work in this PE complements PE 0603275A (Electronic Warfare Advanced Technology). The cited research is consistent with the Under Secretary of War for Research and Engineering priority focus areas and the Army modernization strategy.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 2.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602276A$$, $$Electronic Warfare Cyber Applied Research$$, $$rdte_army_ba2$$, $$devcom_c5isr$$, 2026, 17102000, 0, 0, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 11, "original_pe": "0602276A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) investigates and develops architectures, technologies, techniques, components, and tools to enhance Cyber and Electromagnetic Activities (CEMA) for Multi-Domain Joint Operations in tactical environments. These efforts aim to counter the adversary's Command, Control, Computing, Communications, Cyber, Intelligence, Surveillance, and Targeting (C-C5ISR&T) capabilities and plan, target, execute Cyber effects through the employment of non-traditional access and effect vectors against adversarial systems, communication networks, and decision centers to reduce the adversary's ability to execute command and control of its forces. Additionally, these efforts will protect tactical wired and wireless networks against modern cyber-attacks, focusing on configuration, operation, monitoring, data integrity, and defense in bandwidth constrained tactical environments while reducing the operator workload required to conduct these functions. This PE will investigate key technologies that create windows of opportunity to provide significant operational advantage over adversaries. It will increase unit survivability and maneuverability and enhance the employment of non-kinetic effects in highly contested and congested electromagnetic environments. Work in this PE complements PE 0603276A (Electronic Warfare Cyber Advance Technology). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied          PE 0602276A / Electronic Warfare Cyber Applied Research Research$$, NULL, 10552000, 10927000, 13872000, NULL, NULL, 26, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, NULL, 17102000, 9857000, 9857000, NULL, 9857000, 14010000, $$This PE investigates and develops architectures, technologies, techniques, components, and tools to enhance Cyber and Electromagnetic Activities (CEMA) for Multi- Domain Joint Operations in tactical environments. These efforts aim to counter the adversary's Command, Control, Computing, Communications, Cyber, Intelligence, Surveillance, and Targeting (C-C5ISR&T) capabilities and plan, target, execute Cyber effects through the employment of non-traditional access and effect vectors against adversarial systems, communication networks, and decision centers to reduce the adversary's ability to execute command and control of its forces. Additionally, these efforts will protect tactical wired and wireless networks against modern cyber-attacks, focusing on configuration, operation, monitoring, data integrity, and defense in bandwidth constrained tactical environments while reducing the operator workload required to conduct these functions. This PE will investigate key technologies that create windows of opportunity to provide significant operational advantage over adversaries. It will increase unit survivability and maneuverability and enhance the employment of non-kinetic effects in highly contested and congested electromagnetic environments. Work in this PE complements PE 0603276A (Electronic Warfare Cyber Advance Technology). The cited research is consistent with the Under Secretary of War for Research and Engineering priority focus areas and the Army modernization strategy.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 2.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602298F$$, $$Science and Technology Management - Major Headquarters Activities$$, $$rdte_af_ba2$$, $$afrl$$, 2026, 10813000, 10303000, 9662000, NULL, $${"ba_raw": "6.2", "source": "af_r1_fy26", "original_pe": "0602298F"}$$::jsonb, $$The Air Force Research Laboratory (AFRL) is a global technical enterprise, boasting some of the best and brightest leaders in the world. It provides revolutionary, relevant, and responsive science and technology (S&T) to the Warfighter. AFRL's mission is to lead the discovery, development, and integration of affordable warfighting technologies for the global air, space, and cyberspace force. The FY26 request for 0602298F was reduced by $0.918 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." This program element may include necessary civilian pay expenses required to manage, execute, and deliver science & technology capabilities. The use of program funds in this program element would be in addition to the civilian pay expenses budgeted in program elements 0601102F, 0602020F, 0602102F, 0602201F, 0602202F, 0602203F, 0602204F, 0602336F, 0602602F, 0602605F, 0602788F, 0602298F, 0603680F, 1206601SF and 1206616SF. In FY 2026, $10.813 million is budgeted in this program for 53 direct Full-Time Equivalent (FTE) civilians. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied    PE 0602298F / Science and Technology Management - Major Headquarters Activities Research$$, NULL, 10316000, 10569000, 10630000, NULL, NULL, 11, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 9662000, 13763000, 10285000, 10285000, 0, 10285000, 10932000, $$This program funds government civilian workforce in support of all Air Force Research Laboratory (AFRL) programs and activities. AFRL is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This program includes funding for the requisite DAF Science & Engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The use of program funds in this program element is in conjunction with the civilian pay expenses budgeted in the following program elements: 1206601SF, 1206616SF, 0601102F, 0602020F, 0602102F, 0602202F, 0602203F, 0602204F, 0602336F, 0602602F, 0602605F, 0602788F, and 0603680F. In FY 2027, $10.285 million is budgeted in this program for 53 direct Full-Time Equivalent (FTE) civilians. The Air Force Research Laboratory utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602336F$$, $$Nuclear Delivery Systems Tech Exploration$$, $$rdte_af_ba2$$, $$afrl$$, 2026, 4969000, 0, 0, NULL, $${"ba_raw": "6.2", "source": "af_r1_fy26", "original_pe": "0602336F"}$$::jsonb, $$The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain science and technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Forces to win the future fight. The AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. The Nuclear Delivery Systems Technology Exploration program establishes the foundational computational tools necessary to conduct nuclear forensics, perform potential strategic surveillance, and predict future nuclear re-entry system environmental effects and responses. Program activities aid investigations and analyses of national strategic and nuclear deterrence operations; foreign low yield or evasive underground nuclear tests; and multi-physics algorithms to accurately simulate untested environmental effects and responses in support of nuclear reentry systems development activities in Program Element 0603273F (Science & Technology for Nuclear Reentry Systems). This program provides applied Science & Technology to reestablish nuclear deterrence operations by reestablishing specialized expertise and modernizing the infrastructure and technologies necessary to address, and respond to, current and emerging multi-peer-contested nuclear environments. This program further supports the requisite DAF Science & Engineering mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver Science & Technology capabilities. The use of program funds in this Program Element is aligned with the civilian pay expenses budgeted for in the following program elements: 1206601SF, 0601102F, 0602020F, 0602102F, 0602202F, 0602203F, 0602204F, 0602298F, 0602602F, 0602605F, 0602788F, and 0603680F. In FY 2026, $1.615 million is budgeted in this program for 8 direct Full-Time Equivalent civilians. The Air Force Research Laboratory references statutory language under 10 USC 4091 ("Authorities for certain positions at Science & Technology reinvention laboratories”) to manage the workforce strength, structure, positions, and compensation. This program element may include necessary expenses to support operation and maintenance activities to manage, execute, and deliver science and technology capabilities. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied      PE 0602336F / Nuclear Delivery Systems Tech Exploration Research$$, NULL, 29378000, 31873000, 32517000, NULL, NULL, 12, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 0, 4937000, 27031000, 27031000, 0, 27031000, 33175000, $$The Nuclear Delivery Systems (NDS) Technology Exploration program establishes the foundational computational tools necessary to conduct nuclear forensics, perform strategic surveillance, and predict future nuclear re-entry system environmental requirements, effects, and responses. Program activities aid investigations and analyses of 1) enhanced terminal performance options; 2) national strategic and nuclear deterrence operations; 3) potential clandestine nuclear activity; and 4) multi-physics algorithms to improve accuracy in simulating previously untested environmental effects and responses in support of nuclear re-entry systems efforts under PE 0603273F, Science and Technology (S&T) for Nuclear Re-entry Systems. This program provides applied S&T to augment nuclear deterrence operations by reestablishing specialized expertise and technologies necessary to address, and respond to, current and emerging multi-peer-contested nuclear environments. This program is accomplished by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain S&T solutions that drive innovation now while laying the groundwork for the Air and Space Forces to win the future fight. The AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align with the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This program further supports the requisite DAF science and engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver S&T capabilities. The use of program funds in this PE is in conjunction with the civilian pay expenses budgeted for in the following PEs: 1206616SF, 1206601SF, 0601102F, 0602020F, 0602102F, 0602202F, 0602203F, 0602204F, 0602298F, 0602602F, 0602605F, 0602788F, and 0603680F. In FY 2027, $1.648 million is budgeted in this program for 8 direct Full-Time Equivalent civilians. AFRL references statutory language under 10 USC 4091 ("Authorities for certain positions at S&T reinvention laboratories”) to manage the workforce strength, structure, positions, and compensation. To manage, execute, and deliver science and technology capabilities, this Program may include necessary expenses to support the operation and maintenance of facilities as well as expenses related to travel, supplies, Information Technology (IT) hardware, software and support, administrative contractor services, etc. Funds in this program may be used to investigate specific technological advancements in air, space and/or related cyber domains. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied         PE 0602336F / Nuclear Delivery Systems Tech Exploration Research$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602345A$$, $$Unmanned Aerial Systems Launched Effects Applied Research$$, $$rdte_army_ba2$$, $$cft_fvl$$, 2026, 18408000, 0, 0, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 11, "original_pe": "0602345A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) conducts uncrewed air vehicle and mission system component design, fabrication, and evaluation to enable unmanned aerial system modernization. Emphasis is on developing aviation platform and mission system technologies to enhance uncrewed air vehicle combat and combat support operations for attack, reconnaissance, air assault, survivability, logistics, and command and control missions. The PE will fund civilian salaries for in-house researchers/scientists and program managers. Work in this PE contributes to the Army Science and Technology (S&T) air systems portfolio and is fully coordinated with efforts in PE 0603465A (Future Vertical Lift Advanced Technology), 0603043A (Air Platform Advanced Technology), and 0603345A (Unmanned Aerial Systems Launched Effects Advanced Technology Development). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                         Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied        PE 0602345A / Unmanned Aerial Systems Launched Effects Applied Research Research$$, NULL, 17270000, 19648000, 19120000, NULL, NULL, 27, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, NULL, 18408000, 22871000, 22871000, NULL, 22871000, 19346000, $$This PE conducts uncrewed air vehicle and mission system component design, fabrication, and evaluation to enable unmanned aerial system modernization. Emphasis is on developing aviation platform and mission system technologies to enhance uncrewed air vehicle combat and combat support operations for attack, reconnaissance, air assault, survivability, logistics, and command and control missions. The PE will fund civilian salaries for in-house researchers/scientists and program managers. Work in this PE contributes to the Army Science and Technology (S&T) air systems portfolio and is fully coordinated with efforts in PE 0603465A (Future Vertical Lift Advanced Technology), 0603043A (Air Platform Advanced Technology), and 0603345A (Unmanned Aerial Systems Launched Effects Advanced Technology Development). The cited work is consistent with the Under Secretary of War for Research and Engineering priority focus areas and the Army modernization strategy. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied           PE 0602345A / Unmanned Aerial Systems Launched Effects Applied Research Research$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 2.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602386A$$, $$Biotechnology for Materials - Applied Research$$, $$rdte_army_ba2$$, $$dw_osd$$, 2026, 8209000, 16060000, 11780000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 11, "original_pe": "0602386A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) investigates, designs, and performs research focused on novel biotechnological methods, techniques, and materials to increase the resiliency of the military supply chain. The Army is responsible for centrally managing funding for Tri-Service Biotechnology for a Resilient Supply Chain (T-BRSC) efforts. T-BRSC leverages bio-industrial manufacturing to ensure critical domestic supply chain resilience for defense needs through domestic production of raw materials and critical products. Efforts under this PE collaborate with sister Services and select allied partners to create a cohesive biotechnology architecture to enable defense needs. Applied research projects investigate and design bio-engineered materials to ensure domestic sourcing for critical supply chain resiliency. This PE designs and validates technologies to enable rapid prototyping and evaluating of bio-engineered and bio-manufactured materials. Also under this PE are efforts determine and validate a digital architecture to secure biotech data and create computer aided design software to support the safe design and enhanced biosecurity of biotechnology products and applications. Research in this PE is coordinated with PE 0603386A (Biotechnology for Materials - Advanced Research). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. The FY 2026 request was reduced by $0.037 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                       Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied       PE 0602386A / Biotechnology for Materials - Applied Research Research$$, NULL, 18625000, 18785000, 18984000, NULL, NULL, 28, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, 10496000, 8209000, 14979000, 14979000, NULL, 14979000, 19173000, $$This PE investigates, designs, and performs research focused on novel biotechnological methods, techniques, and materials to increase the resiliency of the military supply chain. The Army is responsible for centrally managing funding for Tri-Service Biotechnology for a Resilient Supply Chain (T-BRSC) efforts. T-BRSC leverages bio-industrial manufacturing to ensure critical domestic supply chain resilience for defense needs through domestic production of raw materials and critical products. Efforts under this PE collaborate with sister Services and select allied partners to create a cohesive biotechnology architecture to enable defense needs. Applied research projects investigate and design bio-engineered materials to ensure domestic sourcing for critical supply chain resiliency. This PE designs and validates technologies to enable rapid prototyping and evaluating of bio-engineered and bio-manufactured materials. Also under this PE are efforts determine and validate a digital architecture to secure biotech data and create computer aided design software to support the safe design and enhanced biosecurity of biotechnology products and applications. Research in this PE is coordinated with PE 0603386A (Biotechnology for Materials - Advanced Research). The cited research is consistent with the Under Secretary of War for Research and Engineering priority focus areas and the Army Modernization Strategy.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 2.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602602F$$, $$Conventional Munitions$$, $$rdte_af_ba2$$, $$afrl_rw$$, 2026, 125102000, 149962000, 142497000, NULL, $${"ba_raw": "6.2", "source": "af_r1_fy26", "original_pe": "0602602F"}$$::jsonb, $$This program investigates, develops, and establishes the technical feasibility and military utility of guidance and ordnance technologies for conventional munitions. The effort supports core technical competencies of munitions aerodynamics, guidance, navigation, and control; terminal seeker sciences; fuze technology; energetic materials; damage mechanisms; and munition systems effects. Technologies and associated models and simulation assets to be developed include seekers that provide high-confidence target discrimination and classification with precise target location and robust terminal tracking; navigation technologies that do not rely upon the Global Positioning System (GPS); blast, fragmentation, penetrating, low-collateral-damage, and multi-mission warheads; collaborative, synchronized fuzing; and high- performance and insensitive explosives. Funds in this PE may be used to investigate specified technology advancements in air, space and/or cyber domains. The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This program includes funding for the requisite DAF Science & Engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The use of program funds in this program element is in conjunction with the civilian pay expenses budgeted in the following program elements: 1206601SF, 0601102F, 0602020F, 0602102F, 0602202F, 0602203F, 0602204F, 0602298F, 0602336F, 0602605F, 0602788F, and 0603680F. In FY 2026, $49.406 million is budgeted in this program for 257 direct Full-Time Equivalent (FTE) civilians. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology capabilities. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied       PE 0602602F / Conventional Munitions Research$$, NULL, 137368000, 146492000, 149009000, NULL, NULL, 13, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 136072000, 124433000, 130146000, 130146000, 0, 130146000, 151876000, $$This program investigates, develops, and establishes the technical feasibility and military utility of guidance and ordnance technologies for conventional munitions. This program is focused on integration by design and starting with desired mission effect to deliver war winning capabilities to defend the homeland, provide nuclear deterrence, and deliver force projection. The effort supports core technical competencies of munitions aerodynamics, guidance, navigation, and control; terminal seeker sciences; fuze technology; energetic materials; damage mechanisms; and munition systems effects. Technologies and associated models and simulation assets to be developed include seekers that provide high-confidence target discrimination and classification with precise target location and robust terminal tracking; navigation technologies that do not rely upon the Global Positioning System (GPS); blast, fragmentation, penetrating, low-collateral-damage, and multi-mission warheads; collaborative, synchronized fuzing; and high-performance and insensitive explosives. This program is executed by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. Funds in this PE may be used to investigate specified technology advancements in air, space and/or cyber domains. This program includes funding for the requisite DAF Science & Engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The use of program funds in this program element is in conjunction with the civilian pay expenses budgeted in the following program elements: 1206601SF, 1026616SF, 0601102F, 0602020F, 0602102F, 0602202F, 0602203F, 0602204F, 0602298F, 0602336F, 0602605F, 0602788F, and 0603680F. In FY 2027, $47.497 million is budgeted in this program for 250 direct Full-Time Equivalent (FTE) civilians. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology capabilities. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                              Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied        PE 0602602F / Conventional Munitions Research$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602605F$$, $$Directed Energy Technology$$, $$rdte_af_ba2$$, $$afrl_rd$$, 2026, 92331000, 111169000, 98012000, NULL, $${"ba_raw": "6.2", "source": "af_r1_fy26", "original_pe": "0602605F"}$$::jsonb, $$The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This program conducts research, development, test and evaluation in advanced high energy laser (HEL) and high power electromagnetic (HPEM) technologies to satisfy Department of the Air Force requirements in areas including counter-adversary unmanned aerial systems (c-UAS), counter-adversary intelligence/surveillance/ reconnaissance (c-ISR), counter-adversary missiles (c-Missile), and counter-adversary electronics (c-Electronic). This program also conducts research and development in directed energy for lethal and non-lethal applications by assessing the vulnerability and lethality of high energy lasers and high power microwave systems to meet Air Force needs. Technologies developed under this PE 0602605 (Directed Energy Technology) feed directly into directed energy technology demonstrations to graduate the technology to a higher technology readiness level (TRL) under program 0603605F (Advanced Weapons Technology), project 633151 (High Power Solid State Laser Technology) and project 633152 (High Power Microwave Development and Integration). This program includes funding for the requisite DAF Science & Engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The use of program funds in this program element is in conjunction with the civilian pay expenses budgeted in the following program elements: 0601102F, 0602020F, 0602102F, 0602202F, 0602203F, 0602204F, 0602298F, 0602336F, 0602602F, 0602788F, and 0603680F. In FY 2026, 54.717 million is budgeted in this program for 291 direct Full-Time Equivalent (FTE) civilians. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation without regard to any limitation on appointments, positions, or funding in a manner consistent with the budget. This program element does include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology capabilities. Funds in this PE may be used to investigate specified technology advancements in air, space and/or cyber domains. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied      PE 0602605F / Directed Energy Technology Research This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters.$$, NULL, 92341000, 101062000, 105063000, NULL, NULL, 14, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 92374000, 96154000, 91798000, 91798000, 0, 91798000, 108260000, $$This Program conducts research, development, test and evaluation in advanced high energy laser (HEL) and high power electromagnetic (HPEM) technologies to satisfy Department of the Air Force requirements in areas including counter unmanned aerial systems (c-UAS), counter intelligence/surveillance/reconnaissance (c-ISR), counter missiles (c-Missile), and counter electronics (c-Electronic). This Program also conducts research and development in directed energy for lethal and non-lethal applications by assessing the vulnerability and lethality of high energy lasers and high power microwave systems to meet Air Force needs. Technologies developed under this program feed directly into directed energy technology demonstrations to graduate the technology to a higher technology readiness level (TRL) under Program Element 0603605F / Advanced Weapons Technology. This program is accomplished by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This program includes funding for the requisite DAF Science & Engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The use of program funds in this program element is in conjunction with the civilian pay expenses budgeted in the following program elements: 1206601SF, 1206616SF, 0601102F, 0602020F, 0602102F, 0602202F, 0602203F, 0602204F, 0602298F, 0602336F, 0602602F, 0602788F, and 0603680F. In FY 2027, 53.597 million is budgeted in this program for 278 direct Full-Time Equivalent (FTE) civilians. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories" to manage the workforce strength, structure, positions, and compensation. In order to manage, execute, and deliver science and technology capabilities, this program element may include: expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, etc. Funds in this PE may be used to investigate specified technology advancements in air, space and/or cyber domains. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied      PE 0602605F / Directed Energy Technology Research This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602668D8Z$$, $$Cyber Security Research$$, $$rdte_dw_ba2$$, $$dw$$, 2026, 17988000, 29523000, 31652000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "dw", "page_num": 67, "original_pe": "0602668D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This Program Element supports the Department's interim National Defense Strategy priorities to Defend the Homeland, Deter Strategic Attacks against the United States, Deterring Aggression, and Building a resilient Joint Force and defense ecosystem. The Cyber Security Applied Research program promotes innovative higher risk cyber research to meet joint force challenges in full spectrum cyber operations. The program addresses joint Service science and technology (S&T) gaps that influence DoD cyber research priorities and shapes the direction of the wider cyber community by integrating both defensive and offensive cyber research to develop interchangeable, defense-wide technology options to meet Combatant Command (CCMD) needs and requirements. To better align itself to the interim National Defense Strategy (NDS), Department of Defense (DoD) Cyber Strategy, and Office of Under Secretary of Defense for Research and Engineering (OUSD(R&E)) strategic cyber capability goals, the effort recognizes the role of electromagnetic spectrum operations (EMSO) and artificial intelligence as key enablers for cyber power projection mass, maneuver, and unity of command for dominance. The research thrusts areas are: Augmented Cognition, Dominant Cyber Operations, Dependable Systems and Networks, and Cyber Foundations. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                   Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:              PE 0602668D8Z / Cyber Security Research Applied Research$$, NULL, 18874000, 19219000, 19618000, NULL, NULL, 22, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 30516000, 30314000, 18575000, 18575000, NULL, 18575000, 19617000, $$Cyber Security Research supports the Department's 2026 National Defense Strategy priorities to Defend the U.S. Homeland including America’s skies and borders, Deterring China in the Indo-Pacific, and Supercharging the DIB. It does so by developing cyber capabilities that integrate functionally with electromagnetic spectrum operations to increase readiness and deterrence, particularly in priority areas such as USINDOPACOM. It builds a cyber and electromagnetic spectrum talent pathway to prepare the defense industrial base and government workforce for technical and operational success starting on their very first day on the job. This program explores technical and scientific concepts to overcome challenges in the Joint Warfighting Environment with cyber effects and integrated non-kinetic options through applied research for an asymmetric advantage across all domains (maritime, land, air, cyberspace, and space). It applies the Joint Publication (JP) 3-0 principles of Mass, Maneuver, and Unity of Command to achieve specific outcomes with minimal collateral damage and unforeseen consequences for integrated non-kinetic effects development Efforts are focused to support the Joint Warfighting Environment through intended cyber effects execution without perturbing the unintended kinetic and non-kinetic entities through disruptive integration of cyberspace operations with electromagnetic spectrum operations (EMSO) and sensing. The program accelerates cyber S&T capability development to directly address INDSG priorities to defend the homeland and deter aggression/prepared to prevail in U.S. Indo-Pacific Command (USINDOPACOM) area of responsibility against the People’s Republic of China (PRC). Adversaries are increasingly leveraging asymmetric tactics in the Joint Warfighting Environment. The Department of War (DoW) needs to evolve its approach to warfare, integrating cyber and non-kinetic effects to maintain a decisive advantage across all domains. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                 Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:              PE 0602668D8Z / Cyber Security Research Applied Research The Non-Kinetic Advantage (NKA) project is a collaborative effort aimed at revolutionizing how the Joint Force employs non-kinetic capabilities. By focusing on four key pillars – Protect, Process, Visualize, and Align & Shape – NKA will deliver a decisive advantage in the information battlespace. NKA will enable the Joint Force to conduct faster, more effective operations across all domains, even in contested environments. Will provide Asymmetric Advantage by mastering the information battlespace, NKA will provide a decisive edge against adversaries, deterring aggression and ensuring US dominance. Will enable Rapid Decision Making by NKA empowering commanders with the information and tools needed to make rapid, well-informed decisions in complex, dynamic environments.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602669D8Z$$, $$Microelectronics Commons - 0400D$$, $$rdte_dw_ba2$$, $$dw_ousd_re$$, 2026, 0, 65062000, 0, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "dw", "page_num": 67, "original_pe": "0602669D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This Program supports the Department's initiatives to Build Sustainable and Long-Term Advantage, Defend the Homeland, and Deter Aggression. The Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)) is executing the Microelectronics Commons (the Commons) activity pursuant to the Fiscal Year (FY) 2021 National Defense Authorization Act (NDAA) (Pub. L. 116-283), including the CHIPS for America Act, and funded through the CHIPS for America Defense Fund established by the CHIPS Act of 2022. The FY 2021 NDAA legislation significantly emphasizes solutions that promote the domestic on-shoring of capabilities to address economic and technology security concerns. Under FY 2021 NDAA Sec. 9903(b), the DOD is directed to establish a National Network for Microelectronics Research and Development (NNMRD) to enable the laboratory-to-fabrication transition of microelectronics innovations in the United States and to expand the global leadership in microelectronics of the United States. Specifically, the DOD is addressing a component of the NNMRD, the Commons, through a public- private partnership consisting of regional innovation hubs distributed across the U.S. to foster a pipeline of innovative ideas and talent residing in, for example, university labs and small business R&D teams. Background U.S. technological dominance in microelectronics materials, processes, devices, and architectural designs can only be sustained through the development of a robust domestic innovation ecosystem that fosters the rapid development and transition of novel concepts into commercially viable manufacturing processes. The U.S. innovation ecosystem has long been the driver of our nation’s technology leadership throughout the world. U.S. R&D kick-started the enormous semiconductor industry and continues to lead the world in developing the next generation of disruptive technologies including new materials, devices, circuits, architectures, and design tools. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                    Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:               PE 0602669D8Z / Microelectronics Commons - 0400D Applied Research In recent years, the efficient domestic adoption of U.S. chip innovation has been threatened as emerging hardware technologies have become increasingly reliant on offshore sources for State of the Art (SOTA) manufacturing, prototyping, and investment. There are several significant hurdles that hardware startups face, including limited or expensive access to necessary facilities and design infrastructure, high costs of design intellectual property, limited expertise with hardware engineering, and high costs of prototyping. As a result, the number of U.S. hardware startups has dropped significantly and foreign investment in U.S.-based technology startups has enabled offshore fabrication and maturation of emerging technologies. To address these needs, OUSD(R&E) is standing up the Commons as a public private partnership, consisting of regional innovation hubs distributed across the U.S. to foster a pipeline of innovative ideas and talent residing in university labs and small business R&D teams. The partnership will provide resources for and access to specialized lab equipment, technical expertise, and connections to existing or upgraded prototyping facilities. Fabrication facilities (fabs) will help mature promising technologies and demonstrate the manufacturing and economic benefits of these innovations for dual-use application for defense and commercial sectors. The Commons will focus on critical, on-shore prototyping to transition innovation from universities, start-ups, and small companies to fabrication facilities (lab-to-fab transition). Key features are: • Creates and connects “Lab-to-Fab” testing/prototyping hubs to form a network focused on maturing emerging microelectronics technologies • Provides broad access to these prototyping hubs, potentially by augmenting facilities and enabling access to facilities within local semiconductor companies or FFRDCs. • Facilitates microelectronics education and training of students at local colleges and universities and grows a talent pipeline to bolster local semiconductor economies and contribute more broadly to the growth of a domestic semiconductor workforce. This program element focuses on the applied research activities of the Commons, including staffing at Commons hub facilities, early technology identification, preliminary microelectronics prototyping planning, and experimental tools.$$, NULL, NULL, NULL, NULL, NULL, NULL, 23, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 72188000, 0, NULL, NULL, NULL, NULL, NULL, $$This Program supports the Department's initiatives to Build Sustainable and Long-Term Advantage, Defend the Homeland, and Deter Aggression. The Office of the Under Secretary of War for Research and Engineering (OUSW(R&E)) is executing the Microelectronics Commons (the Commons) activity pursuant to the Fiscal Year (FY) 2021 National Defense Authorization Act (NDAA) (Pub. L. 116-283), including and funded through the CHIPS for America Defense Fund established by the CHIPS Act of 2022. The FY 2021 NDAA legislation significantly emphasizes solutions that promote the domestic on-shoring of capabilities to address economic and technology security concerns. Under FY 2021 NDAA Sec. 9903(b), the Department is directed to establish a National Network for Microelectronics Research and Development (NNMRD) to enable the laboratory-to-fabrication transition of microelectronics innovations in the United States and to expand the global leadership in microelectronics of the United States. Specifically, DoW is addressing a component of the NNMRD, the Commons, through a public-private partnership consisting of regional innovation hubs distributed across the U.S. to foster a pipeline of innovative ideas and talent residing in, for example, university labs and small business R&D teams. U.S. technological dominance in microelectronics materials, processes, devices, and architectural designs can only be sustained through the development of a robust domestic innovation ecosystem that fosters the rapid development and transition of novel concepts into commercially viable manufacturing processes. The U.S. innovation ecosystem has long been the driver of our nation’s technology leadership throughout the world. U.S. R&D kick-started the enormous semiconductor industry and continues to lead the world in developing the next generation of disruptive technologies including new materials, devices, circuits, architectures, and design tools. In recent years, the efficient domestic adoption of U.S. chip innovation has been threatened as emerging hardware technologies have become increasingly reliant on offshore sources for State of the Art (SOTA) manufacturing, prototyping, and investment. There are several significant hurdles that hardware startups face, including limited or expensive access to necessary facilities and design infrastructure, high costs of design intellectual property, limited expertise with hardware engineering, and high costs of prototyping. As a result, the number of U.S. hardware startups has dropped significantly and foreign investment in U.S.-based technology startups has enabled offshore fabrication and maturation of emerging technologies. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                  Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:            PE 0602669D8Z / Microelectronics Commons - 0400D Applied Research To address these needs, OUSW(R&E) stood up the Commons as a public private partnership, consisting of regional innovation hubs distributed across the U.S. to foster a pipeline of innovative ideas and talent residing in university labs and small business R&D teams. The partnership provides resources for and access to specialized lab equipment, technical expertise, and connections to existing or upgraded prototyping facilities. Fabrication facilities (fabs) will help mature promising technologies and demonstrate the manufacturing and economic benefits of these innovations for dual-use application for defense and commercial sectors. The Commons focuses on critical, on-shore prototyping to transition innovation from universities, start-ups, and small companies to fabrication facilities (lab-to-fab transition). Key features are: • Creates and connects “Lab-to-Fab” testing/prototyping hubs to form a network focused on maturing emerging microelectronics technologies • Provides broad access to these prototyping hubs, potentially by augmenting facilities and enabling access to facilities within local semiconductor companies or FFRDCs. • Facilitates microelectronics education and training of students at local colleges and universities and grows a talent pipeline to bolster local semiconductor economies and contribute more broadly to the growth of a domestic semiconductor workforce. This program element focuses on the applied research activities of the Commons, including staffing at Commons hub facilities, early technology identification, preliminary microelectronics prototyping planning, and experimental tools.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602675D8Z$$, $$Social Sciences for Environmental Security$$, $$rdte_dw_ba2$$, $$dw$$, 2026, 0, 3100000, 4910000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "dw", "page_num": 67, "original_pe": "0602675D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Department's initiative to Build Sustainable and Long-Term Advantage. This program funds Department of Defense (DoD) physical climate and social science applied research. Climate and environmental change will impact the full range of U.S. military operating environments. DoD capabilities, until recently, have been aligned toward the historical environmental and geopolitical record; failure to anticipate and plan for the security effects of climate and environmental change holds significant potential to not only degrade DoD readiness and effectiveness but also compound the frequency and scope of novel geostrategic risks and surprises. Efforts under this program will focus on interdisciplinary science and technology that spans physical climate modeling and forecasting and social sciences capable of yielding tangible decision support tools that empower operational planners to prepare for and adapt to the complicated, interconnected security and stability challenges of climate and environmental change. Insights derived from this program will enable Combatant Commands to better engage key partners and allies in efforts to plan for and mitigate risks and promote global peace and stability. The program includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                             Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:         PE 0602675D8Z / Social Sciences for Environmental Security Applied Research$$, NULL, NULL, NULL, NULL, NULL, NULL, 24, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 3783000, 0, NULL, NULL, NULL, NULL, NULL, $$This program supports the Department's initiative to Build Sustainable and Long-Term Advantage. This program funds Department of War (DoW) physical climate and social science applied research. Climate and environmental change will impact the full range of U.S. military operating environments. DoW capabilities, until recently, have been aligned toward the historical environmental and geopolitical record; failure to anticipate and plan for the security effects of climate and environmental change holds significant potential to not only degrade DoW readiness and effectiveness but also compound the frequency and scope of novel geostrategic risks and surprises. Efforts under this program will focus on interdisciplinary science and technology that spans physical climate modeling and forecasting and social sciences capable of yielding tangible decision support tools that empower operational planners to prepare for and adapt to the complicated, interconnected security and stability challenges of climate and environmental change. Insights derived from this program will enable Combatant Commands to better engage key partners and allies in efforts to plan for and mitigate risks and promote global peace and stability. The program includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                        Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:       PE 0602675D8Z / Social Sciences for Environmental Security Applied Research$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602702E$$, $$TACTICAL TECHNOLOGY$$, $$rdte_dw_ba2$$, $$dw_darpa$$, 2026, 0, 196114000, 117935000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "dw", "page_num": 67, "original_pe": "0602702E", "page_header": "Defense-Wide"}$$::jsonb, $$The efforts described in this Program Element (PE) address the Applied Research associated with the Tactical Technology Program that supports the advancement of concepts and technologies to enhance the next generation of tactical systems. This PE funds a number of projects in the areas of Naval Warfare, Advanced Land Systems, Aeronautics and Space Technology and Information Analytics Technology. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA-funded technologies take root in the U.S. and provide new capabilities for national defense. The Naval Warfare Technology project develops advanced technologies for application to a broad range of naval requirements. Enabling and novel technologies include concepts for expanding the envelope of operational naval capabilities to include the entire sea column such as improved situational awareness over large maritime environments, ship self-defense techniques, novel underwater propulsion modalities, high speed underwater vessels, improved techniques for underwater object detection and discrimination, long endurance unmanned surface vehicles, methods and techniques for servicing assets throughout the sea column, and high bandwidth communications. This project will also examine methods and architectures for distributing maritime operations to enable a more agile, survivable, and cost-effective fleet. The Advanced Land Systems Technology project is developing technologies for enhancing U.S. military effectiveness and survivability in operations ranging from traditional threats to military operations against irregular forces that can employ disruptive or catastrophic capabilities, or disrupt stabilization operations, including competing in underground spaces. Programs in this project will break the relative symmetry of land combat to give U.S. forces a decided advantage in the current and future ground battlefield. The emphasis is on developing affordable technologies that reduce reliance on consolidated forward-operating bases and required lines of communication, and provide small units and individual warfighters with hyper-mobility and hyper-lethality. This project will develop methods and technologies to expand the maneuver trade space to include the vertical dimension, including subterranean environments, as well as underground spaces. It will leverage advances in artificial intelligence to enable integrated manned-unmanned operations and decrease warfighter exposure through the use of autonomous agents. Aeronautics and Space Technology efforts will address high payoff opportunities that dramatically reduce costs associated with advanced aeronautical and space systems and/or provide revolutionary new system capabilities for satisfying current and projected military mission requirements. This includes advanced technology Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                           Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:              PE 0602702E / TACTICAL TECHNOLOGY Applied Research studies of revolutionary propulsion, vehicle, and launch concepts, sophisticated fabrication methods, and examination of novel materials and enabling technologies for aeronautics and space system applications. Studies that also fundamentally change the calculus of battle including consideration of a mix of assets, platforms that are potentially disposable or with limited lifespans, and autonomous integration of space and air platforms in the tactical battlespace are included. The Information Analytics Technology project develops technology for analyzing data and information arising from: 1) intelligence networks; 2) open sources, social and broadcast media, and other external sources; 3) sensors and signal/image processors; and 4) collection platforms and weapon systems. Technical challenges include processing huge volumes of diverse, incomplete, and uncertain data in tactically-relevant timeframes, and countering the information operations of sophisticated adversaries who seek to deceive, degrade, deny, and disrupt the U.S. information enterprise. Benefits sought include a deeper understanding of the evolving operational environment tailored to the needs of commanders at every echelon; an enhanced capability to plan, monitor, and control diverse military operations ranging from stabilization and information operations to combat engagements; and increased efficiency of core military functions such as national and homeland security, warfighter protection, and defense support of law enforcement and civil authorities. Beginning in FY 2026, efforts in this PE will be funded in PE 0602023E, Access and Awareness.$$, NULL, 0, 0, 0, NULL, NULL, 25, $$RDTE_Vol1_DARPA_MasterJustificationBook_PB_2026.pdf$$, $$DARPA$$, FALSE, 112715000, 0, 0, 0, NULL, 0, 0, $$The efforts described in this Program Element (PE) address the Applied Research associated with the Tactical Technology Program that supports the advancement of concepts and technologies to enhance the next generation of tactical systems. This PE funds a number of projects in the areas of Advanced Land Systems, Aeronautics and Space Technology and Information Analytics Technology. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA-funded technologies take root in the U.S. and provide new capabilities for national defense. The Advanced Land Systems Technology project is developing technologies for enhancing U.S. military effectiveness and survivability in operations ranging from traditional threats to military operations against irregular forces that can employ disruptive or catastrophic capabilities, or disrupt stabilization operations, including competing in underground spaces. Programs in this project will break the relative symmetry of land combat to strengthen and maintain U.S. forces' decisive advantages in the current and future ground battlefield. The emphasis is on developing affordable technologies that reduce reliance on consolidated forward-operating bases and required lines of communication, and provide small units and individual warfighters with hyper-mobility and hyper-lethality. This project will develop methods and technologies to expand the maneuver trade space to include the vertical dimension, including subterranean environments, as well as underground spaces. It will leverage advances in artificial intelligence to enable integrated manned-unmanned operations and decrease warfighter exposure through the use of autonomous agents. Aeronautics and Space Technology efforts will address high payoff opportunities that dramatically reduce costs associated with advanced aeronautical and space systems and/or provide revolutionary new system capabilities for satisfying current and projected military mission requirements. This includes advanced technology studies of revolutionary propulsion, vehicle, and launch concepts, sophisticated fabrication methods, and examination of novel materials and enabling technologies for aeronautics and space system applications. Studies that also fundamentally change the calculus of battle including consideration of a mix of assets, platforms that are potentially disposable or with limited lifespans, and autonomous integration of space and air platforms in the tactical battlespace are included. The Information Analytics Technology project developed technology for analyzing data and information arising from: 1) intelligence networks; 2) open sources, social and broadcast media, and other external sources; 3) sensors and signal/image processors; and 4) collection platforms and weapon systems. Technical challenges included processing huge volumes of diverse, incomplete, and uncertain data in tactically relevant timeframes and countering the information operations of sophisticated adversaries who seek to deceive, degrade, deny, and disrupt the U.S. information enterprise. Benefits sought include a deeper understanding of the evolving operational Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Advanced Research Projects Agency                                          Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:          PE 0602702E / TACTICAL TECHNOLOGY Applied Research environment tailored to the needs of commanders at every echelon; an enhanced capability to plan, monitor, and control diverse military operations ranging from stabilization and information operations to combat engagements; and increased efficiency of core military functions such as national and homeland security, warfighter protection, and defense support of law enforcement and civil authorities. Beginning in FY 2026, efforts in this PE will be funded in PE 0602023E, Access and Awareness.$$, $$Budget J-Books/FY27/DW/RDTE_Vol1_DARPA_MasterJustificationBook_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602715E$$, $$MATERIALS AND BIOLOGICAL TECHNOLOGY$$, $$rdte_dw_ba2$$, $$dw_darpa$$, 2026, 0, 319370000, 316221000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "dw", "page_num": 67, "original_pe": "0602715E", "page_header": "Defense-Wide"}$$::jsonb, $$The efforts described in this Program Element (PE) address the Applied Research associated with the Materials and Biological Technology Program that is focused on developing materials and biological technologies that make possible a wide range of new military capabilities. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. The Materials Processing Technology project will develop novel materials, fabrication and processing techniques, models, devices and components that will lower the cost, increase the performance, and/or enable new missions for military platforms and systems. Included in this project are efforts across a wide range of technology areas including manufacturing, electronics, sensors, optics, and complex and autonomous systems. The Biologically Based Materials and Devices project will leverage the growing application space of the biological sciences for the development of new DoD capabilities to improve the sustainability of warfighters, and operational platforms in varied environments. This project will develop solutions for critical resource processing, materials development, threat detection and characterization, environmental remediation, and warfighter resilience to infectious disease and environmental stressors. The materials developed through this project will protect and sustain warfighters and operations in austere environments. Beginning in FY 2026, efforts in this PE will be funded in PE 0602024E, Warfighting Performance, and PE 0602025E, Making, Maintaining, Supply Chain and Logistics. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                   Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:        PE 0602715E / MATERIALS AND BIOLOGICAL TECHNOLOGY Applied Research$$, NULL, 0, 0, 0, NULL, NULL, 26, $$RDTE_Vol1_DARPA_MasterJustificationBook_PB_2026.pdf$$, $$DARPA$$, FALSE, 304669000, 0, 0, 0, NULL, 0, 0, $$The efforts described in this Program Element (PE) address the Applied Research associated with the Materials and Biological Technology Program that is focused on developing materials and biological technologies that make possible a wide range of new military capabilities. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. The Materials Processing Technology project will develop novel materials, fabrication and processing techniques, models, devices and components that will lower the cost, increase the performance, and/or enable new missions for military platforms and systems. Included in this project are efforts across a wide range of technology areas including manufacturing, electronics, sensors, optics, and complex and autonomous systems. The Biologically Based Materials and Devices project will leverage the growing application space of the biological sciences for the development of new DoW capabilities to improve the sustainability of warfighters, and operational platforms in varied environments. This project will develop solutions for critical resource processing, materials development, threat detection and characterization, environmental remediation, and warfighter resilience to infectious disease and environmental stressors. The materials developed through this project will protect and sustain warfighters and operations in austere environments. Beginning in FY 2026, efforts in this PE will be funded in PE 0602024E, Warfighting Performance, and PE 0602025E, Making, Maintaining, Supply Chain and Logistics. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Advanced Research Projects Agency                                   Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:        PE 0602715E / MATERIALS AND BIOLOGICAL TECHNOLOGY Applied Research$$, $$Budget J-Books/FY27/DW/RDTE_Vol1_DARPA_MasterJustificationBook_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602718BR$$, $$COUNTER WEAPONS OF MASS DESTRUCTION APPLIED RESEAR$$, $$rdte_dw_ba2$$, $$dw_dtra$$, 2026, 161495000, 209202000, 170615000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "dw", "page_num": 67, "original_pe": "0602718BR", "page_header": "Defense-Wide"}$$::jsonb, $$The Counter Weapons of Mass Destruction (CWMD) Cross-Cutting Technical and Information Sciences project develops concepts and technologies in the areas of high-speed information processing, modeling and simulation, signal detection, and data-driven decision analysis in support of the Defense Threat Reduction Agency's (DTRA's) technical reachback teams. This project develops and maintains continuously improving collaborative architectures and Weapons of Mass Destruction (WMD) modeling and simulation codes that drive an integrated suite of decision support tools serving the Combatant Commands, other Department of Defense (DoD) agencies, and national and international CWMD partners. This effort also funds research activities that benefit the public through analysis and engagement to reduce and counter threats posed by WMD via the Strategic Trends Research Initiative. Strategic Trends Research Initiative cultivates national and international research community partnerships across domains, bringing scientific, technical, and social science experts together to help understand and anticipate WMD capabilities and threats. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Threat Reduction Agency                                                   Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:           PE 0602718BR / COUNTER WEAPONS OF MASS DESTRUCTION APPLIED RESEAR Applied Research                                                               CH$$, NULL, 156337000, 161397000, 164926000, NULL, NULL, 28, $$RDTE_DTRA_PB_2026.pdf$$, $$DTRA$$, FALSE, 166400000, 149443000, 157287000, 157287000, NULL, 157287000, 168319000, $$DTRA’s Counter Weapons of Mass Destruction (WMD) Applied Research Program seeks to understand the means to deter and counter critical WMD problems. Through the program’s four project areas, DTRA invests in the development of science and technology capabilities to counter WMD and emerging threats. The CWMD Cross-Cutting Technical and Information Sciences project develops concepts and technologies in the areas of high-speed information processing, modeling and simulation, signal detection, and data-driven decision analysis in support of the DTRA's technical reachback teams. The Nuclear Technologies and Capabilities Development project develops direct and indirect technologies for the detection of radiation and nonradioactive signatures associated with nuclear threats, and advance warfighter capabilities to rapidly locate, characterize, and counter such threats. The CWMD Technologies and Capabilities Development project develops innovative kinetic and non-kinetic weapons technologies to expand traditional and asymmetric options available to Combatant Commanders to deny, disrupt, and defeat adversarial use of WMD while minimizing collateral effects. The CWMD Test and Evaluation project provides unique national test bed capability for the study of weapon-target interaction, simulated WMD facility characterization, and WMD facility defeat testing to evaluate the implications of WMD and other special weapon use against U.S. military and civilian assets. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Threat Reduction Agency                                                Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:          PE 0602718BR / COUNTER WEAPONS OF MASS DESTRUCTION APPLIED RESEAR Applied Research                                                              CH$$, $$Budget J-Books/FY27/Remaining/RDTE_DTRA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602747N$$, $$Undersea Warfare Applied Res$$, $$rdte_navy_ba2$$, $$onr$$, 2026, 64335000, 98285000, 88525000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "navy", "page_num": 26, "original_pe": "0602747N", "page_header": "Department of the Navy"}$$::jsonb, $$The Undersea Warfare Applied Research Program Element (PE) funds applied research efforts in undersea target detection, classification, localization, tracking, and neutralization. Associated efforts focus on new Anti-Submarine Warfare (ASW) operational concepts that promise to improve wide-area surveillance, detection, localization, tracking, and attack capabilities against quiet adversary submarines operating in noisy and cluttered shallow water environments. Related efforts are aimed at leveraging technologies that will protect the country's current capital investment in surveillance, submarine, surface ship, and air ASW assets. Research focused on understanding the impacts on marine mammals of manmade underwater sound is also conducted in the PE. The activities described in this PE address future Navy and Marine Corps capabilities needed to maintain maritime superiority and ensure national security. Targeted capabilities are based on input from Naval Research Enterprise stakeholders including combatant commands, Office of the Chief of Naval Operations (OPNAV) and Headquarters Marine Corps and are designed to exploit breakthroughs in science and technology in order to deliver maximum undersea warfighting benefit to our sailors and marines. Today's Sailors and Marines are enabled by naval Science and Technology (S&T). Since 1946, the Office of Naval Research (ONR) has fostered scientific research related to the maintenance of maritime superiority and national defense. ONR manages the Department of the Navy's (DON) portfolio of naval Basic and Applied research, and Advanced Technology Development investments to ensure naval forces can effectively deter conflict, but when called upon, fight, win and come home safe. Current investments hedge against uncertainty, providing solutions to commanders today, and options for the future. The Naval S&T budget supports higher guidance defined by the National Defense Strategy, and responds to requirements identified by the Secretary of the Navy through research priorities set by the Chief of Naval Research, coordinated across the Naval Research Enterprise (NRE), and outlined in the Naval R&D Framework. This PE funds Applied Research, which is the systematic study to understand the means to meet a recognized and specific need. Most of the work in this PE can be classified between Technology Readiness Level (TRL) 2 (technology concept and/or application formulation) and TRL 4 (component and/or breadboard validation in laboratory environments). Due to the number of efforts in this PE, the programs described herein are representative of the work included in this PE. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                              Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 2: Applied           PE 0602747N / Undersea Warfare Applied Res Research$$, NULL, 57348000, 58237000, 56976000, NULL, NULL, 11, $$RDTEN_BA1-3_Book.pdf$$, NULL, FALSE, 90135000, 120808000, 52515000, 52515000, NULL, 52515000, 58240000, $$The Undersea Warfare Applied Research Program Element (PE) funds applied research efforts in undersea target detection, classification, localization, tracking, and neutralization. Associated efforts focus on new Anti-Submarine Warfare (ASW) operational concepts that promise to improve wide-area surveillance, detection, localization, tracking, and attack capabilities against quiet adversary submarines operating in noisy and cluttered shallow water environments. Related efforts are aimed at leveraging technologies that will protect the country's current capital investment in surveillance, submarine, surface ship, and air ASW assets. Research focused on understanding the impacts on marine species of manmade underwater sound is also conducted in the PE. The activities described in this PE address future Navy and Marine Corps capabilities needed to maintain maritime superiority and ensure national security. Targeted capabilities are based on input from Naval Research Enterprise stakeholders including combatant commands, Office of the Chief of Naval Operations (OPNAV) and Headquarters Marine Corps and are designed to exploit breakthroughs in science and technology in order to deliver maximum undersea warfighting benefit to our sailors and marines. Today's Sailors and Marines are enabled by naval Science and Technology (S&T). Since 1946, the Office of Naval Research (ONR) has fostered scientific research related to the maintenance of maritime superiority and national defense. ONR manages the Department of the Navy's (DON) portfolio of naval Basic and Applied research, and Advanced Technology Development investments to ensure naval forces can effectively deter conflict, but when called upon, fight, win and come home safe. Current investments hedge against uncertainty, providing solutions to commanders today, and options for the future. The Naval S&T budget supports higher guidance defined by the National Defense Strategy, and responds to requirements identified by the Secretary of the Navy through research priorities set by the Chief of Naval Research and outlined in the Naval R&D Framework. This PE funds Applied Research, which is the systematic study to understand the means to meet a recognized and specific need. Most of the work in this PE can be classified between Technology Readiness Level (TRL) 2 (technology concept and/or application formulation) and TRL 4 (component and/or breadboard validation in laboratory environments). Due to the number of efforts in this PE, the programs described herein are representative of the work included in this PE. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                           Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 2: Applied         PE 0602747N / Undersea Warfare Applied Res Research$$, $$Budget J-Books/FY27/Navy/RDTEN_BA1-3_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602782N$$, $$Mine and Expeditionary Warfare Applied Research$$, $$rdte_navy_ba2$$, $$onr$$, 2026, 29081000, 30011000, 32460000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "navy", "page_num": 26, "original_pe": "0602782N", "page_header": "Department of the Navy", "fy26_v182_disc_K": 18081, "fy26_v182_supp_K": 80000, "fy26_v182_total_K": 98081, "fy26_v182_note_name": "Research, Development, Test and Evaluation, Navy", "fy26_v182_source_file": "RDTEN_BA1-3_Book.txt", "fy26_v182_source_line": 22212}$$::jsonb, $$Sea mines remain a significant threat to ships. In fact, fifteen U.S. Navy ships have been sunk or damaged by mines since World War II, almost four times more than any other weapon. The Mine and Expeditionary Warfare Applied Research Program Element (PE) provides technologies for Naval Mine Countermeasures (MCM), Expeditionary Warfare, U.S. Naval sea mining, Naval Special Warfare (NSW), and Joint Tri-Service Explosive Ordnance Disposal (EOD) as well as continuing support to research vessels of the U.S. Academic Research Fleet for operations and maintenance that enable applied research at sea. This program strongly aligns with the Joint Chiefs of Staff Joint Warfighting Capability Objectives through the development of technologies to achieve military objectives with minimal casualties and collateral damage. This investment will enable Ship-to-Objective Maneuver (STOM) and focus on technologies that will provide the Naval Force with the capability to dominate the battlespace, project power from the sea, and support forces ashore with particular emphasis on rapid MCM operations. These efforts concentrate on the development and transition of technologies for the MCM-related and Urban Asymmetric/Expeditionary Warfare Operations (UAEO)-related Future Naval Capabilities (FNC) Enabling Capabilities (ECs). The Mine and Obstacle Detection and Neutralization efforts include technologies for clandestine and overt minefield reconnaissance, organic ship self-protection, organic mine hunting and neutralization/breaching. The Urban Asymmetric Operation effort includes critical warfighting functions such as Command, Control, Communications, Computers, Intelligence, Surveillance and Reconnaissance (C4ISR), fires, maneuver, sustainment, etc. The Naval Special Warfare and Explosive Ordnance Disposal technology efforts concentrate on the development of technologies for safe near-shore mine detection, diver mobility and survivability, and ordnance disposal operations. The activities described in this PE address future Navy and Marine Corps capabilities needed to maintain maritime superiority and ensure national security. They are based on input from Naval Research Enterprise stakeholders including the Naval enterprises, the combatant commands, Office of the Chief of Naval Operations (OPNAV) and Headquarters Marine Corps and are designed to exploit breakthroughs in science and technology in order to deliver maximum warfighting benefit to our sailors and Marines. These efforts align with shared priorities throughout the whole of RDT&E in order to quickly advance new capabilities from discovery to deployment across the warfighting domains. Today's Sailors and Marines are enabled by naval Science and Technology (S&T). Since 1946, the Office of Naval Research (ONR) has fostered scientific research related to the maintenance of maritime superiority and national defense. ONR manages the Department of the Navy's (DON) portfolio of naval Basic and Applied research, and Advanced Technology Development investments to ensure naval forces can effectively deter conflict, but when called upon, fight, win and come home safe. Current investments hedge against uncertainty, providing solutions to commanders today, and options for the future. The Naval S&T budget supports higher guidance defined by the National Defense Strategy, and responds to requirements identified by the Secretary of the Navy through research priorities set by the Chief of Naval Research, coordinated across the Naval Research Enterprise (NRE), and outlined in the Naval R&D Framework. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 2: Applied             PE 0602782N / Mine and Expeditionary Warfare Applied Research Research This Program Element (PE) funds Applied Research, which is the systematic study to understand the means to meet a recognized and specific need. Most of the work in this PE can be classified between Technology Readiness Level (TRL) 2 (technology concept and/or application formulation) and TRL 4 (component and/or breadboard validation in laboratory environments). Due to the number of efforts in this PE, the programs described herein are representative of the work included in this PE.$$, NULL, 26616000, 26582000, 27901000, NULL, NULL, 13, $$RDTEN_BA1-3_Book.pdf$$, NULL, FALSE, 29294000, 98081000, 24634000, 24634000, NULL, 24634000, 28255000, $$Sea mines remain a significant threat to ships. In fact, fifteen U.S. Navy ships have been sunk or damaged by mines since World War II, almost four times more than any other weapon. The Mine and Expeditionary Warfare Applied Research Program Element (PE) provides technologies for Naval Mine Countermeasures (MCM), Expeditionary Warfare, U.S. Naval sea mining, Naval Special Warfare (NSW), and Joint Tri-Service Explosive Ordnance Disposal (EOD) as well as continuing support to research vessels of the U.S. Academic Research Fleet for operations and maintenance that enable applied research at sea. This program strongly aligns with the Joint Chiefs of Staff Joint Warfighting Capability Objectives through the development of technologies to achieve military objectives with minimal casualties and collateral damage. This investment will enable Ship-to-Objective Maneuver (STOM) and focus on technologies that will provide the Naval Force with the capability to dominate the battlespace, project power from the sea, and support forces ashore with particular emphasis on rapid MCM operations. These efforts concentrate on the development and transition of technologies for the MCM-related and Urban Asymmetric/Expeditionary Warfare Operations (UAEO)-related Future Naval Capabilities (FNC) Enabling Capabilities (ECs). The Mine and Obstacle Detection and Neutralization efforts include technologies for clandestine and overt minefield reconnaissance, organic ship self-protection, organic mine hunting and neutralization/breaching. The Urban Asymmetric Operation effort includes critical warfighting functions such as Command, Control, Communications, Computers, Intelligence, Surveillance and Reconnaissance (C4ISR), fires, maneuver, sustainment, etc. The Naval Special Warfare and Explosive Ordnance Disposal technology efforts concentrate on the development of technologies for safe near-shore mine detection, diver mobility and survivability, and ordnance disposal operations. The activities described in this PE address future Navy and Marine Corps capabilities needed to maintain maritime superiority and ensure national security. They are based on input from Naval Research Enterprise stakeholders including the Naval enterprises, the combatant commands, Office of the Chief of Naval Operations (OPNAV) and Headquarters Marine Corps and are designed to exploit breakthroughs in science and technology in order to deliver maximum warfighting benefit to our sailors and Marines. These efforts align with shared priorities throughout the whole of RDT&E in order to quickly advance new capabilities from discovery to deployment across the warfighting domains. Today's Sailors and Marines are enabled by naval Science and Technology (S&T). Since 1946, the Office of Naval Research (ONR) has fostered scientific research related to the maintenance of maritime superiority and national defense. ONR manages the Department of the Navy's (DON) portfolio of naval Basic and Applied research, and Advanced Technology Development investments to ensure naval forces can effectively deter conflict, but when called upon, fight, win and come home safe. Current investments hedge against uncertainty, providing solutions to commanders today, and options for the future. The Naval S&T budget supports higher guidance defined by the National Defense Strategy, and responds to requirements identified by the Secretary of the Navy through research priorities set by the Chief of Naval Research and outlined in the Naval R&D Framework. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 2: Applied             PE 0602782N / Mine and Expeditionary Warfare Applied Research Research This Program Element (PE) funds Applied Research, which is the systematic study to understand the means to meet a recognized and specific need. Most of the work in this PE can be classified between Technology Readiness Level (TRL) 2 (technology concept and/or application formulation) and TRL 4 (component and/or breadboard validation in laboratory environments). Due to the number of efforts in this PE, the programs described herein are representative of the work included in this PE. The FY 2026 spend plan amount for Research, Development, Test and Evaluation, Navy includes $18,081 thousand of discretionary and $80,000 thousand of mandatory (reconciliation) for a total of $98,081.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA1-3_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602785A$$, $$Manpower/Personnel/Training Technology$$, $$rdte_army_ba2$$, $$dw_osd$$, 2026, 17191000, 19667000, 19795000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 11, "original_pe": "0602785A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) designs and validates applied behavioral and social science research to enhance the Soldier Lifecycle (e.g., selection, assignment, training, and leader development) and human relations (e.g., unit cohesion). This PE develops new personnel measures and methods that more fully assess potential and predict performance, behavior, attitudes, and resilience. These technologies also provide innovative and effective Talent Management methods to optimize individual and team performance to ensure the Army can meet mission requirements in uncertain and complex environments. This PE develops new performance measures and metrics for individuals and units, designs innovative training methods, and conducts scientific assessments to inform Human Capital policy and programs. Research in this PE will result in effective non-materiel solutions to help the Army adjust to changes in force size and structure, a variety of mission demands and contexts, challenges in human relations, and budgetary constraints. Research in this PE complements PE 0603007A (Manpower, Personnel and Training Advanced Technology). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas, the Army Vision, the Army's Talent Management Strategy, and the Army Modernization Strategy. Research is performed by the Army Research Institute (ARI) for the Behavioral and Social Sciences at Fort Belvoir, VA. The FY 2026 request was reduced by $0.14 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.118 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                        Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied         PE 0602785A / Manpower/Personnel/Training Technology Research$$, NULL, 15759000, 16159000, 16299000, NULL, NULL, 30, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, 19072000, 17191000, 14275000, 14275000, NULL, 14275000, 16474000, $$This PE designs and validates applied behavioral and social science research to enhance the Soldier Lifecycle (e.g., selection, assignment, training, and leader development) and human relations. This PE develops new personnel measures and methods that more fully assess potential and predict performance, behavior, attitudes, and resilience. These technologies also provide innovative and effective Talent Management methods to optimize individual and team performance to ensure the Army can meet mission requirements in uncertain and complex environments. This PE develops new performance measures and metrics for individuals and units, designs innovative training methods, and conducts scientific assessments to inform Human Capital policy and programs. Research in this PE will result in effective non-materiel solutions to help the Army adjust to changes in force size and structure, a variety of mission demands and contexts, challenges in human relations, and budgetary constraints. Research in this PE complements PE 0603007A / project 792 (Manpower, Personnel and Training Advanced Technology). The cited research is consistent with the Under Secretary of War for Research and Engineering priority focus areas, the Army Vision, the Army's Talent Management Strategy, and the Army Modernization Strategy. Research is performed by the Army Research Institute for the Behavioral and Social Sciences (ARI) at Fort Belvoir, VA.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 2.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2035_L200$$, $$Special Equipment for Test and Evaluatio...$$, $$proc_army_2035_ba3$$, $$peo_c3t$$, 2026, 93777000, 52481000, 90705000, NULL, $${"page": 50, "ba_num": "03", "source": "p1_fy26", "ba_name": "Other support equipment", "line_no": "200", "service": "army", "fy24_qty": null, "fy25_qty": null, "appr_code": "2035", "appr_name": "Other Procurement, Army", "fy26_v178": {"note": "no_parser_pair", "source": "p40_fy26_v178"}, "fy26t_qty": null, "fy26d_cost": 93777000, "fy26r_cost": 0, "ident_code": "B"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, 740732000, NULL, NULL, NULL, FALSE, 90705000, 93777000, 0, 0, 0, 0, NULL, NULL, $$Budget J-Books/FY27/Army/Other Procurement - BA3 & 4 - Other Support Equipment & Initial Spares.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602787A$$, $$Medical Technology$$, $$rdte_army_ba2$$, $$dw_dha$$, 2026, 143293000, 139515000, 68481000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 11, "original_pe": "0602787A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) supports application of knowledge gained through basic research to optimize drugs, medical devices, medical practices/procedures, and other preventive measures to include injury predictive strategies and tools essential to the protection and sustainment of Warfighter health and performance. Projects are coordinated with the Defense Health Agency. The cited research is consistent with the Under Secretary of Defense for Research and Engineering science and technology focus areas and the Army Modernization Strategy. All medical applied research is conducted in compliance with Food and Drug Administration (FDA) or Environmental Protection Agency (EPA) regulations. The FDA requires thorough testing in animals (preclinical testing) to ensure safety and, where possible, effectiveness prior to evaluation in controlled human clinical trials (upon transition to Advanced Technology Development). This PE focuses on research and refinement of technologies such as product formulation and purification and laboratory test refinement with the aim of identifying candidate solutions. This work often involves testing in animal models. The EPA also requires thorough testing of products, such as sterilants, disinfectants, repellents, and insecticides to ensure the environment is adequately protected before these products are licensed for use. Program refinement and execution is externally peer-reviewed and fully coordinated with all Services as well as other agencies through the Joint Technology Coordinating Groups of the Biomedical Community of Interest. The Biomedical Community of Interest, formed under the authority of the Assistant Secretary of Defense for Research and Engineering, serves to facilitate coordination and prevent unnecessary duplication of effort within the Department of Defenses (DoD) biomedical research community, as well as their associated enabling research areas. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied         PE 0602787A / Medical Technology Research The FY 2026 request was reduced by $2.082 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.116 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 155330000, 155964000, 158198000, NULL, NULL, 31, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, 64842000, 186793000, 149221000, 149221000, NULL, 149221000, 156672000, $$This PE supports application of knowledge gained through basic research to optimize drugs, medical devices, medical practices/procedures, and other preventive measures to include injury predictive strategies and tools essential to the protection and sustainment of Warfighter health and performance. Projects are coordinated with the Defense Health Agency. The cited research is consistent with the Under Secretary of War for Research and Engineering science and technology focus areas and the Army Modernization Strategy. All medical applied research is conducted in compliance with Food and Drug Administration (FDA) or Environmental Protection Agency (EPA) regulations. The FDA requires thorough testing in animals (preclinical testing) to ensure safety and, where possible, effectiveness prior to evaluation in controlled human clinical trials (upon transition to Advanced Technology Development). This PE focuses on research and refinement of technologies such as product formulation and purification and laboratory test refinement with the aim of identifying candidate solutions. This work often involves testing in animal models. The EPA also requires thorough testing of products, such as sterilants, disinfectants, repellents, and insecticides to ensure the environment is adequately protected before these products are licensed for use. Program refinement and execution is externally peer-reviewed and fully coordinated with all Services as well as other agencies through the Joint Technology Coordinating Groups of the Biomedical Community of Interest. The Biomedical Community of Interest, formed under the authority of the Assistant Secretary of War for Research and Engineering, serves to facilitate coordination and prevent unnecessary duplication of effort within the DoW biomedical research community, as well as their associated enabling research areas. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied             PE 0602787A / Medical Technology Research$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 2.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602788F$$, $$Dominant Information Sciences and Methods$$, $$rdte_af_ba2$$, $$afrl_ri$$, 2026, 187036000, 337052000, 207333000, NULL, $${"ba_raw": "6.2", "source": "af_r1_fy26", "original_pe": "0602788F"}$$::jsonb, $$The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now, while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This program executes applied research to develop information technologies for the Department of the Air Force to address technology gaps for Command, Control, Communications, Computers, Cyber, Intelligence, Surveillance, Reconnaissance, and Targeting (C5ISRT). These technologies are required to advance the state-of- the-art for C5ISRT that encompasses integrated systems and processes used by the Department of the Air Force and its joint & coalition partners, to collect, process, analyze, and disseminate information to achieve decision-making superiority for warfighter operations. The C4I Dominance Technology Project provides the technologies for (a) informed decision making and coordinated operations; (b) reliable, resilient, and secure communications; (c) advanced computer processing and data & information analysis. C4I is defined as Command, Control, Communications, Computers, and Intelligence. The Cyberspace Dominance Technology Project provides the technologies to achieve and maintain superiority in cyberspace (aligning with air, land, sea, and space domains), focusing on cyber offense, cyber defense, and cyber resilience. The Research Site Support Project provides the Rome Research Site infrastructure at Rome, New York and provides for the continued operations of all Rome Research Site properties, buildings, and services necessary for the research mission for AFRL and for the Defense Finance and Accounting Service (DFAS) Rome, NY location. Efforts in this program have been coordinated through the Department of Defense (DoD) Science and Technology (S&T) Executive Committee process to harmonize efforts and eliminate duplication. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied         PE 0602788F / Dominant Information Sciences and Methods Research This program includes funding for the requisite DAF Science & Engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The use of program funds in this program element is in conjunction with the civilian pay expenses budgeted in the following program elements: 1206601SF, 0601102F, 0602020F, 0602102F, 0602202F, 0602203F, 0602204F, 0602298F, 0602336F, 0602602F, 0602605F, and 0603680F. In FY 2026, $104.926 million is budgeted in this program for 627 direct Full-Time Equivalent (FTE) civilians. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters.$$, NULL, 148799000, 185821000, 195805000, NULL, NULL, 15, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 196117000, 295677000, 149174000, 149174000, 0, 149174000, 202758000, $$This program executes applied research to develop information technologies for the Department of the Air Force to address technology gaps for Command, Control, Communications, Computers, Cyber, Intelligence, Surveillance, Reconnaissance, and Targeting (C5ISRT). These technologies are required to advance the state-of- the-art for C5ISRT that encompasses integrated systems and processes used by the Department of the Air Force and its joint & coalition partners, to collect, process, analyze, and disseminate information to achieve decision-making superiority for warfighter operations. The C4I Dominance Technology Project provides the technologies for (a) informed decision making and coordinated operations; (b) reliable, resilient, and secure communications; (c) advanced computer processing and data & information analysis. C4I is defined as Command, Control, Communications, Computers, and Intelligence. The Cyberspace Dominance Technology Project provides the technologies to achieve and maintain superiority in cyberspace (aligning with air, land, sea, and space domains), focusing on cyber offense, cyber defense, and cyber resilience. The Research Site Support Project provides the Rome Research Site infrastructure at Rome, New York and provides for the continued operations of all Rome Research Site properties, buildings, and services necessary for the research mission for AFRL and for the Defense Finance and Accounting Service (DFAS) Rome, NY location. This program is executed by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now, while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. Funds in this PE may be used to investigate specified technology advancements in air, space and/or cyber domains. This program includes funding for the requisite DAF Science & Engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The use of program funds in this program element is in conjunction with the civilian pay expenses Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied      PE 0602788F / Dominant Information Sciences and Methods Research budgeted in the following program elements: 1206601SF, 1206616SF, 0601102F, 0602020F, 0602102F, 0602202F, 0602203F, 0602204F, 0602298F, 0602336F, 0602602F, 0602605F, and 0603680F. In FY 2027, 102.327 million is budgeted in this program for 604 direct Full-Time Equivalent (FTE) civilians. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation. R-1 Line Item 14, received a Congressional add for FY2026 16.000 million for Advanced LiDAR for CUAS. Upon Congressional spend plan approval, an Internal Reprogramming (IR) will be processed aligning the funding to PE 0602605F for proper execution. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602861N$$, $$Science & Tech Management - ONR Field Acts$$, $$rdte_navy_ba2$$, $$onr$$, 2026, 81423000, 84907000, 90939000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "navy", "page_num": 26, "original_pe": "0602861N", "page_header": "Department of the Navy"}$$::jsonb, $$This Program Element (PE) is for the Office of Naval Research (ONR) to cover corporate expenses including salaries, Information Technology (IT), Financial Improvement Plan (FIP) efforts, Defense Finance and Accounting Service (DFAS) Billings, and some of the day-to-day logistical costs. The vast majority of these items represent fixed costs associated with Scientists and Engineers supporting the Navy's Science and Technology (S&T) Programs.$$, NULL, 79060000, 74214000, 76684000, NULL, NULL, 15, $$RDTEN_BA1-3_Book.pdf$$, NULL, FALSE, 100330000, 81423000, 74378000, 74378000, NULL, 74378000, 77974000, $$This Program Element (PE) provides funding for the essential corporate expenses that form the foundational support structure for the Office of Naval Research (ONR). These costs, the vast majority of which are fixed, include salaries for the world-class scientists and engineers who lead our S&T programs, as well as critical operational expenses such as Information Technology (IT), cyber security efforts, Defense Finance and Accounting Service (DFAS) billings, and day-to-day logistical support. This investment is not merely overhead but a direct enabler of ONR's core mission to discover, develop, and transition innovative science and technology. This foundational support ensures that ONR can continue to provide the U.S. Navy and Marine Corps with the decisive technological advantage required to preserve national security.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA1-3_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602890D8Z$$, $$High Energy Laser Research$$, $$rdte_dw_ba2$$, $$dw$$, 2026, 48738000, 46507000, 48640000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "dw", "page_num": 67, "original_pe": "0602890D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program is executed via the Joint Directed Energy Transition Office (JDETO) in alignment the Department of Defense Directed Energy Roadmap, as well as other strategic guidance. Section 219 of the 2017 National Defense Authorization Act designated a senior official for directed energy and redesignated a legacy office as the JDETO with reporting to the senior official. Currently, the Principal Director for Directed Energy serves as this senior official and updates the Department of Defense Directed Energy Roadmap on an annual basis. The goal of this program, in turn, is to support the Department’s initiatives in directed energy to build a sustainable and long-term advantage, as well as a resilient Joint force and defense ecosystem. This program funds applied research in directed energy to enable future defense capabilities realized by the Services and Agencies. These efforts include studies, investigations, and component and subsystem design and development to further the knowledge base of high energy laser and high power microwave technologies. In practice, directed energy weapon systems have many potential advantages, including speed-of-light time-to-target, high precision, low incremental cost per kill, and a magazine that is recharged through on-board, fuel-based power and thermal management systems that reduce logistics requirements in contrast to stocks of munitions or warheads. As a result, directed energy weapon systems have the potential to perform a wide variety of military missions. Activities conducted under this program are generally chosen for their potential to have an impact on multiple directed energy weapon systems and multiple military missions while complementing specific Service and Agency needs. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                    Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:        PE 0602890D8Z / High Energy Laser Research Applied Research$$, NULL, 50913000, 51108000, 51432000, NULL, NULL, 30, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 47374000, 47110000, 50408000, 50408000, NULL, 50408000, 51428000, $$This program is executed via Scaled Directed Energy (SCADE) Science and Technology and in alignment with the Department of War Directed Energy Roadmap, as well as other strategic guidance. The goal of this program is to support the Department’s initiatives in directed energy to build a sustainable and long-term advantage. This program funds applied research in directed energy to enable future defense capabilities realized by the Services and Agencies. These efforts include studies, investigations, and component and subsystem design and development to further the knowledge base of high energy laser and high power microwave technologies. In practice, directed energy weapon systems have many potential advantages, including speed-of-light time-to-target, high precision, low incremental cost per kill, and a magazine that is recharged through on-board, fuel-based power and thermal management systems that reduce logistics requirements in contrast to stocks of munitions or warheads. As a result, directed energy weapon systems have the potential to perform a wide variety of military missions. Activities conducted under this program are generally chosen for their potential to have an impact on multiple directed energy weapon systems and multiple military missions while complementing specific Service and Agency needs.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602891D8Z$$, $$FSRM Modeling$$, $$rdte_dw_ba2$$, $$dw_mda$$, 2026, 5994000, 2000000, 1897000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "dw", "page_num": 67, "original_pe": "0602891D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$The FY 2026 request for FSRM Modeling PE includes $0.994 million of discretionary and $5.000 million of mandatory (reconciliation) for a total of $5.994 million. The mandatory funds Golden Dome Cyber Resilience and Readiness Exercises . Further information for this reconciliation request is provided in Section 20003 Missile Defense of the Reconciliation Exhibit. FSRM Mission Description and Budget Justification: The Facilities Sustainment, Restoration, and Modernization (FSRM) Modeling requirement is inclusive of the development of a computer system, development of software, development of standards for the FSRM prioritization. This will aid in the establishment metrics for adjudicating FSRM funding sufficiency for use in future program and budget reviews. Golden Dome Mission Description and Budget Justification: Golden Dome Cyber Resilience and Readiness Exercises funding of $5.000 million supports the assessment of the control systems which allow for the Golden Dome mission execution. The allocated $5.000 million will be used to develop "live fire" cyber resilience exercises to assess the readiness and resilience of the control systems at Golden Dome installations. These live exercises will afford the system owners and operators hands on experience in detecting and providing defense against APT- actor cyber-attacks and the physical disruptions that can result. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                              Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:          PE 0602891D8Z / FSRM Modeling Applied Research$$, NULL, 6654000, 6684000, 6722000, NULL, NULL, 31, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 1897000, 994000, 6635000, 6635000, NULL, 6635000, 6856000, $$The Facilities Sustainment, Restoration, and Modernization (FSRM) Modeling requirement is inclusive of the development of a computer system, development of software, and development of standards for the FSRM prioritization. This will aid in the establishment metrics for adjudicating FSRM funding sufficiency for use in future program and budget reviews. Of the $6.635 million, Golden Dome Cyber Resilience and Readiness Exercises make up a total of $5 million. Golden Dome Cyber Resilience and Readiness Exercises funding of $5 million supports the assessment of the control systems which allow for the Golden Dome mission execution. The allocated $5 million will be used to develop "live fire" cyber resilience exercises to assess the readiness and resilience of the control systems at four (4) additional Golden Dome installations. These live exercises will afford the system owners and operators hands on experience in detecting, protecting and responding to Advanced Persistent Threat- actor and zero-day cyber-attacks, and the physical disruptions that can result. Four (4) different installations will be selected each year in coordination with the Missile Defense Agency (MDA) and Golden Dome for America (GDA) offices.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603000D8Z$$, $$Joint Munitions Advanced Technology$$, $$rdte_dw_ba3$$, $$dw_ousd_re$$, 2026, 50663000, 39486000, 39394000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 67, "fy27_mand_k": 415000, "original_pe": "0603000D8Z", "page_header": "Defense-Wide", "fy27_mand_v157": "2026-05-08", "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy27_mand_section": "Munitions"}$$::jsonb, $$This program supports the Department's priority to reestablish deterrence through developing and demonstrating munitions technologies that deliver crosscutting capabilities to the Services to solve operational and mission-focused challenges. The Joint Enhanced Munitions Technology Program (JEMTP), within the Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)), was established to develop and demonstrate munitions enhancing technologies (energetics, warheads, propulsion systems, advanced lethality mechanisms, fuzes and fuze components, and target detection), to transition future kinetic fires capabilities and ensure lethality advantage for U.S. warfighters. The JEMTP concentrates on cross- cutting, all-domain munitions technology needs that benefit multiple services. JEMTP investments focus on increasing and improving the performance, lethality, range, and survivability of existing and future weapons systems. The program’s technology investment and munitions application strategy are informed by threat-opportunity based analysis from Joint Force campaign scenarios. The advancements through JEMTP provide capabilities that impact a wide range of munitions including One-Way Attack, Counter-small UAS technologies, and munitions that may be utilized for Homeland Missile Defense. The JEMTP program also delivers technologies that support munitions and energetics organic industrial base resiliency and increased production rates of critical weapon systems. The JEMTP activities within Program Element 0603000D8Z are executed under two Project Codes: 077 - Enhanced Advanced Munitions Technology and 356 – Energetics Advanced Technologies. Project Code 077 - The Enhanced Munitions Advanced Technology Project demonstrates critical munitions technologies including advanced fuzing, power sources, seeker technologies, and counter-countermeasure technologies that combine with Energetics Advanced Technologies to provide increases to munitions performance and survivability. Project Code 356 – The Energetics Advanced Technology Project supports DoD strategies for advanced energetics and enables the transition of higher performance explosives and propellants for U.S. munitions and delivers new technologies supporting a resilient manufacturing base. The project delivers weapon capabilities through highly lethal warheads and propulsion systems with greater range and speed. The project starts investments in FY 2026 of CL-20 advanced energetic Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                               Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:             PE 0603000D8Z / Joint Munitions Advanced Technology Advanced Technology Development (ATD) development and formulation scale-up for incorporation into weapon systems. Also in FY 2026, the project incorporates investment in area effects, focusing on maturing the High Reliability Cluster Munition concept for demonstration and transition.$$, NULL, 127359000, 105973000, 100145000, NULL, NULL, 33, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 39088000, 45325000, 64251000, 64251000, 415000000, 479251000, 102989000, $$This program supports the Department's priority to reestablish deterrence through developing and demonstrating munitions technologies that deliver crosscutting capabilities to the Services to solve operational and mission-focused challenges. The Joint Enhanced Munitions Technology Program (JEMTP), within the Office of the Under Secretary of War for Research and Engineering (OUSW(R&E)), was established to develop and demonstrate munitions enhancing technologies (energetics, warheads, propulsion systems, advanced lethality mechanisms, fuzes and fuze components, and target detection), to transition in support of future kinetic fires capabilities and ensure lethality advantage for U.S. warfighters. The JEMTP concentrates on cross-cutting, all-domain munitions technology needs that benefit multiple services. JEMTP investments focus on increasing and improving the performance, lethality, range, and survivability of existing and future weapons systems. The program’s technology investment and munitions application strategy are informed by threat-opportunity based analysis from Joint Force campaign scenarios. The advancements through JEMTP enable capabilities that impact a wide range of munitions including One-Way Attack, Counter-small UAS technologies, and munitions that may be utilized for Homeland Missile Defense. The JEMTP program also delivers technologies that support munitions and energetics organic industrial base resiliency and increased production rates of critical weapon systems. The Enhanced Munitions Advanced Technology Project demonstrates critical munitions technologies including advanced fuzing, power sources, seeker technologies, and counter-countermeasure technologies that combine with Energetics Advanced Technologies to enhance munitions performance and survivability against future advanced threats. The Energetics Advanced Technology Project supports DoW strategies for advanced energetics and enables the transition of higher performance explosives and propellants for U.S. munitions and delivers new technologies supporting a resilient manufacturing base. The project enhances weapon capabilities through highly lethal warheads and propulsion systems with greater range and speed. The project continues investment in area effects, focusing on maturing High Reliability Cluster Munitions technology. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                   Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:             PE 0603000D8Z / Joint Munitions Advanced Technology Advanced Technology Development (ATD) The Energetics Maturation project continues investments in FY 2027 of Hexanitrohexaazaisowurtzitane (CL-20) advanced energetics development and formulation scale-up for incorporation into weapon systems. The FY 2027 request for Research, Development, Test & Evaluation, Defense-Wide for Joint Munitions Advanced Technology includes $64,251 thousand of discretionary and $415,000 thousand of mandatory for a total of $479,251 thousand. The mandatory funds Joint Munitions Advanced Technology is for a program that will assist the Army in the development of a low cost, long-range precision hypersonic strike weapon and integration with launcher systems commonly found in the Army inventory. This weapon will be both low-cost and suitable to production at scale, enabling large inventories. Efforts under this activity will support platform integration, qualification, validation, flight testing, manufacturing readiness assessments, technical upgrades, and additional test rounds with which the Army will evaluate operational effectiveness. The delivery of 124 low-cost hypersonic strike weapons is associated with this FY 2027 funding. The FY 2027 mandatory funds continue efforts from FY 2027 to FY 2028.$$, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603002A$$, $$Medical Advanced Technology$$, $$rdte_army_ba3$$, $$devcom$$, 2026, 1860000, 18730000, 8112000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 11, "original_pe": "0603002A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) matures and demonstrates advanced medical technologies including drugs, medical devices, and developing medical practices and procedures to effectively protect and improve the survivability of United States Forces across the entire spectrum of military operations. Successful completion of efforts relies on tri-Service coordination and cooperation. Promising medical technologies are refined and validated through extensive testing, which is conducted in compliance with Food and Drug Administration (FDA) regulations for human medical products, and Environmental Protection Agency (EPA) regulations for insect-control products that impact humans or the environment (e.g., repellents and insecticides). The FDA requires medical products to undergo extensive preclinical testing in animals and/or other models to obtain preliminary effectiveness and safety information before they can be tested in human clinical trials. Clinical trials are conducted stepwise: first to prove the product is safe in humans, second to demonstrate the desired effectiveness and optimal dosage (amount to be administered) in a small group human study, and third to demonstrate effectiveness in large, diverse human populations. Each successive phase includes larger numbers of human subjects and requires FDA cognizance prior to proceeding. Work conducted in this PE primarily focuses on late stages of technology maturation activities required to conduct safety and effectiveness clinical trials. Some high-risk technologies may require additional maturation with FDA guidance prior to initiating these clinical trials. Such things as proof of product stability and purity are necessary to meet FDA standards before entering later stages of testing and prior to transitioning into a formal acquisition program where large pivotal trials in diverse populations will be conducted for licensure. Activities in this PE may include completion of preclinical animal studies and small safety and effectiveness studies involving humans according to FDA and EPA requirements. Promising medical technologies that are not regulated by the FDA or EPA are modeled, prototyped, and tested in relevant environments. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced          PE 0603002A / Medical Advanced Technology Technology Development (ATD) Blast research and research into maturing field rations in this PE are fully coordinated with the United States Army Combat Capabilities Development Command Soldier Center. This coordination enables improved body armor design and rations for Soldiers. Additionally, the activities funded in this PE are externally peer reviewed and fully coordinated with all Services as well as other agencies through the Joint Technology Coordinating Groups of the Armed Services Biomedical Research Evaluation and Management (ASBREM) Community of Interest (COI). The ASBREM COI, formed under the authority of the Under Secretary of Defense for Research and Engineering, serves to facilitate coordination and prevent unnecessary duplication of effort within the Department of Defense's biomedical research and development community, as well as its associated enabling research areas. The cited research is consistent with the Under Secretary of Defense (Research and Engineering) Science and Technology (S&T) focus areas and the Army Modernization Strategy. The FY 2026 request was reduced by $0.059 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.01 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 23627000, 12373000, 6687000, NULL, NULL, 32, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, 9599000, 8860000, 17876000, 17876000, NULL, 17876000, 6708000, $$This Program Element (PE) matures and demonstrates advanced medical technologies including drugs, medical devices, and developing medical practices and procedures to effectively protect and improve the survivability of United States Forces across the entire spectrum of military operations. Successful completion of efforts relies on tri-Service coordination and cooperation. Promising medical technologies are refined and validated through extensive testing, which is conducted in compliance with Food and Drug Administration (FDA) regulations for human medical products, and Environmental Protection Agency (EPA) regulations for insect-control products that impact humans or the environment (e.g., repellents and insecticides). The FDA requires medical products to undergo extensive preclinical testing in animals and/or other models to obtain preliminary effectiveness and safety information before they can be tested in human clinical trials. Clinical trials are conducted stepwise: first to prove the product is safe in humans, second to demonstrate the desired effectiveness and optimal dosage (amount to be administered) in a small group human study, and third to demonstrate effectiveness in large, diverse human populations. Each successive phase includes larger numbers of human subjects and requires FDA cognizance prior to proceeding. Work conducted in this PE primarily focuses on late stages of technology maturation activities required to conduct safety and effectiveness clinical trials. Some high-risk technologies may require additional maturation with FDA guidance prior to initiating these clinical trials. Such things as proof of product stability and purity are necessary Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                   Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced              PE 0603002A / Medical Advanced Technology Technology Development (ATD) to meet FDA standards before entering later stages of testing and prior to transitioning into a formal acquisition program where large pivotal trials in diverse populations will be conducted for licensure. Activities in this PE may include completion of preclinical animal studies and small safety and effectiveness studies involving humans according to FDA and EPA requirements. Promising medical technologies that are not regulated by the FDA or EPA are modeled, prototyped, and tested in relevant environments. Blast research and research into maturing field rations in this PE are fully coordinated with the United States Army Combat Capabilities Development Command Soldier Center. This coordination enables improved body armor design and rations for Soldiers. Additionally, the activities funded in this PE are externally peer reviewed and fully coordinated with all Services as well as other agencies through the Joint Technology Coordinating Groups of the Armed Services Biomedical Research Evaluation and Management (ASBREM) Community of Interest (COI). The ASBREM COI, formed under the authority of the Under Secretary of War for Research and Engineering, serves to facilitate coordination and prevent unnecessary duplication of effort within the Department of War's biomedical research and development community, as well as its associated enabling research areas. The cited research is consistent with the Under Secretary of War (Research and Engineering) Science and Technology (S&T) focus areas and the Army Modernization Strategy.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603007A$$, $$Manpower, Personnel and Training Advanced Technology$$, $$rdte_army_ba3$$, $$dw_osd$$, 2026, 13559000, 15845000, 16716000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 11, "original_pe": "0603007A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) matures and validates applied behavioral and social science technologies that enhance the Soldier Lifecycle (e.g., selection, assignment, training, leader development) and human relations (e.g. unit cohesion). These technologies provide advanced personnel measures that more fully assess potential and predict performance, behavior, attitudes, and resilience. These technologies also provide innovative and effective Talent Management methods to optimize individual and team performance to ensure the Army can meet mission requirements in uncertain and complex environments. This PE evaluates new selection measures, assignment methods, and performance metrics for individuals and units, assesses innovative training methods, and conducts scientific assessments to inform Human Capital policy and programs. Work in this PE will result in effective non-materiel solutions to help the Army adjust to changes in force size and structure, a variety of mission demands and contexts, challenges in human relations, and budgetary constraints. Work in this PE complements and is fully coordinated with PE 0602785A (Manpower/Personnel/Training Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas, the Army Vision, the Army's Talent Management Strategy, and the Army Modernization Strategy Work in this PE is performed by the United States Army Research Institute (ARI) for the Behavioral and Social Sciences in Ft. Belvoir, VA. The FY 2026 request was reduced by $0.955 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.086 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                            Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced         PE 0603007A / Manpower, Personnel and Training Advanced Technology Technology Development (ATD)$$, NULL, 14887000, 14998000, 15211000, NULL, NULL, 33, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, 14693000, 13559000, 11113000, 11113000, NULL, 11113000, 15292000, $$This Program Element (PE) matures and validates applied behavioral and social science technologies that enhance the Soldier Lifecycle (e.g., selection, assignment, training, leader development) and human relations (e.g. unit cohesion). These technologies provide advanced personnel measures that more fully assess potential and predict performance, behavior, attitudes, and resilience. These technologies also provide innovative and effective Talent Management methods to optimize individual and team performance to ensure the Army can meet mission requirements in uncertain and complex environments. This PE evaluates new selection measures, assignment methods, and performance metrics for individuals and units, assesses innovative training methods, and conducts scientific assessments to inform Human Capital policy and programs. Work in this PE will result in effective non-materiel solutions to help the Army adjust to changes in force size and structure, a variety of mission demands and contexts, challenges in human relations, and budgetary constraints. Work in this PE complements and is fully coordinated with PE 0602785A (Manpower/Personnel/Training Technology). The cited work is consistent with the Under Secretary of War (Research and Engineering) priority focus areas, the Army Vision, the Army's Talent Management Strategy, and the Army Modernization Strategy Work in this PE is performed by the United States Army Research Institute (ARI) for the Behavioral and Social Sciences in Ft. Belvoir, VA.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603021D8Z$$, $$National Security Innovation Capital$$, $$rdte_dw_ba3$$, $$dw_osd$$, 2026, 15001000, 14643000, 572717000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 67, "original_pe": "0603021D8Z", "page_header": "Defense-Wide", "fy26_v182_disc_K": 0, "fy26_v182_supp_K": 15001, "fy26_v182_total_K": 15001, "fy26_v182_note_name": "0603021D8Z", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 6322}$$::jsonb, $$This program supports the Department's initiatives to Build Sustainable and Long-Term Advantage and Build a Resilient Joint Force Defense Ecosystem. This effort also supports Title 10 USC, Section 4811, requiring the Secretary of Defense to develop a national security strategy for the National Technology and Industrial Base (NTIB) that “reflects a prioritized assessment of the risks and challenges to the defense supply chain.” The mission of National Security Innovation Capital (NSIC) is to accelerate the development of dual-use hardware technologies critical to our national security and economic competitiveness. It is an initiative that enables dual-use hardware startups to advance key milestones in their product development by addressing the shortfall of private investment from trusted sources. NSIC's support enables companies to develop their technologies and products more rapidly. The resulting reductions in technical risk, along with the signaling of DoD interest in such dual-use companies, attracts trusted private investment that might otherwise sit on the sidelines. The overall result is more rapid and robust development of hardware in the U.S., the expansion of the defense industrial base and reduction of technology flow to adversaries. Areas of focus are autonomy, communications, power, sensors, and space.$$, NULL, NULL, NULL, NULL, NULL, NULL, 34, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 5843000, 15001000, NULL, NULL, NULL, NULL, NULL, $$This program supports the Department's initiatives to Build Sustainable and Long-Term Advantage and Build a Resilient Joint Force Defense Ecosystem. The FY 2026 spend plan amount for 0603021D8Z includes $0 of discretionary and $15,001 thousand of mandatory (reconciliation) for a total of $15,001 thousand.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603025A$$, $$Army Agile Innovation and Demonstration$$, $$rdte_army_ba3$$, $$devcom$$, 2026, 19679000, 25513000, 14608000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 11, "original_pe": "0603025A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) funds the Army's goal of accelerating innovative solutions to achieve future force modernization. The Army is using strategic and "non- traditional" partnerships and working with traditional vendors in novel ways to respond at the speed of innovation to accelerate the development of cutting-edge technology. Critical technologies that allow for technological superiority are increasingly dual-use or developed in academia-led partnerships that leverage cutting edge innovation. In an era of global competition, technological superiority requires agile and rapid innovation. Cross-cutting modernization initiatives leveraging strategic partnerships and foster an environment to bring knowledge and expertise to demonstrate breakthrough and innovative technologies that will benefit the warfighter. These collaborations bring new ways of doing business to demonstrate emerging technologies and systems with high payoff potential to address current technology shortfalls or future capability gaps and systems. Leveraging other innovative mechanisms, to include accelerators, incubators, and other technology accelerants, to enhance innovation is part of the overall innovation strategy. Innovation includes not only hardware, and physical products but also software, software development, artificial intelligence (AI) and machine learning, all as stand-alone initiatives and as part of broader innovation to programs and technology development. Senior leadership approves Innovation projects in the budget year and year of execution based on priority and opportunity, ensuring that innovations have a high potential for filling capability gaps and transitioning to Army acquisition to rapidly deliver capabilities to the Soldier through the Army's Innovation Oversight Board or Army Futures Command. Research in this PE is closely coordinated with PE 0602002A (Army Agile Innovation and Development-Applied Research) Work is performed by the United States Army Combat Capabilities Development Command (DEVCOM), Army Artificial Intelligence Integration Center (AI2C), Army Applications Laboratory (AAL), the Engineering Research and Development Center, Space and Missile Defense Technical Center, and the United States Army Research Institute for the Behavioral and Social Sciences. The FY 2026 request was reduced by $0.044 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced           PE 0603025A / Army Agile Innovation and Demonstration Technology Development (ATD)$$, NULL, 4125000, 4566000, 4887000, NULL, NULL, 34, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, 14075000, 44150000, 3325000, 3325000, NULL, 3325000, 5132000, $$This PE funds the Army's goal of accelerating innovative solutions to achieve future force modernization. The Army is using strategic and "non-traditional" partnerships and working with traditional vendors in novel ways to respond at the speed of innovation to accelerate the development of cutting-edge technology. Critical technologies that allow for technological superiority are increasingly dual-use or developed in academia-led partnerships that leverage cutting edge innovation. In an era of global competition, technological superiority requires agile and rapid innovation. Cross-cutting modernization initiatives leveraging strategic partnerships and foster an environment to bring knowledge and expertise to demonstrate breakthrough and innovative technologies that will benefit the warfighter. These collaborations bring new ways of doing business to demonstrate emerging technologies and systems with high payoff potential to address current technology shortfalls or future capability gaps and systems. Leveraging other innovative mechanisms, to include accelerators, incubators, and other technology accelerants, to enhance innovation is part of the overall innovation strategy. Innovation includes not only hardware, and physical products but also software, software development, artificial intelligence (AI) and machine learning, all as stand-alone initiatives and as part of broader innovation to programs and technology development. Senior leadership approves Innovation projects in the budget year and year of execution based on priority and opportunity, ensuring that innovations have a high potential for filling capability gaps and transitioning to Army acquisition to rapidly deliver capabilities to the Soldier through the Army's Innovation Oversight Board or Army Futures Command. Research in this PE is closely coordinated with PE 0602002A (Army Agile Innovation and Development-Applied Research). Work is performed by the U.S. Army Combat Capabilities Development Command (DEVCOM), Army Artificial Intelligence Integration Center (AI2C), Army Applications Laboratory (AAL), the Engineering Research and Development Center, Space and Missile Defense Technical Center, and the U.S. Army Research Institute for the Behavioral and Social Sciences. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced          PE 0603025A / Army Agile Innovation and Demonstration Technology Development (ATD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603032F$$, $$Future AF Integrated Technology Demos$$, $$rdte_af_ba3$$, $$afrl$$, 2026, 268754000, 154013000, 161336000, NULL, $${"ba_raw": "6.3", "source": "af_r1_fy26", "original_pe": "0603032F"}$$::jsonb, $$This Program is a concentrated effort to evolve Air Force Research Laboratory (AFRL) business practices to accelerate transition of emerging technologies into the hands of the warfighter. Vanguard programs draw the operational, acquisition, and technology communities together into coherent teams to solve hard Science & Technology (S&T) problems based on Department of the Air Force (DAF) strategic priorities which do not have readily available emerging technology solutions. Teams follow a disciplined process to accelerate efforts as deemed necessary by the department. This process (known as WARTECH, for WARfighter / TECHnologist) utilizes discrete progress gates to deliver S&T efforts organized as Vanguard Pathfinders, Vanguard Prospects, and Vanguards. This construct organizes these multi- disciplinary, capability-focused investments based on characteristics such as effort maturity, established military utility, technical viability and transitionability. Each progress gate has built-in off-ramps to promote transition. The process is overseen by an Executive Committee, whose membership includes the DAF Technical Leadership, operational requirements representatives, and acquisitions communities. Vanguard Pathfinders are focused thrust areas which comprise numerous exploratory efforts intended to establish military utility and technical viability of concepts under exploration. Extensive socialization occurs within these efforts to inform activities inherent to these emerging investment areas. Concept socialization activities include but are not limited to the codification of the operational champion, planning engagements with other government R&D, exploratory outreach to industry and other non- traditional partners, and the initial identification of potential transition partners. These investments seek to identify and integrate emerging applied research efforts from government labs and/or industry into integrated technology demonstrations. Vanguard pathfinder teams seek to bring appropriate communities together to answer the question "are we solving the right problem” while establishing technical viability of the concepts under consideration. This phase can be accelerated or bypassed for efforts with well understood operational requirements and concepts with established technical viability. Pathfinders serve as the pipeline for DAF's future Vanguards Prospects and Vanguards. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603032F / Future AF Integrated Technology Demos Technology Development (ATD) Vanguard Prospects focus on maturing contributing technologies in accordance with the technical objectives of the effort while further engaging acquisitions communities and industry partners. Teams draw in technologies from multiple sources and ensure use of the right technologies. By establishing fielding strategies, teams solve the problem in a transitionable way. Vanguard Prospects provide focused S&T investment to accelerate the maturation of contributing technologies while laying the foundation for the effort to achieve full Vanguard status or transition into a Program of record. Vanguards build on the foundational work of the earlier stages, maturing and integrating contributing technologies to demonstrate solutions to the department's most pressing S&T problems based on DAF strategic requirements. Vanguard Programs - high risk by design - are focused, Secretary of the Air Force-priority initiatives with enterprise commitment. They are commissioned by the Assistant Secretary of the Air Force for Acquisition, Technology and Logistics, the Vice Chief of Staff of the Air Force, and the Vice Chief of Space Operations as DAF investments. This program element may include necessary civilian pay expenses required to manage, execute, and deliver science & technology capabilities. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. The FY 2026 request was reduced by $0.487 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment.$$, NULL, 296683000, 317885000, 318776000, NULL, NULL, 16, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 150643000, 255570000, 282004000, 282004000, 0, 282004000, 320226000, $$This Program is a concentrated effort to accelerate transition of emerging technologies into the hands of the warfighter. Vanguard programs draw the operational, acquisition, and technology communities together into coherent teams to solve hard Science & Technology (S&T) problems based on Department of the Air Force (DAF) strategic priorities which do not have readily available emerging technology solutions. Teams follow a disciplined process to accelerate efforts as deemed necessary by the department. This process (known as WARTECH, for WARfighter / TECHnologist) utilizes discrete progress gates to deliver S&T efforts organized as Vanguard Pathfinders, Vanguard Prospects, and Vanguards. This construct organizes these multi- disciplinary, capability-focused investments based on characteristics such as effort maturity, established military utility, technical viability and transitionability. Each progress gate has built-in off-ramps to promote transition. The process is overseen by DAF TEO with support garnered throughout from the DAF general officer community that represent authority, accountability, and responsibility in the specific technology areas. Vanguard Pathfinders are focused effort areas which comprise numerous exploratory activities intended to establish military utility and technical viability of concepts under exploration. Extensive socialization occurs within these efforts to inform activities inherent to these emerging investment areas. Concept socialization activities include but are not limited to the codification of the operational champion, planning engagements with other government R&D, exploratory outreach to industry and other non- traditional partners, and the initial identification of potential transition partners. These investments seek to identify and integrate emerging applied research efforts from government labs and/or industry into integrated technology demonstrations. Vanguard pathfinder teams seek to bring appropriate communities together to answer the question "are we solving the right problem” while establishing technical viability of the concepts under consideration. This phase can be accelerated or bypassed for efforts with well understood operational requirements and concepts with established technical viability. Pathfinders serve as the pipeline for DAF's future Vanguards Prospects and Vanguards. Vanguard Prospects focus on maturing contributing technologies in accordance with the technical objectives of the effort while further engaging acquisitions communities and industry partners. Teams draw in technologies from multiple sources and ensure use of the right technologies. By establishing fielding strategies, teams solve the problem in a transitionable way. Vanguard Prospects provide focused S&T investment to accelerate the maturation of contributing technologies while laying the foundation for the effort to achieve full Vanguard status or transition into a Program of record. Vanguards build on the foundational work of the earlier stages, maturing and integrating contributing technologies to demonstrate solutions to the department's most pressing S&T problems based on DAF strategic requirements. Vanguard Programs - high risk by design - are focused, Secretary of the Air Force-priority initiatives with enterprise commitment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603032F / Future AF Integrated Technology Demos Technology Development (ATD) This program is accomplished by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. Funds in this PE may be used to investigate specified technology advancements in air, space and/or cyber domains. In order to manage, execute, and deliver science and technology capabilities, this program element may include: necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. R-1 Line Item 15, received a Congressional add for FY2026 $5.000 million for Adversarial systems exploitation lab. Upon Congressional spend plan approval, an Internal Reprogramming (IR) will be processed aligning the funding to PE 0603788F for proper execution. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603040A$$, $$Artificial Intelligence and Machine Learning Advanced Technologies$$, $$rdte_army_ba3$$, $$dw_cdao$$, 2026, 20487000, 23909000, 30263000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 12, "original_pe": "0603040A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) will mature and demonstrate advanced technologies using artificial intelligence (AI) and machine learning (ML) to improve target recognition/ detection using multiple cooperative autonomous sensors, leader decision-making, and replication of tactical behaviors to enable autonomous capabilities for maneuver, predictive maintenance, talent management, Intel support for Operations, network and cybersecurity and medical support. The Army's Artificial Intelligence Integration Center (AI2C) will provide strategic guidance and coordination of these advanced research efforts in AI/ML across the Army Modernization enterprise. Research in this PE contributes to the Army Science and Technology (S&T) portfolio and is fully coordinated with efforts in PE 0601601A (Artificial Intelligence and Machine Learning Basic Research) and PE 0602180A (Artificial Intelligence and Machine Learning Technologies). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced          PE 0603040A / Artificial Intelligence and Machine Learning Advanced Technologies Technology Development (ATD) The cited research is consistent with the Under Secretary of Defense for Research and Engineering S&T focus areas, the Army Modernization Strategy and the Chief Digital and Artificial Intelligence Office (CDAO).$$, NULL, NULL, NULL, NULL, NULL, NULL, 35, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, 25025000, 37487000, NULL, NULL, NULL, NULL, NULL, $$This PE will mature and demonstrate advanced technologies using artificial intelligence (AI) and machine learning (ML) to improve target recognition/detection using multiple cooperative autonomous sensors, leader decision-making, and replication of tactical behaviors to enable autonomous capabilities for maneuver, predictive maintenance, talent management, Intel support for Operations, network and cybersecurity and medical support. The Army's Artificial Intelligence Integration Center (AI2C) will provide strategic guidance and coordination of these advanced research efforts in AI/ML across the Army Modernization enterprise. Research in this PE contributes to the Army Science and Technology (S&T) portfolio and is fully coordinated with efforts in PE 0601601A (Artificial Intelligence and Machine Learning Basic Research) and PE 0602180A (Artificial Intelligence and Machine Learning Technologies). The cited research is consistent with the Under Secretary of War (Research and Engineering) S&T focus areas, the Army Modernization Strategy and the Chief Digital and Artificial Intelligence Office (CDAO). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced         PE 0603040A / Artificial Intelligence and Machine Learning Advanced Technologies Technology Development (ATD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603041A$$, $$All Domain Convergence Advanced Technology$$, $$rdte_army_ba3$$, $$cft_fvl$$, 2026, 10560000, 26721000, 23722000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 12, "original_pe": "0603041A", "page_header": "Department of the Army"}$$::jsonb, $$The Program Element (PE) develops, matures, and demonstrates as part of a campaign of learning, technologies in an operational environment, learning from early failure and re-scope research to improve speed of response, scalability, interoperability and range of engagement. This PE will deliver technologies that will enable sensor to shooter applications, from tactical to strategic level, taking a system design approach in support of Army experimentation events and Department of Defense (DoD) Combined Joint All-Domain Command and Control (CJADC2). The research will enable optimal lethal and non-lethal effects across all domains using artificial intelligence and machine learning to improve how we recognize threats, augment and enhance leader decision-making, and replicate tactical behaviors to enable autonomous capabilities. Work in this PE complements PE 0603465A (Future Vertical Lift Advanced Technology), PE 0603462A (Next Generation Combat Vehicle Advanced Technology), and PE 0603463 (Network C3I Advanced Technology). The cited research is consistent with the Under Secretary of Defense for Research and Engineering Priority focus areas. The FY 2026 request was reduced by $0.039 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                       Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced      PE 0603041A / All Domain Convergence Advanced Technology Technology Development (ATD)$$, NULL, 4170000, 4480000, 4651000, NULL, NULL, 36, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, 23183000, 10560000, 3575000, 3575000, NULL, 3575000, 4654000, $$The PE develops, matures, and demonstrates as part of a campaign of learning, technologies in an operational environment, learning from early failure and re-scope research to improve speed of response, scalability, interoperability and range of engagement. This PE will deliver technologies that will enable sensor to shooter applications, from tactical to strategic level, taking a system design approach in support of Army experimentation events and DoW Combined Joint All-Domain Command and Control (CJADC2). The research will enable optimal lethal and non-lethal effects across all domains using artificial intelligence and machine learning to improve how we recognize threats, augment and enhance leader decision-making, and replicate tactical behaviors to enable autonomous capabilities. Work in this PE complements PE 0603465A (Future Vertical Lift Advanced Technology), PE 0603462A (Next Generation Combat Vehicle Advanced Technology), and PE 0603463 (Network C3I Advanced Technology). The cited research is consistent with the Under Secretary of War (Research and Engineering) Priority focus areas.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603042A$$, $$C3I Advanced Technology$$, $$rdte_army_ba3$$, $$dw_osd$$, 2026, 15028000, 18590000, 21889000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 12, "original_pe": "0603042A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) matures, demonstrates, optimizes, and validates Network Command, Control, Communications, and Intelligence (C3I) technologies through the integration of future equipment and systems that improve overmatch and meet mission needs in the future operating environments. This PE provides mid-to-long term tactical C3I capabilities (e.g. networking, cyber, electronic warfare, Positioning, Navigation, and Timing (PNT), space, persistent surveillance) based upon promising technologies that address emerging and future threats, and includes research critical and unique to the Army and DoD. Efforts focus on advanced maturation and demonstration of materials, technologies, methodologies and systems that span the range from electronics, protective technologies, electronic warfare, and mission Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                 Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced             PE 0603042A / C3I Advanced Technology Technology Development (ATD) support capabilities such as situational awareness. These efforts directly inform and transition key capabilities to Army programs of record that support the Army modernization priorities. The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. The FY 2026 request was reduced by $0.471 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.038 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 1248000, 1258000, 1273000, NULL, NULL, 37, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, 19860000, 26228000, 1211000, 1211000, NULL, 1211000, 1286000, $$This PE matures, demonstrates, optimizes, and validates Network Command, Control, Communications, and Intelligence (C3I) technologies through the integration of future equipment and systems that improve overmatch and meet mission needs in the future operating environments. This PE provides mid-to-long term tactical C3I capabilities (e.g. networking, cyber, electronic warfare, Positioning, Navigation, and Timing (PNT), space, persistent surveillance) based upon promising technologies that address emerging and future threats, and includes research critical and unique to the Army and DoW. Efforts focus on advanced maturation and demonstration of materials, technologies, methodologies and systems that span the range from electronics, protective technologies, electronic warfare, and mission support capabilities such as situational awareness. These efforts directly inform and transition key capabilities to Army programs of record that support the Army modernization priorities. The cited research is consistent with the Under Secretary of War (Research and Engineering) priority focus areas and the Army Modernization Strategy. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced          PE 0603042A / C3I Advanced Technology Technology Development (ATD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603044A$$, $$Soldier Advanced Technology$$, $$rdte_army_ba3$$, $$dw_osd$$, 2026, 18143000, 1170000, 14094000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 12, "original_pe": "0603044A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) matures, optimizes, and validates applied research technologies to demonstrate improved capabilities and systems that advance Soldier and Squad lethality-overmatch and Soldier performance beyond those technologies planned within the Soldier Lethality Cross-Functional Team. Advanced technology research efforts focus on the maturation and integration of broad capabilities and systems that span a range of technical areas to address enduring Soldier needs. These efforts transition outputs to existing and emerging systems in support of continuing enhancement of Soldier capabilities. This PE will fund civilian salaries for in- house researchers/scientists and program managers collaborating with external subject matter experts in academia and industry who are leaders in these technology research areas. The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                       Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced       PE 0603044A / Soldier Advanced Technology Technology Development (ATD)$$, NULL, 1016000, NULL, NULL, NULL, NULL, 39, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, 13580000, 10807000, 3951000, 3951000, NULL, 3951000, NULL, $$This PE matures, optimizes, and validates applied research technologies to demonstrate improved capabilities and systems that advance soldier and squad lethality- overmatch and soldier performance beyond those technologies planned within the Soldier Lethality Cross-Functional Team. Advanced technology research efforts focus on the maturation and integration of broad capabilities and systems that span a range of technical areas to address enduring Soldier needs. These efforts transition outputs to existing and emerging systems in support of continuing enhancement of soldier capabilities. This PE will fund civilian salaries for in-house researchers/ scientists and program managers collaborating with external subject matter experts in academia and industry who are leaders in these technology research areas. The cited research is consistent with the Under Secretary of War (Research and Engineering) priority focus areas and the Army Modernization Strategy. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced          PE 0603044A / Soldier Advanced Technology Technology Development (ATD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603055D8Z$$, $$Operational Energy Capability Improvement$$, $$rdte_dw_ba3$$, $$dw_osd$$, 2026, 168253000, 0, 0, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 68, "fy27_mand_k": 93888, "original_pe": "0603055D8Z", "page_header": "Defense-Wide", "fy27_mand_v157": "2026-05-08", "fy26_v182_disc_K": 216497, "fy26_v182_supp_K": 82000, "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy26_v182_total_K": 298497, "fy27_mand_section": "Defense Industrial Base", "fy26_v182_note_name": "Operational Energy Capability Improvement (PE 0603055D8Z)", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 6587}$$::jsonb, $$The mission of this program element (PE) is to fund innovation to improve the Department of Defense’s (DOD) operational effectiveness via targeted operational energy science and technology (S&T) investments. The Operational Energy Capability Improvement Fund (OECIF) incentivizes S&T to promote long term change in DOD capabilities, so they are better aligned with the DOD's and National Strategy. OECIF fosters Joint, not Service specific, innovation that improves operational energy performance and has two key mission aspects: first, to develop operational energy technologies and practices that improve DOD military capabilities and possibly reduce costs; and second, to establish within and among the military Services institutional momentum to transition those innovations. OECIF funds serve as “seed money” to start or consolidate promising first-of-a-kind operational energy innovation. OECIF investments also lead in areas of Departmental level interest. The overall aim is to improve the operational effectiveness of the Joint Force. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                     Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:              PE 0603055D8Z / Operational Energy Capability Improvement Advanced Technology Development (ATD) OECI powers this future by investing in early-stage energy innovation for military capabilities, incentivizing the Components to achieve energy superiority for U.S. Joint Forces and missions. The OECI program accelerates the transition of pre-commercial, military-unique technologies, promoting rapid fielding to warfighters. OECI is innovating today for energy superiority tomorrow, delivering unmatched value to the DOD warfighter by: • Boosting lethality and supportability • Enhancing operational readiness and responsiveness • Extending operational capabilities and endurance for advanced platforms and weapons OECI's technical thrust areas are: • Operational Energy Dominance: Providing energy capability and battlespace awareness technologies to collect, camouflage, and control power and energy data. These investments leverage AI and machine learning to integrate U.S., allied, and adversary energy information into the combined joint all-domain command and control (CJADC2) architecture. • Operational Energy Surety: Ensuring U.S. forces, capabilities, and missions assured, robust, and resilient access to energy, including powering energy magazines (missile defense, Golden Dome, and counter-UAS) and data centers in the homeland and abroad. Technical areas include fuel fabrication processes, energy conversion, novel power generation, and energy storage and distribution technologies. • Operational Energy and Power Projection: Giving U.S. forces operational flexibility, freedom to operate at will, and a qualitative edge in all domains (including space and cyber), through implementation of advanced energy technologies. Investments include novel platform structures and power plant solutions for extended duration and enabling and enhancing maneuver without regret (including next-generation power and energy delivery (power beaming)). • Nuclear Innovation: Developing power and energy solutions for the battlespace including assured power for critical missions at home, underway, and abroad. Nuclear innovations do not overlap efforts covered by the Chief of Naval Reactors (CNR) but are broadly applicable in all domains from sub-sea to space. The OECI program demonstrates its commitment to innovation by maturing first-of-their-kind advanced OE technologies across warfighting platforms and domains. OECI's competitive execution approach, which funds DOD laboratories, not only strengthens technical depth within the DOD and secures government purpose rights but also drives down acquisition costs and fosters academic and initial industry engagement. Furthermore, it expedites technology development and capability delivery to warfighters through the implementation of other transaction and rapid acquisition authorities. Current/ongoing OECI investments focus on providing agile OE solutions that address insights from current operations. Technical advancements include: • Advanced Algorithms & Analytics: Developing AI/ML algorithms for anomaly detection, predictive power analysis, energy optimization, and pattern-of-life analysis • Joint All Domain Command and Control (JADC2) Integration: Developing data models, user interfaces, and communication protocols to integrate OE assets and data into the JADC2 architecture • Power Electronics & Microgrids: Designing high-efficiency power converters, inverters, and microgrid controllers for tactical applications, with a focus on vehicle-centric microgrids and integration with Joint and Coalition energy sources • Energy Storage & Generation: Developing advanced battery chemistries (Li-ion, Lithium Sulfur, Americium), fuel cells (hydrogen), and waste-to-energy systems for mobile and expeditionary power • Wireless Power Transfer Technologies: Advancing RF, mm-Wave and laser power beaming systems, including rectenna design, beam steering, and integration with UAVs and other platforms Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                       Date: June 2025 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:                PE 0603055D8Z / Operational Energy Capability Improvement Advanced Technology Development (ATD) • Space-Based Solar Power: Developing low-cost, high-efficiency solar cells and arrays for space applications, including perovskite and III-V materials • Nuclear Reactor Technology: Developing small modular reactors (SMRs), TRISO fuel, and advanced shielding materials for both space and terrestrial applications • Fuel Efficiency & Hybridization: Developing hybrid-electric architectures for tactical vehicles, aircraft, and naval vessels to improve fuel efficiency and enable new capabilities Looking ahead to FY 2026 and beyond, the President’s mission to the DOD is clear: achieve peace through strength and remain the World’s greatest military. Fulfilling this mission, the DOD prioritizes investments that revive the warrior ethos, rebuild the military, and reestablish deterrence. Aligning with these priorities, OECI investments focus on technology advancements that increase OE Readiness: • Power and Energy Sensing for Command and Control: Investments providing Red, Green, and Blue (abroad) information for warfighter decision making and increased battlespace awareness and impact • Nuclear Power – Focused investments advancing resilient, long-lived, and low-profile spaceflight radioisotope power system (RPS) technologies available for national security needs • DE Weapon Advancement: Prototyping of first of kind power and thermal hardened system solutions, suitable for transport and utilization in varied locations, including populated, austere, and arctic conditions • UxV Advancements: Innovating power and energy solutions enabling advanced maneuver, extended reach, and increased endurance for UxV’s across warfighting domains • Space Superiority – Advancing space maneuver and survivability through focused investment in energy generation, storage, refueling distribution, transmission, and data analytics • Energy Surety – Secure power advancements, increasing energy efficiency, and developing isolated power and energy solutions at operational installations (and data centers) - enabling critical missions at home and abroad The OECI program has a long history of successfully transitioning emerging OE capabilities (greater than 80%). As the department rebuilds the military, OECI continues accelerating technology development for critical OE capabilities required for defense of the homeland and deterring Chinese aggression in the Indo-Pacific theater. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                           Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:         PE 0603055D8Z / Operational Energy Capability Improvement Advanced Technology Development (ATD)$$, NULL, 168206000, 171320000, 175047000, NULL, NULL, 35, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, NULL, 298497000, 165060000, 165060000, 93888000, 258948000, 178624000, $$The Operational Energy Capability Improvement program funds innovation that improves the DoW’s operational effectiveness via targeted operational energy (OE) science and technology (S&T) investments. The Operational Energy Capability Improvement Fund (OECIF) incentivizes S&T that promotes long term change in DoW capabilities, so they are better aligned with the National Defense Strategy. OECIF fosters Joint, not Service specific, innovation that improves operational energy performance and has two key mission aspects: first, to develop operational energy technologies and practices that improve DoW military capabilities and possibly reduce costs; and second, to establish within and among the military Services institutional momentum to transition those innovations. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                   Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:              PE 0603055D8Z / Operational Energy Capability Improvement Advanced Technology Development (ATD) OECIF funds serve as “seed money” to start or consolidate promising first-of-a-kind operational energy innovation. OECIF investments also lead in areas of Departmental level interest. The overall goal is to improve the operational effectiveness of the Joint Force. OECIF powers this future by investing in early-stage (pre-commercial) energy innovation for military capabilities, incentivizing the Components to achieve energy superiority for U.S. Joint Forces and missions. The OECI program accelerates the transition of pre-commercial, military-unique technologies, promoting rapid fielding to warfighters. OECI is innovating today for energy superiority tomorrow, delivering unmatched value to the DoW warfighter by: • Boosting lethality and supportability • Enhancing operational readiness and responsiveness • Extending operational capabilities and endurance for advanced platforms and weapons OECIF prioritizes technology development for multiple-Service use-cases, deconflicts across Service investments reducing duplication, and increases auditability of funding both within the program and community-wide from 6.2 through warfighter transition. OECIF maintains and advances use of accountability tools and process development. OECI's technical thrust areas are: • Operational Energy Dominance: Providing energy capability and battlespace awareness technologies for collecting, camouflaging, and controlling power and energy data. These investments leverage Artificial Intelligence and machine learning (AI/ML) for integrating U.S., allied, and adversary energy information into the combined joint all-domain command and control (CJADC2) architecture. Additional information is available in a classified addendum for this budget exhibit. Dominance supports solutions to power and energy vulnerabilities and threat reduction at home and abroad. • Advanced Operational Energy Mobility: Accelerating Joint Force freedom of maneuver by transforming assured energy access into operational reach, tempo, and sustained movement across contested, austere, and denied environments. Investments prioritize next generation propulsion for crewed/uncrewed platforms, power and energy mission planning / in-route visibility, integrating energy technologies across domains, platforms and electrical grids, and operationalizing energy for high-powered applications (Golden Dome), producing energy at the tactical edge, and enabling energy prepositioning and storage. • Operational Energy and Power Projection: Giving U.S. forces operational flexibility, freedom to operate at will, and a qualitative edge in all domains (including air, space, and cyber), through implementation of advanced energy technologies. Investments enable and enhance Space maneuver without regret (including next- generation power and energy delivery/resupply), terrestrial and space wireless power transfer, and counter-unmanned aerial system capabilities. • Nuclear Innovation: Developing power and energy solutions for the battlespace including assured power for critical missions at home, underway, and abroad. Nuclear innovations do not overlap efforts covered by the Chief of Naval Reactors (CNR) but are broadly applicable in all domains from sub-sea to space. The OECIF program demonstrates its commitment to innovation by maturing first-of-their-kind advanced OE technologies across warfighting platforms and domains. OECIF's competitive execution approach, which funds DoW and defense-related DOE laboratories, not only strengthens technical depth within the DoW and secures government purpose rights but also drives down acquisition costs and fosters academic and initial industry engagement. Furthermore, it expedites technology development and capability delivery to warfighters through the implementation of other transaction and rapid acquisition authorities. Current/ongoing OECI investments (initiated under PE 0604055D8Z) focus on providing agile OE solutions that address insights from current operations. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                      Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:               PE 0603055D8Z / Operational Energy Capability Improvement Advanced Technology Development (ATD) Technical advancements include: • Advanced Algorithms & Analytics: Developing AI/ML algorithms for anomaly detection, predictive power analysis, energy optimization, and pattern-of-life analysis • Joint All-Domain Command and Control (JADC2) Integration: Developing data models, user interfaces, and communication protocols to integrate and visualize OE assets and data into the JADC2 architecture • Power Electronics & Microgrids: Designing high-efficiency power converters, inverters, and microgrid controllers for tactical applications, with a focus on vehicle-centric microgrids and integration with Joint and Coalition energy sources • Energy Storage & Generation: Developing advanced battery chemistries (Li-ion, Lithium Sulfur, fuel cells (hydrogen)), and waste-to-energy systems for mobile and expeditionary power • Wireless Power Transfer Technologies: Advancing RF, mm-Wave and laser power beaming systems, including rectenna design, beam steering, and integration with UAVs and other platforms • Space-Based Solar Power: Space assembly, mobility, and logistics (including refueling); maneuver without regret; and wireless power transfer • Nuclear Reactor Technology: Developing small modular reactors (SMRs), TRISO fuel, and advanced reactor materials for both space and terrestrial applications • Increasing Range and Survivability: Developing longer-range architectures for tactical vehicles, aircraft, and naval vessels, enabling new mission sets The President’s mission to the DoW is clear: achieve peace through strength and remain the World’s greatest military. Advancing this mission, FY 2026 OECIF investments focus on those technology advancements required to increase OE Readiness. Investment priorities include: 1) OE-Informed Planning and Decision Making; 2) Readiness to Fight in Emerging Battlefields; 3) Next-Generation Platforms and Weapons Systems; 4) OE and Installation Energy Convergence with a focus on Homeland Defense; and 5) Focused investments advancing resilient, long-lived, and low-profile spaceflight radioisotope power system (RPS) technologies available for national security needs. FY 2027 OECI investments focus on technologies that enhance the operational effectiveness of the DoW and its allies specifically within the context of deterring aggression in the Indo-Pacific region and bolstering homeland defense. The program recognizes that energy security is a critical component of both forward-deployed forces and continental U.S. operations, and that investments in distributed, resilient, and efficient energy solutions are essential for maintaining military readiness, being resilient in contested environments, and projecting power in key strategic theaters. Specific investment priorities include: • Energy Sensing and Characterization – Critical infrastructure protection and exploitation (Bison Herd expansion) • Radioisotope Power Systems (RPS) and Nuclear Supply Chain innovations – advanced reactor acceleration • In-transit fuel/power visibility and mission planning – solutions that optimize, communicate, and operationalize energy data across the mobility enterprise • Space-based refueling and robotics – dynamic, serviceable architecture, ensuring ability to resupply, refuel, augment, and defend critical space assets • Classified efforts – technology fusion and integration efforts acceleration energy solutions for SOF requirements Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                               Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:           PE 0603055D8Z / Operational Energy Capability Improvement Advanced Technology Development (ATD) The OECI program has a long history of successfully transitioning emerging OE capabilities (greater than 80%). As the department rebuilds the military, OECI continues accelerating technology development for critical OE capabilities required for defense of the homeland and deterring Chinese aggression in the Indo-Pacific theater. The FY 2027 request for PE 0603055D8Z includes $165,060 thousand of discretionary and $93,888 thousand of mandatory for a total of $258,948 thousand. The mandatory funds advance Golden Dome and High-Power Energy Requirements - Integrating directed energy component technologies into platforms and weapons systems, conducting power conditioning, increasing the domestic supply chain in support of advanced propulsion and energy storage of air platforms (including one-way kinetic effects), and advancing coupled thermal energy storage and advanced power controls for high-power applications. The FY 2027 mandatory funds are different from the FY 2026 mandatory funds that 1) Advance aviation and space propulsion and space to ground power beaming – delivering reliable power to warfighters and using a robotic assembly demonstrating scalability for a variety of national security applications ($60,000) and 2) Expand Joint All-Domain Command and Control (JADC2) Power and Energy Sensor Enabled Effects – protecting high-valued assets and personnel in contested regions and equipping Commanders with a deep- magazine of effects that dominate the energy battlespace ($22,000). The FY 2026 spend plan amount for Operational Energy Capability Improvement (PE 0603055D8Z) includes $216,497 thousand of discretionary and $82,000 thousand of mandatory (reconciliation) for a total of $298,497 thousand.$$, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603112F$$, $$Advanced Materials for Weapon Systems$$, $$rdte_af_ba3$$, $$afrl_rx$$, 2026, 31021000, 55005000, 32161000, NULL, $${"ba_raw": "6.3", "source": "af_r1_fy26", "original_pe": "0603112F"}$$::jsonb, $$The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This program develops and demonstrates advanced materials and process technologies to satisfy Department of the Air Force requirements in areas such as survivability, readiness, affordability, and new processes and materials. These projects ensure the Department of the Air Force weapon systems are ready and able when needed. Funds in this PE may be used to investigate specified technology advancements in air, space and/or cyber domains. In order to manage, execute, and deliver science and technology capabilities, this program element may include: necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603112F / Advanced Materials for Weapon Systems Technology Development (ATD)$$, NULL, 32059000, 35611000, 36331000, NULL, NULL, 17, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 30035000, 45202000, 32808000, 32808000, 0, 32808000, 37067000, $$This program develops and demonstrates advanced materials and process technologies to satisfy Department of the Air Force requirements in areas such as survivability, readiness, affordability, and new processes and materials. These projects ensure the Department of the Air Force weapon systems are ready and able when needed. This program is accomplished by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. Funds in this PE may be used to investigate specified technology advancements in air, space, and/or cyber domains. In order to manage, execute, and deliver science and technology capabilities, this program element may include: necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, etc. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603112F / Advanced Materials for Weapon Systems Technology Development (ATD) This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603116A$$, $$Lethality Advanced Technology$$, $$rdte_army_ba3$$, $$cft_ngcv$$, 2026, 13232000, 70529000, 49629000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 12, "original_pe": "0603116A", "page_header": "Department of the Army"}$$::jsonb, $$Work done in this Program Element (PE) matures technologies, methodologies, and models required to enable next generation lethality. The PE focuses on: lethal mechanism technologies for projectiles and warheads that provide revolutionary capability to defeat Tier 1 adversary vehicle and body armors; selection of propulsion and energetic materials and technology to validate novel energetic materials concepts to exploit controllable energy release for future gun/missile systems; scalable effects for mixed target defeat while simultaneously decreasing warhead mass; experimentation of materials solutions for improvement of weight and volume efficiency, lethal effects and sustainability for the warfighter in the Army of today and beyond; and multiple pathways to enhance lethal effects by investigating synergistic effects of novel micro warheads using advanced materials. This PE continues to mature and demonstrate technology developed under PE 0602141A (Lethality Technology). Work in this PE complements PE 0603118A (Soldier Lethality Advanced Technology), PE 0603462A (Next Generation Combat Vehicle Advanced Technology), PE 0603464A (Long Range Precision Fires Advanced Technology), 0603465A (Future Vertical Lift Advanced Technology), and 0603466A (Air and Missile Defense Advanced Technology). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced        PE 0603116A / Lethality Advanced Technology Technology Development (ATD) Research in this PE is performed by University Technologies Development Division (UTDD), GeoTechnical Instructors Laboratory, Armaments Center, Space and Missile Defense Technical Center and Command, Control, Communication, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center. The FY 2026 request was reduced by $0.031 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.077 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 34073000, 33941000, 26928000, NULL, NULL, 40, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, 53785000, 51232000, 31812000, 31812000, NULL, 31812000, 21466000, $$Work done in this Program Element (PE) matures technologies, methodologies, and models required to enable next generation lethality. The PE focuses on: lethal mechanism technologies for projectiles and warheads that provide revolutionary capability to defeat Tier 1 adversary vehicle and body armors; selection of propulsion and energetic materials and technology to validate novel energetic materials concepts to exploit controllable energy release for future gun/missile systems; scalable effects for mixed target defeat while simultaneously decreasing warhead mass; experimentation of materials solutions for improvement of weight and volume efficiency, lethal effects and sustainability for the warfighter in the Army of today and beyond; and multiple pathways to enhance lethal effects by investigating synergistic effects of novel micro warheads using advanced materials. This PE continues to mature and demonstrate technology developed under PE 0602141A (Lethality Technology). Work in this PE complements PE 0603118A (Soldier Lethality Advanced Technology), PE 0603462A (Next Generation Combat Vehicle Advanced Technology), PE 0603464A (Long Range Precision Fires Advanced Technology), 0603465A (Future Vertical Lift Advanced Technology), and 0603466A (Air and Missile Defense Advanced Technology). The cited research is consistent with the Under Secretary of War for Research and Engineering priority focus areas and the Army Modernization Strategy. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced        PE 0603116A / Lethality Advanced Technology Technology Development (ATD) Research in this PE is performed by University Technologies Development Division (UTDD), GeoTechnical Instructors Laboratory, Armaments Center, Space and Missile Defense Technical Center and Command, Control, Communication, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603117A$$, $$Army Advanced Technology Development$$, $$rdte_army_ba3$$, $$devcom$$, 2026, 0, 140980000, 0, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 12, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0603117A", "page_header": "Department of the Army"}$$::jsonb, $$The Army Advanced Technology Development budget line includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Efforts develop proof of technological feasibility and assessment of subsystem and component operability that may lead to full system development and prototyping.$$, NULL, NULL, NULL, NULL, NULL, NULL, 41, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, NULL, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603119A$$, $$Ground Advanced Technology$$, $$rdte_army_ba3$$, $$afc$$, 2026, 30507000, 276299000, 87775000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 12, "original_pe": "0603119A", "page_header": "Department of the Army", "fy26_v182_disc_K": 187007, "fy26_v182_supp_K": 1500, "fy26_v182_total_K": 188507, "fy26_v182_note_name": "Ground Advanced Technology", "fy26_v182_source_file": "RDTE - Vol 1 - Budget Activity 3.txt", "fy26_v182_source_line": 5991}$$::jsonb, $$This Program Element (PE) matures and demonstrates ground movement and maneuver technologies that support and enable the Army's modernization priority for the Next Generation of Combat Vehicles. This PE also matures, integrates and demonstrates advanced technologies that are necessary and foundational for legacy and future ground platforms and ground maneuver. These technology areas include: robotic and autonomous Army Combat Engineer equipment, liquid logistics (i.e., fuels, lubricants, and oils) and related monitoring and distribution, forensic analysis of explosives and other chemical materials, rapidly deployable passive protection technologies, entry and maneuver assessment technologies and structural hardening technologies to protect personnel and critical assets from advanced weapon effects. Project BK9: Ground System Fluids and Fuels Adv Tech was eliminated in PE 0603119A to reflect Department of Defense priorities and will cease Army capabilities to qualify advanced fuels and coolants for combat vehicles and to inform fuel logistics. Project CJ9: Ground Enabling University Adv Development in PE 0603119A was eliminated to reflect Department of Defense priorities and will cease university partnerships in the development of autonomy. The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas in support of the National Defense Strategy. Research is performed by the United States (U.S.) Army Futures Command and the U.S. Army Engineer Research and Development Center. Research in this PE complements PE 0602144A (Ground Technology), PE 0602145A (Next Generation Combat Vehicle Technology), and PE 0603462A (Next Generation Combat Vehicle Advanced Technology). The FY 2026 request was reduced by $0.063 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.176 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                      Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced           PE 0603119A / Ground Advanced Technology Technology Development (ATD)$$, NULL, 37273000, 45065000, 44095000, NULL, NULL, 43, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, 89885000, 188507000, 25043000, 25043000, NULL, 25043000, 45636000, $$This PE matures and demonstrates ground movement and maneuver technologies that support and enable the Army's modernization priority for the Next Generation of Combat Vehicles. This PE also matures, integrates and demonstrates advanced technologies that are necessary and foundational for legacy and future ground platforms and ground maneuver. These technology areas include robotic and autonomous Army Combat Engineer equipment, liquid logistics (i.e., fuels, lubricants, and oils) and related monitoring and distribution, forensic analysis of explosives and other chemical materials, rapidly deployable passive protection technologies, entry and maneuver assessment technologies and structural hardening technologies to protect personnel and critical assets from advanced weapon effects. Project BK9: Ground System Fluids and Fuels Adv Tech was eliminated in PE 0603119A to reflect Department of War priorities. Project CJ9: Ground Enabling University Adv Development in PE 0603119A was eliminated to reflect Department of War priorities. The cited research is consistent with the Under Secretary of War for Research and Engineering priority focus areas in support of the National Defense Strategy. Research is performed by the U.S. Army Futures Command and the U.S. Army Engineer Research and Development Center. Research in this PE complements PE 0602144A (Ground Technology), PE 0602145A (Next Generation Combat Vehicle Technology), and PE 0603462A (Next Generation Combat Vehicle Advanced Technology).$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603123N$$, $$Force Protection Advanced Technology$$, $$rdte_navy_ba3$$, $$onr$$, 2026, 45527000, 75136000, 52657000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "navy", "page_num": 26, "original_pe": "0603123N", "page_header": "Department of the Navy", "fy26_v182_disc_K": 113756, "fy26_v182_supp_K": 21800, "fy26_v182_total_K": 135556, "fy26_v182_note_name": "Research, Development, Test and Evaluation, Navy", "fy26_v182_source_file": "RDTEN_BA1-3_Book.txt", "fy26_v182_source_line": 24137}$$::jsonb, $$This PE addresses advanced technology development associated with providing the capability of Platform and Force Protection for the U.S. Navy. This program supports the development of technologies associated with mission capable, persistent and survivable Naval platforms (surface, subsurface, terrestrial and air) in the areas of Platform Design & Engineering, Power, Energy & Propulsion, and Materials. The program develops technologies for enhanced capability of Naval aviation aircraft platforms in terms of mission effectiveness, platform range, responsiveness, survivability, observability, readiness, safety and life cycle cost. It also develops new Naval air vehicle concepts and high impact, scalable Naval air vehicle technologies. The program also develops advanced technologies, critical to protecting naval installations, to provide seamless full spectrum protection against asymmetric attack by improving the ability to: detect and identify developing and immediate threats; shape our responses through improved situational awareness and decision making; shield personnel, mission critical facilities, infrastructure, and operating fleet assets; maintain essential functions; and sustain and restore critical services in the aftermath of an incident. Today's Sailors and Marines are enabled by naval Science and Technology (S&T). Since 1946, the Office of Naval Research (ONR) has fostered scientific research related to the maintenance of maritime superiority and national defense. ONR manages the Department of the Navy's (DON) portfolio of naval Basic and Applied research, and Advanced Technology Development investments to ensure naval forces can effectively deter conflict, but when called upon, fight, win and come home safe. Current investments hedge against uncertainty, providing solutions to commanders today, and options for the future. The Naval S&T budget supports higher guidance defined by the National Defense Strategy, and responds to requirements identified by the Secretary of the Navy through research priorities set by the Chief of Naval Research, coordinated across the Naval Research Enterprise (NRE), and outlined in the Naval R&D Framework. This Program Element (PE) funds Advanced Technology Development (ATD) that includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Efforts in this PE generally have Technology Readiness Levels TRL) of 4 (component and/or breadboard validation in laboratory environment.), 5 (component and/or breadboard validation in relevant environment.), or 6 (system/subsystem model or prototype demonstration in a relevant environment). Due to the number of efforts in this PE, the programs described herein are representative of the work included in this PE. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                 Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 3: Advanced           PE 0603123N / Force Protection Advanced Technology Technology Development (ATD)$$, NULL, 66129000, 59510000, 44109000, NULL, NULL, 16, $$RDTEN_BA1-3_Book.pdf$$, NULL, FALSE, 54667000, 135556000, 50869000, 50869000, NULL, 50869000, 44143000, $$This PE addresses advanced technology development associated with providing the capability of Platform and Force Protection for the U.S. Navy. This program supports the development of technologies associated with mission capable, persistent and survivable Naval platforms (surface, subsurface, terrestrial and air) in the areas of Platform Design & Engineering, Power, Energy & Propulsion, and Materials. The program develops technologies for enhanced capability of Naval aviation aircraft platforms in terms of mission effectiveness, platform range, responsiveness, survivability, observability, readiness, safety and life cycle cost. It also develops new Naval air vehicle concepts and high impact, scalable Naval air vehicle technologies. The program also develops advanced technologies, critical to protecting naval installations, to provide seamless full spectrum protection against asymmetric attack by improving the ability to: detect and identify developing and immediate threats; shape our responses through improved situational awareness and decision making; shield personnel, mission critical facilities, infrastructure, and operating fleet assets; maintain essential functions; and sustain and restore critical services in the aftermath of an incident. Today's Sailors and Marines are enabled by naval Science and Technology (S&T). Since 1946, the Office of Naval Research (ONR) has fostered scientific research related to the maintenance of maritime superiority and national defense. ONR manages the Department of the Navy's (DON) portfolio of naval Basic and Applied research, and Advanced Technology Development investments to ensure naval forces can effectively deter conflict, but when called upon, fight, win and come home safe. Current investments hedge against uncertainty, providing solutions to commanders today, and options for the future. The Naval S&T budget supports higher guidance defined by the National Defense Strategy, and responds to requirements identified by the Secretary of the Navy through research priorities set by the Chief of Naval Research and outlined in the Naval R&D Framework. This Program Element (PE) funds Advanced Technology Development (ATD) that includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Efforts in this PE generally have Technology Readiness Levels TRL) of 4 (component and/or breadboard validation in laboratory environment.), 5 (component and/or breadboard validation in relevant environment.), or 6 (system/subsystem model or prototype demonstration in a relevant environment). Due to the number of efforts in this PE, the programs described herein are representative of the work included in this PE. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                            Date: April 2026 Appropriation/Budget Activity                                             R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 3: Advanced     PE 0603123N / Force Protection Advanced Technology Technology Development (ATD) The FY 2026 spend plan amount for Research, Development, Test and Evaluation, Navy includes $113,756 thousand of discretionary and $21,800 thousand of mandatory (reconciliation) for a total of $135,556.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA1-3_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603128N$$, $$Unmanned Aerial System$$, $$rdte_navy_ba4$$, $$dw_mda$$, 2026, 28388000, 98807000, 78175000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 27, "original_pe": "0603128N", "page_header": "Department of the Navy"}$$::jsonb, $$Project 3448 - MALE RDTE is pursuing MQ-9A mission (payloads/sensors) and mission enabler capabilities design, development capabilities and integration and testing. These capabilities will support the MALE program's electronic warfare, Maritime Domain Awareness (MDA), tactical edge automation, and airborne network support missions. Consisting of Common Operating and Intelligence Picture (COP/CIP), Detect and Avoid System (DAAS), Airborne Network Extension, Electronic Support development, integration and testing. Additionally, this RDTE is pursuing automated sensor synchronization and onboard forward edge data fusion and transmission using AI/ML apparatus that will transmit fused signals and visual information back to Marine and Joint intelligence apparatus and proliferate the information at the forward edge to stand-in forces (SIF) through the use of Proliferated Low Earth Orbit (PLEO). The PLEO SatCom capacity provides high data throughput and resilient command and control architecture. The USMC MALE program will be supported by UX-24 and VMX-1 as the primary test activity/squadron for capability development as well as system modification validation efforts. UX-24 will provide direct support of testing associated with payloads/sensors in support of USMC requirements. The payloads/sensors which undergo testing may require or drive hardware and software modifications during testing to satisfy system, subsystem and component level test parameters. VMX-1 provides operational test and evaluation of capabilities for MAGTF SIF such as the Marine Littoral Regiment. In FY25 the program will close out the current MDA pod development and transition to conducting studies, analysis, and prototype development for alternative material solutions to meet MALE MDA capability requirements. The FY 2026 cost of the Sky Tower II Middle Tier of Acquisition effort is $60.9 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                            Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced         PE 0603128N / Unmanned Aerial System Component Development & Prototypes (ACD&P)$$, NULL, 31818000, 29505000, 24158000, NULL, NULL, 27, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 75841000, 28388000, 35706000, 35706000, NULL, 35706000, 24578000, $$Project 3448 - MALE RDTE is pursuing the design, development, integration and testing of MQ-9A mission (payloads/sensors) and mission enabler capabilities. These capabilities will support the MALE program's electronic warfare, Maritime Domain Awareness (MDA), tactical edge automation, and airborne network support missions, consisting of the Common Computing Environment (CCE) architecture which includes the Common Operating and Intelligence Picture (COP/CIP), Detect and Avoid System (DAAS), Airborne Network Extension (ANE), Electronic Support development, integration and testing. Additionally, this RDTE is pursuing automated sensor synchronization and onboard forward edge data fusion and transmission using AI/ML apparatus that will transmit fused signals and visual information back to Marine and Joint intelligence apparatus and proliferate the information at the forward edge to Stand-In Forces (SIF) through the use of Proliferated Low Earth Orbit (PLEO). The PLEO SatCom capacity provides high data throughput and resilient command and control architecture. The USMC MALE program will be supported by UX-24 and VMX-1 as the primary test activity/squadron for capability development as well as system modification validation efforts. UX-24 will provide direct support of testing associated with payloads/sensors in support of USMC requirements. The payloads/sensors which undergo testing may require or drive hardware and software modifications during testing to satisfy system, subsystem and component level test parameters. VMX-1 provides operational test and evaluation of capabilities for MAGTF SIF such as the Marine Littoral Regiment. The cost of the Sky Tower II Middle Tier of Acquisition effort is $64.9 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                           Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced        PE 0603128N / Unmanned Aerial System Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2031_L008$$, $$UH-72 LAKOTA LIGHT UTILITY HELICOPTER$$, $$proc_army_2031_ba1$$, $$peo_aviation$$, 2026, 0, 10000000, 10000000, NULL, $${"page": 10, "ba_num": "01", "source": "p1_fy26", "ba_name": "Aircraft", "line_no": "8", "service": "army", "fy24_qty": 1, "fy25_qty": null, "appr_code": "2031", "appr_name": "Aircraft Procurement, Army", "fy26_v178": {"disc_K": 26850, "li_num": 5, "source": "p40_fy26_v178", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Army/Aircraft_Procurement_Army.txt"}, "fy26t_qty": null, "fy26d_cost": 0, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, 3224254000, NULL, NULL, NULL, FALSE, 10000000, 26850000, 227569000, 227569000, 0, 227569000, NULL, NULL, $$Budget J-Books/FY27/Army/Aircraft_Procurement_Army.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603134A$$, $$Counter Improvised-Threat Simulation$$, $$rdte_army_ba3$$, $$afc$$, 2026, 15692000, 20965000, 21398000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 12, "original_pe": "0603134A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) develops technology for detecting and defeating Improvised Explosive Devices (IEDs). The goal of this research is to increase the ability of deployed forces to positively identify IEDs with minimal false alarms and positively neutralize or mitigate the effects of IEDs with minimal collateral damage. This PE is executed by the Army Futures Command (AFC) in coordination with the Under Secretary of Defense for Research and Engineering (USD/R&E) and the Defense Threat Reduction Agency (DTRA).$$, NULL, NULL, NULL, NULL, NULL, NULL, 44, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, 20688000, 15692000, NULL, NULL, NULL, NULL, NULL, $$This Program Element (PE) develops technology for detecting, geolocating, classifying, and defeating existing and emerging explosive hazards to include mines, minefields, and other complex obstacles to enable remote breaching, combat engineer modernization, and freedom of maneuver.). The goal of this effort is to enable automated sensing integrated with defeat methods to maintain the necessary rate of advance to support breach operations under stressing operational conditions and environments. This PE is executed by the Transformation & Training Command (T2COM) in coordination with the Under Secretary of War for Research and Engineering (USD/R&E) and the Defense Threat Reduction Agency (DTRA).$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603135A$$, $$Counter Small Unmanned Aerial Systems (C-SUAS) Advanced Technolo$$, $$rdte_army_ba3$$, $$dw_osd$$, 2026, 7773000, 0, 0, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 12, "original_pe": "0603135A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) develops, matures, and demonstrates novel capabilities that aid in the detection, tracking, identification, mitigation, and/or defeat of small unmanned aerial systems (sUAS) groups 1-3. Develops and matures counter-small UAS (C-SUAS) detection capabilities in radar, radio frequency (RF), electro-optical and infrared (EO/IR), and acoustic signature regimes. Develops capabilities to track and predict UAS flight paths, airspace situational awareness, and/or location of UAS operators to increase defeat and force protection capabilities. Matures identification methods to discern aerial systems and payloads. Matures and demonstrates algorithms to enable threat prioritization, airspace control, coordinated response, and resource management of C-SUAS capabilities. Mature, demonstrate, and transition interceptor capabilities to deliver physical effects that enable faster intercept, greater standoff ranges, increased magazine depth, survivability, affordability, and/or decrease in size, weight, and/or power requirements. The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy.$$, NULL, 54124000, 48802000, 53282000, NULL, NULL, 45, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, NULL, 7773000, 156520000, 156520000, NULL, 156520000, 56274000, $$This Program Element (PE) develops, matures, and demonstrates novel capabilities that aid in the detection, tracking, identification, mitigation, and/or defeat of small unmanned aerial systems (sUAS) groups 1-3. Develops and matures counter-small UAS (C-SUAS) detection capabilities in radar, radio frequency (RF), electro-optical and infrared (EO/IR), and acoustic signature regimes. Develops capabilities to track and predict UAS flight paths, airspace situational awareness, and/or location of UAS operators to increase defeat and force protection capabilities. Matures identification methods to discern aerial systems and payloads. Matures and demonstrates algorithms to enable threat prioritization, airspace control, coordinated response, and resource management of C-SUAS capabilities. Mature, demonstrate, and transition interceptor capabilities to deliver physical effects that enable faster intercept, greater standoff ranges, increased magazine depth, survivability, affordability, and/or decrease in size, weight, and/or power requirements. The cited research is consistent with the Under Secretary of War for Research and Engineering priority focus areas and the Army modernization strategy.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603142D8Z$$, $$Mission Engineering and Integration (ME&I)$$, $$rdte_dw_ba3$$, $$dw_osd$$, 2026, 99534000, 0, 104832000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 68, "original_pe": "0603142D8Z", "page_header": "Defense-Wide", "fy26_v182_disc_K": 76768, "fy26_v182_supp_K": 32000, "fy26_v182_total_K": 108768, "fy26_v182_note_name": "Mission Engineering and Integration", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 9555}$$::jsonb, $$Mission Engineering and Integration is a strategically driven, mission-focused DoD framework to synchronize resources and integrate cross-service capabilities to achieve timely and accurate mission effects. It fulfills responsibilities outlined in the National Defense Authorization Act (NDAA) for FY17, Section 855 by prioritizing investments in capabilities that address warfighting needs, interoperability, and capability gaps through rigorous mission engineering activities and Joint Force Integration studies. To achieve its goals, ME&I conducts Joint Force Integration Mission Engineering studies that align with the National Defense Strategic Guidance, Defense Planning Scenarios, and Key Operational Problems. These studies assess the impact of integrating new technologies and capabilities into critical warfighter missions. Furthermore, ME&I utilizes advanced modeling and simulation tools to develop and analyze Joint Mission Engineering Threads (METs), also known as "Kill Webs," in operational scenarios, ultimately informing technology investment decisions by DoD leadership. This integrated approach ensures the effective incorporation of new technologies and capabilities to address current and future warfighting demands.$$, NULL, 171099000, 144271000, 143088000, NULL, NULL, 39, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 101099000, 108768000, 144454000, 144454000, NULL, 144454000, 137186000, $$Mission Engineering and Integration (ME&I) is a strategically driven, mission-focused DoW framework to synchronize resources and integrate cross-service capabilities to achieve timely and accurate mission effects. It fulfills responsibilities outlined in the National Defense Authorization Act (NDAA) for FY17, Section 855 by prioritizing investments in capabilities that address warfighting needs, interoperability, and joint operational problems through rigorous mission engineering activities. To achieve its goals, ME&I conducts Joint Force Integration Mission Engineering studies that align with the National Defense Strategy, Defense Planning Scenarios, and Key Operational Problems. These studies assess the impact of integrating new technologies and capabilities into critical warfighter missions. Furthermore, ME&I utilizes advanced modeling and simulation tools to develop and analyze Joint Mission Engineering Threads (METs), also known as "Kill Webs," in operational scenarios, ultimately informing technology investment decisions by DoW leadership. This integrated approach ensures the effective incorporation of new technologies and capabilities that address current and future warfighting demands. The FY 2026 spend plan amount for Mission Engineering and Integration includes $76,768 thousand of discretionary and $32,000 thousand of mandatory for a total of $108,768 thousand. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:         PE 0603142D8Z / Mission Engineering and Integration (ME&I) Advanced Technology Development (ATD)$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603159D8Z$$, $$Golden Dome for America - DARPA$$, $$rdte_gd_ba3$$, $$dw_darpa$$, 2026, 0, 0, 0, NULL, $${"ba": "03", "line": 8, "page": 82, "unit": "K", "source": "r1_fy27", "fy26_pl": 697700, "fy27_disc": 0, "fy27_mand": 174300, "fy26_total": 697700, "fy27_total": 174300, "appropriation": "3007D"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 8, $$Budget J-Books/FY27/Remaining/FY2027_r1.txt$$, $$GDAF$$, FALSE, 0, 697700000, 0, 0, 174300000, 174300000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603160BR$$, $$COUNTER WEAPONS OF MASS DESTRUCTION ADVANCED TECHN$$, $$rdte_dw_ba3$$, $$dw_dtra$$, 2026, 393469000, 390581000, 410112000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 68, "original_pe": "0603160BR", "page_header": "Defense-Wide"}$$::jsonb, $$Counter Weapons of Mass Destruction (CWMD) Technologies and Capabilities Development project develops advanced technologies and weapon concepts and validates their applicability to CWMD. Research encompasses the following areas: Defeat Technologies supports Combatant Commands through research, development, and transition of offensive weapons and other capabilities to counter Weapons of Mass Destruction (WMD) while mitigating collateral contamination effects. Enable rapid capability delivery supports urgent warfighter operational requirements in countering WMD and emerging threats, often below the level of armed conflict. This research develops and delivers urgent CWMD capabilities to provide Combatant Commands a competitive advantage against WMD-capable adversaries with a focus on innovative, agile, achievable, and effective technology solutions for DoD sensitive and classified programs, Combatant Command hybrid warfare support, and competition below the level of armed conflict. Counter emergent threat technologies research develops and transitions a full spectrum of new technologies to counter emergent WMD threats providing combatant commanders improved offensive capabilities in support of near-peer emerging threats and counter-proliferation missions that combat weapons of mass destruction. This research supports the U.S. Special Operations Command (USSOCOM) in two areas: (1) counter proliferation research is a collaborative effort to develop advanced, warfighter-unique technologies to defeat WMD development and acquisition pathways, to include defeat of the devices themselves, while minimizing risks to U.S. forces; and (2) counter emerging threats concepts and technologies to integrate and synchronize activities that prevent violent extremist organizations and rogue nation states from developing, acquiring, proliferating, or using WMD. This effort supports Commander, USSOCOM responsibilities under the Chairman, Joint Chiefs of Staff Unified Command Plan. Counterforce technologies research develops, integrates, demonstrates, and transitions advanced sensors, surveillance, and target defeat planning technologies to enable the warfighter to hold WMD-related targets at risk. There are three core research efforts in this project: Technical Reconnaissance; CWMD Weapons Effects; and, Applied CWMD Computational, Physical and Life Science Research. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Threat Reduction Agency                                                            Date: June 2025 Appropriation/Budget Activity                                                           R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:                    PE 0603160BR / COUNTER WEAPONS OF MASS DESTRUCTION ADVANCED TECHN Advanced Technology Development (ATD)                                                   OLOGY DEVELOPMENT Target assessment technologies research develops, applies, and transitions processes and technologies providing advanced capabilities in the areas of WMD Targets Immersive Mission Planning (TIMP), and Full Dimensional Defeat Enterprise (FDDE). Nuclear - Advanced Automated Target Development automates intelligence input to provide more realistic target input parameters incorporating 3-D models. WMD-TIMP provides an interactive virtual reality platform for mission planning that mitigates impact of characterization uncertainty by allowing mission planners to execute multiple planning iterations with varied uncertainty parameters. FDDE aims to develop an enterprise capability for finding and identifying a facility, characterizing its function and physical layout, determining current or future vulnerabilities to available defeat mechanisms, planning and executing an attack, assessing damage, and denying reconstitution efforts. The dynamic capabilities encompassed in this effort provide Combatant Commands and the intelligence community tools and processes needed to hold at risk high value hard targets and WMD targets possessed by adversaries.$$, NULL, 515366000, 515591000, 502911000, NULL, NULL, 40, $$RDTE_DTRA_PB_2026.pdf$$, $$DTRA$$, FALSE, 399980000, 374450000, 509160000, 509160000, NULL, 509160000, 507631000, $$Defense Threat Reduction Agency's (DTRA's) Counter Weapons of Mass Destruction (WMD) Advanced Technology Development (ATD) Program capitalizes on Applied Research (Budget Activity 6.2) RDT&E transitioning to the development of advanced concepts, components, and prototypes. The project objective is to determine technical feasibility and practicality of a new technologies and approaches to solve WMD problems and integrate components and subsystems into system prototypes for testing in realistic or simulated environments. DTRA’s RDT&E WMD project accomplishes these objectives through four project areas. The CWMD Cross-Cutting Technical and Information Sciences project develops concepts and technologies in the areas of high-speed information processing, modeling and simulation, signal detection, and data-driven decision analysis in support of the DTRA's technical teams. The Nuclear Technologies and Capabilities Development project develops direct and indirect technologies for the detection of radiation and nonradioactive signatures associated with nuclear threats, and advance warfighter capabilities to rapidly locate, characterize, and counter such threats. The CWMD Technologies and Capabilities Development project develops innovative kinetic and non-kinetic weapons technologies to expand traditional and asymmetric options available to Combatant Commanders to deny, disrupt, and defeat adversarial use of WMD while minimizing collateral effects. The CWMD Test and Evaluation project provides unique national test bed capability for the study of weapon-target interaction, simulated WMD facility characterization, and WMD facility defeat testing to evaluate the implications of WMD and other special weapon use against U.S. military and civilian assets. DTRA will conduct Research & Development (R&D) to address adversary Hardened and Deeply Buried Target (HDBT) threats and capabilities as outlined in the National Defense Strategy (NDS), Defense Planning Guidance (DPG), and supporting Combatant Command operational requirements. DTRA will lead HDBT-Defeat requirement development and capability planning, coordination, and prioritization in support of a larger, collaborative HDBT-Defeat capability development strategy in concert with DoW and Combatant Command strategies and priorities. DTRA will advocate for Service HDBT-Defeat capabilities and programs in accordance with applicable strategies, plans, and guidance. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Threat Reduction Agency                                                Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:           PE 0603160BR / COUNTER WEAPONS OF MASS DESTRUCTION ADVANCED TECHN Advanced Technology Development (ATD)                                          OLOGY DEVELOPMENT$$, $$Budget J-Books/FY27/Remaining/RDTE_DTRA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603176BR$$, $$Advanced Concepts and Performance$$, $$rdte_dw_ba3$$, $$dw_dtra$$, 2026, 0, 7788000, 0, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 68, "original_pe": "0603176BR", "page_header": "Defense-Wide"}$$::jsonb, $$The NAG conducts rapid, secure, and independent assessments of critical and unique technologies to support the Military Services, other government agencies, and DTRA. This rapid assessment group provides independent assessments of critical and unique technologies and capabilities for customers in the areas of counter WMD and emerging threats. The NAG provides an independent review/analysis and reporting of operational assessments, capability demonstrations, and test events.$$, NULL, NULL, NULL, NULL, NULL, NULL, 41, $$RDTE_DTRA_PB_2026.pdf$$, $$DTRA$$, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603176C$$, $$Advanced Concepts and Performance Assessment$$, $$rdte_dw_ba3$$, $$dw_mda$$, 2026, 21625000, 29019000, 17920000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 68, "original_pe": "0603176C", "page_header": "Defense-Wide"}$$::jsonb, $$The Advanced Concepts and Performance Assessment (ACPA) Program Element delivers a government concept that integrates concept definition, simulation, analysis, and testbed capability. ACPA's focus is on the exploration of novel and/or emerging capabilities that may have the potential to enhance the Missile Defense System. ACPA centralizes assessment of advanced missile defense technology and delivers insight into the performance of proposed concepts extending the Missile Defense Agency's (MDA) ability to address evolving threats for the Warfighter. Working with national laboratories and industry, MDA will invest in the analysis and assessment of directed energy system components to determine their effectiveness and capability for missile defense. Subject Matter Experts provide independent assessments of government, university, and industry technology concepts, used in concert with systems engineering requirements, to support acquisition strategy decisions and define technology focus areas. The innovative structured concept definition and assessment methodology enables MDA to quickly validate focus areas, verify contractor technology solutions, and evaluate promising concepts in future Missile Defense System architectures. This methodology significantly enhances MDA's ability to assess technology concepts while decreasing the cost of development by: - Delivering Independent model-based simulations of industry technology concepts to inform the systems engineering process. - Quantifying expectations through algorithms, digital simulation, hardware-in-the-loop, and/or demonstration events prior to expensive live fire test events. - Executing end-to-end testing of technology concepts integrated with weapon systems through Command and Control network architectures. - Maturing and conducting assessments of new technologies to evaluate their readiness for transition to the future Missile Defense System. - Supports early coordination with the program elements to promote efficient integration into the Missile Defense System and provide additional capability to meet the Warfighter needs. - Collaborate with partners across Industry, the Office of the Undersecretary of Defense for Research and Engineering, Other Government Agencies, Service Partners, and the National Laboratories to transition advanced technologies into functional areas and programs of record. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Missile Defense Agency                                                           Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:              PE 0603176C / Advanced Concepts and Performance Assessment Advanced Technology Development (ATD) Performance assessment of advanced concepts is the key enabler for government evaluation of technology in the earliest stages of development and maximizes the efficiency of technology investments. Performance assessment is used to quantify capability expectations of innovative concepts to counter the expanding regional and homeland missile threats, including ballistic and cruise missiles, and hypersonic vehicles.$$, NULL, 0, 0, 0, NULL, NULL, 42, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 21091000, 30901000, 0, 0, NULL, 0, 0, $$The ACPA PE delivers a government concept that integrates concept definition, simulation, analysis, and testbed capability. ACPA's focus is on the exploration of novel and/or emerging capabilities that may have the potential to enhance the Missile Defense System. ACPA centralizes assessment of advanced missile defense technology and delivers insight into the performance of proposed concepts extending the Missile Defense Agency's ability to address evolving threats for the Warfighter.$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603178N$$, $$(U)LARGE UNMANNED SURFACE VESSELS (LUSVs)$$, $$rdte_navy_ba4$$, $$peo_usc$$, 2026, 57860000, 98759000, 46964000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 27, "original_pe": "0603178N", "page_header": "Department of the Navy"}$$::jsonb, $$This Program Element provides resources for Unmanned Surface Vessels, which play a key role in the Navy's Future Surface Combatant Force (FSCF). This Program Element also provides resources for the Prototype vessels that are being operated under PMS 406 for technology maturation and risk reductions efforts. USVs will provide affordable, high endurance ships able to accommodate various payloads for unmanned missions and augment the Navy's manned surface force. LUSVs will be capable of autonomous operation, with operators in-the-loop to control the combat system. USV Command and Control (C2) will be maintained via an afloat element (i.e., embarked on a United States Navy (USN) combatant/other assigned afloat asset) or via an ashore element (C2 station ashore). USVs are a key enabler of the Navy's Distributed Maritime Operations (DMO) concept, which includes being able to forward deploy and team with individual manned combatants or augment battle groups. USVs will complement the Navy's manned combatant force by delivering increased readiness, capability and needed capacity at lower procurement and sustainment costs and reduced risk to sailors. While unmanned surface vehicles are new additions to the fleet units, USVs will combine robust and proven commercial vessel specifications with existing military payloads to rapidly and affordably expand the capacity and capability of the surface fleet. USV development is supported by research and development prototype vessels intended to demonstrate successful integration of government furnished Command, Control, Communications, Computers and Intelligence (C4I), combat systems, and the reliability of automated hull, mechanical, and electrical (HM&E) systems. The program leverages years of investment and full scale demonstration efforts in autonomy, endurance, command and control, payloads and testing from the Defense Advanced research Projects Agency (DARPA) Anti-Submarine Warfare Continuous Trail Unmanned Vessel (ACTUV), Office of Naval Research (ONR) Medium Displacement Unmanned Surface Vehicle (MDUSV)/Sea Hunter (FY 2017 to FY 2021), and Office of the Secretary of Defense Strategic Capabilities Office (OSD- SCO) Ghost Fleet Overlord USV experimentation effort (FY 2018 - FY 2021). The combination of fleet-ready C2 solutions developed by the Ghost Fleet Overlord program and man-in-the-loop or man-on-the-loop control will reduce the risk of fleet integration of unmanned surface vehicles and allow autonomy and payload technologies to develop in parallel with fielding vehicles with standardized interfaces. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                            Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced         PE 0603178N / (U)LARGE UNMANNED SURFACE VESSELS (LUSVs) Component Development & Prototypes (ACD&P)$$, NULL, 0, 0, 0, NULL, NULL, 28, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 45514000, 0, 0, 0, NULL, 0, 1000, $$This Program Element provided resources for Unmanned Surface Vessels, which play a key role in the Navy's Future Surface Combatant Force (FSCF). This Program Element also provided resources for the Prototype vessels that are being operated under PMS 406 for technology maturation and risk reductions efforts. USV development is supported by research and development prototype vessels intended to demonstrate successful integration of government furnished Command, Control, Communications, Computers and Intelligence (C4I), combat systems, and the reliability of automated hull, mechanical, and electrical (HM&E) systems. The program leveraged years of investment and full scale demonstration efforts in autonomy, endurance, command and control, payloads and testing from the Defense Advanced research Projects Agency (DARPA) Anti-Submarine Warfare Continuous Trail Unmanned Vessel (ACTUV), Office of Naval Research (ONR) Medium Displacement Unmanned Surface Vehicle (MDUSV)/Sea Hunter (FY 2017 to FY 2021), and Office of the Secretary of Defense Strategic Capabilities Office (OSD- SCO) Ghost Fleet Overlord USV experimentation effort (FY 2018 - FY 2021). The combination of fleet-ready C2 solutions developed by the Ghost Fleet Overlord program and man-in-the- loop or man-on-the-loop control will reduce the risk of fleet integration of unmanned surface vehicles and allow autonomy and payload technologies to develop in parallel with fielding vehicles with standardized interfaces. The FY 2026 spend plan for Large Unmanned Surface Vessel (LUSV) includes $0 of discretionary and $57,860 thousand of mandatory (reconciliation) for a total of $57,860 thousand. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                          Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced       PE 0603178N / (U)LARGE UNMANNED SURFACE VESSELS (LUSVs) Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603180C$$, $$Advanced Research$$, $$rdte_dw_ba3$$, $$dw_mda$$, 2026, 42093000, 61537000, 46854000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 68, "original_pe": "0603180C", "page_header": "Defense-Wide"}$$::jsonb, $$The Advanced Research Program conducts leading edge technology research and development efforts to enable future missile defense capabilities. The Missile Defense Agency executes this mission by capitalizing on the creativity and innovation of the brightest minds in our Nation's universities, small and large businesses, national laboratories, other government agencies, and allied countries. In coordination with identified Agency requirements, Warfighter needs and industry rapid innovation, the program develops/matures, assesses and demonstrates emerging and disruptive component technologies and prototypes. After successful maturation, demonstration, and prototyping activities, the program facilitates transition of the technologies to the Missile Defense System and other programs to defeat the missile threat.$$, NULL, 960322000, 1056974000, 770880000, NULL, NULL, 43, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 50248000, 76628000, 482573000, 482573000, NULL, 482573000, 933215000, $$The threat is evolving and becoming more complex, which introduces new challenges for missile defense. Some of these complex challenges include the volume of threats, system performance in raids, latency across the kill chain, communication between disparate systems, performance in a contested environment and cybersecurity of networks/systems. These challenges to missile defense require more disruptive capabilities like the following: - Kinetic & hypersonic defense in the areas of advanced sensing and low-cost systems. - Non-kinetics and electronic warfare. - Next generation command, control & integration. - Disruptive technology and space demonstrations. - National Integrated Air and Missile Defense Center. - Cyber Protection / Information Assurance. The Cyber Operations project supports both the security and effective execution of program office mission-related activities to include information assurance and cyber network defense. Program Wide Support contains non-headquarter management costs and activities in support of the Missile Defense Agency (MDA) functions across the entire Missile Defense System. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Missile Defense Agency                                                                Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:             PE 0603180C / Advanced Research Advanced Technology Development (ATD) The MDA Advanced Capability Office provides enhancements to the missile defense system by focusing on accelerated delivery of disruptive capabilities to the warfighter by pursuing rapid prototypes and demonstrations with incremental capability deliveries. The activities utilize two/three-year technology sprints and lean project teams to support rapid development and transition to the Warfighter for evolving regional and homeland missile threats.$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1507_L002$$, $$TRIDENT II Mods$$, $$proc_navy_1507_ba1$$, $$peo_iws$$, 2026, 2644029000, 1284705000, 1793867000, NULL, $${"page": 66, "ba_num": "01", "source": "p1_fy26", "ba_name": "Ballistic missiles", "line_no": "2", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "01", "appr": "WPN", "title": "P-1 Line 1", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/WPN_Book.pdf", "fy27_base_K": 750387, "p1_line_num": 1, "fy27_total_K": 750387}, "appr_code": "1507", "appr_name": "Weapons Procurement, Navy", "fy26_v179": {"note": "no_parser_pair", "source": "p40_fy26_v179"}, "fy26_v197": {"method": "title_fuzzy_partial", "delta_K": 610000, "src_pdf": "Budget J-Books/FY27/Navy/WPN_Book.pdf", "mapped_K": 3829652, "applied_at": "2026-05-09T_v197d", "table2_total_K": 4063652, "supersedes_partial": "fy26_v179_concentrated", "unmapped_residual_K": 234000}, "fy26t_qty": null, "fy26d_cost": 2582029000, "fy26r_cost": 62000000, "ident_code": ""}$$::jsonb, NULL, NULL, NULL, NULL, NULL, 4352768000, 51316899000, NULL, NULL, NULL, FALSE, 1793867000, 2541712000, 750387000, 750387000, 0, 750387000, NULL, NULL, $$Budget J-Books/FY27/Navy/WPN_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603183D8Z$$, $$Joint Hypersonic Technology Development & Transition$$, $$rdte_dw_ba3$$, $$dw_osd$$, 2026, 650998000, 53148000, 56941000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 68, "original_pe": "0603183D8Z", "page_header": "Defense-Wide", "fy26_v182_disc_K": 59515, "fy26_v182_supp_K": 367000, "fy26_v182_total_K": 426515, "fy26_v182_note_name": "Research, Development, Test & Evaluation, Defense-Wide for Joint Hypersonic Technology Development & Transition", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 10158}$$::jsonb, $$This program supports the Department's initiatives to Build Sustainable and Long-Term Advantage, and Build a Resilient Joint Force and Defense Ecosystem. The Joint Hypersonics Transition Office (JHTO), within the Office of the Assistant Secretary of Defense for Science and Technology (ASD(S&T)), was created to establish a university consortium for hypersonics research; support workforce development; expedite testing, evaluation, and acquisition of hypersonic technologies to meet the stated needs of the warfighter; ensure that prototyping demonstration programs on hypersonic systems integrate advanced technologies to speed the maturation and deployment of future hypersonic systems; develop strategies, roadmaps, and technology protection measures for hypersonics to enable the transition of such technologies to future operational capabilities for the warfighter; and develop and implement a strategy for enhancing the current and future hypersonics workforce.$$, NULL, 278700000, 327520000, 286116000, NULL, NULL, 44, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 55745000, 426515000, 424422000, 424422000, NULL, 424422000, 177810000, $$This program supports the Department's initiatives to Build Sustainable and Long-Term Advantage, and Build a Resilient Joint Force and Defense Ecosystem. The Joint Hypersonics Transition Office (JHTO), within the Office of the Assistant Secretary of War for Science and Technology (ASW(S&T)), was created to establish a university consortium for hypersonics research; support workforce development; expedite testing, evaluation, and acquisition of hypersonic technologies to meet the stated needs of the warfighter; ensure that prototyping demonstration programs on hypersonic systems integrate advanced technologies to speed the maturation and deployment of future hypersonic systems; develop strategies, roadmaps, and technology protection measures for hypersonics to enable the transition of such technologies to future operational capabilities for the warfighter; and develop and implement a strategy for enhancing the current and future hypersonics workforce. The FY 2026 spend plan amount for Research, Development, Test & Evaluation, Defense-Wide for Joint Hypersonic Technology Development & Transition includes $59,515 thousand of discretionary and $367,000 thousand of mandatory for a total of $426,515 thousand.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603207N$$, $$Air/Ocean Tactical Applications$$, $$rdte_navy_ba4$$, $$mc$$, 2026, 35870000, 42257000, 50765000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 27, "original_pe": "0603207N", "page_header": "Department of the Navy"}$$::jsonb, $$Understanding and accurately predicting the maritime environment is a naval warfighting advantage. Effective meteorological and oceanographic modeling depends upon a network of advanced, reliable sensors below, on and above the world's oceans. Combined with state-of-the-art computational infrastructure, the Navy-Marine Corps Meteorological and Oceanographic (METOC) team delivers 24/7 observations, precise forecasts and operational recommendation to commanders. The Air Tactical Applications (AOTA) Program Element (PE) is aligned with the Navy's maritime strategy to enhance future METOC mission capabilities supporting naval warfighters worldwide. New state-of-the art government and commercial technologies are identified, transitioned, demonstrated and then integrated into Combat Systems and programs of record to provide capabilities that provide real-time and near-real-time operational effects of the physical environment on the performance of combat forces and their new and emerging platforms, sensors, systems and munitions. The AOTA program element focuses on sensing and characterizing and predicting the littoral and deep-strike battlespace in the context of regional conflicts and crisis response scenarios. Projects in this PE transition state-of-the art sensing, assimilation, modeling and decision aid technologies from government and commercial sources. Unique project development efforts include atmospheric and oceanographic data assimilation techniques, forecast models, data base management systems and associated software for use in mainframe, desktop and laptop computers. Model data, products and services can be used by forward-deployed personnel or in a reach-back mode to Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                               Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced             PE 0603207N / Air/Ocean Tactical Applications Component Development & Prototypes (ACD&P) optimize sensor placement and force allocation decisions. Global Geospatial Information and Services efforts within this program address the bathymetric needs of the Navy. Also developed are algorithms to process new satellite sensor data for integration into Navy and Marine Corps decision support systems and for display as part of the common operational and tactical pictures. In addition, the projects provide for demonstration and validation of specialized atmospheric and oceanographic instrumentation and measurement techniques, new sensors, communications and interfaces. Included are new capabilities to assess, predict and enhance the performance of current and emerging undersea warfare and mine warfare weapons systems. AOTA capabilities are designed to support the latest versions of the Global Command and Control System and specific unit-level combat systems. This PE develops technological upgrades for the U.S. Naval Observatory's Master Clock system to meet requirements of Department of Defense communications, cryptographic, intelligence, geolocation, and targeting systems; develops near-real-time earth orientation predictions; develops very precise determination of positions of both faint and bright stars; and supports satellite tracking and space debris studies. Major emphasis areas include the Naval Integrated Tactical Environmental System Next Generation (NITES-Next) and the METOC Data Acquisition, the METOC Data Assimilation & Modeling, the Precise Timing and Astrometry, the Fleet Synthetic Training, the Tactical Environmental Support, Decision Support Products & Dissemination, the Earth System Prediction Capability projects, and the Remote Sensing Capability Development. Advanced Component Development and Prototypes (ACD&P) efforts necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment are funded in this PE. Most of the work in this PE can be classified between Technology Readiness Level (TRL) 6 (system/subsystem model or prototype demonstration in a relevant environment) and TRL 7 (system prototype demonstration in an operational environment). Due to the number of efforts in this PE, the programs described herein are representative of the work included in this PE.$$, NULL, 41764000, 41605000, 41451000, NULL, NULL, 29, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 48819000, 35409000, 76141000, 76141000, NULL, 76141000, 42252000, $$Understanding and accurately predicting the maritime environment is a naval warfighting advantage. Effective meteorological and oceanographic modeling depends upon a network of advanced, reliable sensors below, on and above the world's oceans. Combined with state-of-the-art computational infrastructure, the Navy-Marine Corps Meteorological and Oceanographic (METOC) team delivers 24/7 observations, precise forecasts and operational recommendation to commanders. The Air Tactical Applications (AOTA) Program Element (PE) is aligned with the Navy's maritime strategy to enhance future METOC mission capabilities supporting naval warfighters worldwide. New state-of-the art government and commercial technologies are identified, transitioned, demonstrated and then integrated into Combat Systems and programs of record to provide capabilities that provide real-time and near-real-time operational effects of the physical environment on the performance of combat forces and their new and emerging platforms, sensors, systems and munitions. The AOTA program element focuses on sensing and characterizing and predicting the littoral and deep-strike battlespace in the context of regional conflicts and crisis response scenarios. Projects in this PE transition state-of-the art sensing, assimilation, modeling and decision aid technologies from government and commercial sources. Unique project development efforts include atmospheric and oceanographic data assimilation techniques, forecast models, data base management systems and associated software for use in mainframe, desktop and laptop computers. Model data, products and services can be used by forward-deployed personnel or in a reach-back mode to Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                               Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced             PE 0603207N / Air/Ocean Tactical Applications Component Development & Prototypes (ACD&P) optimize sensor placement and force allocation decisions. Global Geospatial Information and Services efforts within this program address the bathymetric needs of the Navy. Also developed are algorithms to process new satellite sensor data for integration into Navy and Marine Corps decision support systems and for display as part of the common operational and tactical pictures. In addition, the projects provide for demonstration and validation of specialized atmospheric and oceanographic instrumentation and measurement techniques, new sensors, communications and interfaces. Included are new capabilities to assess, predict and enhance the performance of current and emerging undersea warfare and mine warfare weapons systems. AOTA capabilities are designed to support the latest versions of the Global Command and Control System and specific unit-level combat systems. This PE develops technological upgrades for the U.S. Naval Observatory's Master Clock system to meet requirements of Department of Defense communications, cryptographic, intelligence, geolocation, and targeting systems; develops near-real-time earth orientation predictions; develops very precise determination of positions of both faint and bright stars; and supports satellite tracking and space debris studies. Major emphasis areas include the Naval Integrated Tactical Environmental System Next Generation (NITES-Next) and the METOC Data Acquisition, the METOC Data Assimilation & Modeling, the Precise Timing and Astrometry, the Fleet Synthetic Training, the Tactical Environmental Support, Decision Support Products & Dissemination, the Earth System Prediction Capability projects, and the Remote Sensing Capability Development. Advanced Component Development and Prototypes (ACD&P) efforts necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment are funded in this PE. Most of the work in this PE can be classified between Technology Readiness Level (TRL) 6 (system/subsystem model or prototype demonstration in a relevant environment) and TRL 7 (system prototype demonstration in an operational environment). Due to the number of efforts in this PE, the programs described herein are representative of the work included in this PE.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603208N$$, $$Training System Aircraft$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 15101000, 39283000, 26120000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 32, "original_pe": "0603208N", "page_header": "Department of the Navy"}$$::jsonb, $$This program element provides for design, development, integration and test of various pre and post production platform improvements for Naval Undergraduate Flight Training Systems which include T-45, T-6, T-44, TH-57, TH-73A, T-54, and T-45 Follow-On: Undergraduate Jet Training System (UJTS). Continued development engineering for improvements in reliability, maintainability, and safety are required to ensure maximum benefit is achieved to provide effective cost of ownership and availability of aircraft to meet Chief of Naval Air Training (CNATRA) student training requirements. Specific efforts include: T-45, T-6, TH-57, T-44, T-54, and TH-73A Training System Improvements such as development and sustainment engineering change proposals (ECPs), avionics reliability and modernization, corrosion prevention ECPs, obsolescence ECPs, T-45 Retrofit Integration Testing (RIT), and new solutions required to meet evolving fleet training requirements; T-45 and T-6 Physiological Episode (PE) mitigation analysis; New Start T-6B Avionics Modernization; and T-45 Follow-On UJTS development. This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full-rate production decision.$$, NULL, 235857000, 232715000, 134860000, NULL, NULL, 108, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 25493000, 15101000, 80617000, 80617000, NULL, 80617000, 90132000, $$This program element provides for design, development, integration and test of various pre- and post-production platform improvements for Naval Undergraduate Flight Training Systems which include T-45, T-6, T-44, TH-73A, T-54, and T-45 Follow-On, the Undergraduate Jet Training System (UJTS). Continued development engineering for improvements in reliability, maintainability, and safety are required to ensure maximum benefit is achieved to provide effective cost of ownership and availability of aircraft to meet Chief of Naval Air Training (CNATRA) student training requirements. Specific efforts include: T-45, T-6, T-44, T-54, and TH-73A Training System Improvements such as development and sustainment engineering change proposals (ECPs), avionics reliability and modernization, corrosion prevention ECPs, obsolescence ECPs, T-45 Retrofit Integration Testing (RIT), and new solutions required to meet evolving fleet training requirements; T-45 and T-6 Physiological Episode (PE) mitigation analysis; T-6B Avionics Modernization; and UJTS development. This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full-rate production decision.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603211F$$, $$Aerospace Technology Dev/Demo$$, $$rdte_af_ba3$$, $$afrl_rq$$, 2026, 102125000, 131596000, 91719000, NULL, $${"ba_raw": "6.3", "source": "af_r1_fy26", "original_pe": "0603211F"}$$::jsonb, $$This program supports Department of Defense (DoD) priorities for Aerospace Systems demonstrations to include high-speed systems and autonomous collaborative platforms. System level integration and demonstration of advanced aerospace system technologies (autonomy, propulsion, power and thermal, air vehicle, fuels, etc.) in a near-realistic operational environment enhance performance and supportability of existing and future aerospace systems while reducing the risk and time required to transition technologies into operational aircraft. Additionally, this program supports the nuclear enterprise and nuclear deterrence through advanced component and technology demonstrations. Projects in this program have been coordinated through the DoD Science and Technology (S&T) Executive Committee process to harmonize efforts and eliminate duplication. The program has six current projects, each focusing on technologies with a high potential to enhance the performance of existing and future Air Force weapon systems via modeling, simulation, and analysis while utilizing digital engineering to accelerate and enhance the S&T development. - Missile Rocket Propulsion Integration and Demonstration: Develops and demonstrates innovative rocket propulsion technologies, propellants, and manufacturing techniques for strategic and tactical systems to reduce costs, schedule, and increase performance. - Next Gen Platform Dev/Demo: Supports the nuclear enterprise and nuclear deterrence through advanced component and technology demonstrations. - Flight Vehicle Tech Integration: Develops and demonstrates aerospace vehicle technology to enhance the capability of current and future aerospace systems with current focus on autonomous collaborative platform capabilities. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603211F / Aerospace Technology Dev/Demo Technology Development (ATD) - Aircraft Propulsion Subsystems Integration: Develops and demonstrates propulsion technology to increase warfighting capability by advancing engine operational reliability and durability, providing mission flexibility, and improved performance while reducing weight, fuel consumption, and cost of ownership. - High-Speed Systems Integration and Demonstration: Develops, demonstrates, and integrates high-speed propulsion capability (to include hypersonic) propulsion, vehicle, and subsystems to enhance and enable high-speed system technology, increasing long range strike capabilities at the speed of critical warfighting capabilities required for near peer competition. - Flight Systems Control: Develops and demonstrates adaptive power and thermal management components, controls and systems for high-power payloads enabling aerospace systems to deliver strike capabilities while integrating autonomy and control technologies to enable affordable mass in the fight and revolutionary autonomous collaborative platform capabilities. In FY 2025, the RDT&E Budget Activity 03 (BA03) Aerospace Propulsion and Power Technology efforts and activities under PE 0603216F, were transferred to PE 0603211F, Aerospace Technology Dev/Demo for increased integration between airframe, flight control, propulsion, electrical, power and thermal management. In FY 2025, the entirety of PE 0603216F, Aerospace Propulsion and Power Technology, Project 633035 Aerospace Power Technology, was transferred to PE 0603211F, Aerospace Technology Dev/Demo, Project 634927 Flight Systems Control. In FY 2025, the entirety of PE 0603216F, Aerospace Propulsion and Power Technology, Project 634093 Missile Rocket Propulsion Integ & Demo, was transferred to PE 0603211F, Aerospace Technology Dev/Demo, Project 634093 Missile Rocket Propulsion Integ & Demo. In FY 2025, the entirety of PE 0603216F, Aerospace Propulsion and Power Technology, Project 634921 Aircraft Propulsion Subsystems Int, was transferred to PE 0603211F, Aerospace Technology Dev/Demo, Project 634921 Aircraft Propulsion Subsystems Int. In FY 2025, the entirety of PE 0603216F, Aerospace Propulsion and Power Technology, Project 635098 Advanced Aerospace Propulsion, was transferred to PE 0603211F, Aerospace Technology Dev/Demo, Project 634926 High-Speed Systems Integ & Demo. Efforts in this program have been coordinated through the Department of Defense (DoD) Science and Technology (S&T) Executive Committee process to harmonize efforts and eliminate duplication. This program element may include necessary civilian pay expenses required to manage, execute, and deliver science & technology (S&T) capabilities. The use of program funds in this program element would be in addition to the civilian pay expenses budgeted in program elements 0601102F, 0602020, 0602102F, 0602202F,0602203F, 0602204F, 0602602F, 0602605F, 0602788F, 0602298F, and 1206601SF. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology (S&T) capabilities. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603211F / Aerospace Technology Dev/Demo Technology Development (ATD) The FY 2026 request was reduced by $0.240 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment.$$, NULL, 291636000, 312842000, 236485000, NULL, NULL, 20, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 75627000, 264439000, 260212000, 260212000, 0, 260212000, 183228000, $$This program supports Department of War (DoW) priorities for Aerospace Systems demonstrations to include high-speed systems and autonomous collaborative platforms through integration by design and starting with desired mission effect to deliver war winning capabilities to defend the homeland, provide nuclear deterrence, and deliver force projection. System level integration and demonstration of advanced aerospace system and weapon technologies (autonomy, propulsion, power and thermal, air vehicle, fuels, etc.) in a near-realistic operational environment to enhance the performance and supportability of existing and future aerospace systems while reducing the risk and time required to transition technologies into operational platforms. Additionally, this program supports the nuclear enterprise and nuclear deterrence through advanced components and technology demonstrations. -The program focuses on technologies with a high potential to enhance the performance of existing and future Air Force weapon systems via modeling, simulation, and analysis while utilizing digital engineering to accelerate and enhance S&T development. -Missile Rocket Propulsion Integration and Demonstration: Develops and demonstrates innovative rocket propulsion technologies, propellants, and manufacturing techniques for strategic and tactical systems to reduce costs, schedule, and increase performance. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603211F / Aerospace Technology Dev/Demo Technology Development (ATD) -Flight Vehicle Tech Integration: Develops and demonstrates aerospace platform technology to enhance the capability of current and future aerospace systems with focus on scalable modular scalable unmanned autonomous systems and affordable mass capabilities. -Aircraft Propulsion Subsystems Integration: Develops and demonstrates propulsion technology to increase warfighting capability by advancing engine operational reliability and durability, providing mission flexibility, and improved performance while reducing weight, fuel consumption, and cost of ownership. -High-Speed Systems Integration and Demonstration: Develops, demonstrates, and integrates high-speed and hypersonic propulsion, vehicle, and subsystem technologies to enhance and enable high-speed systems, increasing long range strike and Intelligence, Surveillance and Reconnaissance (ISR) capabilities at the speed required for air warfare. Work is focused on enabling scalable and affordable, exquisite, and response strike hypersonic capabilities. -Flight Systems Control: Develops and demonstrates adaptive power and thermal management components, controls and systems for high-power payloads enabling aerospace systems to deliver strike capabilities while integrating autonomy and control technologies to enable affordable mass in the fight and revolutionary autonomous collaborative platform capabilities. The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game changing S&T. Funds in this PE may be used to investigate specified technology advancements in air, space and/or cyber domains. In order to manage, execute, and deliver science and technology capabilities, this program element may include: necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology (S&T) capabilities. The FY2027 funding request was reduced by 3.400 million to account for the availability of prior year execution balances. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603211F / Aerospace Technology Dev/Demo Technology Development (ATD)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603216N$$, $$Aviation Survivability$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 24064000, 20490000, 23115000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 27, "original_pe": "0603216N", "page_header": "Department of the Navy"}$$::jsonb, $$Aviation Survivability addresses the issues of aircrew and platform survivability, focusing on enhancing overall opportunity for aircrew and platform protection and enhanced performance. The capabilities addressed under this program element counter emerging threats of next generation operational weapons systems and enhance combat effectiveness in future operational mission scenarios. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under ADVANCED COMPONENT DEVELOPMENT AND PROTOTYPES because it includes all efforts necessary to evaluate integrated technologies, representative models or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 18178000, 18428000, 18334000, NULL, NULL, 30, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 22877000, 24064000, 20010000, 20010000, NULL, 20010000, 18817000, $$Aviation Survivability addresses the issues of aircrew and platform survivability, focusing on enhancing overall opportunity for aircrew and platform protection and enhanced performance. The capabilities addressed under this program element counter emerging threats of next generation operational weapons systems and enhance combat effectiveness in future operational mission scenarios. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under ADVANCED COMPONENT DEVELOPMENT AND PROTOTYPES because it includes all efforts necessary to evaluate integrated technologies, representative models or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603239N$$, $$(U)NAVAL CONSTRUCTION FORCES$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 8603000, 7769000, 7866000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 27, "original_pe": "0603239N", "page_header": "Department of the Navy"}$$::jsonb, $$Project 3444 directly supports Joint Force resiliency in accordance with the National Defense Strategy (NDS), A Design for Maintaining Maritime Superiority 2.0, and Distributed Maritime Logistics Operations by addressing capability gaps within the Naval Construction Force (NCF) to support Joint Operations in a contested environment. Project 3444 invests in technologies that enable capabilities such as Expeditionary Rapid Airfield Damage Repair (ExRADR), Expeditionary Port Damage Repair and Opening (ExPDRO), Advanced Naval Base (ANB) Construction, Expeditionary Ordnance Re-load (ExOR), Expeditionary Fuel Storage and Distribution (ExFUEL), and Expeditionary Force Sustainment in a contested l environment. Future changes to NCF capabilities, organization, and table of allowance material are required to support new warfighting concepts and operational plans. Further, mobile infrastructure repair capabilities are envisioned to supplement these vulnerable fixed airfield and port infrastructure assets. This program provides for investment in technologies, materials, and process solutions to improve logistics resiliency and enhance Expeditionary Navy performance in the following portfolio areas; ExRADR, ExPDRO, ANB Construction, and Advanced Manufacturing (AdvM). Investments that facilitate ExRADR include autonomous airfield inspection and survey; autonomous airfield damage repair construction equipment integration, testing, and evaluation; and test and evaluation of Joint Capability Technology Demonstration (JCTD) products. Additional investments that facilitate ExPDRO include expeditionary dredge research; quay wall repair techniques and technologies; expeditionary mooring and fendering systems; port assessment sensor package integration for port engineering reconnaissance and assessment; floating work platform family of systems (FoS) integration to support dredging, pile driving, and waterfront construction; development, testing, and evaluation of diving tools and equipment to support underwater construction; and integration, testing, and evaluation of remote-controlled, semi-autonomous, and full-autonomous engineering surveying and construction equipment capabilities. Investments in AdvM includes the developmental and prototyping efforts for a forward deployable family of AdvM systems; developmental testing and evaluation; and operational testing and evaluation. Development of ANB Construction materials and equipment will maximize agility and resiliency while reducing the demand on logistics during distributed maritime operations. These technologies will enable new concepts for expeditionary engineering by enhancing the Naval Construction Force's capabilities for site identification, selection, and planning; site clearing and preparation; construction activities; water purification, distribution, and management; waste water management; energy production, storage, and distribution; site operations support (including local material handling, damage repair, etc.); and site deconstruction and retrograde activities. Technologies demonstrated will provide required engineer support capability while maximizing the ability to deploy (by minimizing size and weight) and enhancing operator safety (by providing direct operator protection or allowing for remote or autonomous operation). The results of these efforts will enhance Navy force response plans, and Joint Force Commander's flexibility to deploy and employ from expeditionary airfields, as well as deliver and sustain warfighting capabilities at the point of effect. This includes "right size, just-in-time" technologies that can facilitate both conventional and autonomous rapid assessment, repair, and re-constitution of expeditionary airfields. These efforts to develop technologies supporting NCF's ExPDRO capabilities include just-in-time assessment and rapid repair of piers, quay- walls, fleet moorings, critical expeditionary waterfront facilities and infrastructure, and port facilities Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                   Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced            PE 0603239N / (U)NAVAL CONSTRUCTION FORCES Component Development & Prototypes (ACD&P) above, at, and below the waterline to enable the reviving, re-armament, repair, re- fueling, re-calibration and re-constitution of fleet platforms at Sea Ports of Debarkation (SPODs) available during Major Combat Operations (MCO). Efforts involves transitioning these capabilities into a program of record within an existing Table of Allowance (TOA) and Supports NDS requirements of Resilient and Agile Logistics and supplements the Navy's ExRADR Program of DMO 38-Operational Logistics allowing dynamic operational maneuverability with both fixed and mobile logistics.$$, NULL, 7572000, 7612000, 7618000, NULL, NULL, 31, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 7563000, 13102000, 7726000, 7726000, NULL, 7726000, 7761000, $$Project 3444 directly supports Joint Force resiliency in accordance with the National Defense Strategy (NDS), A Design for Maintaining Maritime Superiority 2.0, and Distributed Maritime Logistics Operations by addressing capability gaps within the Naval Construction Force (NCF) to support Joint Operations in a contested environment. Project 3444 invests in technologies that enable capabilities such as Expeditionary Rapid Airfield Damage Repair (ExRADR), Expeditionary Port Damage Repair and Opening (ExPDRO), Advanced Naval Base (ANB) Construction, Expeditionary Ordnance Re-load (ExOR), Expeditionary Fuel Storage and Distribution (ExFUEL), and Expeditionary Force Sustainment in a contested l environment. Future changes to NCF capabilities, organization, and table of allowance material are required to support new warfighting concepts and operational plans. Further, mobile infrastructure repair capabilities are envisioned to supplement these vulnerable fixed airfield and port infrastructure assets. This program provides for investment in technologies, materials, and process solutions to improve logistics resiliency and enhance Expeditionary Navy performance in the following portfolio areas; ExRADR, ExPDRO, ANB Construction, and Advanced Manufacturing (AdvM). Investments that facilitate ExRADR include autonomous airfield inspection and survey; autonomous airfield damage repair construction equipment integration, testing, and evaluation; and test and evaluation of Joint Capability Technology Demonstration (JCTD) products. Additional investments that facilitate ExPDRO include expeditionary dredge research; quay wall repair techniques and technologies; expeditionary mooring and fendering systems; port assessment sensor package integration for port engineering reconnaissance and assessment; floating work platform family of systems (FoS) integration to support dredging, pile driving, and waterfront construction; development, testing, and evaluation of diving tools and equipment to support underwater construction; and integration, testing, and evaluation of remote-controlled, semi-autonomous, and full-autonomous engineering surveying and construction equipment capabilities. Investments in AdvM includes the developmental and prototyping efforts for a forward deployable family of AdvM systems; developmental testing and evaluation; and operational testing and evaluation. Development of ANB Construction materials and equipment will maximize agility and resiliency while reducing the demand on logistics during distributed maritime operations. These technologies will enable new concepts for expeditionary engineering by enhancing the Naval Construction Force's capabilities for site identification, selection, and planning; site clearing and preparation; construction activities; water purification, distribution, and management; waste water management; energy production, storage, and distribution; site operations support (including local material handling, damage repair, etc.); and site deconstruction and retrograde activities. Technologies demonstrated will provide required engineer support capability while maximizing the ability to deploy (by minimizing size and weight) and enhancing operator safety (by providing direct operator protection or allowing for remote or autonomous operation). The results of these efforts will enhance Navy force response plans, and Joint Force Commander's flexibility to deploy and employ from expeditionary airfields, as well as deliver and sustain warfighting capabilities at the point of effect. This includes "right size, just-in-time" technologies that can facilitate both conventional and Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                   Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced             PE 0603239N / (U)NAVAL CONSTRUCTION FORCES Component Development & Prototypes (ACD&P) autonomous rapid assessment, repair, and re-constitution of expeditionary airfields. These efforts to develop technologies supporting NCF's ExPDRO capabilities include just-in-time assessment and rapid repair of piers, quay- walls, fleet moorings, critical expeditionary waterfront facilities and infrastructure, and port facilities above, at, and below the waterline to enable the reviving, re-armament, repair, re- fueling, re-calibration and re-constitution of fleet platforms at Sea Ports of Debarkation (SPODs) available during Major Combat Operations (MCO). Efforts involves transitioning these capabilities into a program of record within an existing Table of Allowance (TOA) and Supports NDS requirements of Resilient and Agile Logistics and supplements the Navy's ExRADR Program of DMO 38-Operational Logistics allowing dynamic operational maneuverability with both fixed and mobile logistics.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603254N$$, $$ASW Systems Development$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 18904000, 16691000, 20033000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 27, "original_pe": "0603254N", "page_header": "Department of the Navy"}$$::jsonb, $$Includes RDT&E funds for advanced development and developmental testing of airborne Anti-Submarine Warfare (ASW) systems including aircraft, equipment, and devices for use against all types of submarine targets. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under ADVANCED COMPONENT DEVELOPMENT AND PROTOTYPES because it includes all efforts necessary to evaluate integrated technologies, representative models or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 19230000, 19550000, 19747000, NULL, NULL, 32, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 18058000, 33384000, 20070000, 20070000, NULL, 20070000, 20093000, $$Includes RDT&E funds for advanced development and developmental testing of airborne Anti-Submarine Warfare (ASW) systems including aircraft, equipment, and devices for use against all types of submarine targets. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under ADVANCED COMPONENT DEVELOPMENT AND PROTOTYPES because it includes all efforts necessary to evaluate integrated technologies, representative models or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603260F$$, $$Intelligence Advanced Development$$, $$rdte_af_ba4$$, $$acc$$, 2026, 3901000, 6977000, 3820000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0603260F"}$$::jsonb, $$Intelligence Advanced Development (IAD) develops and demonstrates technology required to support warfighter needs for timely, all-source intelligence information. IAD supports global awareness, consistent battlespace knowledge, and the execution of time-critical missions. IAD focuses on enhancing defense intelligence capabilities through exploration and development of innovative tools including data analytics for mining and exploitation, machine-learning, and software automation. In FY 2026, IAD provides improved on-time information to the warfighter using new and existing data sources, streamlining data analysis; thereby reducing the footprint required; and enhancing performance. IAD requirements reflect specific warfighter and intelligence organization deficiencies at the tactical and operational levels as identified and prioritized by Air Combat Command (ACC). The Air Force Research Lab, Rome Research Site, Information Intelligence Systems and Analysis Division (AFRL/RIE), then works directly with users to meet the requirements, employing evolutionary approaches and integrating finished modules directly into the field. This PE expedites technology transition from the laboratory to operational users via rapid prototyping. IAD may also reallocate existing resources to support out-of-cycle new/updated warfighter requirements. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0.226M was expended for civilian pay expenses in this program element, and in FY 2025 $0.142M is forecasted for civilian pay expenses in this program element. This PE received $740K Ukraine Supplemental Funds in FY 2024. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                              Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0603260F / Intelligence Advanced Development Component Development & Prototypes (ACD&P)$$, NULL, 4156000, 4232000, 4313000, NULL, NULL, 32, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 3820000, 3901000, 4012000, 4012000, 0, 4012000, 4401000, $$Intelligence Advanced Development (IAD) develops and demonstrates technology required to support warfighter needs for timely, all-source intelligence information. IAD supports global awareness, consistent battlespace knowledge, and the execution of time-critical missions. IAD focuses on enhancing defense intelligence capabilities through exploration and development of innovative tools including data analytics for mining and exploitation, machine-learning, and software automation. In FY 2027, IAD improves the performance of warfighters and intel analysts by providing enhanced, on-time information through streamlined data analysis of new and existing sources, thereby reducing the operational footprint. IAD requirements reflect specific warfighter and intelligence organization deficiencies at the tactical and operational levels as identified and prioritized by Air Combat Command (ACC). The Air Force Research Lab, Rome Research Site, Information Intelligence Systems and Analysis Division (AFRL/RIE), then works directly with users to meet the requirements, employing evolutionary approaches and integrating finished modules directly into the field. This PE expedites technology transition from the laboratory to operational users via rapid prototyping. IAD may also reallocate existing resources to support out-of-cycle new/updated warfighter requirements. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                    Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0603260F / Intelligence Advanced Development Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603261N$$, $$Tactical Airborne Reconnaissance$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 2241000, 3721000, 3358000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 27, "original_pe": "0603261N", "page_header": "Department of the Navy"}$$::jsonb, $$This program element funds efforts to develop common technical and interoperability standards for current and future unmanned platforms, sensors, communications, and networking capabilities to achieve the required integration and interoperability of Unmanned Systems (UxS) represented in approved Naval Concept of Operations (CONOPS) in support of the Navy's Unmanned Campaign Framework. This program is funded under ADVANCED COMPONENT DEVELOPMENT AND PROTOTYPES because it includes all efforts necessary to evaluate integrated technologies and representative models or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 3178000, 2949000, 2982000, NULL, NULL, 33, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 3358000, 2241000, 3239000, 3239000, NULL, 3239000, 3035000, $$This program element funds efforts to develop common technical and interoperability standards for current and future unmanned platforms, sensors, communications, and networking capabilities to achieve the required integration and interoperability of Unmanned Systems (UxS) represented in approved Naval Concept of Operations (CONOPS) in support of the Navy's Unmanned Campaign Framework. This program is funded under ADVANCED COMPONENT DEVELOPMENT AND PROTOTYPES because it includes all efforts necessary to evaluate integrated technologies and representative models or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1506_L015$$, $$E-2D AHE$$, $$proc_navy_1506_ba1$$, $$peo_aasm$$, 2026, 1503556000, 571100000, 95219000, NULL, $${"page": 58, "ba_num": "01", "source": "p1_fy26", "ba_name": "Combat aircraft", "line_no": "15", "service": "navy", "fy24_qty": 2, "fy25_qty": null, "fy27_v24": {"ba": "01", "appr": "APN", "title": "P-1 Line 11", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/APN_BA1-4_Book.pdf + APN_BA5_Book.pdf + APN_BA6-7_Book.pdf", "fy27_base_K": 2075025, "p1_line_num": 11, "fy27_total_K": 2075025}, "appr_code": "1506", "appr_name": "Aircraft Procurement, Navy", "fy26_v179": {"note": "no_parser_pair", "source": "p40_fy26_v179"}, "fy26t_qty": 4, "fy26d_cost": 1503556000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, 24727920000, NULL, NULL, NULL, FALSE, 95219000, 1100800000, 2075025000, 2075025000, 0, 2075025000, NULL, NULL, $$Budget J-Books/FY27/Navy/APN_BA1-4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603270F$$, $$Electronic Combat Technology$$, $$rdte_af_ba3$$, $$afrl_ry$$, 2026, 0, 30543000, 36445000, NULL, $${"ba_raw": "6.3", "source": "af_r1_fy26", "original_pe": "0603270F"}$$::jsonb, $$This program develops and demonstrates technologies to support Air Force electronic combat warfighting capabilities. The program focuses on developing components, subsystems, and technologies with potential aerospace, special operations, and airlift electronic combat applications. It develops and demonstrates technologies for integrating electronic combat sensors and systems into a fused and seamless whole. It integrates and focuses research efforts in electronic warfare and cyber warfare to rapidly demonstrate a capability for rapid fielding. It develops and demonstrates technologies for navigation and timing in radio frequency (RF) contested and denied environments. It develops and demonstrates advanced technologies for radio frequency electronic combat suites and advanced warning and countermeasure technologies to defeat electro-optical, infrared, and laser threats to aerospace platforms. It also develops and demonstrates technologies that will enable mission systems to be more resilient, agile, autonomous, and be able to operate in multiple domains. This program has been coordinated through the Department of Defense (DoD) Science and Technology (S&T) Executive Committee process to harmonize efforts and eliminate duplication. In order to manage, execute, and deliver science and technology capabilities, this program element may include: necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. In FY 2026, in order to better plan, execute, and demonstrate integrated sensing and spectrum dominance technologies/capabilities, funding and technical work was transferred from this program into Program Element 0603203F, Advanced Aerospace Sensors, Project 63665A, Advanced Aerospace Sensors Technology. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                    Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603270F / Electronic Combat Technology Technology Development (ATD)$$, NULL, 0, 0, 0, NULL, NULL, 22, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 34654000, 0, 0, 0, 0, 0, 0, $$This program develops and demonstrates technologies to support Air Force electronic combat warfighting capabilities. The program focuses on developing components, subsystems, and technologies with potential aerospace, special operations, and airlift electronic combat applications. It develops and demonstrates technologies for integrating electronic combat sensors and systems into a fused and seamless whole. It integrates and focuses research efforts in electronic warfare and cyber warfare to rapidly demonstrate a capability for rapid fielding. It develops and demonstrates technologies for navigation and timing in radio frequency (RF) contested and denied environments. It develops and demonstrates advanced technologies for radio frequency electronic combat suites and advanced warning and countermeasure technologies to defeat electro-optical, infrared, and laser threats to aerospace platforms. It also develops and demonstrates technologies that will enable mission systems to be more resilient, agile, autonomous, and be able to operate in multiple domains. This program has been coordinated through the Department of War (DoW) Science and Technology (S&T) Executive Committee process to harmonize efforts and eliminate duplication. In order to manage, execute, and deliver science and technology capabilities, this program element may include: necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, information technology hardware, software and support, administrative contractor services, etc. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                    Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603270F / Electronic Combat Technology Technology Development (ATD)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603273F$$, $$Science & Technology for Nuclear Re-entry Systems$$, $$rdte_af_ba3$$, $$afnwc$$, 2026, 128407000, 65088000, 91885000, NULL, $${"ba_raw": "6.3", "source": "af_r1_fy26", "original_pe": "0603273F"}$$::jsonb, $$The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain science and technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Forces to win the future fight. The AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This program oversees the engineering and demonstration of advanced Department of Air Force nuclear delivery system components and technologies that support integrated nuclear deterrence operations missions. Next Generation Platform Development/Demonstration efforts are accomplished through the design, development, integration, experimentation, and evaluation of specific technologies which will enable future delivery of multiple Government Reference Designs and Government Reference Vehicles. These technologies include aeroshell modeling and re-entry system materials manufacturing; fuzing technologies for improved system trajectory performance; advanced guidance, navigation, and control systems; strategic radiation-hardened communications in representative operational nuclear environments; and the integration, experimentation, and evaluation with respect to specialized nuclear expertise and infrastructure. This program supports Department of Defense priorities to revitalize enduring nuclear deterrence operations by modernizing and demonstrating the specialized expertise, infrastructure, and technologies necessary to address, and respond to, current and emerging multi-peer-contested nuclear environments. This effort will develop the advanced technologies necessary to effectively address peer threats and maintain operational effectiveness in a cost-effective manner by reducing technical and programmatic risks associated with the execution of collective nuclear modernization activities. Program Element 0603211F, Project 634094, was realigned into this Program Element 0603273F, Project 634094, to enhance transparency and traceability of the Nuclear Science & Technology portfolio. This program element may include necessary expenses to support operation and maintenance activities to manage, execute, and deliver science and technology capabilities. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603273F / Science & Technology for Nuclear Re-entry Systems Technology Development (ATD) This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment.$$, NULL, 170401000, 173808000, 177315000, NULL, NULL, 23, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 85661000, 141569000, 165949000, 165949000, 0, 165949000, 180906000, $$This program oversees the engineering and demonstration of advanced Department of the Air Force (DAF) Nuclear Delivery System (NDS) components and technologies that support integrated Nuclear Deterrence Operations (NDO) missions. This work is achieved through foundational science, development of technologies, sub-scale validation and testing, and full-scale flight testing of re-entry system components. The Next-Generation Platform Development/Demonstration project encompasses the design, development, integration, experimentation, and evaluation of specific technologies that will enable the future delivery of multiple Government Reference Designs (GRDs) and Government Reference Vehicles (GRVs) comprised of various technology suites. These technologies include advanced aeroshell modeling and re-entry system materials development; fuzing technologies for improved system trajectory performance; advanced guidance, navigation, and control (GNC) systems; strategic radiation-hardened communications in representative operational nuclear environments; the development of specialized nuclear science and technology (S&T) expertise; and the Integration, Experimentation, and Evaluation (IE&E) of technologies through infrastructure developments. Collectively, these efforts will produce various testbeds that enable relevant environment characterizations for DAF nuclear re-entry vehicles and their sub-systems. This program requires close DAF and Department of Energy (DOE) interagency coordination to ensure informed and rapid nuclear re-entry system technology maturation and transitions. This program supports Department of War (DOW) priorities to revitalize enduring nuclear deterrence operations by modernizing and demonstrating the specialized infrastructure and technologies necessary to address, and respond to, current and emerging multi-peer-contested nuclear threats while also developing specialized expertise to continuously execute this work. This effort will develop the advanced technologies necessary to effectively address multi-peer threats and maintain operational effectiveness in a cost-effective manner by reducing technical and programmatic risks associated with the execution of collective nuclear modernization activities. This program is accomplished by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain S&T solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the DAF S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. Funds in this PE may be used to investigate specified technology advancements in air, space and/or cyber domains. To manage, execute, and deliver S&T capabilities, this PE may include necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; and expenses related to travel, supplies, IT hardware, software and support, etc. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603273F / Science & Technology for Nuclear Re-entry Systems Technology Development (ATD) This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603273N$$, $$Science & Technology for Nuclear Re-entry Systems$$, $$rdte_navy_ba3$$, $$onr$$, 2026, 121618000, 109226000, 118624000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "navy", "page_num": 27, "original_pe": "0603273N", "page_header": "Department of the Navy"}$$::jsonb, $$This Program Element supports Department of Defense (DoD) priorities for enduring science and technology (S&T) for nuclear re-entry systems. For several decades, foundational nuclear R&D investments outside of major acquisition programs have been significantly reduced. This historical trend contrasts with the DoD's recent recognition of the need to invest in advanced nuclear-related components and technologies in support of the nuclear enterprise, nuclear deterrence operations, and integrated deterrence operations. This effort will provide pre-program of record advanced technology development that will effectively address evolving threats and maintain operational effectiveness while also aligning with the highest-level guidance for nuclear forces identified in the 2022 Nuclear Posture Review and National Defense Strategy. This effort will contribute to preserving the viability of the nuclear deterrent in a cost-effective manner by reducing technical and programmatic risk associated with execution of the overall nuclear modernization program. These ends will be reached by developing technologies to inform future system requirements, establishing interagency partnerships for re-entry system test platform development, and coordinating with existing programs for next generation strategic system development. In conjunction with U.S. Strategic Command (STRATCOM) Priorities and collaboration with Air Force, the Nuclear Delivery Systems (NDS) funding will identify and mature technologies from Technology Readiness Level (TRL) 3 to TRL 6 via relevant ground and flight test environments.$$, NULL, 116043000, 118735000, 119329000, NULL, NULL, 18, $$RDTEN_BA1-3_Book.pdf$$, NULL, FALSE, 115050000, 121618000, 114767000, 114767000, NULL, 114767000, 121516000, $$This Program Element supports Department of War (DoW) priorities for enduring science and technology (S&T) for nuclear re-entry systems. For several decades, foundational nuclear R&D investments outside of major acquisition programs have been significantly reduced. This historical trend contrasts with the DoW's recent recognition of the need to invest in advanced nuclear-related components and technologies in support of the nuclear enterprise, nuclear deterrence operations, and integrated deterrence operations. This effort will provide pre-program of record advanced technology development that will effectively address evolving threats and maintain operational effectiveness while also aligning with the highest-level guidance for nuclear forces identified in the Nuclear Posture Review and National Defense Strategy. This effort will contribute to preserving the viability of the nuclear deterrent in a cost-effective manner by reducing technical and programmatic risk associated with execution of the overall nuclear modernization program. These ends will be reached by developing technologies to inform future system requirements, establishing interagency partnerships for re-entry system test platform development, and coordinating with existing programs for next generation strategic system development. In conjunction with U.S. Strategic Command (STRATCOM) Priorities and collaboration with Air Force, the Nuclear Delivery Systems (NDS) funding will identify and mature technologies from Technology Readiness Level (TRL) 3 to TRL 6 via relevant ground and flight test environments.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA1-3_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603275A$$, $$Electronic Warfare Advanced Technology$$, $$rdte_army_ba3$$, $$devcom$$, 2026, 83922000, 0, 0, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 12, "original_pe": "0603275A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) focuses on rapidly maturing and demonstrating advanced Electromagnetic Warfare (EW) capabilities for modern, multi-domain military operations. It matures cutting-edge technologies - including architectures, infrastructure, tools, and techniques - across the spectrum of EW activities: Electronic Attack (EA) to disrupt enemy Command, Control, Computing, Communications, Cyber, Intelligence, Surveillance, and Targeting (C-C5ISR&T) systems and ensure non- kinetic survivability; Electronic Support (ES) for precise detection, identification, and geolocation of enemy RF emissions to enable effective fires; Electronic Protection (EP) to bolster the resiliency and robustness of Army systems against increasingly sophisticated electronic attacks; battle management tools for intelligent planning, targeting, and execution of effects across the entire electromagnetic spectrum; and position, navigation, and timing techniques to enable coordination of electronic attacks. This PE aims to deliver a comprehensive and integrated EW suite that not only ensures our forces maintain a decisive advantage in the contested electromagnetic environment, but also creates novel opportunities for operational advantage, increasing unit survivability, maneuverability, and the effective employment of non-kinetic effects in highly contested and congested spaces. Work in this PE complements PE 0602275A (Electronic Warfare Applied Research). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy.$$, NULL, 115703000, 110391000, 107270000, NULL, NULL, 46, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, NULL, 85922000, 156326000, 156326000, NULL, 156326000, 100905000, $$This PE focuses on rapidly maturing and demonstrating advanced Electromagnetic Warfare (EW) capabilities for modern, multi-domain military operations. It matures cutting-edge technologies - including architectures, infrastructure, tools, and techniques - across the spectrum of EW activities: Electronic Attack (EA) to disrupt enemy Command, Control, Computing, Communications, Cyber, Intelligence, Surveillance, and Targeting (C-C5ISR&T) systems and ensure non- kinetic survivability; Electronic Support (ES) for precise detection, identification, and geolocation of enemy RF emissions to enable effective fires; Electronic Protection (EP) to bolster the resiliency and robustness of Army systems against increasingly sophisticated electronic attacks; battle management tools for intelligent planning, targeting, and execution of effects across the entire electromagnetic spectrum; and position, navigation, and timing techniques to enable coordination of electronic attacks. This PE aims to deliver a comprehensive and integrated EW suite that not only ensures our forces maintain a decisive advantage in the contested electromagnetic environment, but also creates novel opportunities for operational advantage, increasing unit survivability, maneuverability, and the effective employment of non-kinetic effects in highly contested and congested spaces. Work in this PE complements PE 0602275A (Electronic Warfare Applied Research). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced         PE 0603275A / Electronic Warfare Advanced Technology Technology Development (ATD) The cited research is consistent with the Under Secretary of War (Research and Engineering) priority focus areas and the Army modernization strategy.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603276A$$, $$Electronic Warfare Cyber Advanced Technology$$, $$rdte_army_ba3$$, $$devcom_c5isr$$, 2026, 15254000, 0, 0, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 12, "original_pe": "0603276A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) matures and demonstrates architectures, technologies, techniques, components, and tools to enhance Cyber and Electromagnetic Activities (CEMA) for Multi-Domain Joint Operations in tactical environments. These efforts aim to counter the adversary's Command, Control, Computing, Communications, Cyber, Intelligence, Surveillance, and Targeting (C-C5ISR&T) capabilities and plan, target, execute Cyber effects through the employment of non-traditional access and effect vectors against adversarial systems, communication networks, and decision centers to reduce the adversary's ability to execute command and control of its forces. Additionally, these efforts will protect tactical wired and wireless networks against modern cyber-attacks, focusing on configuration, operation, monitoring, data integrity, and defense in bandwidth constrained tactical environments while reducing the operator workload required to conduct these functions. This PE will mature and demonstrate key technologies that create windows of opportunity to provide significant operational advantage over adversaries. It will increase unit survivability and maneuverability and enhance the employment of non-kinetic effects in highly contested and congested electromagnetic environments. Work in this PE complements PE 0602376A (Electronic Warfare Cyber Applied Research). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                         Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced       PE 0603276A / Electronic Warfare Cyber Advanced Technology Technology Development (ATD)$$, NULL, 15204000, 10375000, 10485000, NULL, NULL, 47, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, NULL, 15254000, 15278000, 15278000, NULL, 15278000, 10589000, $$This Program Element (PE) matures and demonstrates architectures, technologies, techniques, components, and tools to enhance Cyber and Electromagnetic Activities (CEMA) for Multi-Domain Joint Operations in tactical environments. These efforts aim to counter the adversary's Command, Control, Computing, Communications, Cyber, Intelligence, Surveillance, and Targeting (C-C5ISR&T) capabilities and plan, target, execute Cyber effects through the employment of non-traditional access and effect vectors against adversarial systems, communication networks, and decision centers to reduce the adversary's ability to execute command and control of its forces. Additionally, these efforts will protect tactical wired and wireless networks against modern cyber-attacks, focusing on configuration, operation, monitoring, data integrity, and defense in bandwidth constrained tactical environments while reducing the operator workload required to conduct these functions. This PE will mature and demonstrate key technologies that create windows of opportunity to provide significant operational advantage over adversaries. It will increase unit survivability and maneuverability and enhance the employment of non-kinetic effects in highly contested and congested electromagnetic environments. Work in this PE complements PE 0602376A (Electronic Warfare Cyber Applied Research). The cited research is consistent with the Under Secretary of War for Research and Engineering priority focus areas and the Army modernization strategy. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced          PE 0603276A / Electronic Warfare Cyber Advanced Technology Technology Development (ATD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603286E$$, $$ADVANCED AEROSPACE SYSTEMS$$, $$rdte_dw_ba3$$, $$dw_darpa$$, 2026, 0, 239289000, 252018000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 68, "original_pe": "0603286E", "page_header": "Defense-Wide"}$$::jsonb, $$The efforts described in this Program Element (PE) address the Advanced Technology Development associated with the Advanced Aerospace Systems Program that is focused on exploiting high pay-off opportunities to provide revolutionary new system capabilities, as opposed to incremental or evolutionary advancements, in order to achieve undeterrable air presence at dramatically reduced costs. Rapid prototyping and experimentation of integrated system concepts, as well as enabling vehicle subsystems will be conducted. Programs will explore new architectural concepts that employ a mix of weapon technologies that achieve lethality through a combination of overwhelming performance and overwhelming numbers rather than through the use of singular and costly high value assets. Studies conducted under this program element include examination and evaluation of emerging aerospace threats, technologies, concepts, use of autonomy to minimize risk, and applications for missiles, munitions, and vehicle systems. Beginning in FY 2026, efforts in this PE will be funded in PE 0603468E, Advanced Complex Systems.$$, NULL, 0, 0, 0, NULL, NULL, 46, $$RDTE_Vol1_DARPA_MasterJustificationBook_PB_2026.pdf$$, $$DARPA$$, FALSE, 241495000, 0, 0, 0, NULL, 0, 0, $$The efforts described in this Program Element (PE) address the Advanced Technology Development associated with the Advanced Aerospace Systems Program that is focused on exploiting high pay-off opportunities to provide revolutionary new system capabilities, as opposed to incremental or evolutionary advancements, in order to achieve undeterrable air presence at dramatically reduced costs. Rapid prototyping and experimentation of integrated system concepts, as well as enabling vehicle subsystems will be conducted. Programs will explore new architectural concepts that employ a mix of weapon technologies that achieve lethality through a combination of overwhelming performance and overwhelming numbers rather than through the use of singular and costly high value assets. Studies conducted under this program element include examination and evaluation of emerging aerospace threats, technologies, concepts, use of autonomy to minimize risk, and applications for missiles, munitions, and vehicle systems. Beginning in FY 2026, efforts in this PE will be funded in PE 0603468E, Advanced Complex Systems.$$, $$Budget J-Books/FY27/DW/RDTE_Vol1_DARPA_MasterJustificationBook_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603287E$$, $$SPACE PROGRAMS AND TECHNOLOGY$$, $$rdte_dw_ba3$$, $$dw_darpa$$, 2026, 0, 119125000, 181498000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 68, "original_pe": "0603287E", "page_header": "Defense-Wide"}$$::jsonb, $$The efforts described in this Program Element (PE) address the Advanced Technology Development associated with the Space Programs and Technology Program that addresses high payoff opportunities to dramatically reduce costs associated with advanced space systems and provides revolutionary new system capabilities for satisfying current and projected military missions. A space force structure that is robust against attack represents a stabilizing deterrent against adversary attacks on space assets. This program element will examine concepts and architectures that move the U.S. away from a dependence on monolithic, ultra-capable, vulnerable, and unsustainably costly assets; replacing them with disaggregated assets that are agile, affordable, and easily replaced. Ready access to space requires the delivery of capabilities, replenishment of supplies into orbit, and rapid manufacturing of affordable space capabilities. In addition, developing space access and spacecraft servicing technologies will lead to reduced ownership costs of space systems and new opportunities for introducing technologies for the exploitation of space. Systems development is also required to increase the interactivity and functionality of space systems, space-derived information, and services with terrestrial users. Studies under this program element include technologies and systems that will enable satellites and microsatellites to operate more effectively by increasing maneuverability, survivability, and situational awareness, and precision control of multi-payload systems. Studies will actively seek to take advantage of new commercial developments which may enable both rapid constitution/reconstitution of assets, and agility/functionality not previously available for military systems. Beginning in FY 2026, efforts in this PE will be funded in PE 0603468E, Advanced Complex Systems. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                          Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:            PE 0603287E / SPACE PROGRAMS AND TECHNOLOGY Advanced Technology Development (ATD)$$, NULL, 0, 0, 0, NULL, NULL, 47, $$RDTE_Vol1_DARPA_MasterJustificationBook_PB_2026.pdf$$, $$DARPA$$, FALSE, 175105000, 0, 0, 0, NULL, 0, 0, $$The efforts described in this Program Element (PE) address the Advanced Technology Development associated with the Space Programs and Technology Program that addresses high payoff opportunities to dramatically reduce costs associated with advanced space systems and provides revolutionary new system capabilities for satisfying current and projected military missions. A space force structure that is robust and resilient to attack represents a stabilizing deterrent against adversary attacks on space assets. This program element will examine concepts and architectures that move the U.S. away from a dependence on monolithic, ultra-capable, vulnerable, and unsustainably costly assets; replacing them with disaggregated assets that are agile, affordable, and easily replaced. Ready access to space requires the delivery of capabilities, replenishment of supplies into orbit, and rapid manufacturing of affordable space capabilities. In addition, developing space access and spacecraft servicing technologies will lead to reduced ownership costs of space systems and new opportunities for introducing technologies for the exploitation of space. Systems development is also required to increase the interactivity and functionality of space systems, space-derived information, and services with terrestrial users. Studies under this program element include technologies and systems that will enable satellites and microsatellites to operate more effectively by increasing maneuverability, survivability, and situational awareness, and precision control of multi-payload systems. Studies will actively seek to take advantage of new commercial developments which may enable both rapid constitution/reconstitution of assets, and agility/functionality not previously available for military systems. Beginning in FY 2026, efforts in this PE will be funded in PE 0603468E, Advanced Complex Systems. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Advanced Research Projects Agency                                            Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:             PE 0603287E / SPACE PROGRAMS AND TECHNOLOGY Advanced Technology Development (ATD)$$, $$Budget J-Books/FY27/DW/RDTE_Vol1_DARPA_MasterJustificationBook_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2031_L009$$, $$AH-64 Apache Block IIIA Reman$$, $$proc_army_2031_ba1$$, $$peo_aviation$$, 2026, 1669000, 649317000, 557399000, NULL, $${"page": 10, "ba_num": "01", "source": "p1_fy26", "ba_name": "Aircraft", "line_no": "9", "service": "army", "fy24_qty": 37, "fy25_qty": 31, "appr_code": "2031", "appr_name": "Aircraft Procurement, Army", "fy26_v178": {"disc_K": 0, "li_num": 6, "source": "p40_fy26_v178", "supp_K": 98000, "source_pdf": "uploads/Budget J-Books/FY27/Army/Aircraft_Procurement_Army.txt"}, "fy26t_qty": null, "fy26d_cost": 1669000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 98000000, 0, 0, 0, 0, NULL, NULL, $$Budget J-Books/FY27/Army/Aircraft_Procurement_Army.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603308A$$, $$Army Space Systems Integration$$, $$rdte_army_ba4$$, $$smdc$$, 2026, 83080000, 28813000, 29659000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 13, "original_pe": "0603308A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) funds the United States Army Space and Missile Defense Command (USASMDC) development activities, and employment of global space and high-altitude (SHA) capabilities to the Army, joint force, allies and partners, to enable multi-domain combat effects; enhance deterrence, assurance, and detection of strategic attacks; and protect the Nation. The USASMDC is the warfighting function lead and Department of the Army force modernization proponent for integration of current and future SHA systems to enable Army forces on the battlefield. The USASMDC workforce supports the research and doctrine development from one of the USASMDC principal locations in Huntsville, AL; Colorado Springs, CO; and Joint Base Langley-Eustis. Employing cutting-edge technology and incorporating feedback from the warfighter, the command develops critical space and high-altitude capabilities to maintain overmatch of the nation's near-peer adversaries and to deter, deny and defeat any challenge. Headquarters, Department of the Army General Order 37, dated 16 October 2006, designated USASMDC as the Army proponent for space, the Army integrator for global missile defense (GMD), and the Army Service Component Command (ASCC) of the USSTRATCOM. Army Regulation (AR) 10-87, Army Commands, Army Service Component Commands, and Direct Reporting Units, dated 4 September 2007, and AR 5-22, The Army Force Modernization Proponent System, dated 19 August 2009, designated USASMDCas the Army specified proponent for Space/High Altitude capabilities. As the Army proponent for space and high altitude, USASMDC is responsible for developing warfighting concepts, conduct warfighting experiments to validate those concepts, identify capabilities needed to implement the validated concepts, and develop Doctrine, Organizations, Training, Material, Leadership & Education, Personnel, Facilities and Policy (DOTMLPF-P) solutions. The FY 2026 request was reduced by $2.577 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.406 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                           Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced        PE 0603308A / Army Space Systems Integration Component Development & Prototypes (ACD&P)$$, NULL, 51966000, 52404000, 52528000, NULL, NULL, 61, $$RDTE - Vol 2 - Budget Activity 4A.pdf$$, NULL, FALSE, 32132000, 92580000, 59573000, 59573000, NULL, 59573000, 53049000, $$This Program Element (PE) funds the United States Army Space and Missile Defense Command (USASMDC) development activities, and employment of global space and high-altitude (SHA) capabilities to the Army, joint force, allies and partners, to enable multi-domain combat effects; enhance deterrence, assurance, and detection of strategic attacks; and protect the Nation. The USASMDC is the warfighting function lead and Department of the Army force modernization proponent for integration of current and future SHA systems to enable Army forces on the battlefield. The USASMDC workforce supports the research and doctrine development from one of the USASMDC principal locations in Huntsville, AL; Colorado Springs, CO; and Joint Base Langley-Eustis. Employing cutting-edge technology and incorporating feedback from the warfighter, the command develops critical space and high-altitude capabilities to maintain overmatch of the nation's near-peer adversaries and to deter, deny and defeat any challenge. Headquarters, Department of the Army General Order 37, dated 16 October 2006, designated USASMDC as the Army proponent for space, the Army integrator for global missile defense (GMD), and the Army Service Component Command (ASCC) of the USSTRATCOM. Army Regulation (AR) 10-87, Army Commands, Army Service Component Commands, and Direct Reporting Units, dated 4 September 2007, and AR 5-22, The Army Force Modernization Proponent System, dated 19 August 2009, designated USASMDCas the Army specified proponent for Space/High Altitude capabilities. As the Army proponent for space and high altitude, USASMDC is responsible for developing warfighting concepts, conduct warfighting experiments to validate those concepts, identify capabilities needed to implement the validated concepts, and develop Doctrine, Organizations, Training, Material, Leadership & Education, Personnel, Facilities and Policy (DOTMLPF-P) solutions.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603327A$$, $$Air and Missile Defense Systems Engineering$$, $$rdte_army_ba4$$, $$dw_mda$$, 2026, 0, 13000000, 30000000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 13, "original_pe": "0603327A", "page_header": "Department of the Army"}$$::jsonb, $$Funding in this program supports Cyber and Electromagnetic Activities (CEMA) and Deep CEMA efforts to conduct realistic assessments of Army Integrated Fires performance, identify system vulnerabilities, and develop mitigations against threats across the Cyber and Electromagnetic spectrum. Army radars and sensors, integrated air and missile defense mission command and fire control, Radio Frequency (RF) data and voice networks, and Positioning, Navigation, and Timing (PNT) technology will be assessed against current and postulated threat systems and techniques. Potential solutions developed by the Army, other Services, and Defense agencies (for example Missile Defense Agency) to close identified gaps will be demonstrated and assessed in live and simulated CEMA environments. Assessment events will be conducted approximately every two years. Implementation of potential solutions will occur between events using system-specific funding. The proposed solutions will then be assessed at the next event after implementation. Included in this line are funds to plan and execute periodic CEMA and Deep CEMA activities, in conjunction with Air and Missile Defense and Long-Range Cross Functional Teams to support the Army Integrated Fires system, to include other Service and other Agency radar and sensor systems as appropriate. Funding will be used to develop solutions to protect Army weapon systems from emerging and future CEMA threats such as advanced Electronic Warfare techniques, Radio Frequency- enabled cyber effects, use of photonics, etc. Efforts in this program will also develop tools for use by Army radar and sensor systems to improve overall system performance in contested environments, to include effects-based CEMA Modeling and Simulation (M&S) to assess Army CEMA concepts in Hardware-In-The-Loop (HWIL) environment. Additionally, virtual models of critical hardware and software are being developed and implemented to allow for destructive testing with advanced CEMA threats in a lab environment. There will be continual interface with intelligence communities to maintain cognizance of emerging CEMA threats and incorporate these threats in future CEMA demonstrations. These activities follow a time-phased roadmap that identifies the investments needed to improve the resiliency of Army radar and sensors, C2, and RF data and voice networks in contested CEMA environments. Deep CEMA efforts support assessment of quantum-based hardware, development of software algorithms, and will integrate cutting-edge technology prototypes into Army weapon systems for advanced experimentation and assessment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                        Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced      PE 0603327A / Air and Missile Defense Systems Engineering Component Development & Prototypes (ACD&P)$$, NULL, NULL, NULL, NULL, NULL, NULL, 62, $$RDTE - Vol 2 - Budget Activity 4A.pdf$$, NULL, FALSE, 30000000, 100000000, NULL, NULL, NULL, NULL, NULL, $$Funding in this program supports Cyber and Electromagnetic Activities (CEMA) and Deep CEMA efforts to conduct realistic assessments of Army Integrated Fires performance, identify system vulnerabilities, and develop mitigations against threats across the Cyber and Electromagnetic spectrum. Army radars and sensors, integrated air and missile defense mission command and fire control, Radio Frequency (RF) data and voice networks, and Positioning, Navigation, and Timing (PNT) technology will be assessed against current and postulated threat systems and techniques. Potential solutions developed by the Army, other Services, and Defense agencies (for example Missile Defense Agency) to close identified gaps will be demonstrated and assessed in live and simulated CEMA environments. Assessment events will be conducted approximately every two years. Implementation of potential solutions will occur between events using system-specific funding. The proposed solutions will then be assessed at the next event after implementation. Included in this line are funds to plan and execute periodic CEMA and Deep CEMA activities, in conjunction with Air and Missile Defense and Long-Range Cross Functional Teams to support the Army Integrated Fires system, to include other Service and other Agency radar and sensor systems as appropriate. Funding will be used to develop solutions to protect Army weapon systems from emerging and future CEMA threats such as advanced Electronic Warfare techniques, Radio Frequency- enabled cyber effects, use of photonics, etc. Efforts in this program will also develop tools for use by Army radar and sensor systems to improve overall system performance in contested environments, to include effects-based CEMA Modeling and Simulation (M&S) to assess Army CEMA concepts in Hardware-In-The-Loop (HWIL) environment. Additionally, virtual models of critical hardware and software are being developed and implemented to allow for destructive testing with advanced CEMA threats in a lab environment. There will be continual interface with intelligence communities to maintain cognizance of emerging CEMA threats and incorporate these threats in future CEMA demonstrations. These activities follow a time-phased roadmap that identifies the investments needed to improve the resiliency of Army radar and sensors, C2, and RF data and voice networks in contested CEMA environments. Deep CEMA efforts support assessment of quantum-based hardware, development of software algorithms, and will integrate cutting-edge technology prototypes into Army weapon systems for advanced experimentation and assessment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                       Date: April 2026 Appropriation/Budget Activity                                             R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced     PE 0603327A / Air and Missile Defense Systems Engineering Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603330D8Z$$, $$Quantum Application$$, $$rdte_dw_ba3$$, $$dw$$, 2026, 59521000, 19268000, 24290000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 68, "original_pe": "0603330D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Department's initiative to Build Sustainable and Long-Term Advantage. Quantum technology has reached a tipping point where current investments will determine its future impact. If the United States can stay on pace, many important outcomes for the DoD will be realized. Quantum PNT sensor technology will create robust position, navigation, and timing (PNT) for the freedom of operations having precision-strike capabilities even within contested spectrum, space, or cyber operations. Quantum radio frequency (RF) sensors will greatly enhance capabilities in the spectrum giving the DoD significant advantages for electronic warfare; command, control, and communications and intelligence, surveillance, and reconnaissance (C3ISR). Quantum computing (QC) may revolutionize DoD’s ability to develop advanced materials and potentially other computational problems. However, the transition of laboratory innovations to devices that are competitive with existing ones is hampered by immature quantum component technology and the need for specialized fabrication, integration, and packaging processes to manufacture quantum devices. This funding will identify detailed component requirements develop the most critical technology solutions. This effort will be coordinated with non-defense U.S. Government (USG) agencies to ensure their commercial viability. The resulting component supply chain will enable defense and dual-use applications of quantum technology leveraging existing resources in academic institutions, national laboratories, private industries; and other DoD programs such as Manufacturing Innovation Institutes (DoD MIIs) and the Microelectronics Commons. PNT and RF sensor technologies demonstrate substantial improvements in technical performance against their current fielded, classical counterparts. However, sustained research and development is needed to mature these technologies at the quantum system level as well as to mature the component supply chain for them. All these technologies require refinement of the concepts of operation to maximize impact to the DoD and accelerate the timelines to such impacts. Required research and development efforts are guided by OUSD(R&E) with input from the services for their technical requirements as a DoD-wide effort. These sensors are not yet at a maturity level for system integration by the services. The relative cost and workforce barrier is too high for one service or agency alone to transition this complex and emerging technology for a single mission. DoD agencies working together, however, guided by OUSD(R&E), can overcome these barriers and impact all DoD Service Departments. Initial funding to develop quantum sensor maturity was undertaken in FY2024 by the Defense Innovation Unit (DIU) through a $55M transfer from Quantum Transition Acceleration. OUSD(R&E) will continue to work with DIU as well as the services to optimize execution of the projects in the program. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                  Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:               PE 0603330D8Z / Quantum Application Advanced Technology Development (ATD) Finally, QC will likely allow rapid advances in critical DoD areas such as materials and chemistry for advanced energetics, propulsion, and platform coatings, and machine learning, but significant work is required to understand which QC application will be most relevant and available the soonest. This program will develop that application knowledge and facilitate future large impacts.$$, NULL, 60829000, 62092000, 63443000, NULL, NULL, 50, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 23401000, 58723000, 60333000, 60333000, NULL, 60333000, 61260000, $$This program supports the Department's initiative to Build Sustainable and Long-Term Advantage. Quantum technology is at a point where current investments will determine its future impact. If the United States can stay on pace, many important outcomes for the DoW will be realized. Quantum Position, Navigation, and Timing (PNT) sensor technology will create robust position, navigation, and timing (PNT) for the freedom of operations having precision-strike capabilities even within contested spectrum, space, or cyber operations. Quantum magnetometers and gravimeters may improve standoff detection of buried and submerged mines, tunnels, and other objects and structures needed to improve warfighter operations in challenging environments. Quantum radio frequency (RF) sensors will greatly enhance capabilities in the spectrum giving the DoW significant advantages for electronic warfare; command, control, and communications and intelligence, surveillance, and reconnaissance (C3ISR). Quantum computing (QC) may revolutionize DoW’s ability to develop advanced materials and potentially other computational problems. However, the transition of laboratory innovations to devices that are competitive with existing ones is hampered by immature quantum component technology and quantum lifecycle development from gaps in specialized fabrication, integration, packaging, and manufacturing processes needed to deploy quantum sensors at the functional capability and manufacturing scalability needed for deployment in future conflicts. This funding will identify detailed component and quantum lifecycle requirements develop the most critical technology solutions. This effort will be coordinated with non- defense U.S. Government (USG) agencies to ensure their commercial viability. The resulting quantum lifecycle chain will enable defense and dual-use applications of quantum technology leveraging existing resources in academic institutions, national laboratories, private industries; and other DoW programs such as Manufacturing Innovation Institutes (DoW MIIs), the Microelectronics Commons, and the Defense Innovation Unit. PNT, detection, and RF sensor technologies demonstrate substantial improvements in technical performance against their current fielded, classical counterparts. However, sustained research and development is needed to mature these technologies at the quantum system level as well as to mature their underlying components and fabricated systems to meet size, weight, power requirements and to validate their operation in the field. All these technologies require refinement of the concepts of operation to maximize impact to the DoW and accelerate the timelines to such impacts. Required research and development efforts are guided by OUSW(R&E) with input from the services for their technical requirements as a DoW-wide effort. These sensors are not yet at a maturity level for system integration by the services, but they have shown great progress under this program element. However, the relative cost and workforce barrier is too high for one service or agency alone to transition this complex and emerging technology for a single mission. DoW agencies working together, however, guided by OUSW(R&E), can overcome these barriers and impact Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                              Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:            PE 0603330D8Z / Quantum Application Advanced Technology Development (ATD) all DoW Service Departments. Initial funding to develop quantum sensor maturity was undertaken in FY 2024 by the Defense Innovation Unit (DIU) in collaboration with OUSW (R&E). This collaboration will continue, as well as with the services to optimize execution of the projects in the program.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603331D8Z$$, $$Future Generation Wireless Technologies$$, $$rdte_dw_ba3$$, $$dw$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 30468000, 32500000, 34000000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 5000000, 5000000, NULL, 5000000, 37000000, $$The Future Generation Wireless Technologies program accelerates the development, integration, and testing of 6G technologies to ensure Department of War (DoW) dominance in future operating environments. This program bridges the gap between advanced research and operational deployment by rapidly maturing and integrating commercially driven 6G advancements into military systems and concepts of operation. The program will focus on key technologies such as AI-enabled Radio Access Networks (AI RAN), Integrated Sensing and Communications (ISAC), multi-access edge computing in Non-Terrestrial Network (NTN) platforms, and native spectrum sharing. The program will enable secure, resilient, and interoperable communications; improved sensing capabilities; and AI-driven resource optimization for enhanced warfighting capabilities in contested and denied environments in the combatant command areas of responsibility with emphasis on INDOPACOM.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603342D8Z$$, $$Defense Innovation Unit (DIU)$$, $$rdte_dw_ba3$$, $$dw_diu$$, 2026, 661219000, 218589000, 199716000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 68, "original_pe": "0603342D8Z", "page_header": "Defense-Wide", "fy26_v182_disc_K": 140000, "fy26_v182_supp_K": 1735861, "fy26_v182_total_K": 1875861, "fy26_v182_note_name": "0603342D8Z", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 11720}$$::jsonb, $$On April 4, 2023, the Secretary of Defense elevated DIU as a direct report, placing the Defense Innovation Unit (DIU) under the Secretary’s authority, direction and control and provided guidance on DIU’s reporting and management structure. This change significantly increased the scope and scale of DIU’s responsibilities and authorities as reflected in the DIU 3.0 strategy. In the National Defense Authorization Act of Fiscal Year 2026, Congress elevated DIU as a Principal Staff Assistant (PSA) to the Secretary of Defense, codifying DIU as the DoD's innovation organization and advisor to the SECDEF and DEPSECDEF, and supports the Department's initiatives to build enduring advantages across the defense ecosystem - the Department of Defense, the defense industrial base, and the array of private sector enterprises and academia that create and sharpen the Joint Force’s technological edge, with a focus on innovation and rapid adjustment to new strategic demands. The DIU mission is to strengthen U.S. national security by accelerating the adoption of commercial technology throughout the military and growing the national security innovation base. DIU partners with organizations across the DoD and the interagency to rapidly prototype, field, and scale commercially derived solutions to meet the most critical operational capability gaps identified by the Department with the focus, speed, and scale required to help deter major conflict and win if forced to fight. With offices in Silicon Valley, Boston, Austin, Chicago, and the Pentagon, DIU is able to attract the best and brightest talent and cutting-edge solutions. For the Department of Defense (DoD) to effectively implement the NDS and counter the pacing challenge of China while simultaneously addressing the other strategic threats facing the nation, it must leverage commercial technology with the focus, speed, and scale necessary to deter major conflict and win if forced to fight. The Secretary of Defense’s decision to realign DIU as a direct report and empower it to provide leadership, namely through serving as the Advisor to the Secretary on commercial technology innovation and chairing the Deputy’s Innovation Working Group is a reflection of this imperative. Spurred by trillions of dollars of private investment, innovation in many critical areas of technology central to military power is proceeding at a much faster rate in the private sector than in the traditional defense sector. Progress in 11 of the 14 critical technology areas identified by the Undersecretary of Defense for Research and Engineering (R&E) is primarily led by the commercial sector, with the most cutting-edge technology more likely to occur in its research and development pathways, tested and refined through its relentless market-driven requirements. DIU strengthens the Department’s ability to rapidly prototype, acquire and field commercial technology at a pace that effectively deters our adversaries and helps ensure victory if we are forced to fight. Working across the country, and in collaboration with our allies and partners, DIU is developing new ways of doing business, growing our national security innovation base to include more "non-traditional" companies that had previously not collaborated with the military, working with traditional vendors in novel ways to increase efficiency and efficacy, and challenging innovators to share their knowledge and expertise in support of our nation's defense. Through a competitive prototype process, DIU identifies and provides access to technology companies and products on behalf of DoD partners. Additionally, DIU executes projects to leverage commercial sector technology analogous to military applications thereby increasing dual-use technology agility for the DoD. DIU funds facilitate the award of projects that can augment commercial technologies, existing government-owned capabilities, or concepts for defense application. DIU focuses on seven technology areas where commercial industry is the lead: • Artificial Intelligence (AI)/ Machine Learning (ML) – Applying AI/ML learning to accelerate critical decision making and operational impact. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                  Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:            PE 0603342D8Z / Defense Innovation Unit (DIU) Advanced Technology Development (ATD) • Autonomy – Adopting and countering autonomous systems with a focus on human-machine interaction and scalable teaming. • Cyber – Making enterprise combat information open, accessible, and secure for defense personnel across the globe. • Energy – Leveraging proven advancement in energy and materials technology to enhance capabilities and strengthen resilience across installation and distributed operations. • Human Systems – Optimizing the human system and its enabling platforms through enhanced equipment, innovative training, and novel health applications. • Space – Developing on-demand access to space, persistent satellite capabilities, and broadband space data transfer. • Emerging Technology - Focused on developing and delivering innovative quantum applications, hypersonics capabilities, and advanced material solutions.$$, NULL, 1293396000, 1633489000, 1811477000, NULL, NULL, 51, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 134797000, 1875861000, 522559000, 522559000, NULL, 522559000, 1713343000, $$The Defense Innovation Unit (DIU) mission is to strengthen U.S. national security by accelerating the adoption of commercial technology and externally developed products--connecting American entrepreneurs and commercial technology companies to Department needs at speed. DIU serves as the Department's center of excellence for commercial technology adoption and product transition, available to Portfolio Acquisition Executives and program offices across the Department. DIU is the Department's primary interface with the nontraditional and commercial ecosystem for rapid product adoption and transition. In support of the Secretary of War’s directive to transform the Defense Innovation Ecosystem to Accelerate Warfighting Advantage, DIU will: 1) Focus on high technologies that produce overmatch domination; 2) Focus on technologies that reduce the number of Soldiers, Sailors, Airmen, Marines, and Guardians in harm’s way; 3) Focus on capabilities that can scale quickly and dramatically reduce costs. Funding in this Program Element is requested to support DIU’s mission, including operational support, development of the nontraditional and commercial ecosystems, and for the development and integration of prototypes for rapid product adoption and transition. DIU partners with Military Departments, organizations, and agencies across the Department of War (DoW) to rapidly prototype and field dual-use capabilities that solve operational challenges at speed and scale. By funding projects that augment commercial technologies, existing government capabilities, or new concepts, DIU increases the DoW's access to innovative, dual-use technology. The FY 2026 spend plan amount for 0603342D8Z includes $140,000 thousand of discretionary and $1,735,861 thousand of mandatory (reconciliation) for a total of $1,875,861 thousand. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                             Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:         PE 0603342D8Z / Defense Innovation Unit (DIU) Advanced Technology Development (ATD)$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2031_L013$$, $$UH-60 Blackhawk M Model (MYP)$$, $$proc_army_2031_ba1$$, $$peo_aviation$$, 2026, 732060000, 728258000, 769054000, NULL, $${"page": 11, "ba_num": "01", "source": "p1_fy26", "ba_name": "Aircraft", "line_no": "13", "service": "army", "fy24_qty": 26, "fy25_qty": 26, "appr_code": "2031", "appr_name": "Aircraft Procurement, Army", "fy26_v178": {"disc_K": 361669, "li_num": 7, "source": "p40_fy26_v178", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Army/Aircraft_Procurement_Army.txt"}, "fy26t_qty": 24, "fy26d_cost": 732060000, "fy26r_cost": 0, "ident_code": ""}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 361669000, 1552000, 1552000, 0, 1552000, NULL, NULL, $$Budget J-Books/FY27/Army/Aircraft_Procurement_Army.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603345A$$, $$Unmanned Aerial Systems Launched Effects Advanced Technology Devel$$, $$rdte_army_ba3$$, $$devcom$$, 2026, 13898000, 0, 0, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 12, "original_pe": "0603345A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) matures and demonstrates uncrewed air vehicles and mission system technologies as well as advanced teaming capabilities to enable unmanned aerial system modernization. Emphasis is on developing aviation platform and mission system technologies to enhance uncrewed air vehicle combat and combat support operations for attack, reconnaissance, air assault, survivability, logistics, and command and control missions. The PE will fund civilian salaries for in- house researchers/scientists and program managers. Work in this PE contributes to the Army Science and Technology (S&T) air systems portfolio and is fully coordinated with efforts in PE 0602148A (Future Verticle Lift Technology), PE 0602345A (Unmanned Aerial Systems Launched Effects Applied Research), and PE 0603043A (Air Platform Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy.$$, NULL, 43915000, 45557000, 45151000, NULL, NULL, 48, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, NULL, 13898000, 33129000, 33129000, NULL, 33129000, 45478000, $$This PE matures and demonstrates uncrewed air vehicles and mission system technologies as well as advanced teaming capabilities to enable unmanned aerial system modernization. Emphasis is on developing aviation platform and mission system technologies to enhance uncrewed air vehicle combat and combat support operations for attack, reconnaissance, air assault, survivability, logistics, and command and control missions. The PE will fund civilian salaries for in-house researchers/scientists and program managers. Work in this PE contributes to the Army Science and Technology (S&T) air systems portfolio and is fully coordinated with efforts in PE 0602148A (Future Verticle Lift Technology), PE 0602345A (Unmanned Aerial Systems Launched Effects Applied Research), and PE 0603043A (Air Platform Advanced Technology). The cited work is consistent with the Under Secretary of War (Research and Engineering) priority focus areas and the Army modernization strategy.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603375D8Z$$, $$Technology Innovation$$, $$rdte_dw_ba3$$, $$dw$$, 2026, 19654000, 48393000, 58729000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 69, "original_pe": "0603375D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Department's initiatives to Deter Strategic Attacks, Defend the Homeland, and Build a Resilient Joint Force and Defense Ecosystem. In order to sustain technological superiority, the Department must take immediate advantage of the rapid evolution of emerging technologies that will be a source of battlefield advantage, when integrated with military systems and novel concepts of operation. This program focuses on rapidly moving these technologies to a Technology Readiness Level where they would then be ready to demonstrate in a prototyping or demonstration acceleration program to support warfighter needs. This funding is focused on supporting efforts within the Department’s Critical Technology Areas that contribute to the broader joint mission needs. Leveraging these technologies from both defense and commercial sources, to include non-traditional sources such as startup companies, has the potential to rapidly address warfighter problem sets in areas where commercial innovation outstrips government investment in the same technology areas.$$, NULL, 592093000, 239502000, 179700000, NULL, NULL, 52, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 57222000, 19460000, 982694000, 982694000, NULL, 982694000, 196344000, $$This program supports the Department's initiatives to Deter Strategic Attacks, Defend the Homeland, and Build a Resilient Joint Force and Defense Ecosystem. In order to sustain technological superiority, the Department must take immediate advantage of the rapid evolution of emerging technologies that will be a source of battlefield advantage, when integrated with military systems and novel concepts of operation. This program focuses on rapidly moving these technologies to a Technology Readiness Level where they would then be ready to demonstrate in a prototyping or demonstration acceleration program to support warfighter needs. This funding is focused on supporting efforts within the Department's Critical Technology Areas that contribute to the broader joint mission needs. Leveraging these technologies from both defense and commercial sources, to include non-traditional sources such as startup companies, has the potential to rapidly address warfighter problem sets in areas where commercial innovation outstrips government investment in the same technology areas.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603379D8Z$$, $$Advanced Technical Integration$$, $$rdte_dw_ba3$$, $$dw$$, 2026, 19991000, 10597000, 26053000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 69, "original_pe": "0603379D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$Classified details provided upon request.$$, NULL, 19856000, 20653000, 21302000, NULL, NULL, 53, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 25118000, 29576000, 79268000, 79268000, NULL, 79268000, 21947000, $$Classified details provided upon request.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603382N$$, $$Advanced Combat Systems Tech$$, $$rdte_navy_ba4$$, $$navy_cno$$, 2026, 2083000, 27142000, 7051000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 28, "original_pe": "0603382N", "page_header": "Department of the Navy", "fy26_v182_disc_K": 19307, "fy26_v182_supp_K": 39000, "fy26_v182_total_K": 58307, "fy26_v182_note_name": "Research, Development, Test and Evaluation, Navy", "fy26_v182_source_file": "RDTEN_BA4_Book.txt", "fy26_v182_source_line": 8713}$$::jsonb, $$Open architecture sets standards for technology fields to promote interoperability. For defense systems, standards enable interconnectivity across services and in coalition operations at machine-to-machine speeds. Reducing barriers associated with proprietary software speeds development and delivery of warfighting advantage. The Advanced Combat System Technology line is to evolve the technical and business practices for programs to change to an open architecture construct. The program was constructed to mature both technical and business model integration for C5I systems programs of record in an open architecture environment. The priority was incorporating the principles of modular design and design disclosure, reusable application software, interoperability and secure information exchange, lifecycle affordability and encouraging competition and collaboration. Project Unit 0324: This funding supports the implementation of the Naval Open Systems Architecture (OSA) Strategy. The primary tools and assistance will be established through the implementation of an enterprise reference architecture that transforms and standardizes the Navy technical and interoperability baseline and through related enterprise engineering technologies with consistent contract language guidance, Intellectual Property strategies and improvements in transparency of design disclosure and information exchange on past and current investments; support portfolio management and cross-program reuse. Applicable technologies will also be leveraged to facilitate the Navy's implementation of OSA and similar constructs like Modular Open Systems Approaches (MOSA). The OSA transformation effort will be applied to programs of record. Those elements include ensuring that naval systems, families of systems, programs, and prototypes move to modular OSA in accordance with SECNAV Instruction 5000.2G (Department of the Navy Implementation of the Defense Acquisition System and The Adaptive Acquisition Framework, 08 April 2022) which mandates that all DoD programs utilize Modular OSA to field affordable and interoperable systems. This project facilitates a strategic shift in the technical and business methods to establish cooperation and cross-domain/community of interest (COI) business relationships. This improves innovation and economies of scale throughout the Navy and Marine Corps. This project includes identification of use cases and cost avoidance as a result of moving the Navy towards an open systems approach, supported by the development of open systems technologies and integrated best operational and technical practices for open systems development within Naval acquisition. This project also supports systems engineering and acquisition services to deliver capabilities through acquisition, development, integration, production, test, deployment and sustainment of interoperable command, control, communication, computers, intelligence, surveillance reconnaissance, cyber, and information technology capabilities. Naval OSA ensures system architectures become extensible and scalable in function, capacity, and workload to meet Service and Joint warfighting requirements. This also includes the identification and development of common software components, functions, reuse methodologies, and extensible product lines. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                              Date: June 2025 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced                PE 0603382N / Advanced Combat Systems Tech Component Development & Prototypes (ACD&P) Project 3438: This activity addresses the advanced component development and prototype demonstration associated with ONR's Innovative Naval Prototypes (INP) Program and the Leap Ahead Technology (LA-Tech) investments. INP and LA-Tech investments represent game changing technologies with the potential to revolutionize operational concepts. They are disruptive in nature as they would dramatically change the way naval forces fight. INPs and LA-Techs push the imagination of our nation's technical talent to deliver transformational warfighting capabilities. Investments may include such mission areas as Unmanned and Autonomous Systems, Directed Energy / Electric Weapons, Electromagnetic Maneuver Warfare, Cyber Warfare, and Undersea Warfare. Advanced Component Development and Prototypes (ACD&P) efforts necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment are funded in this PE. Most of the work in this PE can be classified between Technology Readiness Level (TRL) 6 (system/subsystem model or prototype demonstration in a relevant environment) and TRL 7 (system prototype demonstration in an operational environment).$$, NULL, 32646000, 41158000, 70693000, NULL, NULL, 34, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 6817000, 58307000, 32263000, 32263000, NULL, 32263000, 67355000, $$Project 0303: Tactical Advancements for the Next Generation (TANG) is a Navy-wide innovation project that has expanded throughout the Department of War (DoW) that addresses mission-driven, human-centered challenges for warfighters and developers. TANG drives front-end innovation for national security utilizing emerging technologies including Extended Reality (XR) and Artificial Intelligence/Machine Learning (AI/ML). TANG solves these challenges leveraging a divergent-convergent process (e.g., design thinking) and harnessing the expertise and perspective of the user, subject matter experts (SMEs), stakeholders, and industry partners, to ideate and create new actionable solutions that will impact the DoW. For each project, TANG will tailor the methods and approaches to the respective topic and scope. Approaches include domain user research, facilitation of workshops, strategic process improvements, building project roadmaps, and rapid prototyping of perspective solutions. Project Unit 0304: Technology Maturation and Transition: Funds vetted and endorsed prototype technologies and capabilities based on projects curated by N94 from initiatives throughout the joint and USN innovation portfolio. Projects align with National Defense Strategy (NDS), Chief of Naval Operations (CAAPP) and Fleet priorities and receive USN endorsement based on a rigorous vetting process and the closure of critical capability gaps. Projects are cross-domain and accelerate integration of high priority technologies to enable transition into Programs of Record and support warfighter needs. Projects also support USN experimentation in priority areas required for evaluation and transition of key technologies. Project Unit 0324: This funding supports the implementation of the Naval Open Systems Architecture (OSA) Strategy. The Navy's implementation of OSA and similar constructs like Modular Open Systems Approaches (MOSA). The OSA transformation effort will be applied to programs of record. Those elements include ensuring that naval systems, families of systems, programs, and prototypes move to MOSA in accordance with DoW Memo 7 Nov 2025, Joint Memo 17 Dec 2024, 10 USC 4402 5 Nov 2025, and SECNAV Instruction 5000.2G (Department of the Navy Implementation of the Defense Acquisition System, 08 April 2022) which mandates that all DoW programs utilize MOSA to field affordable and interoperable systems. This project facilitates a strategic shift to digitally engineered modular systems deployment. This Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                             Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced           PE 0603382N / Advanced Combat Systems Tech Component Development & Prototypes (ACD&P) improves innovation and economies of scale throughout the Navy and Marine Corps. This project includes identification of use cases and cost avoidance the benefits as a result of moving the Navy towards an open systems approach, supported by the development of open systems technologies and integrated best operational and technical practices for open systems development within Naval acquisition. Naval MOSA ensures system architectures become extensible and scalable in function, capacity, and workload to meet Service and Joint warfighting requirements. This also includes the identification and development of common software components, functions, reuse methodologies, and extensible product lines. Open architectures set the standard for technology fields to promote interoperability. The Advanced Combat System Technology line advances the principles of modular design and design disclosure, reusable application software, interoperability and secure information exchange, lifecycle affordability and encouraging standardization. The FY 2026 spend plan amount for Research, Development, Test and Evaluation, Navy includes $19,307 thousand of discretionary and $39,000 thousand of mandatory (reconciliation) for a total of $58,307.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603384BP$$, $$Chemical and Biological Defense Program - Advanced Development$$, $$rdte_dw_ba3$$, $$dw_cbdp$$, 2026, 247043000, 247437000, 232551000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 69, "original_pe": "0603384BP", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 244909000, 245876000, 244743000, NULL, NULL, NULL, NULL, NULL, FALSE, 230200000, 241043000, 310308000, 310308000, 0, 310308000, 247471000, $$This program element (PE) resources Advanced Technology Development across the Understand, Protect, Mitigate, and Enabling Investments portfolios. Chemical and Biological Defense Program (CBDP) investments provide an integrated, layered capability to enable Department of War (DoW) missions in a chemical and biological environment, ranging from combat operations to domestic incident prevention and response. The Projects in this PE demonstrate technologies supporting the transition to advanced component development for physical capabilities, which cover chemical and biological (CB) detection, situational awareness and effects modeling, and protection and hazard mitigation. FY 2027 funding accelerates characterization and situational awareness of emerging biothreats and accelerates delivery of improved protection from and mitigation of biothreats, including rapid repurposing of available therapeutics and development of new vaccines. Individual Projects include: - Understand (UN3): Demonstration of enhanced chemical detection capabilities for aerosols and non-traditional agents, expanded capabilities for biosurveillance in pathogen detection and diagnosis, produce biological diagnostic arrays and reagents and diagnostic device platforms. - Protect (PT3): Production of pretreatment candidates for bacterial, viral, and toxin threats. - Mitigate (MT3): Production of therapeutic candidates for bacterial, viral, and toxin threats. - Enabling Investments (EN3): Demonstrations of CB defense technologies, including biological detection, chemical detection, and decontamination, including non- traditional agents. Continued efforts to enhance the military operational capability, concepts of operation, and Weapons of Mass Destruction (WMD) elimination. - Emerging Threats (ET3): identify and develop scientific solutions or to modernize capabilities that allow for a more rapid response to emerging threats. CBDP Science and Technology (S&T) Applied Research Performers: U.S. Army Combat Capabilities Development Command Chemical Biological Center (DEVCOM CBC), United States Army Medical Research Institute of Infectious Diseases (USAMRIID), United States Army Medical Research Institute of Chemical Defense Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Chemical and Biological Defense Program                                         Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:            PE 0603384BP / Chemical and Biological Defense Program - Advanced Development Advanced Technology Development (ATD) (USAMRICD), United States Army Natick Soldier Systems Center, Naval Research Lab (NRL), Air Force Research Lab (AFRL), and Department of Energy Laboratories such as Pacific Northwest National Laboratory (PNNL), among others. The intent is to maintain strategic partnerships with the DoW Service communities & the interagency for mission success across the enterprise through collaborative planning and programming maintaining budget assurance. Work conducted under this PE will transition to and will provide risk reduction for Advanced Component Development and Prototypes (PE 0603884BP) and System Development and Demonstration (PE 0604384BP) activities.$$, $$Budget J-Books/FY27/DW/RDTE_CBDP_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603386A$$, $$Biotechnology for Materials - Advanced Research$$, $$rdte_army_ba3$$, $$dw_osd$$, 2026, 24683000, 57686000, 36360000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 12, "original_pe": "0603386A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) matures and demonstrates novel biotechnological methods, processes, and materials to enhance military supply chain resilience. The Army is responsible for centrally managing funding for Tri-Service Biotechnology for a Resilient Supply Chain (T-BRSC) efforts. T-BRSC leverages bio-industrial manufacturing to ensure critical domestic supply chain resilience for defense needs through domestic production of raw materials and critical products. The Army supports this Tri-Service effort under this PE with collaboration among sister Services and select allied partners to support a robust pipeline for biotechnology related manufacturing. Advanced research projects optimize and rapidly demonstrate future novel biotechnologies for disruptive breakthrough capabilities. This PE provides bio- engineered and biosynthetic materials to ensure domestic sourcing of critical products in the defense supply chain. Also under this PE, efforts mature and demonstrate rapid prototyping methods for rapid testing of bio-derived materials as well as optimize models for the design and bio-security of bio-engineered materials for defense applications. This PE is coordinated with PE 0602386A (Biotechnology for Materials - Applied Research). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. The FY 2026 request was reduced by $0.128 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 23910000, 24092000, 24347000, NULL, NULL, 49, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, 35033000, 24683000, 22402000, 22402000, NULL, 22402000, 24590000, $$This Program Element (PE) matures and demonstrates novel biotechnological methods, processes, and materials to enhance military supply chain resilience. The Army is responsible for centrally managing funding for Tri-Service Biotechnology for a Resilient Supply Chain (T-BRSC) efforts. T-BRSC leverages bio-industrial manufacturing to ensure critical domestic supply chain resilience for defense needs through domestic production of raw materials and critical products. The Army supports this Tri-Service effort under this PE with collaboration among sister Services and select allied partners to support a robust pipeline for biotechnology related manufacturing. Advanced research projects optimize and rapidly demonstrate future novel biotechnologies for disruptive breakthrough capabilities. This PE provides bio- engineered and biosynthetic materials to ensure domestic sourcing of critical products in the defense supply chain. Also under this PE, efforts mature and demonstrate rapid prototyping methods for rapid testing of bio-derived materials as well as optimize models for the design and bio-security of bio-engineered materials for defense applications. This PE is coordinated with PE 0602386A (Biotechnology for Materials - Applied Research). The cited research is consistent with the Under Secretary of War for Research and Engineering priority focus areas and the Army Modernization Strategy.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603444F$$, $$Maui Space Surveillance System (MSSS)$$, $$rdte_af_ba3$$, $$afrl_rd$$, 2026, 0, 2000, 0, NULL, $${"ba_raw": "6.3", "source": "af_r1_fy26", "original_pe": "0603444F"}$$::jsonb, $$This program funded ground-based optical space situational awareness (SSA) technology development and demonstration at the Maui Space Surveillance System (MSSS) in Hawaii, as well as the operation and upgrade of the facility. Efforts in this program were coordinated through the Department of Defense Science and Technology Executive Committee process to harmonize efforts and eliminate duplication. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology capabilities. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment.$$, NULL, NULL, NULL, NULL, NULL, NULL, 24, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603456F$$, $$Human Effectiveness Advanced Technology Development$$, $$rdte_af_ba3$$, $$afrl_rh$$, 2026, 19790000, 39929000, 14608000, NULL, $${"ba_raw": "6.3", "source": "af_r1_fy26", "original_pe": "0603456F"}$$::jsonb, $$This program develops, demonstrates, and transitions technologies to enhance Airman performance and effectiveness. State-of-the-science advances are made in warfighter training, warfighter system interfaces, directed energy bioeffects, deployment and sustainment of warfighters in extreme environments, and understanding and shaping adversarial behavior. The Directed Energy Bioeffects Parameters project develops, demonstrates, and transitions technologies to predict, evaluate, and mitigate the effects of directed energy on personnel and mission performance, and exploits the offensive capabilities of directed energy systems. The Biosciences Performance Demonstration project develops, demonstrates, and transitions technologies to sustain airman performance in adverse operational and/or training environments, monitor and mitigate in-flight unexplained physiological events, and prevent human performance related mishaps through real-time monitoring and mitigation—particularly through highly automated or autonomous systems. The Mission Effective Performance project develops, demonstrates, and transitions advanced training, simulation, mission rehearsal, and other performance-aiding methods and technologies to enhance warfighter readiness. The Warfighter Interfaces project develops, demonstrates, and transitions technologies to revolutionize the way Airmen and Guardians synergistically use Department of the Air Force combat and combat support systems, including autonomous machines and adaptive teams of Airmen, Guardians, and machines. Efforts in this program have been coordinated through the Department of Defense (DoD) Science and Technology (S&T) Executive Committee process to harmonize efforts and eliminate duplication. The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology capabilities. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603456F / Human Effectiveness Advanced Technology Development Technology Development (ATD)$$, NULL, 17832000, 21401000, 21834000, NULL, NULL, 25, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 13549000, 19549000, 20338000, 20338000, 0, 20338000, 22276000, $$This program develops, demonstrates, and transitions technologies to enhance Department of the Air Force (DAF) warfighter performance and effectiveness through breakthrough advances in warfighter training, warfighter system interfaces, directed energy bioeffects, deployment and sustainment of warfighters in extreme environments, and understanding and shaping adversarial behavior. This program develops, demonstrates, and transitions technologies to predict, evaluate, and mitigate the effects of directed energy on personnel and mission performance, and exploits the offensive capabilities of directed energy systems. In addition, this program sustains Airman performance and prevents mishaps by using real-time monitoring and mitigation—especially through autonomous systems—to counter the effects of adverse environments and in-flight unexplained physiological events. This program develops, demonstrates, and transitions advanced training, simulation, mission rehearsal, and other performance-aiding methods and technologies to enhance warfighter readiness. Finally, this program develops, demonstrates, and transitions technologies to revolutionize the way Airmen synergistically use DAF combat and combat support systems, including autonomous machines and adaptive teams of Airmen and machines. Efforts in this program have been coordinated through the Department of War (DoW) Science and Technology (S&T) Executive Committee process to harmonize efforts and eliminate duplication. The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain S&T solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the DAF S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603456F / Human Effectiveness Advanced Technology Development Technology Development (ATD) Funds in this PE may be used to investigate specified technology advancements in air, space and/or cyber domains. In order to manage, execute, and deliver S&T capabilities, this program element may include necessary civilian pay expenses, expenses to support the operation and maintenance of facilities, as well as expenses related to travel, supplies, IT hardware, software and support, etc. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603457A$$, $$C3I Cyber Advanced Development$$, $$rdte_army_ba3$$, $$dw_osd$$, 2026, 3329000, 28275000, 39616000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 13, "original_pe": "0603457A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) matures and demonstrates technologies for offensive and defensive cyber operations in tactical environments. Projects optimize devices, techniques, services, software and algorithms to enable cyber situational understanding and Cyber Electromagnetic Activities (CEMA). For offensive cyber, efforts demonstrate integrated electronic attack (EA) and CEMA hardware and software to execute force protection (FP), EA, electronic surveillance (ES), signals intelligence (SIGINT), electronic warfare (EW) and cyber missions in a dynamic, distributed and coordinated fashion. For defensive cyber, efforts demonstrate hardware and software to protect tactical wired and wireless networks against modern cyber attacks and focuses on configuration, operation, monitoring, data integrity, and defense in bandwidth constrained tactical environments while reducing the operator workload required to conduct these functions. This PE directly supports the Network Army Modernization Priority. The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy.$$, NULL, 10272000, 6139000, 7554000, NULL, NULL, 50, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, 39616000, 29829000, 8509000, 8509000, NULL, 8509000, 7629000, $$This Program Element (PE) matures and demonstrates technologies for offensive and defensive cyber operations in tactical environments. Projects optimize devices, techniques, services, software and algorithms to enable cyber situational understanding and Cyber Electromagnetic Activities (CEMA). For offensive cyber, efforts demonstrate integrated electronic attack (EA) and CEMA hardware and software to execute force protection (FP), EA, electronic surveillance (ES), signals intelligence (SIGINT), electronic warfare (EW) and cyber missions in a dynamic, distributed and coordinated fashion. For defensive cyber, efforts demonstrate hardware and software to protect tactical wired and wireless networks against modern cyber attacks and focuses on configuration, operation, monitoring, data integrity, and defense in bandwidth constrained tactical environments while reducing the operator workload required to conduct these functions. This PE directly supports the Network Army Modernization Priority. The cited research is consistent with the Under Secretary of War for Research and Engineering priority focus areas and the Army modernization strategy.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603462A$$, $$Next Generation Combat Vehicle Advanced Technology$$, $$rdte_army_ba3$$, $$cft_ngcv$$, 2026, 141301000, 433324000, 254662000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 13, "original_pe": "0603462A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) executes development, maturation, and demonstration for the Army's modernization priority for the Next Generation of Combat Vehicle (NCCV). This PE matures, integrates and demonstrates combat vehicle technologies that enable the Army to have a smarter, faster, more lethal, more precise, more protected, and more adaptable force. Technology development builds upon the foundational vehicle architectures to support the NGCV, to include autonomy architecture, power architecture, vehicle electronic architecture, physical architecture, lethality architecture and vehicle protection architecture. Technologies developed, matured, and demonstrated will enable leap ahead capabilities for manned, optionally manned and unmanned vehicles that deliver decisive lethality. Project BF4: Combat Vehicle Robotics Adv Tech was rescoped in PE 0603462A to reflect Department of Defense priorities and will cease the testing and validation of Government developed autonomy software and renewing focus towards integration and testing of industry software. Project BH6: Platform Electrification and Mobility Adv Tech was rescoped in PE 0603462A to reflect Department of Defense priorities and will cease the testing and validation of hybrid-drive systems for combat vehicles. Research in this PE complements PE 0602141A (Lethality Technology), PE 0602144A (Ground Technology), PE 0602145A (Next Generation Combat Vehicle Technology), PE 0602146A (Network C3I Technology), PE 0603116A (Lethality Advanced Technology), PE 0603119A (Ground Advanced Technology), PE 0603463A (Network C3I Advanced Technology), PE 0604115A (Technology Maturation Initiatives), and PE 0708045A (End Item Industrial Preparedness Activities). Research in this PE also transitions to PE 0603645A (Armored Systems Modernization Adv Dev) and PE 0604017A (Robotics Development). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Research is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center, Armament Center, Ground Vehicle Systems Center, and the Geotechnical and Structures Laboratory. The FY 2026 request was reduced by $0.806 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.726 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                      Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced         PE 0603462A / Next Generation Combat Vehicle Advanced Technology Technology Development (ATD)$$, NULL, 146638000, 145920000, 153201000, NULL, NULL, 52, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, 248074000, 308201000, 118207000, 118207000, NULL, 118207000, 159325000, $$This Program Element (PE) executes development, maturation, and demonstration for the Army's modernization priority for the Next Generation of Combat Vehicle (NCCV). This PE matures, integrates and demonstrates combat vehicle technologies that enable the Army to have a smarter, faster, more lethal, more precise, more protected, and more adaptable force. Technology development builds upon the foundational vehicle architectures to support the NGCV, to include autonomy architecture, power architecture, vehicle electronic architecture, physical architecture, lethality architecture and vehicle protection architecture. Technologies developed, matured, and demonstrated will enable leap ahead capabilities for manned, optionally manned and unmanned vehicles that deliver decisive lethality. Project BF4: Combat Vehicle Robotics Adv Tech was rescoped in PE 0603462A to reflect Department of War priorities and will cease the testing and validation of Government developed autonomy software and renewing focus towards integration and testing of industry software. Project BH6: Platform Electrification and Mobility Adv Tech was rescoped in PE 0603462A to reflect Department of War priorities and will cease the testing and validation of hybrid-drive systems for combat vehicles. Research in this PE complements PE 0602141A (Lethality Technology), PE 0602144A (Ground Technology), PE 0602145A (Next Generation Combat Vehicle Technology), PE 0602146A (Network C3I Technology), PE 0603116A (Lethality Advanced Technology), PE 0603119A (Ground Advanced Technology), PE 0603463A (Network C3I Advanced Technology), PE 0604115A (Technology Maturation Initiatives), and PE 0708045A (End Item Industrial Preparedness Activities). Research in this PE also transitions to PE 0603645A (Armored Systems Modernization Adv Dev) and PE 0604017A (Robotics Development). The cited research is consistent with the Under Secretary of War for Research and Engineering priority focus areas and the Army Modernization Strategy. Research is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center, Armament Center, Ground Vehicle Systems Center, and the Geotechnical and Structures Laboratory.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L049$$, $$Cooperative Engagement Capability$$, $$proc_navy_1810_ba2$$, $$navsea$$, 2026, 31169000, 33887000, 45975000, NULL, $${"page": 97, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "49", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 45", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 72190, "p1_line_num": 45, "fy27_total_K": 72190}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 31169, "li_num": 45, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA2_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 31169000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 26644000, 26648000, 72190000, 72190000, 0, 72190000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603463A$$, $$Network C3I Advanced Technology$$, $$rdte_army_ba3$$, $$peo_c3t$$, 2026, 78539000, 214351000, 142224000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 13, "original_pe": "0603463A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) matures and demonstrates technologies to provide an Army tactical network and enabling infrastructure that support operations in any environment, to include where the electromagnetic spectrum is denied or degraded. This is accomplished through the exploitation and optimization of components and systems for robust, low signature communications and data networks; assured positioning, navigation, and timing in contested environments; converged and coordinated cyber and electronic warfare activities; resilient mission command on the move; and the collection, processing, and dissemination of information for intelligence, surveillance, and reconnaissance in a common operating picture. Work in this PE complements PE 0602146A (Network C3I Technology), PE 0602143A (Soldier Lethality Technology), PE 0602145A (Next Generation Combat Vehicle Technology), PE 0602147A (Long Range Precision Fires Technology), PE 0602148A (Future Vertical Lift Technology), PE 0602150A (Air and Missile Defense Technology), PE 0602213A (C3I Applied Cyber), PE 0603118A (Soldier Lethality Advanced Technology), PE 0603462A (Next Generation Combat Vehicle Advanced Technology), PE 0603464A (Long Range Precision Fires Advanced Technology), PE 0603465A (Future Vertical Lift Advanced Technology), and PE 0603466A (Air and Missile Defense Advanced Technology). This PE is directly aligned with the Network and Assured Positioning, Navigation, and Timing (APNT) Army Modernization priorities. The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Research is performed by the U.S. Army Engineer Research and Development Center (ERDC). The FY 2026 request was reduced by $6.818 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                           Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced          PE 0603463A / Network C3I Advanced Technology Technology Development (ATD) The FY 2026 request was reduced by $0.444 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 76255000, 88359000, 94690000, NULL, NULL, 53, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, 150510000, 143939000, 48490000, 48490000, NULL, 48490000, 97913000, $$This Program Element (PE) matures and demonstrates technologies to provide an Army tactical network and enabling infrastructure that support operations in any environment, to include where the electromagnetic spectrum is denied or degraded. This is accomplished through the exploitation and optimization of components and systems for robust, low signature communications and data networks; assured positioning, navigation, and timing in contested environments; converged and coordinated cyber and electronic warfare activities; resilient mission command on the move; and the collection, processing, and dissemination of information for intelligence, surveillance, and reconnaissance in a common operating picture. Work in this PE complements PE 0602146A (Network C3I Technology), PE 0602143A (Soldier Lethality Technology), PE 0602145A (Next Generation Combat Vehicle Technology), PE 0602147A (Long Range Precision Fires Technology), PE 0602148A (Future Vertical Lift Technology), PE 0602150A (Air and Missile Defense Technology), PE 0602213A (C3I Applied Cyber), PE 0603118A (Soldier Lethality Advanced Technology), PE 0603462A (Next Generation Combat Vehicle Advanced Technology), PE 0603464A (Long Range Precision Fires Advanced Technology), PE 0603465A (Future Vertical Lift Advanced Technology), and PE 0603466A (Air and Missile Defense Advanced Technology). This PE is directly aligned with the Network and Assured Positioning, Navigation, and Timing (APNT) Army Modernization priorities. The cited research is consistent with the Under Secretary of War for Research and Engineering priority focus areas and the Army Modernization Strategy. Research is performed by the U.S. Army Engineer Research and Development Center (ERDC). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                     Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced          PE 0603463A / Network C3I Advanced Technology Technology Development (ATD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603464A$$, $$Long Range Precision Fires Advanced Technology$$, $$rdte_army_ba3$$, $$cft_lrpf$$, 2026, 162236000, 233806000, 164943000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 13, "original_pe": "0603464A", "page_header": "Department of the Army", "fy26_v182_disc_K": 184206, "fy26_v182_supp_K": 155700, "fy26_v182_total_K": 339906, "fy26_v182_note_name": "Long Range Precision Fires Advanced Technology", "fy26_v182_source_file": "RDTE - Vol 1 - Budget Activity 3.txt", "fy26_v182_source_line": 12874}$$::jsonb, $$This Program Element (PE) matures and demonstrates Long Range Precision Fires (LRPF) technologies to destroy, neutralize, or suppress the enemy by cannon artillery and missile fire and enable integration of fire support assets into combined arms operations. Major Focus Areas for LRPF Science and Technology include: Missiles, Cannon Artillery, and Supporting LRPF Technologies covering Strategic, Operational and Tactical Lines of Effort. LRPF Missiles Advanced Development matures and demonstrates a broad range of Missile technologies to enhance Army integrated LRPF capabilities at extended range. Cannon Artillery Advanced Development matures and demonstrates critical technologies to increase range, precision, and both point and area effects for cannon artillery. Supporting LRPF Technologies Advanced Development matures and demonstrates a broad range of component technologies to address weapon cost drivers and enhance performance of future LRPF munitions and systems. Research in this Program Element (PE) complements PE 0602147A Long Range Precision Fires Technology. This PE is directly aligned to the Army Long Range Precision Fires (LRPF) Modernization Priority. The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced        PE 0603464A / Long Range Precision Fires Advanced Technology Technology Development (ATD) The FY 2026 request was reduced by $9.794 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.932 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 173884000, 159071000, 152821000, NULL, NULL, 54, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, 174160000, 339906000, 422590000, 422590000, NULL, 422590000, 149838000, $$This Program Element (PE) matures and demonstrates Long Range Precision Fires (LRPF) technologies to destroy, neutralize, or suppress the enemy by cannon artillery and missile fire and enable integration of fire support assets into combined arms operations. Major Focus Areas for LRPF Science and Technology include: Missiles, Cannon Artillery, and Supporting LRPF Technologies covering Strategic, Operational and Tactical Lines of Effort. LRPF Missiles Advanced Development matures and demonstrates a broad range of Missile technologies to enhance Army integrated LRPF capabilities at extended range. Cannon Artillery Advanced Development matures and demonstrates critical technologies to increase range, precision, and both point and area effects for cannon artillery. Supporting LRPF Technologies Advanced Development matures and demonstrates a broad range of component technologies to address weapon cost drivers and enhance performance of future LRPF munitions and systems. Research in this Program Element (PE) complements PE 0602147A Long Range Precision Fires Technology. This PE is directly aligned to the Army Long Range Precision Fires (LRPF) Modernization Priority. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced          PE 0603464A / Long Range Precision Fires Advanced Technology Technology Development (ATD) The cited research is consistent with the Under Secretary of War for Research and Engineering priority focus areas and the Army modernization strategy.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603465A$$, $$Future Vertical Lift Advanced Technology$$, $$rdte_army_ba3$$, $$cft_fvl$$, 2026, 66686000, 219137000, 175369000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 13, "original_pe": "0603465A", "page_header": "Department of the Army", "fy26_v182_disc_K": 111686, "fy26_v182_supp_K": 8401, "fy26_v182_total_K": 120087, "fy26_v182_note_name": "Future Vertical Lift Advanced Technology", "fy26_v182_source_file": "RDTE - Vol 1 - Budget Activity 3.txt", "fy26_v182_source_line": 13553}$$::jsonb, $$This Program Element (PE) matures and demonstrates manned and unmanned air vehicle and mission system technologies as well as advanced teaming capabilities to enable Army Future Vertical Lift. Emphasis is on platform and mission system technologies to enhance manned and unmanned air vehicle combat and combat support operations for attack, reconnaissance, air assault, survivability, logistics, and command and control missions. Within this PE, aviation technologies are advanced and integrated into realistic and robust demonstrations. Research in this PE contributes to the Army Science and Technology (S&T) air systems portfolio and is fully coordinated with efforts in PE 0602148A (Future Vertical Lift Technology), PE 0602183A (Air Platform Applied Research) and PE 0603043A (Air Platform Advanced Technology). A portion of this PE is directly aligned to the Future Vertical Lift (FVL) Army Modernization Priority. The cited research is consistent with the Under Secretary of Defense for Research and Engineering S&T focus areas and the Army Modernization Strategy. The FY 2026 request was reduced by $9.46 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.453 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 19130000, 26383000, 28294000, NULL, NULL, 55, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, 173161000, 120087000, 14984000, 14984000, NULL, 14984000, 29906000, $$This Program Element (PE) matures and demonstrates manned and unmanned air vehicle and mission system technologies as well as advanced teaming capabilities to enable Army Future Vertical Lift. Emphasis is on platform and mission system technologies to enhance manned and unmanned air vehicle combat and combat support operations for attack, reconnaissance, air assault, survivability, logistics, and command and control missions. Within this PE, aviation technologies are advanced and integrated into realistic and robust demonstrations. Research in this PE contributes to the Army Science and Technology (S&T) air systems portfolio and is fully coordinated with efforts in PE 0602148A (Future Vertical Lift Technology), PE 0602183A (Air Platform Applied Research) and PE 0603043A (Air Platform Advanced Technology). A portion of this PE is directly aligned to the Future Vertical Lift (FVL) Army Modernization Priority. The cited research is consistent with the Under Secretary of War for Research and Engineering S&T focus areas and the Army modernization strategy.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603466A$$, $$Air and Missile Defense Advanced Technology$$, $$rdte_army_ba3$$, $$smdc$$, 2026, 23330000, 98784000, 61333000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 13, "original_pe": "0603466A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) matures demonstrates technology in support of Army Modernization Priority Air and Missile Defense by maturating, demonstrating and conducting system level experimentation for the development of advanced air defense technologies that reduce the cost curve of missile defense, restore overmatch, survive volley-fire attacks, and operate within sophisticated Anti-Access/Area Denial (A2/AD) and contested domains. Research in this PE complements PE 0602150A (Air and Missile Defense Technology). This PE is directly aligned to the Air & Missile Defense (AMD) Army Modernization Priority. The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Research is performed by the United States (U.S.) Army Futures Command (AFC), the United States Army Space and Missile Defense Command/Army Forces Strategic Command (SMDC/ARSTRAT), and the Engineer Research and Development Center (ERDC), and the United States Army Rapid Capabilities and Critical Technologies Office (RCCTO). The FY 2026 request was reduced by $0.154 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                            Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced          PE 0603466A / Air and Missile Defense Advanced Technology Technology Development (ATD) The FY 2026 request was reduced by $0.096 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 46685000, 28188000, 32254000, NULL, NULL, 56, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, 60451000, 59080000, 63924000, 63924000, NULL, 63924000, 31324000, $$This Program Element (PE) matures and demonstrates technology in support of Army Modernization Priority Air and Missile Defense by maturating, demonstrating and conducting system level experimentation for the development of advanced air defense technologies that reduce the cost curve of missile defense, restore overmatch, survive volley-fire attacks, and operate within sophisticated Anti-Access/Area Denial (A2/AD) and contested domains. Research in this PE complements PE 0602150A (Air and Missile Defense Technology). This PE is directly aligned to the Air & Missile Defense (AMD) Army Modernization Priority. The cited research is consistent with the Under Secretary of War for Research and Engineering priority focus areas and the Army Modernization Strategy. Research is performed by the United States (U.S.) Training and Transformation Command (T2COM), the United States Army Space and Missile Defense Command (SMDC), and the Engineer Research and Development Center (ERDC), and the Program Acquisition Executive (PAE) FIRES. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced          PE 0603466A / Air and Missile Defense Advanced Technology Technology Development (ATD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603467E$$, $$DARPA ADVANCED TECHNOLOGY DEVELOPMENT$$, $$rdte_dw_ba3$$, $$dw_darpa$$, 2026, 1733465000, 0, 0, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 69, "original_pe": "0603467E", "page_header": "Defense-Wide", "fy26_v182_disc_K": 1528100, "fy26_v182_supp_K": 90000, "fy26_v182_total_K": 1618100, "fy26_v182_note_name": "Research, Development, Test and Evaluation, Defense-Wide for DARPA", "fy26_v182_source_file": "RDTE_Vol1_DARPA_MasterJustificationBook_PB_2027.txt", "fy26_v182_source_line": 10049}$$::jsonb, $$The efforts described in this Program Element (PE) address the Advanced Technology Development associated with Systems, Intelligence, Surveillance and Reconnaissance (ISR) and Sensors that addresses high payoff opportunities to develop and rapidly mature advanced technologies required for today's warfare concepts. It is imperative that future U.S. forces operate seamlessly in all domains with improved battlefield awareness, strike capability and battle damage assessment. This PE also supports innovation and robust transition and experimentation planning in the technology cycle to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. The Advanced Systems project will create enabling technologies for seamless all domain operations, from strategic planning to tactical and urban operations. All Domain Warfare Systems leverage current and emerging network, robotic, and information technology and provide next generation U.S. forces with greatly increased capability, lethality, and rapid responsiveness. Critical issues facing this project are: (1) U.S. opponents using systems that are flexible, robust, and difficult to neutralize; and (2) U.S. doctrine that limits the use of firepower to lessen the impact of operations on noncombatants. Meeting these challenges places a heavy burden on joint war planning. Understanding opponent networks is essential so that creative options can be developed to counter their strategies. Synchronization of air, sea, space, and ground operations to apply force only where needed and with specific effects is required. This project supports all levels of the force structure including: (1) the strategic/ operational level by generating targeting options against opponents' centers of gravity that have complex networked relationships; (2) the tactical/operational level by managing highly automated forces with tight coupling between air, seas, space, and ground platforms; and (3) the focused tactical level by developing platforms and tools, which acquire targets of opportunity and cue network-based analysis of likely enemy operations. The ISR and Sensors project develops technologies to improve surveillance and targeting systems for improved battlefield awareness, strike capability and battle damage assessment, and demonstrates these technologies and system concepts against emerging threat scenarios to support rapid technology adoption by the warfighter. Leveraging technology advancements in size, weight, power and cost and enabling with the practical application of mature machine learning and artificial intelligence, these efforts are also packaged in novel ways for rapid deployment and adoption for operational use. Capabilities are intended to overcome an adversary s intent to deny and deceive sensing and ISR systems in order to provide all-weather continuous coverage over areas of interest. This project will exploit recent advances Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                         Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:           PE 0603467E / DARPA ADVANCED TECHNOLOGY DEVELOPMENT Advanced Technology Development (ATD) in multispectral target phenomenology, signal processing, low-power high-performance computing, and low-cost microelectronics to develop advanced surveillance and targeting systems. The DARPA Advanced Technology Development Support project contains non-headquarters management costs in support of DARPA functions and activities across the entire DARPA Advanced Technology Development PE. These costs include: DARPA classified and unclassified network support and equipment; contractor support; classified program security; building security; commercial transition services that increase the likelihood that DARPA-funded technologies remain in the U.S. and provide new capabilities for national defense; DARPA outreach to universities and industry; external contracting, financial and support fees; Program Manager Intragovernmental Personnel Act (IPA) Funding; Program Managers from other Government Agencies; and similar operating expenses. Agency support is allocated on a pro-rata basis across the Agency's BA1, BA2 and BA3 PEs and, therefore, fluctuates per PE by fiscal year based on the total Agency budget in that fiscal year. Prior to FY 2026, efforts in this PE were funded in PE 0603760E, Command, Control and Communications Systems, PE 0603766E, Network-Centric Warfare Technology and PE 0603767E, Sensor Technology.$$, NULL, 1142182000, 1198039000, 1126657000, NULL, NULL, 55, $$RDTE_Vol1_DARPA_MasterJustificationBook_PB_2026.pdf$$, $$DARPA$$, FALSE, 0, 1618100000, 1568124000, 1568124000, NULL, 1568124000, 1068912000, $$The efforts described in this Program Element (PE) address the Advanced Technology Development associated with Systems, Intelligence, Surveillance and Reconnaissance (ISR) and Sensors that addresses high payoff opportunities to develop and rapidly mature advanced technologies required for today's warfare concepts. It is imperative that future U.S. forces operate seamlessly in all domains with improved battlefield awareness, strike capability and battle damage assessment. This PE also supports innovation and robust transition and experimentation planning in the technology cycle to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. The Advanced Systems project will create enabling technologies for seamless all domain operations, from strategic planning to tactical and urban operations. All Domain Warfare Systems leverage current and emerging network, robotic, and information technology and provide next generation U.S. forces with greatly increased capability, lethality, and rapid responsiveness. Critical issues facing this project are: (1) U.S. opponents using systems that are flexible, robust, and difficult to neutralize; and (2) U.S. doctrine that limits the use of firepower to lessen the impact of operations on noncombatants. Meeting these challenges places a heavy burden on joint war planning. Understanding opponent networks is essential so that creative options can be developed to counter their strategies. Synchronization of air, sea, space, and ground operations to apply force only where needed and with specific effects is required. This project supports all levels of the force structure including: (1) the strategic/ operational level by generating targeting options against opponents' centers of gravity that have complex networked relationships; (2) the tactical/operational level by managing highly automated forces with tight coupling between air, seas, space, and ground platforms; and (3) the focused tactical level by developing platforms and tools, which acquire targets of opportunity and cue network-based analysis of likely enemy operations. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Advanced Research Projects Agency                                          Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:            PE 0603467E / DARPA ADVANCED TECHNOLOGY DEVELOPMENT Advanced Technology Development (ATD) The ISR and Sensors project develops technologies to improve surveillance and targeting systems for improved battlefield awareness, strike capability and battle damage assessment, and demonstrates these technologies and system concepts against emerging threat scenarios to support rapid technology adoption by the warfighter. Leveraging technology advancements in size, weight, power and cost and enabling with the practical application of mature machine learning and artificial intelligence, these efforts are also packaged in novel ways for rapid deployment and adoption for operational use. Capabilities are intended to overcome an adversary's intent to deny and deceive sensing and ISR systems in order to provide all-weather continuous coverage over areas of interest. This project will exploit recent advances in multispectral target phenomenology, signal processing, low-power high-performance computing, and low-cost microelectronics to develop advanced surveillance and targeting systems. The DARPA Advanced Technology Development Support project contains management costs in support of DARPA functions and activities across the entire DARPA Advanced Technology Development PE. These costs include: DARPA classified and unclassified network support and equipment; contractor support; classified program security; building security; commercial transition services that increase the likelihood that DARPA-funded technologies remain in the U.S. and provide new capabilities for national defense; DARPA outreach to universities and industry; external contracting, financial and support fees; Program Manager Intragovernmental Personnel Act (IPA) Funding; Program Managers from other Government Agencies; and similar operating expenses. Agency support is allocated on a pro-rata basis across the Agency's BA1, BA2 and BA3 PEs and, therefore, fluctuates per PE by fiscal year based on the total Agency budget in that fiscal year. Prior to FY 2026, efforts in this PE were funded in PE 0603760E, Command, Control and Communications Systems, PE 0603766E, Network-Centric Warfare Technology and PE 0603767E, Sensor Technology.$$, $$Budget J-Books/FY27/DW/RDTE_Vol1_DARPA_MasterJustificationBook_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2031_L014$$, $$HADES PLATFORM, PAYLOADS/PED, AND INTEGR...$$, $$proc_army_2031_ba1$$, $$peo_aviation$$, 2026, 0, 92494000, 58170000, NULL, $${"page": 11, "ba_num": "01", "source": "p1_fy26", "ba_name": "Aircraft", "line_no": "14", "service": "army", "fy24_qty": null, "fy25_qty": null, "appr_code": "2031", "appr_name": "Aircraft Procurement, Army", "fy26_v178": {"note": "no_parser_pair", "source": "p40_fy26_v178"}, "fy26t_qty": null, "fy26d_cost": 0, "fy26r_cost": 0, "ident_code": ""}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 26850000, 0, 0, 0, 0, NULL, NULL, $$Budget J-Books/FY27/Army/Aircraft_Procurement_Army.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603469E$$, $$ADVANCED ENABLING TECHNOLOGIES$$, $$rdte_dw_ba3$$, $$dw_darpa$$, 2026, 345647000, 0, 0, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 69, "original_pe": "0603469E", "page_header": "Defense-Wide", "fy26_v182_disc_K": 317460, "fy26_v182_supp_K": 20000, "fy26_v182_total_K": 337460, "fy26_v182_note_name": "Research, Development, Test and Evaluation, Defense-Wide for DARPA", "fy26_v182_source_file": "RDTE_Vol1_DARPA_MasterJustificationBook_PB_2027.txt", "fy26_v182_source_line": 11604}$$::jsonb, $$The Advanced Enabling Technologies program element is focused on exploiting opportunities to leverage novel capabilities to address the challenges of the modern physical and cyber battlefields. Programs will explore new concepts across electronics, quantum, photonics, materials, communication, software, artificial intelligence (AI), machine learning (ML), and cyber while also pulling from the best available commercial technologies and combining them in ways that give the warfighter disruptive capabilities. Efforts conducted under this program element include quantum circuits, integrated photonic-electronic components, novel materials, next generation command and control, resilient software, formal methods, adversarial AI/ML, and AI/ML-based cyber. This PE also supports innovation and robust transition and experimentation planning in the technology cycle to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. The Advanced C4 project develops and demonstrates technologies that will provide effective communications, information integration, and decision support to U.S. forces. The success of military operations depends on timely, reliable, secure, and synchronized dissemination of command and control and relevant situational awareness information to every military echelon. Technologies are intended to support highly distributed crewed, uncrewed, and human machine teams in all domains and across the entire spectrum of conflict, specifically end-to-end kill chains. While leveraging advancements in commercial technology development, novel approaches promote adaptability, resilience and reliability to overcome environmental challenges while countering a highly capable and dynamic adversary. The Advanced Disruptive Microtechnologies project supports activities to enable and accelerate the transition of advanced microsystems advancement, including those developed under the Disruptive Microtechnologies Sciences (EMR-02) and Disruptive Microtechnologies (MSL-02) projects. Funding under this project will include quantum circuits for computation and sensing; integrated photonic-electronic components for timing and data transfer; and developing new technologies and capabilities that intelligently leverage commercial scaling while still preserving advanced capabilities for the warfighter. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                              Date: June 2025 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:                 PE 0603469E / ADVANCED ENABLING TECHNOLOGIES Advanced Technology Development (ATD) The Advanced Cyber Systems project develops, implements, and demonstrates techniques, tools, and frameworks for the full range of cyber operations. Cyber is now ubiquitous to warfighting. For non-kinetic operations in advance of lethal conflict, cyber can be a powerful enabler of information operations that limit adversary options and deter adversary actions. For kinetic operations during lethal conflict, cyber can be a force multiplier and provide an asymmetric advantage. The Advanced Cyber Systems project aims to create operational prototypes based on the cyber technology developed in applied research programs in the private sector and in academia. The utility of the operational prototypes that are developed in this project will be assessed, and improvements made, based on demonstrations and evaluations conducted in collaboration with warfighters, acquisition programs, and combatant commands. The Advanced Enabling Technologies Support project contains non-headquarters management costs in support of DARPA functions and activities across the entire Advanced Enabling Technologies PE. These costs include: DARPA classified and unclassified network support and equipment; contractor support; classified program security; building security; commercial transition services that increase the likelihood that DARPA-funded technologies remain in the U.S. and provide new capabilities for national defense; DARPA outreach to universities and industry; external contracting, financial and support fees; Program Manager Intragovernmental Personnel Act (IPA) Funding; Program Managers from other Government Agencies; and similar operating expenses. Agency support is allocated on a pro-rata basis across the Agency's BA1, BA2 and BA3 PEs and, therefore, fluctuates per PE by fiscal year based on the total Agency budget in that fiscal year. Prior to FY 2026, efforts in this PE were funded in PE 0603760E, Command, Control and Communications Systems, and PE 0603739E, Advanced Electronics Technologies.$$, NULL, 539812000, 667235000, 673690000, NULL, NULL, 57, $$RDTE_Vol1_DARPA_MasterJustificationBook_PB_2026.pdf$$, $$DARPA$$, FALSE, 0, 337460000, 331007000, 331007000, NULL, 331007000, 707458000, $$The Advanced Enabling Technologies program element is focused on exploiting opportunities to leverage novel capabilities to address the challenges of the modern physical and cyber battlefields. Programs will explore new concepts across electronics, quantum, photonics, materials, communication, software, artificial intelligence (AI), machine learning (ML), and cyber while also pulling from the best available commercial technologies and combining them in ways that give the warfighter disruptive capabilities. Efforts conducted under this program element include quantum circuits, integrated photonic-electronic components, novel materials, next generation command and control, resilient software, formal methods, adversarial AI/ML, and AI/ML-based cyber. This PE also supports innovation and robust transition and experimentation planning in the technology cycle to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. The Advanced C4 project develops and demonstrates technologies that will provide effective communications, information integration, and decision support to U.S. forces. The success of military operations depends on timely, reliable, secure, and synchronized dissemination of command and control and relevant situational awareness information to every military echelon. Technologies are intended to support highly distributed crewed, uncrewed, and human machine teams in all domains and across the entire spectrum of conflict, specifically end-to-end kill chains. While leveraging advancements in commercial technology development, novel approaches promote adaptability, resilience and reliability to overcome environmental challenges while countering a highly capable and dynamic adversary. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Advanced Research Projects Agency                                           Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:              PE 0603469E / ADVANCED ENABLING TECHNOLOGIES Advanced Technology Development (ATD) The Advanced Disruptive Microtechnologies project supports activities to enable and accelerate the transition of advanced microsystems advancement, including those developed under the Disruptive Microtechnologies Sciences (EMR-02) and Disruptive Microtechnologies (MSL-02) projects. Funding under this project will include quantum circuits for computation and sensing; integrated photonic-electronic components for timing and data transfer; and developing new technologies and capabilities that intelligently leverage commercial scaling while still preserving advanced capabilities for the warfighter. The Advanced Cyber Systems project develops, implements, and demonstrates techniques, tools, and frameworks for the full range of cyber operations. Cyber is now ubiquitous to warfighting. For non-kinetic operations in advance of lethal conflict, cyber can be a powerful enabler of operations that limit adversary options and deter adversary actions. For kinetic operations during lethal conflict, cyber can be a force multiplier and provide an asymmetric advantage. The Advanced Cyber Systems project aims to create operational prototypes based on the cyber technology developed in applied research programs in the private sector and in academia. The utility of the operational prototypes that are developed in this project will be assessed, and improvements made, based on demonstrations and evaluations conducted in collaboration with warfighters, acquisition programs, and combatant commands. The Advanced Enabling Technologies Support project contains management costs in support of DARPA functions and activities across the entire Advanced Enabling Technologies PE. These costs include: DARPA classified and unclassified network support and equipment; contractor support; classified program security; building security; commercial transition services that increase the likelihood that DARPA-funded technologies remain in the U.S. and provide new capabilities for national defense; DARPA outreach to universities and industry; external contracting, financial and support fees; Program Manager Intragovernmental Personnel Act (IPA) Funding; Program Managers from other Government Agencies; and similar operating expenses. Agency support is allocated on a pro-rata basis across the Agency's BA1, BA2 and BA3 PEs and, therefore, fluctuates per PE by fiscal year based on the total Agency budget in that fiscal year. Prior to FY 2026, efforts in this PE were funded in PE 0603760E, Command, Control and Communications Systems, and PE 0603739E, Advanced Electronics Technologies.$$, $$Budget J-Books/FY27/DW/RDTE_Vol1_DARPA_MasterJustificationBook_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603506N$$, $$Surface Ship Torpedo Defense$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 11832000, 728000, 4790000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 28, "original_pe": "0603506N", "page_header": "Department of the Navy"}$$::jsonb, $$The Surface Ship Torpedo Defense (SSTD) program provides a detect-to-engage layered torpedo defense capability. The four (4) major efforts that comprise SSTD are the AN/SLQ-25 (NIXIE) system, Torpedo Warning System (TWS), the Countermeasure Anti-Torpedo (CAT), and Acoustic Device Countermeasure (Surface ADC MK2). A layered torpedo defense to protect surface ships against current and future threats. SSTD development will include a new anti-torpedo Hard Kill (HK) capability by pairing proven technology and the MK 58 Compact Rapid Attack Weapon (CRAW) with improved AN/SLQ-25E that has additional software capabilities. An upgrade to the AN/SLQ25E system using MK 58 CRAW along with an ADC launcher is detailed below as the NIXIE HK. FY 2024 funding provided minimal support to the 2 remaining CVN installations with system preservation the primary focus. FY 2024 funding also supported the beginning of a Research, Development, Test & Evaluation (RDT&E) planning efforts to develop and incorporate TWS capabilities into the AN/SLQ-25 (Nixie) via a series Tech Insertions (TIs). FY 2025 funding supported the two remaining TWS on installed systems and established development of a NIXIE follow-on Torpedo Defense Hardkill System that will incorporate the capabilities of the TWS, the Compact Rapid Attack Weapon (CRAW), and ADC MK2 MOD6/8. FY 2026 funding will support the continued development of the NIXIE Torpedo Defense Hardkill (HK) system with concentration on the development of the torpedo alertment and fire control / Torpedo Warning System (TWS) integration into the NIXIE 25E tow. FY 2026 funds will also support the development of NIXIE 25E software & winch improvements along with the development of a CRAW launcher that will be capable of launching the Anti-Torpedo Torpedo (ATT) variant of the CRAW and the ADC MK2 MOD 6/8 and MK5 (series) Acoustic Countermeasures Device (ADC). Research and development of new technologies and capabilities for torpedo defense initiated under the Future Naval Capabilities (FNC), Small Business and Innovative Research (SBIR), and/or other Research, Development, Test & Evaluation (RDT&E) initiatives are evaluated to determine their effectiveness and impact on improving ship survivability. Evaluations of new and emerging torpedo defense hardware and software in representative acoustic environments, against projected threats using both digital and hardware-in-the-loop simulations will be performed. The potential hardware and software will be considered for integration into the modular and Commercial-Off-The-Shelf (COTS)-based design of AN/SLQ-25E, which allows for future capability growth into a NIXIE HK System to outpace the threat in torpedo defense. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                            Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced         PE 0603506N / Surface Ship Torpedo Defense Component Development & Prototypes (ACD&P)$$, NULL, 25791000, 28059000, 40668000, NULL, NULL, 36, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 4632000, 11832000, 9920000, 9920000, NULL, 9920000, 41396000, $$The Surface Ship Torpedo Defense (SSTD) program provides a detect-to-engage layered torpedo defense capability. The four (4) major efforts that comprise SSTD are the AN/SLQ-25 (NIXIE) system, Torpedo Warning System (TWS), the Countermeasure Anti-Torpedo (CAT), and Acoustic Device Countermeasure (Surface ADC MK2). A layered torpedo defense to protect surface ships against current and future threats. SSTD development will include a new anti-torpedo Hard Kill (HK) capability by pairing proven technology and the MK 58 the Compact Rapid Attack Weapon (CRAW) with improved AN/SLQ-25E that has additional software capabilities. An upgrade to the AN/SLQ25E system using MK 58 CRAW along with an Acoustic Device Countermeasure (ADC) launcher is detailed below as the NIXIE HK. FY 2027 funding will support the continued development of the NIXIE Torpedo Defense HK system with concentration on the development of the torpedo alertment and fire control / TWS integration into the NIXIE 25E tow. Research and development of new technologies and capabilities for torpedo defense initiated under the Future Naval Capabilities (FNC), Small Business and Innovative Research (SBIR), and/or other RDT&E initiatives are evaluated to determine their effectiveness and impact on improving ship survivability. Evaluations of new and emerging torpedo defense hardware and software in representative acoustic environments, against projected threats using both digital and hardware-in-the-loop simulations will be performed. The potential hardware and software will be used for integration into the modular and Commercial-Off-The-Shelf (COTS)-based design of AN/SLQ-25E, which allows for future capability growth into a NIXIE HK System to outpace the threat in torpedo defense.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603512N$$, $$Carrier Systems Development$$, $$rdte_navy_ba4$$, $$peo_aasm$$, 2026, 8361000, 10244000, 5659000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 28, "original_pe": "0603512N", "page_header": "Department of the Navy"}$$::jsonb, $$This Program Element (PE) addresses technology areas associated with Command and Control (C2) of the MH-60R/S Seahawk Helicopter, as well as the development of other technologies and enhancements for Aircraft Carrier-based systems. PROJECT 3216: The AN/SQQ-34 Aircraft Carrier Tactical Support Center (CV-TSC) program delivers Anti-Submarine Warfare (ASW) and Surface Warfare (SUW) combat capability to the Aircraft Carrier supporting Aircraft Carrier, Nuclear power (CVN) Tactical Action Office (TAO) and embarked Carrier Strike Group (CSG) Sea Combat Commander. This project develops, tests, certifies, and fields improved combat capability and critical cyber-security enhancements via incremental Fleet Capability Releases (FCR). The project maintains interoperability with current interfaces and develops interoperability with future interfaces; supports mission data exchange; improves ASW/SUW track/sensor processing and analysis techniques; improves mission planning; improves data recording, reconstruction, and distribution; improves embedded simulation and training capabilities; and implements cyber-security measures to effectively employ overall CVN self-defense capabilities. CV- TSC integrates sensor data from organic rotary wing aircraft (MH-60R), organic platform sensors and tracks via Ship Self Defense System (SSDS) (both Product Line Architecture (PLA) and non-PLA), Link-16 track data, Global Command and Control System (GCCS) Over-the-Horizon (OTH) track data, and environmental and threat databases to assess the threat and assist the TAO and CSG to effectively employ overall CVN self-defense capabilities against ASW/SUW threats. Current development efforts are focused on extending non-organic ASW/SUW data sources to provide situational awareness and targets beyond the CSG surveillance area. This includes Minotaur Family of Services (MFoS)/Joint Tactical Terminal - Maritime (JTT-M) and Maritime Targeting Cell - Afloat (MTC-A), Integrated Broadcast Service (IBS), and future Resilient Command & Control, Communication (RC3) data links. CV-TSC generates real-time ASW/SUW information and recommendations, tactical planning and employment of ASW/SUW assets, ASW/SUW sensor data processing and analysis, and distribution of tactically significant data. Aircraft supported include the MH-60R/S Seahawk, with P-8 Poseidon and MQ-4C Triton as future ASW/SUW non-organic supporting platforms. FY 2026 will focus on final development and testing of FCR-7, to include critical software architecture upgrades, MTC-A integration, MH-60S interface enhancements, cyber-security upgrades, as well as the initiation of FCR-8 development, to include Integrated Combat System (ICS) integration, development, and testing. PROJECT 4005: The In-Service Carrier Systems Development Demonstration and Validation Program develops new technology and enhancements to deliver an affordable, robust, operator-friendly automation control environment for Navy Aircraft Carrier shipboard equipment. The program provides the system architecture, requirements/specification development, technology selection, software development (including software baseline), manpower requirements, Total Ownership Costs (TOC), cyber-security engineering and integration, as well as land-based and shipboard testing of new technologies to improve shipboard operations. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                              Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced           PE 0603512N / Carrier Systems Development Component Development & Prototypes (ACD&P) PROJECT 9999 / C989: CONGRESSIONAL ADD - Digital Component Certification Center tri-service, Army-Air Force-Navy installation for Joint Base McGuire-Dix- Lakehurst to address cyber threats to Naval Aviation Aircraft Carrier Systems.$$, NULL, 7944000, 8058000, 8153000, NULL, NULL, 37, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 5583000, 8361000, 8806000, 8806000, NULL, 8806000, 8300000, $$This Program Element (PE) addresses technology areas associated with Command and Control (C2) of the MH-60R/S Seahawk Helicopter, as well as the development of other technologies and enhancements for Aircraft Carrier-based systems. PROJECT 3216: The AN/SQQ-34 Aircraft Carrier Tactical Support Center (CV-TSC) program delivers Anti-Submarine Warfare (ASW) and Surface Warfare (SUW) combat capability to the Aircraft Carrier supporting Aircraft Carrier, Nuclear power (CVN) Tactical Action Office (TAO) and embarked Carrier Strike Group (CSG) Sea Combat Commander. This project develops, tests, certifies, and fields improved combat capability and critical cyber-security enhancements via incremental Fleet Capability Releases (FCR). The project maintains interoperability with current interfaces and develops interoperability with future interfaces; supports mission data exchange; improves ASW/SUW track/sensor processing and analysis techniques; improves mission planning; improves data recording, reconstruction, and distribution; improves embedded simulation and training capabilities; and implements cyber-security measures to effectively employ overall CVN self-defense capabilities. CV-TSC integrates sensor data from organic rotary wing aircraft (MH-60R/S), organic platform sensors and tracks via Ship Self Defense System (SSDS) (both Product Line Architecture (PLA) and non-PLA), Link-16 track data, Global Command and Control System (GCCS) Over-the-Horizon (OTH) track data, and environmental and threat databases to assess the threat and assist the TAO and CSG to effectively employ overall CVN self-defense capabilities against ASW/SUW threats. Current development efforts are focused on extending non-organic ASW/SUW data sources to provide situational awareness and targets beyond the CSG surveillance area. This includes Joint Tactical Terminal - Maritime (JTT-M), Maritime Targeting Cell - Afloat (MTC-A), Integrated Broadcast Service (IBS), and future Resilient Command & Control, Communication (RC3) data links. CV-TSC generates real-time ASW/SUW information and recommendations, tactical planning and employment of ASW/SUW assets, ASW/SUW sensor data processing and analysis, and distribution of tactically significant data. Aircraft supported include the MH-60R/S Seahawk, with P-8 Poseidon and MQ-4C Triton as future ASW/SUW non-organic supporting platforms. FY 2027 will focus on final testing and certification of FCR-7, which delivers critical software architecture and networking upgrades, MTC-A integration, MH-60S Knightlink interface enhancements, and cyber-security upgrades; FCR-8 software development, to include system architecture and networking modifications for integration into the future Integrated Combat System (ICS); and initiating FCR-8 Independent Verification and Validation (IV&V) to include external interface tests with the multiple interfacing systems CV-TSC supports. PROJECT 4005: The In-Service Carrier Systems Development Demonstration and Validation Program develops new technology and enhancements to deliver an affordable, robust, operator-friendly automation control environment for Navy Aircraft Carrier shipboard equipment. The program provides the system architecture, requirements/specification development, technology selection, software development (including software baseline), manpower requirements, Total Ownership Costs (TOC), cyber-security engineering and integration, as well as land-based and shipboard testing of new technologies to improve shipboard operations. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                            Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced          PE 0603512N / Carrier Systems Development Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603525N$$, $$PILOT FISH$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 1218486000, 877003000, 982324000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 28, "original_pe": "0603525N", "page_header": "Department of the Navy"}$$::jsonb, $$The details of this budget justification are classified, per Executive Order 13526, Sec 1.4 (a) and are submitted annually to Congress in the classified budget justification book.$$, NULL, NULL, NULL, NULL, NULL, NULL, 38, $$Budget J-Books/FY27/Remaining/FY2027_r1.pdf$$, NULL, FALSE, 937900000, 1118482000, 1339052000, 1339052000, 0, 1339052000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.txt$$) ON CONFLICT DO NOTHING;
