INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603536N$$, $$RETRACT JUNIPER$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 206429000, 200890000, 199172000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 28, "original_pe": "0603536N", "page_header": "Department of the Navy"}$$::jsonb, $$The details of this budget justification are classified, per Executive Order 13526, Sec 1.4 (a) and are submitted annually to Congress in the classified budget justification book.$$, NULL, NULL, NULL, NULL, NULL, NULL, 39, $$Budget J-Books/FY27/Remaining/FY2027_r1.pdf$$, NULL, FALSE, 197772000, 184606000, 275300000, 275300000, 0, 275300000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603542N$$, $$Radiological Control$$, $$rdte_navy_ba4$$, $$msc$$, 2026, 730000, 808000, 801000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 28, "original_pe": "0603542N", "page_header": "Department of the Navy"}$$::jsonb, $$Mission Description: The Radiation Detection, Indication and Computation (RADIAC) Program is responsible for providing radiation monitoring instruments that detect and measure ionizing radiation. These instruments are used on all Navy, Coast Guard and Military Sealift Command vessels, and at every Navy shore installation, in order to ensure the safety of personnel, continuity of operations in radiological contingencies, and protection of the environment. Justification: Title 10 of the Code of Federal Regulations, Part 20 (10 CFR 20) requires RADIAC instruments be used to ensure the safety of personnel who work with or who are exposed to radioactive materials in their jobs. Additionally, the Navy's mission requires personnel and ships to have the ability to operate in radiological environments and the ability to identify and interdict radiological Weapons of Mass Destruction (WMD). Navy programs that require RADIAC instruments for Occupational Safety & Health (OSH) under the provisions of 10 CFR 20 include Naval Nuclear Propulsion, Nuclear Weapons, Medical, and Radiological Affairs Support. Non-OSH programs include Radiological Defense, Consequence Management, Training, Technical (RADIAC calibration, shielding evaluation, research) and Radiological Search (maritime interdiction and radiological search missions to locate or intercept WMD). This budget item develops, tests and evaluates new, highly reliable, more easily calibrated, easy to care and maintain, light weight and modern RADIAC instruments in order to improve the effectiveness of radiation safety, to make instruments simpler to use, and to reduce life cycle costs. The ultimate goal is to replace old, bulky, costly to maintain and repair, unreliable and obsolete instrumentation with multifunction equipment that can be automatically calibrated at greatly reduced cost.$$, NULL, 723000, 734000, 745000, NULL, NULL, 41, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 795000, 730000, 704000, 704000, NULL, 704000, 758000, $$Mission Description: The Radiation Detection, Indication and Computation (RADIAC) Program is responsible for providing radiation monitoring instruments that detect and measure ionizing radiation. These instruments are used on all Navy, Coast Guard and Military Sealift Command vessels, and at every Navy shore installation, in order to ensure the safety of personnel, continuity of operations in radiological contingencies, and protection of the environment. Justification: Title 10 of the Code of Federal Regulations, Part 20 (10 CFR 20) requires RADIAC instruments be used to ensure the safety of personnel who work with or who are exposed to radioactive materials in their jobs. Additionally, the Navy's mission requires personnel and ships to have the ability to operate in radiological environments and the ability to identify and interdict radiological Weapons of Mass Destruction (WMD). Navy programs that require RADIAC instruments for Occupational Safety & Health (OSH) under the provisions of 10 CFR 20 include Naval Nuclear Propulsion, Nuclear Weapons, Medical, and Radiological Affairs Support. Non-OSH programs include Radiological Defense, Consequence Management, Training, Technical (RADIAC calibration, shielding evaluation, research) and Radiological Search (maritime interdiction and radiological search missions to locate or intercept WMD). This budget item develops, tests and evaluates new, highly reliable, more easily calibrated, easy to care and maintain, light weight and modern RADIAC instruments in order to improve the effectiveness of radiation safety, to make instruments simpler to use, and to reduce life cycle costs. The ultimate goal is to replace old, bulky, costly to maintain and repair, unreliable and obsolete instrumentation with multifunction equipment that can be automatically calibrated at greatly reduced cost.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603553N$$, $$Surface ASW$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 0, 1142000, 1194000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 28, "original_pe": "0603553N", "page_header": "Department of the Navy"}$$::jsonb, $$Effective FY 2026, Project 1704 moves from PE 0603553N to PE 0603561N as part of the PE/BLI consolidation effort in the DoD Implementation Plan from the Commission on Planning, Programming, Budgeting, and Execution (PPBE) Reform Final Report in an effort to rapidly increase Navy Lethality in the Submarine and Surface Fleet. The objective of this Program Element (PE) is to pursue the development of technologies with the goal of improving Anti-Submarine Warfare (ASW) effectiveness to the point of rendering the enemy submarine irrelevant against U.S. and coalition forces. U.S. adversaries continue to develop asymmetric capabilities and capacities to deter, disrupt, or delay the entry of U.S. and allied naval forces, and pose a constant challenge as we implement the Maritime Strategy. These trends increase the threats to U.S. surface combatants, thus requiring a focused effort to identify the most promising ASW technologies through a process of discovery, assessment, experimentation, and analysis. Studies, experiments, and/or technology developments under this PE will seek to improve the ability of surface combatants to detect, classify, localize, and track submerged contacts and detect and defend against modern torpedoes. To achieve these objectives, it is essential to develop new ASW technologies. The products from these efforts will be provided to the Advanced Capability Build (ACB) program supporting the continuing improvement of the AN/ SQQ-89A(V)15 Surface Ship ASW Combat System.$$, NULL, 0, 0, 0, NULL, NULL, 42, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 1147000, 0, 0, 0, NULL, 0, 0, $$The objective of this Program Element (PE) is to pursue the development of technologies with the goal of improving Anti-Submarine Warfare (ASW) effectiveness to the point of rendering the enemy submarine irrelevant against U.S. and coalition forces. U.S. adversaries continue to develop asymmetric capabilities and capacities to deter, disrupt, or delay the entry of U.S. and allied naval forces, and pose a constant challenge as we implement the Maritime Strategy. These trends increase the threats to U.S. surface combatants, thus requiring a focused effort to identify the most promising ASW technologies through a process of discovery, assessment, experimentation, and analysis. Studies, experiments, and/or technology developments under this PE will seek to improve the ability of surface combatants to detect, classify, localize, and track submerged contacts and detect and defend against modern torpedoes. To achieve these objectives, it is essential to develop new ASW technologies. The products from these efforts will be provided to the Advanced Capability Build (ACB) program supporting the continuing improvement of the AN/ SQQ-89A(V)15 Surface Ship ASW Combat System.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603561N$$, $$Advanced Submarine System Development$$, $$rdte_navy_ba4$$, $$dw_darpa$$, 2026, 162651000, 93255000, 106694000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 28, "original_pe": "0603561N", "page_header": "Department of the Navy"}$$::jsonb, $$Effective FY26, the scope of this PE is changing based on the PE/BLI consolidation effort in the DoD Implementation Plan from the Commission on Planning, Programming, Budgeting, and Execution (PPBE) Reform Final Report with the intention of rapidly increasing Navy Lethality in the Submarine and Surface Fleet. The focus of this PE (existing Projects 0223 and 2033) is to support innovative research and development in submarine Hull, Mechanical and Electrical (HM&E) and combat systems technologies and the subsequent evaluation, demonstration, and validation for submarine platforms. It will increase the submarine technology base and provide subsystem design options not currently feasible. The PE also supports programs transitioning from Science and Technology (S&T), Defense Advanced Research Projects Agency (DARPA), Office of Naval Research (ONR), Independent Research & Development (IR&D), and Small Business Innovation Research (SBIR) projects. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                               Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced              PE 0603561N / Advanced Submarine System Development Component Development & Prototypes (ACD&P) Beginning in FY26, this PE will incorporate existing projects/funding from the following Program Executive Office for Integrated Warfare Systems (PEO IWS) PEs: Project 1916 from PE 0205620N Surface Anti-Submarine Warfare (ASW) Combat System Integration; Project 1704 from PE 0603553N Surface ASW; Projects 0770 and 1739 from PE 0603562N Submarine Tactical Warfare Systems; and Projects 3094 and 3439 from PE 0604518N Combat Information Center Conversion. DESCRIPTION/JUSTIFICATION BY PROJECT: PROJECT 0223: The Submarine Combat System Improvement (Advanced) (Non-ACAT) project researches, develops, and tests new sonar, combat system, imaging, and electronic warfare software for Program Executive Office, Undersea Warfare Systems (PEO UWS), delivering new capabilities every other year. The project also develops, tests, and prototypes new sonar arrays for PMS 401, the Submarine Acoustics Program Office in PEO UWS. This project supports Navy Submarine Acoustic Superiority and Technology Insertion (TI) initiatives through the application of advanced development and testing of sensors and sensor processing systems supporting tactical control systems improvements. Improvements are supportive of "Advantage at Sea: Prevailing with Integrated All-Domain Naval Power", Secretary of the Navy (SECNAV) Naval Science and Technology Strategy, and the Chief of Naval Operations (CNO) "America's Warfighting Navy"; addressing threats posed by strategic adversaries China and Russia. This project targets all force design imperatives rapidly providing unique capabilities to expand distance and generate decision advantage. Project 0223 is comprised of three (3) major efforts: Advanced Processing Builds (APB), Advanced Sensors, and Large Vertical Array (LVA). APB develops, tests and transitions capabilities for: - Acoustics, transitioning to AN/BQQ-10; - Tactical control, transitioning to AN/BYG-1; - Imaging, transitioning to AN/BVY-1; and - Electronic Warfare (EW), transitioning to AN/BLQ-10. Advanced Sensors develops new technologies for hull-mounted and towed arrays. Hull-mounted array improvements support submarine applications only. Towed array improvements are developed to support submarine, surface, and surveillance applications. LVA leverages demonstrated flank array developments to conduct critical testing and analysis needed to improve array performance and develop sensor employment tactics. It introduces new electronic hardware and software applications to enhance array and signal processing performance. These improvements will be incorporated in future LVA builds for Virginia class SSNs, Ohio and Columbia classes of SSBNs, as well as backfits. The LVA project also sustains the prototype LVA on USS Maryland. PROJECT 0770 - The Advanced Submarine Support Equipment Program (ASSEP) objective is to improve submarine operational effectiveness through the implementation of advanced Research and Development (R&D) efforts focused on advanced Imaging and Electronic Warfare (EW) support. A continuing need exists to improve these capabilities in view of the advancements in imaging counter-detection, the need to support specialized missions, and the increasingly dense and sophisticated electronic environment caused by the proliferation of complex radar, communications, and navigation equipment of our adversaries. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                               Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced           PE 0603561N / Advanced Submarine System Development Component Development & Prototypes (ACD&P) Ongoing developments include improved antennas, tethered buoy, 360-degree imaging systems, and electro-optic infra-red (EO/IR) vulnerability signature reduction technologies. This project also supports the development of changes internal to submarine platforms to integrate the Submarine Tethered Expendable Buoy (STEB). This integration will provide a communications path to and from the buoy bringing buoy sensor data into the submarine combat system to improve situational awareness and tactical control while maintaining a covert posture. PROJECT 1704: The objective of the Undersea Warfare (USW) project is to pursue the development of technologies with the goal of improving Anti-Submarine Warfare (ASW) effectiveness to the point of rendering the enemy submarine irrelevant against U.S. and coalition forces. U.S. adversaries continue to develop asymmetric capabilities and capacities to deter, disrupt, or delay the entry of U.S. and allied naval forces, and pose a constant challenge as we implement the Maritime Strategy. These trends increase the threats to U.S. surface combatants, thus requiring a focused effort to identify the most promising ASW technologies through a process of discovery, assessment, experimentation, and analysis. Studies, experiments, and/or technology developments under this PE will seek to improve the ability of surface combatants to detect, classify, localize, and track submerged contacts and detect and defend against modern torpedoes. To achieve these objectives, it is essential to develop new ASW technologies. The products from these efforts will be provided to the Advanced Capability Build (ACB) program supporting the continuing improvement of the AN/SQQ-89A(V)15 Surface Ship ASW Combat System. PROJECT 1739 - The Submarine Arctic Warfare Development Project is aligned to Commander, Undersea Warfighting Development Center (UWDC), Detachment Arctic Submarine Laboratory (ASL). This Project provides the U.S. Navy Submarine Force (SUBFOR) a cadre of trained Arctic Operation Specialists (AOS) and an inventory of unique Arctic sensors that are installed to optimize submarine safety during under-ice operations. AOS personnel assigned from ASL embark on submarines that deploy to the Arctic, cold water and iceberg regions, and marginal ice zones (MIZ) in northern latitudes of the Atlantic and Pacific Oceans and are advisers to the Commanding Officer. ASL is a shore facility at Naval Base Point Loma with the infrastructure capable of supporting personnel and equipment to conduct the submarine Arctic Warfare Development mission. Improvements and life-cycle expenditures to the facility and warehousing are made as necessary to support the mission. Project 1739, via ASL, responds to the increased threat of naval activity in the Arctic regions while continuously supporting the Navy's strategic objective of Assured Access and Combat Credibility. ASL provides a unique capability that enables the SUBFOR to satisfy the requirements laid out in the Arctic Maritime Homeland Defense Initial Capabilities Document (ICD). ASL and SUBFOR demonstrate existing Arctic Warfare capabilities and operational and tactical proficiency while developing advanced submarine technology in unique cold-water environments, in under-ice conditions, and in ice-covered shallow water regions through the Ice Exercise (ICEX) program that includes Operation Ice Camp. ICEX places an emphasis on submarine operability and mission capability in the world's harshest maritime environment. Efforts include assessment of combat system effectiveness, weapons testing, use of High Frequency (HF) sonars in Arctic regions, testing of ice-capable submarine structures, and development of class-specific Arctic operational guidelines. Tactical Development (TACDEV) is conducted biennially and requires up front comprehensive planning and work-up training, as well as post exercise analysis and reporting. ICEX provides the framework for various submarine test and evaluation efforts in Arctic regions and at periodic Ice Camps. The ICEX program represents DoD's only drifting ice station capability through Operation Ice Camp. Emphasis during Operation Ice Camp is placed on the areas of sonar operability, tactical surveillance, weapon utility, and other submarine support missions. A Torpedo Exercise (TORPEX) occurs every four (4) years in order to meet minimum Fleet requirements of exercise torpedo (EXTORP) firings in the Arctic. A TORPEX requires a significantly higher level of logistics, personnel, and infrastructure to account for the recovery and transportation efforts of the EXTORPs. The ICEX Program also includes Arctic Exercise (ARCEX), a biennial exercise that rotates with the biennial Operation Ice Camp drifting ice camps, that includes Arctic operations to support ice camp equipment evaluation, systems development, extreme cold weather training, drifting sea ice and scientific research. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                              Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced          PE 0603561N / Advanced Submarine System Development Component Development & Prototypes (ACD&P) PROJECT 1916: The objective of the Surface ASW System Improvement project is to significantly improve existing AN/SQQ-89A(V)15 Surface Ship ASW sonar system capabilities through quick and affordable development and integration of emergent, transformational technologies in support of Surface Ship and Theater ASW (TASW) as required to pace the threat. Detection and classification play uniquely vital roles in the success of any ASW campaign. The ACB spiral development process is the primary means by which these improvements are developed. This project takes advantage of the AN/SQQ-89A(V)15 Open System Architecture (OSA) and Acoustic Rapid Commercial-Off-The-Shelf (COTS) Insertion (ARCI) initiatives to integrate Torpedo Detection, Classification, and Localization (TDCL) and ASW sonar combat system capability improvements. The AN/SQQ-89A(V)15 COTS-based Surface Ship ASW Combat System is planned as a backfit program for all DDG51 class ships, but also contributes to the development of the ASW component of the guided missile Frigate (CONSTELLATION Class, FFG 62) program. The Open Architecture (OA) system enables the ACB process and provides budget flexibility to make COTS/OA technology solutions and ARCI-type initiatives affordable. Improvements are tested in the laboratory and at-sea. USW technology implementation will take advantage of improvements developed under the submarine APB and Advanced Surveillance Build (ASB) pr… [truncated]$$, NULL, 137023000, 134475000, 137099000, NULL, NULL, 43, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 103870000, 171718000, 132885000, 132885000, NULL, 132885000, 136948000, $$Effective FY26, the scope of this PE changed based on the PE/BLI consolidation effort in the DoD Implementation Plan from the Commission on Planning, Programming, Budgeting, and Execution (PPBE) Reform Final Report with the intention of rapidly increasing Navy Lethality in the Submarine and Surface Fleet. The focus of this PE (existing Projects 0223 and 2033) is to support innovative research and development in submarine Hull, Mechanical and Electrical (HM&E) and combat systems technologies and the subsequent evaluation, demonstration, and validation for submarine platforms. It will increase the submarine technology base and provide subsystem design options not currently feasible. The PE also supports programs transitioning from Science and Technology (S&T), Defense Advanced Research Projects Agency (DARPA), Office of Naval Research (ONR), Independent Research & Development (IR&D), and Small Business Innovation Research (SBIR) projects. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                               Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced            PE 0603561N / Advanced Submarine System Development Component Development & Prototypes (ACD&P) Beginning in FY26, this PE incorporates existing projects/funding from the following Program Executive Office for Integrated Warfare Systems (PEO IWS) PEs: Project 1916 from PE 0205620N Surface Anti-Submarine Warfare (ASW) Combat System Integration; Project 1704 from PE 0603553N Surface ASW; Projects 0770 and 1739 from PE 0603562N Submarine Tactical Warfare Systems; and Projects 3094 and 3439 from PE 0604518N Combat Information Center Conversion. DESCRIPTION/JUSTIFICATION BY PROJECT: PROJECT 0223: The Submarine Combat System Improvement (Advanced) (Non-ACAT) project researches, develops, tests, and delivers capabilities for sonar, combat system, imaging, and electronic warfare software for PEO Undersea Warfare Systems (UWS) programs of record. The project also develops, tests, and prototypes new sonar arrays for PMS 401, the Submarine Acoustics Program Office in PEO UWS. This project supports Navy Submarine Acoustic Superiority and Technology Insertion (TI) initiatives through the application of advanced development and testing of sensors and sensor processing systems supporting tactical control systems improvements. Improvements are supportive of "Advantage at Sea: Prevailing with Integrated All-Domain Naval Power", Secretary of the Navy (SECNAV) Naval Science and Technology Strategy, and the Chief of Naval Operations (CNO) "America's Warfighting Navy"; addressing threats posed by strategic adversaries China and Russia. This project targets all force design imperatives rapidly providing unique capabilities to expand distance and generate decision advantage. Project 0223 is comprised of three (3) major efforts: Advanced Processing Builds (APB), Advanced Sensors, and Large Vertical Array (LVA). APB develops, tests and transitions capabilities for: - Acoustics, transitioning to AN/BQQ-10; - Tactical control, transitioning to AN/BYG-1; - Imaging, transitioning to AN/BVY-1; and - Electronic Warfare (EW), transitioning to AN/BLQ-10. Advanced Sensors develops new technologies for hull-mounted and towed arrays. Hull-mounted array improvements support submarine applications only. Towed array improvements are developed to support submarine, surface, and surveillance applications. LVA leverages demonstrated flank array developments to conduct critical testing and analysis needed to improve array performance and develop sensor employment tactics. It introduces new electronic hardware and software applications to enhance array and signal processing performance. These improvements are being incorporated in LVA builds for Virginia class SSNs, Ohio and Columbia classes of SSBNs, as well as backfits. The LVA project also sustains the prototype LVA on USS Maryland. PROJECT 0770 - The Advanced Submarine Support Equipment Program objective is to improve submarine operational effectiveness through the implementation of advanced R&D efforts focused on advanced Imaging and EW support. A continuing need exists to improve these capabilities in view of the advancements in imaging counter-detection, the need to support specialized missions, and the increasingly dense and sophisticated electronic environment caused by the proliferation of complex radar, communications, and navigation equipment of our adversaries. Ongoing developments include improved antennas, tethered buoy, 360-degree imaging systems, and electro-optic infra-red (EO/IR) vulnerability signature reduction technologies. This project also supports the development of changes internal to submarine platforms Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                              Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced              PE 0603561N / Advanced Submarine System Development Component Development & Prototypes (ACD&P) to integrate the Submarine Tethered Expendable Buoy (STEB). This integration will provide a communications path to and from the buoy bringing buoy sensor data into the submarine combat system to improve situational awareness and tactical control while maintaining a covert posture. STEB transitions from advanced development into production design and testing in FY 2026. A new sensor development effort for the Advanced Sensor Capability (ASC) mast will kick off in FY 2026 to support integration, test, evaluation, and transition for a classified development program. Project 0770 also includes performance and reliability improvements to submarine EW Direction Finding (DF) arrays and improved data collection efforts for complex emitters in support of advanced EW sensor and processing improvements. PROJECT 1704: The objective of the Undersea Warfare (USW) project is to pursue the development of technologies with the goal of improving ASW effectiveness to the point of rendering the enemy submarine irrelevant against U.S. and coalition forces. U.S. adversaries continue to develop asymmetric capabilities and capacities to deter, disrupt, or delay the entry of U.S. and allied naval forces, and pose a constant challenge as we implement the Maritime Strategy. These trends increase the threats to U.S. surface combatants, thus requiring a focused effort to identify the most promising ASW technologies through a process of discovery, assessment, experimentation, and analysis. Studies, experiments, and/or technology developments under this PE will seek to improve the ability of surface combatants to detect, classify, localize, and track submerged contacts and detect and defend against modern torpedoes. To achieve these objectives, it is essential to develop new ASW technologies. The products from these efforts will be provided to the Advanced Capability Build (ACB) program supporting the continuing improvement of the AN/ SQQ-89A(V)15 Surface Ship ASW Combat System. PROJECT 1739 - The Submarine Arctic Warfare Development Project is aligned to Commander, Undersea Warfighting Development Center (UWDC), Detachment Arctic Submarine Laboratory (ASL). This Project provides the U.S. Navy Submarine Force (SUBFOR) a cadre of trained Arctic Operation Specialists (AOS) and an inventory of unique Arctic sensors that are installed to optimize submarine safety during under-ice operations. AOS personnel assigned from ASL embark on submarines that deploy to the Arctic, cold water and iceberg regions, and marginal ice zones (MIZ) in northern latitudes of the Atlantic and Pacific Oceans and are advisers to the Commanding Officer. ASL is a shore facility at Naval Base Point Loma with the infrastructure capable of supporting personnel and equipment to conduct the submarine Arctic Warfare Development mission. Improvements and life-cycle expenditures to the facility and warehousing are made as necessary to support the mission. Project 1739, via ASL, responds to the increased threat of naval activity in the Arctic regions while continuously supporting the Navy's strategic objective of Assured Access and Combat Credibility. ASL provides a unique capability that enables the SUBFOR to satisfy the requirements laid out in the Arctic Maritime Homeland Defense Initial Capabilities Document (ICD). ASL and SUBFOR demonstrate existing Arctic Warfare capabilities and operational and tactical proficiency while developing advanced submarine technology in unique cold-water environments, in under-ice conditions, and in ice-covered shallow water regions through the Ice Exercise (ICEX) program that includes Operation Ice Camp. ICEX places an emphasis on submarine operability and mission capability in the world's harshest maritime environment. Efforts include assessment of combat system effectiveness, weapons testing, use of High Frequency (HF) sonars in Arctic regions, testing of ice-capable submarine structures, and development of class-specific Arctic operational guidelines. Tactical Development (TACDEV) is conducted biennially and requires up front comprehensive planning and work-up training, as well as post-exercise analysis and reporting. ICEX provides the framework for various submarine test and evaluation efforts in Arctic regions and at periodic Ice Camps. The ICEX program represents DoD's only drifting ice station capability through Operation Ice Camp. Emphasis during Operation Ice Camp is placed on the areas of sonar operability, tactical surveillance, weapon utility, and other submarine support missions. A Torpedo Exercise (TORPEX) occurs every four (4) years in order to meet minimum Fleet requirements of exercise torpedo (EXTORP) firings in the Arctic. A TORPEX requires a significantly higher level of logistics, personnel, and infrastructure to account for the recovery and transportation efforts of the EXTORPs. The ICEX Program also Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                 Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced            PE 0603561N / Advanced Submarine System Development Component Development & Prototypes (ACD&P) includes Arctic Exercise (ARCEX), a biennial exercise that rotates with the biennial Operation Ice Camp drifting ice camps, that includes Arctic operations to support ice camp equipment evaluation, systems development, extreme cold weather training and drifting sea ice and scientific research. PROJECT 1916: The objective of the Surface ASW System Improvement project is to significantly improve existing AN/SQQ-89A(V)15 Surface Ship ASW sonar system capabilities through quick and affordable development and integration of emergent, transformational technologies in support of Surface Ship and Theater ASW (TASW) as required to pace the threat. Detection and classification play uniquely vital roles in the success of any ASW campaign. The ACB spiral development process is the primary means by which these improvements are developed. This project takes advantage of the AN/SQQ-89A(V)15 Open System Architecture (OSA) and Acoustic Rapid Commercial-Off-The-Shelf (COTS) Insertion (ARCI) initiatives to integrate Torpedo Detection, Classification, and Localization (TDCL) and ASW sonar combat system capability improvements. The AN/SQQ-89A(V)15 COTS-based Surface Ship ASW Combat System is planned as a backfit program for all DDG51 class ships. The Open Architecture (OA) system enables the ACB process and provides budget flexibility to make COTS/OA technology solutions and ARCI-type initiatives affordable. Improvements are tested in the laboratory and at-sea. USW technology implementation will take advantage of improvements developed under the submarine APB and Advanced Surveillance Build (ASB) programs and will in turn share unique improvements developed under this program with the submarine and surveillance USW communities. The ACB and APB programs are managed under a common development organization and process titled 'AxB'. While each platform retains its uniqueness and focus in functional domains essential to mission success, a premium is placed on development of common capabilities and modular architecture technologies to maximize commonality and cost effectiveness. Project 1916 includes funding for the AN/SQQ-89A(V)15 Surface Ship ASW Test & Evaluation (T&E) program, which conducts testing and analysis to support certification of AN/SQQ-89A(V)15 Surface Ship ASW Combat System ACBs prior to fielding. Additionally, finalization of T&E Master Plans (TEMPs) and AN/SQQ-89(V) Developmental Test (DT) and Operational Test (OT) events are conducted under this program. This project includes funding for the AN/SQQ-89A(V)15 Surface Ship Engineering Measurement Program (SSEMP), which measures the performance of existing and new AN/SQQ-89A(V)15 Surface Ship ASW Combat System Technical Insertion (TI)/ACB baselines and enables data-based assessment of the capabilities and shortfalls in the performance of these systems in realistic scenarios. (Note about TI nomenclature: After TI-20, there will be a nomenclature shift for hardware baselines. Hypervisor Technology 0 (HT0) will replace what would have been TI-22. HT0 enables the deployment of virtualization technologies that create a logical separation between hardware and software, which can simplify future upgrades and accelerate software certification.) Finally, this project supports cyber security initiatives to align future AN/SQQ-89A(V)15 Surface Ship ASW Combat System baselines with future AEGIS Integrated Combat Systems. PROJECT 2033: Advanced Submarine Systems Development (ASSD) is a non-acquisition program that develops, matures and tests advanced technologies for successful integration into current and future submarine classes, to lower the technical/cost risks of integrating new technologies prior to acquisition and speed the delivery of capability and lethality to the Fleet. ASSD transitions Hull, Mechanical, and Electrical (HM&E) technologies, and future naval concepts from the Science & Technology (S&T) and Research and Development (R&D) communities through the development, maturation, and integration of technology projects to operational submarine platforms for assessment, testing, and evaluation. Once projects have proven their maturity and promise through at-sea demonstration, they are formally transitioned into acquisition Programs Of Record (PORs). Additionally, ASSD operates and maintains strategic R&D infrastructure and measurement assets that are critical to the long-term design, assessment and construction of modern, stealthy submarine platforms. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                               Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced          PE 0603561N / Advanced Submarine System Development Component Development & Prototypes (ACD&P) Project 2033 is comprised of three programmatic budget categories: Strategic Capability R&D Infrastructure, Long Range R&D Investment, and Rapid Technology Development. Strategic infrastructure investments maintain and operate critical, one-of-a-kind undersea warfare R&D assets that enable the design and manufacture of the stealthiest submarines in the world, without the requirement to develop and test at full scale, which is inordinately expensive and risky. Long-range R&D investment is the maturation and prototyping at full scale of long-range (5-10 years) technologies, to enable their readiness for incorporation into existing and future submarines. The objective is to achieve high technology readiness levels (TRL-7) of the targeted technology so that it can be incorporated into the baseline submarine design during the detailed design and construction contract award and evaluated for back-fit into existing platforms. This is class agnostic technology development that supports the VIRGINIA program, COLUMBIA program, and future submarine technology. Rapid Technology Development projects are efforts designed to rapidly mature higher TRL capabilities and field the particular technology project capability within an 18-30 month window, from program start to submarine at-sea demonstration. Also included in this category are innovative technology transition projects, seedling efforts (<$800K/year) which assess new technology candidates and keep the submarine and Undersea Warfare (USW) technology pipeline primed. The Program works with Small Business Innovation Research (SBIR), Office of Secretary of Defense (OSD), Office of Naval Research (ONR), and Defense Advanced Research Projects Agency (DARPA) organizations to identify and mature technology candidates for integration into current/future submarine classes to provide new/ transformational capabilities, while achieving total-ownership cost reductions. Experimentation and demonstration enable early assessment of a new technology's warfighting capabilities which inform the Fleet and acquisition community on smarter technology-selection decisions. This Program also supports cooperative R&D through Information/Data Exchange Agreements (IEA/ DEA) and joint Project Arrangements (PA) with international Allies. Major technology developmental efforts within this budget submission include: Strategic Capability R&D Infrastructure - Large Scale Vehicle (LSV) - Intermediate Scale Measurement System (ISMS) - High Gain Measurement System (HGMS) - South TOTO Acoustic Measurement Facility (STAFAC) Recapitalization - Acoustic Research Detachment (ARD) Ranges Recapitalization Long Range R&D - Advanced Hull Treatments - Advanced Material Propeller - Advanced SSN Technologies - Advanced Signature Management Rapid Technology Development - Innovative Technology Transfer Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                            Date: April 2026 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced               PE 0603561N / Advanced Submarine System Development Component Development & Prototypes (ACD&P) PROJECT 3094: Undersea Warfare Decision Support System (USW-DSS) is the Navy Program of Record Net-Centric ASW and Theater USW (TUSW) Command and Control (C2) system supporting the Sea Combat Commander (SCC) and Theater USW Commander (TUSWC). USW-DSS provides an integrated near-real time ASW Common Tactical Picture (CTP) and Common Operational Picture (COP) in support of theater, group, and independent destroyer squadron (DESRON) operations. USW-DSS enables effective planning and execution of USW operations, optimizes placement of sensors for exploitation of the environment, manages available resources, balances operations versus risk, and provides a clear vulnerability assessment of the operational environment. USW-DSS shortens C2 decision processes for detection-to-engagement across multiple platforms (DDGs, CVNs) as well as shore nodes. Tactical data such as friendly, neutral, and enemy tracks, bathymetry, meteorology and oceanographic data, and sensor performance characteristics are combined to inform USW decisions. USW-DSS pulls data from platform specific interfaces such as the AN/SQQ-89A(V)15 Surface Ship ASW Combat System, the Global Command and Control System-Maritime (GCCS-M), Aircraft Carrier Tactical Support Center (CV-TSC) and Link 16. USW-DSS processes this data with a series of Tactical Decision Aids (TDA), probability-based assessment tools, data fusion, and data quality analytics to support the intelligent dissemination of offensive and defensive USW missions. PROJECT 3439: The Networked Architecture for Undersea Theater Integrated C2 Advantage (NAUTICA) Project provides TASW architecture development, systems engineering, and design, and continues the system engineering effort required to design, develop, and deliver an integrated TASW battle management suite in accordance with the 2007 ASW Initial Capabilities Document (ICD). The plan prioritizes NAUTICA investments in accordance with the Commander U.S. Fleet Forces endorsement of "Theater ASW Capability Requirements" letter (dated 24 February 2017) and Center for Security Forces (CSF) letter "Criticality of Sustaining Prevention of Mutual Interference (PMI) and Waterspace Management (WSM) Capability and Meeting Emerging Requirements for Great Competition" submitted to OPNAV N2N6. The design of the integrated TASW battle management suite will include a system-of-systems TASW architecture to enable the existing Programs of Record under development from the PEO IWS, PEO Command, Controls, Communications, Computers and Intelligence (C4I), PEO AIR, PEO SUB, and N9SP to exploit a common framework. The common architecture will define the key data exchanges, common displays and processing, data models, cross domain interfaces, and multi-level security software to fuse TUSW C2 data within USW-DSS and an ever-increasing number of C4I tactical data sources into a CTP. This development will include tactical dissemination of USW tactical picture and targeting data to the submarine, allied system-to-system interoperability, Unmanned Undersea Vehicle (UUV), and Subsurface and Seabed Warfare (SSW) situational awareness. NAUTICA will focus on closing seams issues across the multi-program system-of-systems that provides C2 tools for TUSW and will support the curation of tactical picture, targeting, and cueing data to allow for transmission to ships and submarines in emission control (EMCON) status to support USW and Anti-Surface Warfare (ASuW). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                          Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced       PE 0603561N / Advanced Submarine System Development Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603562N$$, $$Submarine Tactical Warfare Sys$$, $$rdte_navy_ba4$$, $$navsea$$, 2026, 0, 14859000, 14924000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 28, "original_pe": "0603562N", "page_header": "Department of the Navy"}$$::jsonb, $$Effective FY 2026, Projects 0770 and 1739 move from PE 0603562N to PE 0603561N as part of the PE/BLI consolidation effort in the DoD Implementation Plan from the Commission on Planning, Programming, Budgeting, and Execution (PPBE) Reform Final Report in an effort to rapidly increase Navy Lethality in the Submarine and Surface Fleet. This Program Element (PE) addresses advanced submarine technology areas in support of the Navy's strategic objective of Assured Access and Combat Credibility. All projects funded in this PE are non-Acquisition Category (ACAT) programs. PROJECT 0770 - The Advanced Submarine Support Equipment Program (ASSEP) objective is to improve submarine operational effectiveness through the implementation of advanced Research and Development (R&D) efforts focused on advanced Imaging and Electronic Warfare (EW) support. A continuing need exists to improve these capabilities in view of the advancements in imaging counter-detection, the need to support specialized missions, and the increasingly dense and sophisticated electronic environment caused by the proliferation of complex radar, communications, and navigation equipment of our adversaries. Ongoing developments include improved antennas, tethered buoy, 360-degree imaging systems, and electro-optic infra-red (EO/IR) vulnerability signature reduction technologies. This project also supports the development of changes internal to submarine platforms to integrate the Submarine Tethered Expendable Buoy (STEB). This integration will provide a communications path to and from the buoy bringing buoy sensor data into the submarine combat system to improve situational awareness and tactical control while maintaining a covert posture. PROJECT 1739 - The Submarine Arctic Warfare Development Project is aligned to Commander, Undersea Warfighting Development Center (UWDC), Detachment Arctic Submarine Laboratory (ASL). This Project provides the U.S. Navy Submarine Force (SUBFOR) a cadre of trained Arctic Operation Specialists (AOS) and an inventory of unique Arctic sensors that are installed to optimize submarine safety during under-ice operations. AOS personnel assigned from ASL embark on submarines that deploy to the Arctic, cold water and iceberg regions, and marginal ice zones (MIZ) in northern latitudes of the Atlantic and Pacific Oceans and are advisers to the Commanding Officer. ASL is a shore facility at Naval Base Point Loma with the infrastructure capable of supporting personnel and equipment to conduct the submarine Arctic Warfare Development mission. Improvements and life-cycle expenditures to the facility and warehousing are made as necessary to support the mission. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                 Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced            PE 0603562N / Submarine Tactical Warfare Sys Component Development & Prototypes (ACD&P) The Submarine Arctic Warfare Development Project, via ASL, responds to the increased threat of naval activity in the Arctic regions while continuously supporting the Navy's strategic objective of Assured Access and Combat Credibility. ASL provides a unique capability that enables the SUBFOR to satisfy the requirements laid out in the Arctic Maritime Homeland Defense Initial Capabilities Document (ICD). ASL and SUBFOR demonstrate existing Arctic Warfare capabilities and operational and tactical proficiency while developing advanced submarine technology in unique cold-water environments, in under-ice conditions, and in ice-covered shallow water regions through the Ice Exercise (ICEX) program that includes Operation Ice Camp. ICEX places an emphasis on submarine operability and mission capability in the world's harshest maritime environment. Efforts include assessment of combat system effectiveness, weapons testing, use of High Frequency (HF) sonars in Arctic regions, testing of ice-capable submarine structures, and development of class-specific Arctic operational guidelines. Tactical Development (TACDEV) is conducted biennially and requires up front comprehensive planning and work-up training, as well as post exercise analysis and reporting. ICEX provides the framework for various submarine test and evaluation efforts in Arctic regions and at periodic Ice Camps. The ICEX program represents DoD's only drifting ice station capability through Operation Ice Camp. Emphasis during Operation Ice Camp is placed on the areas of sonar operability, tactical surveillance, weapon utility, and other submarine support missions. A Torpedo Exercise (TORPEX) occurs every four (4) years in order to meet minimum Fleet requirements of exercise torpedo (EXTORP) firings in the Arctic. A TORPEX requires a significantly higher level of logistics, personnel, and infrastructure to account for the recovery and transportation efforts of the EXTORPs. The ICEX Program also includes Arctic Exercise (ARCEX), a biennial exercise that rotates with the biennial Operation Ice Camp drifting ice camps, that includes Arctic operations to support ice camp equipment evaluation, systems development, extreme cold weather training, drifting sea ice and scientific research.$$, NULL, 0, 0, 0, NULL, NULL, 44, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 14695000, 0, 0, 0, NULL, 0, 0, $$This Program Element (PE) addresses advanced submarine technology areas in support of the Navy's strategic objective of Assured Access and Combat Credibility. All projects funded in this PE are non-Acquisition Category (ACAT) programs. PROJECT 0770 - The Advanced Submarine Support Equipment Program objective is to improve submarine operational effectiveness through the implementation of advanced Research and Development (R&D) efforts focused on advanced Imaging and Electronic Warfare (EW) support. A continuing need exists to improve these capabilities in view of the advancements in imaging counter-detection, the need to support specialized missions, and the increasingly dense and sophisticated electronic environment caused by the proliferation of complex radar, communications, and navigation equipment of our adversaries. Ongoing developments include improved antennas, tethered buoy, 360-degree imaging systems, and electro-optic infra-red (EO/IR) vulnerability signature reduction technologies. This project also supports the development of changes internal to submarine platforms to integrate the Submarine Tethered Expendable Buoy (STEB). This integration will provide a communications path to and from the buoy bringing buoy sensor data into the submarine combat system to improve situational awareness and tactical control while maintaining a covert posture. PROJECT 1739 - The Submarine Arctic Warfare Development Project is aligned to Commander, Undersea Warfighting Development Center (UWDC), Detachment Arctic Submarine Laboratory (ASL). This Project provides the U.S. Navy Submarine Force (SUBFOR) a cadre of trained Arctic Operation Specialists (AOS) and an inventory of unique Arctic sensors that are installed to optimize submarine safety during under-ice operations. AOS personnel assigned from ASL embark on submarines that deploy to the Arctic, cold water and iceberg regions, and marginal ice zones (MIZ) in northern latitudes of the Atlantic and Pacific Oceans and are advisers to the Commanding Officer. ASL is a shore facility at Naval Base Point Loma with the infrastructure capable of supporting personnel and equipment to conduct the submarine Arctic Warfare Development mission. Improvements and life-cycle expenditures to the facility and warehousing are made as necessary to support the mission. The Submarine Arctic Warfare Development Project, via ASL, responds to the increased threat of naval activity in the Arctic regions while continuously supporting the Navy's strategic objective of Assured Access and Combat Credibility. ASL provides a unique capability that enables the SUBFOR to satisfy the requirements laid out in the Arctic Maritime Homeland Defense Initial Capabilities Document (ICD). ASL and SUBFOR demonstrate existing Arctic Warfare capabilities and operational and Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                 Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced            PE 0603562N / Submarine Tactical Warfare Sys Component Development & Prototypes (ACD&P) tactical proficiency while developing advanced submarine technology in unique cold-water environments, in under-ice conditions, and in ice-covered shallow water regions through the Ice Exercise (ICEX) program that includes Operation Ice Camp. ICEX places an emphasis on submarine operability and mission capability in the world's harshest maritime environment. Efforts include assessment of combat system effectiveness, weapons testing, use of High Frequency (HF) sonars in Arctic regions, testing of ice-capable submarine structures, and development of class-specific Arctic operational guidelines. Tactical Development (TACDEV) is conducted biennially and requires up front comprehensive planning and work-up training, as well as post exercise analysis and reporting. ICEX provides the framework for various submarine test and evaluation efforts in Arctic regions and at periodic Ice Camps. The ICEX program represents DoD's only drifting ice station capability through Operation Ice Camp. Emphasis during Operation Ice Camp is placed on the areas of sonar operability, tactical surveillance, weapon utility, and other submarine support missions. A Torpedo Exercise (TORPEX) occurs every four (4) years in order to meet minimum Fleet requirements of exercise torpedo (EXTORP) firings in the Arctic. A TORPEX requires a significantly higher level of logistics, personnel, and infrastructure to account for the recovery and transportation efforts of the EXTORPs. The ICEX Program also includes Arctic Exercise (ARCEX), a biennial exercise that rotates with the biennial Operation Ice Camp drifting ice camps, that includes Arctic operations to support ice camp equipment evaluation, systems development, extreme cold weather training, drifting sea ice and scientific research.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603563N$$, $$Ship Concept Advanced Design$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 80418000, 207361000, 105811000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 28, "original_pe": "0603563N", "page_header": "Department of the Navy"}$$::jsonb, $$Project 2196 - This project provides the analytical foundation for making informed force structure, capability, and affordability decisions in the development of all future surface ship platforms, weapons, sensors and combat systems. It realizes this through total ship system engineering, technology integration, cost estimation, mission effectiveness analysis, force architecture synthesis, and force-level effectiveness analysis, as well as continuous development of the people, tools and processes required to accomplish these efforts efficiently. This includes early-stage concept development studies for all potential future surface ships. It also includes quantitative mission and force-level analysis to identify future capability gaps and requirements related to advances in threat capabilities, and evaluation of the effectiveness and affordability of potential future technology and concept of operations (CONOP) solutions. Results from this project are used to inform senior Navy leadership in support of budgetary decisions, Capability Evolution Plans (CEP), and requirements related to surface ship force structure, platforms and major combat system elements. Project 3161 - This project provides a coordinated approach to the development of cross platform ship and weapon system designs and technologies common to multiple ships and systems. This project directly influences technical standards for design, construction, certification and operation and provides an avenue for innovative solutions and technologies to compete with legacy product requirements and specifications. This project conducts risk reduction of alternative technical architectures, designs and technology solutions that meet Fleet operational and technical requirements at lower cost; and develops engineering capabilities in the areas of design tools, criteria and methods. This project funds a prioritized portfolio of time-sensitive initiatives through the Cross Platform Systems Development (CPSD) Program, supporting NAVSEA Technical Authority and associated risk reduction activity. The areas of exploration for the CPSD Program include Ship Technology Improvements, Fleet Maintenance and Life Cycle Cost Reduction, Advanced Manufacturing and Material Technology, Additive Manufacturing (AM), Digital Framework/Electromagnetic Environment, Development and Unmanned Systems and Condition Based Maintenance Plus (CBM+). The research products developed by this project directly support and influence both current Fleet requirements and future acquisition programs by providing a range of technically acceptable alternatives and evaluation of emerging Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                   Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced              PE 0603563N / Ship Concept Advanced Design Component Development & Prototypes (ACD&P) technologies. The prototypes, standards/specs, tools and processes and other products developed in this project focus on technical requirements and technologies applicable to multiple ship classes or systems. Products from this project transition directly to early-stage ship design for Ship Preliminary Design and Feasibility Studies, Program Executive Office (PEO) ship acquisition programs, and Systems Engineering Technical Authority (SETA) requirements documentation. Tasks within this project include efforts focused on increasing sustainment technologies and improving performance at reduced cost for current and future naval platforms. This Project supports the Navy National Shipbuilding Research Program (NSRP). Starting in FY 2026, the AM program moves to a new Program Element (PE) 0604286N, Navy Advanced Manufacturing, and the Learning to Action Board (L2AB) moves to PE 0604516N, Ship Survivability. Project 3505 - The MPF(X) ships will recapitalize the aging BOBO Class maritime prepositioning ships. The 'Sealift the Nation Needs' report to Congress defines a three- phase Sealift Recapitalization approach: Service Life Extensions, Acquiring Used ships, and new construction. The MPF(X) portion represents the prepositioning new construction aspect of the three-phase sealift recapitalization approach. USNS BOBO class ships will retire from service beginning in FY 2033. Project 3244 - This effort funds the research, design, development, testing, and installation of Cybersecurity solutions for all installed integrated computer networks to include shipboard Hull Mechanical and Electrical (HM&E), Navigation Systems, Combat Systems, Fire Control, Sonar, Radar, Communications and all other shipboard computerized control systems for all afloat U.S. Navy platforms. Cybersecurity Engineering supports the development of specifications and standards for the Cybersecurity of all Navy Control Systems (NCS). Project 3376 - Strategic Sealift Research and Development - Develops new concepts and technologies which can be applied to or will enable future strategic sealift, and Seabasing systems. The technologies include ship configuration concepts, equipment to increase cargo handling and cargo loading/unloading rates (including commercial and merchant ship systems), improved man/machine interfaces, improved structural configurations and materials, and Logistics-Over-the-Shore (LOTS) equipment and system improvements. FY 2016 and prior year (FY 2014 and earlier) efforts were financed under the National Defense Sealift Fund (NDSF) BA 04 Project 3116 Strategic Sealift Research and Development. FY 2015, FY 2017, and FY 2019 and future efforts are financed under this program element and project, 3376. Project 4044 - Medium Landing Ship (LSM) is a medium-sized landing ship that enables distributed maneuver and logistics such as Distributed Maritime Operations (DMO), Littoral Operations in a Contested Environment (LOCE), and Expeditionary Advanced Base Operations (EABO) in support of the newly established Marine Littoral Regiment (MLR). It is designed to fill the gap in capability between the Navy's large, multipurpose amphibious warfare class ships and smaller landing vessels. This ship will deploy tailored logistics, select power projection and support strike capabilities via the embarked MLR. Project 4045 - The Next Generation Logistics Ship (NGLS), also known as T-AOL, is planned to be a new class of ships to augment the traditional Combat Logistics Force (CLF) to enable refueling, rearming, and resupply of Naval assets - afloat and ashore - near contested environments via ship-to-ship operations and ship-to port operations in support of Distributed Maritime Operations (DMO), Littoral Operations Contested Environment (LOCE), and Expeditionary Advanced Base Operations (EABO). Augmenting the traditional CLF, NGLS will provide a flexible, responsive platform to move fuel, personnel, equipment, and supplies between ships, advanced bases, ports, and dispersed nodes of the sea base; sustaining afloat (Surface Action Group) and ashore (Expeditionary Advanced Base) requirements. RDT&E funding will continue to support development of the NGLS ship design(s), specification development, affordability analyses, and definition of ship mission systems. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                             Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced           PE 0603563N / Ship Concept Advanced Design Component Development & Prototypes (ACD&P) Project 5010 - This project supports Submarine Tender Recapitalization Acquisition Documentation development, Preliminary Design, Detail Design, Program Management/Engineering Services and Total Ship Integration. The Submarine Tender approach leverages current Submarine Tender capabilities, Nuclear Support Facility, integrating new VACL and CLB capabilities into the requirements generation and shipbuilding contracts. Identified missions include submarine tending, re- arming, re-supply of material, medical/dental, nuclear support, submarine systems repair, and other maintenance support. Funding informs requirements definition, early industry engagement preliminary designs, trade studies, and follow-on assessment for Submarine Tender. Project 9999 (Congressional Add)- Funding provided in the Department of Defense Appropriations Act 2024 for wave energy converters and marine energy systems for sensors and microgrids for digital cybersecurity engineering, Navy Expeditionary Sustainment and Repair (NESAR), Forward Advanced Manufacturing for Expeditionary Deployment (FAMED), Maintenance Technologies Supporting Operational Readiness (MTOR).$$, NULL, 66398000, 67694000, 56884000, NULL, NULL, 45, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 95525000, 4823000, 353893000, 353893000, NULL, 353893000, 56173000, $$Project 2196 - This project provides the analytical foundation for making informed force structure, capability, and affordability decisions in the development of all future surface ship platforms, weapons, sensors and combat systems. It realizes this through total ship system engineering, technology integration, cost estimation, mission effectiveness analysis, force architecture synthesis, and force-level effectiveness analysis, as well as continuous development of the people, tools and processes required to accomplish these efforts efficiently. This includes early-stage concept development studies for all potential future surface ships. It also includes quantitative mission and force-level analysis to identify future capability gaps and requirements related to advances in threat capabilities, and evaluation of the effectiveness and affordability of potential future technology and concept of operations (CONOP) solutions. Results from this project are used to inform senior Navy leadership in support of budgetary decisions, Capability Evolution Plans (CEP), and requirements related to surface ship force structure, platforms and major combat system elements. Project 3161 - This project provides a coordinated approach to the development of cross platform ship and weapon system designs and technologies common to multiple ships and systems. This project directly influences technical standards for design, construction, certification and operation and provides an avenue for innovative solutions and technologies to compete with legacy product requirements and specifications. This project conducts risk reduction of alternative technical architectures, designs and technology solutions that meet Fleet operational and technical requirements at lower cost; and develops engineering capabilities in the areas of design tools, criteria and methods. This project funds a prioritized portfolio of time-sensitive initiatives through the Cross Platform Systems Development (CPSD) Program, supporting NAVSEA Technical Authority and associated risk reduction activity. The areas of exploration for the CPSD Program include Ship Technology Improvements, Fleet Maintenance and Life Cycle Cost Reduction, Advanced Manufacturing and Material Technology, Additive Manufacturing (AM), Digital Framework/Electromagnetic Environment, Development and Unmanned Systems and Condition Based Maintenance Plus (CBM+). The research products developed by this project directly support and influence both current Fleet requirements and future acquisition programs by providing a range of technically acceptable alternatives and evaluation of emerging technologies. The prototypes, standards/specs, tools and processes and other products developed in this project focus on technical requirements and technologies Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                   Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced              PE 0603563N / Ship Concept Advanced Design Component Development & Prototypes (ACD&P) applicable to multiple ship classes or systems. Products from this project transition directly to early-stage ship design for Ship Preliminary Design and Feasibility Studies, Program Executive Office (PEO) ship acquisition programs, and Systems Engineering Technical Authority (SETA) requirements documentation. Tasks within this project include efforts focused on increasing sustainment technologies and improving performance at reduced cost for current and future naval platforms. This Project supports the Navy National Shipbuilding Research Program (NSRP). Starting in FY 2026, the AM program moves to a new Program Element (PE) 0604286N, Navy Advanced Manufacturing, and the Learning to Action Board (L2AB) moves to PE 0604516N, Ship Survivability. Project 3505 - The MPF(X) ships will recapitalize the aging BOBO Class maritime prepositioning ships. The 'Sealift the Nation Needs' report to Congress defines a three- phase Sealift Recapitalization approach: Service Life Extensions, Acquiring Used ships, and new construction. The MPF(X) portion represents the prepositioning new construction aspect of the three-phase sealift recapitalization approach. USNS BOBO class ships will retire from service beginning in FY 2033. Project 3244 - This effort funds the research, design, development, testing, and installation of Cybersecurity solutions for all installed integrated computer networks to include shipboard Hull Mechanical and Electrical (HM&E), Navigation Systems, Combat Systems, Fire Control, Sonar, Radar, Communications and all other shipboard computerized control systems for all afloat U.S. Navy platforms. Cybersecurity Engineering supports the development of specifications and standards for the Cybersecurity of all Navy Control Systems (NCS). Project 3376 - Strategic Sealift Research and Development - Develops new concepts and technologies which can be applied to or will enable future strategic sealift, and Seabasing systems. The technologies include ship configuration concepts, equipment to increase cargo handling and cargo loading/unloading rates (including commercial and merchant ship systems), improved man/machine interfaces, improved structural configurations and materials, and Logistics-Over-the-Shore (LOTS) equipment and system improvements. FY 2016 and prior year (FY 2014 and earlier) efforts were financed under the National Defense Sealift Fund (NDSF) BA 04 Project 3116 Strategic Sealift Research and Development. FY 2015, FY 2017, and FY 2019 and future efforts are financed under this program element and project, 3376. Project 4044 - Medium Landing Ship (LSM) is a medium-sized landing ship that enables distributed maneuver and logistics such as Distributed Maritime Operations (DMO), Littoral Operations in a Contested Environment (LOCE), and Expeditionary Advanced Base Operations (EABO) in support of the newly established Marine Littoral Regiment (MLR). It is designed to fill the gap in capability between the Navy's large, multipurpose amphibious warfare class ships and smaller landing vessels. This ship will deploy tailored logistics, select power projection and support strike capabilities via the embarked MLR. Project 4045 - The Next Generation Logistics Ship (NGLS), also known as T-AOL, is planned to be a new class of ships to augment the traditional Combat Logistics Force (CLF) to enable refueling, rearming, and resupply of Naval assets - afloat and ashore - near contested environments via ship-to-ship operations and ship-to port operations in support of Distributed Maritime Operations (DMO), Littoral Operations Contested Environment (LOCE), and Expeditionary Advanced Base Operations (EABO). Augmenting the traditional CLF, NGLS will provide a flexible, responsive platform to move fuel, personnel, equipment, and supplies between ships, advanced bases, ports, and dispersed nodes of the sea base; sustaining afloat (Surface Action Group) and ashore (Expeditionary Advanced Base) requirements. RDT&E funding will continue to support development of the NGLS ship design(s), specification development, affordability analyses, and definition of ship mission systems. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                             Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced           PE 0603563N / Ship Concept Advanced Design Component Development & Prototypes (ACD&P) Project 5010 - This project supports Submarine Tender Recapitalization Acquisition Documentation development, Preliminary Design, Detail Design, Program Management/Engineering Services and Total Ship Integration. The Submarine Tender approach leverages current Submarine Tender capabilities, Nuclear Support Facility, integrating new VACL and CLB capabilities into the requirements generation and shipbuilding contracts. Identified missions include submarine tending, re- arming, re-supply of material, medical/dental, nuclear support, submarine systems repair, and other maintenance support. Funding informs requirements definition, early industry engagement preliminary designs, trade studies, and follow-on assessment for Submarine Tender. Project 9999 (Congressional Add)- Funding provided in the Department of Defense Appropriations Act 2024 for wave energy converters and marine energy systems for sensors and microgrids for digital cybersecurity engineering, Navy Expeditionary Sustainment and Repair (NESAR), Forward Advanced Manufacturing for Expeditionary Deployment (FAMED), Maintenance Technologies Supporting Operational Readiness (MTOR).$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603564N$$, $$Ship Prel Design & Feasibility Studies$$, $$rdte_navy_ba4$$, $$peo_ships$$, 2026, 96022000, 161639000, 52586000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 28, "original_pe": "0603564N", "page_header": "Department of the Navy"}$$::jsonb, $$0409 - This project provides Test and Evaluation (T&E) requirements for DDG-51 Flight III ships and efforts for the Navigation, Aviation and Hull, Mechanical & Electrical (HM&E) Cyber Enclaves Design for implementation on future new construction ships. T&E will concentrate on verifying integration and interoperability of employed technologies and systems in the DDG-51 FLT III design to achieve the mission capabilities and performance requirements as defined in the DDG-51 Flight III Capability Development Document (CDD) to reach Initial Operational Capability (IOC). T&E functions will include the evaluation of Critical Technical Parameters (CTP), Measures of Effectiveness (MOE), Measures of Suitability (MOS), and Key Performance Parameters (KPP). Funding is also planned for the execution of Developmental Testing (DT), Operational Testing (OT), Live Fire Test and Evaluation (LFT&E), and Full Ship Shock Trials (FSST). The Navigation, Aviation and Hull, Mechanical & Electrical (HM&E) Cyber Enclaves Design effort will provide a new design to physically separate Hull, Mechanical, and Electrical (HM&E) communications from Navigation communications to meet multiple DoD Directives/Instructions on Cybersecurity and Navy Joint-SYSCOM Cybersecurity Standards on Enclave management. This design will be utilized to support implementation on future new construction DDG 51 class ships. 0411 - The Navy's DDG(X) program is the Navy's Future Guided Missile Destroyer ship acquisition program to follow the DDG 51 class that is essential to field capabilities required for the future fight as validated by the Future Surface Combatant Force (FSCF) ICD, FSCF AoA, and Future Naval Force Study (FNFS). DDG(X) Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                 Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced            PE 0603564N / Ship Prel Design & Feasibility Studies Component Development & Prototypes (ACD&P) will integrate non-developmental systems into a new hull design that incorporates platform flexibility and the space, weight, power and cooling (SWAP-C) to meet future combatant force capability/system requirements that are not achievable without the new hull design. The DDG(X) platform will have the flexibility to rapidly and affordably upgrade to future warfighting systems when they become available as well as have improved range and fuel efficiency for increased operational flexibility and decreased demand on the logistics force. DDG(X) will provide an Integrated Power System (IPS) with flexibility to enable fielding of high demand electronic weapons, sensor systems and computing resources. To decouple ship development risk from technology risk, accommodation of additional future capabilities will be pre-planned; these future capabilities may include missile launchers capable of larger weapons to exceed adversary capabilities, high power lasers, or other systems that can be efficiently incorporated when developed and demonstrated. 3262 - T-AGS(X), Oceanographic Survey Ship, is the planned recapitalization of the Pathfinder Class (T-AGS 60) six vessels which are approaching the end of their life starting in 2024. The T-AGS ship is a multi-mission, world-wide deployable oceanographic survey ship providing oceanographic capabilities in coastal and deep ocean areas. Data collected from charting the world's coastlines is vital in support of undersea warfare, enemy ship detection, and humanitarian assistance and disaster relief efforts. The recapitalization ensures the CNO requirement for eight T-AGS survey ships. 3389 - Naval Operational Logistics (OPLOG) Integration IPT Development - Develops enabling technologies for future and in-service afloat operational logistics and integrated supply force and combatant logistics requirements; and conducts cooperative initiatives with acquisition programs, program sponsors, engineering managers, the Navy science and technology community and Fleet customers. OPLOG develops integrated, cross-platform (i.e. applicable to more than one ship class/type) operational logistics and energy conservation technologies and capabilities as well as draft acquisition and operations policy ensuring future Naval systems leverage emerging logistic capabilities and technologies to provide operationally effective and energy efficient logistics delivery. 4044 - Medium Landing Ship (LSM) is a medium-sized landing ship that enables distributed maneuver and logistics such as Distributed Maritime Operations (DMO), Littoral Operations in a Contested Environment (LOCE), and Expeditionary Advanced Base Operations (EABO), in support of the Marine Littoral Regiment (MLR). It is designed to fill the gap in capability between the Navy's large, multipurpose amphibious warfare class ships and smaller landing vessels. This ship will deploy tailored logistics, select power projection and support strike capabilities via the embarked MLR. With the authorities granted in Section 128 of the FY 2025 National Defense Authorization Act, the LSM program will procure an existing design to construct Non-Developmental Vessels (NDV). This procurement is known as LSM Block 1. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                            Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced         PE 0603564N / Ship Prel Design & Feasibility Studies Component Development & Prototypes (ACD&P)$$, NULL, 399468000, 633342000, 576826000, NULL, NULL, 46, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 52843000, 100845000, 666640000, 666640000, NULL, 666640000, 524338000, $$0409 - This project provides Test and Evaluation (T&E) requirements for DDG-51 Flight III ships and efforts for the Navigation, Aviation and Hull, Mechanical & Electrical (HM&E) Cyber Enclaves Design for implementation on future new construction ships. T&E will concentrate on verifying integration and interoperability of employed technologies and systems in the DDG-51 FLT III design to achieve the mission capabilities and performance requirements as defined in the DDG-51 Flight III Capability Development Document (CDD) to reach Initial Operational Capability (IOC). T&E functions will include the evaluation of Critical Technical Parameters (CTP), Measures of Effectiveness (MOE), Measures of Suitability (MOS), and Key Performance Parameters Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                 Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced         PE 0603564N / Ship Prel Design & Feasibility Studies Component Development & Prototypes (ACD&P) (KPP). Funding is also planned for the execution of Developmental Testing (DT), Operational Testing (OT), Live Fire Test and Evaluation (LFT&E), and Full Ship Shock Trials (FSST). The Navigation, Aviation and Hull, Mechanical & Electrical (HM&E) Cyber Enclaves Design effort will provide a new design to physically separate Hull, Mechanical, and Electrical (HM&E) communications from Navigation communications to meet multiple DoD Directives/Instructions on Cybersecurity and Navy Joint-SYSCOM Cybersecurity Standards on Enclave management. This design will be utilized to support implementation on future new construction DDG 51 class ships. 0411 - The Navy's DDG(X) program is the Navy's Future Guided Missile Destroyer ship acquisition program to follow the DDG 51 class that is essential to field capabilities required for the future fight as validated by the Future Surface Combatant Force (FSCF) ICD, FSCF AoA, and Future Naval Force Study (FNFS). DDG(X) will integrate non-developmental systems into a new hull design that incorporates platform flexibility and the space, weight, power and cooling (SWAP-C) to meet future combatant force capability/system requirements that are not achievable without the new hull design. The DDG(X) platform will have the flexibility to rapidly and affordably upgrade to future warfighting systems when they become available as well as have improved range and fuel efficiency for increased operational flexibility and decreased demand on the logistics force. DDG(X) will provide an Integrated Power System (IPS) with flexibility to enable fielding of high demand electronic weapons, sensor systems and computing resources. To decouple ship development risk from technology risk, accommodation of additional future capabilities will be pre-planned; these future capabilities may include missile launchers capable of larger weapons to exceed adversary capabilities, high power lasers, or other systems that can be efficiently incorporated when developed and demonstrated. The DDG(X) program is transitioning to BBG(X) addressed below in PU 0413. The Battleship will be an addition to the Large Surface Combatant Fleet; the BBG(X) will not replace the Arleigh Burke class (DDG 51) destroyer. DDG 51 procurement will continue in parallel with the Battleship. 0413 - The Navy's Guided Missile Battleship BBG(X) acquisition program meets the realities of modern maritime conflict. As the centerpiece of the Golden Fleet, the Battleship reflects the Navy's priority to strengthen sea power through battlespace dominance and restore warfighting advantages including defendable C2 capability. The Battleship will be designed for survivability, sustained force presence, and decisive offensive combat power in contested environments. It integrates modern sensors, weapons, and command and control systems while emphasizing durability, endurance and lethality. The Battleship bridges significant capability gaps identified in the Future Surface Combatant Force Initial Capabilities Document (ICD) and will integrate the advanced systems required to dominate the future battlespace. BBG(X) will provide an Integrated Power System (IPS) with flexibility to enable fielding of high demand electronic weapons, sensor systems and computing resources. Filling the high-end requirement of the Golden Fleet's high-low mix of surface combat power, BBG(X) procurement and development efforts are in addition to the Arleigh Burke class (DDG 51) and are not intended as a replacement. 3262 - The Next Generation Oceanographic Survey Ship (T-AGS Next) will provide the Navy with persistent, globally deployable oceanographic survey capability required to support undersea warfare, mine warfare, seabed warfare, safe navigation, and environmental intelligence. The platform will collect, process, and disseminate high-resolution bathymetric, hydrographic, geophysical, acoustic, and oceanographic data in support of fleet operations and joint force requirements. T-AGS Next will replace aging T-AGS 60 Pathfinder Class oceanographic survey ships reaching the end of their service lives in the 2030s. The new capability will be designed to operate worldwide and will integrate manned and unmanned survey systems to increase survey speed, coverage, and persistence. The ship will function as a mothership for unmanned underwater, surface, and airborne survey vehicles and will support rapid data processing and dissemination to fleet and joint users. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                 Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced              PE 0603564N / Ship Prel Design & Feasibility Studies Component Development & Prototypes (ACD&P) 3389 - Naval Operational Logistics (OPLOG) Integration IPT Development - Develops enabling technologies for future and in-service afloat operational logistics and integrated supply force and combatant logistics requirements; and conducts cooperative initiatives with acquisition programs, program sponsors, engineering managers, the Navy science and technology community and Fleet customers. OPLOG develops integrated, cross-platform (i.e. applicable to more than one ship class/type) operational logistics and energy conservation technologies and capabilities as well as draft acquisition and operations policy ensuring future Naval systems leverage emerging logistic capabilities and technologies to provide operationally effective and energy efficient logistics delivery. The FY2026 spend plan for OPLOG IPT Development included $7,163 thousand of discretionary and $29,200 thousand of mandatory (reconciliation) for a total of $36,363 thousand. The mandatory funds supported the acceleration of innovative military logistics and energy capability. 4044 - Medium Landing Ship (LSM) is a medium-sized landing ship that enables distributed maneuver and logistics such as Distributed Maritime Operations (DMO), Littoral Operations in a Contested Environment (LOCE), and Expeditionary Advanced Base Operations (EABO), in support of the Marine Littoral Regiment (MLR). It is designed to fill the gap in capability between the Navy's large, multipurpose amphibious warfare class ships and smaller landing vessels. This ship will deploy tailored logistics, select power projection and support strike capabilities via the embarked MLR. With the authorities granted in Section 128 of the FY 2025 National Defense Authorization Act, the LSM program will procure an existing design to construct a Non-Developmental Vessel (NDV).$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603570N$$, $$Advanced Nuclear Power Systems$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 383831000, 292656000, 318002000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 28, "original_pe": "0603570N", "page_header": "Department of the Navy"}$$::jsonb, $$The details of this program element are classified CONFIDENTIAL and are submitted annually to Congress in the classified budget justification books.$$, NULL, NULL, NULL, NULL, NULL, NULL, 46, $$Budget J-Books/FY27/Remaining/FY2027_r1.pdf$$, NULL, FALSE, 318002000, 343831000, 392426000, 392426000, 0, 392426000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603573N$$, $$Advanced Surface Machinery Sys$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 101136000, 156380000, 98942000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 28, "original_pe": "0603573N", "page_header": "Department of the Navy"}$$::jsonb, $$This Program Element (PE) supports innovative research and development of advanced surface ship Hull, Mechanical, and Electrical (HM&E) components and systems, primarily power and energy systems, and the subsequent test, evaluation, and demonstration of those systems for future ships and back-fit ships, where appropriate. This PE provides resources for Ships HM&E cyber analysis. This PE also serves as the bridge for power and energy systems between Science and Technology (S&T), ship platform, and mission systems acquisition programs by identifying prospective applications for S&T research, advanced development, and performing additional product development and qualification when necessary to meet platform or mission system requirements. This PE includes risk mitigation efforts for the DDG(X) Integrated Power System (IPS) which will satisfy the FY 2020 National Defense Authorization Act (NDAA) Section 131 requirements for land-based testing of propulsion systems in a realistic environment and FY 2022 NDAA Section 221 requirement for a land-based test program for the engineering plant prior to DDG(X) construction start. The IPS hardware development and procurement and Land Based Testing integration and test efforts executed under this PE are informed by the DDG(X) Ship Design specifications developed under PE 0603564N / PU 0411.$$, NULL, 242757000, 268644000, 371755000, NULL, NULL, 48, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 80955000, 150330000, 269961000, 269961000, NULL, 269961000, 369146000, $$This Program Element (PE) supports innovative research and development of advanced surface ship Hull, Mechanical, and Electrical (HM&E) components and systems, primarily power and energy systems, and the subsequent test, evaluation, and demonstration of those systems for future ships and back-fit ships, where appropriate. This PE provides resources for Ships HM&E cyber analysis. This PE also serves as the bridge for power and energy systems between Science and Technology (S&T), ship platform, and mission systems acquisition programs by identifying prospective applications for S&T research, advanced development, and performing additional product development and qualification when necessary to meet platform or mission system requirements. This PE includes DDG(X) risk mitigation efforts being modified to meet the BBG(X) Integrated Power System (IPS) requirements. The IPS hardware development and procurement and Land Based Testing integration and test efforts executed under this PE are informed by the BBG(X) Ship Design specifications developed under PE 0603564N / PU 0413. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced        PE 0603573N / Advanced Surface Machinery Sys Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603576N$$, $$CHALK EAGLE$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 156686000, 111639000, 137372000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 28, "original_pe": "0603576N", "page_header": "Department of the Navy", "fy27_base_v158_t7": "hygiene: base=request for disc-only RDT&E rows post v7 I-23/I-24 + v9 I-2 INSERTs"}$$::jsonb, $$The details of this budget justification are classified, per Executive Order 13526, Sec 1.4 (a) and are submitted annually to Congress in the classified budget justification book.$$, NULL, NULL, NULL, NULL, NULL, NULL, 49, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, NULL, NULL, 149351000, 149351000, NULL, 149351000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603581N$$, $$Littoral Combat Ship$$, $$rdte_navy_ba4$$, $$peo_usc$$, 2026, 10203000, 20839000, 9132000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 28, "original_pe": "0603581N", "page_header": "Department of the Navy"}$$::jsonb, $$The Littoral Combat Ship (LCS) Program Element (PE) provides funds for detailed design, development, construction, issue resolution, certification, integration, and testing of the Littoral Combat Ship (LCS). LCS operates with focused-Mission Packages that deploy manned and unmanned vehicles to execute a variety of missions, including, Surface Warfare (SUW) and Mine Countermeasures (MCM). LCS also possesses inherent capabilities, regardless of the Mission package installed, including intelligence/surveillance/reconnaissance (ISR), LCS SUW will also include Maritime Interdiction/interception Operations (MIO), Anti-Terrorism/Force Protection (AT/ FP), air warfare self-defense, joint littoral mobility and logistic support for movement of personnel and supplies. This relatively small, shallow-draft, high-speed surface combatant complements the U.S. Navy's Surface Fleet by operating in environments where it is impossible or undesirable to employ larger, deeper-draft, multi-mission ships. LCS can deploy independently to overseas littoral regions or remain on station for extended periods of time either with a battle group or through a forward-basing arrangement. LCS will operate with Carrier Strike Groups, Surface Action Groups, or independently as dictated by the mission and environment. Additionally, LCS can operate cooperatively with the U.S. Coast Guard and Allies. This PE also provides funds for the design, development, engineering, implementation, and testing of the combat system modifications for Lethality and Survivability (L&S) for both LCS variants (Independence and Freedom). The L&S upgrades include the development of a common Combat Management System (CMS) and integration and testing of government furnished systems including the Gun Weapon System (GWS), Electronic Warfare (EW) system and Decoy Launching System (DLS) for both LCS Class Variant ships. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                           Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced         PE 0603581N / Littoral Combat Ship Component Development & Prototypes (ACD&P)$$, NULL, 11002000, 9249000, 9228000, NULL, NULL, 50, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 8955000, 10203000, 12576000, 12576000, NULL, 12576000, 9398000, $$The Littoral Combat Ship (LCS) Program Element (PE) provides funds for detailed design, development, construction, issue resolution, certification, integration, and testing of the Littoral Combat Ship (LCS). LCS operates with focused-Mission Packages that deploy manned and unmanned vehicles to execute a variety of missions, including, Surface Warfare (SUW) and Mine Countermeasures (MCM). LCS also possesses inherent capabilities, regardless of the Mission package installed, including intelligence/surveillance/reconnaissance (ISR), LCS SUW will also include Maritime Interdiction/interception Operations (MIO), Anti-Terrorism/Force Protection (AT/ FP), air warfare self-defense, joint littoral mobility and logistic support for movement of personnel and supplies. This relatively small, shallow-draft, high-speed surface combatant complements the U.S. Navy's Surface Fleet by operating in environments where it is impossible or undesirable to employ larger, deeper-draft, multi-mission ships. LCS can deploy independently to overseas littoral regions or remain on station for extended periods of time either with a battle group or through a forward-basing arrangement. LCS will operate with Carrier Strike Groups, Surface Action Groups, or independently as dictated by the mission and environment. Additionally, LCS can operate cooperatively with the U.S. Coast Guard and Allies. This PE also provides funds for the design, development, engineering, implementation, and testing of the combat system modifications for Lethality and Survivability (L&S) for both LCS variants (Independence and Freedom). The L&S upgrades include the development of a common Combat Management System (CMS) and integration and testing of government furnished systems including the Gun Weapon System (GWS), Electronic Warfare (EW) system and Decoy Launching System (DLS) for both LCS Class Variant ships. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                          Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced           PE 0603581N / Littoral Combat Ship Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603582N$$, $$Combat System Integration$$, $$rdte_navy_ba4$$, $$navsea$$, 2026, 19643000, 18482000, 20135000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 28, "original_pe": "0603582N", "page_header": "Department of the Navy"}$$::jsonb, $$Chief of Naval Operations (CNO) created the Navy's Strike Force Interoperability (SFI) program in 1998 in response to critical shortfalls in the introduction of integrated and interoperable System of Systems (SoS) to deploying Strike Forces. Interoperability concerns still exist today as new systems are introduced to the Fleet, interoperating with older systems, and the complexity of the SoS integration has continued to increase. The SFI program mitigates SoS integration and interoperability issues by identifying critical shortfalls before the systems are released to the Fleet. Warfighters depend on the SFI program on a daily basis to remove or reduce the interoperability risk associated with the systems they are tasked to operate. Commander, Naval Sea Systems Command (COMNAVSEA) acts as management lead for Joint System Command (SYSCOM) system certification policy and guidance and certifies platforms for interoperability within the platform and throughout the enterprise, in accordance with Commander, US Fleet Forces Command/Commander, Pacific Fleet COMUSFLTFORCOM/COMPACFLT) Ins. 4720.3C dated 18 SEP 2017 (C5ISR Modernization Policy). COMUSFLTFORCOM/COMPACFLT INST. 4720.3C also requires that COMNAVSEA act as administrative agent for Command, Control, Communications, Computers, Combat Systems, Intelligence, Surveillance, and Reconnaissance Modernization Process (C5IMP), and execution agent for Navy Command and Control, Communications, Computers, Combat Systems, Intelligence, Surveillance, and Reconnaissance Modernization Council (NCMC). This program conducts Interoperability Assessments that are required to certify Aircraft Carriers, Amphibious Assault Ships, and Surface Combatants in accordance with the Naval Warfare System Certification Policy (NWSCP) NAVSEAINST 9410.2B, NAVAIR 5230.20, AND SPAWAR 5234.1. The SFI program ensures overall Strike Force Interoperability is characterized and assessed. COMNAVSEA is assigned central United States Navy (USN) responsibility for interoperability, directing the development of policy and architecture for Strike Force Warfare Systems engineering and implementation of common warfare systems engineering processes. There are three priorities within the Strike Force Interoperability Program: (1) Support Fleet "as-is" state which includes Navigation System Certification (NAVCERT), Strike Group Interoperability (SGI) Capabilities & Limitations (CAPS&LIMS), and Interoperability Tactical Information Coordinator Technical Aids (TIC TECHAIDs). These functions provide the critical review, assessment and documentation to properly inform the warfighter of the status of the interoperability for the systems they operate. (2) Support Ship's system modernization (non-HME) including warfighting capability & other C5I upgrades including C5IMP Baseline Management. These functions ensure the warfighter is provided integrated and interoperable fielded systems to fulfill mission success. (3) Support Ship Warfare System Certification & Force Level Assessments. This includes Warfare Systems Certification, Interoperability Certification, Force Level Interoperability Analysis, & Assessments, and recommendations for improvements to the program offices for implementation at the systems' level. This critical function Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                        Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced             PE 0603582N / Combat System Integration Component Development & Prototypes (ACD&P) provides the confidence to the warfighter they are getting the best possible systems and that through the certification process the systems have been properly tested and assessed to ensure the best possible interoperability. Project 0164 Combat System Integration: This project consists of four key Pillars executed within the Strike Force Interoperability (SFI) Program: (1) Command, Control, Communications, Computer, Combat Systems, Intelligence, Surveillance and Reconnaissance (C5ISR) Modernization Process (C5IMP). The C5IMP validates the introduction of new systems and upgrades to existing systems into the fleet and ensures systems' maturity prior to shipboard installation thereby reducing risk and enhancing readiness and effectiveness of deploying ships and strike groups. (2) Warfare Systems Certification (WSCERT), which is essential to validating the maturity and operational performance of warfare systems prior to Fleet delivery and deployment. (3) The integrated Navigation System Certification (NAVCERT) program certifies the shipboard integrated navigation suite for safe navigation using the Electronic Charting and Display Information System Navy (ECDIS-N) as the primary plot. To support Strike Force Interoperability and ship's mission requirements, it ensures that the installed integration navigation suite provides accurate and timely navigation information (position, velocity, speed, heading, roll, and pitch) to all navigation data consumers (Warfare/Weapons Systems, Control Systems, and precision approach and landing systems) to enable the safe maneuver of naval forces to execute missions throughout the full spectrum of conflict. (4) Interoperability Certification and Assessment (IOP C&A) is the critical independent assessment of strike group warfare systems operational performance. Interoperability assessment examines force level engagement threads, aircraft control, air battle management, and operational displays to ensure the warfighter is being provided the most interoperable systems available. Assessments of deploying ships in strike force configurations are accomplished through the use of the Navy's Distributed Integration and Interoperability Assessment Capability (DIIAC) which supports the Deputy Assistant Secretary of the Navy (DASN) "shift to the left" policy by providing early interoperability testing in the acquisition lifecycle. Interoperability characterization results are used to develop fleet tactical tools (Strike Group Interoperability Capabilities & Limitations (SGI C&L) documentation and Tactical Information Coordinator Technical Aids (TIC TECHAIDS)) that ensure that systems' operators understand the interoperability capabilities and limitations of their combat systems, as well as all units within the networked architecture, and have the watch station tools necessary for the execution of their tactical responsibilities. The Fleet operators require these products to ensure warfighter awareness of Strike Force Interoperability. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                           Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced         PE 0603582N / Combat System Integration Component Development & Prototypes (ACD&P)$$, NULL, 19370000, 19675000, 19924000, NULL, NULL, 51, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 19933000, 19643000, 18819000, 18819000, NULL, 18819000, 20138000, $$Chief of Naval Operations (CNO) created the Navy's Strike Force Interoperability (SFI) program in 1998 in response to critical shortfalls in the introduction of integrated and interoperable System of Systems (SoS) to deploying Strike Forces. Interoperability concerns still exist today as new systems are introduced to the Fleet, interoperating with older systems, and the complexity of the SoS integration has continued to increase. The SFI program mitigates SoS integration and interoperability issues by identifying critical shortfalls before the systems are released to the Fleet. Warfighters depend on the SFI program on a daily basis to remove or reduce the interoperability risk associated with the systems they are tasked to operate. Commander, Naval Sea Systems Command (COMNAVSEA) acts as management lead for Joint System Command (SYSCOM) system certification policy and guidance and certifies platforms for interoperability within the platform and throughout the enterprise, in accordance with Commander, US Fleet Forces Command/Commander, Pacific Fleet COMUSFLTFORCOM/COMPACFLT) Ins. 4720.3C dated 18 SEP 2017 (C5ISR Modernization Policy). COMUSFLTFORCOM/COMPACFLT INST. 4720.3C also requires that COMNAVSEA act as administrative agent for Command, Control, Communications, Computers, Combat Systems, Intelligence, Surveillance, and Reconnaissance Modernization Process (C5IMP), and execution agent for Navy Command and Control, Communications, Computers, Combat Systems, Intelligence, Surveillance, and Reconnaissance Modernization Council (NCMC). This program conducts Interoperability Assessments that are required to certify Aircraft Carriers, Amphibious Assault Ships, and Surface Combatants in accordance with the Naval Warfare System Certification Policy (NWSCP) NAVSEAINST 9410.2B, NAVAIR 5230.20, AND SPAWAR 5234.1. The SFI program ensures overall Strike Force Interoperability is characterized and assessed. COMNAVSEA is assigned central United States Navy (USN) responsibility for interoperability, directing the development of policy and architecture for Strike Force Warfare Systems engineering and implementation of common warfare systems engineering processes. There are three priorities within the Strike Force Interoperability Program: (1) Support Fleet "as-is" state which includes Navigation System Certification (NAVCERT), Strike Group Interoperability (SGI) Capabilities & Limitations (CAPS&LIMS), and Interoperability Tactical Information Coordinator Technical Aids (TIC TECHAIDs). These functions provide the critical review, assessment and documentation to properly inform the warfighter of the status of the interoperability for the systems they operate. (2) Support Ship's system modernization (non-HME) including warfighting capability & other C5I upgrades including C5IMP Baseline Management. These functions ensure the warfighter is provided integrated and interoperable fielded systems to fulfill mission success. (3) Support Ship Warfare System Certification & Force Level Assessments. This includes Warfare Systems Certification, Interoperability Certification, Force Level Interoperability Analysis, & Assessments, and recommendations for improvements to the program offices for implementation at the systems' level. This critical function provides the confidence to the warfighter they are getting the best possible systems and that through the certification process the systems have been properly tested and assessed to ensure the best possible interoperability. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                        Date: April 2026 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced                PE 0603582N / Combat System Integration Component Development & Prototypes (ACD&P) Project 0164 Combat System Integration: This project consists of four key Pillars executed within the Strike Force Interoperability (SFI) Program: (1) Command, Control, Communications, Computer, Combat Systems, Intelligence, Surveillance and Reconnaissance (C5ISR) Modernization Process (C5IMP). The C5IMP validates the introduction of new systems and upgrades to existing systems into the fleet and ensures systems' maturity prior to shipboard installation thereby reducing risk and enhancing readiness and effectiveness of deploying ships and strike groups. (2) Warfare Systems Certification (WSCERT), which is essential to validating the maturity and operational performance of warfare systems prior to Fleet delivery and deployment. (3) The integrated Navigation System Certification (NAVCERT) program certifies the shipboard integrated navigation suite for safe navigation using the Electronic Charting and Display Information System Navy (ECDIS-N) as the primary plot. To support Strike Force Interoperability and ship's mission requirements, it ensures that the installed integration navigation suite provides accurate and timely navigation information (position, velocity, speed, heading, roll, and pitch) to all navigation data consumers (Warfare/Weapons Systems, Control Systems, and precision approach and landing systems) to enable the safe maneuver of naval forces to execute missions throughout the full spectrum of conflict. (4) Interoperability Certification and Assessment (IOP C&A) is the critical independent assessment of strike group warfare systems operational performance. Interoperability assessment examines force level engagement threads, aircraft control, air battle management, and operational displays to ensure the warfighter is being provided the most interoperable systems available. Assessments of deploying ships in strike force configurations are accomplished through the use of the Navy's Distributed Integration and Interoperability Assessment Capability (DIIAC) which supports the Deputy Assistant Secretary of the Navy (DASN) "shift to the left" policy by providing early interoperability testing in the acquisition lifecycle. Interoperability characterization results are used to develop fleet tactical tools (Strike Group Interoperability Capabilities & Limitations (SGI C&L) documentation and Tactical Information Coordinator Technical Aids (TIC TECHAIDS)) that ensure that systems' operators understand the interoperability capabilities and limitations of their combat systems, as well as all units within the networked architecture, and have the watch station tools necessary for the execution of their tactical responsibilities. The Fleet operators require these products to ensure warfighter awareness of Strike Force Interoperability. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                      Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced       PE 0603582N / Combat System Integration Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L050$$, $$Naval Tact Cmd Supt Sys (NTCSS)$$, $$proc_navy_1810_ba2$$, $$mc$$, 2026, 461380000, 325996000, 182011000, NULL, $${"page": 97, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "50", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 46", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 653483, "p1_line_num": 46, "fy27_total_K": 653483}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 422704, "li_num": 46, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA2_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 461380000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 13614000, 7972000, 653483000, 653483000, 0, 653483000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603595N$$, $$SSBN New Design$$, $$rdte_navy_ba4$$, $$peo_subs$$, 2026, 273265000, 274320000, 192631000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 28, "original_pe": "0603595N", "page_header": "Department of the Navy"}$$::jsonb, $$This program element supports innovative research and development in submarine Hull, Mechanical and Electrical (HM&E) and combat systems technologies and the subsequent evaluation, demonstration, and validation for submarine platforms over the life cycle of the COLUMBIA Class. It will increase the submarine technology base and provide subsystem design options not currently feasible. The program element also supports programs transitioning from Science and Technology (S&T), Defense Advanced Research Projects Agency (DARPA), Independent Research and Development, and Small Business Innovation Research (SBIR) projects. The funding applies to the design, systems engineering, prototyping, and vendor qualification activities needed to execute the schedule for Common Missile Compartment (CMC) design, whole ship design, and component technologies development for the next generation U.S. ballistic missile submarine (SSBN), the COLUMBIA Class. Project Unit 3220: The objective of the COLUMBIA Class Submarine Development is to design, prepare for, and support construction and delivery of the class that is the replacement of the OHIO Class SSBN. Project Unit 3440: This project provides the engineering development and program management required to outfit, upgrade, and support each ship of the COLUMBIA Class Submarine with a Non- Propulsion Electronics System (combat, sonar, etc.) that satisfies requirements to meet its sole mission of Strategic Deterrence over the class life cycle. Project Unit 3441: This project encompasses ship system development, coordination, and management efforts for the COLUMBIA Class Submarine Technology Insertion Program and Technology Refresh Program over the class life cycle. Project Unit 9999: This Congressional Add project funds efforts for COLUMBIA Advanced Composite Shaft Design and Shipyard and Ship Repair Workforce Training. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                            Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced         PE 0603595N / SSBN New Design Component Development & Prototypes (ACD&P)$$, NULL, 345106000, 247224000, 142321000, NULL, NULL, 52, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 188012000, 278305000, 331577000, 331577000, NULL, 331577000, 98777000, $$This program element supports innovative research and development in submarine Hull, Mechanical and Electrical (HM&E) and combat systems technologies and the subsequent evaluation, demonstration, and validation for submarine platforms over the life cycle of the COLUMBIA Class. It will increase the submarine technology base and provide subsystem design options not currently feasible. The program element also supports programs transitioning from Science and Technology (S&T), Defense Advanced Research Projects Agency (DARPA), Independent Research and Development, and Small Business Innovation Research (SBIR) projects. The funding applies to the design, systems engineering, prototyping, and vendor qualification activities needed to execute the schedule for Common Missile Compartment (CMC) design, whole ship design, and component technologies development for the next generation U.S. ballistic missile submarine (SSBN), the COLUMBIA Class. Project Unit 3220: The objective of the COLUMBIA Class Submarine Development is to design, prepare for, and support construction and delivery of the class that is the replacement of the OHIO Class SSBN. Project Unit 3440: This project provides the engineering development and program management required to outfit, upgrade, and support each ship of the COLUMBIA Class Submarine with a Non- Propulsion Electronics System (combat, sonar, etc.) that satisfies requirements to meet its sole mission of Strategic Deterrence over the class life cycle. Project Unit 3441: This project encompasses ship system development, coordination, and management efforts for the COLUMBIA Class Submarine Technology Insertion Program and Technology Refresh Program over the class life cycle. Project Unit 9999: This Congressional Add project funds efforts for Shipyard and Ship Repair Workforce Training, Submarine Supply Chain Management, and Advanced Composite Shaft Design. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                            Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced         PE 0603595N / SSBN New Design Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603596N$$, $$LCS Mission Modules$$, $$rdte_navy_ba4$$, $$peo_usc$$, 2026, 39258000, 31192000, 28801000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 28, "original_pe": "0603596N", "page_header": "Department of the Navy"}$$::jsonb, $$The Littoral Combat Ship (LCS) Mission Modules (MM) Program Element (PE) provides funds for detailed design, development, issue resolution, certification, integration, and testing of the LCS MM. LCS is a fast, agile, and networked surface combatant with capabilities optimized to defeat asymmetric threats and ensure naval and joint force access into contested littoral regions. It uses open-systems architecture design, modular weapons, sensor systems, and a variety of manned and unmanned vehicles to expand the battle space and project offensive power into the littorals. The LCS MM Program employs an incremental development approach to deliver capability, which allows for insertion of mature capabilities throughout the life of the program without the need for modifications to the seaframes. Future capabilities will be considered when joint warfighting objectives or changing threats create new operational capability requirements that cannot be met by current mission package designs, or when new technological opportunities allow significant progress toward delivering cost effective, enhanced capabilities. Future mission module increments can be tested, constructed, and incorporated into existing mission packages, which is one of the most important benefits of LCS modular design. Mission Package funding is aligned into three (3) projects: 2550 Mine Countermeasures (MCM) Mission Package 2552 Surface Warfare (SUW) Mission Package 3129 LCS Mission Package Development MCM MP: Counters bottom, tethered, near surface, and surface mines in the littorals without putting sailors in the minefield. In FY25, the MCM MP will deploy to C5F, update and deliver various tactical and logistic documentation, commence development of MCM MPAS 4.0 software, modify the MCM MP to commence integration of Barracuda, development of the Near Surface Neutralization Module (NSN), and TBEC design upgrades and achieve Ready for Training (RFT). SUW MP: Increases firepower and offensive/defensive capabilities against large numbers of highly maneuverable, fast, small craft threats, giving LCS the ability to protect the sea lanes while moving a force quickly through a choke point or other strategic waterway, and to conduct maritime security missions. In FY24, the SUW MP will complete the efforts to revise the SSMM hatch and cover design. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                           Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced         PE 0603596N / LCS Mission Modules Component Development & Prototypes (ACD&P) ASW MP: Enables the LCS to conduct detect-to-engage operations against modern submarines. In FY23, the ASW Mission Package was divested from the LCS Mission Modules program. C5I: Enabling products required by all MPs such as common hardware interfaces, computer operating environment (Mission Package Computing Environment (MPCE)), communications systems (Multi-Vehicle Communications System (MVCS)), aviation interface systems, UxV interfaces and Mission Package Portable Control Stations (MPPCS). MPCE provides common services and an Operating Environment to support all Mission Package Application Software (MPAS) and Open Architecture Products. MVCS enables the simultaneous control and data exchange between unmanned mission vehicles and the ship. Aviation interface systems include integration and management of data communications, data processing, and physical hardware interfaces such as common equipment and containers used by all mission packages. MPPCS provides a mobile operating environment installed in a 20ft ISO container and serves as a surrogate ship during mission package development and integration test events at test ranges. In FY24, project 3129 (LCS Mission Package Common Development) efforts include continuing MPCE v2.0 tech refresh development and initiation of MVCS v2.X tech refresh development.$$, NULL, 39312000, 41798000, 41327000, NULL, NULL, 53, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 28533000, 39258000, 46239000, 46239000, NULL, 46239000, 42083000, $$The Littoral Combat Ship (LCS) Mission Modules (MM) Program Element (PE) provides funds for detailed design, development, issue resolution, certification, integration, and testing of the LCS MM. LCS is a fast, agile, and networked surface combatant with capabilities optimized to defeat asymmetric threats and ensure naval and joint force access into contested littoral regions. It uses open-systems architecture design, modular weapons, sensor systems, and a variety of manned and unmanned vehicles to expand the battle space and project offensive power into the littorals. The LCS MM Program employs an incremental development approach to deliver capability, which allows for insertion of mature capabilities throughout the life of the program without the need for modifications to the seaframes. Future capabilities will be considered when joint warfighting objectives or changing threats create new operational capability requirements that cannot be met by current mission package designs, or when new technological opportunities allow significant progress toward delivering cost effective, enhanced capabilities. Future mission module increments can be tested, constructed, and incorporated into existing mission packages, which is one of the most important benefits of LCS modular design. Mission Package funding is aligned into three (3) projects: 2550 Mine Countermeasures (MCM) Mission Package 2552 Surface Warfare (SUW) Mission Package 3129 LCS Mission Package Development MCM MP: Counters bottom, tethered, near surface, and surface mines in the littorals without putting sailors in the minefield. In FY27, the MCM MP will deploy to C7F, update and deliver various tactical and logistic documentation, commence development of MCM MPAS 4.0 software including expansion of multi-mission software architecture (MMSA) capabilities, modify the MCM MP to commence integration of Barracuda, development of the Near Surface Neutralization Module (NSN), and achieve Ready For Training (RFT) SUW MP: Increases firepower and offensive/defensive capabilities against large numbers of small mannedand unmanned threats including fast attack craft, fast inshore attack craft, and aircraft, giving LCS the ability to protect the sea lanes and move a force quickly through a choke point or other strategic waterway. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                        Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced         PE 0603596N / LCS Mission Modules Component Development & Prototypes (ACD&P) C5I: Enabling products required by all MPs such as common hardware interfaces, computer operating environment (Mission Package Computing Environment (MPCE)), communications systems (Multi-Vehicle Communications System (MVCS)), aviation interface systems, UxV interfaces and Mission Package Portable Control Stations (MPPCS). MPCE provides common services and an Operating Environment to support all Mission Package Application Software (MPAS) and Open Architecture Products. The Multi-Mission Software Architecture (MMSA) will provide a framework that enables hybrid mission packages such as combining Mine Countermeasures (MCM) with the Surface-to-Surface Missile Module (SSMM) to operate concurrently without mission package swaps, improving cyber survivability and providing common control for unmanned systems. MVCS enables simultaneous control and data exchange between unmanned mission vehicles and the ship. Aviation interface systems include integration and management of data communications, data processing, and physical hardware interfaces such as common equipment and containers used by all mission packages. MPPCS provides a mobile operating environment installed in a 20ft ISO container and serves as a surrogate ship during mission package development, integration test events, and operational situations at test ranges and in theatre operations. In FY24, project 3129 (LCS Mission Package Common Development) efforts include continuing MPCE v2.0 tech refresh development and initiation of MVCS v2.X tech refresh development.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603597N$$, $$(U)AUTOMATED TEST AND RE-TEST (ATRT)$$, $$rdte_navy_ba4$$, $$navy_cno$$, 2026, 9862000, 25202000, 25805000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 28, "original_pe": "0603597N", "page_header": "Department of the Navy"}$$::jsonb, $$ATRT technologies provide essential development, assessment, and operational analysis capabilities to streamline testing and certification for both single systems and systems of systems capabilities in order to reduce development time for new capabilities from years to weeks. Also, ATRT leverages support to refactoring, development, and assessment of Artificial Intelligence / Machine Learning (AI/ML) aids with other applications to deliver warfighting capability. The integration of legacy code and systems across the Naval warfighting portfolio aims to achieve an open integration and interoperability environment. Project funding supports the development of enterprise level strategies and activities to apply ATA technologies to software-intensive acquisition programs. The objectives include support for the Chief of Naval Operations' (CNO) vision outlined in the CNO's Navigation Plan (NAVPLAN) through continued development and commercialization of ATRT Small Business Innovation Research (SBIR) technologies across the Navy enterprise. These SBIR derived technologies enable the Navy enterprise to make rapid capability improvements through software updates while maintaining a continuous Authority to Operate (ATO) on a common digital warfighting platform, and in enterprise sandbox technologies.$$, NULL, 19028000, 19918000, 20841000, NULL, NULL, 54, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 25030000, 29169000, 18070000, 18070000, NULL, 18070000, 21227000, $$ATRT technologies provide essential development, assessment, and operational analysis capabilities to streamline testing and certification for both single systems and systems of systems capabilities in order to reduce development time for new capabilities from years to weeks. Also, ATRT leverages support to refactoring, development, and assessment of Artificial Intelligence / Machine Learning (AI/ML) aids with other applications to deliver warfighting capability. The integration of legacy code and systems across the Naval warfighting portfolio aims to achieve an open integration and interoperability environment. Project funding supports the development of enterprise level strategies and activities to apply ATA technologies to software-intensive acquisition programs. The objectives include support for the Chief of Naval Operations' (CNO) vision outlined in the CNO's Navigation Plan (NAVPLAN) through continued development and commercialization of ATRT Small Business Innovation Research (SBIR) technologies across the Navy enterprise. These SBIR derived technologies enable the Navy enterprise to make rapid capability improvements through software updates while maintaining a continuous Authority to Operate (ATO) on a common digital warfighting platform, and in enterprise sandbox technologies.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603598N$$, $$(U)ATRT ENTERPRISE RAPID DEVELOPMENT$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 20000000, 86813000, 53343000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 29, "original_pe": "0603598N", "page_header": "Department of the Navy"}$$::jsonb, $$Automated Test and ReTest (ATRT) Enterprise Rapid Capability develops, integrates, and deploys novel capabilities aggregated from mature technologies in support of Distributed Maritime Operations. These capabilities are enabled through the use of virtualized systems of systems, automated test and analysis, automated certification, rapid interface development, and field with and data collection and edge analytics. These technologies are at the heart of the Navy's rapid capability approach, which combines digital engineering tools with evolutionary approaches to requirements generation, operational testing, and deployment. This process will meet Fleet demands for near-term capability in a predictable and repeatable fashion.$$, NULL, 90873000, 91543000, 118395000, NULL, NULL, 55, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 51454000, 116459000, 87585000, 87585000, NULL, 87585000, 119170000, $$Automated Test and ReTest (ATRT) Enterprise Rapid Capability develops, integrates, and deploys novel capabilities aggregated from mature technologies in support of Distributed Maritime Operations. ATRT technologies provide essential development, assessment, and operational analysis capabilities to streamline testing and certification for both single systems and systems of systems capabilities in order to reduce development time for new capabilities from years to weeks. Further, ATRT leverages support to refactoring, development, and assessment of Artificial Intelligence / Machine Learning (AI/ML) aids with other applications to deliver warfighting capability. The integration of legacy code and systems across the Naval warfighting portfolio aims to achieve an open integration and interoperability environment. These capabilities are enabled through the use of virtualized systems of systems, automated test and analysis, automated certification, rapid interface development, and field with data collection and edge analytics. These technologies are at the heart of the Navy's rapid capability approach, which combines digital engineering tools with evolutionary approaches to requirements generation, operational testing, and deployment. Project funding supports application of Automated Test and Analysis (ATA) technologies to software-intensive acquisition programs through continued development and commercialization of ATRT Small Business Innovation Research (SBIR) technologies across the Navy enterprise. These SBIR derived technologies enable the Navy enterprise to make rapid capability improvements through software updates while maintaining a continuous Authority to Operate (ATO) on a common digital warfighting platform, and in enterprise sandbox technologies. The Department of the Navy Rapid Capabilities Office (DONRCO) was established in August 2025 with the objective of accelerating development and fielding of critical capabilities to enable our warfighters with solutions to overcome emerging threats. The DONRCO expands the ATRT capability and strengthens the Navy's ability to rapidly develop and scale near-term capability solutions from existing technologies. To the furthest extent available, the DONRCO leverages commercially available solutions with high Technical Readiness Levels (TRLs) to form new/novel capabilities and kill chains to address urgent operational needs. The DONRCO capability development approach utilizes the ATRT extensive use of virtualized systems, automated test and analysis tools, automated certification practices, and edge computing analytics. Rapid Development and Deployment (RDD) funding supports the DONRCO execution of capability development, delivery, and scaling efforts in response to critical operational needs derived directly from Combatant Commanders and Fleet demand signals and executed via agile capability development practices. Capability Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                               Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced             PE 0603598N / (U)ATRT ENTERPRISE RAPID DEVELOPMENT Component Development & Prototypes (ACD&P) development and delivery execute in a user-centric design manner, in which the Fleet users are integral to the design, development, and testing of the capabilities. These processes meet Fleet demands for solutions to urgent operational gaps, providing capability delivery within a 0-3 year timeframe in support of the Navy's strategy to invest in cost-effective innovation and readiness to hedge against future conflicts while the general purpose Navy pursues exquisite capability.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603599N$$, $$FRIGATE Development$$, $$rdte_navy_ba4$$, $$peo_ships$$, 2026, 84199000, 97581000, 105482000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 29, "original_pe": "0603599N", "page_header": "Department of the Navy"}$$::jsonb, $$The Constellation Class Frigate (FFG 62) is a more lethal and survivable multi-mission small surface combatant. With FFG 62, the Navy will maximize the small surface combatant capabilities in the Anti-Surface Warfare (SUW), Anti-Submarine Warfare (ASW), Electronic Warfare/Information Operations (EW/IO), Air Warfare (AW) mission areas, and survivability while keeping the ship an affordable component of the "high-low" mix of surface ships. The FFG 62 Capability Development Document (CDD) was approved by the Joint Requirement Oversight Council (JROC) in Feb 2019 and completed Milestone B, an informed Independent Cost Estimate, and award of the Detail Design & Construction (DD&C) contract in April 2020. FY26 funds continue development of the Variable Depth Sonar (VDS) capability via the Combined Active Passive Towed Array Sonar (CAPTAS) and continue Combat System and AEGIS Weapon System (AWS) integration, Live Fire Test & Evaluation (LFT&E) and Developmental Testing (DT) support as well as Cyber security implementation and Land Based Engineering Site (LBES) construction. FY25 funds continue development of the Variable Depth Sonar (VDS) capability via the Combined Active Passive Towed Array Sonar (CAPTAS) and continue Combat System and Over-the-Horizon (OTH) development and AEGIS Weapon System (AWS) integration, Live Fire Test & Evaluation (LFT&E) and Developmental Testing (DT) support as well as Cyber security implementation and Land Based Engineering Site (LBES) construction. FY24 funds developed Variable Depth Sonar (VDS) capability via the Combined Active Passive Towed Array Sonar (CAPTAS) and continue Combat System and Over-the-Horizon (OTH) development and AEGIS Weapon System (AWS) integration, test and evaluation efforts including Live Fire Test & Evaluation (LFT&E) and Developmental Testing (DT) support as well as Cyber security implementation and LBES construction. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                           Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced        PE 0603599N / FRIGATE Development Component Development & Prototypes (ACD&P)$$, NULL, 247567000, 193661000, 197303000, NULL, NULL, 56, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 103211000, 81218000, 212041000, 212041000, NULL, 212041000, 195581000, $$The FF(X) Frigate is a strategic necessity to close a significant shortfall in the Navy's small surface combatant inventory and to build a more balanced, flexible fleet. Frigate directly supports the 2025 National Security Strategy which calls for, "A more suitable Navy presence to control sea lanes, to thwart illegal and other unwanted migration, to reduce human and drug trafficking, and to control key transit routes in a crisis". FF(X) will be a vanguard of the Navy's Hedge Strategy, within the General- Purpose Force handling routine missions across the globe and freeing the Main Battle Force to remain focused on high-end combat. FF(X) will act as the command ship for Tailored Offsets, specifically Robotic and Autonomous Systems (RAS), and integrating with RAS to lead Tailored Forces into a cohesive warfighting approach. As the low-end anchor of the Golden Fleet high-low mix, the Frigate will relieve high end assets such as Arleigh Burke-Class destroyers from missions that do not require large multi mission combatants, including maritime interdiction and counter drug operations. Its primary role is to execute surface warfare, Counter-Unmanned Aerial Systems (C-UAS), and Command and Control (C2) of Unmanned Systems missions as well as others as enabled through containerized payloads, all through a highly producible, cost effective and adaptable platform. These containerized payload capabilities are aligned with and supported by the Navy's dedicated containerized payloads program, enabling rapid integration and fielding of mission modules, including containerized Vertical Launch System (VLS) payloads. This ensures that while Flight I of the FF(X) Class (currently planned as at least the first 2 ships) does not incorporate a traditional fixed VLS battery, it retains the capability to deploy VLS- equivalent payloads through modular, mission-tailored configurations. To deliver at speed and scale, the Navy is acquiring its new class of Frigates based on Huntington Ingalls Industry's (HII) Legend-class National Security Cutter (NSC) design - a proven American built ship that has been operational for 17 years with ten delivered cutters, protecting U.S. interests at home and abroad. In addition to program maturity through the proven NSC design as the FF(X) baseline, the FF(X) program is also utilizing equipment, systems and material from the cancelled NSC 11 on hand at the shipbuilder to support execution and accelerated production of the first FF(X) in FY27. Frigate will take the same validated flight-upgrade approach as our Arleigh Burke DDG-51 program - incorporating improvements over successive flights to evolve the ship's capabilities over time. Flight I Frigates will have minimal adaptations from the existing NSC to start production as quickly as possible. The limited modifications of the NSC baseline to the Flight I Frigate requirements incorporate Navy weapons, combat systems, and communications programs of record, add a flexible weapons station in lieu of the NSC stern boat ramp, add a port-mid-ships boat davit, incorporate shipbuilder recommended producibility enhancements, and change to standard Navy grey paint. Studies for future flights will consider expanded capabilities including Vertical Launch Systems, and Anti-Submarine Warfare systems. FF(X) RAS C2 is enabled through use of Navy warfare system programs of record including the FF(X) combat system and eventually Aegis based Integrated Combat System (ICS), communications systems, and design reservations dedicated to future RAS C2 systems. Design Reservations for unmanned systems will also enable "plug-and-play" accommodation of future unmanned Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced              PE 0603599N / FRIGATE Development Component Development & Prototypes (ACD&P) systems. FF(X) addition of the flexible weapons station facilitates loadout of containerized payloads, the same payloads as Medium Unmanned Surface Vessel (MUSV) can carry, and ultimately enabling associated benefits of scalable technology, rapid and cost-effective innovation, and tailored missions through containerized missiles or other weapons systems. This approach provides an inherent growth path for VLS and other capabilities through containerized solutions in early flights, reinforcing the platform's adaptability while mitigating cost, schedule, and integration risks associated with fixed VLS installation. Combat system development activities focus on integration and verification of key sensors and weapons, including Atalanta Combat System (CS), SPS-77 radar, Mk48 Mod 2 Gun Weapon System, and Rolling Airframe Missile (RAM). Efforts include hardware and software integration, interface definition, and validation of system performance within the platform's warfare architecture. The program supports development of an integrated warfare system baseline, ensuring interoperability across combat, C4I, and aviation domains and enabling effective response to current and emerging threats. RDTE funding supports risk reduction through system-level integration, collaborative design efforts with the shipbuilder and stakeholders, land-based and ship-based test planning, and preparation for developmental and operational test events. Activities include maturation of system interfaces, validation of combat system functionality, and integration of unmanned system command and control capabilities. Studies conducted under this effort will inform future capability increments and flight upgrades, including transition from Atalanta Weapon System to ICS, incorporation of future RAS C2 elements, potential integration of Vertical Launch Systems (VLS) and Anti- Submarine Warfare (ASW) systems in follow-on flights. The program maintains a development schedule aligned to launch of the lead ship in 2028. Early investment in design completion, integration, and test planning reduces technical and schedule risk and supports a transition to production. Additionally, future RDTE funding will develop integration of unmanned assets such as Medium Unmanned Surface Vessel (MUSV) into the FF(X) kill chain. FF(X) will team with and quarterback MUSVs across all domains. These unmanned assets will function as extensions, or in addition to, FF(X)'s own sensors and weapons providing persistent capabilities in early warning, Intelligence, Surveillance, and Reconnaissance (ISR), communications, and offensive strikes. This integration enhances the common operating picture and supports integrated fire control solutions, enabling a distributed and more lethal force.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603600D8Z$$, $$WALKOFF$$, $$rdte_dw_ba4$$, $$dw$$, 2026, 152449000, 149934000, 149704000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 70, "original_pe": "0603600D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Department's initiatives to Deter Aggression, Defend the Homeland, and Build Sustainable and Long-Term Advantage. The program is Classified.$$, NULL, 214557000, 195392000, 198722000, NULL, NULL, 82, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 146245000, 151244000, 227158000, 227158000, NULL, 227158000, 202213000, $$This program supports the Department's initiatives to Deter Aggression, Defend the Homeland, and Build Sustainable and Long-Term Advantage. The program is Classified.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603601F$$, $$Conventional Weapons Technology$$, $$rdte_af_ba3$$, $$afrl_rw$$, 2026, 99263000, 122854000, 125460000, NULL, $${"ba_raw": "6.3", "source": "af_r1_fy26", "original_pe": "0603601F"}$$::jsonb, $$This program develops, integrates, and demonstrates advanced ordnance and guidance technologies for conventional weapons. The effort focuses on conventional ordnance component technologies such as warheads, fuzes, and explosives, as well as munition guidance component technologies such as navigation and control systems and seekers. Technologies to be developed, demonstrated, and integrated into system concepts will address blast, fragmentation, penetration, low collateral damage, variable depth/location fuzing, precise guidance, and high-performance and insensitive explosives. Efforts in this project have been coordinated through the Department of Defense Science and Technology Executive Committee process to harmonize efforts and eliminate duplication. Funds in this PE may be used to investigate specified technology advancements in air, space and/or cyber domains. The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This program includes funding for the requisite DAF Science & Engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The use of program funds in this program element is in conjunction with the civilian pay expenses budgeted in the following program elements: 1206601SF, 0601102F, 0602020F, 0602102F, 0602202F, 0602203F, 0602204F, 0602298F, 0602336F, 0602605F, 0602788F, and 0603680F. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology capabilities. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603601F / Conventional Weapons Technology Technology Development (ATD)$$, NULL, 139783000, 165830000, 161574000, NULL, NULL, 26, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 117877000, 98569000, 131397000, 131397000, 0, 131397000, 147613000, $$This program develops, integrates, and demonstrates advanced ordnance and guidance technologies for conventional weapons. This program focuses on integration by design and starting with desired mission effect to deliver war winning capabilities to defend the homeland, provide nuclear deterrence, and deliver force projection. The effort focuses on conventional ordnance component technologies such as warheads, fuzes, and explosives, as well as munition guidance component technologies such as navigation and control systems and seekers. Technologies to be developed, demonstrated, and integrated into system concepts will address blast, fragmentation, penetration, low collateral damage, variable depth/location fuzing, precise guidance, and high-performance and insensitive explosives. Funds in this PE may be used to investigate specified technology advancements in air, space and/or cyber domains. This program is accomplished by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. In order to manage, execute, and deliver science and technology capabilities, this program element may include: necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, etc. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                    Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603601F / Conventional Weapons Technology Technology Development (ATD)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603605F$$, $$Advanced Weapons Technology$$, $$rdte_af_ba3$$, $$afrl_rw$$, 2026, 4434000, 96178000, 25050000, NULL, $${"ba_raw": "6.3", "source": "af_r1_fy26", "original_pe": "0603605F"}$$::jsonb, $$The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This program develops and demonstrates integrated, state of the art, high energy laser (HEL) and high power electromagnetic (HPEM) directed energy (DE) weapon demonstrator systems to satisfy Department of the Air Force requirements in areas including: counter adversary unmanned aerial systems (c-UAS), counter adversary intelligence/surveillance/reconnaissance (c-ISR), counter adversary missiles (c-Missile), counter adversary electronics (c-Electronic), and other mission objectives. Efforts in this program have been coordinated through the Department of Defense Science and Technology Executive Committee process to harmonize efforts and eliminate duplication. Technologies developed under PE 0602605F (Directed Energy Technology), 624867 (Advanced Weapons & Survivability Technology) and 625173 (Laser Technology), feed directly into this program. In order to manage, execute, and deliver science and technology capabilities, this program element may include necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology capabilities. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603605F / Advanced Weapons Technology Technology Development (ATD)$$, NULL, 14589000, 19409000, 20701000, NULL, NULL, 27, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 27161000, 16783000, 13744000, 13744000, 0, 13744000, 20801000, $$This research is accomplished by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. AFRL is focused on high-impact, multi-domain S&T solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This program develops and demonstrates integrated, state of the art, high energy laser (HEL) and high power electromagnetic (HPEM) directed energy (DE) weapon demonstrator systems to satisfy Department of the Air Force requirements in areas including: counter adversary unmanned aerial systems (c-UAS), counter adversary intelligence/surveillance/reconnaissance (c-ISR), counter adversary missiles (c-Missile), counter adversary electronics (c-Electronic), and other mission objectives. Efforts in this program have been coordinated through the Department of War Science and Technology Executive Committee process to harmonize efforts and eliminate duplication. Technologies developed under Program Element 0602605F / Directed Energy Technology feed directly into this program. Funds in this PE may be used to investigate specified technology advancements in air, space and/or cyber domains. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603605F / Advanced Weapons Technology Technology Development (ATD) In order to manage, execute, and deliver science and technology capabilities, this program element may include necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, etc. R-1 Line Item 24, received a Congressional add for FY2026 12.400 million special purpose power generation for novel effectors. Upon Congressional spend plan approval, an Internal Reprogramming (IR) will be processed aligning the funding to PE 0602605F for proper execution. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603609N$$, $$Conventional Munitions$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 10877000, 9001000, 8950000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 29, "original_pe": "0603609N", "page_header": "Department of the Navy"}$$::jsonb, $$Most Navy munitions react violently when exposed to unplanned stimuli such as fire, shock, and bullet or fragment impact, thus presenting a great hazard to ships, aircraft, and personnel. The Insensitive Munitions Advanced Development (IMAD) program will provide, validate, and transition technology to all new weapon developments and priority weapon systems and enable production of munitions insensitive to these stimuli with no reduction in combat performance. Insensitive Munitions (IM) is the Navy's focused effort on propellants, propulsion units, explosives, warheads, fuses, and pyrotechnics to reduce the severity of cook-off and bullet/ fragment impact reactions, minimizing the probability for sympathetic detonation, both in normal storage and in use, increasing ship and platform survivability and satisfying performance and readiness requirements.$$, NULL, 10092000, 9277000, 9131000, NULL, NULL, 57, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 8801000, 10877000, 10216000, 10216000, NULL, 10216000, 9296000, $$Most Navy munitions react violently when exposed to unplanned stimuli such as fire, shock and bullet or fragment impact, thus presenting a great hazard to ships, aircraft and personnel. The Insensitive Munitions Advanced Development (IMAD) program (Project 0363) will provide, validate and transition technology to all new weapon developments and priority weapon systems and enable production of munitions insensitive to these stimuli with no reduction in combat performance. Insensitive Munitions (IM) is the Navy's focused effort on propellants, propulsion units, explosives, warheads, fuses and pyrotechnics to reduce the severity of cook-off and bullet/ fragment impact reactions, minimizing the probability for sympathetic detonation, both in normal storage and in use, increasing ship and platform survivability and satisfying performance and readiness requirements. The Explosives Safety and Weapons Assessment (ES&WA) program (Project 0364) was a new start in FY 2025.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603618D8Z$$, $$Joint Electronic Advanced Technology$$, $$rdte_dw_ba3$$, $$dw$$, 2026, 20575000, 16584000, 17177000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 69, "original_pe": "0603618D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$The Electromagnetic Operating Environment (EMOE) spans the terrestrial and space domains. It is the largest and most complex warfighting environment because it is universally pervasive, largely unseen, and can only be perceived through the use of advanced electronic technologies. Understanding and addressing warfighting challenges in the EMOE is essential to all military operations because it is through the use of Electromagnetic Spectrum (EMS) technologies that we perceive operational realities - the state and disposition of all military and nonmilitary forces and groups within operational environments - and coordinate all actions of our military forces. And it is through Electromagnetic Spectrum Operations (EMSO) that adversarial use of the EMOE can be impacted and potentially denied. EMS-enabled cyber capabilities have linked the cyber and EMOE domains in such a way that the two domains often enable each other. Independently, and sometimes in concert with each other, they will be used to deliver or enable non-kinetic effects. It is important that the two domains be considered in terms of their many potential synergies and not in isolation of one another. Cyberspace and the EMOE can and will overlap in operationally significant ways. Adversary radars are evolving from fixed analog systems to programmable digital variants with agile waveforms and unknown behaviors making preprogrammed electronic countermeasure less effective. Cognitive, adaptive, and passive technologies figure prominently. Foreign developments include new generations of challenging threats ranging from small, unmanned air systems and easily transportable Man-Portable Air Defense Systems (MANPADS) to dedicated anti-access area denial (A2/AD) military systems including integrated air defense systems and increasingly capable cruise and ballistic missiles that have incorporated the most advanced sensors, communication and electromagnetic warfare (EW) technologies. Non-kinetic exploits against the Command and Control (C2) networks in the cyber domain or at an EMS/cyber interface are also relevant. The Joint Electromagnetic Advanced Technology (JEAT) Program was established to address these challenges through efforts designed to substantially accelerate the development and maturing of innovative technologies to (1) address new EW and EW/Cyber warfighting challenges and (2) provide new, leap ahead EMSO warfighting capabilities to ensure U.S. warfighters will always have decisive EW and EW/Cyber overmatch capabilities. The JEAT program focuses on emerging EW and EW/Cyber- related technologies that fall outside the Services’ purviews, technologies that can be influenced with a joint (multi-Service) interest or technologies that are not being developed rapidly enough. JEAT investment influences all of these. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                         Date: June 2025 Appropriation/Budget Activity                                             R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:      PE 0603618D8Z / Joint Electronic Advanced Technology Advanced Technology Development (ATD)$$, NULL, 21482000, 21887000, 22330000, NULL, NULL, 59, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 16868000, 20438000, 49083000, 49083000, NULL, 49083000, 22330000, $$This program supports the Department's National Defense Strategy priorities to Defend the U.S. Homeland including America’s skies and borders, and Deterring China in the Indo-Pacific. It also supports DODD 3222.04 - EW Policy, 8/31/2018, FY 2025 NDAA, Sec. 234, SECDEF Priorities, Classified Integrated Priority List(s) (IPL’s) and Joint Requirements. The Electromagnetic Superiority Strategy (EMSS) and EMSS Implementation Plan (I-Plan) highlight that the U.S. has entered an age of warfighting wherein U.S. dominance in air, land, sea, space, cyberspace and the electromagnetic spectrum (EMS) is challenged by peer and near peer adversaries and these challenges have exposed the cross cutting reliance of U.S. forces on the EMS and are driving a change in how the Department of War approaches activities in the EMS to maintain all domain advantage. EMS Superiority brings important advantages to any cost imposition strategy. By developing asymmetric EMS capabilities, the DoW can protect friendly fire capabilities from disruption and attrition, while simultaneously denying or degrading the effectiveness of adversaries high priced systems. The EMS SS identifies key thrust areas and those thrust areas benefit from robust S&T investment: 1. Improve technologies to enable systems to sense, assess, share, maneuver and survive in complex Electromagnetic Operating Environments (EMOE) – noted “EMSO C2” (Electromagnetic Spectrum Operations Command and Control) from here on. 2. Leverage and Adapt Commercial Technologies (to include low cost and attritable options) – noted “Cost imposing EMSO” from here on. 3. Field Disruptive EMS Capabilities to counter and survive against Complex, distributed and rapidly proliferating effects – noted “Countering Complex Emitters’ from here on. Adversary radars are evolving from fixed analog systems to programmable digital variants with agile waveforms and unknown behaviors making preprogrammed electronic countermeasure less effective. Cognitive, adaptive, and passive technologies figure prominently. Foreign developments include new generations of challenging threats ranging from small, unmanned air systems and easily transportable Man-Portable Air Defense Systems (MANPADS) to dedicated anti-access area denial (A2/AD) military systems including integrated air defense systems and increasingly capable cruise and ballistic missiles that have incorporated the most advanced sensors, communication and electromagnetic warfare (EW) technologies. Non-kinetic exploits against the Command and Control (C2) networks in the cyber domain or at an EMS/cyber interface are also relevant. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                    Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:           PE 0603618D8Z / Joint Electronic Advanced Technology Advanced Technology Development (ATD) The Joint Electromagnetic Advanced Technology (JEAT) Program was established to address these challenges through efforts designed to substantially accelerate the development and maturing of innovative technologies to (1) address the aforementioned technical challenges and (2) provide new, leap ahead EMSO warfighting capabilities to ensure U.S. warfighters will always have decisive EMSO overmatch capabilities. JEAT focuses on exploring and advancing emerging technologies to give the military an advantage in Electromagnetic Warfare (EW). It aims to develop new capabilities, address existing challenges, and provide tactical advantages in EW across all domains. The JEAT program focuses on technologies that fall typically outside the Services’ purviews, technologies that can be influenced with a joint (multi-Service) interest or technologies that are not being developed rapidly enough. JEAT investment influences all of these.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603619A$$, $$Landmine Warfare and Barrier - Adv Dev$$, $$rdte_army_ba4$$, $$asa_alt$$, 2026, 41516000, 60202000, 60617000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 13, "original_pe": "0603619A", "page_header": "Department of the Army"}$$::jsonb, $$Projects CE5 - The current mounted breaching system, the M58 Mine Clearing Line Charge (MICLIC), is a rocket-projected explosive line charge that was initially fielded over 50 years ago and is becoming increasingly less effective against modernized threat obstacles which does not support Multi-Domain Operations (MDO). This effort will focus on the development of the XM123 Ground Obstacle Breaching Lane Neutralizer (GOBLN) system, an MDO-capable modular mission payload which will provide greater effectiveness against current and emerging threat obstacles and enhanced operational reliability, supportability, mobility and survivability beyond the current state. The Program will collaborate with Transformation In Contact (TIC) units to further mature breaching technologies. The target platforms for GOBLN is the ground robotic vehicle to support the Combat Engineer mission and any future emerging requirements. GOBLN has been endorsed by the Next Generation Combat Vehicle (NGCV) Cross Functional Team (CFT) and will have the ability to integrate with current and future platforms. The modularity also allows for integration with other current and future platforms. The FY 2026 request supports continued Technology Maturation and Risk Reduction (TMRR) and a soldier touchpoint that will include a Technology Readiness Level (TRL) 6 prototype demonstration. Project EK7 Area Denial Capability Development provides for the advanced capability development of Terrain Shaping systems and develops modernized, non- persistent U.S. Anti-personnel landmine policy compliant munition fields. During joint, multi-domain, high intensity conflicts, Terrain Shaping systems disrupt, fix, turn and block enemy freedom of maneuver while enhancing friendly freedom of maneuver within the same battle space. Terrain Shaping systems enable maneuver commanders to directly influence where battlefield engagements occur. Terrain Shaping systems will replace a portion of the Family of Scatterable Mines (FASCAM) systems which are beyond their designed life. The project will develop Terrain Shaping prototype systems to evaluate and integrate emerging technologies in collaboration with Transformation in Contact (TIC) units to further mature terrain shaping technologies in real time to drive innovation, enhance learning, refine requirements and accelerate solution development. Terrain Shaping systems will use an open system and modular architecture to facilitate future development, maintenance, repair, and product improvements to include emerging requirements such as the ground robotic vehicle to support the Combat Engineer mission. XM204 Interim Top Attack program, the first Terrain Shaping capability insertion, has entered into production with Initial Operational Capability (IOC) projected for 1QFY26 to meet United States Army Europe (USAREUR) Operational Needs (ONS) #18-22702. The Army is developing an enduring solution to fill the directed obstacle capability gap. FY 2026 budget supports the research and development of the Terrain Shaping systems to include development of a complex obstacle employing a modernized, semiautonomous/autonomous bottom attack capability. Terrain Shaping systems will include complementary lethal capability and advanced network integration to provide a complex Terrain Shaping capability that complies with U.S. Anti-Personnel Landmine Policy and provides the commander greater speed and flexibility to transition between offensive and defensive operations. The enduring Terrain Shaping Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                               Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced       PE 0603619A / Landmine Warfare and Barrier - Adv Dev Component Development & Prototypes (ACD&P) capability development supports the approved Terrain Shaping Abbreviated-Capability Development Document (A-CDD) and Army Futures Command (AFC) Terrain Shaping Strategy for Land Domain and Multi-Domain Operations (MDO). The FY 2026 request was reduced by $1.107 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, 46485000, 29329000, 9044000, NULL, NULL, 63, $$RDTE - Vol 2 - Budget Activity 4A.pdf$$, NULL, FALSE, 58477000, 34296000, 31374000, 31374000, NULL, 31374000, NULL, $$Projects CE5 - The XM123 Autonomous Breaching System (ABS), previously referred to as Ground Obstacle Breaching Lane Neutralizer (GOBLN), will enhance Combat Engineer capabilities by providing a system to defeat current and emerging threats - including mines and other explosive hazards - improving force survivability and mobility. Collaborating with Transformation In Contact (TIC) units, the program will mature advanced breaching technologies in Precision Detection, Precision Neutralization, Area Reduction, and Mission Planning, leveraging advancements in detection and Automated Target Recognition (ATR) for both surface laid and surface flush hazards as well as maturation of detection capabilities for buried hazards. ABS's modular design will enable integration with air and ground autonomy platforms, reducing Soldier exposure to risk. The FY 2027 request supports accelerated development and integration of precision detection and neutralization components and software with candidate autonomous platforms to evaluate Area Reduction capabilities and further develops mature component technologies. Project EK7 Area Denial Capability Development provides for the advanced capability development of Terrain Shaping systems and develops modernized, non- persistent U.S. Anti-personnel landmine policy compliant munition fields. During joint high intensity conflicts, Terrain Shaping systems disrupt, fix, turn and block enemy freedom of maneuver while enhancing friendly freedom of maneuver within the same battle space. Terrain Shaping systems enable maneuver commanders to directly influence where battlefield engagements occur. Terrain Shaping systems will replace a portion of the Family of Scatterable Mines (FASCAM) systems which are beyond their designed life. The project will develop Terrain Shaping prototype systems leveraging an accelerated agile acquisition strategy that includes rapid prototyping followed by system of system demonstration, collaboration and fielding to Transformation in Contact (TiC) units to mature Terrain Shaping technologies in real time to drive innovation, enhance learning, refine requirements, and accelerate solution development. The Terrain Shaping systems will use an open system and modular approach to leverage existing Army infrastructure and capabilities to include Command, Control, Communication, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) platforms, Robotic Ground Vehicles, and Unmanned Aerial Systems. The FY2027 request supports the rapid prototyping effort and delivery of initial capability to TiC units to inform a follow-on prototyping effort and production decision. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced          PE 0603619A / Landmine Warfare and Barrier - Adv Dev Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603627A$$, $$Smoke, Obscurant and Target Defeating Sys-Adv Dev$$, $$rdte_army_ba4$$, $$asa_alt$$, 2027, 0, 0, 0, NULL, $${"fy26_v180": {"note": "FY27_only_PE_no_FY26_reality", "source": "b1_null_zero_v180"}}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 0, 5596000, 5596000, NULL, 5596000, NULL, $$Screening Obscuration Module (SOM) is a rapidly deployable modular system that can disrupt electromagnetic sensors used for identification and targeting. SOM can be deployed on multiple platforms ranging from fielded platforms to future unmanned robotic platforms. The SOM strategy includes an incremental approach: SOM- Visual (SOM-V, increment one), SOM-Bispectral (SOM-B, increment two), and SOM-Multispectral (SOM-M, increment three). SOM-M covers the full spectrum of visual through millimeter wave screening obscuration; covering all three incremental capabilities. SOM benefits the warfighter by disrupting adversaries targeting systems and improving soldier and platform survivability. The SOM-M program will utilize FY 2027 RDTE to award a contract and initiate a preliminary design in order to develop prototypes and initiate risk reduction testing.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2031_L014_v19$$, $$Future Vertical Lift FAMILY OF SYSTEMS$$, $$proc_army_2031_ba1$$, $$cft_fvl$$, 2027, 0, 0, 0, NULL, $${"fy26_v178": {"disc_K": 913060, "li_num": 10, "source": "p40_fy26_v178", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Army/Aircraft_Procurement_Army.txt"}}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 913060000, 0, 0, 0, 0, NULL, NULL, $$Budget J-Books/FY27/Army/Aircraft_Procurement_Army.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603635M$$, $$Marine Corps Grnd Cmbt/Supt Sys$$, $$rdte_navy_ba4$$, $$mc$$, 2026, 278261000, 118753000, 94013000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "mc", "page_num": 29, "original_pe": "0603635M", "page_header": "Department of the Navy", "fy26_v182_deferred": true, "fy26_v182_source_file": "RDTEN_BA4_Book.txt", "fy26_v182_source_line": 28606, "fy26_v182_supp_K_skipped": 4750, "fy26_v182_deferred_reason": "parser_disc_does_not_match_db_disc"}$$::jsonb, $$This PE supports the demonstration and validation of Marine Corps Ground/Supporting Arms Systems for utilization in Marine Air-Ground Expeditionary Force amphibious operations. This program is funded under Demonstration and Validation because it develops and integrates hardware for experimental tests related to specific ground weapon systems.$$, NULL, 291953000, 280916000, 216883000, NULL, NULL, 58, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 89449000, 222951000, 521995000, 521995000, NULL, 521995000, 159152000, $$This PE is fundamentally a crucial "try before you buy" initiative for the Marine Corps' entire arsenal of ground combat and fire support systems. Its core purpose is to rigorously test, experiment with, and ultimately validate new or upgraded weapons and equipment in the most realistic scenarios possible before the Corps commits to a massive investment in full-scale production and fielding. This meticulous process ensures that every piece of gear eventually placed into the hands of a Marine is not only lethal and effective but also entirely reliable and perfectly suited for their unique mission, thereby safeguarding lives and taxpayer dollars by preemptively avoiding costly failures. Focus on the formal "Demonstration and Validation" phase within the military acquisition lifecycle. This stage, arriving after initial concepts and foundational technologies have been explored but before a commitment to mass procurement, is designed to reduce inherent risks. It seeks definitive answers to critical questions: Does this new weapon system truly perform as its manufacturer claims? Can our Marines effectively operate and maintain it under the severe stress of a combat environment? Will it seamlessly integrate with our existing communication networks, targeting equipment, and other systems? Ultimately, this is the "prove it to me" phase, where this PE funds the necessary activities to secure that undeniable proof. The scope of this funding is directed precisely at Marine Corps Ground and Supporting Arms Systems. This means it explicitly covers the direct combat tools of our infantry and combat support units, such as new rifles, machine guns, or anti-tank weapons, alongside the systems that provide crucial indirect fire support, including advanced artillery, rocket systems like HIMARS, and the sophisticated fire control technology that ensures their pinpoint accuracy. Crucially, all this testing and validation is focused on their utilization within Marine Air-Ground Task Force (MAGTF) amphibious operations - the signature mission of the Marine Corps. This context is paramount, as it defines the specific, unforgiving environment where these systems must not only function but excel. Amphibious operations introduce unique challenges: can the equipment withstand corrosive saltwater spray and fine sand? Can it be easily and robustly transported on landing craft, helicopters, or amphibious vehicles through rough seas and onto a contested beach? Is it durable enough to survive such transit and still perform? Does it fit within the Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                  Date: April 2026 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced               PE 0603635M / Marine Corps Grnd Cmbt/Supt Sys Component Development & Prototypes (ACD&P) limited confines of a naval vessel or an amphibious vehicle, and can it be maintained in an austere environment with minimal logistical support? A weapon that performs flawlessly on a controlled test range might catastrophically fail during a real-world beach landing; this PE funds the vital testing to uncover such vulnerabilities before lives are on the line. This program prioritizes the development and integration of actual hardware for these experimental tests. This isn't merely about theoretical reports or computer simulations. Instead, this funding is directly used to build production-representative prototypes, integrate them with existing Marine Corps gear to ensure interoperability, and then put them through rigorous, live-fire exercises and simulated amphibious landings in the hands of Marines. Through these essential, hands-on, hardware- focused experiments, the Marine Corps gathers the empirical data needed to make informed, sound decisions on whether to proceed with a major acquisition, ultimately ensuring our warfighters are equipped with nothing but the best. The FY 2026 spend plan amount for Combat Capability Development Transition Long Range Unmanned Surface Vessels (LRUSV) includes $23,793 thousands of discretionary and $4,750 thousands of mandatory (reconciliation) for a total of $28,543 thousands.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603639A$$, $$Tank and Medium Caliber Ammunition$$, $$rdte_army_ba4$$, $$cft_fvl$$, 2026, 185472000, 90139000, 102027000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 13, "original_pe": "0603639A", "page_header": "Department of the Army", "fy26_v182_disc_K": 87972, "fy26_v182_supp_K": 50000, "fy26_v182_total_K": 137972, "fy26_v182_note_name": "Tank and Medium Caliber Ammunition", "fy26_v182_source_file": "RDTE - Vol 2 - Budget Activity 4A.txt", "fy26_v182_source_line": 2687}$$::jsonb, $$A portion of this funding line is directly aligned to each Future Vertical Lift (FVL) and Assured Positioning, Navigation, & Timing (APNT) Army Modernization Priorities. The Tank and Medium Caliber Ammunition Program Element encompasses a comprehensive program to develop, rapidly transition to production, and field advanced weapons and munitions for small, medium and large caliber munitions, tank ammunition, mortar ammunition, cannon artillery ammunition, and close combat system items. These Projects will ensure continued battlefield overmatch and lethality of United States maneuver forces against the full range of modern battlefield threats. To achieve this, Tank and Medium Caliber Ammunition projects will identify and develop promising technologies through competitive development and streamlined acquisition procedures. Project CD8 - Long Range Precision Munition (LRPM) is the lethal variant of the Launched Effects (LE) Family of Systems which provide a range of capabilities through variations of platforms, payloads, and mission systems. LE provides tactical and operational flexibility through collaboration of heterogeneous groups of LE launched from multiple domains (land and air) in conjunction with other manned platforms, C2, unmanned systems, and sensors throughout the operational environment. The ability to interoperate and coordinate with other LE systems at long ranges and adapt to changing threats is a core concept of the Launched Effects Abbreviated Capability Development Document validated in June 2024. Primary target set for LRPM is Integrated Air Defense Systems. LRPM will provide Army Aviation and Ground Forces with a precise long range munition system to rapidly respond in a combat environment to improve the lethality and stand-off of Warfighters and aviation platforms in an Anti-Access Area Denial (A2AD) and positioning, navigation, and timing (PNT) denied environment. FY 2026 funding for LRPM transferred to PE 0609345A/Project A46. Project DK5 - The 155 millimeter (mm) High Explosive Conventional Artillery Modernization Project is focused on the design and development of common artillery projectiles capable of accurate delivery of multiple payloads to deliver the Army's Field Artillery operational efficiencies. These efforts will provide the Army's Field Artillery lethal and nonlethal area effects at ranges relevant and decisive to the Division fight. The Modular Artillery for Combat Effectiveness (MACE) line of effort will develop lethal area effects. The Extended Range (ER) Cargo line of effort will develop lethal and non-lethal areas effects at the longer ranges necessary to enable transformation in contact. The Army requires versatile, affordable, sustainable, and enduring projectiles capable of rendering a variety of lethal and non-lethal effects necessary to disable and destroy a broad set of targets within multiple threat formations. This Project is executing an evolutionary approach to ensure a common projectile can support multiple cargo capabilities, including lethal, Radio Frequency (RF) obscuration, visible obscuration, Intelligence, Surveillance, and Reconnaissance (ISR), Infra-red (IR) illumination, visible illumination, electronic attack, Terrain Shaping Obstacles, and future cargo capabilities. Fiscal Year (FY) 2026 funding will support the technical assessments, system development, prototypes and integration, concept studies, component testing, technology maturation, and engineering evaluations in support of the Army's Field Artillery Cannon Transformation Strategy. Project DK7 - 155mm Artillery Propulsion Modernization (Advanced Component Development) supports the United States Army's Cannon Transformation Strategy and develops and improves three propulsion systems components: (1) modular charge that achieves minimum to intermediate ranges, (2) super charge that achieves maximum range and (3) percussion primer that initiates both the modular and super charges. Development efforts also include the design of packaging solutions (for Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced              PE 0603639A / Tank and Medium Caliber Ammunition Component Development & Prototypes (ACD&P) protection during transportation and long-term storage), digital engineering, test measurement devices and modeling and simulation tools. Design emphasis will be placed upon Joint Ballistic Memorandum of Understanding (JBMOU) compatibility to maximize interoperability with foreign allies and ensuring that the components support manufacturability within the national technology and industrial base (NTIB) that includes Australia, Canada, UK and US. The Fiscal Year (FY) 2026 funding will support prototyping and testing of propelling charge and ignition components to advance technology for improvement of the propellant effectiveness, cannon life, primer and charge ignition performance, system-level handling and rates-of-fire, and overall propulsion suitability and survivability. Project DL5 - 155mm Extended Range Artillery Munitions: The Extended Range Artillery Munitions (ERAM) Project supports the development of a 155mm system of systems that includes projectile, propellant, primer, fuze, and fuze setter which will deliver lethality and range overmatch in 155mm artillery weapon systems at more than double the current range from legacy artillery cannons and will be compatible with future 155mm artillery systems in a Global Positioning System (GPS) degraded and denied environments. The ERAM development effort is part of an organic Long Range Precision Fires capability, which will provide overmatching cannon artillery range capability at both Tactical and Operational Fires range by shaping the nature of the close fight through seeking moving and imprecisely located targets at extended ranges, increase range capability of the current 39 caliber cannon fleet and will also be compatible with future 52 caliber and above artillery weapon systems. Fiscal Year (FY) 2026 funding will support technology maturation and risk reduction of key system and subsystems improvements in performance in difficult use cases, and integration of the tactical warhead and seeker culminating in a series of Design Verification Testing (DVT) to achieve Technology Readiness Level (TRL) six (6) maturity. Project DN7 - The Mobile-Long Range Precision Strike Missile (M-LRPSM) is an approved Directed Requirement (DR). It must defeat Tier 1 thru Tier 3 Armor (stationary & defilade) Troops, Field Fortifications & Urban structures, and achieve a range of greater than 25 KM. It will be transportable by existing Infantry Brigade Combat Teams (IBCT) Light Tactical Vehicle platforms. It has the ability to adjust the missile flight, retarget, and abort, and have multiple missile launch capability. It must be survivable and resilient in denied and degraded environments. Project EC3 - Ammunition Logistics Prototyping: This project supports the future force by improving the distribution, management, reliability, and survivability of ammunition through the advanced development, integration, and demonstration of logistics system enablers supporting the Design of Army 2040. These enablers will improve the efficiency and effectiveness of ammunition operations, to include retrograde, while reducing the logistics footprint on the battlefield. Technology areas addressed include handling, distribution, management (strategic and tactical), prognostics, diagnostics, asset visibility, explosives safety, autonomous friendly packaging and palletization. The efficient deployment and sustainment of reliable ammunition is vital to success on the battlefield. This project enhances the operational effectiveness of the ammunition logistics system to ensure the distribution of reliable ammunition to the Warfighter. Project FA5 - The Assured Precision Weapons and Munitions (APWM) - FA5 Project is focused on advanced risk mitigation, technology integration, prototyping, and product support to identify, evaluate, mature, test, and demonstrate various assured precision and countermeasure prototype technologies in Weapon and Munitions (W&M) components and subsystems within a complex System-of-Systems (SoS) environment. The APWM Project reinforces the National Defense Strategy's (NDS) major lines of effort through technology development and prototyping, which increases lethality and ensures future combat overmatch success of the Joint Force against peer/near-peer adversaries. This project also aims to improve program performance and affordability for multiple W&M Programs of Record (PoRs) via Joint Lethality Positioning, Navigation and Timing (PNT), layered Navigation Warfare (NavWar) and Electronic Warfare (EW) converged munition delivered effects, and Army M-Code Global Positioning System (GPS) coordinated efforts. The APWM Project directly supports the top Army Modernization Priorities via the All-Domain Sensing (ADS) and Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                  Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced         PE 0603639A / Tank and Medium Caliber Ammunition Component Development & Prototypes (ACD&P) Long-Range Precision Fires (LRPF) imperatives in support of the NDS and multiple Public Law related Congressional imperatives. Funding will support engagement by W&M PNT experts in the development, evaluation, and technology maturation/delivery activities of the US Space Force's (USSF) M-Code GPS, Army's PNT related programs, and ADS Cross-Functional Team (CFT) programs in support of LRPF and Counter Anti- Access/Area Denial (A2/AD) missions. Funding will also enable component and subsystem architecture input essential for Precision W&M operating in a contested NavWar and EW SoS environment, Army M-Code GPS technology integration and evaluation, planning and evaluating next generation M-Code GPS to validate capability for future Joint precision munitions, and maturation of alternative PNT and NavWar related technologies and solutions to enable informed PoR milestone and Army cross-functional modernization decisions. Project FG1 - The Cannon Delivered Area Effects Munitions (C-DAEM) Budget Activity Four (BA4) Project supports the development efforts of the XM1155 projectile, which transitioned in FY 2025 from Budget Activity Three (BA3) PE 0603464A / Long Range Precision Fires Advanced Technology Project BO8 Long Range Precision Fires Advanced Tech), will deliver lethality and range overmatch in 155mm artillery weapon systems at more than double the current range from legacy artillery cannons and will be compatible in future 155MM artillery systems in a Global Positioning System (GPS) degraded and denied environments. The XM1155 projectile, developed as part of an organic Long Range Precision Fires capability, will provide overmatching cannon artillery range capability at both Tactical and Operational Fires range by shaping the nature of the close fight through seeking moving and imprecisely located targets at extended ranges, will increase range capability of the current 39 caliber cannon fleet and will also be compatible with future 52 caliber and above artillery weapon systems. This project does not have a FY 2026 budget request. Project XT5 - 30mm Anti-Personnel and Counter Unmanned Aerial Systems (UAS): Airburst capability is identified as a threshold Key System Attribute (KSA) in Apache Block 3 Capability Production Document (CPD) - Approved 14 June 2017 and other cannon caliber Operational N… [truncated]$$, NULL, 180585000, 63455000, 45139000, NULL, NULL, 64, $$RDTE - Vol 2 - Budget Activity 4A.pdf$$, NULL, FALSE, 108340000, 137972000, 277248000, 277248000, NULL, 277248000, 45589000, $$A portion of this funding line is directly aligned to each Future Vertical Lift (FVL) and Assured Positioning, Navigation, & Timing (APNT) Army Modernization Priorities. The Tank and Medium Caliber Ammunition Program Element encompasses a comprehensive program to develop, rapidly transition to production, and field advanced weapons and munitions for small, medium and large caliber munitions, tank ammunition, mortar ammunition, cannon artillery ammunition, and close combat system items. These Projects will ensure continued battlefield overmatch and lethality of United States maneuver forces against the full range of modern battlefield threats. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                   Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced            PE 0603639A / Tank and Medium Caliber Ammunition Component Development & Prototypes (ACD&P) To achieve this, Tank and Medium Caliber Ammunition projects will identify and develop promising technologies through competitive development and streamlined acquisition procedures. . Project CD8 - Long Range Precision Munition (LRPM) is the lethal variant of the Launched Effects (LE) Family of Systems which provide a range of capabilities through variations of platforms, payloads, and mission systems. LE provides tactical and operational flexibility through collaboration of heterogeneous groups of LE launched from multiple domains (land and air) in conjunction with other manned platforms, C2, unmanned systems, and sensors throughout the operational environment. The ability to interoperate and coordinate with other LE systems at long ranges and adapt to changing threats is a core concept of the Launched Effects Abbreviated Capability Development Document validated in June 2024. Primary target set for LRPM is Integrated Air Defense Systems. LRPM will provide Army Aviation and Ground Forces with a precise long range munition system to rapidly respond in a combat environment to improve the lethality and stand-off of Warfighters and aviation platforms in an Anti-Access Area Denial (A2AD) and positioning, navigation, and timing (PNT) denied environment. Project DK5 - The 155 millimeter (mm) High Explosive Conventional Artillery Modernization will develop common artillery projectiles capable of accurate delivery of multiple payloads to provide US Army's Field Artillery units with lethal and nonlethal area effects at ranges necessary to disable and destroy a broad set of targets within multiple threat formations. The Modular Artillery for Combat Effectiveness (MACE) line of effort will develop lethal area effects. The Extended Range (ER) Cargo line of effort will develop lethal and non-lethal areas effects at the longer ranges necessary to enable transformation in contact. This effort is executing an evolutionary approach to ensure a common projectile can support multiple cargo capabilities, including but not limited to lethal, Radio Frequency (RF) obscuration, visible obscuration, Intelligence, Surveillance, and Reconnaissance (ISR), Infra-red (IR) illumination, visible illumination, electronic attack, Terrain Shaping Obstacles, and future cargo capabilities. Fiscal Year (FY) 2027 funding will support the Technology Readiness Level (TRL) 6 demonstration, down-selection, contract award for system development, and technical assessment in support of the Army's Field Artillery modernization objectives. Project DK7 - The 155mm Artillery Propulsion Modernization (Advanced Component Development) project supports the United States Army's Field Artillery modernization objectives by developing and maturing three propulsion system components: (1) modular charge that achieves minimum to intermediate ranges, (2) supercharge that achieves maximum range, and (3) percussion primer that initiates both the modular and supercharges. Development efforts also include the design of packaging solutions required for protection during transportation and long-term storage, digital engineering, test measurement devices and modeling and simulation tools. Design emphasis will shift from Joint Ballistic Memorandum of Understanding (JBMOU) compatibility to down selected Mobile Tactical Cannon (MTC) that maximizes interoperability with foreign allies, ensuring that the components support manufacturability within the National Technology and Industrial Base (NTIB). Fiscal Year (FY) 2027 funding will support continued prototyping and testing of propelling charges, combustible cases, additives, and ignition components to advance technologies that improve propellant effectiveness, extend cannon life, enhance primer and charge ignition performance, optimize system-level handling, rates of fire, and overall propulsion suitability and survivability. Project DL5 - The Extended Range Artillery Munitions (ERAM) project supports the development of a 155mm system of systems that includes projectile, propellant, primer, fuze, and fuze setter which will deliver lethality and range overmatch in 155mm artillery weapon systems at more than double the current range from legacy artillery cannons and will be compatible with future 155mm artillery systems in contested Global Positioning System (GPS) environments and suboptimal atmospheric conditions. The ERAM development effort is part of an organic Long Range Precision Fires capability, which will provide overmatching cannon artillery range capability at both Tactical and operational Fires range by shaping the nature of the close fight through seeking moving and imprecisely located targets at extended ranges, Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced              PE 0603639A / Tank and Medium Caliber Ammunition Component Development & Prototypes (ACD&P) increase range capability of the current 39 caliber cannon fleet and will also be compatible with future 52 caliber and above artillery weapon systems. Fiscal Year (FY) 2027 funding will support technology maturation and risk reduction of key system and subsystems improvements in performance in difficult use cases (such as GPS contested environments and suboptimal atmospheric conditions), and integration of the tactical warhead and seeker culminating in a series of Design Verification Testing (DVT) to achieve Technology Readiness Level (TRL) six (6) maturity. The FY 2026 President's Budget request included $50.000 million of mandatory funding. Project DN7 - The Mobile-Long Range Precision Strike Missile (M-LRPSM) is an approved Directed Requirement (DR). It must defeat Tier 1 thru Tier 3 Armor (stationary & defilade) Troops, Field Fortifications & Urban structures, and achieve a range of greater than 25 KM. It will be transportable by existing Infantry Brigade Combat Teams (IBCT) Light Tactical Vehicle platforms. It has the ability to adjust the missile flight, retarget, and abort, and have multiple missile launch capability. It must be survivable and resilient in denied and degraded environments. Project EC3 - Ammunition Logistics Prototyping - This project supports the future force by improving the distribution, management, reliability, and survivability of ammunition through the advanced development, integration, and demonstration of logistics system enablers in alignment with Transformation In Contact and Deliberate Transformation. These enablers will improve the resiliency, efficiency and effectiveness of ammunition operations, to include retrograde, while reducing the logistics footprint on the battlefield. Technology areas addressed include handling, distribution, management (strategic and tactical), prognostics, diagnostics, asset visibility, explosives safety, autonomy friendly packaging, and palletization. The efficient deployment and sustainment of reliable ammunition is vital to success on the battlefield. This project enhances the operational effectiveness of the ammunition logistics system to ensure the distribution of reliable ammunition to the Warfighter. Project FA5 - The Assured Precision Weapons and Munitions (APWM) - FA5 Project is focused on advanced risk mitigation, technology integration, expedited prototyping, and product support to rapidly identify, evaluate, mature, test, and demonstrate various assured precision related prototype technologies in munitions and munition resilient support and survivability components and subsystems within a complex environment with the overarching goal of solving tough operational problems and addressing critical capability gaps. The APWM project reinforces the Secretary of War's Acquisition Transformation Strategy, and the Army Transformation Initiative (ATI) major lines of effort through fast technology development and prototyping, which increases lethality and ensures future combat overmatch success of the Joint force against peer/near-peer adversaries and the China pacing threat. This project also aims to improve performance and affordability of Army and Joint capability portfolios via Joint Lethality (JL) Positioning, Navigation and Timing (PNT), Navigation Warfare (NavWar), and Army M-code Global Positioning System (GPS) coordinated efforts and integration of innovative industry contributions. The APWM project directly supports the top Army and Joint force modernization priorities in support of the NDS and multiple Public Law (PL) related congressional imperatives. Funding will support engagement by munition PNT and NavWar related Lethality experts in the development, evaluation, and technology delivery activities of the M-code GPS as well as the Army's continuous adaptation of PNT, NavWar, and Electronic Warfare (EW) enabled capabilities to achieve accurate extended range and hypersonic lethality, increase warfighter survivability, maximizing precision munition stowed kills and countering Anti-Access/Area Denial (A2/AD) threats. The APWM project enables component and subsystem architecture input essential for precision munitions and other such lethality delivery mechanisms operating in a complex EW threat environments, M-code GPS and technology integration and evaluation (including verifying and validating this capability for future Joint precision munitions), and maturation of alternative PNT and EW/NavWar related technologies, components, payloads, and solutions. Overall, these efforts contribute to informed Army modernization, portfolio, and milestone decisions enhancing the Department's capacity to deploy new technologies and capabilities swiftly. The FY 2026 President's Budget request included $20.000 million of mandatory funding. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                 Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced             PE 0603639A / Tank and Medium Caliber Ammunition Component Development & Prototypes (ACD&P) Project FG1 - The Cannon-Delivered Area Effects Munitions (C-DAEM) Budget Activity Four (BA4) project supports the development efforts of the Extended Range Artillery Projectile (ERAP), which transitioned in Fiscal Year (FY) 2025 from Budget Activity Three (BA3) PE 0603464A / Long Range Precision Fires Advanced Technology Long Range Precision Fires Advanced Tech, Project BO8), will deliver lethality and range overmatch in 155mm artillery weapon systems at more than double the current range from legacy artillery cannons and will be compatible in future 155MM artillery systems in a Global Positioning System (GPS) degraded and denied environments. ERAP, developed as part of an organic Long Range Precision Fires capability, will provide overmatching cannon artillery range capability at both Tactical and Operational Fires range by shaping the nature of the close fight through seeking moving and imprecisely located targets at extended ranges, will increase range capability of the current 39 caliber cannon fleet and will also be compatible with future 52 caliber and above artillery weapon systems. This project does not have a Fiscal Year (FY) 2027 budget request. Project XT5 - 30mm Anti-Personnel and Counter Unmanned Aerial Systems (UAS): Airburst capability is identified as a threshold Key System Attribute (KSA) in Apache Block 3 Capability Production Document (CPD) - Approved 14 June 2017 and other cannon caliber Operational Needs Statements (ONS) and Capability Development Documents (CDD). The Anti-Personnel and Counter Unmanned Aerial Systems (UAS) munition provides increased lethality through airburst effects against personnel, small boats, and small Unmanned Aerial Systems (UAS) without requiring modification to the platform.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603640M$$, $$MC Advanced Technology Demo$$, $$rdte_navy_ba3$$, $$onr$$, 2026, 347124000, 455288000, 296147000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "mc", "page_num": 27, "original_pe": "0603640M", "page_header": "Department of the Navy", "fy26_v182_disc_K": 447950, "fy26_v182_supp_K": 63413, "fy26_v182_total_K": 511363, "fy26_v182_note_name": "Research, Development, Test and Evaluation, Navy", "fy26_v182_source_file": "RDTEN_BA1-3_Book.txt", "fy26_v182_source_line": 25382}$$::jsonb, $$The United States Navy/Marine Corps team is the most potent naval fighting force in the world. Fundamental to their success are the technologies necessary for effective Distributed Maritime Operations (DMO), Expeditionary Advanced Base Operations (EABO), Littoral Operations in Contested Environments (LOCE), Joint Warfighting Concepts, Stand-In Forces, and Reconnaissance / Counter-Reconnaissance. The Office of Naval Research (ONR) combines knowledge of the naval mission with researchers to select and explore solutions critical to expeditionary warfighting needs. It has become clear the joint force needs a capability that operates persistently and with maximum organic mobility and dispersion to compete and deter in the contact and blunt layers. This Program Element (PE) supports investments in critically needed capabilities, as outlined in Expeditionary Advanced Base Operations (EABO), that seeks to initially operate below the threshold of armed conflict by winning the reconnaissance and counter-reconnaissance competition in facilitating deterrence by detection. The USMC also requires combat credible capabilities that employ mobile, low-signature, operationally relevant, and relatively easy to maintain and sustain naval expeditionary forces from a series of austere, temporary locations ashore or inshore within a contested or potentially contested maritime area in order to conduct sea denial, support sea control, or enable fleet sustainment. These future challenges and portents demand robust technologies for the Marine Corps, but the technology options are constrained. They must have a lightweight deployable character, and the ability to operate in austere conditions with little fixed infrastructure or support while retaining the agility and lethality of an integrated maneuver force. Technology must provide full spectrum capability against robust and complex peer and near- peer adversaries while meeting size, weight, power, cost limitations, and information availability command and control systems that work within degraded, disconnected, intermittent and limited environments with reduced threat detectability. The approach within this Program Element (PE) encompasses ideas that support both revolutionary and evolutionary capabilities, and in this way considers and balances both "push" and "pull" aspects of technology projects. This PE matures technologies emerging from PE 0602131M-Marine Corps Landing Force Technology to develop concept prototypes and initial experimentation to confirm utility and suitability in an environment relevant to operations. This PE funds Advanced Technology Development (ATD) that includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Efforts in this PE generally have Technology Readiness Levels (TRLs) of 4 (component and/or breadboard validation in laboratory environment), 5 (component and/or breadboard validation in relevant environment), or 6 (system/subsystem model or prototype demonstration in a relevant environment). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                       Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 3: Advanced           PE 0603640M / MC Advanced Technology Demo Technology Development (ATD) Due to the number of efforts in this PE, the programs described herein are representative of the work included in this PE.$$, NULL, 241294000, 254259000, 257482000, NULL, NULL, 19, $$RDTEN_BA1-3_Book.pdf$$, NULL, FALSE, 287017000, 511363000, 287897000, 287897000, NULL, 287897000, 261538000, $$The United States Navy/Marine Corps team is the most potent naval fighting force in the world. Fundamental to their success are the technologies necessary for effective Distributed Maritime Operations (DMO), Expeditionary Advanced Base Operations (EABO), Littoral Operations in Contested Environments (LOCE), Joint Warfighting Concepts, Stand-In Forces, and Reconnaissance / Counter-Reconnaissance. The Office of Naval Research (ONR) combines knowledge of the naval mission with researchers to select and explore solutions critical to expeditionary warfighting needs. It has become clear the joint force needs a capability that operates persistently and with maximum organic mobility and dispersion to compete and deter in the contact and blunt layers. This Program Element (PE) supports investments in critically needed capabilities, as outlined in EABO, that seeks to initially operate below the threshold of armed conflict by winning the reconnaissance and counter- reconnaissance competition in facilitating deterrence by detection. The USMC also requires combat credible capabilities that employ mobile, low-signature, operationally relevant, and relatively easy to maintain and sustain naval expeditionary forces from a series of austere, temporary locations ashore or inshore within a contested or potentially contested maritime area in order to conduct sea denial, support sea control, or enable fleet sustainment. These future challenges and portents demand robust technologies for the Marine Corps, but the technology options are constrained. They must have a lightweight deployable character, and the ability to operate in austere conditions with little fixed infrastructure or support while retaining the agility and lethality of an integrated maneuver force. Technology must provide full spectrum capability against robust and complex peer and near- peer adversaries while meeting size, weight, power, cost limitations, and information availability command and control systems that work within degraded, disconnected, intermittent and limited environments with reduced threat detectability. The approach within this Program Element (PE) encompasses ideas that support both revolutionary and evolutionary capabilities, and in this way considers and balances both "push" and "pull" aspects of technology projects. This PE matures technologies emerging from PE 0602131M-Marine Corps Landing Force Technology to develop concept prototypes and initial experimentation to confirm utility and suitability in an environment relevant to operations. This PE funds Advanced Technology Development (ATD) that includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Efforts in this PE generally have Technology Readiness Levels (TRLs) of 4 (component and/or breadboard validation in laboratory environment), 5 (component and/or breadboard validation in relevant environment), or 6 (system/subsystem model or prototype demonstration in a relevant environment). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                      Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 3: Advanced           PE 0603640M / MC Advanced Technology Demo Technology Development (ATD) Due to the number of efforts in this PE, the programs described herein are representative of the work included in this PE. The FY 2026 spend plan amount for Research, Development, Test and Evaluation, Navy includes $447,950 thousand of discretionary and $63,413 thousand of mandatory (reconciliation) for a total of $511,363.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA1-3_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603645A$$, $$Armored System Modernization - Adv Dev$$, $$rdte_army_ba4$$, $$asa_alt$$, 2026, 22645000, 54456000, 23235000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 13, "original_pe": "0603645A", "page_header": "Department of the Army"}$$::jsonb, $$Armored System Modernization Advanced Development provides maturation of emerging Science and Technology (S&T) and industry technologies for potential integration onto ground combat vehicles. The purpose of this Program Element's (PE) funding is to demonstrate new capabilities to meet current and future military needs and to determine integration potential across the Army portfolio of ground combat vehicles by testing and evaluating a variety of technologies. The Robotic Combat Vehicle (RCV) Middle Tier Acquisition-Rapid Prototype (MTA-RP) program was funded through RDT&E appropriation via lines 643645EV7, 644107CF4 and 654641CF5. The total investment of the program prior to Army Transformation Initiative (ATI) Executive Order (EXORD) directing to cease development of RCV Hardware was $225M Base-Year 2025 (BY25) dollars. Future development efforts focused on Software Pathway (SWP), as well as autonomous and unmanned system initiatives, will be funded under RDT&E lines 644017FD9 and 655053FB3. The FY 2026 request was reduced by $0.247 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, 23574000, 23765000, 23618000, NULL, NULL, 65, $$RDTE - Vol 2 - Budget Activity 4A.pdf$$, NULL, FALSE, 22387000, 22645000, 23594000, 23594000, NULL, 23594000, 24007000, $$Armored System Modernization Advanced Development provides maturation of emerging Science and Technology (S&T) and industry technologies for potential integration onto ground combat vehicles. The purpose of this Program Element's (PE) funding is to demonstrate new capabilities to meet current and future military needs and to determine integration potential across the Army portfolio of ground combat vehicles by testing and evaluating a variety of technologies.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603662D8Z$$, $$Networked Communications Capability$$, $$rdte_dw_ba3$$, $$dw$$, 2026, 19937000, 3122000, 23034000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 69, "original_pe": "0603662D8Z", "page_header": "Defense-Wide", "fy26_v182_disc_K": 19658, "fy26_v182_supp_K": 65000, "fy26_v182_total_K": 84658, "fy26_v182_note_name": "Network Communications Capabilities", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 12643}$$::jsonb, $$The Networked Communications Capability (NCC) plays a vital role in supporting the Department of Defense (DoD) and Defense Industrial Base (DIB) ecosystem. NCC focuses on maturing and demonstrating technologies that foster interoperable, resilient, and capable strategic and Joint Force communications capabilities. Given the critical reliance of DoD missions on command, control, and communications (C3) infrastructure, the NCC addresses challenges faced by the DoD's existing C3 infrastructure, including internal system-centric design approaches, as opposed to network- and data-centric ones, and external threats from aggressive adversary actions. The integration of both DoD and commercial embedded, virtualized, and cloud-hosted hybrid systems and networks underscores the increasing importance of the DoD's ability to rapidly reconfigure and reconstitute this infrastructure. The NCC strategy employs secure and rapidly reconfigurable software-defined/hardware-supported solutions across the layers of the DoD communications stack (physical, network, information, and application layers). The technology integrates these layers to establish a highly agile, adaptable, and resilient C3 infrastructure. This approach ensures the DoD's ability to maintain critical communications in diverse mission domains such as terrestrial, maritime, air, space, and cyberspace. Additionally, it operates effectively in degraded, contested, or denied environments, supporting both tactical edge and strategic contexts. Building upon previous work with Software Defined Radios (SDRs), the NCC utilizes adaptive methods to dynamically analyze the operating environment. This includes considering parameter changes within individual waveforms and switching between high-data rate, low probability of detection techniques, and leveraging tunable waveforms for C3 across various scenarios. The integration of Software Defined Network (SDN) protocols facilitates routing the right information to the right users at the optimal speed and quality, aligning with the requirements of diverse warfighting missions. These advancements will leverage commercially available software and hardware where possible. The NCC works in collaboration with the Joint Staff and Military Services in collaborative partnership to advocate for the proper testing, evaluation, verification and validation, and certification of all relevant solutions from DIB partners for the purpose of ensuring enduring interoperability / compatibility, resiliency, and capability advancement for the positive benefit of US DoD warfighters and as well those of Allied Nations. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                         Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:       PE 0603662D8Z / Networked Communications Capability Advanced Technology Development (ATD)$$, NULL, 421601000, 164049000, 105511000, NULL, NULL, 60, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 22199000, 84658000, 696297000, 696297000, NULL, 696297000, 72511000, $$The Networked Communications Capability (NCC) plays a vital role in supporting the Department of War (DoW) and Defense Industrial Base (DIB) ecosystem. NCC focuses on maturing and demonstrating technologies that foster interoperable, resilient, and capable strategic and Joint Force communications capabilities. Given the critical reliance of DoW missions on command, control, and communications (C3) infrastructure, the NCC addresses challenges faced by the DoW's C3 infrastructure, including internal system-centric design approaches, as opposed to network- and data-centric ones, and external threats from aggressive adversary actions. The integration of both DoW and commercial embedded, virtualized, and cloud-hosted hybrid systems and networks underscores the increasing importance of the DoW's ability to rapidly reconfigure and reconstitute this infrastructure. The NCC strategy employs secure and rapidly reconfigurable software-defined/hardware-supported solutions across the layers of the DoW communications stack (physical, network, information, and application layers). The technology integrates these layers to establish a highly agile, adaptable, and resilient C3 infrastructure. This approach ensures the DoW's ability to maintain critical communications in diverse mission domains such as terrestrial, maritime, air, space, and cyberspace. Additionally, it operates effectively in degraded, contested, or denied environments, supporting both tactical edge and strategic contexts. The NCC utilizes adaptive methods to dynamically analyze the operating environment. This includes considering parameter changes within individual waveforms and switching between high-data rate, low probability of detection techniques, and leveraging tunable waveforms for C3 across various scenarios. The integration of Software Defined Network (SDN) protocols facilitates routing the right information to the right users at the optimal speed and quality, aligning with the requirements of diverse warfighting missions. These advancements will leverage commercially available technologies where possible. The NCC works in collaboration with the Joint Staff and Military Services, on new requirements and improved concepts of operations, to advocate for the proper testing, evaluation, verification and validation, and certification of all relevant solutions from DIB partners for the purpose of ensuring enduring interoperability / compatibility, resiliency, and capability advancement for the positive benefit of US DoW warfighters and as well those of Allied Nations. The FY 2026 spend plan amount for Network Communications Capabilities includes $19,658 thousand of discretionary and $65,000 thousand of mandatory for a total of $84,658 thousand. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:         PE 0603662D8Z / Networked Communications Capability Advanced Technology Development (ATD)$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603669D8Z$$, $$Microelectronics Commons - 0400D$$, $$rdte_dw_ba3$$, $$dw_ousd_re$$, 2026, 0, 269504000, 0, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 69, "original_pe": "0603669D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This Program Element supports the Department's initiatives to Build Sustainable and Long-Term Advantage, Defend the Homeland, and Deter Aggression. The Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)) is executing the Microelectronics Commons (the Commons) activity pursuant to the Fiscal Year (FY) 2021 National Defense Authorization Act (NDAA) (Pub. L. 116-283), including the CHIPS for America Act, and funded through the CHIPS for America Defense Fund established by the CHIPS Act of 2022. The FY 2021 NDAA legislation significantly emphasizes solutions that promote the domestic on-shoring of capabilities to address economic and technology security concerns. Under FY 2021 NDAA Sec. 9903(b), the DOD is directed to establish a National Network for Microelectronics Research and Development (NNMRD) to enable the laboratory-to-fabrication transition of microelectronics innovations in the United States and to expand the global leadership in microelectronics of the United States. Specifically, the DOD is addressing a component of the NNMRD, the Commons, through a public- private partnership consisting of regional innovation hubs distributed across the U.S. to foster a pipeline of innovative ideas and talent residing in, for example, university labs and small business R&D teams. Background U.S. technological dominance in microelectronics materials, processes, devices, and architectural designs can only be sustained through the development of a robust domestic innovation ecosystem that fosters the rapid development and transition of novel concepts into commercially viable manufacturing processes. The U.S. innovation ecosystem has long been the driver of our nation’s technology leadership throughout the world. U.S. R&D kick-started the enormous semiconductor industry and continues to lead the world in developing the next generation of disruptive technologies including new materials, devices, circuits, architectures, and design tools. In recent years, the efficient domestic adoption of U.S. chip innovation has been threatened as emerging hardware technologies have become increasingly reliant on offshore sources for State of the Art (SOTA) manufacturing, prototyping, and investment. There are several significant hurdles that hardware startups face, including limited or expensive access to necessary facilities and design infrastructure, high costs of design intellectual property, limited expertise with hardware engineering, and Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                   Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:            PE 0603669D8Z / Microelectronics Commons - 0400D Advanced Technology Development (ATD) high costs of prototyping. As a result, the number of U.S. hardware startups has dropped significantly and foreign investment in U.S.-based technology startups has enabled offshore fabrication and maturation of emerging technologies. To address these needs, OUSD(R&E) is standing up the Commons as a public private partnership, consisting of regional innovation hubs distributed across the U.S. to foster a pipeline of innovative ideas and talent residing in university labs and small business R&D teams. The partnership will provide resources for and access to specialized lab equipment, technical expertise, and connections to existing or upgraded prototyping facilities. Fabrication facilities (fabs) will help mature promising technologies and demonstrate the manufacturing and economic benefits of these innovations for dual-use application for defense and commercial sectors. The Commons will focus on critical, on-shore prototyping to transition innovation from universities, start-ups, and small companies to fabrication facilities (lab-to-fab transition). Key features are: • Creates and connects “Lab-to-Fab” testing/prototyping hubs to form a network focused on maturing emerging microelectronics technologies • Provides broad access to these prototyping hubs, potentially by augmenting facilities and enabling access to facilities within local semiconductor companies or FFRDCs. • Facilitates microelectronics education and training of students at local colleges and universities and grows a talent pipeline to bolster local semiconductor economies and contribute more broadly to the growth of a domestic semiconductor workforce. This program element focuses on the technology development activities of the Commons, including staffing at Commons hub facilities, advanced technology development, and significant prototyping activity. In addition, it provides for the establishment, staffing, and operation of the Microelectronics Commons Consortium Manager (CM), the overall management of the Commons, and will support the required physical, digital, and human infrastructure of the hubs.$$, NULL, NULL, NULL, NULL, NULL, NULL, 61, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 265108000, 0, NULL, NULL, NULL, NULL, NULL, $$This program supports the Department's initiatives to Build Sustainable and Long-Term Advantage, Defend the Homeland, and Deter Aggression. The Office of the Under Secretary of War for Research and Engineering (OUSW(R&E)) is executing the Microelectronics Commons (the Commons) activity pursuant to the Fiscal Year (FY) 2021 National Defense Authorization Act (NDAA) (Pub. L. 116-283), including the CHIPS for America Act, and funded through the CHIPS for America Defense Fund established by the CHIPS Act of 2022. The FY 2021 NDAA legislation significantly emphasizes solutions that promote the domestic on-shoring of capabilities to address economic and technology security concerns. Under FY 2021 NDAA Sec. 9903(b), the DoW is directed to establish a National Network for Microelectronics Research and Development (NNMRD) to enable the laboratory-to-fabrication transition of microelectronics innovations in the United States and to expand the global leadership in microelectronics of the United States. Specifically, the DoW is addressing a component of the NNMRD, the Commons, through a public- private partnership consisting of regional innovation hubs distributed across the U.S. to foster a pipeline of innovative ideas and talent residing in, for example, university labs and small business R&D teams. U.S. technological dominance in microelectronics materials, processes, devices, and architectural designs can only be sustained through the development of a robust domestic innovation ecosystem that fosters the rapid development and transition of novel concepts into commercially viable manufacturing processes. The U.S. innovation ecosystem has long been the driver of our nation’s technology leadership throughout the world. U.S. R&D kick-started the enormous semiconductor industry and continues to lead the world in developing the next generation of disruptive technologies including new materials, devices, circuits, architectures, and design tools. In recent years, the efficient domestic adoption of U.S. chip innovation has been threatened as emerging hardware technologies have become increasingly reliant on offshore sources for State of the Art (SOTA) manufacturing, prototyping, and investment. There are several significant hurdles that hardware startups face, including limited or expensive access to necessary facilities and design infrastructure, high costs of design intellectual property, limited expertise with hardware engineering, and high costs of prototyping. As a result, the number of U.S. hardware startups has dropped significantly and foreign investment in U.S.-based technology startups has enabled offshore fabrication and maturation of emerging technologies. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                  Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:            PE 0603669D8Z / Microelectronics Commons - 0400D Advanced Technology Development (ATD) To address these needs, OUSW(R&E) is standing up the Commons as a public private partnership, consisting of regional innovation hubs distributed across the U.S. to foster a pipeline of innovative ideas and talent residing in university labs and small business R&D teams. The partnership will provide resources for and access to specialized lab equipment, technical expertise, and connections to existing or upgraded prototyping facilities. Fabrication facilities (fabs) will help mature promising technologies and demonstrate the manufacturing and economic benefits of these innovations for dual-use application for defense and commercial sectors. The Commons will focus on critical, on-shore prototyping to transition innovation from universities, start-ups, and small companies to fabrication facilities (lab-to-fab transition). Key features are: • Creates and connects “Lab-to-Fab” testing/prototyping hubs to form a network focused on maturing emerging microelectronics technologies • Provides broad access to these prototyping hubs, potentially by augmenting facilities and enabling access to facilities within local semiconductor companies or FFRDCs. • Facilitates microelectronics education and training of students at local colleges and universities and grows a talent pipeline to bolster local semiconductor economies and contribute more broadly to the growth of a domestic semiconductor workforce. This program element focuses on the technology development activities of the Commons, including staffing at Commons hub facilities, advanced technology development, and significant prototyping activity. In addition, it provides for the establishment, staffing, and operation of the Microelectronics Commons Consortium Manager (CM), the overall management of the Commons, and will support the required physical, digital, and human infrastructure of the hubs.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603673N$$, $$Future Naval Capabilities Advanced Tech Dev$$, $$rdte_navy_ba3$$, $$onr$$, 2026, 455851000, 280682000, 257768000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "navy", "page_num": 27, "original_pe": "0603673N", "page_header": "Department of the Navy"}$$::jsonb, $$The Office of Naval Research (ONR) was established to ensure the technological advantage of U.S. Naval forces. ONR manages the Department of the Navy's science and technology (S&T) research portfolio (Basic, Applied and Advanced Technology Development investments). This work includes the Future Naval Capabilities (FNC) program, which delivers technology solutions to known requirements and accelerates innovative technology insertion into Programs of Record (PORs). In close and structured coordination with POR Stakeholders (Combat Capability Development organizations, Operating Forces, and acquisition organizations), FNC efforts create revolutionary technology for Programs of Record (PORs). ONR's S&T competencies create substantially higher levels of technology, trade space, and capability gain than acquisition can create within POR programmatic risk constraints. FNC projects create exponential technology improvement substantially cheaper than POR vendors do. The structured FNC process and its specific transition mechanisms manage technical risk and increase the likelihood that technologies systematically deploy to warfighters. The FNC efforts described in this Program Element (PE) 0603673N for FNC Advanced Technology Development use earlier research conducted in PE 0602750N for FNC Applied Research and have follow-on transition funding commitments in the receiving acquisition POR PEs. Using a competitive selection process, ONR and POR Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                 Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 3: Advanced            PE 0603673N / Future Naval Capabilities Advanced Tech Dev Technology Development (ATD) Stakeholders assess and select each effort in this PE based on its revolutionary technology payoff to the naval warfighter and prioritized operating force requirements. FNC requests from POR Stakeholders exceed funding available in the FNC Program and drive the competitive selection. The addition of Innovative Naval Prototypes in FY 2026 described in this Program Element (PE) 0603673N for FNC Advanced Technology Development are contained in RDTE Project 2966 S&T Campaigns and contain the Budget Activity 3 portion of the Innovative Naval Prototype (INP Program). These INP efforts, which are developed in coordination with INP Applied Research Investments now funded in PE 0602750N Future Naval Capabi8lities Applied Research, attempt to solve problems and respond to mission requirements, by exploratory research for new ideas and breakthrough capabilities. INPs are Larger in scope, scale and risk than FNCs and are selected for their high-payoff and potential to revolutionize operational concepts. Due to high technical risk, INPs often have long trial-and-error timeframes to work through challenges, but typically no more than three years between decision points. INP BA3 efforts require advanced technology development funding to bridge from Applied Research to working prototypes. INPs prove technological and capability potential, validate production feasibility, and acquisition potential. ONR demonstrates INPs in relevant environments. Successful experimentation and demonstrations present the Department of the Navy with disruptive capabilities that may lead to new acquisition programs. INPs are selected by senior leadership in the Department of the Navy. Due to the classified efforts in this PE, some have incomplete descriptions. ONR can provide additional information in classified documents.$$, NULL, 455258000, 458833000, 451249000, NULL, NULL, 21, $$RDTEN_BA1-3_Book.pdf$$, NULL, FALSE, 250477000, 523426000, 445977000, 445977000, NULL, 445977000, 480741000, $$The Office of Naval Research (ONR) was established to ensure the technological advantage of U.S. Naval forces. ONR manages the Department of the Navy's science and technology (S&T) research portfolio (Basic, Applied and Advanced Technology Development investments). This work includes the Future Naval Capabilities (FNC) program, which delivers technology solutions to known requirements and accelerates innovative technology insertion into Programs of Record (PORs). In close and structured coordination with POR Stakeholders (Combat Capability Development organizations, Operating Forces, and acquisition organizations), FNC efforts create revolutionary technology for Programs of Record (PORs). ONR's S&T competencies create substantially higher levels of technology, trade space, and capability gain than acquisition can create within POR programmatic risk constraints. FNC projects create exponential technology improvement substantially cheaper than POR vendors do. The structured FNC process and its specific transition mechanisms manage technical risk and increase the likelihood that technologies systematically deploy to warfighters. The FNC efforts described in this Program Element (PE) 0603673N for FNC Advanced Technology Development use earlier research conducted in PE 0602750N for FNC Applied Research and have follow-on transition funding commitments in the receiving acquisition POR PEs. Using a competitive selection process, ONR and POR Stakeholders assess and select each effort in this PE based on its revolutionary technology payoff to the naval warfighter and prioritized operating force requirements. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                 Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 3: Advanced          PE 0603673N / Future Naval Capabilities Advanced Tech Dev Technology Development (ATD) Selections may be refined as technologies mature and priorities evolve enabling the program to meet emerging warfighter needs. FNC requests from POR Stakeholders exceed funding available in the FNC Program and drive the competitive selection. The addition of Innovative Naval Prototypes in FY 2026 described in this Program Element (PE) 0603673N for FNC Advanced Technology Development are contained in RDTE Project 2966 S&T Campaigns and contain the Budget Activity 3 portion of the Innovative Naval Prototype (INP Program). These INP efforts, which are developed in coordination with INP Applied Research Investments now funded in PE 0602750N Future Naval Capabi8lities Applied Research, attempt to solve problems and respond to mission requirements, by exploratory research for new ideas and breakthrough capabilities. INPs are Larger in scope, scale and risk than FNCs and are selected for their high-payoff and potential to revolutionize operational concepts. Due to high technical risk, INPs often have long trial-and-error timeframes to work through challenges, but typically no more than three years between decision points. INP BA3 efforts require advanced technology development funding to bridge from Applied Research to working prototypes. INPs prove technological and capability potential, validate production feasibility, and acquisition potential. ONR demonstrates INPs in relevant environments. Selections may be refined as technologies mature and priorities evolve enabling the program to meet emerging warfighter needs. Successful experimentation and demonstrations present the Department of the Navy with disruptive capabilities that may lead to new acquisition programs. INPs are selected by senior leadership in the Department of the Navy. Due to the classified efforts in this PE, some have incomplete descriptions. ONR can provide additional information in classified documents.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA1-3_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603677F$$, $$In-Transit Visibility (ITV) Modernization$$, $$rdte_af_ba4$$, $$aflcmc$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 10000000, 0, 0, 0, 0, 0, $$The mission of In-Transit Visibility (ITV) is to continuously improve and provide accurate, auditable, secure, and resilient end-to-end data for all DoW materiel moving through the Defense Transportation System (DTS). Modernizing ITV will significantly improve the ability of Combatant Commands (CCMDs) to forecast the arrival of materiel in their Area of Responsibility (AOR), leading to more accurate timelines for power projection planning. Enhanced visibility also supports dynamic optimization of routing, improved shipment security, informed stock posturing, and other advanced supply chain analytic capabilities. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L051$$, $$Adv Tact Data Link Sys (ATDLS)$$, $$proc_navy_1810_ba2$$, $$peo_iws$$, 2026, 379908000, 367452000, 362099000, NULL, $${"page": 97, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "51", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 47", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 701667, "p1_line_num": 47, "fy27_total_K": 701667}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 379908, "li_num": 47, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA2_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 379908000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 68458000, 58739000, 701667000, 701667000, 0, 701667000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_3022_L008$$, $$FABT FORCE ELEMENT TERMINAL$$, $$proc_sf_3022_ba1$$, $$sf$$, 2026, 0, 103184000, 210155000, NULL, $${"page": 146, "ba_num": "01", "source": "p1_fy26", "ba_name": "SPACE PROCUREMENT, SF", "line_no": "8", "service": "af", "fy24_qty": null, "fy25_qty": null, "appr_code": "3022", "appr_name": "Procurement, Space Force", "fy26_v180": {"ba": "01", "disc_K": 0, "li_num": 7, "source": "p40_fy26_v180", "supp_K": 0, "source_pdf": "FY27 Air Force Space Procurement"}, "fy26t_qty": null, "fy26d_cost": 0, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, 206702000, NULL, NULL, NULL, FALSE, 206702000, 0, 139700000, 139700000, 0, 139700000, NULL, NULL, $$Budget J-Books/FY27/Air Force/FY27 Air Force Space Procurement.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603680D8Z$$, $$Defense Wide Manufacturing Science and Technology Program$$, $$rdte_dw_ba3$$, $$dw_osd$$, 2026, 409493000, 457472000, 205857000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 69, "original_pe": "0603680D8Z", "page_header": "Defense-Wide", "fy26_v182_disc_K": 555108, "fy26_v182_supp_K": 1493556, "fy26_v182_total_K": 2048664, "fy26_v182_note_name": "Research, Development, Test & Evaluation, Defense-Wide for Defense-Wide Manufacturing Science & Technology", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 13089}$$::jsonb, $$This program supports the Department's initiatives to Build Sustainable and Long-Term Advantage and Build a Resilient Joint Force Defense Ecosystem. The Defense-wide Manufacturing Science and Technology (DMS&T) program is the joint, defense-wide component of the Department of Defense (DoD) Manufacturing Technology (ManTech) Program directed in Title 10 U.S.C. Section 2521. DMS&T addresses joint, cross-cutting, and high-risk/high payoff technologies; manufacturing challenges within the DoD critical technology areas; and many of the recommendations in the Executive Order Report “Assessing and Strengthening the Manufacturing and Defense Industrial Base and Supply Chain Resiliency of the United States” September 2018. The DMS&T program objective is to increase the speed at which innovation, inventions, and scientific discoveries are turned into equipment and capabilities through advances in manufacturing technologies and processes. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                           Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:        PE 0603680D8Z / Defense Wide Manufacturing Science and Technology Program Advanced Technology Development (ATD)$$, NULL, 365079000, 308823000, 270548000, NULL, NULL, 62, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 198845000, 2048664000, 581847000, 581847000, NULL, 581847000, 239694000, $$This program supports the Department's initiatives to Build Sustainable and Long-Term Advantage and Build a Resilient Joint Force Defense Ecosystem. The Defense-wide Manufacturing Science and Technology (DMS&T) program is the joint, defense-wide component of the Department of War (DoW) Manufacturing Technology (ManTech) Program directed in Title 10 U.S.C. Section 2521. DMS&T addresses joint, cross-cutting, and high-risk/high payoff technologies; manufacturing challenges within the DoW critical technology areas; and many of the recommendations in the Executive Order Report “Assessing and Strengthening the Manufacturing and Defense Industrial Base and Supply Chain Resiliency of the United States” September 2018. The DMS&T program objective is to increase the speed at which innovation, inventions, and scientific discoveries are turned into equipment and capabilities through advances in manufacturing technologies and processes. The FY 2026 spend plan amount for Research, Development, Test & Evaluation, Defense-Wide for Defense-Wide Manufacturing Science & Technology includes $555,108 thousand of discretionary and $1,493,556 thousand of mandatory for a total of $2,048,664 thousand. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                              Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:            PE 0603680D8Z / Defense Wide Manufacturing Science and Technology Program Advanced Technology Development (ATD)$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603680F$$, $$Manufacturing Technology Program$$, $$rdte_af_ba3$$, $$afrl_rx$$, 2026, 38891000, 165721000, 116130000, NULL, $${"ba_raw": "6.3", "source": "af_r1_fy26", "original_pe": "0603680F"}$$::jsonb, $$The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This program executes technical efforts to develop and maintain an affordable and reliable industrial base and manufacturing capability responsive to Department of the Air Force warfighter needs. The program develops and improves manufacturing technologies and processes to reduce transition risk, enable cost reduction, improve component and system quality, increase readiness and affordable mission availability, enhance industrial capability, and promote transformation through the industrial base. Value stream modifications and manufacturing throughput improvements are implemented to shorten weapon system cycle times during design, development, production, and sustainment. Cost savings are realized through early engagement with stakeholders to promote producible designs, ensuring the industrial base will be ready to manufacture at the needed quantities. Manufacturing technologies objectives are conducted through industrial partnerships that enable targeted investment of manufacturing technologies and reduce risk in the industrial supply chain for existing weapon system upgrades and new warfighter systems. Efforts in the program have been coordinated through the Department of Defense Science and Technology Executive Committee process to harmonize efforts and eliminate duplication. Funds in this PE may be used to investigate specified technology advancements in air, space and/or cyber domains. This program includes funding for the requisite DAF Science & Engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The use of program funds in this program element is in conjunction with the civilian pay expenses budgeted in the following program elements: 1206601SF, 0601102F, 0602020F, 0602102F, 0602202F, 0602203F, 0602204F, 0602298F, 0602336F, 0602602F, 0602605F, and 0602788F. In FY 2026, $8.996 million is budgeted in this program for 45 direct Full-Time Equivalent (FTE) civilians. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology capabilities. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603680F / Manufacturing Technology Program Technology Development (ATD) This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment.$$, NULL, 97704000, 109497000, 112910000, NULL, NULL, 28, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 118087000, 342507000, 99908000, 99908000, 0, 99908000, 101753000, $$This program executes technical efforts to develop and maintain an affordable and reliable industrial base and manufacturing capability responsive to Department of the Air Force warfighter needs. The program develops and improves manufacturing technologies and processes to reduce transition risk, enable cost reduction, improve component and system quality, increase readiness and affordable mission availability, enhance industrial capability, and promote transformation through the industrial base. Value stream modifications and manufacturing throughput improvements are implemented to shorten weapon system cycle times during design, development, production, and sustainment. Cost savings are realized through early engagement with stakeholders to promote producible designs, ensuring the industrial base will be ready to manufacture at the needed quantities. Manufacturing technologies objectives are conducted through industrial partnerships that enable targeted investment of manufacturing technologies and reduce risk in the industrial supply chain for existing weapon system upgrades and new warfighter systems. This program is accomplished by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. Funds in this PE may be used to investigate specified technology advancements in air, space, and/or cyber domains. This program includes funding for the requisite DAF Science & Engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The use of program funds in this program element is in conjunction with the civilian pay expenses budgeted in the following program elements: 1206601SF, 1206616SF, 0601102F, 0602020F, 0602102F, 0602202F, 0602203F, 0602204F, 0602298F, 0602336F, 0602602F, 0602605F, and 0602788F. In FY 2027, $8.114 million is budgeted in this program for 41 direct Full-Time Equivalent (FTE) civilians. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology capabilities. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                    Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603680F / Manufacturing Technology Program Technology Development (ATD) Manufacturing Technologies received a Congressional add for FY2026 $12.500 million for Program increase - prosecuting of advance adversary commercial communications - mobile. Upon Congressional spend plan approval, an Internal Reprogramming (IR) will be processed aligning the funding to PE0603788F for proper execution. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603680N$$, $$Manufacturing Technology Program$$, $$rdte_navy_ba3$$, $$onr$$, 2026, 63903000, 81226000, 63084000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "navy", "page_num": 27, "original_pe": "0603680N", "page_header": "Department of the Navy"}$$::jsonb, $$The Office of Naval Research's (ONR) mission is to foster scientific research for the advancement of naval power. This work does not stop at the laboratory. Delivery of breakthrough capability often requires new technologies in manufacturing and supply chains of national security. The Manufacturing Technology (ManTech) Program is intended to improve the productivity and responsiveness of the U.S. defense industrial base by funding the development, optimization, and transition of enabling manufacturing technologies to key naval suppliers. In general, investments transition emerging Science and Technology (S&T) results to acquisition programs; improve industrial capabilities in production, maintenance, repair and industrial base responsiveness; and advance manufacturing technology to reduce cost, improve performance, and responsiveness. Currently, the ManTech Program is focused on affordability improvements for specific key acquisition platforms as defined in the Navy ManTech Investment Strategy. Key platforms currently targeted include: VIRGINIA Class Submarine (VCS)/COLUMBIA Class submarine (CLB); DDG 51 Class destroyer; CVN 78 Class carrier; FFG 62 Class frigate, and F-35 Lightning II aircraft. PEO IWS was added to the Investment Strategy as a number of their integrated warfare systems are critical to the NAVSEA acquisition platforms currently supported. Office of Naval Research (ONR) ManTech helps these Navy programs achieve their respective affordability goals by transitioning developed manufacturing technology which, when implemented, results in needed cost reduction or cost avoidance. In addition to addressing affordability for key naval platforms, ManTech also addresses manufacturing technology to aid in capability acceleration to the fleet. Today's Sailors and Marines are enabled by naval Science and Technology (S&T). Since 1946, the Office of Naval Research (ONR) has fostered scientific research related to the maintenance of maritime superiority and national defense. ONR manages the Department of the Navy's (DON) portfolio of naval Basic and Applied research, and Advanced Technology Development investments to ensure naval forces can effectively deter conflict, but when called upon, fight, win and come home safe. Current investments hedge against uncertainty, providing solutions to commanders today, and options for the future. The Naval S&T budget supports higher guidance defined by the National Defense Strategy, and responds to requirements identified by the Secretary of the Navy through research priorities set by the Chief of Naval Research, coordinated across the Naval Research Enterprise (NRE), and outlined in the Naval R&D Framework. This Program Element (PE) funds Advanced Technology Development (ATD) that includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Efforts in this PE generally have Technology Readiness Levels TRL) of 4 (component and/or breadboard validation in laboratory environment.), 5 (component and/or breadboard validation in relevant environment.), or 6 (system/subsystem model or prototype demonstration in a relevant environment). Due to the number of efforts in this Program Element (PE), the programs described herein are representative of the work included in this PE. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                            Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 3: Advanced         PE 0603680N / Manufacturing Technology Program Technology Development (ATD)$$, NULL, 83925000, 63638000, 64883000, NULL, NULL, 22, $$RDTEN_BA1-3_Book.pdf$$, NULL, FALSE, 61192000, 78065000, 79132000, 79132000, NULL, 79132000, 65970000, $$The Office of Naval Research's (ONR) mission is to foster scientific research for the advancement of naval power. This work does not stop at the laboratory. Delivery of breakthrough capability often requires new technologies in manufacturing and supply chains of national security. The Manufacturing Technology (ManTech) Program is intended to improve the productivity and responsiveness of the U.S. defense industrial base by funding the development, optimization, and transition of enabling manufacturing technologies to key naval suppliers. In general, investments transition emerging Science and Technology (S&T) results to acquisition programs; improve industrial capabilities in production, maintenance, repair and industrial base responsiveness; and advance manufacturing technology to reduce cost, improve performance, and responsiveness. Currently, the ManTech Program is focused on affordability improvements for specific key acquisition platforms as defined in the Navy ManTech Investment Strategy. Key platforms currently targeted include: VIRGINIA Class Submarine (VCS)/COLUMBIA Class submarine (CLB); DDG 51 Class destroyer; CVN 78 Class carrier; FFG 62 Class frigate, and F-35 Lightning II aircraft. PEO IWS was added to the Investment Strategy as a number of their integrated warfare systems are critical to the NAVSEA acquisition platforms currently supported. Office of Naval Research (ONR) ManTech helps these Navy programs achieve their respective affordability goals by transitioning developed manufacturing technology which, when implemented, results in needed cost reduction or cost avoidance. In addition to addressing affordability for key naval platforms, ManTech also addresses manufacturing technology to aid in capability acceleration to the fleet. Today's Sailors and Marines are enabled by naval Science and Technology (S&T). Since 1946, the Office of Naval Research (ONR) has fostered scientific research related to the maintenance of maritime superiority and national defense. ONR manages the Department of the Navy's (DON) portfolio of naval Basic and Applied research, and Advanced Technology Development investments to ensure naval forces can effectively deter conflict, but when called upon, fight, win and come home safe. Current investments hedge against uncertainty, providing solutions to commanders today, and options for the future. The Naval S&T budget supports higher guidance defined by the National Defense Strategy, and responds to requirements identified by the Secretary of the Navy through research priorities set by the Chief of Naval Research and outlined in the Naval R&D Framework. This Program Element (PE) funds Advanced Technology Development (ATD) that includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Efforts in this PE generally have Technology Readiness Levels TRL) of 4 (component and/or breadboard validation in laboratory environment.), 5 (component and/or breadboard validation in relevant environment.), or 6 (system/subsystem model or prototype demonstration in a relevant environment). Due to the number of efforts in this Program Element (PE), the programs described herein are representative of the work included in this PE. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                           Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 3: Advanced        PE 0603680N / Manufacturing Technology Program Technology Development (ATD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA1-3_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603713N$$, $$Ocean Engineering Tech Dev$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 9647000, 10612000, 15587000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 29, "original_pe": "0603713N", "page_header": "Department of the Navy"}$$::jsonb, $$Developments in this program will enable the U.S. Navy to overcome deficiencies that constrain manned diving operations in several critical areas such as submarine rescue, recovery, salvage, underwater ship husbandry, underwater construction and naval special operations. This program develops biomedical technology, diver life support equipment, and the systems, tools, and procedures to permit manned underwater operations and enhance diver performance and safety.$$, NULL, 9644000, 9103000, 8425000, NULL, NULL, 60, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 15430000, 9647000, 15903000, 15903000, NULL, 15903000, 8575000, $$Developments in this program will enable the U.S. Navy to overcome deficiencies that constrain manned diving operations in several critical areas such as submarine rescue, recovery, salvage, underwater ship husbandry, underwater construction and naval special operations. This program develops biomedical technology, diver life support equipment, and the systems, tools, and procedures to permit manned underwater operations and enhance diver performance and safety.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603716D8Z$$, $$Strategic Environmental Research and Development Program (SERD$$, $$rdte_dw_ba3$$, $$dw$$, 2026, 58092000, 58728000, 58838000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 69, "original_pe": "0603716D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$The Strategic Environmental Research and Development Program (SERDP) invests in applied research to secure Department of Defense installations, while its sister program, the Environmental Security Technology Certification Program (ESTCP), demonstrates and validates these technologies in operational settings. SERDP tackles key challenges facing military bases and training areas, creating innovative approaches that strengthen mission capabilities where they're needed most across more than 800 DoD locations worldwide. The program focuses on cross-Service requirements and pursues solutions to the Department's most pressing installation challenges. SERDP issues solicitations for proposals from government, academia, and industry and employs a competitive selection process to ensure the highest quality research. Through these partnerships, SERDP identifies promising technologies that transition to ESTCP for field demonstration. This coordination helps reduce duplicative efforts and maximizes research impact. Established by Congress in 1990, SERDP serves as a catalyst for cooperation and collaboration across the Armed Services. The development and application of innovative technologies reduces the costs, risks, and time required to resolve installation challenges while advancing military readiness. These investments ensure military installations can withstand operational threats and environmental hazards both inside and outside the fence line, providing a distinct advantage to our warfighters while ensuring military forces remain combat-ready to deter adversaries and defend the nation. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                              Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:          PE 0603716D8Z / Strategic Environmental Research and Development Program (SERD Advanced Technology Development (ATD)                                         P)$$, NULL, 63251000, 57618000, 56773000, NULL, NULL, 65, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 57478000, 57575000, 60774000, 60774000, NULL, 60774000, 57909000, $$The Strategic Environmental Research and Development Program (SERDP) invests in applied research to secure Department of War (DoW) installations, while its companion program, the Environmental Security Technology Certification Program (ESTCP), demonstrates and validates these technologies in operational settings. SERDP tackles key challenges facing military installations, creating innovative approaches that strengthen mission capabilities where they're needed most across more than 800 DoW locations worldwide. The program focuses on cross-Service requirements and pursues solutions to the Department's most pressing installation challenges. To meet these challenges, SERDP develops innovative, scalable technologies that enhance military readiness, improve warfighter capabilities, and strengthen defense infrastructure, prioritizing common-sense, cost-effective solutions that support operational effectiveness at military installations. SERDP issues solicitations for proposals from government, academia, and industry and employs a competitive selection process to ensure the highest quality research. Through these partnerships, SERDP identifies promising technologies that transition to ESTCP for operational demonstration. This coordination helps reduce duplicative efforts and maximizes research impact. Established by Congress in 1990, SERDP serves as a catalyst for cooperation and collaboration across the Armed Services. The development and application of innovative technologies reduces the costs, risks, and time required to resolve installation challenges while advancing military readiness. These investments ensure military installations can withstand operational threats and environmental hazards both inside and outside the fence line, providing a distinct advantage to our warfighters while ensuring military forces remain combat-ready to deter adversaries and defend the nation. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                    Date: April 2026 Appropriation/Budget Activity                                             R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:      PE 0603716D8Z / Strategic Environmental Research and Development Program (SERD Advanced Technology Development (ATD)                                     P)$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603724N$$, $$Navy Energy Program$$, $$rdte_navy_ba4$$, $$navy_n9$$, 2026, 46577000, 108223000, 65610000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 29, "original_pe": "0603724N", "page_header": "Department of the Navy", "fy26_v182_disc_K": 58162, "fy26_v182_supp_K": 98372, "fy26_v182_total_K": 156534, "fy26_v182_note_name": "Research, Development, Test and Evaluation, Navy", "fy26_v182_source_file": "RDTEN_BA4_Book.txt", "fy26_v182_source_line": 33514}$$::jsonb, $$This program supports projects to evaluate, adapt, and demonstrate energy related technologies for Navy aircraft and ship operations to: (a) increase fuel-related weapons systems capabilities such as range and time on station; (b) reduce energy costs; (c) apply energy technologies that improve environmental compliance; (d) examine restrictive fuel specification requirements to reduce cost and increase availability worldwide; (e) provide guidance to fleet operators for the safe use of commercial grade or off-specification fuels; and (f) make needed periodic changes to fuel specifications to ensure fuel quality and avoid fleet operating problems. This program supports the achievement of legislated, White House, Department of Defense, and Navy energy management goals. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under ADVANCED COMPONENT DEVELOPMENT AND PROTOTYPES because it includes all efforts necessary to evaluate integrated technologies, representative models or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                            Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced        PE 0603724N / Navy Energy Program Component Development & Prototypes (ACD&P)$$, NULL, 69723000, 68158000, 62278000, NULL, NULL, 62, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 80698000, 156534000, 59591000, 59591000, NULL, 59591000, 59631000, $$This program supports projects to evaluate, adapt, and demonstrate energy related technologies for Navy aircraft and ship operations to: (a) increase fuel-related weapons systems capabilities such as range and time on station; (b) reduce energy costs; (c) apply energy technologies that improve environmental compliance; (d) examine restrictive fuel specification requirements to reduce cost and increase availability worldwide; (e) provide guidance to fleet operators for the safe use of commercial grade or off-specification fuels; and (f) make needed periodic changes to fuel specifications to ensure fuel quality and avoid fleet operating problems. This program supports the achievement of legislated, White House, Department of War, and Navy energy management goals. The FY 2026 spend plan amount for Research, Development, Test and Evaluation, Navy includes $58,162 thousand of discretionary and $98,372 thousand of mandatory (reconciliation) for a total of $156,534. Reconciliation funding will be used to modernize shore power infrastructure and establish shore energy technology office to coordinate congressionally appropriated pilot programs for small modular reactor demonstrations and strategic naval installations. Reconciliation funding also supports mission to increase the safety and speed of capability deployment by establishing common standards, streamlining safety certification. Funds will be used to enhance lethality, resilience, reach, and sustainment of warfare systems through more effective generation, use and distribution of energy on existing and future surface fleet assets, including Unmanned Surface Vessels (USVs), by developing and transitioning energy and maintenance improvements. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under ADVANCED COMPONENT DEVELOPMENT AND PROTOTYPES because it includes all efforts necessary to evaluate integrated technologies, representative models or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced        PE 0603724N / Navy Energy Program Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603727D8Z$$, $$Joint Warfighting Program (JWP)$$, $$rdte_dw_ba3$$, $$dw_osd$$, 2026, 945000, 2648000, 2684000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 69, "original_pe": "0603727D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$The Joint Warfighting Program (JWP) supports the Assistant Secretary of Defense for Acquisition (ASD(A))'s responsibilities for acquisition and portfolio management. The JWP underwrites analyses, studies, performs limited scope experiments, wargaming, and partnerships that define joint capability gaps and develops credible requirements for follow-on acquisition efforts. These analyses and assessments deliver independent perspectives on potential remedies to align acquisition investments and solutions for joint capability gaps created by future warfighting environments and emerging threats. The JWP supports mission engineering integration management, as well as other high priority emerging issues requiring independent analysis to inform acquisition decisions that impact National Security.$$, NULL, 214000, 155000, NULL, NULL, NULL, 67, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 2586000, 932000, NULL, NULL, NULL, NULL, NULL, $$The Joint Warfighting Program (JWP) supports the Assistant Secretary of War for Acquisition (ASW(A))'s responsibilities for acquisition and portfolio management. The JWP underwrites analyses, studies, performs limited scope experiments, wargaming, and partnerships that define joint capability gaps and develops credible requirements for follow-on acquisition efforts. These analyses and assessments deliver independent perspectives on potential remedies to align acquisition investments and solutions for joint capability gaps created by future warfighting environments and emerging threats. The JWP supports mission engineering integration management, as well as other high priority emerging issues requiring independent analysis to inform acquisition decisions that impact National Security.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603729N$$, $$Warfighter Protection Adv Tech$$, $$rdte_navy_ba3$$, $$onr$$, 2026, 7653000, 35356000, 7605000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "navy", "page_num": 27, "original_pe": "0603729N", "page_header": "Department of the Navy"}$$::jsonb, $$This PE supports the advanced development and demonstration of technologies to improve warfighter performance, safety and survivability. Naval investment in these areas is essential in order to improve the ability to enhance, maintain, and sustain Warfighter effectiveness. Today's Sailors and Marines are enabled by Naval Science and Technology (S&T). Since 1946, the Office of Naval Research (ONR) has fostered scientific research related to the maintenance of maritime superiority and national defense. ONR manages the Department of the Navy's (DON) portfolio of Naval basic and applied research, and advanced technology development investments to ensure Naval forces can effectively deter conflict, but when called upon, fight, win and come home safe. Current investments hedge against uncertainty, providing solutions to commanders today, and options for the future. The Naval S&T budget supports higher guidance defined by the National Defense Strategy, and responds to requirements identified by the Secretary of the Navy through research priorities set by the Chief of Naval Research, coordinated across the Naval Research Enterprise (NRE), and outlined in the Naval R&D Framework. This Program Element (PE) funds Advanced Technology Development (ATD) that includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Efforts in this PE generally have Technology Readiness Levels (TRL) of 4 (component and/or breadboard validation in laboratory environment.), 5 (component and/or breadboard validation in relevant environment.), or 6 (system/subsystem model or prototype demonstration in a relevant environment). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 3: Advanced           PE 0603729N / Warfighter Protection Adv Tech Technology Development (ATD)$$, NULL, 0, 0, 0, NULL, NULL, 23, $$RDTEN_BA1-3_Book.pdf$$, NULL, FALSE, 7518000, 31787000, 0, 0, NULL, 0, 0, $$This PE supports the advanced development and demonstration of technologies to improve warfighter performance, safety and survivability. Naval investment in these areas is essential in order to improve the ability to enhance, maintain, and sustain Warfighter effectiveness. Today's Sailors and Marines are enabled by Naval Science and Technology (S&T). Since 1946, the Office of Naval Research (ONR) has fostered scientific research related to the maintenance of maritime superiority and national defense. ONR manages the Department of the Navy's (DON) portfolio of Naval basic and applied research, and advanced technology development investments to ensure Naval forces can effectively deter conflict, but when called upon, fight, win and come home safe. Current investments hedge against uncertainty, providing solutions to commanders today, and options for the future. The Naval S&T budget supports higher guidance defined by the National Defense Strategy, and responds to requirements identified by the Secretary of the Navy through research priorities set by the Chief of Naval Research, coordinated across the Naval Research Enterprise (NRE), and outlined in the Naval R&D Framework. This Program Element (PE) funds Advanced Technology Development (ATD) that includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Efforts in this PE generally have Technology Readiness Levels (TRL) of 4 (component and/or breadboard validation in laboratory environment.), 5 (component and/or breadboard validation in relevant environment.), or 6 (system/subsystem model or prototype demonstration in a relevant environment). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                           Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 3: Advanced        PE 0603729N / Warfighter Protection Adv Tech Technology Development (ATD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA1-3_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603734N$$, $$CHALK CORAL$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 414282000, 573548000, 873119000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 29, "original_pe": "0603734N", "page_header": "Department of the Navy"}$$::jsonb, $$The details of this budget justification are classified, per Executive Order 13526, Sec 1.4 (a) and are submitted annually to Congress in the classified budget justification book.$$, NULL, NULL, NULL, NULL, NULL, NULL, 63, $$Budget J-Books/FY27/Remaining/FY2027_r1.pdf$$, NULL, FALSE, 829575000, 776792000, 995658000, 995658000, 0, 995658000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603739E$$, $$ADVANCED ELECTRONICS TECHNOLOGIES$$, $$rdte_dw_ba3$$, $$dw_darpa$$, 2026, 0, 242625000, 157844000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 69, "original_pe": "0603739E", "page_header": "Defense-Wide"}$$::jsonb, $$The efforts described in this Program Element (PE) address the Advanced Technology Development associated with the Advanced Electronics Technologies Program that seeks to design and demonstrate state-of-the-art manufacturing and processing technologies for the production of various electronics and microelectronic devices, sensor systems, integrated photonic-electronic components that have military applications and potential commercial utility. Introduction of advanced product design capability and flexible, scalable manufacturing techniques will enable the commercial sector to rapidly and cost-effectively satisfy military requirements. The Mixed Technology Integration project funds the advanced development and demonstration of selected basic and applied electronics research programs. Examples of technologies with funded development and demonstration activities include, but are not limited to: reducing the size, weight, and power (SWaP) of components for laser weapon systems that will protect airborne platforms from emerging surface-to-air missiles; integrated photonic-electronic components for positioning, navigation and timing in GPS-denied environments; flexible, software-defined cameras that enable real-time image analysis of complex scenes to provide more actionable information; and optical communications systems that rely on no moving parts enabling their use on SWaP-restricted platforms. Funding under this project is intended to advance transitioning novel technologies to use, providing advanced components compatible with mid-term and other future warfighting requirements. The Beyond Scaling Advanced Technologies Project supports activities to enable and accelerate the transition of disruptive microelectronics advancement, including those developed under the Beyond Scaling Sciences (ES-02) and Beyond Scaling Technology (ELT-02) projects. Funding under this project will include developing new technologies and capabilities in commercial settings, establishing access to these new processes and to commercial state-of-the-art foundries, enabling prototyping, developing manufacturable processes for three-dimensional heterogeneous integration (including integrated photonics), advancing new architectures and integration technologies for advanced field programmable gate arrays (FPGAs), and innovating back end of line technologies for wide bandgap semiconductors. Beginning in FY 2026, efforts in this PE will be funded in PE 0603469E, Advanced Enabling Technologies. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                   Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:         PE 0603739E / ADVANCED ELECTRONICS TECHNOLOGIES Advanced Technology Development (ATD)$$, NULL, 0, 0, 0, NULL, NULL, 68, $$RDTE_Vol1_DARPA_MasterJustificationBook_PB_2026.pdf$$, $$DARPA$$, FALSE, 148382000, 0, 0, 0, NULL, 0, 0, $$The efforts described in this Program Element (PE) address the Advanced Technology Development associated with the Advanced Electronics Technologies Program that seeks to design and demonstrate state-of-the-art manufacturing and processing technologies for the production of various electronics and microelectronic devices, sensor systems, integrated photonic-electronic components that have military applications and potential commercial utility. Introduction of advanced product design capability and flexible, scalable manufacturing techniques will enable the commercial sector to rapidly and cost-effectively satisfy military requirements. The Mixed Technology Integration project funds the advanced development and demonstration of selected basic and applied electronics research programs. Examples of technologies with funded development and demonstration activities include, but are not limited to: reducing the size, weight, and power (SWaP) of components for laser weapon systems that will protect airborne platforms from emerging surface-to-air missiles; integrated photonic-electronic components for positioning, navigation and timing in GPS-denied environments; flexible, software-defined cameras that enable real-time image analysis of complex scenes to provide more actionable information; and optical communications systems that rely on no moving parts enabling their use on SWaP-restricted platforms. Funding under this project is intended to advance transitioning novel technologies to use, providing advanced components compatible with mid-term and other future warfighting requirements. The Beyond Scaling Advanced Technologies Project supports activities to enable and accelerate the transition of disruptive microelectronics advancement, including those developed under the Beyond Scaling Sciences (ES-02) and Beyond Scaling Technology (ELT-02) projects. Funding under this project will include developing new technologies and capabilities in commercial settings, establishing access to these new processes and to commercial state-of-the-art foundries, enabling prototyping, developing manufacturable processes for three-dimensional heterogeneous integration (including integrated photonics), advancing new architectures and integration technologies for advanced field programmable gate arrays (FPGAs), and innovating back end of line technologies for wide bandgap semiconductors. Beginning in FY 2026, efforts in this PE will be funded in PE 0603469E, Advanced Enabling Technologies. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Advanced Research Projects Agency                                   Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:        PE 0603739E / ADVANCED ELECTRONICS TECHNOLOGIES Advanced Technology Development (ATD)$$, $$Budget J-Books/FY27/DW/RDTE_Vol1_DARPA_MasterJustificationBook_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603742F$$, $$Combat Identification Technology$$, $$rdte_af_ba4$$, $$dw_mda$$, 2026, 25172000, 15922000, 16790000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0603742F"}$$::jsonb, $$Combat Identification (CID) is the process of characterizing threat and non-threat entities in the battlespace. First and foremost, CID is a critical link in the kill chain; positive ID is a required step in every target engagement, whether short range (visual CID) to very long-range (long-range CID provided by off-board sensors, on-board sensors, or a combination of both). CID capability also provides battlespace commanders and aircrew with other options: threat avoidance, monitoring, hand-off to another C2 node or shooter, etc. The Combat Identification program's mission is to advance CID technologies across the Air Force battlespace by identifying new and maturing technologies, evaluating their application/usefulness, conducting operationally relevant demonstrations, and coordinating strategies that expedite transition aligned to Air Force priority mission threads. Activities also include advanced development, studies, and analysis to support current program planning/execution and future program planning. CID products generated in this PE are proliferated to the multiple services (Army, Air Force, Navy, MDA) where services/platforms rely on these technologies to maintain military superiority with state-of-the-art capabilities. This program element focuses on the development, integration and transitioning of new capabilities into fielded aircraft (tactical and strategic), unmanned platforms, weapons, and any system that enables Air Force CID in a battlespace. The objective consists of advancing capability in three areas: Non-cooperative CID, Cooperative CID, and CID database development. This program element is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Non-cooperative CID technologies (algorithms, software application, hardware application) are the predominate means for advancing CID in denied environments and do not depend on a response from the targeted platform. These technologies make up the majority of this PE's products. Cooperative CID technologies assessed under this program element include preliminary studies of next generation systems that could be employed between two non- threat, participating platforms. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0603742F / Combat Identification Technology Component Development & Prototypes (ACD&P) CID database initiates development (for new technologies) or continues advancement of existing databases with new (or upgraded) target representations. CID databases are used by all combat and ISR platforms to enable CID technologies to perform correctly. This program element may include necessary civilian pay expenses required to manage, execute, and deliver CID capability. The use of program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. "In FY 2025 $0.0 million was expended for civilian pay expenses in this program element, and in FY 2026 $0.0 million is forecast for civilian pay expenses in this program element.” This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 25823000, 26319000, 26823000, NULL, NULL, 33, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 16790000, 24860000, 25888000, 25888000, 0, 25888000, 27367000, $$Combat Identification (CID) is the process of characterizing threat and non-threat entities in the battlespace. First and foremost, CID is a critical link in the kill chain; positive ID is a required step in every target engagement, whether short range (visual CID) to very long-range (long-range CID provided by off-board sensors, on-board sensors, or a combination of both). CID capability also provides battlespace commanders and aircrew with other options: threat avoidance, monitoring, hand-off to another C2 node or shooter, etc. The Combat Identification program's mission is to advance CID technologies across the Air Force battlespace by identifying new and maturing technologies, evaluating their application/usefulness, conducting operationally relevant demonstrations, and coordinating strategies that expedite transition aligned to Air Force priority mission threads. Activities also include advanced development, studies, and analysis to support current program planning/execution and future program planning. CID products generated in this Program are proliferated to the multiple services (Army, Air Force, Navy, MDA) where services/platforms rely on these technologies to maintain military superiority with state-of-the-art capabilities. This program focuses on the development, integration and transitioning of new capabilities into fielded aircraft (tactical and strategic), unmanned platforms, weapons, and any system that enables Air Force CID in a battlespace. The objective consists of advancing capability in three areas: Non-cooperative CID, Cooperative CID, and CID database development. This program is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Non-cooperative CID technologies (algorithms, software application, hardware application) are the predominate means for advancing CID in denied environments and do not depend on a response from the targeted platform. These technologies make up the majority of this PE's products. Cooperative CID technologies assessed under this program element include preliminary studies of next generation systems that could be employed between two non- threat, participating platforms. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0603742F / Combat Identification Technology Component Development & Prototypes (ACD&P) CID database initiates development (for new technologies) or continues advancement of existing databases with new (or upgraded) target representations. CID databases are used by all combat and ISR platforms to enable CID technologies to perform correctly. To manage, execute, and deliver combat identification capabilities, this program element may receive additional approval from customer (Air Combat Command - ACC) to cover expenses covering: civilian pay, facility operation/maintenance, travel, supplies, IT hardware, IT software and support, administrative contractor services. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
