INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603758N$$, $$Navy Warfighting Exp & Demo$$, $$rdte_navy_ba3$$, $$onr$$, 2026, 81923000, 103722000, 139915000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "navy", "page_num": 27, "original_pe": "0603758N", "page_header": "Department of the Navy"}$$::jsonb, $$The Office of Naval Research (ONR) guides ongoing research and innovation operations in the pursuit of novel and decisive capabilities for our Sailors and Marines. ONR manages a broad, but priority-driven investment portfolio of near to long-term basic and applied research. This Program Element (PE) develops Science and Technology (S&T) breakthroughs to meet current operational needs, from prototyping solutions for warfighters, to Fleet experimentation and operational demonstrations including Fleet Battle Problems (FBP), Limited Objective Experiments (LOEs) and Fleet/Force exercises. The key aspects of this PE are divided into six areas supporting the continuum of S&T and innovation operations from discovery to delivery: (1) Naval Warfare Prototype and Demonstration develops rapid prototypes and through innovation operations, provides them to the warfighter for experimentation during operational demonstrations and exercises; (2) Operations Analysis provides the Navy and Marine Corps the means to identify capability needs that can be addressed with science and technology solutions and inform future investment; (3) NavalX applies innovation operations to develop, demonstrate, and transition newly invented or recently discovered technologies that address emergent and enduring operational problems in an accelerated timeframe; (4) Tech Solutions to include Tech Bridge industry scanning allows the ability to rapidly prototype science and technology solutions that address Fleet/Force needs submitted by Sailors and Marines within the development environment and at the deck plate level; (5) support for the Naval Precision Strike Operations, providing the Navy capability to quickly locate, target, and strike critical targets; and (6) Undersea Systems Payloads and Weapons, addressing innovative affordable, persistent, and stealthy undersea system. Today's Sailors and Marines are enabled by naval Science and Technology (S&T). Since 1946, the Office of Naval Research (ONR) has fostered scientific research related to the maintenance of maritime superiority and national defense. ONR manages the Department of the Navy's (DON) portfolio of naval Basic and Applied research, and Advanced Technology Development investments to ensure naval forces can effectively deter conflict, but when called upon, fight, win and come home safe. Current investments hedge against uncertainty, providing solutions to commanders today, and options for the future. The Naval S&T budget supports higher guidance defined by the National Defense Strategy, and responds to requirements identified by the Secretary of the Navy through research priorities set by the Chief of Naval Research, coordinated across the Naval Research Enterprise (NRE), and outlined in the Naval R&D Framework. This Program Element (PE) funds Advanced Technology Development (ATD) that includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Efforts in this PE generally have Technology Readiness Levels TRL) of 4 (component and/or breadboard validation in laboratory environment.), 5 (component and/or breadboard validation in relevant environment.), or 6 (system/subsystem model or prototype demonstration in a relevant environment). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                               Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 3: Advanced           PE 0603758N / Navy Warfighting Exp & Demo Technology Development (ATD) Due to the number of efforts in this PE, the programs described herein are representative of the work included in this PE.$$, NULL, 68992000, 69975000, 71351000, NULL, NULL, 24, $$RDTEN_BA1-3_Book.pdf$$, NULL, FALSE, 133296000, 149980000, 66395000, 66395000, NULL, 66395000, 72567000, $$The Office of Naval Research (ONR) guides ongoing research and innovation operations in the pursuit of novel and decisive capabilities for our Sailors and Marines. ONR manages a broad, but priority-driven investment portfolio of near to long-term basic and applied research. This Program Element (PE) develops Science and Technology (S&T) breakthroughs to meet current operational needs, from prototyping solutions for warfighters, to Fleet experimentation and operational demonstrations including Fleet Battle Problems (FBP), Limited Objective Experiments (LOEs) and Fleet/Force exercises. The key aspects of this PE are divided into six areas supporting the continuum of S&T and innovation operations from discovery to delivery: (1) Naval Warfare Prototype and Demonstration develops rapid prototypes and through innovation operations, provides them to the warfighter for experimentation during operational demonstrations and exercises; (2) Operations Analysis provides the Navy and Marine Corps the means to identify capability needs that can be addressed with science and technology solutions and inform future investment; (3) NavalX applies innovation operations to develop, demonstrate, and transition newly invented or recently discovered technologies that address emergent and enduring operational problems in an accelerated timeframe; (4) Tech Solutions to include Tech Bridge industry scanning allows the ability to rapidly prototype science and technology solutions that address Fleet/Force needs submitted by Sailors and Marines within the development environment and at the deck plate level; (5) support for the Naval Precision Strike Operations, providing the Navy capability to quickly locate, target, and strike critical targets; and (6) Undersea Systems Payloads and Weapons, addressing innovative affordable, persistent, and stealthy undersea system. Today's Sailors and Marines are enabled by naval Science and Technology (S&T). Since 1946, the Office of Naval Research (ONR) has fostered scientific research related to the maintenance of maritime superiority and national defense. ONR manages the Department of the Navy's (DON) portfolio of naval Basic and Applied research, and Advanced Technology Development investments to ensure naval forces can effectively deter conflict, but when called upon, fight, win and come home safe. Current investments hedge against uncertainty, providing solutions to commanders today, and options for the future. The Naval S&T budget supports higher Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                               Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 3: Advanced        PE 0603758N / Navy Warfighting Exp & Demo Technology Development (ATD) guidance defined by the National Defense Strategy, and responds to requirements identified by the Secretary of the Navy through research priorities set by the Chief of Naval Research, coordinated across the Naval Research Enterprise (NRE), and outlined in the Naval R&D Framework. This Program Element (PE) funds Advanced Technology Development (ATD) that includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Efforts in this PE generally have Technology Readiness Levels TRL) of 4 (component and/or breadboard validation in laboratory environment.), 5 (component and/or breadboard validation in relevant environment.), or 6 (system/subsystem model or prototype demonstration in a relevant environment). Due to the number of efforts in this PE, the programs described herein are representative of the work included in this PE.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA1-3_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603764M$$, $$LINK EVERGREEN$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 529550000, 496998000, 457721000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "mc", "page_num": 29, "original_pe": "0603764M", "page_header": "Department of the Navy"}$$::jsonb, $$The details of this budget justification are classified, per Executive Order 13526, Sec 1.4 (a) and are submitted annually to Congress in the classified budget justification book.$$, NULL, NULL, NULL, NULL, NULL, NULL, 68, $$Budget J-Books/FY27/Remaining/FY2027_r1.pdf$$, NULL, FALSE, 450729000, 521007000, 593835000, 593835000, 0, 593835000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603766A$$, $$Tactical Electronic Surveillance System - Adv Dev$$, $$rdte_army_ba4$$, $$cft_lrpf$$, 2026, 107525000, 72259000, 87765000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 13, "original_pe": "0603766A", "page_header": "Department of the Army"}$$::jsonb, $$Tactical Exploitation of National Capabilities (TENCAP) exploits national intelligence capabilities to pace evolving threats in support of operations during conflict and competition. TENCAP systems and technologies provide deep sensing to support commanders' situational understanding (patterns of life, threat intentions, etc.), indications & warnings (detection of enemy mobilization and hostile activity), and intelligence support to targeting (order of battle, electronic target folders, target detection, Battle Damage Assessment, etc.). TENCAP systems and technologies support Theater-level fires and effects. TENCAP systems enable integrated Signals Intelligence (SIGINT) / Geospatial Intelligence (GEOINT) / Electronic Warfare (EW) / and Cyberspace operations. TENCAP supports Army modernization priorities including Long Range Precision Fires, Advanced Deep Sensing (ADS), Future Vertical Lift (FVL), and Air Missile Defense (AMD). In summary, TENCAP is a key enabler to defeating peer competitor Anti-Access / Area-Denial (A2/AD) strategies. Tactical Exploitation of National Capabilities (TENCAP) accomplishes the Army's Tactical Electronic Surveillance System Advance Development by leveraging National Intelligence Community (IC) capabilities through cross-agency engineering to evaluate, enhance, prototype, and transition Intelligence, Surveillance and Reconnaissance (ISR) technologies/capabilities from the IC into Army systems and architectures. This Program Element includes three projects: 1) TENCAP Core project (907). 2) Tactical Intelligence Targeting Access Node (TITAN) (space) advanced development project (BX9). 3) Low Earth Orbit ISR (LEO ISR) development project (CC5). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced          PE 0603766A / Tactical Electronic Surveillance System - Adv Dev Component Development & Prototypes (ACD&P)$$, NULL, 112123000, 95393000, 81115000, NULL, NULL, 67, $$RDTE - Vol 2 - Budget Activity 4A.pdf$$, NULL, FALSE, 87765000, 117325000, 98331000, 98331000, NULL, 98331000, 79588000, $$Tactical Exploitation of National Capabilities (TENCAP) exploits national intelligence capabilities to pace evolving threats in support of operations during conflict and competition. TENCAP systems and technologies provide deep sensing to support commanders' situational understanding (patterns of life, threat intentions, etc.), indications & warnings (detection of enemy mobilization and hostile activity), and intelligence support to targeting (order of battle, electronic target folders, target detection, Battle Damage Assessment, etc.). TENCAP systems and technologies support Theater-level fires and effects. TENCAP systems enable integrated Signals Intelligence (SIGINT) / Geospatial Intelligence (GEOINT) / Electronic Warfare (EW) / and Cyberspace operations. TENCAP supports Army Transformation by rapidly discovering, developing and integrating National Intelligence technologies and capabilities to accelerate innovation and rapidly field warfighting capabilities that increase the lethality of Army formations. In summary, TENCAP is a key enabler to defeating peer competitor Anti-Access / Area-Denial (A2/AD) strategies. Tactical Exploitation of National Capabilities (TENCAP) accomplishes the Army's Tactical Electronic Surveillance System Advance Development by leveraging National Intelligence Community (IC) capabilities through cross-agency engineering to evaluate, enhance, prototype, and transition Intelligence, Surveillance and Reconnaissance (ISR) technologies/capabilities from the IC into Army systems and architectures. This Program Element includes three projects: 1) TENCAP Core project (907). 2) Tactical Intelligence Targeting Access Node (TITAN) (space) advanced development project (BX9). 3) Low Earth Orbit ISR (LEO ISR) development project (CC5). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                            Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced           PE 0603766A / Tactical Electronic Surveillance System - Adv Dev Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603766E$$, $$NETWORK-CENTRIC WARFARE TECHNOLOGY$$, $$rdte_dw_ba3$$, $$dw_darpa$$, 2026, 0, 922185000, 866533000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 70, "original_pe": "0603766E", "page_header": "Defense-Wide"}$$::jsonb, $$The efforts described in this Program Element (PE) address the Advanced Technology Development associated with the Network-Centric Warfare Technology Program that addresses high payoff opportunities to develop and rapidly mature advanced technologies and systems required for today's network-centric warfare concepts. It is imperative for the future of the U.S. forces to operate flawlessly with each other, regardless of which services and systems are involved in any particular mission. The overarching goal of this PE is to enable technologies at all levels, regardless of service component, to operate as one system. The objective of the Joint Warfare Systems project is to create enabling technologies for seamless joint operations, from strategic planning to tactical and urban operations. Joint Warfare Systems leverage current and emerging network, robotic, and information technology and provide next generation U.S. forces with greatly increased capability, lethality, and rapid responsiveness. Critical issues facing this project are: (1) U.S. opponents using systems that are flexible, robust, and difficult to neutralize; and (2) U.S. doctrine that limits the use of firepower to lessen the impact of operations on noncombatants. These problems are magnified in urban and semi-urban areas where combatants and civilians are often co-located and in peacekeeping operations where combatants and civilians are often indistinguishable. Meeting these challenges places a heavy burden on joint war planning. Understanding opponent networks is essential so that creative options can be developed to counter their strategies. Synchronization of air and ground operations to apply force only where needed and with specific effects is required. This project supports all levels of the force structure including: (1) the strategic/operational level by generating targeting options against opponents' centers of gravity that have complex networked relationships; (2) the tactical/operational level by managing highly automated forces with tight coupling between air and ground platforms; and (3) the focused tactical level by developing platforms and tools, which acquire targets of opportunity and cue network-based analysis of likely enemy operations thus maximizing the effectiveness of ground forces in stability and support operations. The Maritime Systems project is identifying, developing and rapidly maturing critical advanced technologies and system concepts for the naval forces' role in today's network-centric warfare concept. Improvements in communications between and among submarines, surface ships and naval aircraft have allowed these forces to operate seamlessly with each other and with other Service's network-centric systems. Naval forces will play an ever-increasing role in network-centric warfare because of their forward deployed nature, their unique capability to operate simultaneously in the air, on the sea and under the sea, and their versatile ability to provide both rapid strike and project sustained force. The technologies developed under this project will capitalize on these attributes, improve them and enable them to operate with other network-centric forces. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                      Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:          PE 0603766E / NETWORK-CENTRIC WARFARE TECHNOLOGY Advanced Technology Development (ATD) Beginning in FY 2026, efforts in this PE will be funded in PE 0603467E, DARPA Advanced Technology Development.$$, NULL, 0, 0, 0, NULL, NULL, 70, $$RDTE_Vol1_DARPA_MasterJustificationBook_PB_2026.pdf$$, $$DARPA$$, FALSE, 838984000, 0, 0, 0, NULL, 0, 0, $$The efforts described in this Program Element (PE) address the Advanced Technology Development associated with the Network-Centric Warfare Technology Program that addresses high payoff opportunities to develop and rapidly mature advanced technologies and systems required for today's network-centric warfare concepts. It is imperative for the future of the U.S. forces to operate flawlessly with each other, regardless of which services and systems are involved in any particular mission. The overarching goal of this PE is to enable technologies at all levels, regardless of service component, to operate as one system. The objective of the Joint Warfare Systems project is to create enabling technologies for seamless joint operations, from strategic planning to tactical and urban operations. Joint Warfare Systems leverage current and emerging network, robotic, and information technology and provide next generation U.S. forces with greatly increased capability, lethality, and rapid responsiveness. Critical issues facing this project are: (1) U.S. opponents using systems that are flexible, robust, and difficult to neutralize; and (2) U.S. doctrine that limits the use of firepower to lessen the impact of operations on noncombatants. These problems are magnified in urban and semi-urban areas where combatants and civilians are often co-located and in peacekeeping operations where combatants and civilians are often indistinguishable. Meeting these challenges places a heavy burden on joint war planning. Understanding opponent networks is essential so that creative options can be developed to counter their strategies. Synchronization of air and ground operations to apply force only where needed and with specific effects is required. This project supports all levels of the force structure including: (1) the strategic/operational level by generating targeting options against opponents' centers of gravity that have complex networked relationships; (2) the tactical/operational level by managing highly automated forces with tight coupling between air and ground platforms; and (3) the focused tactical level by developing platforms and tools, which acquire targets of opportunity and cue network-based analysis of likely enemy operations thus maximizing the effectiveness of ground forces in stability and support operations. The Maritime Systems project is identifying, developing and rapidly maturing critical advanced technologies and system concepts for the naval forces' role in today's network-centric warfare concept. Improvements in communications between and among submarines, surface ships and naval aircraft have allowed these forces to operate seamlessly with each other and with other Services' network-centric systems across domains. Naval forces will play an ever-increasing role in network-centric warfare because of their forward deployed nature, their unique capability to operate simultaneously in the air, on the sea and under the sea, and their versatile ability to provide both rapid strike and project sustained force. The technologies developed under this project will capitalize on these attributes, improve them and enable them to operate with other network-centric forces. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Advanced Research Projects Agency                                   Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:          PE 0603766E / NETWORK-CENTRIC WARFARE TECHNOLOGY Advanced Technology Development (ATD) Beginning in FY 2026, efforts in this PE will be funded in PE 0603467E, DARPA Advanced Technology Development.$$, $$Budget J-Books/FY27/DW/RDTE_Vol1_DARPA_MasterJustificationBook_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603767E$$, $$SENSOR TECHNOLOGY$$, $$rdte_dw_ba3$$, $$dw_darpa$$, 2026, 0, 313995000, 267961000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 70, "original_pe": "0603767E", "page_header": "Defense-Wide"}$$::jsonb, $$The efforts described in this Program Element (PE) address the Advanced Technology Development associated with the Sensor Technology Program focused on sensor efforts that will improve the accuracy and timeliness of our surveillance and targeting systems for improved battlefield awareness, strike capability and battle damage assessment. The Surveillance and Countermeasures Technology project funds sensor efforts that will improve the accuracy and timeliness of our surveillance and targeting systems for improved battlefield awareness, strike capability, and battle damage assessment. Timely surveillance of enemy territory under all weather conditions is critical to providing our forces with the tactical information needed to succeed in future wars. This operational surveillance capability must continue to perform during enemy efforts to deny and deceive the sensor systems, and operate, at times, in a clandestine manner. This project will exploit recent advances in multispectral target phenomenology, signal processing, low-power high-performance computing, and low-cost microelectronics to develop advanced surveillance and targeting systems. In addition, this project encompasses several advanced technologies related to the development of techniques to counter advanced battlefield threats. The Sensors and Processing Systems project develops and demonstrates the advanced sensor and processing technologies and systems necessary for Intelligence, Surveillance, and Reconnaissance (ISR) missions. Future battlefields will continue to be populated with targets that use mobility and concealment as key survival tactics, and high-value targets will range from specific individual insurgents and vehicles to groups of individuals and large platforms such as mobile missile launchers and artillery. The Sensors and Processing Systems project is primarily driven by four needs: (a) providing day-night ISR capabilities against the entire range of potential targets; (b) countering camouflage, concealment, and deception of mobile ground targets; (c) detecting and identifying objects of interest/targets across wide geographic areas in near-real-time; and (d) enabling reliable identification, precision fire control tracking, timely engagement, and accurate battle damage assessment of ground targets. The Sensors and Processing Systems project develops and demonstrates technologies and system concepts that combine novel approaches to sensing with emerging sensor technologies and advanced sensor and image processing algorithms, software, and hardware to enable comprehensive knowledge of the battlespace and detection, identification, tracking, engagement, and battle damage assessment for high-value targets in all weather conditions and combat environments. Beginning in FY 2026, efforts in this PE will be funded in PE 0603467E, DARPA Advanced Technology Development. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:       PE 0603767E / SENSOR TECHNOLOGY Advanced Technology Development (ATD)$$, NULL, 0, 0, 0, NULL, NULL, 71, $$RDTE_Vol1_DARPA_MasterJustificationBook_PB_2026.pdf$$, $$DARPA$$, FALSE, 259283000, 0, 0, 0, NULL, 0, 0, $$The efforts described in this Program Element (PE) address the Advanced Technology Development associated with the Sensor Technology Program focused on sensor efforts that will improve the accuracy and timeliness of our surveillance and targeting systems for improved battlefield awareness, strike capability and battle damage assessment. The Surveillance and Countermeasures Technology project funds sensor efforts that will improve the accuracy and timeliness of our surveillance and targeting systems for improved battlefield awareness, strike capability, and battle damage assessment. Timely surveillance of enemy territory under all weather conditions is critical to providing our forces with the tactical information needed to succeed in future wars. This operational surveillance capability must continue to perform during enemy efforts to deny and deceive the sensor systems, and operate, at times, in a clandestine manner. This project will exploit recent advances in multispectral target phenomenology, signal processing, low-power high-performance computing, and low-cost microelectronics to develop advanced surveillance and targeting systems. In addition, this project encompasses several advanced technologies related to the development of techniques to counter advanced battlefield threats. The Sensors and Processing Systems project develops and demonstrates the advanced sensor and processing technologies and systems necessary for Intelligence, Surveillance, and Reconnaissance (ISR) missions. Future battlefields will continue to be populated with targets that use mobility and concealment as key survival tactics, and high-value targets will range from specific individual insurgents and vehicles to groups of individuals and large platforms such as mobile missile launchers and artillery. The Sensors and Processing Systems project is primarily driven by four needs: (a) providing day-night ISR capabilities against the entire range of potential targets; (b) countering camouflage, concealment, and deception of mobile ground targets; (c) detecting and identifying objects of interest/targets across wide geographic areas in near-real-time; and (d) enabling reliable identification, precision fire control tracking, timely engagement, and accurate battle damage assessment of ground targets. The Sensors and Processing Systems project develops and demonstrates technologies and system concepts that combine novel approaches to sensing with emerging sensor technologies and advanced sensor and image processing algorithms, software, and hardware to enable comprehensive knowledge of the battlespace and detection, identification, tracking, engagement, and battle damage assessment for high-value targets in all weather conditions and combat environments. Beginning in FY 2026, efforts in this PE will be funded in PE 0603467E, DARPA Advanced Technology Development. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Advanced Research Projects Agency                                   Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:        PE 0603767E / SENSOR TECHNOLOGY Advanced Technology Development (ATD)$$, $$Budget J-Books/FY27/DW/RDTE_Vol1_DARPA_MasterJustificationBook_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603774A$$, $$Night Vision Systems Advanced Development$$, $$rdte_army_ba4$$, $$asa_alt$$, 2026, 5153000, 41941000, 20714000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 14, "original_pe": "0603774A", "page_header": "Department of the Army"}$$::jsonb, $$A portion of this funding line is directly aligned to the Army Soldier Lethality Modernization Priority in support of situational awareness for the Close Combat Soldier. This Program Element focuses on efforts to evaluate and integrate technologies and representative prototype systems that facilitate the development of Soldier-borne sensor devices transitioning from the laboratory to operational use. Efforts focus on proving out commonality across as broad a spectrum of users as possible to provide enhanced Soldier products, giving them superiority on the battlefield. Project BQ5 (Visual Augmentation System-Advanced Development) This project evaluates and integrates technologies and representative prototype systems transitioning from the Science and Technology (S&T) stage. It develops the next generation augmented vision and situational awareness system providing Soldiers and Squads a single platform for increased lethality, mobility, and situational awareness to achieve overmatch against our current and future adversaries. Funded efforts accelerate the development of components, Heads Up Display (HUD) improvements, terrain shared coordinate data and processing, algorithms including machine learning/artificial intelligence, human machine integration, and demonstrations in support of the next generation augmented vision and situational awareness system. Efforts will provide rapid decision making and passive targeting capabilities with the integration of external video and data sources such as weapon sights, air and ground platforms, unmanned air and ground assets, and other data sources enabled by edge computing devices and advanced network services. This project will provide data driven analytics to optimize unit performance and enhance lethality and to enable training in a mixed reality environment. This project includes costs for efforts associated with edge computing platforms, movement of information and high-level processing, integration, and interface of products with the Soldiers' head, body, weapon, and platforms. Funding in this project aligns with the Army's Continuous Transformation priorities and the National Defense Strategy. This project supports the Soldier Lethality Cross Functional Team. Project VT7 (Soldier Maneuver Sensors-Advanced Development) project enables development of emerging capabilities for the maneuver force, that are envisioned by the Soldier Lethality Cross Functional Team, the Maneuver Center of Excellence (MCoE), the Maneuver Capabilities Development Integration Directorate (MCDID), the Science and Technology (S&T) community, industry partners or the acquisition workforce that may provide the Soldier or Squad increased capability to "fight, win and survive, day and night, in a multi- domain environment now and tomorrow". This project also allows pursuit of technology breakthroughs that challenge current technical solutions and have the potential for providing increased Soldier performance. This effort focuses on capabilities that enable modernization of Soldier sensor and laser Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                 Date: June 2025 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced                PE 0603774A / Night Vision Systems Advanced Development Component Development & Prototypes (ACD&P) devices, including digital features and enhanced solutions including maneuver capabilities to detect, recognize and identify targets, and to provide target acquisition and handoff but not limited to capabilities to mitigate threats. The integration of higher performing multi-spectral sensors with smart processing will provide adjusted weapon sight reticles and leverage network connectivity for improved situational awareness/understanding. Additional project capabilities include advanced optical components and assemblies and techniques for signature management, resiliency across the electromagnetic spectrum, and integration of a modular design structure for target acquisition applications including support for wireless data transfer, passive range determination, technologies for working in a global positioning system (GPS) contested environment, advanced GPS replacement technologies and mitigation of manned and unmanned threat sensor systems. This project supports efforts to evaluate and integrate technologies and representative prototype systems including Micro Electronics Modules (MEMS) technology with improved size, weight and power for development of modernized Soldier sensor capabilities transitioning from the S&T stage to operational use. This project includes costs for efforts associated with development, certification, verification and validation of interface products into the Adaptive Squad Architecture (ASA). This project also includes development of tools and emulators of ASA components. Funding in this project aligns with Army's priorities in support of the National Defense Strategy. Project VT8 (Soldier Precision Targeting Devices - Advanced Development) enables development of emerging technologies that are envisioned by the Fires Center of Excellence (FCoE), the Fires Capabilities Development and Integration Directorate (FCDID), the Science and Technology (S&T) community, industry partners and the acquisition workforce that provide the Fire Support Soldier increased capability and reduced weight to improve operational effectiveness. This project focuses on developing component technologies and representative prototype systems for Soldier portable precision targeting devices to continue improvements to system performance while reducing size, weight, and power required by those systems. The effort will consider emerging Micro-Electronic Modules (MEMs) technologies for improved efficiency and performance. Efforts will improve the Soldier's ability to precisely locate and laser designate targets across a broader range of operating environments, including all weather conditions and in GPS-contested environments using active and passive methods and technologies. Component technology development will precede integration into specific systems and will include improved Precision Azimuth and Vertical Angle Measurement (PAVAM) devices; solid-state, improved lasers for range finding/designation/marking; novel passive target acquisition methods; electro-optical sensors such as infrared, near-infrared, ultra-violet, and visible spectrum imagers; sensor and data fusion; laser designator spot detection and imaging; integration of advanced power management technologies, and Global Positioning System (GPS) M-Code receivers. The effort will also develop, mature and integrate next generation sensors to enable Human Machine Integration improving situational awareness and combat overmatch in complex environments. Funding in this project aligns with Army's priorities in support of the National Defense Strategy. The FY 2026 request was reduced by $0.063 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 cost of the Integrated Visual Augmentation System (IVAS) Middle Tier of Acquisition effort is $85.5 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                          Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced        PE 0603774A / Night Vision Systems Advanced Development Component Development & Prototypes (ACD&P)$$, NULL, 5376000, 5422000, 5425000, NULL, NULL, 68, $$RDTE - Vol 2 - Budget Activity 4A.pdf$$, NULL, FALSE, 20250000, 19353000, 5310000, 5310000, NULL, 5310000, 5479000, $$A portion of this funding line is directly aligned to the Army Soldier Lethality Modernization Priority in support of situational awareness for the Close Combat Soldier. This Program Element focuses on efforts to evaluate and integrate technologies and representative prototype systems that facilitate the development of Soldier-borne sensor devices transitioning from the laboratory to operational use. Efforts focus on proving out commonality across as broad a spectrum of users as possible to provide enhanced Soldier products, giving them superiority on the battlefield. Project BQ5 (Visual Augmentation System-Advanced Development) This project evaluates and integrates technologies and representative prototype systems transitioning from the Science and Technology (S&T) stage. It develops the next generation augmented vision and situational awareness system providing Soldiers and Squads a single platform for increased lethality, mobility, and situational awareness to achieve overmatch against our current and future adversaries. Funded efforts accelerate the development of components, Heads Up Display (HUD) improvements, terrain shared coordinate data and processing, algorithms including machine learning/artificial intelligence, human machine integration, and demonstrations in support of the next generation augmented vision and situational awareness system. Efforts will provide rapid decision making and passive targeting capabilities with the integration of external video and data sources such as weapon sights, air and ground platforms, unmanned air and ground assets, and other data sources enabled by edge computing devices and advanced network services. This project will provide data driven analytics to optimize unit performance and enhance lethality and to enable training in a mixed reality environment. This project includes costs for efforts associated with edge computing platforms, movement of information and high-level processing, integration, and interface of products with the Soldiers' head, body, weapon, and platforms. Funding in this project aligns with the Army's Continuous Transformation priorities and the National Defense Strategy. This project supports the Futures and Concepts Command (FCC) Maneuver Future Capability Directorate. Currently, there is no funding in this project for FY 2027. Project VT7 (Soldier Maneuver Sensors-Advanced Development) project enables development of emerging capabilities for the maneuver force, that are envisioned by the Soldier Lethality Cross Functional Team, the Maneuver Center of Excellence (MCoE), the Maneuver Capabilities Development Integration Directorate (MCDID), the Science and Technology (S&T) community, industry partners or the acquisition workforce that may provide the Soldier or Squad increased capability to "fight, win and survive, day and night, in a multi- domain environment now and tomorrow". This project also allows pursuit of technology breakthroughs that challenge current technical solutions and have the potential for providing increased Soldier performance. This effort focuses on capabilities that enable modernization of Soldier sensor and laser Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                 Date: April 2026 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced                PE 0603774A / Night Vision Systems Advanced Development Component Development & Prototypes (ACD&P) devices, including digital features and enhanced solutions including maneuver capabilities to detect, recognize and identify targets, and to provide target acquisition and handoff but not limited to capabilities to mitigate threats. The integration of higher performing multi-spectral sensors with smart processing will provide adjusted weapon sight reticles and leverage network connectivity for improved situational awareness/understanding. Additional project capabilities include advanced optical components and assemblies and techniques for signature management, resiliency across the electromagnetic spectrum, and integration of a modular design structure for target acquisition applications including support for wireless data transfer, passive range determination, technologies for working in a global positioning system (GPS) contested environment, advanced GPS replacement technologies and mitigation of manned and unmanned threat sensor systems. This project supports efforts to evaluate and integrate technologies and representative prototype systems including Micro Electronics Modules (MEMS) technology with improved size, weight and power for development of modernized Soldier sensor capabilities transitioning from the S&T stage to operational use. This project includes costs for efforts associated with development, certification, verification and validation of interface products into the Adaptive Squad Architecture (ASA). This project also includes development of tools and emulators of ASA components. Funding in this project aligns with Army's priorities in support of the National Defense Strategy. Project VT8 (Soldier Precision Targeting Devices - Advanced Development) enables development of emerging technologies that are envisioned by the Fires Center of Excellence (FCoE), the Fires Capabilities Development and Integration Directorate (FCDID), the Science and Technology (S&T) community, industry partners and the acquisition workforce that provide the Fire Support Soldier increased capability and reduced weight to improve operational effectiveness. This project focuses on developing component technologies and representative prototype systems for Soldier portable precision targeting devices to continue improvements to system performance while reducing size, weight, and power required by those systems. The effort will consider emerging Micro-Electronic Modules (MEMs) technologies for improved efficiency and performance. Efforts will improve the Soldier's ability to precisely locate and laser designate targets across a broader range of operating environments, including all weather conditions and in GPS-contested environments using active and passive methods and technologies. Component technology development will precede integration into specific systems and will include improved Precision Azimuth and Vertical Angle Measurement (PAVAM) devices; solid-state, improved lasers for range finding/designation/marking; novel passive target acquisition methods; electro-optical sensors such as infrared, near-infrared, ultra-violet, and visible spectrum imagers; sensor and data fusion; laser designator spot detection and imaging; integration of advanced power management technologies, and Global Positioning System (GPS) M-Code receivers. The effort will also develop, mature and integrate next generation sensors to enable Human Machine Integration improving situational awareness and combat overmatch in complex environments. Funding in this project aligns with Army's priorities in support of the National Defense Strategy. The total cost of the Integrated Visual Augmentation Systems IVAS 1.2, Rapid Prototyping Middle Tier of Acquisition (RP MTA) effort is $798.10 million RDT&E from FY 2022 to FY 2027. The total cost of the Soldier Borne Mission Command (SBMC) RP MTA effort is $429.8 million RDT&E from FY 2025 to FY 2027. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced          PE 0603774A / Night Vision Systems Advanced Development Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603779A$$, $$Environmental Quality Technology - Dem/Val$$, $$rdte_army_ba4$$, $$asa_alt$$, 2026, 11343000, 19369000, 23299000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 14, "original_pe": "0603779A", "page_header": "Department of the Army"}$$::jsonb, $$There is broad potential application for environmental quality technology (EQT) to be applied to multiple Army weapon systems and installations. However, technology must be demonstrated and validated (total ownership cost and performance data identified) before potential users will consider exploiting it. This Program Element (PE) includes Projects focused on validating the general military utility or cost reduction potential of technology when applied to different types of infrastructure, military equipment or techniques. It may include validations and proof-of-principle demonstrations in field exercises to evaluate upgrades or provide new operational capabilities. The validation of technologies will be in as realistic an operating environment as possible to assess performance or cost reduction potential. EQT demonstration/ validation is systemic and applicable across Department of Army sites and installation problems (e.g. unexploded ordnance detection and discrimination). This PE supports the Army's top modernization priorities by addressing potential obsolescence of legacy materials and current and emerging impacts on human health and the environment. All work is endorsed by potential users and supported by a state-of-the-art assessment to determine when the technology can transition to the user for implementation. The FY 2026 request was reduced by $0.023 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.104 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                            Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced          PE 0603779A / Environmental Quality Technology - Dem/Val Component Development & Prototypes (ACD&P)$$, NULL, 20541000, 20841000, 21017000, NULL, NULL, 69, $$RDTE - Vol 2 - Budget Activity 4A.pdf$$, NULL, FALSE, 22637000, 36343000, 19499000, 19499000, NULL, 19499000, 21293000, $$There is broad potential application for environmental quality technology (EQT) to be applied to multiple Army weapon systems and installations. However, technology must be demonstrated and validated (total ownership cost and performance data identified) before potential users will consider exploiting it. This Program Element (PE) includes Projects focused on validating the general military utility or cost reduction potential of technology when applied to different types of infrastructure, military equipment or techniques. It may include validations and proof-of-principle demonstrations in field exercises to evaluate upgrades or provide new operational capabilities. The validation of technologies will be in as realistic an operating environment as possible to assess performance or cost reduction potential. EQT demonstration/ validation is systemic and applicable across Department of Army sites and installation problems (e.g. unexploded ordnance detection and discrimination). This PE supports the Army's top modernization priorities by addressing potential obsolescence of legacy materials and current and emerging impacts on human health and the environment. All work is endorsed by potential users and supported by a state-of-the-art assessment to determine when the technology can transition to the user for implementation. The FY 2026 request was reduced by $0.023 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.104 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced          PE 0603779A / Environmental Quality Technology - Dem/Val Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603782N$$, $$Mine and Expeditionary Warfare Advanced Technology$$, $$rdte_navy_ba3$$, $$onr$$, 2026, 2075000, 1987000, 2050000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "navy", "page_num": 27, "original_pe": "0603782N", "page_header": "Department of the Navy"}$$::jsonb, $$Explosive ordnance disposal is a critical naval mission vital to the safety of service members and civilians. Highly trained Sailors and Marines utilize their knowhow and courage combined with state-of-the-art technology to remove unexploded ordnance, land/sea mines and even chemical, biological and nuclear weapons. The Department of Defense (DoD) Directive 5160.62 "DoD Executive Agent for Military Explosive Ordnance Disposal Technology & Training" guides research in this Program Element (PE). Unique needs and capabilities identified by the Joint Requirements Oversight Council (JROC) and the DoD EOD Program Board are also addressed by this PE and provide the vision and key objectives for the essential science and technology efforts that will enable the continued supremacy of U.S. Naval and Joint EOD forces in the 21st century. The strategy focuses and aligns Naval S&T with Naval missions, Joint Service EOD S&T with Joint EOD missions and future capability needs that address the complex challenges presented by both rising peer competitors and irregular/asymmetric warfare. This PE primarily develops and demonstrates prototype Mine Countermeasures (MCM), Expeditionary Warfare and Joint EOD system components that support capabilities enabling Naval and Joint EOD Forces to influence operations ashore. Adversarial nations have the capability to procure, stockpile and rapidly deploy all types of naval mines, including new generation mines having sophisticated performance characteristics, throughout the littorals. They also have the capability to develop or modify explosive devices such as mines and unexploded ordnance to construct Improvised Explosive Devices (IEDs) for the purpose of targeting Joint Forces. Real world operations have demonstrated the requirement to quickly counter the mine threat. Current operations have also demonstrated the requirement to quickly counter the threat from explosive hazards and IEDs during DoD operations. Advanced technologies must rapidly detect and neutralize all mine types, from deep water to the inland objective. Advanced technologies must enable Joint EOD forces to detect/locate, gain access, diagnose, render safe, neutralize, recover, exploit and dispose of a broad spectrum of explosive hazards including unexploded ordnance and IEDs. This program supports the advanced development and integration of sensors, processing, warheads, and delivery vehicles to demonstrate improved Naval Warfare capabilities. It supports the advanced development and integration of sensors and tools for standoff capabilities such as detection and location of IEDs (particularly in dismounted operations), dismounted diagnosis of buried munitions and other explosive hazards, precision render safe and neutralization of surface munitions and other explosive hazards, and enhanced access to IEDs. It supports the Expeditionary Maneuver and Undersea Warfare-related FNC Enabling Capabilities (ECs). Today's Sailors and Marines are enabled by naval Science and Technology (S&T). Since 1946, the Office of Naval Research (ONR) has fostered scientific research related to the maintenance of maritime superiority and national defense. ONR manages the Department of the Navy's (DON) portfolio of naval Basic and Applied research, and Advanced Technology Development investments to ensure naval forces can effectively deter conflict, but when called upon, fight, win and come home safe. Current investments hedge against uncertainty, providing solutions to commanders today, and options for the future. The Naval S&T budget supports higher guidance defined by the National Defense Strategy, and responds to requirements identified by the Secretary of the Navy through research priorities set by the Chief of Naval Research, coordinated across the Naval Research Enterprise (NRE), and outlined in the Naval R&D Framework. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                           Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 3: Advanced         PE 0603782N / Mine and Expeditionary Warfare Advanced Technology Technology Development (ATD) This Program Element (PE) funds Advanced Technology Development (ATD) that includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Efforts in this PE generally have Technology Readiness Levels TRL) of 4 (component and/or breadboard validation in laboratory environment.), 5 (component and/or breadboard validation in relevant environment.), or 6 (system/subsystem model or prototype demonstration in a relevant environment).$$, NULL, 0, 0, 0, NULL, NULL, 25, $$RDTEN_BA1-3_Book.pdf$$, NULL, FALSE, 1988000, 2075000, 0, 0, NULL, 0, 0, $$Explosive ordnance disposal is a critical naval mission vital to the safety of service members and civilians. Highly trained Sailors and Marines utilize their knowhow and courage combined with state-of-the-art technology to remove unexploded ordnance, land/sea mines and even chemical, biological and nuclear weapons. The Department of War (DoW) Directive 5160.62 "DoW Executive Agent for Military Explosive Ordnance Disposal Technology & Training" guides research in this Program Element (PE). Unique needs and capabilities identified by the Joint Requirements Oversight Council (JROC) and the DoW EOD Program Board are also addressed by this PE and provide the vision and key objectives for the essential science and technology efforts that will enable the continued supremacy of U.S. Naval and Joint EOD forces in the 21st century. The strategy focuses and aligns Naval S&T with Naval missions, Joint Service EOD S&T with Joint EOD missions and future capability needs that address the complex challenges presented by both rising peer competitors and irregular/asymmetric warfare. This PE primarily develops and demonstrates prototype Mine Countermeasures (MCM), Expeditionary Warfare and Joint EOD system components that support capabilities enabling Naval and Joint EOD Forces to influence operations ashore. Adversarial nations have the capability to procure, stockpile and rapidly deploy all types of naval mines, including new generation mines having sophisticated performance characteristics, throughout the littorals. They also have the capability to develop or modify explosive devices such as mines and unexploded ordnance to construct Improvised Explosive Devices (IEDs) for the purpose of targeting Joint Forces. Real world operations have demonstrated the requirement to quickly counter the mine threat. Current operations have also demonstrated the requirement to quickly counter the threat from explosive hazards and IEDs during DoW operations. Advanced technologies must rapidly detect and neutralize all mine types, from deep water to the inland objective. Advanced technologies must enable Joint EOD forces to detect/locate, gain access, diagnose, render safe, neutralize, recover, exploit and dispose of a broad spectrum of explosive hazards including unexploded ordnance and IEDs. This program supports the advanced development and integration of sensors, processing, warheads, and delivery vehicles to demonstrate improved Naval Warfare capabilities. It supports the advanced development and integration of sensors and tools for standoff capabilities such as detection and location of IEDs (particularly in dismounted operations), dismounted diagnosis of buried munitions and other explosive hazards, precision render safe and neutralization of surface munitions and other explosive hazards, and enhanced access to IEDs. It supports the Expeditionary Maneuver and Undersea Warfare-related FNC Enabling Capabilities (ECs). Today's Sailors and Marines are enabled by naval Science and Technology (S&T). Since 1946, the Office of Naval Research (ONR) has fostered scientific research related to the maintenance of maritime superiority and national defense. ONR manages the Department of the Navy's (DON) portfolio of naval Basic and Applied research, and Advanced Technology Development investments to ensure naval forces can effectively deter conflict, but when called upon, fight, win and come home safe. Current investments hedge against uncertainty, providing solutions to commanders today, and options for the future. The Naval S&T budget supports higher guidance defined by the National Defense Strategy, and responds to requirements identified by the Secretary of the Navy through research priorities set by the Chief of Naval Research, coordinated across the Naval Research Enterprise (NRE), and outlined in the Naval R&D Framework. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                           Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 3: Advanced         PE 0603782N / Mine and Expeditionary Warfare Advanced Technology Technology Development (ATD) This Program Element (PE) funds Advanced Technology Development (ATD) that includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Efforts in this PE generally have Technology Readiness Levels TRL) of 4 (component and/or breadboard validation in laboratory environment.), 5 (component and/or breadboard validation in relevant environment.), or 6 (system/subsystem model or prototype demonstration in a relevant environment).$$, $$Budget J-Books/FY27/Navy/RDTEN_BA1-3_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603788F$$, $$Battlespace Knowledge Development and Demonstration$$, $$rdte_af_ba3$$, $$afrl_ri$$, 2026, 30812000, 59611000, 53672000, NULL, $${"ba_raw": "6.3", "source": "af_r1_fy26", "original_pe": "0603788F"}$$::jsonb, $$The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This program executes advanced development and demonstration of information technologies for the Department of the Air Force to address warfighter requirement gaps and accelerate the delivery of capabilities for Command, Control, Communications, Computers, Cyber, Intelligence, Surveillance, Reconnaissance, and Targeting (C5ISRT). These technologies are required to advance current capabilities in C5ISRT for integrated systems and processes, used by the Department of the Air Force and its joint & coalition partners, to collect, process, analyze, and disseminate information to achieve decision-making superiority for warfighter operations. The C4I Battlespace Dev and Demo Project provides technology enabling the Air Force (a) to perform combined joint all-domain command & control (CJADC2) across the full spectrum of operations; (b) to field assured communications and networks in support of persistent, global, and survivable kinetic and non-kinetic military operations; (c) to process, fuse, and exploit data & information from multiple sources for rapid decision making and situational awareness. C4I is defined as Command, Control, Communications, Computers, and Intelligence. The Cyber Battlespace Dev & Demo Project develops the ability to deliver cyber-offense capabilities (access, stealth, persistence, intelligence, and non-kinetic weapons), cyber defense capabilities (attack detection, attack attribution, and response) and cyber resilience (adaptation, recovery, survivability). In order to manage, execute, and deliver science and technology capabilities, this program element may include: necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603788F / Battlespace Knowledge Development and Demonstration Technology Development (ATD)$$, NULL, 34503000, 35837000, 36582000, NULL, NULL, 29, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 53512000, 32411000, 31938000, 31938000, 0, 31938000, 37392000, $$This program is accomplished by Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. Funds in this PE may be used to investigate specified technology advancements in air, space and/or cyber domains. This program executes advanced development and demonstration of information technologies for the Department of the Air Force to address warfighter requirement gaps and accelerate the delivery of capabilities for Command, Control, Communications, Computers, Cyber, Intelligence, Surveillance, Reconnaissance, and Targeting (C5ISRT). These technologies are required to advance current capabilities in C5ISRT for integrated systems and processes, used by the Department of the Air Force and its joint & coalition partners, to collect, process, analyze, and disseminate information to achieve decision-making superiority for warfighter operations. The C4I Battlespace Dev and Demo Project provides technology enabling the Air Force (a) to perform combined joint all-domain command & control (CJADC2) across the full spectrum of operations; (b) to field assured communications and networks in support of persistent, global, and survivable kinetic and non-kinetic military operations; (c) to process, fuse, and exploit data & information from multiple sources for rapid decision making and situational awareness. C4I is defined as Command, Control, Communications, Computers, and Intelligence. The Cyber Battlespace Dev & Demo Project develops the ability to deliver cyber-offense capabilities (access, stealth, persistence, intelligence, and non-kinetic weapons), cyber defense capabilities (attack detection, attack attribution, and response) and cyber resilience (adaptation, recovery, survivability). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603788F / Battlespace Knowledge Development and Demonstration Technology Development (ATD) In order to manage, execute, and deliver science and technology capabilities, this program element may include: necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, etc. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603790A$$, $$NATO Research and Development$$, $$rdte_army_ba4$$, $$asa_alt$$, 2026, 5031000, 3987000, 4184000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 14, "original_pe": "0603790A", "page_header": "Department of the Army"}$$::jsonb, $$This Project implements the provisions of Title 10 United States (U.S.) Code, Section 2350a, Cooperative Research and Development (R&D) Projects: Allied Countries. The objective is to improve, through the application of emerging technologies, the conventional defense capabilities of the U.S. and our cooperative partners, including the North Atlantic Treaty Organization (NATO), U.S. major non-NATO allies and Friendly Foreign countries through technology sharing and joint equipment development, thereby reducing U.S. acquisition costs. Cooperative efforts also improve multinational force compatibility with potential coalition partners through the development and use of similar equipment and improved interfaces. The Project focuses specifically on international cooperative technology demonstration, validation, and interoperability of Army weapon and command, control, communications and information (C3I) systems, including the NATO Defense Against Terrorism initiatives. Activities are implemented through international agreements with foreign partners that define scope, cost and work sharing arrangements, management, contracting, security, data protection and third-party transfers. Funds are used to pay for only the U.S. work share that occurs within the U.S. at U.S. Government and U.S. contractor facilities.$$, NULL, 4388000, 4424000, 4470000, NULL, NULL, 70, $$RDTE - Vol 2 - Budget Activity 4A.pdf$$, NULL, FALSE, 4031000, 5031000, 5145000, 5145000, NULL, 5145000, 4514000, $$This Project implements the provisions of Title 10 United States (U.S.) Code, Section 2350a, Cooperative Research and Development (R&D) Projects: Allied Countries. The objective is to improve, through the application of emerging technologies, the conventional defense capabilities of the U.S. and our cooperative partners, including the North Atlantic Treaty Organization (NATO), U.S. major non-NATO allies and Friendly Foreign countries through technology sharing and joint equipment development, thereby reducing U.S. acquisition costs. Cooperative efforts also improve multinational force compatibility with potential coalition partners through the development and use of similar equipment and improved interfaces. The Project focuses specifically on international cooperative technology demonstration, validation, and interoperability of Army weapon and command, control, communications and information (C3I) systems, including the NATO Defense Against Terrorism initiatives. Activities are implemented through international agreements with foreign partners that define scope, cost and work sharing arrangements, management, contracting, security, data protection and third-party transfers. Funds are used to pay for only the U.S. work share that occurs within the U.S. at U.S. Government and U.S. contractor facilities.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603790F$$, $$NATO Research and Development$$, $$rdte_af_ba4$$, $$aflcmc$$, 2026, 4595000, 2208000, 2298000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0603790F"}$$::jsonb, $$Funds are used for air, space, and cyber international cooperative research, and development (ICR&D) agreements with North Atlantic Treaty Organization (NATO) member states, major non-NATO allies and friendly foreign countries. Each of the approved ICR&D projects are required to have a concluded international agreement (IA), prior to funds being released, that implements the provisions of Title 10 U.S. Code, Section 2350a. This legislation (Title 10 U.S. Code, Section 2350a) authorizes funds to significantly improve U.S. and allied conventional defense capabilities by leveraging the best defense technologies, eliminating costly duplication of R&D efforts, accelerating the availability of defense systems, and promoting U.S. and allied interoperability or commonality. These funds will not be used for government civilian salaries, permanent construction, or spent overseas. This program element funds the implementation of DAF ICR&D agreements in (1) Basic Research (2) Applied Research (3) Advanced Technology Development (4) Advanced Component Development and Prototypes (5) System Development and Demonstration and (6) RDT&E Management Support. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 2515000, 2618000, 2730000, NULL, NULL, 34, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 2214000, 4532000, 2320000, 2320000, 0, 2320000, 2767000, $$Funds are used for air, space, and cyber international cooperative research, and development (ICR&D) agreements with North Atlantic Treaty Organization (NATO) member states, major non-NATO allies and friendly foreign countries. Each of the approved ICR&D projects are required to have a concluded international agreement (IA), prior to funds being released, that implements the provisions of Title 10 U.S. Code, Section 2350a. This legislation (Title 10 U.S. Code, Section 2350a) authorizes funds to significantly improve U.S. and allied conventional defense capabilities by leveraging the best defense technologies, eliminating costly duplication of research and development (R&D) efforts, accelerating the availability of defense systems, and promoting the United States of America and allied interoperability or commonality. These funds will not be used for government civilian salaries, permanent construction, or spent overseas. This program element funds the implementation of DAF ICR&D agreements in 1) Basic Research, 2) Applied Research, 3) Advanced Technology Development, 4) Advanced Component Development and Prototypes, 5) System Development, and 6) RDT&E Management Support. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603790N$$, $$NATO Research and Deve$$, $$rdte_navy_ba4$$, $$dw_osd$$, 2026, 5234000, 6024000, 5151000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 29, "original_pe": "0603790N", "page_header": "Department of the Navy"}$$::jsonb, $$In accordance with Title 10 United States Code, Section 2350a, this Program Element (PE) provides funding for research and development (R&D) programs with approved allies under international agreements. These funds can only be applied to work efforts in the U.S. The Under Secretary of Defense, Acquisition and Sustainment (USD, A&S) must approve each international agreement. The program provides funds for multiple projects under separately approved international agreements as well as funds that support the establishment of such agreements. Each international agreement is summarized in a separate Summary Statement of Intent (SSOI) that also states why the project serves to increase the defense capabilities of the U.S. The SSOI is used to obtain project approval by the Department of the Navy and the Office of the Secretary of Defense. The North Atlantic Treaty Organization (NATO) R&D cooperative programs differ from other Research, Development, Test and Evaluation (RDT&E) programs because issuance of funding from this Program Element (PE) coincides with the signature of international agreements. These signatures occur throughout the fiscal year and often encounter unexpected delays during the staffing and negotiation phases of agreement processing prior to signature.$$, NULL, 4785000, 4616000, 4710000, NULL, NULL, 70, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 4953000, 5035000, 5513000, 5513000, NULL, 5513000, 4803000, $$In accordance with Title 10 United States Code, Section 2350a, this Program Element (PE) provides funding for Research and Development (R&D) programs with approved allies under international agreements. These funds can only be applied to work efforts in the U.S. The Under Secretary of War, Acquisition and Sustainment (USW, A&S) must approve each international agreement. The program provides funds for multiple projects under separately approved international agreements as well as funds that support the establishment of such agreements. Each international agreement is summarized in a separate Summary Statement of Intent (SSOI) that also states why the project serves to increase the defense capabilities of the U.S. The SSOI is used to obtain project approval by the Department of the Navy and the Office of the Secretary of War. The North Atlantic Treaty Organization (NATO) R&D cooperative programs differ from other Research, Development, Test and Evaluation (RDT&E) programs because issuance of funding from this PE coincides with the signature of international agreements. These signatures occur throughout the fiscal year and often encounter unexpected delays during the staffing and negotiation phases of agreement processing prior to signature.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603795N$$, $$Land Attack Tech$$, $$rdte_navy_ba4$$, $$peo_ships$$, 2026, 1056000, 12643000, 1686000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 29, "original_pe": "0603795N", "page_header": "Department of the Navy"}$$::jsonb, $$Project 2038: The 25mm MK 38 MOD 2 and MOD 3 Machine Gun Systems (MGS) provide Anti-Surface Warfare (ASUW) and Anti-terrorism and Force Protection (AT/ FP) capability as a simple, stabilized, low cost solution to outfit near-term deployers to counter small boat threats. Over 360 U.S. Navy-owned systems are installed on U.S. Navy AS, CG, CVN, DDG, LCC, LHA, LHD, LSD, OSV, PC class ships, MK VI Patrol Boats and U.S. Coast Guard Fast Response Cutters. Established in order to respond to Joint Urgent Operational Need Statement (JUONS) CC-0558 for Counter Unmanned Aerial Systems (C-UAS), the MK 38 MOD 3 MGS's electro-optical/infra- red sensor, hardware, and software are being upgraded to counter emerging unmanned aerial threats. Initial C-UAS capability was fielded in Q1FY 2020. Incremental improvements are being made to this C-UAS capability, for cybersecurity and to address operability issues. The 30mm MK 38 MOD 4 Gun Weapon System, will introduce greater accuracy, lethality, and effective range for C-UAS and Counter Unmanned Surface Vehicle (C-USV) capability with integration to highly accurate fire control system, 30mm gun, targeting sensor and AEGIS combat system. The MOD 4 will be fielded on all DDG 51 Flight IIA and Flight III AEGIS Destroyers. Project 2038 provides qualification and logistics development of the 30mm MK 38 MOD 4. This will include Function Integration Testing, Functional Acceptance Testing, AEGIS Light-off, Structural Test Firing, and an at-sea Quick Reaction Assessment (on board DDG 89). Upgrading fielded 25mm MK 38 MGS to MOD 3 with C-UAS and concurrently developing and fielding the MK 38 MOD 4 Gun Weapon System (GWS) on all current and future DDG 51 Flight IIA and Flight III Destroyers is the fastest and most cost-effective way to field critical C-UAS ship self-defense capability. MK45 C-UAS MK160/MK20 development to utilize a Hypervelocity Projectile (HVP) munition that was developed for the Army and that capability is being developed to operate within a Naval environment using existing systems. The capability includes developing a low-cost C-UAS solution into the five-inch MK 34-gun weapon system on DDGs. This effort includes development of the fire control software, development of a datalink from the ship, hardware in the loop simulation, system integration testing, and at sea live fire testing. FY2024 CENTCOM Operations Transfer, Israel Security Supplemental (P.L. 118-50, Division A., Sec. 101). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                          Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced        PE 0603795N / Land Attack Tech Component Development & Prototypes (ACD&P)$$, NULL, 975000, 986000, 999000, NULL, NULL, 71, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 1673000, 1056000, 985000, 985000, NULL, 985000, 1018000, $$Project 2038: The 25mm MK 38 MOD 2 and MOD 3 Machine Gun Systems (MGS) provide Anti-Surface Warfare (ASUW) and Anti-terrorism and Force Protection (AT/ FP) capability as a simple, stabilized, low cost solution to outfit near-term deployers to counter small boat threats. Over 360 U.S. Navy-owned systems are installed on U.S. Navy AS, CG, CVN, DDG, LCC, LHA, LHD, LSD, OSV, PC class ships, MK VI Patrol Boats and U.S. Coast Guard Fast Response Cutters. Established in order to respond to Joint Urgent Operational Need Statement (JUONS) CC-0558 for Counter Unmanned Aerial Systems (C-UAS), the MK 38 MOD 3 MGS's electro-optical/infra- red sensor, hardware, and software are being upgraded to counter emerging unmanned aerial threats. Initial C-UAS capability was fielded in Q1FY 2020. Incremental improvements are being made to this C-UAS capability, for cybersecurity and to address operability issues. The 30mm MK 38 MOD 4 Gun Weapon System, will introduce greater accuracy, lethality, and effective range for C-UAS and Counter Unmanned Surface Vehicle (C-USV) capability with integration to highly accurate fire control system, 30mm gun, targeting sensor and AEGIS combat system. The MOD 4 will be fielded on all DDG 51 Flight IIA and Flight III AEGIS Destroyers. Project 2038 provides qualification and logistics development of the 30mm MK 38 MOD 4. This will include Function Integration Testing, Functional Acceptance Testing, AEGIS Light-off, Structural Test Firing, and an at-sea Quick Reaction Assessment (on board DDG 89). Upgrading fielded 25mm MK 38 MGS to MOD 3 with C-UAS and concurrently developing and fielding the MK 38 MOD 4 Gun Weapon System (GWS) on all current and future DDG 51 Flight IIA and Flight III Destroyers is the fastest and most cost-effective way to field critical C-UAS ship self-defense capability.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603801A$$, $$Aviation - Adv Dev$$, $$rdte_army_ba4$$, $$cft_fvl$$, 2026, 0, 1452331000, 4943000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 14, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0603801A", "page_header": "Department of the Army"}$$::jsonb, $$This funding line directly aligns to the Future Vertical Lift (FVL) Army modernization priority. Future Vertical Lift (FVL) is an initiative to develop a family of vertical lift aircraft for the United States Armed Forces. The Department of Defense (DOD) established FVL to focus vertical lift capabilities and technology development as well as retain long-term industrial base capabilities. The Deputy Secretary of Defense issued the FVL Strategic Plan in 2012 to outline a joint approach for the next generation vertical lift aircraft for all military services. The Strategic Plan provided a foundation for replacing the current fleet with advanced capability by shaping the development of vertical lift aircraft for the next 25 to 40 years. In Fiscal Year (FY) 2017, the Army identified FVL as one of the Army's six modernization priorities and established the FVL Cross Functional Team (CFT). The FVL objectives are increased vertical lift maneuverability, range, speed, payload, survivability, and reliability while reducing the logistics footprint. This capability will provide critical vertical lift aviation capability in multi-domain operations to the joint warfighter and maneuver force. The Future Long Range Assault Aircraft (FLRAA) program pursues FVL Capability Set 3 (CS3) and provides Combatant Commanders with deterrence, power projection, and tactical capabilities at operational and strategic distances. The Army competitively awarded the weapon system development contract in December 2022, using a hybrid acquisition approach. The contract award initiated the Rapid Prototyping effort to complete a preliminary design and the development of FLRAA Virtual Prototypes, using Middle Tier of Acquisition (MTA) authorities. The Future Attack Reconnaissance Aircraft (FARA) Capability Set 1 (CS1) was intended to restore reconnaissance dominance by mitigating enemy long-range capabilities by creating lethal effects from outside enemy sensor/weapons range and allowing joint force commanders to maneuver from relative sanctuary. The Army has discontinued the FARA effort beyond FY 2024. Both FLRAA and FARA integrate advanced technologies, using a modular open systems approach, and design configurations with appropriate trades to ensure affordability. This resourcing funds both FLRAA and FARA. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                            Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced          PE 0603801A / Aviation - Adv Dev Component Development & Prototypes (ACD&P)$$, NULL, NULL, NULL, NULL, NULL, NULL, 71, $$RDTE - Vol 2 - Budget Activity 4A.pdf$$, NULL, FALSE, 197292000, 0, NULL, NULL, NULL, NULL, NULL, $$This funding line directly aligns to the Future Vertical Lift (FVL) Army modernization priority. Future Vertical Lift (FVL) is an initiative to develop a family of vertical lift aircraft for the United States Armed Forces. The Department of War (DOW) established FVL to focus vertical lift capabilities and technology development as well as retain long-term industrial base capabilities. The Deputy Secretary of War issued the FVL Strategic Plan in 2012 to outline a joint approach for the next generation vertical lift aircraft for all military services. The Strategic Plan provided a foundation for replacing the current fleet with advanced capability by shaping the development of vertical lift aircraft for the next 25 to 40 years. In Fiscal Year (FY) 2017, the Army identified FVL as one of the Army's six modernization priorities and established the FVL Cross Functional Team (CFT). The FVL objectives are increased vertical lift maneuverability, range, speed, payload, survivability, and reliability while reducing the logistics footprint. This capability will provide critical vertical lift aviation capability in multi-domain operations to the joint warfighter and maneuver force. The Future Long Range Assault Aircraft (FLRAA) program pursues FVL Capability Set 3 (CS3) and provides Combatant Commanders with deterrence, power projection, and tactical capabilities at operational and strategic distances. The Army competitively awarded the weapon system development contract in December 2022, using a hybrid acquisition approach. The contract award initiated the Rapid Prototyping effort to complete a preliminary design and the development of FLRAA Virtual Prototypes, using Middle Tier of Acquisition (MTA) authorities. The Future Attack Reconnaissance Aircraft (FARA) Capability Set 1 (CS1) was intended to restore reconnaissance dominance by mitigating enemy long-range capabilities by creating lethal effects from outside enemy sensor/weapons range and allowing joint force commanders to maneuver from relative sanctuary. The Army has discontinued the FARA effort beyond FY 2024. Both FLRAA and FARA integrate advanced technologies, using a modular open systems approach, and design configurations with appropriate trades to ensure affordability. This resourcing funds both FLRAA and FARA. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                               Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced          PE 0603801A / Aviation - Adv Dev Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L052$$, $$Navy Command and Control System (NCCS)$$, $$proc_navy_1810_ba2$$, $$navsea$$, 2026, 13008000, 4079000, 4680000, NULL, $${"page": 97, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "52", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 48", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 8652, "p1_line_num": 48, "fy27_total_K": 8652}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 13008, "li_num": 48, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA2_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 13008000, "fy26r_cost": 0, "ident_code": ""}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 3645000, 3489000, 8652000, 8652000, 0, 8652000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603807A$$, $$Medical Systems - Adv Dev$$, $$rdte_army_ba4$$, $$usamrdc$$, 2026, 1000000, 7999000, 582000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 14, "original_pe": "0603807A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) funds development of medical materiel within the early system integration portion of the System Development and Demonstration phase of the acquisition life cycle using 6.4 (Advanced Component Development and Prototype) funding. Program efforts support transition of promising Science and Technology candidate medical technologies (drugs, vaccines, medical devices, diagnostics, and mechanisms for detection and control of disease carrying insects) to larger scale testing in humans for safety and effectiveness. Programs are aligned to meet future force requirements identified within concept documents and organizational structures. This PE also provides funding for Food and Drug Administration (FDA) regulated human clinical trials to gain additional information about safety and effectiveness on the path to licensure for use in humans. These efforts are managed by U.S. Army Medical Materiel Development Activity (USAMMDA) of the U.S. Army Medical Research and Development Command. The FY 2026 request was reduced by $0.003 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 1028000, 1038000, 1039000, NULL, NULL, 73, $$RDTE - Vol 2 - Budget Activity 4A.pdf$$, NULL, FALSE, 2071000, 1000000, 1017000, 1017000, NULL, 1017000, 1049000, $$This Program Element (PE) provides funding for the development of medical materiel during the early system integration phase of the System Development and Demonstration stage within the acquisition life cycle, utilizing 6.4 Advanced Component Development and Prototype funding. These efforts are critical to advancing medical technologies that address the Army's future force requirements and operational readiness. Historically, under the United States Army Medical Materiel Development Activity (USAMMDA), this funding supported the transition of promising Science and Technology (S&T) candidate medical technologies-including drugs, vaccines, medical devices, diagnostics, and mechanisms for detecting and controlling disease-carrying insects-into larger-scale human testing to evaluate safety and effectiveness. These efforts were instrumental in bridging the gap between early research and operational deployment. Since the transition to Project Manager Soldier Medical Devices (PM SMD), this funding has been strategically applied to address future force requirements identified in concept documents and organizational structures. PM SMD leverages this funding to develop and integrate advanced medical solutions that enhance Warfighter survivability and operational effectiveness in support of Capability Program Executive Ground (Soldier Systems). These efforts ensure the Army remains equipped with cutting-edge medical technologies to meet the demands of modern and future combat environments. This Program Element represents a vital investment in the Army's medical modernization strategy, enabling the development and fielding of innovative medical solutions that align with the Army's readiness priorities and sustain the health and effectiveness of the force.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603829J$$, $$Joint Capability Experimentation$$, $$rdte_dw_ba6$$, $$dw_js$$, 2026, 13822000, 11949000, 12385000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 75, "original_pe": "0603829J", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 11106000, 11184000, 10967000, NULL, NULL, NULL, NULL, NULL, FALSE, 11926000, 13724000, 12332000, 12332000, NULL, 12332000, 11190000, $$The FY 2019 National Defense Authorization Act (NDAA) included as one of the Chairman’s responsibilities to address experimentation on future concepts. Rigorous experimentation takes place on concepts to ensure Department investments adequately address future requirements as well as those of today. Accordingly, the Joint Staff requires an experimentation capability to analyze and validate priority joint concept required capabilities. The Joint Staff leads, plans, and executes the Global Integrated Wargame (GIWG) events to examine the Joint Warfighting Concept (JWC) operational logic and identified gaps to support delivery of an evaluated concept to the Secretary of War. Concept analysis and validation have a multi-faceted nature to meet the Chairman’s Title 10 responsibility of, “identifying new joint military capabilities based on advances in technology and concepts of operation, and recommending investments and experiments in such capabilities.” Wargames assess baseline missions and campaign level outcomes of the concepts as well as identify tradespace for potential new capabilities. This tradespace of capabilities is further explored with quantitative models and software that identify the most efficient cost and capability tradeoffs to help meet the Title 10 responsibility of “advising the Secretary on new and alternative joint military capabilities, and alternative program recommendations and budget proposals, within projected resource levels.” The Joint Staff approach to tradespace exploration provides a cost conscious and operationally relevant prioritization tradeoff technique early in the portfolio design process. Using this rigorous prioritization approach, the capability development cycle can efficiently focus resources on more detailed experimentation of specific capabilities to inform the requirements process. The analysis from the experimentation program will be used to provide foundational evidence to directly inform the Joint Military Net Assessment (JMNA), the Chairman’s Program Recommendation (CPR), and ultimately the Defense Planning Guidance for Joint Force development. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 The Joint Staff                                                               Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:        PE 0603829J / Joint Capability Experimentation RDT&E Management Support$$, $$Budget J-Books/FY27/Remaining/RDTE_TJS_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603834D8Z$$, $$Biosurveillance Program Advanced Technology Development$$, $$rdte_dw_ba3$$, $$dw$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 8680000, 8000000, 7500000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 9800000, 9800000, NULL, 9800000, 6000000, $$This program exploits advances in technology to develop, improve and implement detection, information processing and decision support for biosurveillance. The mission of this program is to create a fit-for-purpose biosurveillance capability with federated collection, processing, analysis, production, and dissemination capabilities to enable strategic, anticipatory, and operational decision-making for deterrence and risk mitigation. To accomplish this mission, the Biosurveillance Program will: 1) Implement agile planning and response processes through a cross-functional biosurveillance organizational architecture—with the structure, function, and authorities —to support time-sensitive needs of DoW leaders; 2) Expand physical and digital detection capabilities and capacity—infused with intelligence collection—to enable early warning, sustained awareness, and agile response focusing on advanced technological capabilities; 3) Enhance biosurveillance insights by increasing data value, knowledge generation and accelerating processing of existing health and biodefense repositories into a fit-for purpose analytic capability; 4) Communicate the full range of analytic products necessary for leadership decision-making across the continuum of conflict. This budget is justified by the critical gap, identified in the 2023 Biodefense Posture Review, in the Department's ability to gather and analyze timely biothreat information to protect the Joint Force and enhance national security. The funding will establish this necessary capability by operationalizing a Biosurveillance Information Platform (BIP), expanding next-generation sequencing, and improving data sharing. These investments are essential for enhancing readiness and resilience against a dynamic landscape of natural, accidental, and deliberate biological threats. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                           Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:        PE 0603834D8Z / Biosurveillance Program Advanced Technology Development Advanced Technology Development (ATD)$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603838D8Z$$, $$Defense Innovation Acceleration (DIA)$$, $$rdte_dw_ba3$$, $$dw$$, 2026, 211027000, 253884000, 165798000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 70, "original_pe": "0603838D8Z", "page_header": "Defense-Wide", "fy26_v182_disc_K": 211541, "fy26_v182_supp_K": 348860, "fy26_v182_total_K": 560401, "fy26_v182_note_name": "Research, Development, Test & Evaluation, Defense-Wide for OUSW(R&E)", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 15298}$$::jsonb, $$This program supports the Department of Defense’s (DoD) initiatives to “Build a Sustainable and Long-Term Advantage” and “Build a Resilient Joint Force and Defense Ecosystem.” The Defense Innovation Acceleration (DIA) program accelerates innovative capability prototypes (TRL 5-7) that address cross-Service/cross-domain military needs in 12 to 36 months. Operational and strategic capability gaps are identified through the alignment of the Joint Warfighting Concept with mission analysis. DIA focuses on providing prototype systems in support of multi-component experimentation, informing programs of record, and validating requirements. DIA prototypes are evaluated in operationally relevant demonstrations in conjunction with Office of the Assistant Secretary of Defense for Mission Capabilities (OASD(MC)) experimentation events. The demonstrations are assessed by representatives from the Combatant Command (CCMD) staffs who look for military utility in addressing the most pressing capability gaps as ranked by the CCMDs and the Joint Staff. DIA also harnesses small business and non-traditional performer innovation to create prototypes to address DoD’s modernization challenges. In FY26, DIA organized sub-projects by focus areas aligned to specific, persistent capability gaps. Aligning investments by focus areas allows Prototyping and Experimentation (P&E) to rapidly respond to urgent and emergent requirements at the speed of relevance. Focus areas include: Kill Web Interoperability: The processes by which Joint Force Commanders plan, direct, coordinate, and control forces to accomplish assigned missions and enable Joint kill webs. Resilient Communications: The ability to maintain hardened mission-capable systems that allow for secure freedom of communications in contested electromagnetic spectrum environments. This includes alternate position, navigation, and timing. Sensors and Data Analytics: Networks of sensors and data collection assets, data analysis, and dissemination resources used to provide information to the Joint force about strategic and tactical threats. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                 Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:            PE 0603838D8Z / Defense Innovation Acceleration (DIA) Advanced Technology Development (ATD) Collaborative Multi-Domain Autonomy: The use of multi-domain uncrewed systems and autonomy to increase warfighting capabilities and to mitigate/negate risk to warfighters. Contested Logistics / Sustainment: The coordinated use, synchronization, and often sharing of logistics resources to deploy, support, and sustain highly dispersed Joint forces in highly contested environments. This also includes other sustainment areas such as supply chain reduction efforts; additive manufacturing; operational/tactical water purification; and sustainment and transportation innovations. Weapons Kinetic/Non-Kinetic Effects: The delivery of weapon systems and long-range kinetic and non-kinetic effects in support of Joint offensive and defensive tasks to create specific lethal effects on a target. This area includes counter position, navigation, and timing; and techniques designed to deceive enemy observers and/or mitigate, disrupt, or negate adversary capabilities. Emerging Prototypes and Enablers: Supports the acceleration of DoD, CCMD, and Service priority efforts which provide unique capability and/or address critical gaps. This focus area incorporates Combat Support/Combat Enablers; Special Forces Capabilities; Medical Technologies/Devices; Special Access Program assimilation and operational management; prototyping through small business and non-traditional pathways; and the rapid development of technologies for inclusion in experimentation venues.$$, NULL, 321627000, 328654000, 346040000, NULL, NULL, 73, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 160928000, 560401000, 310977000, 310977000, 0, 310977000, 346776000, $$This program supports the Department of War’s (DoW) initiatives to “Build a Sustainable and Long-Term Advantage” and “Build a Resilient Joint Force and Defense Ecosystem.” DIA projects are organized by focus areas aligned to specific, persistent capability gaps. Aligning investments by focus areas allows ODASW Prototyping and Experimentation (P&E) to rapidly respond to urgent and emergent requirements at the speed of relevance. Focus areas include: Kill Web Interoperability: The processes by which Joint Force Commanders plan, direct, coordinate, and control forces to accomplish assigned missions and enable Joint kill webs. Resilient Communications: The ability to maintain hardened mission-capable systems that allow for secure freedom of communications in contested electromagnetic spectrum environments. This includes alternate position, navigation, and timing. Sensors and Data Analytics: Networks of sensors and data collection assets, data analysis, and dissemination resources used to provide information to the Joint force about strategic and tactical threats. Collaborative Multi-Domain Autonomy: The use of multi-domain uncrewed systems and autonomy to increase warfighting capabilities and to mitigate/negate risk to warfighters. Contested Logistics / Sustainment: The coordinated use, synchronization, and often sharing of logistics resources to deploy, support, and sustain highly dispersed Joint forces in highly contested environments. This also includes other sustainment areas such as supply chain reduction efforts; additive manufacturing; operational/tactical water purification; and sustainment and transportation innovations. Weapons Kinetic/Non-Kinetic Effects: Explores the delivery of weapon systems and long-range kinetic and non-kinetic effects in support of joint offensive and defensive tasks to create specific lethal effects on a target; includes techniques designed to deceive enemy observers and/or mitigate, disrupt, or negate adversary capabilities. These subprojects are matured through assessment and experimentation to show their readiness and utility to the warfighter. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                       Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:               PE 0603838D8Z / Defense Innovation Acceleration (DIA) Advanced Technology Development (ATD) Experimentation, Prototypes and Enablers: Supports the acceleration of Department of War, Combatant Command (CCMD), and Service priority efforts which provide unique capability and/or address critical gaps. This focus area incorporates Combat Support/Combat Enablers; Special Forces Capabilities; Medical Technologies/ Devices; Special Access Program assimilation and operational management; prototyping through small business and non-traditional pathways; and the rapid development of technologies for inclusion in experimentation venues. The DIA Program Element resources (1) prototype integration by leveraging existing prototypes and integrating them into broader joint mission threads to increase/drive better joint interoperability and (2) the joint experimentation and assessment (E&A) activities that provides the body of evidence for senior-level decision making on what promising capabilities are transitioned and scaled. DIA addresses department-level joint E&A activities broken down in the following tiers: 1. Tier-1 E&A Activities: Single system/prototype qualification at T-REX sponsored events ISO industry partners, academia, service labs, and OGAs. 2. Tier-2 E&A Activities: Joint Rapid Experimentation (JRE) in support of tactical and/or operational mission threads (e.g., kill-chain closure) usually, but not limited to, sponsored service and Combatant Command (CCMD) exercises. The FY 2026 spend plan amount for Research, Development, Test & Evaluation, Defense-Wide for OUSW(R&E) includes $211,541 thousand of discretionary and $348,860 thousand of mandatory for a total of $560,401 thousand.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1611_L039$$, $$Auxiliary Personnel Lighter$$, $$proc_navy_1611_ba5$$, $$peo_carriers$$, 2026, 295000000, 62532000, 0, NULL, $${"ba": "ba5", "ingest": "v18", "source": "p1_fy27", "line_no": "31", "appr_code": "1611", "fy26_v179": {"disc_K": 6015, "li_num": 33, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/SCN_Book.txt"}, "title_raw": "Tagos Surtass Ships", "fy27_total_K": 710664}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, 722366000, NULL, NULL, NULL, FALSE, 76168000, 79000000, 710664000, NULL, 0, 710664000, NULL, NULL, $$Budget J-Books/FY27/Navy/SCN_Book.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2031_L016$$, $$Future Vertical Lift FAMILY OF SYSTEMS$$, $$proc_army_2031_ba1$$, $$cft_fvl$$, 2026, 0, 153196000, 0, NULL, $${"page": 11, "ba_num": "01", "source": "p1_fy26", "ba_name": "Aircraft", "line_no": "16", "service": "army", "fy24_qty": 26, "fy25_qty": null, "appr_code": "2031", "appr_name": "Aircraft Procurement, Army", "fy26_v178": {"disc_K": 65000, "li_num": 11, "source": "p40_fy26_v178", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Army/Aircraft_Procurement_Army.txt"}, "fy26t_qty": null, "fy26d_cost": 0, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 65000000, 127217000, 127217000, 0, 127217000, NULL, NULL, $$Budget J-Books/FY27/Army/Aircraft_Procurement_Army.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603851D8Z$$, $$Environmental Security Technology Certification Program (ESTCP)$$, $$rdte_dw_ba4$$, $$dw$$, 2026, 123981000, 139998000, 149696000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 70, "original_pe": "0603851D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$The Environmental Security Technology Certification Program (ESTCP) demonstrates and validates innovative technologies for military installations, while its sister program, the Strategic Environmental Research and Development Program (SERDP), invests in applied research to develop these solutions. ESTCP tests promising technologies in relevant operational environments across DoD installations, providing decision-makers with reliable performance and cost data before widespread implementation. By validating solutions under real-world conditions, ESTCP reduces adoption risks and accelerates technology transfer to end users. The program has an excellent track record of return on investment, with many solutions deployed directly to installations without further development. ESTCP conducts formal demonstrations at DoD facilities in operational settings to document and validate improved performance and cost savings. To ensure real impact, ESTCP collaborates with end users and regulators throughout the development and execution of each demonstration. Transition challenges are overcome with rigorous and well-documented demonstrations that provide the information needed by all DoD partners for technology adoption. The program employs a competitive selection process to ensure high-quality demonstrations, issuing solicitations for proposals from government, academia, and industry. Each project develops a formal test and evaluation plan, and demonstration results undergo rigorous technical reviews to ensure conclusions are accurate and supported by data. This process ensures installations receive solutions that address current operational needs and deliver measurable benefits to the Department of Defense. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                               Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:          PE 0603851D8Z / Environmental Security Technology Certification Program (ESTCP) Advanced Component Development & Prototypes (ACD&P)$$, NULL, 133651000, 135548000, 137243000, NULL, NULL, 83, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 147548000, 123298000, 125066000, 125066000, NULL, 125066000, 139913000, $$The Environmental Security Technology Certification Program (ESTCP) demonstrates and validates innovative technologies for military installations, while its companion program, the Strategic Environmental Research and Development Program (SERDP), invests in applied research to develop these solutions. ESTCP tests promising technologies in relevant operational environments across Department of War (DoW) installations, providing decision-makers with reliable performance and cost data before widespread implementation. By validating solutions under real-world conditions, ESTCP reduces adoption risks and accelerates technology transfer to end users. The program has an excellent track record of return on investment, with many solutions deployed directly to installations without further development. ESTCP demonstrations provide innovative, scalable technologies that enhance military readiness, improve warfighter capabilities, and strengthen defense infrastructure, prioritizing common sense, cost effective solutions that support operational effectiveness at military installations. ESTCP conducts formal demonstrations at DoW facilities in operational settings to document and validate improved performance and cost savings. To ensure real impact, ESTCP collaborates with end users and regulators throughout the development and execution of each demonstration. Transition challenges are overcome with rigorous and well-documented demonstrations that provide the information needed by all DoW partners to confidently invest in these innovative, transformative technologies. The program employs a competitive selection process to ensure high-quality demonstrations, issuing solicitations for proposals from government, academia, and industry. Each project develops a formal test and evaluation plan, and demonstration results undergo rigorous technical reviews to ensure conclusions are accurate and supported by data. This process ensures installations receive solutions that address current operational needs and deliver measurable benefits to DoW. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                             Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:         PE 0603851D8Z / Environmental Security Technology Certification Program (ESTCP) Advanced Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603851F$$, $$Intercontinental Ballistic Missile - Dem/Val$$, $$rdte_af_ba4$$, $$afrco$$, 2026, 90096000, 51948000, 125561000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0603851F"}$$::jsonb, $$The Intercontinental Ballistic Missile (ICBM) Demonstration/Validation (Dem/Val) program ensures the development of strategic capabilities in response to United States Strategic Command (USSTRATCOM) Strategic Advisory Group, USSTRATCOM Commander Guidance, and the Defense Science Board Task Force on Nuclear Deterrence. ICBM Dem/Val provides responsive solutions to address emerging threats and issues through technology insertion and technology application for legacy and future ICBM systems, and other common strategic deterrent mission areas. The ICBM Dem/Val program conducts technology maturation and risk reduction activities for new capabilities to support Minuteman (MM) III sustainment, MM III-to-LGM-35A Sentinel weapon system transition, and future ICBM systems development. ICBM Dem/Val conducts advanced component development and prototyping to validate emerging strategic technologies and future upgrades to the ICBM enterprise. Efforts will identify methods to improve system performance, develop potential future Reentry Vehicle (RV) designs, mitigate evolving threats, reduce life-cycle costs, and develop/expand modeling and simulation. Additionally, ICBM Dem/Val will provide experimental platforms for weapon qualification activities, improving nuclear safety and surety and ensuring both the viability and durability of strategic missile systems. The ICBM Dem/Val program will develop key enabling engineering tools for the ICBM mission to include Model Based Systems Engineering (MBSE), test software, and modernization of existing analytical tools. This program will leverage modular system, open architecture, and agile software development to build key enabling engineering tools and future upgrades to ICBMs. The FY 2026 request was reduced by 1.088 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0603851F / Intercontinental Ballistic Missile - Dem/Val Component Development & Prototypes (ACD&P) 0606398F. In FY 2024 0M was expended for civilian pay expenses in this program element, and in FY 2025 0M is forecasted for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 136788000, 125652000, 127742000, NULL, NULL, 35, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 106040000, 117120000, 72112000, 72112000, 0, 72112000, 130327000, $$The Intercontinental Ballistic Missile (ICBM) Demonstration/Validation (Dem/Val) program ensures the development of strategic capabilities in response to United States Strategic Command (USSTRATCOM) Strategic Advisory Group, USSTRATCOM Commander Guidance, and the Defense Science Board Task Force on Nuclear Deterrence. ICBM Dem/Val provides responsive solutions to address emerging threats and issues through technology insertion and technology application for legacy and future ICBM systems, and other common strategic deterrent mission areas. The ICBM Dem/Val program conducts technology maturation and risk reduction activities for new capabilities to support Minuteman (MM) III sustainment, MM III-to-LGM-35A Sentinel weapon system transition, and future ICBM systems development. ICBM Dem/Val conducts advanced component development and prototyping to validate emerging strategic technologies and future upgrades to the ICBM enterprise. Efforts will identify methods to improve system performance, develop potential future Reentry Vehicle (RV) designs, mitigate evolving threats, reduce life-cycle costs, and develop/expand modeling and simulation. Additionally, ICBM Dem/Val will provide experimental platforms for weapon qualification activities, improving nuclear safety and surety and ensuring both the viability and durability of strategic missile systems. The ICBM Dem/Val program will develop key enabling engineering tools for the ICBM mission to include Model Based Systems Engineering (MBSE), test software, and modernization of existing analytical tools. This program will leverage modular system, open architecture, and agile software development to build key enabling engineering tools and future upgrades to ICBMs. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0603851F / Intercontinental Ballistic Missile - Dem/Val Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603851M$$, $$Joint Non-Lethal Weapons Testing$$, $$rdte_navy_ba4$$, $$dw_osd$$, 2026, 9832000, 26838000, 30263000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "mc", "page_num": 29, "original_pe": "0603851M", "page_header": "Department of the Navy"}$$::jsonb, $$The DoD Non-Lethal Weapons (NLW) Program was established by the FY 1996 National Defense Authorization Act. The Office of the Secretary of Defense designated the Commandant of the Marine Corps as the DoD NLW Executive Agent (EA). The EA exercises centralized responsibility for joint research and development of non- lethal weapons and technology through the Joint Non-Lethal Weapons Program (JNLWP). The Office of the Under Secretary of Defense for Acquisition and Sustainment serves as the OSD Principal Staff Assistant and oversees, in consultation with the Under Secretary of Defense for Policy and the DoD NLW Executive Agent. The efforts described in this Program Element (PE) reflect Joint Service research and development (R&D) investment decisions by the Joint Non-Lethal Weapons Integrated Product Team, a multi-service flag level corporate board that provides executive oversight and management of the JNLWP for the EA. Research conducted is based on the requirements and capabilities sought by the Services and the Coast Guard, as identified in the Joint Requirements Oversight Council (JROC) approved Joint Non-Lethal Effects Initial Capabilities Documents. This coordinated Joint Research and Development approach addresses mutual capability gaps and assures the most relevant non-lethal technologies, capabilities, and equipment are provided to the Joint Force while eliminating duplicative Service investment. Advanced Component Development and Prototypes non-lethal weapons initiatives provide non-lethal capabilities in direct support of the National Defense Strategy objective of strategic competition by providing options to the Joint Force in pursuit of national objectives in legal or policy constrained scenarios, as well as complementing the use of lethal effects in complex combat scenarios, for example, in urban environments with large civilian populations. Ongoing NLW studies, analyses, and exercise efforts with NATO and Allies also support NDS objectives to strengthen alliances and partnerships. Resulting capabilities facilitate a fully integrated non-lethal competency as a complement to lethal firepower, providing force application options for below lethal threshold engagements. This PE funds Joint Service research, development, test, and evaluation of non-lethal weapons, devices, munitions, and technologies which provide a non-lethal capability to minimize significant injuries as well as undesired damage to property and the environment. Counter-personnel (CP) and counter-materiel (CM) capability investment areas include directed energy (lasers, millimeter wave, and high power microwave), multi-sensory suppression/incapacitation initiatives (acoustics, optical, electro-muscular incapacitation), and other emergent technologies transitioning from coordinated JNLWP Science and Technology PE initiatives. Investments also focus on Joint and allied experimentation, exercise, demonstration, and assessment of advanced component and prototype initiatives in order to assist transition of suitable and effective capabilities to both joint and allied operational applications. The Joint Intermediate Force Capabilities Office (JIFCO) (formally Joint Non-Lethal Weapons Directorate) is designated as a Research and Development organization and was established by the EA to manage the day to day research and development activities of the DoD's JNLWP. Each Service is responsible for their procurement and operating support costs. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                           Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced        PE 0603851M / Joint Non-Lethal Weapons Testing Component Development & Prototypes (ACD&P)$$, NULL, 11394000, 10464000, 10038000, NULL, NULL, 72, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 29360000, 9832000, 14152000, 14152000, NULL, 14152000, 10296000, $$In recognition of a critical operational need for expanded response options, the FY 1996 National Defense Authorization Act established a Defense Non-Lethal Weapons (NLW) Program. This strategic mandate vested the Commandant of the Marine Corps (CMC) with the centralized responsibility to serve as the program's Executive Agent (EA). This program directly supports the National Defense Strategy (NDS) by developing non-lethal capabilities that give the Joint Force options in legally or politically constrained scenarios. These "intermediate force" options complement lethal firepower, particularly in highly dense, metropolitan based, complex environments where the distinction between combatant and non-combatant is paramount. By providing commanding officers with capabilities designed to preserve life and prevent unintended tragedy, these options demonstrate a profound commitment to humanitarian principles ? a core value that strengthens our alliances with NATO and other key partners. All research and development (R&D) investments are driven by the Joint Non-Lethal Weapons Integrated Product Team, a multi-service flag-level board that provides executive oversight for the Executive Agent (EA). This joint approach addresses capability gaps identified in Joint Requirements Oversight Council (JROC) approved documents, ensuring the most relevant technologies are provided to the warfighter while eliminating duplicative investment across the services. The Joint Intermediate Force Capabilities Office (JIFCO) (formally Joint Non-Lethal Weapons Directorate) is designated as a Research and Development (R&D) organization and was established by the EA to manage the day-to-day research and development activities of the JNLWP. Each Service is responsible for their procurement and operating support costs. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                            Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced         PE 0603851M / Joint Non-Lethal Weapons Testing Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603881C$$, $$Ballistic Missile Defense Terminal Defense Segment$$, $$rdte_dw_ba4$$, $$dw_mda$$, 2026, 646898000, 224457000, 285279000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 70, "original_pe": "0603881C", "page_header": "Defense-Wide"}$$::jsonb, $$The Ballistic Missile Defense Terminal Defense Segment provides vital forward-deployable capabilities to support regional defensive Missile Defense System operations. The THAAD system provides Combatant Commands a globally-transportable, rapidly-deployable capability to intercept and destroy short-range, medium-range, and limited intermediate-range missile threats inside or outside the atmosphere during terminal phase of flight. This Program Element investigates concepts and continues the development and integration of multiple, independent THAAD system builds to address the evolving threat, improve reliability, availability and readiness, defense planning, and improved capability to engage short-range ballistic missile, medium-range ballistic missile, and limited intermediate-range ballistic missile threats. Rapidly evolving rogue and peer missile threats have led to a change in national defense policy. The President's January 27, 2025, Executive Order established a goal of protecting the U.S. citizens, safeguarding critical infrastructure, and securing second-strike capability against missile attack from any adversary. The Missile Defense Agency is responding with speed and intensity to deliver next-generation missile defenses to protect the U.S. against ballistic, hypersonic, cruise, and other advanced missile threats. This program submission reflects changes necessary to meet this evolving mission space. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Missile Defense Agency                                                               Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:             PE 0603881C / Ballistic Missile Defense Terminal Defense Segment Advanced Component Development & Prototypes (ACD&P)$$, NULL, 0, 0, 0, NULL, NULL, 84, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 287414000, 465312000, 0, 0, NULL, 0, 0, $$The Ballistic Missile Defense Terminal Defense Segment provides vital forward-deployable capabilities to support regional defensive Missile Defense System operations. The THAAD system provides Combatant Commands a globally-transportable, rapidly-deployable capability to intercept and destroy short-range, medium-range, and limited intermediate-range missile threats inside or outside the atmosphere during terminal phase of flight. This Program Element investigates concepts and continues the development and integration of multiple, independent THAAD system builds to address the evolving threat, improve reliability, availability and readiness, defense planning, and improved capability to engage short-range ballistic missile, medium-range ballistic missile, and limited intermediate-range ballistic missile threats. Beginning in FY 2027, the responsibility for THAAD Research, Development, Test and Evaluation funding will transfer to the Army to support ongoing development of the THAAD weapon system. This transfer consolidates THAAD resources under Army management, reflecting a realignment of responsibilities and ensuring future requirements are planned and resourced directly within the Army. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Missile Defense Agency                                                        Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:         PE 0603881C / Ballistic Missile Defense Terminal Defense Segment Advanced Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603882C$$, $$Ballistic Missile Defense Midcourse Defense Segment$$, $$rdte_dw_ba4$$, $$dw_mda$$, 2026, 825919000, 866585000, 751963000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 71, "original_pe": "0603882C", "page_header": "Defense-Wide"}$$::jsonb, $$The Ballistic Missile Defense Midcourse Defense Segment enables the GMD Weapon System (GWS) to provide the combatant commands, including USNORTHCOM, with a continuously available (24 hours a day, 7 days a week, 365 days a year) Homeland Defense Weapon System. The GWS contributes to the Missile Defense System by acquiring, developing, demonstrating, deploying, and sustaining an operational Weapon System with Ground Based Interceptors, development of a GWS with a mixed fleet of Ground Based Interceptors and Next Generation Interceptors, improved Warfighter capabilities, and Interceptor Fleet Management. The GWS leverages integration of Missile Defense sensors from across the globe and enables the Ground Based Interceptor to deliver a single kill vehicle to counter allocated threats in space during the midcourse phase of the threat's ballistic trajectory. The Ground Systems consist of the GFC, GMD Communications Network (GCN) / GWS Network Infrastructure (GNI) and Data Terminal (IDT), and GSS. The GFC consists of two (2) GFC nodes at Fort Greely, Alaska (FGA) and at the Missile Defense Integration and Operations Center in Colorado Springs, Colorado. The GFC plans midcourse engagement and provides the human-in-control interface to the Warfighter. As a critical component of Ground Systems, the GFC supports decision- making and command execution. The GCN is the communications network for the GWS and network connection to the Missile Defense System. The GNI serves as a common secure platform improving real-time cyber integration and the ability to detect and respond to cyber events. The IDTs are located at FGA (2); Vandenberg Space Force Base, California (VSFB) (2); Eareckson Air Station, Alaska (1); and Fort Drum, New York (1). The IDTs provide secure communications from the GFC to the in-flight interceptors. The GSS consists of the Launch Support System and Missile Field / Launch Site Components located at FGA and VSFB and provides the hardware and software interfaces between the GFC and the interceptors. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Missile Defense Agency                                                                Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:              PE 0603882C / Ballistic Missile Defense Midcourse Defense Segment Advanced Component Development & Prototypes (ACD&P) The Ground-Based Midcourse Defense Program provides USNORTHCOM with a solution that is lethal across the specified threat space, upgradeable to address future and advancing threats, and fully integrated into the Missile Defense System as demonstrated through flight and ground testing. In addition, product improvements will provide USNORTHCOM with the capability to operate the GWS Weapon System with a mixed fleet of Ground Based Interceptors and Next Generation Interceptors while maintaining a robust cyber defense network capable of detecting and defending against current and future cybersecurity threats. In parallel with product improvements, the Ground-Based Midcourse Defense Program will continue to execute Interceptor Fleet Management and will gain efficiencies utilizing the fleet management approach, which is comprised of sustaining a minimal workforce and infrastructure; maintaining the existing fleet; extending the service life of the Ground Based Interceptors; and executing repairs until retired or replaced by Next Generation Interceptors. Rapidly evolving rogue and peer missile threats have led to a change in national defense policy. The President's January 27, 2025, Executive Order established a goal of protecting the United States (U.S.) citizens, safeguarding critical infrastructure, and securing second-strike capability against missile attack from any adversary. The Missile Defense Agency is responding with speed and intensity to deliver next-generation missile defenses to protect the U.S. against ballistic, hypersonic, cruise, and other advanced missile threats. This program submission reflects changes necessary to meet this evolving mission space.$$, NULL, 1406649000, 1232102000, 986826000, NULL, NULL, 85, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 739110000, 757164000, 1360611000, 1360611000, NULL, 1360611000, 1007747000, $$The Ballistic Missile Defense Midcourse Defense Segment enables the GMD Weapon System (GWS) to provide the combatant commands, including United States Northern Command (USNORTHCOM), with a continuously available (24 hours a day, 7 days a week, 365 days a year) Homeland Defense Weapon System. The GWS contributes to the Missile Defense System by acquiring, developing, demonstrating, deploying, and sustaining an operational Weapon System with Ground Based Interceptors, development of a GWS with a mixed fleet of Ground Based Interceptors and Next Generation Interceptors, improved Warfighter capabilities, and Interceptor Fleet Management. The GWS leverages integration of Missile Defense sensors from across the globe to enable the interceptors to deliver kill vehicles to counter allocated threats in space during the midcourse phase of the threat's ballistic trajectory. The Ground Systems consist of the GFC, GCN / GWS Network Infrastructure (GNI), IDT, and GSS. The GFC consists of two (2) GFC nodes at Fort Greely, Alaska (FGA) and at the Missile Defense Integration and Operations Center in Colorado Springs, Colorado. The GFC plans midcourse engagements and provides the human- in-control interface to the Warfighter. As a critical component of Ground Systems, the GFC supports decision-making and command execution. The GCN is the communications network for the GWS and network connection to the Missile Defense System. The GNI serves as a common secure platform improving real-time cyber integration and the ability to detect and respond to cyber events. The IDTs are located at FGA (2); Vandenberg Space Force Base, California (VSFB) (2); Eareckson Air Station, Alaska (1); and Fort Drum, New York (1). The IDTs provide secure communications from the GFC to the in-flight interceptors. The GSS consists of the Launch Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Missile Defense Agency                                                               Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:        PE 0603882C / Ballistic Missile Defense Midcourse Defense Segment Advanced Component Development & Prototypes (ACD&P) Support System and Missile Field / Launch Site Components located at FGA and VSFB and provides the hardware and software interfaces between the GFC and the interceptors. The Ground-Based Midcourse Defense Program provides USNORTHCOM with a solution that is lethal across the specified threat space, upgradeable to address future and advancing threats, and fully integrated into the Missile Defense System as demonstrated through flight and ground testing. In addition, product improvements will provide USNORTHCOM with the capability to operate the GWS Weapon System with a mixed fleet of Ground Based Interceptors and Next Generation Interceptors while maintaining a robust cyber defense network capable of detecting and defending against current and future cybersecurity threats. In parallel with product improvements, the Ground-Based Midcourse Defense Program will continue to execute Interceptor Fleet Management and will gain efficiencies utilizing the fleet management approach, which is comprised of sustaining a minimal workforce and infrastructure; maintaining the existing fleet; extending the service life of the Ground Based Interceptors; and executing repairs until retired or replaced by Next Generation Interceptors. The funds requested in this PE provide both legacy and Global Missile Defense Capability development for the United States, its deployed forces, allies, and partners. The capabilities funded by this budget request are complementary to the architecture funded by the Golden Dome Program's separate budget request and together fulfill the President's Executive Order 14186. The President's January 27, 2025, Executive Order established a goal of protecting the U.S. citizens, safeguarding critical infrastructure, and securing second-strike capability against missile attack from any adversary. This program and budget in addition to the budget requested by the Golden Dome Program Office reflects the changes necessary to protect the U.S. against ballistic, hypersonic, cruise, and other advanced missile threats.$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603884BP$$, $$Chemical and Biological Defense Program - Dem/Val$$, $$rdte_dw_ba4$$, $$dw_cbdp$$, 2026, 272940000, 283271000, 290064000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 71, "original_pe": "0603884BP", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 368438000, 374055000, 364231000, NULL, NULL, NULL, NULL, NULL, FALSE, 283725000, 267204000, 391307000, 391307000, 0, 391307000, 339324000, $$This program element (PE) resources Advanced Component Development and Prototypes across the Understand, Protect, Mitigate, and Enabling Investments portfolios. Program efforts validate high-risk/high-payoff technologies and their respective concepts of operations for significant improvement to warfighter capabilities in preparation for the transition of mature technologies to advanced development programs requiring chemical and biological (CB) defense technologies. Chemical and Biological Defense Program (CBDP) investments provide an integrated, layered capability to enable Department of War (DoW) missions in a chemical and biological environment, ranging from combat operations to domestic incident prevention and response. The Projects in this PE support component and subsystem maturity prior to integration in major, complex systems and may involve risk reduction initiatives and include technology demonstrations. This effort facilitates transitions of Integrated Early Warning and Integrated Layered Defense products. FY 2027 funding accelerates characterization and situational awareness of emerging biothreats and accelerates delivery of improved protection from and mitigation of biothreats, including rapid repurposing of available therapeutics and development of new vaccines. Individual Projects include: - Understand (UN4): Maintain effort in distinguishing between bacterial, viral, and toxin diagnostics. Update detector libraries for relevant detection and identification systems. Continue efforts to integrate detection capabilities into Service combat platforms. Develop detection and diagnostic technologies with compatibility to receive and transmit sensor data on Service networks. Identify Service concepts for Integrated Early Warning (IEW) and maintain cyber compliance of fielded chemical and biological (CB) information systems. - Protect (PT4): Continued efforts to unencumber the warfighter by delivering improved personal protection capabilities that incorporate inherent survivability into Service equipment and platforms and which offer protection against the diverse threat agents that near-peer adversaries are developing. Develop capability for next-generation individual protective equipment. In collaboration with Biomedical Advanced Research and Development Authority (BARDA), develops and tests monoclonal antibody medical countermeasures through Phase 1 clinical trials as an accelerated antibodies program. Develops a robust computational toolset/prototype database intended to decrease product development risk throughout the drug development life cycle, accelerate candidate development, and enable preemptive preparedness and rapid response. Leveraging the Advanced Development Manufacturing Network, delivers the ability to rapidly develop Medical Countermeasures (MCMs) against emerging or known chemical/biological threats by establishing mature platform technologies that allow for rapid response. Develops plague monoclonal antibody-based medical Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Chemical and Biological Defense Program                                                  Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:          PE 0603884BP / Chemical and Biological Defense Program - Dem/Val Advanced Component Development & Prototypes (ACD&P) countermeasure prototype through Phase 1 clinical testing. Continues work to deliver prototype nucleic acid-based vaccines for five CB threats through non-clinical and human Phase I clinical trials. - Mitigate (MT4): Sustain efforts in antiviral therapeutics. Develop capabilities to incorporate the use of in silico and Machine Learning/Artificial Intelligence technologies for drug discovery and development. Increase efforts regarding platform technologies. Development of repurposing pharmaceuticals that enable a rapid response capability to combat emerging threats. Supports the development of robot decontamination platform systems. Completes prototype development for a sprayable slurry Science & Technology (S&T) transition to decontaminate hardened and sensitive equipment, such as weapon system optics, electronic equipment and spot decontamination on vehicles. Continues prototype development for S&T transitions for tactical temporary coatings that mitigate the effects of a CB attack by protecting assets from the effects of chemical warfare agents. - Enabling Investments (EN4): Development of efforts to evaluate integrated technologies or prototype systems in high fidelity and realistic operating environment, including system-specific efforts that help expedite technology transition from the laboratory to operational use. Increase efforts to improve integration of collective protection into Service major combat platforms. The projects in this PE support the advanced component technology development phase of the DoW acquisition system and are therefore correctly placed in Budget Activity 4.$$, $$Budget J-Books/FY27/DW/RDTE_CBDP_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603884C$$, $$Ballistic Missile Defense Sensors$$, $$rdte_dw_ba4$$, $$dw_mda$$, 2026, 672641000, 239648000, 209002000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 71, "original_pe": "0603884C", "page_header": "Defense-Wide"}$$::jsonb, $$The Missile Defense System network of layered sensors provides essential situational awareness and fire control data for the command and control of Missile Defense System weapon systems, such as Ground-Based Midcourse Defense (GMD), Aegis Ballistic Missile Defense (BMD), and Terminal High Altitude Area Defense (THAAD). The suite of remote ground-based sensors provides early warning, midcourse, and terminal missile defense threat data. This data enables layered detection and tracking of missile targets, providing fire-control quality position, velocity, and discrimination data through GMD Fire Control, or Command and Control, Battle Management and Communications (C2BMC). Overlapping coverage of geographically diverse sensors provides improved threat track data, reduces the impact of the loss of any one sensor, and reduces the potential impact of countermeasures. The extended coverage and accuracy provided by a network of layered sensors increases the defensive footprint and reduces the number of target engagements required, thereby conserving interceptor inventory and maintaining a high probability of successful engagement. Networked forward- based sensors enable C2BMC to pair the best sensor coverage with the best available weapon system to provide the most effective defense against missile threats. Threat discrimination improvements will enhance Missile Defense System effectiveness against the evolving adversary threat. The Missile Defense System Sensors Program contributes to regional and homeland missile defense by developing, delivering, and deploying/redeploying Army Navy/ Transportable Radar Surveillance and Control-2 (AN/TPY-2) radars for operations or tests. AN/TPY-2 radars can be configured to operate as either a THAAD Fire Unit Radar (terminal mode) or a Forward-Based Radar. These radars are transportable and add flexibility to respond to geographical changes in threats. Radars provide early warning tracking and discrimination data through all phases of missile flight. Through the Missile Defense System C2BMC and coalition data links, the AN/TPY-2 provides fire control data to enable remote Standard Missile-3 engagements by Aegis BMD and to cue deployed THAAD and United States (U.S.) and partner Phased Array Tracking Radar to Intercept on Target batteries. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Missile Defense Agency                                                                Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:       PE 0603884C / Ballistic Missile Defense Sensors Advanced Component Development & Prototypes (ACD&P) The Missile Defense System sensor network includes the U.S. Space Force (USSF) COBRA DANE (CD) Radar at Eareckson Air Station, AK, and the USSF Upgraded Early Warning Radars (UEWRs) at Beale Air Force Base, CA; Cape Cod Space Force Station (SFS), MA; Clear SFS, AK; Royal Air Force Fylingdales, United Kingdom; and Pituffik Space Base, Greenland, for defense of the homeland. This program element supports sensors Modeling and Simulation development of digital and hardware-in-the-loop models to support Integrated Master Test Plan events and testing for Missile Defense System assessments of the Long Range Discrimination Radar, AN/TPY-2, Sea-Based X-Band, UEWR, and CD radar. This program element also supports the planning and deployment of persistent radars. Cyber Operations sustain the Risk Management Framework (RMF) and Controls Validation Testing activities, analysis of validation results, risk assessments, reviews of plans of action and milestones, and alignment and integration to the Tier 2 Cybersecurity Service Provider for the Ground Sensors mission and support systems. Cyber Operations supports the execution of lab-based developmental cyber testing (Baseline Assessment Technical Testing, Cooperative Vulnerability Identification and Adversarial Cybersecurity Developmental Test and Evaluation) for all major mission system software version releases. These efforts position Ground Sensor assets to complete the transition to National Institute of Standards and Technology Special Publication 800-53 Revision 5 requirements (e.g. RMF 2.0) and enhance software supply chain security by developing and maintaining the software bill of materials for all developed and delivered Ground Sensors mission and support software as directed in the President's Executive Order on Improving the Nation's Cybersecurity dated May 12, 2021. Rapidly evolving rogue and peer missile threats have led to a change in national defense policy. The President's January 27, 2025, Executive Order established a goal of protecting the U.S. citizens, safeguarding critical infrastructure, and securing second-strike capability against missile attack from any adversary. The Missile Defense Agency is responding with speed and intensity to deliver next-generation missile defenses to protect the U.S. against ballistic, hypersonic, cruise, and other advanced missile threats. This program submission reflects changes necessary to meet this evolving mission space.$$, NULL, 897508000, 720356000, 534481000, NULL, NULL, 87, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 226654000, 181320000, 865420000, 865420000, NULL, 865420000, 723643000, $$The Missile Defense System network of layered sensors provides essential situational awareness and fire control data for the command and control of Missile Defense System weapon systems, such as Ground-Based Midcourse Defense (GMD) and Aegis Based Defense. The suite of remote ground-based sensors provides missile defense threat data through all phases of missile flight. This data enables layered detection and tracking of missile targets, providing fire-control quality position, velocity, and discrimination data through GMD Fire Control, or Command and Control, Battle Management and Communications (C2BMC). Overlapping coverage of geographically diverse sensors provides improved threat track data, reduces the impact of the loss of any one sensor, and reduces the potential impact of countermeasures. The extended coverage and accuracy provided by a network of layered sensors increases the defensive footprint and reduces the number of target engagements required, thereby conserving interceptor inventory and maintaining a high probability of successful engagement. Networked forward- based sensors enable C2BMC to pair the best sensor coverage with the best available weapon system to provide the most effective defense against missile threats. Threat discrimination improvements will enhance Missile Defense System effectiveness against the evolving adversary threat. The Missile Defense System Sensors Program Element contributes to regional and homeland missile defense by developing, delivering, and deploying/redeploying Forward-based Army Navy/Transportable Radar Surveillance and Control-2 (AN/TPY-2) radars for operations or tests. Forward-based Mode AN/TPY-2 radars add flexibility to respond to geographical changes in threats. Radars provide early warning tracking and discrimination data through all phases of missile flight. Through the Missile Defense System C2BMC and coalition data links, the AN/TPY-2 provides fire control data to enable remote Standard Missile-3 engagements by Aegis Based Defense and to cue deployed Terminal High Altitude Area Defense (THAAD) and United States (U.S.) and partner Phased Array Tracking Radar to Intercept on Target batteries. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Missile Defense Agency                                                               Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:       PE 0603884C / Ballistic Missile Defense Sensors Advanced Component Development & Prototypes (ACD&P) The Missile Defense System sensor network includes the U.S. Space Force (USSF) COBRA DANE (CD) Radar at Eareckson Air Station, AK, and the USSF Upgraded Early Warning Radar (UEWR) System at Beale Air Force Base, CA; Cape Cod Space Force Station (SFS), MA; Clear SFS, AK; Royal Air Force Fylingdales, United Kingdom; and Pituffik Space Base, Greenland, for defense of the homeland. This PE supports sensors Modeling and Simulation development of digital and hardware-in-the-loop models to support Integrated Master Test Plan events and testing for Missile Defense System assessments of the Long Range Discrimination Radar, AN/TPY-2, Sea-Based X-Band, UEWR, and CD radar. This PE also supports the planning and deployment of persistent radars. Cyber Operations sustain the Risk Management Framework (RMF) and Controls Validation Testing activities, analysis of validation results, risk assessments, reviews of plans of action and milestones, and alignment and integration to the Tier 2 Cybersecurity Service Provider for the Ground Sensors mission and support systems. Cyber Operations supports the execution of lab-based developmental cyber testing (Baseline Assessment Technical Testing, Cooperative Vulnerability Identification and Adversarial Cybersecurity Developmental Test and Evaluation) for all major mission system software version releases. These efforts position Ground Sensor assets to complete the transition to National Institute of Standards and Technology Special Publication 800-53 Revision 5 requirements (e.g. RMF 2.0) and enhance software supply chain security by developing and maintaining the software bill of materials for all developed and delivered Ground Sensors mission and support software as directed in the President's Executive Order on Improving the Nation's Cybersecurity dated May 12, 2021. The funds requested in this PE provide both legacy and Global Missile Defense Capability development for the United States, its deployed forces, allies, and partners. The capabilities funded by this budget request are complementary to the architecture funded by the Golden Dome Program's separate budget request and together fulfill the President's Executive Order 14186. The President's January 27, 2025, Executive Order established a goal of protecting the U.S. citizens, safeguarding critical infrastructure, and securing second-strike capability against missile attack from any adversary. This program and budget in addition to the budget requested by the Golden Dome Program Office reflects the changes necessary to protect the U.S. against ballistic, hypersonic, cruise, and other advanced missile threats.$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603889N$$, $$Counterdrug RDT&E Projects$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 9500000, 6500000, 2500000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 6500000, 6500000, NULL, 6500000, 0, $$The details of this budget justification are classified, per Executive Order 13526, Sec 1.4 (a) and are submitted annually to Congress in the classified budget justification book.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603890C$$, $$BMD Enabling Programs$$, $$rdte_dw_ba4$$, $$dw_mda$$, 2026, 727039000, 578335000, 602314000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 71, "original_pe": "0603890C", "page_header": "Defense-Wide"}$$::jsonb, $$The Missile Defense System Enabling Programs provide critical products and processes needed to combine element missile defense capabilities into a single, integrated, and layered System to counter existing threats and provide new defensive capabilities against emerging threats. Specifically, the Enabling Programs: Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Missile Defense Agency                                                               Date: June 2025 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:                PE 0603890C / BMD Enabling Programs Advanced Component Development & Prototypes (ACD&P) - Analyze and assess architecture alternatives and new technologies to address advanced threats, define Missile Defense System functional requirements, and provide engineering requirements, execution support, and pre- and post-mission analysis for System-level tests. - Provide validated models and simulations for System assessment. - Improve Missile Defense System effectiveness against the evolving adversary threat through threat discrimination improvements. - Assess and document System performance (through data collection and analysis) and deliver capabilities to the Warfighter. - Provide multi-disciplinary security and intelligence support for acquisition, development, test, and deployment of current and future Missile Defense System capabilities. - Identify potential threats and vulnerabilities to the MDA and the Missile Defense System and develop and implement strategies to mitigate those risks. - Provide Information Management tools and products supporting the development of Missile Defense System capabilities while safeguarding networks and critical program information. - Provide MDA secure communication networks, information technology systems, special purpose processing nodes, operations and monitoring centers, and disaster recovery and continuity of operations requirements. - Evaluate quality, technical safeguards, and mission assurance effectiveness. - Assess System ability to maintain integrity and superiority with advances in technology development. Rapidly evolving rogue and peer missile threats have led to a change in national defense policy. The President's January 27, 2025, Executive Order established a goal of protecting the United States (U.S.) citizens, safeguarding critical infrastructure, and securing second-strike capability against missile attack from any adversary. The MDA is responding with speed and intensity to deliver next-generation missile defenses to protect the U.S. against ballistic, hypersonic, cruise, and other advanced missile threats. This program submission reflects changes necessary to meet this evolving mission space.$$, NULL, 1398656000, 1342746000, 1321929000, NULL, NULL, 88, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 611095000, 599861000, 1457437000, 1457437000, NULL, 1457437000, 1348430000, $$The Missile Defense System Enabling Programs provide critical products and processes needed to combine element missile defense capabilities to develop, test, and deliver layered and integrated missile defense capabilities as part of a comprehensive missile defeat approach to defend the United States (U.S.), its deployed forces, allies, and friends from missile attacks in all phases of flight. Specifically, the Enabling Programs: - Deliver rigorous, compliant, and effective IT infrastructure for efficient delivery in support of Missile Defense System programs. - Analyze and assess architecture alternatives and new technologies to address advanced threats, define current and future functional requirements, and provide engineering requirements, execution support, and pre- and post-mission analysis for System-level tests and Real World Events. - Provide innovative technical solutions to develop performance and interface requirements for IAMD and demonstrate kill chain capabilities across Service and partner nation systems. - Provide validated models and simulations for System assessment. - Improve Missile Defense System effectiveness against the evolving adversary threat through threat discrimination improvements. - Assess and document System performance (through data collection and analysis) and deliver capabilities to the Warfighter. - Provide multi-disciplinary security and intelligence support for acquisition, development, test, and deployment of current and future Missile Defense System capabilities. - Identify potential threats and vulnerabilities to the MDA and the Missile Defense System and develop and implement strategies to mitigate those risks. - Provide Information Management tools and products supporting the development of Missile Defense System capabilities while safeguarding networks and critical program information. - Provide MDA secure communication networks, information technology systems, special purpose processing nodes, operations and monitoring centers, and disaster recovery and continuity of operations requirements. - Evaluate quality, technical safeguards, and mission assurance effectiveness. - Assess System ability to maintain integrity and superiority with advances in technology development. - Provide Agency-wide Defensive Cyberspace Operations capabilities, support, and operations. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Missile Defense Agency                                                               Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:               PE 0603890C / BMD Enabling Programs Advanced Component Development & Prototypes (ACD&P) The funds requested in this PE provide both legacy and Global Missile Defense Capability development for the United States, its deployed forces, allies, and partners. The capabilities funded by this budget request are complementary to the architecture funded by the Golden Dome Program's separate budget request and together fulfill the President's Executive Order 14186. The President's January 27, 2025, Executive Order established a goal of protecting the U.S. citizens, safeguarding critical infrastructure, and securing second-strike capability against missile attack from any adversary. This program and budget in addition to the budget requested by the Golden Dome Program Office reflects the changes necessary to protect the U.S. against ballistic, hypersonic, cruise, and other advanced missile threats.$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603891C$$, $$Special Programs - MDA$$, $$rdte_dw_ba4$$, $$dw_mda$$, 2026, 821430000, 551028000, 495570000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 71, "original_pe": "0603891C", "page_header": "Defense-Wide"}$$::jsonb, $$This program is reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program Annual Report to Congress.$$, NULL, 1733026000, 1642558000, 1691308000, NULL, NULL, 89, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 477352000, 443130000, 1742778000, 1742778000, NULL, 1742778000, 1685225000, $$This program is reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program Annual Report to Congress. The funds requested in this PE provide both legacy and Global Missile Defense Capability development for the United States, its deployed forces, allies, and partners. The capabilities funded by this budget request are complementary to the architecture funded by the Golden Dome Program's separate budget request and together fulfill the President's Executive Order 14186. The President's January 27, 2025, Executive Order established a goal of protecting the U.S. citizens, safeguarding critical infrastructure, and securing second-strike capability against missile attack from any adversary. This program and budget in addition to the budget requested by the Golden Dome Program Office reflects the changes necessary to protect the U.S. against ballistic, hypersonic, cruise, and other advanced missile threats.$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603892C$$, $$AEGIS BMD$$, $$rdte_dw_ba4$$, $$dw$$, 2026, 994440000, 601051000, 649255000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 71, "original_pe": "0603892C", "page_header": "Defense-Wide"}$$::jsonb, $$The Aegis Based Defense mission is to deliver an enduring, operationally effective and supportable Ballistic Missile Defense (BMD) capability to defend the nation, deployed forces, friends and allies, and to increase this capability by delivering evolutionary improvements as part of Missile Defense System upgrades. The Aegis Based Defense element of the Missile Defense System capitalizes upon and evolves from the existing United States Navy Aegis Weapon System (AWS) and Standard Missile (SM) infrastructures. Aegis Based Defense provides a forward-deployable, mobile capability to detect and track Ballistic and Hypersonic Missiles of all ranges, and the ability to destroy Short-Range Ballistic Missiles, Medium-Range Ballistic Missiles, and Intermediate-Range Ballistic Missiles in the midcourse phase of flight, and shorter range missiles in the terminal phase of flight. Aegis Based Defense also provides a Long Range Surveillance and Track capability to the Missile Defense System. Upgrades to both the Aegis BMD Weapon System and the SM-3 configuration enable Aegis Based Defense to provide effective, supportable defensive capability against longer range, threats and an enduring Aegis Ashore defensive capability. This Program Element also provides the development of the AWS Software configuration for the Aegis portion of the Defense of Guam, including capabilities for defense against advanced ballistic threats and integration of Land Based Radar configuration. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Missile Defense Agency                                                                Date: June 2025 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:                 PE 0603892C / AEGIS BMD Advanced Component Development & Prototypes (ACD&P) Rapidly evolving rogue and peer missile threats have led to a change in national defense policy. The President's January 27, 2025, Executive Order established a goal of protecting the United States (U.S.) citizens, safeguarding critical infrastructure, and securing second-strike capability against missile attack from any adversary. The Missile Defense Agency is responding with speed and intensity to deliver next-generation missile defenses to protect the U.S. against ballistic, hypersonic, cruise, and other advanced missile threats. This program submission reflects changes necessary to meet this evolving mission space.$$, NULL, 958040000, 883404000, 889738000, NULL, NULL, 90, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 653640000, 550988000, 927870000, 927870000, NULL, 927870000, 781769000, $$The Aegis Based Defense mission is to deliver an enduring, operationally effective, and supportable BMD capability to defend the nation, deployed forces, friends and allies, and to increase this capability by delivering evolutionary improvements as part of Missile Defense System upgrades. The Aegis Based Defense element of the Missile Defense System capitalizes upon and evolves from the existing United States Navy Aegis Weapon System and SM infrastructures. Aegis Based Defense provides a forward-deployable, mobile capability to detect and track Ballistic and Hypersonic Missiles of all ranges, and the ability to destroy Short Range Ballistic Missiles, Medium-Range Ballistic Missiles, and Intermediate-Range Ballistic Missiles in the midcourse phase of flight, and shorter-range missiles in the terminal phase of flight. Aegis Based Defense also provides a Long Range Surveillance and Track capability to the Missile Defense System. Upgrades to both the Aegis BMD Weapon System and the SM-3 configuration enable Aegis Based Defense to provide effective, supportable defensive capability against longer range, threats and an enduring Aegis Ashore defensive capability. This Program Element also provides the development of the Aegis Weapon System Software configuration for the Aegis portion of the Defense of Guam, including capabilities for defense against advanced ballistic threats and integration of Land Based Radar configuration. The funds requested in this PE provide both legacy and Global Missile Defense Capability development for the United States, its deployed forces, allies, and partners. The capabilities funded by this budget request are complementary to the architecture funded by the Golden Dome Program's separate budget request and together Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Missile Defense Agency                                                               Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:               PE 0603892C / AEGIS BMD Advanced Component Development & Prototypes (ACD&P) fulfill the President's Executive Order 14186. The President's January 27, 2025, Executive Order established a goal of protecting the U.S. citizens, safeguarding critical infrastructure, and securing second-strike capability against missile attack from any adversary. This program and budget in addition to the budget requested by the Golden Dome Program Office reflects the changes necessary to protect the U.S. against ballistic, hypersonic, cruise, and other advanced missile threats.$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603896C$$, $$Ballistic Missile Defense Command and Control, Battle Management & C$$, $$rdte_dw_ba4$$, $$dw$$, 2026, 1067183000, 540198000, 551810000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 71, "original_pe": "0603896C", "page_header": "Defense-Wide"}$$::jsonb, $$The C2BMC program is the integrating element of the Missile Defense System. A combat proven operational system, C2BMC enables the United States (U.S.) President, Secretary of Defense and Combatant Commanders at strategic, regional and operational levels to collectively see the battle develop, to dynamically manage designated networked sensors, and to coordinate management of weapons systems to effectively leverage the full range of defense resources against a diverse range of missile threats. Systems linked to C2BMC include, but are not limited to: Patriot, Terminal High Altitude Area Defense, Aegis Ballistic Missile Defense, Aegis Ashore, Ground-based Midcourse Defense, Army Integrated Air and Missile Defense Battle Command System, and sensors such as the Army Navy/Transportable Radar Surveillance and Control-2 Radar, Sea-Based X-Band Radar, Long Range Discrimination Radar, Homeland Defense, Space-Based Infrared System, and Ballistic Missile Defense Systems Overhead Persistent Infrared Architecture. To these linked systems, C2BMC can provide a common operational picture and, to Aegis and Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Missile Defense Agency                                                                Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:              PE 0603896C / Ballistic Missile Defense Command and Control, Battle Management & C Advanced Component Development & Prototypes (ACD&P)                               ommunication Ground-based Midcourse Defense in particular, can provide direct fire-control support with fire-control quality data on incoming threats. The C2BMC program also works to increase U.S. and coalition partners' command and control and battle management functions through concept exploration, system engineering, analysis, development, integration, and testing of future integrated air/space and missile defense capabilities. C2BMC continues to integrate additional multi-mission sensor elements within the Missile Defense Agency (MDA), the Services, and other partners into the Ballistic Missile Defense System Communications Network to establish a globally integrated sensor architecture to provide enhanced, dynamic space capabilities, and extend existing Ballistic Missile Defense System Communications Network and cybersecurity management to cover the expanded architecture. Under the MDA's Defense of Guam Program, the C2BMC program is integrating Missile Defense and Joint systems, establishing a permanent Command Center and providing required communication support throughout the island. Rapidly evolving rogue and peer missile threats have led to a change in national defense policy. The President's January 27, 2025, Executive Order established a goal of protecting the U.S. citizens, safeguarding critical infrastructure, and securing second-strike capability against missile attack from any adversary. The MDA is responding with speed and intensity to deliver next-generation missile defenses to protect the U.S. against ballistic, hypersonic, cruise, and other advanced missile threats. This program submission reflects changes necessary to meet this evolving mission space.$$, NULL, 1348297000, 1241623000, 1264198000, NULL, NULL, 91, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 567620000, 597396000, 939987000, 939987000, NULL, 939987000, 1194946000, $$The C2BMC program is the integrating element of the Missile Defense System. A combat proven operational system, C2BMC enables the United States (U.S.) President, Secretary of War and Combatant Commanders at strategic, regional and operational levels to collectively see the battle develop, to dynamically manage designated networked sensors, and to coordinate management of weapons systems to effectively leverage the full range of defense resources against a diverse range of missile threats. Systems linked to C2BMC include, but are not limited to: Patriot, Terminal High Altitude Area Defense, Aegis Ballistic Missile Defense, Aegis Ashore, Ground-based Midcourse Defense, Army Integrated Air and Missile Defense Battle Command System, and sensors such as the Army Navy/Transportable Radar Surveillance and Control-2 Radar, Sea-Based X-Band Radar, Long Range Discrimination Radar, Homeland Defense, Space-Based Infrared System, and Ballistic Missile Defense Systems Overhead Persistent Infrared Architecture. To these linked systems, C2BMC can provide a common operational picture and, to Aegis and Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Missile Defense Agency                                                               Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:              PE 0603896C / Ballistic Missile Defense Command and Control, Battle Management & C Advanced Component Development & Prototypes (ACD&P)                               ommunication Ground-based Midcourse Defense in particular, can provide direct fire-control support with fire-control quality data on incoming threats. The C2BMC program also works to increase U.S. and coalition partners' command and control and battle management functions through concept exploration, system engineering, analysis, development, integration, and testing of future integrated air/space and missile defense capabilities. C2BMC continues to integrate additional multi-mission sensor elements within the Missile Defense Agency (MDA), the Services, and other partners into the Ballistic Missile Defense System Communications Network to establish a globally integrated sensor architecture to provide enhanced, dynamic space capabilities, and extend existing Ballistic Missile Defense System Communications Network and cybersecurity management to cover the expanded architecture. Under the MDA's Defense of Guam Program, the C2BMC program is integrating Missile Defense and Joint systems, establishing a permanent Command Center and providing required communication support throughout the island. The funds requested in this PE provide both legacy and Global Missile Defense Capability development for the United States, its deployed forces, allies, and partners. The capabilities funded by this budget request are complementary to the architecture funded by the Golden Dome Program's separate budget request and together fulfill the President's Executive Order 14186. The President's January 27, 2025, Executive Order established a goal of protecting the U.S. citizens, safeguarding critical infrastructure, and securing second-strike capability against missile attack from any adversary. This program and budget in addition to the budget requested by the Golden Dome Program Office reflects the changes necessary to protect the U.S. against ballistic, hypersonic, cruise, and other advanced missile threats.$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603898C$$, $$Ballistic Missile Defense Joint Warfighter Support$$, $$rdte_dw_ba4$$, $$dw_mda$$, 2026, 45758000, 47869000, 47723000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 71, "original_pe": "0603898C", "page_header": "Defense-Wide"}$$::jsonb, $$The Joint Warfighter Support Program (JWSP) is the Missile Defense Agency's (MDA's) primary means for providing direct technical support to Combatant Commands (CCMDs), the Military Services, and the Joint Staff on Missile Defense System development, testing, operational support, and configuration management. It enables delivery of Missile Defense System capabilities to Warfighters and ensures their participation in the identification and development of new Missile Defense (MD) capabilities via the Warfighter Involvement Process. The JWSP allows the Warfighter and MDA to work together to identify gaps, seams, and needs in warfighting capability and enhance Missile Defense System attributes by submitting modification and fielding requests. The JWSP administers the global asset management process ensuring Warfighters know what assets are available to support the missile defense fight. This process coordinates and deconflicts schedules to optimize operational availability of assets while maximizing Missile Defense System capability and meeting minimum required defense requirements. It also provides 24 hours a day, 7 days a week, 365 days a year MD operational support to Warfighters worldwide, to include global system verification and validation over the operational Common Interactive Broadcast. The program enables rapid response to Warfighter Requests for Information and Requests for Analyses, which are especially critical to mission success in protecting U.S. Forces and other defended assets during Real World threat events. The program also supports improving products delivered to Warfighters through technical reviews and technical analyses supporting strategic and regional MD planning, development of shot doctrine and MD design. The JWSP also enables the inclusion of both CCMD and MDA MD objectives in CCMD/Joint Staff-sponsored Wargames and Exercises, which are used to sharpen and enhance joint MD warfighting skills. Finally, the JWSP administers all Navy Reserve support personnel and handles coordination for Army, Air Force and Space Force Reserve that provide technical, engineering, intelligence, integration, and operational support to the MDA. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Missile Defense Agency                                                      Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:       PE 0603898C / Ballistic Missile Defense Joint Warfighter Support Advanced Component Development & Prototypes (ACD&P)$$, NULL, 49082000, 50475000, 52207000, NULL, NULL, 92, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 49233000, 45545000, 50430000, 50430000, NULL, 50430000, 52451000, $$The Joint Warfighter Support Program (JWSP) is the Missile Defense Agency's (MDA's) primary means for providing direct technical support to Combatant Commands (CCMDs), the Military Services, and the Joint Staff on Missile Defense System development, testing, operational support of CCMD Operational Plans (OPLANs), and configuration management. The JWSP performs Force Development functions which enables delivery of Missile Defense System capabilities to Warfighters and ensures their participation in the identification and development of new Missile Defense (MD) capabilities. The JWSP allows the Warfighter and MDA to work together to identify gaps, seams, and needs in warfighting capability and enhance Missile Defense System attributes by submitting modification and fielding requests. The JWSP administers the global asset management process ensuring Warfighters know what assets are available to support the missile defense fight. This process coordinates and deconflicts schedules to optimize operational availability of assets while maximizing Missile Defense System capability and meeting minimum required defense requirements. It also provides 24 hours a day, 7 days a week, 365 days a year MD operational support to Warfighters worldwide, to include global system verification and validation over the operational Common Interactive Broadcast. The program enables rapid response to Warfighter Requests for Information and Requests for Analyses, which are especially critical to mission success in protecting United States Forces and other defended assets during Real World threat events. The program also supports improving products delivered to Warfighters through technical reviews and technical analyses supporting strategic and regional MD planning, development of shot doctrine and MD design. The JWSP also enables the inclusion of both CCMD and MDA MD objectives in CCMD/Joint Staff-sponsored Wargames and Exercises, which are used to sharpen and enhance joint MD warfighting skills. Finally, the JWSP administers all Navy Reserve support personnel and handles coordination for Army, Air Force, and Space Force Reserve that provide technical, engineering, intelligence, integration, and operational support to the MDA. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Missile Defense Agency                                                         Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:          PE 0603898C / Ballistic Missile Defense Joint Warfighter Support Advanced Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603904C$$, $$Missile Defense Integration and Operations Center (MDIOC)$$, $$rdte_dw_ba4$$, $$dw_mda$$, 2026, 55097000, 59203000, 54525000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 71, "original_pe": "0603904C", "page_header": "Defense-Wide"}$$::jsonb, $$The MDIOC is the Missile Defense Agency's (MDA) field operating activity in Colorado Springs, Colorado. The MDIOC provides necessary infrastructure and support services through a mission execution platform for MDA elements/components and designated Combatant Commanders' Missile Defense System operations executing missions at the MDIOC. The Integration and Operations Center is responsible for providing a single, integrated set of skilled personnel matrixed from across MDA to manage this mission. The MDIOC mission facilities consist of a highly secure research and development complex and a consolidated support facility located at Schriever Space Force Base, just east of North American Aerospace Defense Command, United States Northern Command and United States Space Command. The MDIOC provides mission essential system technical capabilities and subject matter expertise in a dedicated and adaptable environment that enables developers, testers, and operators to evolve, assess and deliver the capabilities for layered missile defense execution for homeland defense and theater/regional support. The MDIOC interfaces with the Information Technology and Cybersecurity Enterprise to provide high availability access to worldwide secure communications, network health and status monitoring, mission critical restoral capability, and technical expertise for all MDA directed activities and events. The MDIOC functions as the mission control for Missile Defense System distributed ground tests and system wide flight tests enabling the mission and test directors to control both main and associated test operations using secure voice, test, and mission network hubs from the MDIOC. The MDIOC also functions as the only system-level integration and interoperability mission execution platform for Missile Defense System fire control; and it provides the physical interface between the developers and the Combatant Command (CCMD) warfighters. MDIOC mission facilities contribute to the Missile Defense System by directly supporting the concept of Concurrent Test, Training, and Operations by providing mission assurance, engineering integration, resource scheduling, and configuration management for MDA and Missile Defense System-level test, training, and operational mission execution. MDIOC Major Program Goals: - Provide the capabilities and services necessary to support mission assurance, engineering integration, resource scheduling for ground and flight tests, and configuration management of on-site systems and services. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Missile Defense Agency                                                           Date: June 2025 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:                PE 0603904C / Missile Defense Integration and Operations Center (MDIOC) Advanced Component Development & Prototypes (ACD&P) - Ensure around the clock support and restoral of designated Missile Defense System operational systems and services. - Maintain interface with designated CCMD missile defense activities; host/support the headquarters and operations center for the United States Space Command's Joint Functional Component Command for Integrated Missile Defense. - Maintain and improve the reliability, availability, and maintainability of MDIOC mission critical systems.$$, NULL, 59522000, 63661000, 61621000, NULL, NULL, 93, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 53551000, 51514000, 57892000, 57892000, NULL, 57892000, 62608000, $$The MDIOC is the Missile Defense Agency's (MDA) field operating activity in Colorado Springs, Colorado. The MDIOC provides necessary infrastructure and support services through a mission execution platform for MDA elements/components and designated Combatant Commanders' Missile Defense System operations executing missions at the MDIOC. The Integration and Operations Center is responsible for providing a single, integrated set of skilled personnel matrixed from across MDA to manage this mission. The MDIOC mission facilities consist of a highly secure research and development complex and a consolidated support facility located at Schriever Space Force Base, just east of North American Aerospace Defense Command, United States Northern Command and United States Space Command. The MDIOC provides mission essential system technical capabilities and subject matter expertise in a dedicated and adaptable environment that enables developers, testers, and operators to evolve, assess and deliver the capabilities for layered missile defense execution for homeland defense and theater/regional support. The MDIOC interfaces with the Information Technology and Cybersecurity Enterprise to provide high availability access to worldwide secure communications, network health and status monitoring, mission critical restoral capability, and technical expertise for all MDA directed activities and events. The MDIOC functions as the mission control for Missile Defense System distributed ground tests and system wide flight tests enabling the mission and test directors to control both main and associated test operations using secure voice, test, and mission network hubs from the MDIOC. The MDIOC also functions as the only system-level integration and interoperability mission execution platform for Missile Defense System fire control; and it provides the physical interface between the developers and the Combatant Command (CCMD) warfighters. MDIOC mission facilities contribute to the Missile Defense System by directly supporting the concept of Concurrent Test, Training, and Operations by providing mission assurance, engineering integration, resource scheduling, and configuration management for MDA and Missile Defense System-level test, training, and operational mission execution. MDIOC Major Program Goals: - Provide the capabilities and services necessary to support mission assurance, engineering integration, resource scheduling for ground and flight tests, and configuration management of on-site systems and services. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Missile Defense Agency                                                           Date: April 2026 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:                PE 0603904C / Missile Defense Integration and Operations Center (MDIOC) Advanced Component Development & Prototypes (ACD&P) - Ensure around-the-clock support and restoral of designated Missile Defense System operational systems and services. - Maintain interface with designated CCMD missile defense activities; host/support the headquarters and operations center for the United States Space Command's Joint Functional Component Command for Integrated Missile Defense. - Maintain and improve the reliability, availability, and maintainability of MDIOC mission critical systems.$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603907C$$, $$Sea Based X-Band Radar (SBX)$$, $$rdte_dw_ba4$$, $$dw_mda$$, 2026, 166813000, 174993000, 197339000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 71, "original_pe": "0603907C", "page_header": "Defense-Wide"}$$::jsonb, $$The Sea Based X-Band Radar (SBX) is an advanced X-Band Radar capable of mid-course acquisition, tracking, discrimination, and hit-assessment of missile threats. The SBX radar is mounted on a mobile, ocean-going, semi-submersible platform, enabling it to cover any region of the globe. The SBX supports the Missile Defense System Homeland Defense mission by tracking and discriminating sophisticated intercontinental ballistic missile threats. The SBX operates at sea for Missile Defense System flight and ground test participation or in an active, operational status when indications and warnings signal the need for enhanced discrimination. The SBX is located in a Pacific port when not required at sea. The SBX maintains vessel certifications for operations at sea and software compatibility with the Missile Defense System.$$, NULL, 335927000, 431699000, 410167000, NULL, NULL, 95, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 193958000, 166813000, 274204000, 274204000, NULL, 274204000, 338748000, $$The SBX is an advanced X-Band Radar capable of mid-course acquisition, tracking, discrimination, and hit-assessment of missile threats. The SBX radar is mounted on a mobile, ocean-going, semi-submersible platform, enabling it to cover any region of the globe. The SBX supports the Missile Defense System Homeland Defense mission by tracking and discriminating sophisticated intercontinental ballistic missile threats. The SBX operates at sea for the Homeland Defense mission and supports Missile Defense System flight and ground test. The SBX is located in a Pacific port when maintenance is required. The SBX maintains vessel certifications for operations at sea and software compatibility with the Missile Defense System. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Missile Defense Agency                                                        Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:         PE 0603907C / Sea Based X-Band Radar (SBX) Advanced Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L087$$, $$SSN Acoustic Equipment$$, $$proc_navy_1810_ba2$$, $$peo_subs$$, 2026, 220453000, 0, 0, NULL, $${"page": 101, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "87", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 81", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 0, "p1_line_num": 81, "fy27_total_K": 0}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 3389, "li_num": 81, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA2_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 220453000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 458824000, 498597000, 0, 0, 0, 0, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603913C$$, $$Israeli Cooperative Programs$$, $$rdte_dw_ba4$$, $$dw_mda$$, 2026, 300000000, 300000000, 300000000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 71, "original_pe": "0603913C", "page_header": "Defense-Wide"}$$::jsonb, $$Since 1986, the United States (U.S.) and the State of Israel have cooperated on missile defense. Currently, the Missile Defense Agency (MDA) has two major projects with Israel to develop and improve their indigenous capability to defend against short range rockets, cruise missiles, and short and medium range ballistic missiles. These include the Arrow Weapon System (MD26) and the Short Range Ballistic Missile Defense David's Sling Weapon System (MD34). Within these projects MDA along with Israeli Missile Defense Organization develops and produces weapon systems, conducts tests, and exercises interoperability between the U.S. Missile Defense System and the Israeli Missile Defense Architecture. The U.S. and State of Israel entered into a Memorandum of Understanding on September 2016, in which "Such funding, should over a ten year period beginning in FY 2019 and ending in FY 2028, be provided at a level of $500 million per year." (U.S. contributions only). These funds will be distributed between the Israeli Programs in Research Development Test & Evaluation and Procurement Funds. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Missile Defense Agency                                                 Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:       PE 0603913C / Israeli Cooperative Programs Advanced Component Development & Prototypes (ACD&P)$$, NULL, 300000000, 300000000, 300000000, NULL, NULL, 96, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 300000000, 300000000, 300000000, 300000000, NULL, 300000000, 300000000, $$Since 1986, the United States (U.S.) and the State of Israel have cooperated on the Missile Defense System to defend against short-range rockets, cruise missiles, and short and medium-range ballistic missiles. This program element supports the State of Israel per international agreements. The Missile Defense Agency, in coordination with the Israeli Missile Defense Organization, develops and produces two major weapon systems, conducts tests, and exercises interoperability between the U.S. Missile Defense System and the Israeli Missile Defense Architecture. These major weapon systems include: - Arrow Weapon System (MD26). - Short-Range Ballistic Missile Defense / David's Sling Weapon System (MD34). The U.S. and State of Israel entered into a Memorandum of Understanding in September 2016, in which "Such funding, should over a ten-year period beginning in fiscal year (FY) 2019 and ending in FY 2028, be provided at a level of $500 million per year." (U.S. contributions only). These funds will be distributed between the Israeli Programs in Research, Development, Test & Evaluation and Procurement Funds. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Missile Defense Agency                                                        Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:         PE 0603913C / Israeli Cooperative Programs Advanced Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603914C$$, $$Ballistic Missile Defense Test$$, $$rdte_dw_ba4$$, $$dw_mda$$, 2026, 650079000, 358677000, 351866000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 71, "original_pe": "0603914C", "page_header": "Defense-Wide"}$$::jsonb, $$Missile Defense Agency (MDA) utilizes a disciplined system engineering process to develop and integrate the Missile Defense System into an effective, layered defense against ballistic missiles of all ranges during all phases of flight. This process consists of the following steps: Plan, Define, Design, Build, Test and Verify, Assess, and Deliver Missile Defense System Capability, followed by transfer of selected capabilities. The Missile Defense System Test Program Element is responsible for testing that provides critical data to: determine validity of models and simulations used to verify and assess Missile Defense System capabilities; validate that Elements and Components are properly designed, built, and integrated; and provide confidence that the Missile Defense System will perform as designed. Results from the Test and Verify step provide feedback into the Plan, Define, and Design steps to identify areas for system improvements. Key to the systems engineering process is Modeling and Simulation (M&S), which reflects the integrated operational system's performance. Confidence in M&S is based on a comprehensive Verification, Validation, and Accreditation process. The Missile Defense System Test Program, as documented in the IMTP, has a primary emphasis to provide the data necessary to verify and assess Missile Defense System capabilities in support of Technical Capability Declarations, and to anchor Missile Defense System M&S. As models are validated and accredited, MDA and the Missile Defense System Operational Test Agency Team will utilize these models to assess Missile Defense System capabilities through a campaign of ground testing. Missile Defense System Test Program Functions include: - Represent MDA as the single test authority to the test and evaluation community, international cooperative program representatives, and other organization representatives. - Develop and implement MDA test policy, standards, tools, products, and processes to enable effective tests while balancing MDA and element programmatic needs. - Develop an IMTP that compiles all MDA test objectives, test schedules, and funding requirements from the year of execution through the Future Years Defense Program time period and beyond. - Act as the single point of contact in MDA for all external ranges and common test resources. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Missile Defense Agency                                                               Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:              PE 0603914C / Ballistic Missile Defense Test Advanced Component Development & Prototypes (ACD&P) - Provide, maintain, and develop common test resources and infrastructure required to execute tests in the MDA Test Program by leveraging element laboratories, ranges, executing agents, and functional expertise, as applicable. - Certify that test personnel are trained and equipped to conduct safe and effective tests. - Provide test personnel and support services to plan and execute tests. - Collect, archive, and distribute all MDA test data/information. Rapidly evolving rogue and peer missile threats have led to a change in national defense policy. The President's January 27, 2025, Executive Order established a goal of protecting the United States (U.S.) citizens, safeguarding critical infrastructure, and securing second-strike capability against missile attack from any adversary. MDA is responding with speed and intensity to deliver next-generation missile defenses to protect the U.S. against ballistic, hypersonic, cruise, and other advanced missile threats. This program submission reflects changes necessary to meet this evolving mission space.$$, NULL, 845616000, 762302000, 975409000, NULL, NULL, 97, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 355503000, 459074000, 1065474000, 1065474000, NULL, 1065474000, 1016527000, $$MDA utilizes a disciplined system engineering process to develop and integrate the Missile Defense System into an effective, layered defense against ballistic missiles of all ranges during all phases of flight. This process consists of the following steps: Plan, Define, Design, Build, Test and Verify, Assess, and Deliver Missile Defense System Capability, followed by transfer of selected capabilities. The Missile Defense System Test Program Element is responsible for testing that provides critical data to: determine validity of models and simulations used to verify and assess Missile Defense System capabilities; validate that Elements and Components are properly designed, built, and integrated; and provide confidence that the Missile Defense System will perform as designed. Results from the Test and Verify step provide feedback into the Plan, Define, and Design steps to identify areas for system improvements. Key to the systems engineering process is Modeling and Simulation (M&S), which reflects the integrated operational system's performance. Confidence in M&S is based on a comprehensive Verification, Validation, and Accreditation process. The Missile Defense System Test Program, as documented in the Integrated Master Test Plan (IMTP), has a primary emphasis to provide the data necessary to verify and assess Missile Defense System capabilities in support of Technical Capability Declarations, and to anchor Missile Defense System M&S. As models are validated and accredited, MDA and the Missile Defense System Operational Test Agency Team will utilize these models to assess Missile Defense System capabilities through a campaign of ground testing. Missile Defense System Test Program Functions include: Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Missile Defense Agency                                                               Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:              PE 0603914C / Ballistic Missile Defense Test Advanced Component Development & Prototypes (ACD&P) - Represent MDA as the single test authority to the test and evaluation community, international cooperative program representatives, and other organization representatives. - Develop and implement MDA test policy, standards, tools, products, and processes to enable effective tests while balancing MDA and element programmatic needs. - Develop an IMTP that compiles all MDA test objectives, test schedules, and funding requirements from the year of execution through the Future Years Defense Program time period and beyond. - Act as the single point of contact in MDA for all external ranges and common test resources. - Provide, maintain, and develop common test resources and infrastructure required to execute tests in the MDA Test Program by leveraging element laboratories, ranges, executing agents, and functional expertise, as applicable. - Certify that test personnel are trained and equipped to conduct safe and effective tests. - Provide test personnel and support services to plan and execute tests. - Collect, archive, and distribute all MDA test data/information. The funds requested in this PE provide both legacy and Global Missile Defense Capability development for the United States, its deployed forces, allies, and partners. The capabilities funded by this budget request are complementary to the architecture funded by the Golden Dome Program's separate budget request and together fulfill the President's Executive Order 14186. The President's January 27, 2025, Executive Order established a goal of protecting the U.S. citizens, safeguarding critical infrastructure, and securing second-strike capability against missile attack from any adversary. This program and budget in addition to the budget requested by the Golden Dome Program Office reflects the changes necessary to protect the U.S. against ballistic, hypersonic, cruise, and other advanced missile threats.$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603915C$$, $$Ballistic Missile Defense Targets$$, $$rdte_dw_ba4$$, $$dw_mda$$, 2026, 693904000, 617721000, 605951000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 71, "original_pe": "0603915C", "page_header": "Defense-Wide"}$$::jsonb, $$The Missile Defense System Targets Program provides centrally managed targets and countermeasures development and procurement for a cost effective, integrated system-level approach to Missile Defense System testing. Based on engineering assessments of threat intelligence data, the Missile Defense System Targets Program develops, builds, and supports the launch of Short Range Ballistic Missile (Less than 1000 Kilometer Range) targets, Medium Range Ballistic Missile (1000-3000 Kilometer Range) targets, Intermediate Range Ballistic Missile (3000-5500 Kilometer Range) targets, Intercontinental Ballistic Missile (Greater than 5500 Kilometer Range) targets, and Multi-Class Components to test, verify, and validate the performance of the Missile Defense System against threats. The Missile Defense System Targets Program provides an economical and reliable inventory of targets, which are representative of feasible future threats and supports demonstration of the capability of the evolving layered Missile Defense System in a simultaneous test and operations threat environment.$$, NULL, 641408000, 573178000, 431225000, NULL, NULL, 98, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 601524000, 514882000, 518506000, 518506000, NULL, 518506000, 560764000, $$The Missile Defense System Targets Program provides centrally managed targets and countermeasures development and procurement for a cost effective, integrated system-level approach to Missile Defense System testing. Based on engineering assessments of threat intelligence data, the Missile Defense System Targets Program develops, builds, and supports the launch of Short Range Ballistic Missile (Less than 1000 Kilometer Range) targets, Medium Range Ballistic Missile (1000-3000 Kilometer Range) targets, Intermediate Range Ballistic Missile (3000-5500 Kilometer Range) targets, and Intercontinental Ballistic Missile (Greater than 5500 Kilometer Range) targets to test, verify, and validate the performance of the Missile Defense System against threats. The Missile Defense System Targets Program provides an economical and reliable inventory of targets, which are representative of feasible future threats and supports demonstration of the capability of the evolving layered Missile Defense System. The funds requested in this PE provide both legacy and Global Missile Defense Capability development for the United States, its deployed forces, allies, and partners. The capabilities funded by this budget request are complementary to the architecture funded by the Golden Dome Program's separate budget request and together fulfill the President's Executive Order 14186. The President's January 27, 2025, Executive Order established a goal of protecting the U.S. citizens, safeguarding critical infrastructure, and securing second-strike capability against missile attack from any adversary. This program and budget in addition to the budget requested by the Golden Dome Program Office reflects the changes necessary to protect the U.S. against ballistic, hypersonic, cruise, and other advanced missile threats. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Missile Defense Agency                                                        Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:            PE 0603915C / Ballistic Missile Defense Targets Advanced Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603923D8Z$$, $$Coalition Warfare Program (CWP)$$, $$rdte_dw_ba4$$, $$dw$$, 2026, 10090000, 9642000, 9890000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 71, "original_pe": "0603923D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Department's initiatives to Deter Aggression, Defend the Homeland, and Build Sustainable and Long-Term Advantage. The Coalition Warfare Program (CWP) supports the DoD organizations that: 1) work with foreign partners to collaboratively address strategic technology gaps for current and future missions; 2) develop interoperability solutions for coalition operations; and 3) develop and strengthen defense relationships. It comprehensively supports the Interim National Defense Strategic Guidance (INDSCG) direction to engage allies and partners, implementing guidance to "fully engage all countries and institutions to cooperate on shared threats” and “redouble our efforts to deepen our cooperation with like-minded partners." The CWP provides a broad base of technological, operational, and logistical support for military operations and eases the U.S. financial and manpower burdens associated with meeting military goals and objectives. Coalitions and relationships with international partners are high priorities for the nation and the DoD. The CWP supplements the United States (U.S.) Government proponents' funding for cooperative efforts, ensuring U.S. funds are sufficient to complete research and development activities with foreign partners. When CWP funds are used to help fund a cooperative project, that project leverages technical and financial contributions of the foreign partners and accelerates the development and delivery of technical solutions to the warfighter. For every $1 the CWP has invested in cooperative projects with 81 partners since 2001, the program has leveraged $3 in foreign partner resources and $2 in other U.S. Government resources. The CWP funding enables the DoD project teams to transition technology to operational use, further development, or integration into other systems. These projects may also form the basis for future cooperation with international partners. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                  Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:            PE 0603923D8Z / Coalition Warfare Program (CWP) Advanced Component Development & Prototypes (ACD&P)$$, NULL, 10404000, 10740000, 11079000, NULL, NULL, 99, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 9828000, 10062000, 10082000, 10082000, NULL, 10082000, 11299000, $$The Coalition Warfare Program (CWP) supports the Department's initiatives to increase burden sharing, strengthen alliances and enhance interoperability, support the defense industrial base and technological advantage, and maintain focus on warfighter needs. This program supports Department of War (DoW) organizations that work with foreign partners to collaboratively address strategic technology gaps for current and future missions, develop interoperability solutions for coalition operations, and develop and strengthen defense relationships. The CWP provides a broad base of technological, operational, and logistical support for military operations and eases the United States (U.S.) financial and manpower burdens associated with meeting military goals and objectives. Coalitions and relationships with international partners that benefit the U.S. warfighter are high priorities for the nation and the DoW. The CWP supplements U.S. Government proponents' funding for cooperative efforts, unlocking external capital to complete research and development activities with foreign partners. When CWP funds are used to help fund a cooperative project, that project leverages technical and financial contributions of the foreign partners and accelerates the development and delivery of technical solutions to the warfighter. For every $1 the CWP has invested in cooperative projects with 86 partners since 2001, the program has leveraged $3 in foreign partner resources and $2 in other U.S. Government resources. The CWP funding enables the DoW project teams to transition technology to operational use, further development, or integration into other systems. These projects may also form the basis for future cooperation with international partners. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                       Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:        PE 0603923D8Z / Coalition Warfare Program (CWP) Advanced Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603924D8Z$$, $$High Energy Laser Advanced Development$$, $$rdte_dw_ba3$$, $$dw$$, 2026, 130577000, 108442000, 112867000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 70, "original_pe": "0603924D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program is executed via the Joint Directed Energy Transition Office (JDETO) in alignment with the Department of Defense Directed Energy Roadmap, as well as other strategic guidance. Section 219 of the 2017 National Defense Authorization Act designated a senior official for directed energy and redesignated a legacy office as the JDETO with reporting to the senior official. Currently, the Principal Director for Directed Energy serves as this senior official and updates the Department of Defense Directed Energy Roadmap on an annual basis. The goal of this program, in turn, is to support the Department’s initiatives in directed energy to build a sustainable and long-term advantage, in addition to a resilient joint force and defense ecosystem. This program funds advanced technology development in directed energy aimed at transitioning technology solutions for broadly defined military missions. These efforts include demonstrated performance pay-offs, increased capabilities, increased supportability, and increased affordability. In practice, directed energy weapon systems have many potential advantages, including speed-of-light time-to-target, high precision, low incremental cost per kill, and a magazine that is recharged through on-board, fuel-based power and thermal management systems that reduce logistics requirements in contrast to stocks of munitions or warheads. As a result, directed energy weapon systems have the potential to perform a wide variety of military missions. Activities conducted under this program will ultimately enable the employment of directed energy weapon systems.$$, NULL, 187657000, 174154000, 164717000, NULL, NULL, 74, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 109517000, 120763000, 201125000, 201125000, NULL, 201125000, 159717000, $$This program is executed via Scaled Directed Energy (SCADE) Science and Technology and in alignment with the Department of War Directed Energy Roadmap, as well as other strategic guidance. The goal of this program is to support the Department’s initiatives in directed energy to build a sustainable and long-term advantage. This program funds advanced technology development in directed energy aimed at transitioning technology solutions for broadly defined military missions. These efforts include demonstrated performance pay-offs, increased capabilities, increased supportability, and increased affordability. In practice, directed energy weapon systems have many potential advantages, including speed-of-light time-to-target, high precision, low incremental cost per kill, and a rechargeable magazine through on-board power and thermal management systems improving logistics requirements over stocks of munitions or warheads. As a result, directed energy weapon systems have the potential to perform a wide variety of military missions. Activities conducted under this program will ultimately enable the employment of directed energy weapon systems.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603925N$$, $$Directed Energy and Electric Weapon System$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 61000000, 63518000, 19877000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 29, "original_pe": "0603925N", "page_header": "Department of the Navy"}$$::jsonb, $$This program element will transition Directed Energy and Electric Weapon Systems (DE&EWS) technology from Science and Technology (S&T) research to the Technology Maturation and Risk Reduction phase, ultimately leading to acquisition initiation for the Surface/Subsurface Navy. DE&EWS consists of multiple breakthrough technologies including: laser weapons that provide for speed-of-light engagements at tactically significant ranges resulting in savings realized by minimizing the use of defensive missiles and projectiles; electromagnetic launch of projectiles that will significantly increase firing ranges imposing greater cost to adversaries of ballistic and air defense missile engagements; enhance the land attack mission; and fielding of high power radio frequency systems for non-kinetic electronic attack and active denial technology, allowing for non-lethal determination of threat intent beyond small arms fire ranges. Development of DE&EWS includes: Weapons Grade High Energy Lasers, Electromagnetic Railgun (EMRG) Weapon Systems, High Power Radio Frequency Weapon/ Sensor Systems, and other systems/capabilities. Project 2731 - High Energy Laser Counter ASCM Project (HELCAP): Defeating Anti-Ship Cruise Missiles (ASCMs) with a laser weapon system presents several technical challenges (e.g. high atmospheric turbulence, target acquisition and identification, target tracking, aim point maintenance, automatic aim point placement, jitter control). The High Energy Laser Counter ASCM Project (HELCAP) will assess, develop, experiment, and demonstrate the various laser weapon system technologies and methods of implementation (e.g. laser sources, mission analysis, lethality, advanced beam control with atmospheric mitigation, target and tracking sensors, control systems) required to defeat ASCMs in a crossing engagement. Project 3402 - Surface Navy Laser Weapon System (SNLWS): Program supports the National Defense Strategy (NDS) of building a more lethal force by leveraging maturing technology to deliver proven laser weapon capability to the Fleet as part of the Navy Laser Family of Systems (NLFoS) initiative with the objective of providing Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                              Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced              PE 0603925N / Directed Energy and Electric Weapon System Component Development & Prototypes (ACD&P) the fleet with incrementally developed laser weapon system capabilities. Additionally, accelerated learning through incorporation of laser weapon Concept of Operations (CONOPs), employment and maintenance validates warfighting requirements for laser weapon systems to address a variety of threats. The High Energy Laser with Integrated Optical-Dazzler and Surveillance (HELIOS) system provides a low cost-per-shot capability to address Anti-Surface Warfare and Counter-Intelligence, Surveillance and Reconnaissance (C-ISR) gaps with the ability to dazzle and destroy Unmanned Aerial Systems (UAS) and defeat Fast Inshore Attack Craft (FIAC) while integrated into the AEGIS Combat System on a Flt IIA Destroyer. SNLWS, as a Non-Program of Record (POR) provided an industry-developed and government integrated capability to the Fleet in as short a timeframe as possible, thereby addressing the NDS direction to foster a culture of innovation. SNLWS included the development of a laser weapon system in the 60 kW class. SNLWS leveraged technology available at that time to deliver an initial laser weapon system capability to the Fleet. Mk 5 Mod 0 HELIOS development leveraged the previous AN/SEQ-3 Laser Weapon System (LaWS) and the Mk 2 Mod 0 Laser Weapon System Demonstrator (LWSD) efforts. Project 5898 - Directed Energy Components for High Energy Lasers: Supports Industrial Base Analysis and Sustainment (IBAS) program efforts for the improvement of the production capability of the industrial base in order to produce Laser Weapon Beam Director (LWBD) components and sub-systems; reduces production lead times of Laser Weapon System Optics; improves quality and reduces production times of Fast Steering Mirror (FSM) and deformable mirrors. Project 5898 funding completes in FY24. Project 9823 - Lasers for Navy Applications: Optical Dazzler Interdictor Navy (ODIN) development provided directed energy, shipboard Counter-Intelligence, Surveillance, and Reconnaissance (C-ISR) capabilities to the Fleet to dazzle Unmanned Aerial Systems (UASs) and other platforms that address the Urgent Operational Needs (UONs) statement provided by the Fleet. ODIN, as a non-Program of Record, was developed and fielded with RDT&E,N funding and was initially envisioned as a Non-Permanent Change (NPC). FY 2018 was the first year of funding which supported the design, development, procurement, and installation of 8 ODIN standalone units deployed on DDG 51 Flt IIA surface combatants. Eight (8) ODIN units are now operational in the Fleet. Project 9823 R&D funding converted to OPN in FY25 & FY26 and O&MN FY24-FY 26 for the sustainment of 8 ODIN units. Project 9999 (PU C357) - Congressional Add - 100kW Directed Energy Production is a Congressionally directed effort to advance the manufacturing readiness of 'weapon grade' subsystems for 100kW class High Energy Lasers (HELs) including the Main Optical Bench (MOB) for beam combining and beam control. Additionally, these funds will support Navy plans to develop and refine weapon integration processes and system performance qualification and evaluation. In order to expand mass production of weapon grade Laser Fiber Amplifiers (LFAs), manufacturing processes currently utilized need refinement and improvement. This will result in higher production capabilities at a reduced cost per LFA for the United States (US) Government. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                             Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced         PE 0603925N / Directed Energy and Electric Weapon System Component Development & Prototypes (ACD&P)$$, NULL, 89599000, 78986000, 39254000, NULL, NULL, 74, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 19319000, 14480000, 94825000, 94825000, NULL, 94825000, 35464000, $$This program element will transition Directed Energy and Electric Weapon Systems (DE&EWS) technology from Science and Technology (S&T) research to the Technology Maturation and Risk Reduction phase fielding prototype systems in the Fleet, ultimately leading to acquisition initiation for the Surface/Subsurface Navy. DE&EWS consists of multiple breakthrough technologies including: laser weapon systems that provide for speed-of-light engagements at tactically significant ranges resulting in savings realized by minimizing the use of defensive missiles and projectiles; electromagnetic launch of projectiles that will significantly increase firing ranges imposing greater cost to adversaries of ballistic and air defense missile engagements, while enhancing the land attack mission; and fielding of high power radio frequency weapon systems for high power microwave, non-kinetic electronic attack and active denial technology, allowing for non-lethal determination of threat intent beyond small arms fire ranges. Development of DE&EWS includes: Weapons Grade High Energy Lasers, Electromagnetic Railgun (EMRG) Weapon Systems, High Power Microwave Systems, and other designated Directed Energy (DE) systems/capabilities. Project 2731 - High Energy Laser Counter ASCM Project (HELCAP): Defeating Anti-Ship Cruise Missiles (ASCMs) with a laser weapon system presents several technical challenges (e.g. high atmospheric turbulence, target acquisition and identification, target tracking, aim point maintenance, automatic aim point placement, jitter control). The High Energy Laser Counter ASCM Project (HELCAP) will assess, develop, experiment, and demonstrate the various laser weapon system technologies and methods of implementation (e.g. laser sources, mission analysis, lethality, advanced beam control with atmospheric mitigation, target and tracking sensors, control systems) required to defeat ASCMs in a crossing engagement. The FY 2026 request for High Energy Laser Counter ASCM Project (HELCAP) includes $0 of discretionary and $15M of mandatory (reconciliation) for a total of $15M. The mandatory funding will be used for lethality model validation and evaluation of High Energy Laser (HEL) technologies to assess HEL weapon lethality in Navy operational environments against the Counter Anti-ship Cruise Missile (C-ASCM) operational challenge while enabling the Navy to rapidly integrate a fleet-ready HEL weapon system capability. Further information for this reconciliation request is provided in Section 20005 (Low-Cost Weapons) of the Reconciliation Exhibit. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced          PE 0603925N / Directed Energy and Electric Weapon System Component Development & Prototypes (ACD&P) The FY 2027 budget request supports Directed Energy Testing Against Missiles (DETAM) activities focusing on system-level testing and evaluation (T&E) exercises on land and in a maritime environment. The test campaign will leverage the Laser Weapon Testbed (LWT) and other directed energy assets. Project 3402 - Surface Navy Laser Weapon System (SNLWS): Program supports the National Defense Strategy (NDS) of building a more lethal force by leveraging maturing technology to deliver proven laser weapon capability to the Fleet. The Mk 5 Mod 0 High Energy Laser with Integrated Optical-Dazzler and Surveillance (HELIOS) system, as installed in the forward deployed combatant, provides a low cost-per-shot capability to address Anti-Surface Warfare and Counter-Intelligence, Surveillance and Reconnaissance (C-ISR) gaps with the ability to dazzle and destroy Unmanned Aerial Systems (UAS) and defeat Fast Inshore Attack Craft (FIAC) while integrated into the AEGIS Combat System on a Flt IIA Destroyer. SNLWS/HELIOS, as a Non-Program of Record (POR) Research & Development (R&D) asset, provided an industry-developed and government integrated capability to the Fleet in as short a timeframe as possible, thereby addressing the NDS direction to foster a culture of innovation. HELIOS included the development of a laser weapon system in the 60 kW class. The FY 2027 budget request supports the Research & Development (R&D) asset of HELIOS on DDG 88 by providing In Service Engineering Agent (ISEA) and Software Support Activity (SSA) technical product support, component repair and/or replacement, grooming, and testing after the availability and during the operational period; and to begin development of a containerized 150kW Joint Laser Weapon System (JLWS) for cruise missile defense by incrementally providing at least 300kW of power building on existing laser scaling efforts; development of the Joint Beam Control System (JBCS) technology capable of supporting a 300-500kW laser weapon system; and conduct upgrades to the High Energy Laser Counter Anti-Ship Cruise Missile Project (HELCAP) testbed as appropriate to support JLWS testing. In coordination with the military services and the Missile Defense Agency, begin development of a consolidated implementation plan for all Golden Dome Directed Energy projects, leveraging synergy and common weapon architectures between these efforts where possible. Project 9999 (PU C357) - Congressional Add - 100kW Directed Energy Production is a Congressionally directed effort to advance the manufacturing readiness of 'weapon grade' subsystems for 100kW class High Energy Lasers (HELs) including the Main Optical Bench (MOB) for beam combining and beam control. Additionally, these funds will support Navy plans to develop and refine weapon integration processes and system performance qualification and evaluation. In order to expand mass production of weapon grade Laser Fiber Amplifiers (LFAs), manufacturing processes currently utilized need refinement and improvement. This will result in higher production capabilities at a reduced cost per LFA for the United States (US) Government. Project 9999 (PU CA34) - Congressional Add - Enduring-High Energy Laser (E-HEL) supports development, integration and marinization of the E-HEL capability into multi-service Air and Missile Defense networks to demonstrate a capability to defeat Group 1-3 Unmanned Aerial Systems (UASs). Project 9999 (PU CA35) - Congressional Add - Directed Energy Production is a Congressionally directed effort to advance the manufacturing readiness of 'weapon grade' subsystems for 100kW class High Energy Lasers (HELs) including the Main Optical Bench (MOB) for beam combining and beam control. Additionally, these funds will support Navy plans to develop and refine weapon integration processes and system performance qualification and evaluation. In order to expand mass production of weapon grade Laser Fiber Amplifiers (LFAs), manufacturing processes currently utilized need refinement and improvement. This will result in higher production capabilities at a reduced cost per LFA for the United States (US) Government. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced        PE 0603925N / Directed Energy and Electric Weapon System Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603941D8Z$$, $$Test and Evaluation Science and Technology$$, $$rdte_dw_ba3$$, $$dw_osd$$, 2026, 1645772000, 415751000, 305722000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 70, "original_pe": "0603941D8Z", "page_header": "Defense-Wide", "fy26_v182_disc_K": 961052, "fy26_v182_supp_K": 713000, "fy26_v182_total_K": 1674052, "fy26_v182_note_name": "Research, Development, Test, & Evaluation, Defense-Wide for Test and Evaluation Science and Technology", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 16541}$$::jsonb, $$This program supports the Department's priorities to rebuild the military by matching threats to capabilities and re-establish deterrence by defending our homeland. The Test and Evaluation/Science and Technology (T&E/S&T) program seeks out and develops test technologies to keep pace with evolving weapons technologies. Aligned with national strategic guidance, this program is critical to ensure the Department’s readiness to test and field rapidly emerging technologies and weapon systems that defend our homeland, deter aggression, and achieve peace through strength. To meet this objective, the T&E/S&T Program performs the following activities: - Exploits new technologies and processes to meet important T&E requirements. - Expedites the transition of new technologies from the laboratory environment to the T&E community. - Leverages industry advances in equipment, modeling and simulation, and networking to support T&E. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:            PE 0603941D8Z / Test and Evaluation Science and Technology Advanced Technology Development (ATD) Additionally, the T&E/S&T Program examines emerging T&E requirements resulting from Joint Service initiatives to identify T&E technology needs and develop a long- range roadmap for technology insertion. The program leverages and employs applicable applied research efforts from the highly developed technology base in the DoD laboratories and test centers, other Government agencies, and industry to accelerate development of new test capabilities. The program outreaches and engages academia to address test technology challenges. The T&E/S&T Program aligns with the science and technology (S&T) Communities of Interest (COI) to prepare the T&E community to test warfighting capabilities that emerge from priority S&T investments. The T&E/S&T Program utilizes Advanced Technology Development funding, which supports the development and demonstration of high payoff technologies for current and future DoD test capabilities. FY26 Controls are incorrectly reflected subject to the following corrections: 1) Project 091 is understated. Correct control is $579.223M 3) Project 098 is overstated. Correct control is $14.762M. Delta of $141M is reflected in Project 091 total of $579.223M. 4) Project 112 does not reflect an additional $550M of mandatory funding.$$, NULL, 3500143000, 3376235000, 3329232000, NULL, NULL, 75, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 304567000, 1674052000, 3834080000, 3834080000, NULL, 3834080000, 3272588000, $$The Test Resource Management Center (TRMC) Test and Evaluation / Science and Technology (T&E/S&T) Program supports the Department's initiatives to rebuild our military and re-establish deterrence. The T&E/S&T Program seeks out and develops test technologies to keep pace with emerging and evolving weapons technologies. Aligned with the National Defense Strategy, this program is critical to ensure that the Department has the ability to adequately test the advanced systems that will be fielded in the future. To meet this objective, the T&E/S&T Program performs the following activities: - Exploits new technologies and processes to meet important T&E requirements. - Expedites the transition of new technologies from the laboratory environment to the T&E community. - Leverages industry advances in equipment, modeling and simulation, and networking to support T&E. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                             Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:             PE 0603941D8Z / Test and Evaluation Science and Technology Advanced Technology Development (ATD) - Uses non-traditional acquisition processes and contract vehicles for rapid development and fielding of test technologies. Additionally, the T&E/S&T Program examines emerging T&E requirements resulting from Joint Service initiatives to identify T&E technology needs and develop a long- range roadmap for technology insertion. The program leverages and employs applicable applied research efforts from the highly developed technology base in the Department’s laboratories and test centers, other Government agencies, and industry to accelerate development of new test capabilities. The program outreaches and engages academia to address test technology challenges. The T&E/S&T Program aligns with the science and technology (S&T) Communities of Interest (COI) to prepare the T&E community to test warfighting capabilities that emerge from priority S&T investments. The T&E/S&T Program utilizes Advanced Technology Development funding, which supports the development and demonstration of high payoff technologies for current and future test capabilities. The FY 2026 spend plan amount for Research, Development, Test, & Evaluation, Defense-Wide for Test and Evaluation Science and Technology includes $961,052 thousand of discretionary and $713,000 thousand of mandatory (reconciliation) funding for a total of $1,674,052 thousand.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603945D8Z$$, $$International Innovation Initiatives$$, $$rdte_dw_ba3$$, $$dw$$, 2026, 173048000, 12056000, 65680000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 70, "original_pe": "0603945D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Department’s initiatives to (1) deter strategic attacks against the United States, and its Allies and partners; (2) deter aggression while being prepared to prevail in conflict when necessary; and (3) building enduring advantages for the future Joint Force. This program supports the Enhanced Trilateral Security Partnership among Australia, the United Kingdom, and the United States (AUKUS) (Project Code 079), the North Atlantic Treaty Organization (NATO) Defense Innovation Accelerator for the North Atlantic (DIANA) (Project Code 353), and Science and Technology (S&T) International Engagement Initiatives (Project Code 354). AUKUS will deepen defense capability and technological cooperation by developing and providing joint advanced military capabilities to promote security and stability in the Indo-Pacific region. The AUKUS program will accelerate the delivery of advanced military capabilities, increased interoperability, and improved information sharing. The delivery of these capabilities will enhance AUKUS partners’ military edge and strengthen integrated deterrence. In support of these objectives, the marquee AUKUS Pillar II project centers around increasingly complex collaborative demonstrations and evaluations that will lead to the validation of trilaterally-connected platforms from the sea floor to the stratosphere, and ultimately enable trilateral production, acquisition, fielding, and sustainment of these systems. The NATO DIANA program will pursue operationally relevant advanced capability co-development, support integration of multi-national capabilities to act as a force multiplier, and test and evaluate promising solutions found across the innovation ecosystem. This complementary program to DIANA will allow the United States to pull successful security solutions from the DIANA effort across the Alliance into availability in the U.S. industrial base and for operational use and aligns with the critical technology areas and operational requirements. The S&T International Engagement Initiatives program will incentivize the DoD Components, including the Military Services, to engage and/or expand their S&T cooperation with existing partners (e.g., Israel, India, Japan, South Korea) and with those new partners with whom they may be engaged in policy or operational activities but not in the S&T realm. The intent is to consider proposals submitted from the DoD Components. The appropriate leadership will select proposals using Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                  Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:             PE 0603945D8Z / International Innovation Initiatives Advanced Technology Development (ATD) a merit-based process that identifies the most promising solutions to operational challenges. The program portfolio aligns with the interim National Defense Strategy guidance, the priority critical technology areas, and operational requirements.$$, NULL, 161334000, 155985000, 159410000, NULL, NULL, 76, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 54234000, 181497000, 158345000, 158345000, NULL, 158345000, 159410000, $$This program supports the Department’s initiatives to (1) deter strategic attacks against the United States, and its Allies and partners; (2) deter aggression while being prepared to prevail in conflict when necessary; and (3) building enduring advantages for the future Joint Force. This program supports the Enhanced Trilateral Security Partnership among Australia, the United Kingdom, and the United States (AUKUS), the North Atlantic Treaty Organization (NATO) Defense Innovation Accelerator for the North Atlantic (DIANA), and Science and Technology (S&T) International Engagement Initiatives. AUKUS contributes to the Pacific Deterrence Initiative (PDI) by providing funding to pursue operationally relevant advanced capability co-development, support integration of multi-national capabilities to act as a force multiplier, and test and evaluate promising solutions for deployment in the Indo-Pacific theater. It will deepen defense capability and technological cooperation by developing and providing joint advanced military capabilities to promote security and stability in the Indo-Pacific region. The AUKUS program will accelerate the delivery of advanced military capabilities, increased interoperability, and improved information sharing. The delivery of these capabilities will enhance AUKUS partners’ military edge and strengthen integrated deterrence. In support of these objectives, the marquee AUKUS Pillar II project centers around increasingly complex collaborative demonstrations and evaluations that will lead to the validation of trilaterally-connected platforms from the sea floor to the stratosphere, and ultimately enable trilateral production, acquisition, fielding, and sustainment of these systems. The NATO DIANA program will pursue operationally relevant advanced capability co-development, support integration of multi-national capabilities to act as a force multiplier, and test and evaluate promising solutions found across the innovation ecosystem. This complementary program to DIANA will allow the United States to pull successful security solutions from the DIANA effort across the Alliance into availability in the U.S. industrial base and for operational use and aligns with the critical technology areas and operational requirements. The S&T International Engagement Initiatives program will incentivize the Department of War (DoW) Components, including the Military Services, to engage and/or expand their S&T cooperation with existing partners (e.g., Israel, India, Japan, South Korea) and with those new partners with whom they may be engaged in policy or Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:               PE 0603945D8Z / International Innovation Initiatives Advanced Technology Development (ATD) operational activities but not in the S&T realm. The intent is to consider proposals submitted from the DoW Components. The appropriate leadership will select proposals using a merit-based process that identifies the most promising solutions to operational challenges. The program portfolio aligns with the interim National Defense Strategy guidance, the priority critical technology areas, and operational requirements.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603950D8Z$$, $$National Security Innovation Network$$, $$rdte_dw_ba3$$, $$dw_nsin$$, 2026, 21202000, 21179000, 1586000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 70, "original_pe": "0603950D8Z", "page_header": "Defense-Wide", "fy26_v182_disc_K": 0, "fy26_v182_supp_K": 21202, "fy26_v182_total_K": 21202, "fy26_v182_note_name": "0603950D8Z", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 18154}$$::jsonb, $$This program supports the Department’s initiatives to Build a Sustainable and Long-Term Advantage and Build a Resilient Joint Force and Defense Ecosystem. The National Security Innovation Network (NSIN) activities build networks of innovators that generate new solutions to national security problems. On April 4, 2023, the Secretary of Defense issued a memorandum re-aligning the Defense Innovation Unit (DIU) Director as a direct report to the Secretary of Defense. In July 2023, the DIU Director announced a reorganization that integrated NSIN into DIU to maximize strategic impact. The Regional Network Team is responsible for building the networks of innovators. The physical network is spread across regions spanning the Continental United States and reaching out to Hawaii and Alaska. Regional engagement activities are led by Regional Directors supported by additional Regional Network Team members able to reach into critical venture innovation centers throughout the country including: Boston, MA; New York City, NY; Washington, DC; Orlando, FL; Chicago, IL; St. Louis, MO; Austin, TX; Denver, CO; Seattle, WA; San Diego, CA; and San Francisco, CA. Additional members of the Regional Network Team currently include Regional Engagement Principals (REPs) that are embedded in - and have responsibility for - critical innovation ecosystems within each region including universities and other tech hubs. This team will be integrated with DIU’s commercial and regional engagement efforts to reduce duplication, strengthen national outreach, and foster cross- pollination of activities across the technological maturity spectrum. DIU will strengthen pathways for talent to serve and facilitate access to early-stage companies to engage with the Department through the following programmatic portfolios: The Talent Portfolio provides opportunity for individuals outside the traditional federal talent pipeline to serve our country and solve real-world national security, technology, and policy challenges. By bridging the gap between students, academics, and entrepreneurs to engage with the Department of Defense (DoD), DIU is helping build a deep bench of diverse, qualified civilian and military workers to preserve our competitive emerging technology advantage with resilient personnel trained for the unpredictable global operating environment. The Venture Portfolio develops and executes programs and services to facilitate access to emerging technology as it engages the talents of fast-moving innovators and non-traditional problem-solvers. The Venture Portfolio works directly with dual-use early-stage ventures emerging from both the academic and venture community who have solutions that address DoD problems. The Venture Portfolio creates advantage for defense innovation through customer discovery and solution adoption. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                 Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:              PE 0603950D8Z / National Security Innovation Network Advanced Technology Development (ATD) This programmatic activity is supported through other enterprise functions that measure programmatic impact, support follow-on activities by alumni, and help share broader information about the network.$$, NULL, NULL, NULL, NULL, NULL, NULL, 77, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 1586000, 21202000, NULL, NULL, NULL, NULL, NULL, $$This program supports the Department’s initiatives to Build a Sustainable and Long-Term Advantage and Build a Resilient Joint Force and Defense Ecosystem. The National Security Innovation Network (NSIN) activities build networks of innovators that generate new solutions to national security problems. The FY 2026 spend plan amount for 0603950D8Z includes $0 of discretionary and $21,202 thousand of mandatory (reconciliation) for a total of $21,202 thousand.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604001F$$, $$NC3 Advanced Concepts$$, $$rdte_af_ba4$$, $$afnwc_nc$$, 2026, 15910000, 5274000, 5448000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0604001F"}$$::jsonb, $$Nuclear Command, Control, and Communications (NC3) Advanced Concepts are required for analysis, development and prototyping of next generation NC3 systems and subsystems. This program ensures a responsive design and development engineering infrastructure to address evolving Nuclear Deterrence Operations (NDO) mission requirements; emerging issues and technology insertion/technology application on the NC3 Weapon System (WS), future strategic systems/capability, and other common strategic areas where appropriate; and develop enhanced multi-use capabilities. The NC3 Advanced Concepts Program will provide technology maturation and risk reduction activities to support the AF NC3 Weapon System (AN/USQ-225). Activity will reduce life cycle costs, inform technology maturation & risk reduction efforts, improve system performance, mitigate evolving threats, and ensure both viability and durability of the AF NC3 Weapon System. Additional details can be provided at a higher classification. The FY 2026 request was reduced by [0.060] million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0.000M was expended for civilian pay expenses in this program element, and in FY 2025 $0.000M is forecasted for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                             Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604001F / NC3 Advanced Concepts Component Development & Prototypes (ACD&P)$$, NULL, 15191000, 7273000, 7471000, NULL, NULL, 36, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 5283000, 10762000, 14394000, 14394000, 0, 14394000, 7623000, $$Nuclear Command, Control, and Communications (NC3) Advanced Concepts are required for analysis, development and prototyping of next generation NC3 systems and subsystems. This program ensures a responsive design and development engineering infrastructure to address evolving Nuclear Deterrence Operations (NDO) mission requirements; emerging issues and technology insertion/technology application on the NC3 Weapon System (WS), future strategic systems/capability, and other common strategic areas where appropriate; and develop enhanced multi-use capabilities. The NC3 Advanced Concepts Program will provide technology maturation and risk reduction activities to support the AF NC3 Weapon System (AN/USQ-225). Activity will reduce life cycle costs, inform technology maturation & risk reduction efforts, improve system performance, mitigate evolving threats, and ensure both viability and durability of the AF NC3 Weapon System. "NC3 Prototypes & Demonstrations” will focus on the development and operational evaluation of emerging capabilities. This area will 1) create functional prototypes of technologies and system concepts to assess their utility and technical feasibility, 2) conduct a series of demonstrations and experiments in operationally relevant environments to validate performance, and 3) leverage comprehensive methodology to respond to changing warfighter needs to inform requirement refinement. The objective is to reduce technical risk, accelerate the learning process, and provide tangible evidence to guide formal acquisition and integration decisions. "NC3 Technology Insertion & Transition” will bridge the gap between mature prototypes and their integration into operational programs of record. Key activities include 1) identifying and maturing promising technologies from prototypes, laboratory environments, and industry, 2) developing transition plans and strategies in collaboration with NC3 programs or other stakeholders to ensure successful handoffs, and 3) providing advice on the integration of these new capabilities into the existing NC3 architecture and sustainment planning. This ensures that successful innovations are effectively scaled and delivered to programs, reducing life cycle costs, and providing mature technologies. Additional details can be provided at a higher classification. Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604001F / NC3 Advanced Concepts Component Development & Prototypes (ACD&P) This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604002SF$$, $$Space Force Weather Services Research$$, $$rdte_sf_ba4$$, $$sf$$, 2026, 857000, 0, 867000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$This budget activity funds the development necessary to evaluate integrated technologies and models for future operationalization into segments of the Space Force Weather Services (SFWS) in support of three lines of effort. To improve readiness for a more lethal force, SFWS provides timely, accurate, resilient and relevant environmental information, to include space and terrestrial weather, for global battlespace situational awareness for Air Force (AF), Army, Special Operations Forces (SOF), Space Force (USSF), combatant commands, the Intelligence Community (IC), and other government agencies. SFWS capabilities at home station and deployed provide critical environmental information in support of decision makers to gain the asymmetric advantage during the full spectrum of air and space combat operations. SFWS development enhances the lethality, effectiveness, and survivability of AF & SF weapon systems and precision munitions by modernizing capability and seeking the military advantage to accurately predict friendly and foe environmental impacts to optimize mission execution and planning, targeting, weaponeering, battle damage assessment, and space systems operations. To strengthen alliances and partnerships, SFWS development efforts integrate Department of Defense (DoD), government agency, commercial, and international partner environmental data with SFWS information system equipment for processing, storing, exploiting, and disseminating all- domain weather information for analysis, forecasting, mission integration, and greater interoperability. To ensure greater performance and affordability for the AF and SF, SFWS systems are being modernized through improvements to architecture and system efficiency, cybersecurity, joint all-domain command and control (JADC2) and sensing grid integration, migration to cloud computing, and expanding agile software development practices. SFWS aligns activities under four capability areas: Weather Data Collection, Weather Data Analysis and Dissemination, Weather Forecasting, and Product Tailoring/ Warfighter Applications (PTWA). This alignment ensures an integrated and systems-oriented approach to program management decisions. A portion of the Weather Forecasting capability is addressed by RDT&E, BA 04, PE 0604002S, Project 645353 - Space Force Weather Services Research. Weather Forecasting provides global and regional advanced scientific numerical weather prediction capabilities for automated, high-resolution forecast products for mission planning and execution. Space weather modeling assists in characterizing and forecasting the near-earth environment to the sun and enables space weather anomaly and space weather impact assessments. Weather Forecasting includes activities for Numerical Weather Modeling (NWM) and Space Weather Analysis and Forecast System (SWAFS). SWAFS is a software suite of 47 models and applications to ingest, process, and store space environmental data, run space environmental models to specify and forecast the near-earth environment, and run space effects characterization applications. This program element may include necessary civilian pay expenses required to manage, execute, and deliver SFWS for weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:              PE 0604002SF / Space Force Weather Services Research Advanced Component Development & Prototypes (ACD&P) This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 3613000, 3725000, 3644000, NULL, NULL, 8, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 836000, 843000, 3581000, 3581000, 0, 3581000, 3763000, $$The program office is executing the Space Weather Analysis and Forecast System (SWAFS) (Project 643353) for Guardians across the Weather mission area. As a result, the USSF will improve readiness and operational reach of existing the force structure. This budget activity funds the development necessary to evaluate integrated technologies and models for future operationalization into segments of the Space Force Weather Services (SFWS) in support of three lines of effort. To improve readiness for a more lethal force, SFWS provides timely, accurate, resilient and relevant environmental information, to include space and terrestrial weather, for global battlespace situational awareness for Air Force (AF), Army, Special Operations Forces (SOF), Space Force (USSF), combatant commands, the Intelligence Community (IC), and other government agencies. SFWS capabilities at home station and deployed provide critical environmental information in support of decision makers to gain the asymmetric advantage during the full spectrum of air and space combat operations. SFWS development enhances the lethality, effectiveness, and survivability of AF & SF weapon systems and precision munitions by modernizing capability and seeking the military advantage to accurately predict friendly and foe environmental impacts to optimize mission execution and planning, targeting, weaponeering, battle damage assessment, and space systems operations. To strengthen alliances and partnerships, SFWS development efforts integrate Department of War (DoW), government agency, commercial, and international partner environmental data with SFWS information system equipment for processing, storing, exploiting, and disseminating all- domain weather information for analysis, forecasting, mission integration, and greater interoperability. To ensure greater performance and affordability for the AF and SF, SFWS systems are being modernized through improvements to architecture and system efficiency, cybersecurity, joint all-domain command and control (JADC2) and sensing grid integration, migration to cloud computing, and expanding agile software development practices. SFWS aligns activities under four capability areas: Weather Data Collection, Weather Data Analysis and Dissemination, Weather Forecasting, and Product Tailoring/ Warfighter Applications (PTWA). This alignment ensures an integrated and systems-oriented approach to program management decisions. A portion of the Weather Forecasting capability is addressed by RDT&E, BA 04, PE 0604002S, Project 645353 - Space Force Weather Services Research. Weather Forecasting provides global and regional advanced scientific numerical weather prediction capabilities for automated, high-resolution forecast products for mission planning and execution. Space weather modeling assists in characterizing and forecasting the near-earth environment to the sun and enables space weather anomaly and space weather impact assessments. Weather Forecasting includes activities for Numerical Weather Modeling (NWM) and Space Weather Analysis and Forecast System (SWAFS). SWAFS is a software suite of 47 models and applications to ingest, process, and store space environmental data, run space environmental models to specify and forecast the near-earth environment, and run space effects characterization applications. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:            PE 0604002SF / Space Force Weather Services Research Advanced Component Development & Prototypes (ACD&P) This program element may include necessary civilian pay expenses required to manage, execute, and deliver SFWS for weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. SWAFS falls within the Weather mission area which provides mission-critical environmental intelligence to support global military operations and delivers essential meteorological and oceanographic data to joint forces across all domains and detects space-based environmental threats to protect vital U.S. and allied space assets. Space Force investment program interdependencies include: RDT&E Budget Line Items: EO/IR Weather Systems (1203710SF); Space Force Weather Services Research (0604002SF); Weather Satellite Follow-on (1206422SF); elements of Space Situation Awareness Operations (1203940SF); elements of Space Control Technology (1206438SF); and elements of Procurement Budget Line Item: Space Mods (SPCMOD) This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604003F$$, $$Advanced Battle Management System (ABMS)$$, $$rdte_af_ba4$$, $$aflcmc_hb$$, 2026, 1040475000, 455382000, 611943000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0604003F"}$$::jsonb, $$ABMS is the PE funding architecture and systems engineering (ASE), digital infrastructure, software and applications, aerial networking, deployable systems, and long range fires for the DAF's primary contribution to the Combined Joint All-Domain Command and Control (CJADC2) warfighting concept, which the DAF formally refers to as the DAF BATTLE NETWORK. The DAF Program Executive Office for Command, Control, Communication, and Battle Management (DAF PEO C3BM) has the lead role in battle management and Command and Control (C2) capabilities for the DAF. This entails not only directing technical integration throughout the DAF but also holding acquisition authorities to develop and implement organic materiel solutions. These solutions aim to establish resilient and widely distributable command and control capabilities within the DAF BATTLE NETWORK. The ABMS PE portfolio funds specific programs over which the DAF PEO C3BM exercises direct oversight in terms of cost, schedule, and performance. This encompasses both the management of these programs and the necessary architectural and systems engineering efforts to ensure effective technical coordination across the broader DAF infrastructure. Additionally, DAF PEO C3BM has identified an initial array of approximately 50 core programs spanning various PEOs, whose organizations collectively form the C3BM Enterprise. These programs represent an evolving collection of systems that, when integrated together, are pivotal in contributing to the development of the DAF BATTLE NETWORK. Collaborating closely with the PEOs overseeing these core programs, DAF PEO C3BM will orchestrate technical integration of the DAF BATTLE NETWORK. This integration is essential to achieve the requisite operational decision advantage crucial for the triumph of the USAF, USSF, joint, and coalition forces in the face of evolving challenges. These inter-PEO initiatives encompass a spectrum of activities, such as technical and programmatic cooperation, comprehensive reporting, and seamless integration. With authority over technical architectures spanning the C3BM enterprise, DAF PEO C3BM will deliver C2 capabilities. To provide a "best of breed” capability across the DAF and facilitate accelerated delivery of the DAF BATTLE NETWORK, DAF PEO C3BM has aligned activities within the ABMS PE portfolio with six major thrust areas: Thrust Area 1: "Architecture and Systems Engineering (ASE)” will 1) conduct Digital Engineering to support technical development activities, 2) conduct mission domain architecture development and analysis and perform enterprise integration through domain-specific Mission Integration Teams (MITs), 3) leverage an Operational Response Team (ORT) to facilitate quick reaction prototyping and experimentation in response to warfighter-led efforts and new relevant technologies. The culmination of these activities will entail the identification, capture, refinement, and formalization of capability gaps, requirements, standards, and interface specifications, as well as potentially novel technologies, collectively paving the way for a blueprint to successfully deliver an all-encompassing integrated DAF BATTLE NETWORK architecture that informs execution of the following 3 thrust areas listed below. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604003F / Advanced Battle Management System (ABMS) Component Development & Prototypes (ACD&P) Thrust Area 2: "C3BM Digital Infrastructure (DI)" leverages the analysis, technical specifications and associated standards/formats produced by ASE to deliver a suite of fixed and deployable digital infrastructure solutions to enable global C2 and Battle Management (BM). To accomplish this, the following tasks are performed: 1) The Enterprise Systems Engineering Team (ESET) manages the ABMS Consortium to define the technical implementation of network architectures, style guides and standards that will facilitate integration of the larger DAF BATTLE NETWORK with ABMS (and vice versa); 2) build out of the physical DI Processing Nodes and DI Network (Software Defined Wide Area Network (SD-WAN), Tactical and Enterprise Cross Domain Solutions (CDS), and other similar requirements) that will enable the operational use of data and software to perform modern C2 functions at scale. DI activities include the ABMS Battle Lab to allow warfighters direct interaction with ABMS software development teams and prototypes in development, speeding up the feedback loop and product maturity. Thrust Area 3: "C3BM Software and Applications" provides a suite of battle management command and control (BMC2) applications and tools, conducted via two categories of activity. 1) Cloud-Based Command and Control (CBC2) is a suite of BMC2 applications and microservices in development for NORAD and USNORTHCOM & PACAF. CBC2 efforts include line of effort (LOE) #1 for a SW Integrator, LOE #2 for Agile Software Development at scale with an Integrated Digital Environment (IDE) for Model-based systems engineering (MBSE), and LOE #3 for Continuous Integration and Continuous Deployment (CI/CD) software pipelines, platform, data ingest, fusion, transport, storage, and access. CBC2 depends on the fixed DI activities of Thrust Area #2 and expects to begin scaling to support additional combatant commanders in FY26. 2) Distributed Battle Management Applications (DBMA) will continue development and extension of CBC2 functionality to other DAF BATTLE NETWORK entities (e.g. the Tactical Operations Center Family of Systems, or TOC FoS) in line with Air Combat Command's (ACC) Common BMC2 Interface concept, via the newly named CBC2+ program. Integral to the C3BM Software and Applications Thrust Area is the imperative to seamlessly align and integrate with various efforts, including multiple DoD & DAF software factories, centers of excellence dedicated to artificial intelligence and machine learning, and the DAF data fabric. Thrust Area 4: "C3BM Aerial Networking" will develop key technologies for the "final leg” connection of C3BM DI and Software and Applications to DAF aerial assets. Aerial Networking activities include: 1) Phalanx Griffon (PG), to extend C3BM aerial networking capabilities to tactically relevant aircraft. Major Release (MR) 2 will initiate and support initial capability delivery to long-range fires platforms by FY27. Phalanx Griffon will include continued development and maturation of multi-function processors, multi-function arrays, edge node hardware and software to host mission applications, and platform integration options to ease implementation and scaling. 2) The joint development of a SOSA-aligned, liquid and air-cooled integrated hybrid SATCOM chassis for rapid integration of PG capability by FY27, and 3) the C3 Hybrid SATCOM (C3HST) product line with a start date of FY26. The C3HST product line will consist of transition of the Global Lightning (GL) prototypes from AFRL to modernize and align those solutions to meet architectural requirements for multiple AF organizations. Thrust Area 5: "C3BM Deployable Systems" thrust to include Distributable Battle Management Node (DBMN) was previously captured under the C3BM Digital Infrastructure (DI) thrust area. The Deployable Systems effort will develop and deliver the Tactical Operations Center - Light (TOC-L) system. The TOC-L is a light, expeditionary BMC2 system designed to rapidly generate battle management effects tailored to mission needs, enabling the C2 warfighter to conduct independent, pulsed operations. The TOC-L enables tactical C2 elements to rapidly relocate, establish datalinks, connect to a variety of sensors, and operate in theater mission partner environments. TOC-L provides ground-based sensor and data-link integration, track correlation, and intelligence fusion, displayed on a Common Tactical Picture (CTP), leveraging and integrating with current and future capabilities across ABMS. Currently, the TOC-L program has two major releases (MR): 1) MR1 provided 16 operationally realistic experimentation kits to operational units; and 2) MR2, a Middle Tier of Acquisition (MTA) Rapid Prototyping program, which builds upon the lessons learned from MR1 and integrates other ABMS sub-systems. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604003F / Advanced Battle Management System (ABMS) Component Development & Prototypes (ACD&P) Thrust Area 6: "C3BM DAF Integrated Fires C2" is the development of Beyond Line of Sight (BLOS) long range fire & control capability for specialized targets. The program consists of integrating multiple prototypes currently under development within AFRL and TENCAP into the DAF BATTLE NETWORK. This will include integration and synergistic fusion within the ABMS portfolio. To ensure delivery of projects in each Thrust Area, and to ensure alignment of the broader DAF from a battle management perspective, ABMS PE funding provides for program management support, operational concept development in collaboration with the ABMS Cross-Functional Team, and portfolio integration to orchestrate delivery of the DAF BATTLE NETWORK. Investments in the ABMS portfolio of programs aligns USAF investment with USSF investment (e.g., Space Command and Control (C2) Program Element PE (1208248SF) and the MeshOne-T PE (1206760SF)) to eliminate duplication of effort while optimizing capability delivery to create the DAF BATTLE NETWORK deliverable. ABMS DI aligns with ISR DI PE (0303010F) to provide a consistent set of capabilities, services and customer experience across all classification levels, and meets DAF requirements while ensuring compliance with Director of National Intelligence (DNI) requirements and minimizing duplication of effort. the FY 2026 cost of the Distributable Battle Management Node (DBMN) Phase II Tactical Operations Center-Light Rapid Prototyping Middle Tier of Acquisition effort is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. The FY 2026 cost of the Deployable Digital Infrastructure Rapid Prototyping Middle Tier of Acquisition effort is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. The FY 2026 cost of the Digital Infrastructure Network Major Release #1 Rapid Prototyping Middle Tier of Acquisition effort is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. The FY 2026 cost of the Fixed Digital Infrastructure (FDI) MR1 Rapid Prototyping Middle Tier of Acquisition effort is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. The FY 2026 cost of the Phalanx Griffon (PG) MR2 Rapid Prototyping Middle Tier of Acquisition effort is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. The FY 2026 request was reduced by 4.648 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Init… [truncated]$$, NULL, 987350000, 937208000, 872539000, NULL, NULL, 37, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 595537000, 870876000, 1040945000, 1040945000, 0, 1040945000, 865275000, $$ABMS is the PE funding architecture and systems engineering (ASE), digital infrastructure, a suite of battle management command and control (BMC2) applications and tools used for homeland defense and other tactical C2 mission sets, airborne connectivity (formerly known as aerial networking), deployable systems, and Beyond Line of Sight (BLOS) long range fire & control software capability for specialized targets for the DAF's primary contribution to the Combined Joint All-Domain Command and Control (CJADC2) warfighting concept, which the DAF formally refers to as the DAF BATTLE NETWORK. The DAF Portfolio Acquisition Executive for Command, Control, Communication, and Battle Management (DAF PAE C3BM) has the lead role in battle management and Command and Control (C2) capabilities for the DAF. This entails not only directing technical integration throughout the DAF but also holding acquisition authorities to develop and implement organic materiel solutions. These solutions aim to establish resilient and widely distributable command and control capabilities within the DAF BATTLE NETWORK. The ABMS PE portfolio funds specific interdependent programs over which the DAF PAE C3BM exercises direct oversight in terms of cost, schedule, and performance. This encompasses both the management of these programs and the necessary architectural and systems engineering efforts to ensure effective technical coordination across the broader DAF infrastructure. Additionally, DAF PAE C3BM has identified an initial array of approximately 50 core programs spanning various PAEs/Program Executive Offices (PEO), whose organizations collectively form the C3BM Enterprise. These programs represent an evolving collection of systems that, when integrated together, are pivotal in contributing to the development of the DAF BATTLE NETWORK. Collaborating closely with the PAE/PEOs overseeing these core programs, DAF PAE C3BM orchestrates technical integration of the DAF BATTLE NETWORK. This integration is essential to achieve the requisite operational decision advantage crucial for the triumph of the USAF, USSF, joint, and coalition forces in the face of evolving challenges. These inter-PAE/PEO initiatives encompass a spectrum of activities, such as technical and programmatic cooperation, comprehensive reporting, and seamless integration. With authority over technical architectures spanning the C3BM enterprise, DAF PAE C3BM will deliver C2 capabilities. To provide a "best of breed” capability across the DAF and facilitate accelerated delivery of the DAF BATTLE NETWORK, DAF PAE C3BM has aligned activities within the ABMS PE portfolio with six major thrust areas: Thrust Area 1: Architecture and Systems Engineering (ASE) and the Operational Response Team (ORT) Thrust Area 1a ASE: Mission Domain Architecture and Mission Integration Teams: will 1) conduct Digital Engineering to support technical development activities, 2) conduct mission domain architecture development and analysis and perform enterprise integration through domain-specific Mission Integration Teams (MITs). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                              Date: April 2026 Appropriation/Budget Activity                                                          R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604003F / Advanced Battle Management System (ABMS) Component Development & Prototypes (ACD&P) Thrust Area 1b: The Operational Response Team facilitates quick reaction prototyping and experimentation in response to warfighter-led efforts and new relevant technologies. The culmination of Thrust 1 activities will entail the identification, capture, refinement, and formalization of capability gaps, requirements, standards, and interface specifications, as well as potentially novel technologies, collectively paving the way for a blueprint to successfully deliver an all-encompassing integrated DAF BATTLE NETWORK architecture that informs execution of the following 5 thrust areas listed below and the greater C3BM Enterprise. Thrust Area 2: "C3BM Digital Infrastructure (DI)" leverages the analysis, technical specifications and associated standards/formats produced by ASE to deliver a suite of fixed and deployable digital infrastructure solutions to enable global C2 and Battle Management (BM). To accomplish this, the following tasks are performed: 1) The Enterprise Engineering Group (EEG) manages the ABMS Consortium to define the technical implementation of network architectures, style guides and standards that will facilitate integration of the larger DAF BATTLE NETWORK with ABMS (and vice versa); 2) build out of the physical DI Processing Nodes and DI Network (Software Defined Wide Area Network (SD-WAN), Tactical and Enterprise Cross Domain Solutions (CDS), and other similar requirements) that will enable the operational use of data and software to perform modern C2 functions at scale. DI activities include the ABMS DI-Network Integration Lab (DI-NIL) to allow warfighters direct interaction with ABMS software development teams and prototypes in development, speeding up the feedback loop and product maturity. Thrust Area 3: "C3BM Software and Applications" provides a suite of battle management command and control (BMC2) applications and tools, conducted via two categories of activity. 1) Cloud-Based Command and Control (CBC2) is a suite of BMC2 applications and microservices in development for NORAD, USNORTHCOM & PACAF. CBC2 efforts include line of effort (LOE) #1 for a SW Integrator, LOE #2 for Agile Software Development at scale with an Integrated Digital Environment (IDE) for Model-based systems engineering (MBSE), and LOE #3 for Continuous Integration and Continuous Deployment (CI/CD) software pipelines, platform, data ingest, fusion, transport, storage, and access. CBC2 depends on the Fixed DI activities of Thrust Area #2 and continues to scale to support additional combatant commanders added in FY26. 2) CBC2+ will continue development and extension of CBC2 functionality to other DAF BATTLE NETWORK and tactical C2 entities (e.g. the Tactical Operations Center-Lite, Air Base Air Defense Systems) in line with Air Combat Command's (ACC) Common BMC2 Interface concept and the ABMS CFT's Common Battle Management Engine (CBME) capability need statement, via the newly named CBC2+ program. Integral to the C3BM Software and Applications Thrust Area is the imperative to seamlessly align and integrate with various efforts, including multiple DoD & DAF software factories, centers of excellence dedicated to artificial intelligence and machine learning, and the DAF data fabric. Thrust Area 4: "C3BM Airborne Connectivity" will develop key technologies for the "final leg” connection of C3BM DI and Software and Applications to DAF airborne assets. Airborne Connectivity activities include: 1) Phalanx Griffon (PG), to extend C3BM airborne connectivity capabilities to tactically relevant aircraft. Major Release (MR) 2 will initiate and support initial capability delivery to long-range fires platforms in FY27. Phalanx Griffon will include continued development and maturation of multi- function processors, multi-function arrays, edge node hardware and software to host mission applications, and platform integration options to ease implementation and scaling. 2) The joint development of a Sensor Open Systems Architecture (SOSA)-aligned, liquid and air-cooled integrated hybrid SATCOM chassis for rapid integration of PG capability in FY27, and 3) the C3 Hybrid SATCOM (C3HST) product line. The C3HST product line consists of transition of the Global Lightning (GL) prototypes from AFRL to modernize and align those solutions to meet architectural requirements for multiple AF organizations. Thrust Area 5: "C3BM Deployable Systems" will develop and deliver the Tactical Operations Center - Light (TOC-L) system. The TOC-L is a light, expeditionary BMC2 system designed to rapidly generate battle management effects tailored to mission needs, enabling the C2 warfighter to conduct independent, pulsed operations. The Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604003F / Advanced Battle Management System (ABMS) Component Development & Prototypes (ACD&P) TOC-L enables tactical C2 elements to rapidly relocate, establish datalinks, connect to a variety of sensors, and operate in theater mission partner environments. TOC- L provides ground-based sensor and data-link integration, track correlation, and intelligence fusion, displayed on a Common Tactical Picture (CTP), leveraging and integrating with current and future capabilities across ABMS. Currently, the TOC-L program has two major releases (MR): 1) MR1 provided 16 operationally realistic experimentation kits to operational units; and 2) MR2, a Middle Tier of Acquisition (MTA) Rapid Prototyping program, which builds upon the lessons learned from MR1 and integrates other ABMS sub-systems. Thrust Area 6: "C3BM DAF Integrated Fires C2" is the development of Beyond Line of Sight (BLOS) long range fire & control capability for specialized targets. The program consists of integrating multiple prototypes currently under development within AFRL and TENCAP into the DAF BATTLE NETWORK. This will include integration and synergistic fusion within the ABMS portfolio. To ensure delivery of projects in each Thrust Area, and to ensure alignment of the broader DAF from a battle management perspective, ABMS PE funding provides for Program Management, Systems Engineering, Test & Evaluation Support, operational concept development in collaboration with the ABMS Cross-Functional Team, and portfolio integration to orchestrate delivery of the DAF BATTLE NETWORK. Investments in the ABMS portfolio of programs aligns USAF investment with USSF investment (e.g., Space Command and Control (C2) Program Element PE (1208248SF) and the MeshOne-T PE (1206760SF)) to eliminate duplication of effort while optimizing capability delivery to create the DAF BATTLE NETWORK deliverable. Additional alignment of the ABMS portfolio (PE) to minimize duplication of effort are: ABMS DI aligns with ISR DI PE (0303010F) to provide a consistent set of capabilities, services and customer experience across all classification levels, and meets DAF requirements while ensuring compliance with Director of National Intelligence (DNI) requirements. ABMS Software and Applications and DI aligns with USAF investment in Mission Planning Systems (PE 0208006F), Air Operations Center (0207410F), All Domain Common Platform (0303248F), and Command and Control Incident Management Emergency Response Application (C2IMERA) (0305836F), and Flight Operations (0207461F) to deliver the Theater Air Planning System of Systems (TAP-SoS) architecture for the DAF BATTLE NETWORK providing the development, infrastructure, and support necessary for each of these programs and TAP-SoS interdependencies to deliver the capabilities required for deliberate planning, dynamic mission replanning, friendly order of battle management, and mission tasking and execution. ABMS Airborne Connectivity aligns with USAF investment in Tactical Datalinks Network Enterprise (0604281F), and Tech Transition - Air (0604858F) to deliver beyond line of sight communications to airborne assets integration on the DAF BATTLE NETWORK. ABMS Deployable Systems aligns with USAF investment in Control and Reporting Center (0207412F) and Air Base Air Defense Systems (0207522F) to deliver a common hardware and software baseline for DAF BATTLE NETWORK deployable systems. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                             Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604003F / Advanced Battle Management System (ABMS) Component Development & Prototypes (ACD&P) ABMS DAF Integrated Fires C2 aligns with Tech Transition - Air (0604858F), AF DCGS (0305208F) and ISR Transport and Processing (0305240F), formerly Support to DCGS Enterprise, to deliver the Long Range Fires architecture for the DAF BATTLE NETWORK. The total cost of the Distributable Battle Management Node (DBMN) Phase II Tactical Operations Center-Light Middle Tier of Acquisition effort is 473.076 million, including RDT&E and procurement of prototype units. The Distributable Battle Management Node (DBMN) Phase I Tactical Operations Center-Light is fully funded across the Future Years Defense Program. The total cost of the Deployable Digital Infrastructure Middle Tier of Acquisition effort is 53.7 million, including RDT&E and procurement of prototype units. The Deployable Digital Infrastructure is fully funded across the Future Years Defense Program. The total cost of the Digital Infrastructure Network Major Release #1 Middle Tier of Acquisition effort is 399.1 million, including RDT&E and procurement of prototype units. The Digital Infrastructure Network Major Release #1 is fully funded across the Future Years Defense Program. The total cost of the Fixed Digital Infrastructure (FDI) Middle Tier of Acquisition effort is 185.9 million, including RDT&E and procurement of prototype units. The Fixed Digital Infrastructure (FDI) is fully funded across the Future Years Defense Program. The total cost of the Phalanx Griffon MR2 Middle Tier of Acquisition effort is 304.3 million, including RDT&E and procurement of prototype units. The Phalanx Griffon MR2 is fully funded across the Future Years Defense Program. Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604003F / Advanced Battle Management System (ABMS) Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604004F$$, $$Advanced Engine Development$$, $$rdte_af_ba4$$, $$aflcmc$$, 2026, 0, 269971000, 100000000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0604004F"}$$::jsonb, $$The Advanced Engine Development (AED) Program includes all efforts necessary to develop and evaluate advanced propulsion system components and prototypes in realistic environments. The program also includes all efforts to define and evaluate required modifications to commercial and military off the shelf propulsion systems for use in existing and future aircraft and munitions. These activities enable maturation and risk reduction of advanced propulsion system architectures, designs, modifications, enabling materials and technologies, and manufacturing processes for follow-on Engineering, Manufacturing and Development and integration efforts. Prototyping and assessments of the prototypes at sea-level, simulated altitudes, and durability assessments across multiple power settings provides data to validate system performance, calibrate engineering models, and ensure appropriate manufacturing and technology readiness for future propulsion system development and platform integration as well as potential insertion into already fielded propulsion systems. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 $4.971 million was expended for civilian pay expenses in this program element, and in FY 2025 $0.0 million is forecasted for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604004F / Advanced Engine Development Component Development & Prototypes (ACD&P)$$, NULL, 0, 0, 0, NULL, NULL, 38, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 96470000, 25000000, 0, 0, 0, 0, 0, $$The Advanced Engine Development (AED) Program includes all efforts necessary to develop and evaluate advanced propulsion system components and prototypes in realistic environments. The program also includes all efforts to define and evaluate required modifications to commercial and military off-the-shelf propulsion systems for use in existing and future aircraft and munitions. These activities enable maturation and risk reduction of advanced propulsion system architectures, designs, modifications, enabling materials and technologies, and manufacturing processes for follow-on Engineering, Manufacturing and Development (EMD) and platform integration efforts within this program. Prototyping and assessments of the prototypes at sea-level, simulated altitudes, and durability assessments across multiple power settings provide data to validate system performance, calibrate engineering models, and ensure appropriate manufacturing and technology readiness for future propulsion system development and platform integration as well as potential insertion into already fielded propulsion systems. Digital transformation, modernization, and expansion of the propulsion industrial base are additional facets of the AED program essential to re-building the military and industrial base surge capacity. Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604004F / Advanced Engine Development Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
